// ========== HOOK: detección de viewport móvil ==========
// Devuelve true cuando el ancho de pantalla es ≤ el breakpoint dado (default 640px = sm de Tailwind).
// Lo usan los drawers flotantes (VetPatientCard, GroomingAttendanceDrawer, ClientServiceWindow)
// para conmutar a layout vertical con tabs en lugar de columnas, y para ocupar pantalla completa.
function useIsMobile(breakpoint = 640) {
  const [isMobile, setIsMobile] = useState(() => {
    if (typeof window === "undefined") return false;
    return window.innerWidth <= breakpoint;
  });
  useEffect(() => {
    if (typeof window === "undefined") return;
    const onResize = () => setIsMobile(window.innerWidth <= breakpoint);
    window.addEventListener("resize", onResize);
    return () => window.removeEventListener("resize", onResize);
  }, [breakpoint]);
  return isMobile;
}

// ========== HANDLE DE RESIZE para ventanas flotantes ==========
// Triángulo en la esquina inferior derecha que permite arrastrar para
// redimensionar la ventana. Lo usan todas las ventanas flotantes (VetPatientCard,
// GroomingAttendanceDrawer, VetAgendaModal, GroomingCalendarModal, ChatWindow).
//
// Props:
// - size: { w, h } - tamaño actual de la ventana
// - setSize: (newSize) => void - setter del tamaño
// - minW, minH: tamaño mínimo aceptable (defaults razonables)
// - disabled: oculta el handle (en móvil o cuando la ventana está maximizada)
function WindowResizeHandle({ size, setSize, minW = 480, minH = 360, disabled = false }) {
  if (disabled) return null;

  const onMouseDown = (e) => {
    e.preventDefault();
    e.stopPropagation();
    const startX = e.clientX;
    const startY = e.clientY;
    const startW = size.w;
    const startH = size.h;
    const handleMove = (ev) => {
      const newW = Math.max(minW, startW + (ev.clientX - startX));
      const newH = Math.max(minH, startH + (ev.clientY - startY));
      setSize({ w: newW, h: newH });
    };
    const handleUp = () => {
      window.removeEventListener("mousemove", handleMove);
      window.removeEventListener("mouseup", handleUp);
      // Restaurar el cursor del body por si quedó pegado
      document.body.style.cursor = "";
      document.body.style.userSelect = "";
    };
    // Cursor global durante el drag para que no parpadee al pasar sobre otros elementos
    document.body.style.cursor = "nwse-resize";
    document.body.style.userSelect = "none";
    window.addEventListener("mousemove", handleMove);
    window.addEventListener("mouseup", handleUp);
  };

  return (
    <div
      onMouseDown={onMouseDown}
      title="Arrastra para redimensionar"
      className="absolute bottom-0 right-0 w-5 h-5 cursor-nwse-resize z-10 group"
      style={{ touchAction: "none" }}
    >
      {/* Tres líneas diagonales tipo "esquinita" estilo macOS */}
      <svg
        viewBox="0 0 16 16"
        className="absolute bottom-0.5 right-0.5 w-3.5 h-3.5 text-stone-400 group-hover:text-orange-600 transition pointer-events-none"
        fill="none"
        stroke="currentColor"
        strokeWidth="1.6"
        strokeLinecap="round"
      >
        <line x1="14" y1="6"  x2="6"  y2="14" />
        <line x1="14" y1="10" x2="10" y2="14" />
        <line x1="14" y1="14" x2="14" y2="14" strokeWidth="2" />
      </svg>
    </div>
  );
}

