// === Helpers para servicios multi-módulo ===
// Cada servicio del catálogo tiene un `moduleId` que identifica la INSTANCIA específica
// a la que pertenece. Eso permite tener "Veterinaria 1" con sus 3 servicios y
// "Veterinaria 2" con otros 3, aunque ambos sean del kind "vet".
//
// Para retro-compatibilidad: si un servicio no tiene `moduleId`, lo derivamos de `module`:
//   module="vet" → moduleId="vet"
//   module="grooming" → moduleId="grooming-ops"
//   module="b2b" → moduleId="standard"
function resolveServiceModuleId(service) {
  if (service.moduleId) return service.moduleId;
  if (service.module === "vet") return "vet";
  if (service.module === "grooming") return "grooming-ops";
  if (service.module === "b2b") return "standard";
  return null;
}

// Filtra la lista de servicios para un módulo específico (por moduleId, no por kind).
function getServicesForModule(services, moduleId) {
  if (!moduleId) return [];
  return (services || []).filter(s => resolveServiceModuleId(s) === moduleId);
}

