 passport: { crumb: "Clientes", here: "Pasaportes", title: <>Pasaportes <span className="italic text-orange-600">veterinarios</span></> },
 "passport-updates": { crumb: "Clientes", here: "Actualizar pasaporte", title: <>Actualizar <span className="italic text-orange-600">pasaporte</span></> },
 "settings-hub": { crumb: "Panel", here: "Ajustes", title: <>Ajustes <span className="italic text-orange-600">del sistema</span></> },
 roles: { crumb: "Ajustes", here: "Roles & permisos", title: <>Roles <span className="italic text-orange-600">y permisos</span></> },
 clients: { crumb: "Operación", here: "Clientes", title: <>Tutores <span className="italic text-orange-600">y mascotas</span></> },
 profile: { crumb: "Cuenta", here: "Mi perfil", title: <>Configuración <span className="italic text-orange-600">de mi cuenta</span></> },
 dashboard: { crumb: "General", here: "Dashboard", title: <>Panorama <span className="italic text-orange-600">general</span></> },
 agenda: { crumb: "General", here: "Agenda", title: <>Agenda <span className="italic text-orange-600">unificada</span></> },
 messages: { crumb: "General", here: "Mensajes", title: <>Bandeja de <span className="italic text-orange-600">conversaciones</span></> },
