// ========== VISTA: VENTAS / RECIBOS ==========

function SalesView({ invoices: invoicesAll, setInvoices, clients, paymentPlans, setPaymentPlans, onMessageClient, modules = [], userRole = "super", customRoles = [], activeSedeId = null, sedes = [], initialSearch = "", onSearchConsumed }) {
  const [activeTab, setActiveTab] = useState("kanban"); // kanban | list | history | debtors | plans
  const [selectedInvoice, setSelectedInvoice] = useState(null);
  const [showPayment, setShowPayment] = useState(false);
  const [showCreatePlan, setShowCreatePlan] = useState(false);
  // Toggle para mostrar la columna "En plan de pago" en el kanban (oculta por defecto)
  const [showPlanColumn, setShowPlanColumn] = useState(false);
  const [searchQuery, setSearchQuery] = useState(initialSearch || "");

  // Si llegamos con un initialSearch (ej. desde el historial del cliente),
  // switchear a vista lista para que la búsqueda se vea y consumir el valor.
  useEffect(() => {
    if (initialSearch) {
      setSearchQuery(initialSearch);
      setActiveTab("list");
      onSearchConsumed?.();
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // === Filtro por sede ===
  // Para super: dropdown manual con todas las sedes + opción "Todas"/"Sin sede".
  // Para roles custom con assignedModuleIds: filtro automático invisible.
  // Para roles core (vet, grooming, sales): ven todo lo que sus permisos les permitan.
  const myCustomRole = useMemo(
    () => (customRoles || []).find(r => r.id === userRole),
    [customRoles, userRole]
  );
  const isSuperUser = userRole === "super";
  const restrictedModuleIds = myCustomRole?.assignedModuleIds || [];
  const isRestrictedByRole = restrictedModuleIds.length > 0;

  // moduleFilter: "all" | "none" (sin sede) | <moduleId>
  // Si el rol está restringido, fijamos al primero asignado por defecto.
  const [moduleFilter, setModuleFilter] = useState(
    isRestrictedByRole ? restrictedModuleIds[0] : "all"
  );

  // Lista de instancias visibles para el dropdown del super
  const visibleModules = useMemo(
    () => (modules || []).filter(m => !m.removed),
    [modules]
  );

  // Aplicar el filtro de sede a las recibos.
  // Lógica:
  // 1. Si hay activeSedeId, mostramos recibos cuyo moduleId pertenezca a un módulo de esa sede.
  //    Esto incluye recibos con campo `sedeId` explícito que coincida (por si en el futuro se asigna directo).
  // 2. Si el rol está restringido (assignedModuleIds), también respetamos ese filtro de roles.
  // 3. Si NO hay sede activa (fallback), comportamiento legacy.
  const sceneFilteredInvoices = useMemo(() => {
    let result = invoicesAll;
    // Filtro por sede activa
    if (activeSedeId) {
      const moduleIdsOfSede = (modules || [])
        .filter(m => m.sedeId === activeSedeId && !m.removed)
        .map(m => m.id);
      result = result.filter(inv =>
        inv.sedeId === activeSedeId ||
        (inv.moduleId && moduleIdsOfSede.includes(inv.moduleId))
      );
    }
    // Filtro adicional por rol restringido (compatibilidad)
    if (isRestrictedByRole) {
      result = result.filter(inv => restrictedModuleIds.includes(inv.moduleId));
    }
    return result;
  }, [invoicesAll, activeSedeId, modules, isRestrictedByRole, restrictedModuleIds]);

  // Helper para encontrar cliente
  const clientMap = useMemo(() => {
    const m = {};
    clients.forEach(c => { m[c.id] = c; });
    return m;
  }, [clients]);

  // === Aliasing crítico ===
  // De aquí en adelante, "invoices" se refiere a la lista YA FILTRADA por sede.
  // Para mutar (pagos, cierres, etc.) seguimos usando setInvoices que opera sobre el global.
  // Esto permite que las stats, kanbans, listas, etc. usen automáticamente el filtro.
  const invoices = sceneFilteredInvoices;

  // === Planes de pago filtrados por sede ===
  // Cruzamos los paymentPlans con las invoices ya filtradas. Si un plan pertenece
  // a una recibo que no está visible en esta sede, el plan tampoco se muestra.
  // Esto evita que María Pérez (Pet 1) aparezca con plan de pago cuando estás en Pet 2.
  const visibleInvoiceIds = useMemo(() => new Set(invoices.map(i => i.id)), [invoices]);
  const paymentPlansFiltered = useMemo(
    () => (paymentPlans || []).filter(p => visibleInvoiceIds.has(p.invoiceId)),
    [paymentPlans, visibleInvoiceIds]
  );

  // Filtrado por búsqueda — defensivo contra recibos con campos faltantes
  const filtered = useMemo(() => {
    if (!searchQuery.trim()) return invoices;
    const q = searchQuery.toLowerCase();
    return invoices.filter(inv => {
      const c = clientMap[inv.clientId];
      return (inv.number || "").toLowerCase().includes(q) ||
             (c && (c.name?.toLowerCase().includes(q) || c.cedula?.toLowerCase().includes(q)));
    });
  }, [invoices, searchQuery, clientMap]);

  // Stats — defensivos contra recibos con campos faltantes para no crashear la vista
  const stats = useMemo(() => {
    const totalInvoiced = invoices.reduce((s, i) => s + (i.total ?? 0), 0);
    const totalCollected = invoices.reduce((s, i) => s + (i.paid ?? 0), 0);
    const totalDebt = invoices.reduce((s, i) => s + (i.balance ?? 0), 0);
    const debtors = new Set(invoices.filter(i => (i.balance ?? 0) > 0).map(i => i.clientId)).size;
    const overdue = invoices.filter(i => i.state === "vencido").length;
    return { totalInvoiced, totalCollected, totalDebt, debtors, overdue };
  }, [invoices]);

  // Aplicar abono
  const applyPayment = (invoiceId, amount, method, note, voucher) => {
    let updatedInv = null;
    setInvoices(invs => invs.map(inv => {
      if (inv.id !== invoiceId) return inv;
      const newPaid = Math.min(inv.total, inv.paid + amount);
      const newBalance = inv.total - newPaid;
      const newState = newBalance === 0 ? "pagado" : inv.state;
      const result = {
        ...inv,
        paid: newPaid,
        balance: newBalance,
        state: newState,
        payments: [
          ...inv.payments,
          {
            id: `pay-${invoiceId}-${inv.payments.length + 1}`,
            date: new Date().toISOString().slice(0, 10),
            amount, method, note,
            voucher: voucher || null,
          }
        ]
      };
      updatedInv = result;
      return result;
    }));
    // Refrescar el drawer con el snapshot recién actualizado
    if (updatedInv && selectedInvoice && selectedInvoice.id === invoiceId) {
      setSelectedInvoice(updatedInv);
    }
    setShowPayment(false);
  };

  const tabs = [
    { id: "kanban",   label: "Kanban",          Icon: LayoutGrid },
    { id: "list",     label: "Lista",           Icon: LayoutDashboard },
    { id: "debtors",  label: "Deudores",        Icon: AlertTriangle, accent: stats.debtors > 0 ? "red" : null },
    { id: "plans",    label: "Planes de pago",  Icon: Calendar },
    { id: "history",  label: "Histórico",       Icon: History },
  ];

  return (
    <div className="space-y-5">
      {/* Filtro de sede eliminado: la sede ahora se controla desde las pestañas globales del CRM (CRMHubView). */}

      {/* Tabs principales */}
      <div className="bg-white border border-stone-200 rounded-2xl shadow-sm p-1.5 flex gap-1 overflow-x-auto">
        {(() => {
          const activePlansCount = paymentPlansFiltered.filter(p => {
            if (p.status === "deleted" || p.status === "completed") return false;
            if (p.installments.length > 0 && p.installments.every(i => i.paid)) return false;
            return true;
          }).length;
          return tabs.map(t => {
            const Icon = t.Icon;
            const active = activeTab === t.id;
            return (
              <button
                key={t.id}
                onClick={() => setActiveTab(t.id)}
                className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-semibold transition flex-shrink-0 ${
                  active
                    ? t.accent === "red"
                      ? "bg-red-600 text-white"
                      : "bg-stone-900 text-white"
                    : t.accent === "red"
                      ? "text-red-700 hover:bg-red-50"
                      : "text-stone-600 hover:bg-stone-50"
                }`}
              >
                <Icon size={14} />
                {t.label}
                {t.id === "debtors" && stats.debtors > 0 && (
                  <span className={`text-xs font-bold px-1.5 py-px rounded-full ${
                    active ? "bg-red-700 text-white" : "bg-red-100 text-red-700"
                  }`}>{stats.debtors}</span>
                )}
                {t.id === "plans" && activePlansCount > 0 && (
                  <span className={`text-xs font-bold px-1.5 py-px rounded-full ${
                    active ? "bg-stone-700 text-white" : "bg-stone-100 text-stone-600"
                  }`}>{activePlansCount}</span>
                )}
              </button>
            );
          });
        })()}
      </div>

      {/* Buscador (excepto en planes) */}
      {activeTab !== "plans" && (
        <div className="bg-white border border-stone-200 rounded-2xl shadow-sm p-4">
          <div className="flex items-center gap-2">
            <div className="relative flex-1">
              <Search size={16} className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-400" />
              <input
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                placeholder="Buscar por número de recibo, cliente o cédula..."
                className="w-full pl-11 pr-10 py-2.5 bg-stone-50 border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500 focus:bg-white"
              />
              {searchQuery && (
                <button
                  onClick={() => setSearchQuery("")}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-stone-400 hover:text-stone-600"
                >
                  <X size={14} />
                </button>
              )}
            </div>
            {/* Toggle: mostrar columna "En plan de pago" — solo en vista kanban */}
            {activeTab === "kanban" && (
              <button
                onClick={() => setShowPlanColumn(v => !v)}
                title={showPlanColumn ? "Ocultar columna de planes activos" : "Mostrar columna de planes activos"}
                className={`flex items-center gap-1.5 px-3 py-2.5 rounded-xl text-sm font-semibold transition border ${
                  showPlanColumn
                    ? "bg-purple-100 border-purple-400 text-purple-800"
                    : "bg-white border-stone-200 text-stone-600 hover:border-purple-400 hover:text-purple-700"
                }`}
              >
                <Calendar size={13} />
                <span className="hidden sm:inline">{showPlanColumn ? "Ocultar planes" : "Ver planes"}</span>
              </button>
            )}
          </div>
        </div>
      )}

      {/* Vista activa */}
      {activeTab === "kanban" && (
        <SalesKanban
          invoices={filtered}
          clientMap={clientMap}
          onSelect={setSelectedInvoice}
          paymentPlans={paymentPlansFiltered}
          showPlanColumn={showPlanColumn}
          onMoveState={(invoiceId, newState) => {
            setInvoices(prev => prev.map(inv => {
              if (inv.id !== invoiceId) return inv;
              const update = { ...inv, state: newState };
              // Al pasar a "pagado", marcamos balance = 0 (asumiendo que el pago está registrado)
              if (newState === "pagado") update.balance = 0;
              return update;
            }));
          }}
        />
      )}
      {activeTab === "list" && (
        <SalesList
          invoices={filtered}
          clientMap={clientMap}
          onSelect={setSelectedInvoice}
        />
      )}
      {activeTab === "debtors" && (
        <SalesDebtors
          invoices={filtered.filter(i => i.balance > 0)}
          clientMap={clientMap}
          onSelect={(inv) => { setSelectedInvoice(inv); setShowPayment(true); }}
          onCreatePlan={(inv) => { setSelectedInvoice(inv); setShowCreatePlan(true); }}
          plansByInvoice={paymentPlansFiltered.reduce((acc, p) => {
            if (p.status !== "deleted") acc[p.invoiceId] = p;
            return acc;
          }, {})}
        />
      )}
      {activeTab === "plans" && (
        <SalesPaymentPlans
          plans={paymentPlansFiltered}
          invoices={invoices}
          clientMap={clientMap}
          onPayInstallment={(planId, instId, voucher, method) => {
            // Buscar el plan y la cuota antes de actualizar
            const plan = paymentPlans.find(p => p.id === planId);
            if (!plan) return;
            const inst = plan.installments.find(i => i.id === instId);
            if (!inst || inst.paid) return;

            const today = new Date().toISOString().slice(0, 10);
            const paymentMethod = method || "Transferencia";

            // 1. Actualizar el plan: cuota como pagada y, si era la última, marcar plan como completed
            setPaymentPlans(plans => plans.map(p => {
              if (p.id !== planId) return p;
              const updatedInstallments = p.installments.map(i =>
                i.id === instId
                  ? { ...i, paid: true, paidDate: today, voucher: voucher || null, method: paymentMethod }
                  : i
              );
              const allPaid = updatedInstallments.every(i => i.paid);
              return {
                ...p,
                installments: updatedInstallments,
                status: allPaid ? "completed" : p.status,
                completedAt: allPaid && !p.completedAt ? today : p.completedAt,
              };
            }));

            // 2. Actualizar la recibo: agregar pago, recalcular saldo, transicionar a "pagado" si saldo = 0
            let updatedInv = null;
            setInvoices(invs => invs.map(inv => {
              if (inv.id !== plan.invoiceId) return inv;
              const newPaid = Math.min(inv.total, inv.paid + inst.amount);
              const newBalance = inv.total - newPaid;
              const newState = newBalance === 0 ? "pagado" : inv.state;
              const result = {
                ...inv,
                paid: newPaid,
                balance: newBalance,
                state: newState,
                payments: [
                  ...inv.payments,
                  {
                    id: `pay-${inv.id}-${inv.payments.length + 1}`,
                    date: today,
                    amount: inst.amount,
                    method: paymentMethod,
                    note: `Cuota ${inst.number} del plan`,
                    voucher: voucher || null,
                    installmentId: instId, // este pago proviene del plan
                  }
                ]
              };
              updatedInv = result;
              return result;
            }));

            // 3. Refrescar el drawer si es la misma recibo
            if (updatedInv && selectedInvoice && selectedInvoice.id === plan.invoiceId) {
              setSelectedInvoice(updatedInv);
            }
          }}
          onDeletePlan={(planId) => {
            // Marcar como eliminado en lugar de borrar (para auditoría)
            // Las cuotas pagadas ya están registradas como pagos en la recibo
            setPaymentPlans(plans => plans.map(p =>
              p.id === planId
                ? { ...p, status: "deleted", deletedAt: new Date().toISOString().slice(0, 10) }
                : p
            ));
          }}
        />
      )}
      {activeTab === "history" && (() => {
        // Conjunto de invoiceIds cuyo plan está 100% pagado (aunque la recibo siga sin transicionar)
        const invoicesWithCompletedPlan = new Set(
          paymentPlansFiltered
            .filter(p => p.status !== "deleted" && p.installments.length > 0 && p.installments.every(i => i.paid))
            .map(p => p.invoiceId)
        );
        const historicInvoices = filtered.filter(i =>
          i.state === "pagado" || i.state === "finalizado" || invoicesWithCompletedPlan.has(i.id)
        );
        return (
          <SalesHistory
            invoices={historicInvoices}
            clientMap={clientMap}
            paymentPlans={paymentPlansFiltered}
            onSelect={setSelectedInvoice}
          />
        );
      })()}

      {/* Modal: detalle de recibo */}
      {selectedInvoice && !showPayment && !showCreatePlan && (
        <InvoiceDetailModal
          invoice={selectedInvoice}
          client={clientMap[selectedInvoice.clientId]}
          invoices={invoicesAll}
          onClose={() => setSelectedInvoice(null)}
          onPayment={() => setShowPayment(true)}
          onCreatePlan={() => setShowCreatePlan(true)}
          onMessageClient={onMessageClient}
          readOnly={selectedInvoice.state === "finalizado"}
          setInvoices={setInvoices}
          paymentPlans={paymentPlans}
          setPaymentPlans={setPaymentPlans}
          onUpdateSelected={(updates) => setSelectedInvoice(prev => ({ ...prev, ...updates }))}
        />
      )}

      {/* Modal: registrar abono */}
      {showPayment && selectedInvoice && (
        <PaymentModal
          invoice={selectedInvoice}
          client={clientMap[selectedInvoice.clientId]}
          onClose={() => setShowPayment(false)}
          onSubmit={(amount, method, note, voucher) => applyPayment(selectedInvoice.id, amount, method, note, voucher)}
        />
      )}

      {/* Modal: crear plan de pago */}
      {showCreatePlan && selectedInvoice && (
        <CreatePlanModal
          invoice={selectedInvoice}
          client={clientMap[selectedInvoice.clientId]}
          onClose={() => setShowCreatePlan(false)}
          onSubmit={(installments) => {
            const newPlan = {
              id: `plan-${selectedInvoice.id}-${Date.now()}`,
              invoiceId: selectedInvoice.id,
              clientId: selectedInvoice.clientId,
              totalAmount: selectedInvoice.balance,
              installments,
              createdAt: new Date().toISOString().slice(0, 10),
              status: "activo",
            };
            setPaymentPlans([...paymentPlans, newPlan]);
            setShowCreatePlan(false);
          }}
        />
      )}
    </div>
  );
}

function SalesKpi({ label, value, accent }) {
  const colors = {
    emerald: "bg-emerald-600 text-white",
    red: "bg-red-600 text-white",
  };
  return (
    <div className={`px-5 py-3 rounded-xl text-center min-w-20 ${
      accent ? colors[accent] : "bg-white border border-stone-200"
    }`}>
      <div className={`text-xs tracking-widest uppercase font-semibold ${
        accent ? "text-white" : "text-stone-500"
      }`}>{label}</div>
      <div className="font-serif text-2xl font-semibold leading-none mt-1">{value}</div>
    </div>
  );
}

// ========== KANBAN DE RECIBOS ==========

function SalesKanban({ invoices, clientMap, onSelect, paymentPlans = [], showPlanColumn = false, onMoveState }) {
  // Set de IDs de recibos que tienen plan ACTIVO (no eliminado)
  const planInvoiceIds = useMemo(() => {
    const s = new Set();
    paymentPlans.forEach(p => {
      if (p.status !== "deleted" && p.invoiceId) s.add(p.invoiceId);
    });
    return s;
  }, [paymentPlans]);

  // === Drag & drop SOLO HACIA ADELANTE: borrador → emitido → pagado → finalizado ===
  // No se permite retroceder, ni mover a/desde la columna especial "in-plan".
  // Las recibos vencidas tampoco se arrastran (son una alerta, no un estado regular).
  const STATE_ORDER = { borrador: 1, emitido: 2, pagado: 3, finalizado: 4 };
  const canMoveTo = (from, to) => {
    if (from === to) return false;
    if (to === "in-plan" || from === "in-plan") return false;
    if (!STATE_ORDER[from] || !STATE_ORDER[to]) return false;
    return STATE_ORDER[to] > STATE_ORDER[from];
  };
  const [dragOverColumnId, setDragOverColumnId] = useState(null);
  const dragDataRef = useRef(null);
  const handleDragStart = (e, invoiceId, fromState) => {
    if (!invoiceId || !STATE_ORDER[fromState]) return;
    dragDataRef.current = { invoiceId, fromState };
    if (e.dataTransfer) {
      e.dataTransfer.effectAllowed = "move";
      try { e.dataTransfer.setData("text/plain", String(invoiceId)); } catch (_) {}
    }
  };
  const handleDragEnd = () => {
    dragDataRef.current = null;
    setDragOverColumnId(null);
  };
  const handleColumnDragOver = (e, columnId) => {
    const data = dragDataRef.current;
    if (!data) return;
    if (!canMoveTo(data.fromState, columnId)) return; // bloqueado: no se permite el drop
    e.preventDefault();
    if (e.dataTransfer) e.dataTransfer.dropEffect = "move";
    if (dragOverColumnId !== columnId) setDragOverColumnId(columnId);
  };
  const handleColumnDrop = (e, columnId) => {
    e.preventDefault();
    const data = dragDataRef.current;
    setDragOverColumnId(null);
    dragDataRef.current = null;
    if (!data) return;
    if (!canMoveTo(data.fromState, columnId)) return;
    onMoveState && onMoveState(data.invoiceId, columnId);
  };

  // Etapas: si la columna "en plan" está activa, se intercala entre emitido y pagado
  const stages = showPlanColumn
    ? ["borrador", "emitido", "in-plan", "pagado", "finalizado"]
    : ["borrador", "emitido", "pagado", "finalizado"];

  const grouped = useMemo(() => {
    const m = { borrador: [], emitido: [], "in-plan": [], pagado: [], finalizado: [] };
    invoices.forEach(inv => {
      // Si tiene plan activo y la columna está visible, lo mandamos a "in-plan"
      // (no aparece duplicado en "emitido")
      if (showPlanColumn && planInvoiceIds.has(inv.id) && inv.state !== "pagado" && inv.state !== "finalizado") {
        m["in-plan"].push(inv);
        return;
      }
      const stage = inv.state === "vencido" ? "emitido" : inv.state;
      if (m[stage]) m[stage].push(inv);
    });
    return m;
  }, [invoices, planInvoiceIds, showPlanColumn]);

  // Etiquetas y colores para la columna nueva
  const stageMeta = {
    borrador:   { label: "Borrador",      dot: "bg-slate-500" },
    emitido:    { label: "Emitido",       dot: "bg-blue-500" },
    "in-plan":  { label: "En plan de pago", dot: "bg-purple-500" },
    pagado:     { label: "Pagado",        dot: "bg-emerald-500" },
    finalizado: { label: "Finalizado",    dot: "bg-stone-500" },
  };

  return (
    <div className="overflow-x-auto pb-2 -mx-2 px-2">
      <div className="flex gap-3 min-w-max">
        {stages.map(stage => {
          const list = grouped[stage] || [];
          const meta = stageMeta[stage];
          const isPlanCol = stage === "in-plan";
          const isDropTarget = dragOverColumnId === stage;
          return (
            <div
              key={stage}
              onDragOver={(e) => handleColumnDragOver(e, stage)}
              onDragLeave={() => { if (dragOverColumnId === stage) setDragOverColumnId(null); }}
              onDrop={(e) => handleColumnDrop(e, stage)}
              className={`rounded-xl p-3 min-h-80 w-64 flex-shrink-0 transition ${
                isPlanCol ? "bg-purple-50 border-2 border-dashed border-purple-200" : "bg-stone-100"
              } ${isDropTarget ? "ring-2 ring-orange-400 ring-offset-2" : ""}`}
            >
              <div className="flex items-center justify-between mb-3 px-1">
                <div className="flex items-center gap-2">
                  <span className={`w-2 h-2 rounded-full ${meta.dot}`}></span>
                <span className="font-semibold text-sm">{meta.label}</span>
                <span className="text-xs text-stone-400">· {list.length}</span>
              </div>
              <MoreHorizontal size={14} className="text-stone-400" />
            </div>
            <div className="space-y-2">
              {list.map(inv => {
                const c = clientMap[inv.clientId];
                const isOverdue = inv.state === "vencido";
                const wasModified = Boolean(inv.modifiedByProposal);
                const cameFromProposal = Boolean(inv.fromProposal);
                const isPaidExternally = Boolean(inv.paidExternally);
                const isServiceCompleted = Boolean(inv.serviceCompleted);
                const isPaidInAdvance = Boolean(inv.paidInAdvance);
                const hasPlan = planInvoiceIds.has(inv.id);
                // Solo arrastrable si está en un stage del flujo lineal y no es vencida ni en-plan
                const isDraggable = !isPlanCol && !isOverdue && STATE_ORDER[inv.state] && stage !== "finalizado";
                return (
                  <button
                    key={inv.id}
                    draggable={isDraggable}
                    onDragStart={(e) => isDraggable && handleDragStart(e, inv.id, inv.state)}
                    onDragEnd={handleDragEnd}
                    onClick={() => onSelect(inv)}
                    className={`relative text-left w-full bg-white p-3 rounded-xl border hover:-translate-y-0.5 hover:shadow transition overflow-hidden ${
                      isDraggable ? "cursor-grab active:cursor-grabbing" : "cursor-pointer"
                    } ${
                      isOverdue ? "border-red-300" :
                      isPlanCol ? "border-purple-300" :
                      hasPlan && !showPlanColumn ? "border-purple-200 ring-1 ring-purple-100" :
                      wasModified ? "border-emerald-300 ring-1 ring-emerald-200" :
                      isPaidExternally ? "border-teal-300 ring-1 ring-teal-100" :
                      isPaidInAdvance ? "border-blue-300 ring-1 ring-blue-100" :
                      isServiceCompleted ? "border-amber-300 ring-1 ring-amber-100" :
                      cameFromProposal ? "border-emerald-200" :
                      "border-stone-200"
                    }`}
                  >
                    {/* Cinta diagonal cuando la recibo fue modificada por propuesta aprobada */}
                    {wasModified && (
                      <div className="absolute -top-px -right-px overflow-hidden w-20 h-20 pointer-events-none">
                        <div className="absolute top-3 -right-7 w-28 transform rotate-45 bg-gradient-to-r from-emerald-500 to-emerald-600 text-white text-xs font-bold py-0.5 text-center shadow">
                          + insumos
                        </div>
                      </div>
                    )}
                    {/* Cinta para recibos creadas desde una propuesta aprobada */}
                    {cameFromProposal && !wasModified && (
                      <div className="absolute -top-px -right-px overflow-hidden w-20 h-20 pointer-events-none">
                        <div className="absolute top-3 -right-7 w-28 transform rotate-45 bg-gradient-to-r from-emerald-500 to-emerald-600 text-white text-xs font-bold py-0.5 text-center shadow">
                          de Grooming
                        </div>
                      </div>
                    )}
                    {/* Cinta para servicios concluidos en grooming pendientes de cobro */}
                    {isServiceCompleted && !wasModified && !cameFromProposal && (
                      <div className="absolute -top-px -right-px overflow-hidden w-24 h-24 pointer-events-none">
                        <div className="absolute top-4 -right-7 w-32 transform rotate-45 bg-gradient-to-r from-amber-500 to-orange-600 text-white text-xs font-bold py-0.5 text-center shadow">
                          ✓ Concluido
                        </div>
                      </div>
                    )}
                    {/* Cinta para recibos con pago anticipado, esperando que se preste el servicio */}
                    {isPaidInAdvance && !isServiceCompleted && !wasModified && !cameFromProposal && (
                      <div className="absolute -top-px -right-px overflow-hidden w-24 h-24 pointer-events-none">
                        <div className="absolute top-4 -right-7 w-32 transform rotate-45 bg-gradient-to-r from-blue-500 to-blue-700 text-white text-xs font-bold py-0.5 text-center shadow">
                          $ adelantado
                        </div>
                      </div>
                    )}
                    <div className="flex items-center justify-between gap-2 mb-1">
                      <span className="font-mono text-xs font-semibold text-stone-600">{inv.number}</span>
                      {isOverdue && (
                        <span className="text-xs font-bold px-1.5 py-px rounded bg-red-100 text-red-700">
                          VENCIDA
                        </span>
                      )}
                    </div>
                    <div className="font-semibold text-sm mb-1 truncate">
                      {c ? c.name : "Cliente desconocido"}
                    </div>
                    <div className="text-xs text-stone-500 mb-2">
                      {inv.issueDate}
                    </div>
                    <div className="flex items-center justify-between pt-2 border-t border-stone-100">
                      <span className="font-serif text-base font-semibold text-orange-700">
                        ${(inv.total ?? 0).toLocaleString()}
                      </span>
                      {inv.balance > 0 && inv.balance < inv.total && (
                        <span className="text-xs font-semibold text-amber-600">
                          Parcial
                        </span>
                      )}
                    </div>
                  </button>
                );
              })}
              {list.length === 0 && (
                <div className="text-xs text-stone-400 text-center py-6">
                  Sin recibos
                </div>
              )}
            </div>
          </div>
        );
      })}
      </div>
    </div>
  );
}

// ========== LISTA DE RECIBOS ==========

function SalesList({ invoices, clientMap, onSelect }) {
  const PER_PAGE = 50;
  const [page, setPage] = useState(1);
  const totalPages = Math.max(1, Math.ceil(invoices.length / PER_PAGE));
  const safePage = Math.min(page, totalPages);
  const pageInvoices = invoices.slice((safePage - 1) * PER_PAGE, safePage * PER_PAGE);

  // Reset page when filters change
  useEffect(() => { setPage(1); }, [invoices.length]);

  return (
    <div className="bg-white border border-stone-200 rounded-2xl shadow-sm overflow-hidden">
      <div className="overflow-x-auto">
        <table className="w-full">
          <thead className="bg-stone-50 border-b border-stone-200">
            <tr>
              <th className="text-left px-4 py-3 text-xs tracking-widest uppercase text-stone-500 font-semibold">Recibo</th>
              <th className="text-left px-4 py-3 text-xs tracking-widest uppercase text-stone-500 font-semibold">Cliente</th>
              <th className="text-left px-4 py-3 text-xs tracking-widest uppercase text-stone-500 font-semibold">Fecha</th>
              <th className="text-left px-4 py-3 text-xs tracking-widest uppercase text-stone-500 font-semibold">Estado</th>
              <th className="text-right px-4 py-3 text-xs tracking-widest uppercase text-stone-500 font-semibold">Total</th>
              <th className="text-right px-4 py-3 text-xs tracking-widest uppercase text-stone-500 font-semibold">Saldo</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-stone-100">
            {pageInvoices.map(inv => {
              const c = clientMap[inv.clientId];
              const stateInfo = INVOICE_STATES[inv.state];
              return (
                <tr key={inv.id} onClick={() => onSelect(inv)} className="hover:bg-orange-50 cursor-pointer">
                  <td className="px-4 py-3">
                    <span className="font-mono text-xs font-semibold text-stone-700">{inv.number}</span>
                  </td>
                  <td className="px-4 py-3">
                    <div className="text-sm font-semibold truncate">{c ? c.name : "—"}</div>
                    <div className="text-xs text-stone-500 font-mono">{c ? c.cedula : ""}</div>
                  </td>
                  <td className="px-4 py-3 text-sm text-stone-600 whitespace-nowrap">{inv.issueDate}</td>
                  <td className="px-4 py-3">
                    <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded text-xs font-bold ${stateInfo.badge}`}>
                      {stateInfo.label}
                    </span>
                  </td>
                  <td className="px-4 py-3 text-right font-mono font-semibold text-sm">
                    ${(inv.total ?? 0).toLocaleString()}
                  </td>
                  <td className={`px-4 py-3 text-right font-mono font-semibold text-sm ${
                    inv.balance > 0 ? "text-red-700" : "text-stone-400"
                  }`}>
                    {inv.balance > 0 ? `$${(inv.balance ?? 0).toLocaleString()}` : "—"}
                  </td>
                </tr>
              );
            })}
            {invoices.length === 0 && (
              <tr>
                <td colSpan={6} className="px-4 py-12 text-center text-stone-400 text-sm">
                  Sin recibos para mostrar.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Paginación — solo si hay más de PER_PAGE */}
      {totalPages > 1 && (
        <div className="px-4 py-3 border-t border-stone-200 bg-stone-50 flex items-center justify-between">
          <button
            onClick={() => setPage(p => Math.max(1, p - 1))}
            disabled={safePage <= 1}
            className="flex items-center gap-1 px-3 py-1.5 rounded-lg text-xs font-semibold border border-stone-200 hover:border-orange-300 transition disabled:opacity-40 disabled:cursor-not-allowed"
          >
            <ChevronLeft size={12} /> Anterior
          </button>
          <div className="flex items-center gap-1.5 text-xs text-stone-600">
            <span className="font-bold text-orange-700">
              {(safePage - 1) * PER_PAGE + 1}–{Math.min(safePage * PER_PAGE, invoices.length)}
            </span>
            de <span className="font-bold">{invoices.length}</span> recibos
            <span className="text-stone-400 ml-1">· Página {safePage} de {totalPages}</span>
          </div>
          <button
            onClick={() => setPage(p => Math.min(totalPages, p + 1))}
            disabled={safePage >= totalPages}
            className="flex items-center gap-1 px-3 py-1.5 rounded-lg text-xs font-semibold border border-stone-200 hover:border-orange-300 transition disabled:opacity-40 disabled:cursor-not-allowed"
          >
            Siguiente <ChevronRight size={12} />
          </button>
        </div>
      )}
    </div>
  );
}

// ========== HISTÓRICO (read-only) ==========

function SalesHistory({ invoices, clientMap, onSelect, paymentPlans = [] }) {
  // Vista: "list" (cards expandidas, como antes) | "table" (compacta, muchos a la vez)
  const [viewMode, setViewMode] = useState("list");

  // === Configuración de la vista tabla ===
  // Columnas visibles — el admin puede ocultar lo que no necesite.
  const [visibleCols, setVisibleCols] = useState({
    number: true, client: true, date: true, state: true, payments: true, vouchers: true, total: true,
  });
  // Orden — key (qué columna) + dir (asc | desc)
  const [sortKey, setSortKey] = useState("date");
  const [sortDir, setSortDir] = useState("desc");
  // Dropdown de filtro de columnas
  const [showColMenu, setShowColMenu] = useState(false);

  // Mapear plan por recibo para enriquecer cada card
  const planByInvoice = useMemo(() => {
    const m = {};
    paymentPlans.forEach(p => {
      // Mostramos planes activos o completados (excluimos eliminados)
      if (p.status !== "deleted") m[p.invoiceId] = p;
    });
    return m;
  }, [paymentPlans]);

  const sorted = useMemo(() => {
    return [...invoices].sort((a, b) => {
      const aDate = a.finalizedAt || (a.payments?.[a.payments.length - 1]?.date) || a.issueDate || "";
      const bDate = b.finalizedAt || (b.payments?.[b.payments.length - 1]?.date) || b.issueDate || "";
      return bDate.localeCompare(aDate);
    });
  }, [invoices]);

  if (sorted.length === 0) {
    return (
      <div className="space-y-3">
        <div className="bg-stone-100 border border-stone-200 rounded-xl p-3 flex items-center gap-2 text-xs text-stone-600">
          <Lock size={13} className="flex-shrink-0" />
          <span>El histórico es solo lectura. Las recibos pagadas y finalizadas se conservan inalteradas para auditoría.</span>
        </div>
        <div className="bg-white border border-stone-200 rounded-2xl p-12 text-center">
          <History size={32} className="text-stone-300 mx-auto mb-3" />
          <div className="text-base font-semibold text-stone-700">Aún no hay recibos en histórico</div>
          <div className="text-sm text-stone-500 mt-1">
            Las recibos aparecerán aquí cuando pasen a <strong>Pagado</strong> o <strong>Finalizado</strong>.
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-3">
      <div className="bg-stone-100 border border-stone-200 rounded-xl p-3 flex items-center gap-2 text-xs text-stone-600">
        <Lock size={13} className="flex-shrink-0" />
        <span className="flex-1">El histórico es solo lectura. Las recibos pagadas y finalizadas se conservan inalteradas para auditoría.</span>
        {/* Filtro de columnas — solo en vista tabla */}
        {viewMode === "table" && (
          <div className="relative">
            <button
              onClick={() => setShowColMenu(v => !v)}
              title="Mostrar / ocultar columnas"
              className={`flex items-center gap-1 px-2 h-7 rounded text-[10px] font-semibold uppercase tracking-wider transition ${
                showColMenu ? "bg-stone-900 text-white" : "bg-white border border-stone-200 text-stone-600 hover:border-stone-400"
              }`}
            >
              <Filter size={11} /> Columnas
            </button>
            {showColMenu && (
              <>
                <div onClick={() => setShowColMenu(false)} className="fixed inset-0 z-30"></div>
                <div className="absolute right-0 top-9 w-52 bg-white border border-stone-200 rounded-xl shadow-2xl z-40 overflow-hidden">
                  <div className="px-3 py-2 border-b border-stone-100 text-[10px] tracking-widest uppercase text-stone-500 font-bold">
                    Columnas visibles
                  </div>
                  {[
                    { id: "number",    label: "Recibo" },
                    { id: "client",    label: "Cliente" },
                    { id: "date",      label: "Fecha cerrada" },
                    { id: "state",     label: "Estado" },
                    { id: "payments",  label: "Pagos" },
                    { id: "vouchers",  label: "Comprobantes" },
                    { id: "total",     label: "Total" },
                  ].map(col => (
                    <label key={col.id} className="flex items-center gap-2 px-3 py-2 hover:bg-stone-50 cursor-pointer transition">
                      <input
                        type="checkbox"
                        checked={!!visibleCols[col.id]}
                        onChange={(e) => setVisibleCols(prev => ({ ...prev, [col.id]: e.target.checked }))}
                        className="w-3.5 h-3.5 accent-orange-600"
                      />
                      <span className="text-xs text-stone-700 flex-1">{col.label}</span>
                    </label>
                  ))}
                  <div className="border-t border-stone-100 px-3 py-1.5 flex gap-1.5">
                    <button
                      onClick={() => setVisibleCols({ number: true, client: true, date: true, state: true, payments: true, vouchers: true, total: true })}
                      className="flex-1 px-2 py-1 rounded text-[10px] font-semibold bg-stone-100 hover:bg-stone-200 text-stone-700 transition"
                    >
                      Mostrar todas
                    </button>
                  </div>
                </div>
              </>
            )}
          </div>
        )}
        {/* Toggle Vista: Lista / Tabla */}
        <div className="flex items-center gap-0.5 bg-white border border-stone-200 rounded-lg p-0.5 flex-shrink-0">
          <button
            onClick={() => setViewMode("list")}
            title="Vista de lista (expandida)"
            className={`w-7 h-7 rounded grid place-items-center transition ${
              viewMode === "list" ? "bg-stone-900 text-white" : "text-stone-500 hover:bg-stone-100"
            }`}
          >
            <Menu size={12} />
          </button>
          <button
            onClick={() => setViewMode("table")}
            title="Vista de tabla (compacta)"
            className={`w-7 h-7 rounded grid place-items-center transition ${
              viewMode === "table" ? "bg-stone-900 text-white" : "text-stone-500 hover:bg-stone-100"
            }`}
          >
            <Table size={12} />
          </button>
        </div>
      </div>

      {/* === VISTA TABLA — Compacta, varios elementos a la vez === */}
      {viewMode === "table" && (() => {
        // Helper para extraer la fecha de cierre (se repite en sort + render)
        const closeDateOf = (inv) => inv.finalizedAt || (inv.payments?.[inv.payments.length - 1]?.date) || inv.issueDate || "";
        // Helper para extraer el número de pagos
        const paymentCountOf = (inv) => {
          const plan = planByInvoice[inv.id];
          return plan ? plan.installments.filter(i => i.paid).length : (inv.payments || []).length;
        };
        // Helper para contar comprobantes (vouchers) registrados vs pagos hechos
        const voucherCountOf = (inv) => {
          const plan = planByInvoice[inv.id];
          if (plan) {
            const paid = plan.installments.filter(i => i.paid);
            return { withVoucher: paid.filter(i => i.voucher).length, total: paid.length };
          }
          const pays = inv.payments || [];
          return { withVoucher: pays.filter(p => p.voucher).length, total: pays.length };
        };
        // Orden dinámico por la columna seleccionada
        const tableData = [...sorted].sort((a, b) => {
          let cmp = 0;
          if (sortKey === "number") cmp = (a.number || "").localeCompare(b.number || "");
          else if (sortKey === "client") cmp = (clientMap[a.clientId]?.name || "").localeCompare(clientMap[b.clientId]?.name || "");
          else if (sortKey === "date") cmp = closeDateOf(a).localeCompare(closeDateOf(b));
          else if (sortKey === "state") cmp = (a.state || "").localeCompare(b.state || "");
          else if (sortKey === "payments") cmp = paymentCountOf(a) - paymentCountOf(b);
          else if (sortKey === "vouchers") cmp = voucherCountOf(a).withVoucher - voucherCountOf(b).withVoucher;
          else if (sortKey === "total") cmp = (a.total || 0) - (b.total || 0);
          return sortDir === "desc" ? -cmp : cmp;
        });

        // Cabecera clickeable
        const SortHeader = ({ id, label, align = "left" }) => {
          if (!visibleCols[id]) return null;
          const active = sortKey === id;
          return (
            <th
              onClick={() => {
                if (active) {
                  setSortDir(d => d === "asc" ? "desc" : "asc");
                } else {
                  setSortKey(id);
                  setSortDir("desc");
                }
              }}
              className={`px-3 py-2.5 font-semibold cursor-pointer select-none hover:bg-stone-100 transition ${
                align === "right" ? "text-right" : "text-left"
              } ${active ? "text-stone-900" : "text-stone-500"}`}
            >
              <span className={`inline-flex items-center gap-1 ${align === "right" ? "flex-row-reverse" : ""}`}>
                {label}
                {active && (
                  sortDir === "desc"
                    ? <ChevronDown size={11} strokeWidth={2.5} />
                    : <ChevronUp size={11} strokeWidth={2.5} />
                )}
              </span>
            </th>
          );
        };

        return (
          <div className="bg-white border border-stone-200 rounded-2xl shadow-sm overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead className="bg-stone-50 border-b border-stone-200">
                  <tr className="text-xs tracking-widest uppercase">
                    <SortHeader id="number" label="Recibo" />
                    <SortHeader id="client" label="Cliente" />
                    <SortHeader id="date" label="Cerrada" />
                    <SortHeader id="state" label="Estado" />
                    <SortHeader id="payments" label="Pagos" />
                    <SortHeader id="vouchers" label="Comprobantes" />
                    <SortHeader id="total" label="Total" align="right" />
                  </tr>
                </thead>
                <tbody className="divide-y divide-stone-100">
                  {tableData.map(inv => {
                    const c = clientMap[inv.clientId];
                    const stateInfo = INVOICE_STATES[inv.state];
                    const plan = planByInvoice[inv.id];
                    const closeDate = closeDateOf(inv) || "—";
                    const paymentCount = paymentCountOf(inv);
                    const initials = c ? c.name.split(" ").slice(0, 2).map(s => s[0]).join("").toUpperCase() : "??";
                    return (
                      <tr
                        key={inv.id}
                        onClick={() => onSelect(inv)}
                        className="hover:bg-stone-50 cursor-pointer transition"
                      >
                        {visibleCols.number && (
                          <td className="px-3 py-2.5 font-mono text-xs font-bold text-stone-800">{inv.number}</td>
                        )}
                        {visibleCols.client && (
                          <td className="px-3 py-2.5">
                            <div className="flex items-center gap-2 min-w-0">
                              <div className={`w-6 h-6 rounded-md grid place-items-center text-white text-[9px] font-bold flex-shrink-0 ${
                                c?.isOrg ? "bg-gradient-to-br from-stone-700 to-stone-900" : "bg-gradient-to-br from-orange-500 to-orange-700"
                              }`}>
                                {initials}
                              </div>
                              <span className="font-semibold text-stone-800 truncate text-xs">{c ? c.name : "—"}</span>
                            </div>
                          </td>
                        )}
                        {visibleCols.date && (
                          <td className="px-3 py-2.5 text-xs text-stone-600 font-mono whitespace-nowrap">{closeDate}</td>
                        )}
                        {visibleCols.state && (
                          <td className="px-3 py-2.5">
                            <span className={`inline-flex items-center gap-1 px-1.5 py-0.5 rounded text-[10px] font-bold uppercase ${stateInfo.badge}`}>
                              {stateInfo.label}
                            </span>
                            {plan && (
                              <span className="ml-1 inline-flex items-center gap-1 px-1.5 py-0.5 rounded text-[10px] font-bold bg-purple-100 text-purple-700">
                                <Calendar size={8} /> Plan
                              </span>
                            )}
                          </td>
                        )}
                        {visibleCols.payments && (
                          <td className="px-3 py-2.5 text-xs text-stone-600">
                            {paymentCount} pago{paymentCount !== 1 ? "s" : ""}
                          </td>
                        )}
                        {visibleCols.vouchers && (() => {
                          // Recolectar los comprobantes (vouchers) registrados
                          const plan = planByInvoice[inv.id];
                          const sources = plan ? plan.installments.filter(i => i.paid) : (inv.payments || []);
                          const withVoucher = sources.filter(s => s.voucher);
                          if (sources.length === 0) {
                            return <td className="px-3 py-2.5 text-xs text-stone-400 italic">—</td>;
                          }
                          if (withVoucher.length === 0) {
                            return (
                              <td className="px-3 py-2.5 text-xs text-stone-400 italic">
                                Sin registrar
                              </td>
                            );
                          }
                          return (
                            <td className="px-3 py-2.5">
                              <div className="flex flex-wrap items-center gap-x-2 gap-y-0.5">
                                {withVoucher.map((s, i) => (
                                  <span
                                    key={i}
                                    title={`${s.method || "Pago"} · $${(s.amount || 0).toLocaleString()}`}
                                    className="font-mono text-sm font-semibold text-stone-800"
                                  >
                                    {s.voucher}
                                  </span>
                                ))}
                                {withVoucher.length < sources.length && (
                                  <span
                                    title={`Faltan ${sources.length - withVoucher.length} comprobante(s) por registrar`}
                                    className="text-xs text-amber-600 italic"
                                  >
                                    +{sources.length - withVoucher.length} sin reg.
                                  </span>
                                )}
                              </div>
                            </td>
                          );
                        })()}
                        {visibleCols.total && (
                          <td className="px-3 py-2.5 text-right font-mono font-bold text-emerald-700 whitespace-nowrap">
                            ${(inv.total ?? 0).toLocaleString()}
                          </td>
                        )}
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>
        );
      })()}

      {/* === VISTA LISTA — Cards expandidas con desglose de pagos === */}
      {viewMode === "list" && sorted.map(inv => {
        const c = clientMap[inv.clientId];
        const plan = planByInvoice[inv.id];
        const stateInfo = INVOICE_STATES[inv.state];
        const initials = c ? c.name.split(" ").slice(0, 2).map(s => s[0]).join("").toUpperCase() : "??";
        const closeDate = inv.finalizedAt || (inv.payments?.[inv.payments.length - 1]?.date) || inv.issueDate || "";

        // Decidir qué lista de comprobantes mostrar:
        //  - Si hay plan: mostramos las cuotas (cada una con su voucher o "no se registró")
        //  - Si no hay plan: mostramos los pagos directos
        const usePlanView = !!plan;
        const items = usePlanView
          ? plan.installments
          : inv.payments;

        return (
          <div key={inv.id} className="bg-white border border-stone-200 rounded-2xl shadow-sm overflow-hidden">
            {/* Header de la recibo */}
            <button
              onClick={() => onSelect(inv)}
              className="w-full p-4 border-b border-stone-200 flex items-center gap-3 flex-wrap hover:bg-stone-50 transition text-left"
            >
              <div className={`w-10 h-10 rounded-xl grid place-items-center text-white text-xs font-bold flex-shrink-0 ${
                c?.isOrg ? "bg-gradient-to-br from-stone-700 to-stone-900" : "bg-gradient-to-br from-orange-500 to-orange-700"
              }`}>
                {initials}
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2 flex-wrap">
                  <span className="font-semibold text-sm truncate">{c ? c.name : "—"}</span>
                  <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded text-xs font-bold ${stateInfo.badge}`}>
                    {stateInfo.label}
                  </span>
                  {plan && (() => {
                    const isComplete = plan.status === "completed" ||
                      (plan.installments.length > 0 && plan.installments.every(i => i.paid));
                    return (
                      <span className={`text-xs font-bold px-2 py-0.5 rounded-full inline-flex items-center gap-1 ${
                        isComplete ? "bg-emerald-100 text-emerald-700" : "bg-purple-100 text-purple-700"
                      }`}>
                        <Calendar size={9} /> Plan {isComplete ? "completado" : "activo"}
                      </span>
                    );
                  })()}
                </div>
                <div className="text-xs text-stone-500 font-mono mt-0.5">
                  {inv.number} · Cerrada {closeDate}
                </div>
              </div>
              <div className="text-right">
                <div className="text-xs text-stone-400">Total</div>
                <div className="font-serif text-lg font-bold">${(inv.total ?? 0).toLocaleString()}</div>
              </div>
            </button>

            {/* Lista de comprobantes */}
            <div className="p-3 bg-stone-50">
              {items.length === 0 ? (
                <div className="text-xs text-stone-500 italic text-center py-2">
                  Esta recibo no tiene pagos registrados.
                </div>
              ) : (
                <>
                  <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold mb-2">
                    {usePlanView ? `Plan de pago · ${items.length} cuota${items.length !== 1 ? "s" : ""}` : `Pagos · ${items.length}`}
                  </div>
                  <div className="space-y-1.5">
                    {items.map((it, idx) => {
                      // Para items del plan: { number, amount, paid, paidDate, voucher, method, dueDate }
                      // Para items de pago directo: { id, date, amount, method, note, voucher }
                      const label = usePlanView
                        ? `Cuota ${it.number}`
                        : it.method;
                      const dateLabel = usePlanView
                        ? (it.paid ? `Pagada el ${it.paidDate}${it.method ? ` · ${it.method}` : ""}` : `Pendiente · vence ${it.dueDate}`)
                        : it.date + (it.note ? ` · ${it.note}` : "");
                      const isPaid = usePlanView ? it.paid : true;
                      const voucher = it.voucher;
                      return (
                        <div key={it.id || idx} className="bg-white rounded-lg border border-stone-200 p-2.5 flex items-start gap-2.5 text-xs">
                          <div className={`w-7 h-7 rounded-full grid place-items-center flex-shrink-0 ${
                            isPaid ? "bg-emerald-500 text-white" : "bg-stone-100 text-stone-500 border border-stone-200"
                          }`}>
                            {isPaid ? <Check size={12} strokeWidth={3} /> : <Clock size={12} />}
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-2 flex-wrap">
                              <span className="font-semibold text-stone-800">{label}</span>
                              <span className="font-mono font-bold text-stone-700">${it.amount.toLocaleString()}</span>
                            </div>
                            <div className="text-stone-500 truncate mt-0.5">{dateLabel}</div>
                            {isPaid && (
                              voucher ? (
                                <div className="mt-1 inline-flex items-center gap-1 px-1.5 py-0.5 rounded bg-emerald-100 text-emerald-800 font-mono">
                                  <Receipt size={10} /> {voucher}
                                </div>
                              ) : (
                                <div className="mt-1 text-xs text-stone-400 italic flex items-center gap-1">
                                  <AlertCircle size={10} /> No se registró comprobante
                                </div>
                              )
                            )}
                          </div>
                        </div>
                      );
                    })}
                  </div>
                </>
              )}
            </div>
          </div>
        );
      })}
    </div>
  );
}

// ========== DEUDORES ==========

function SalesDebtors({ invoices, clientMap, onSelect, onCreatePlan, plansByInvoice = {} }) {
  const totalDebt = invoices.reduce((s, i) => s + i.balance, 0);

  // Agrupar por cliente
  const byClient = useMemo(() => {
    const m = {};
    invoices.forEach(inv => {
      if (!m[inv.clientId]) m[inv.clientId] = [];
      m[inv.clientId].push(inv);
    });
    return m;
  }, [invoices]);

  return (
    <div className="space-y-3">
      <div className="bg-red-50 border border-red-200 rounded-2xl p-4 flex items-start gap-3">
        <div className="w-10 h-10 rounded-xl bg-red-600 text-white grid place-items-center flex-shrink-0">
          <AlertTriangle size={18} />
        </div>
        <div className="flex-1">
          <div className="font-serif text-2xl font-semibold text-red-900 leading-none">
            ${totalDebt.toLocaleString()} <span className="text-sm font-normal">en deuda activa</span>
          </div>
          <div className="text-sm text-red-700 mt-1">
            {invoices.length} recibo{invoices.length !== 1 ? "s" : ""} sin saldo completo · {Object.keys(byClient).length} cliente{Object.keys(byClient).length !== 1 ? "s" : ""}
          </div>
        </div>
      </div>

      {Object.keys(byClient).length === 0 && (
        <div className="bg-white border border-stone-200 rounded-2xl p-12 text-center">
          <Check size={32} className="text-emerald-500 mx-auto mb-3" strokeWidth={2.5} />
          <div className="text-base font-semibold text-stone-700">¡No hay deudas!</div>
          <div className="text-sm text-stone-500 mt-1">Todas las recibos están pagadas.</div>
        </div>
      )}

      {Object.entries(byClient).map(([clientId, list]) => {
        const c = clientMap[clientId];
        const clientDebt = list.reduce((s, i) => s + i.balance, 0);
        const initials = c ? c.name.split(" ").slice(0, 2).map(s => s[0]).join("").toUpperCase() : "??";
        return (
          <div key={clientId} className="bg-white border border-red-200 rounded-2xl shadow-sm overflow-hidden">
            <div className="bg-red-50 px-4 py-3 flex items-center gap-3 border-b border-red-200">
              <div className={`w-10 h-10 rounded-xl grid place-items-center text-white text-xs font-bold ${
                c?.isOrg ? "bg-gradient-to-br from-stone-700 to-stone-900" : "bg-gradient-to-br from-orange-500 to-orange-700"
              }`}>
                {initials}
              </div>
              <div className="flex-1 min-w-0">
                <div className="font-semibold text-sm truncate">{c ? c.name : "Cliente desconocido"}</div>
                <div className="text-xs text-stone-500">
                  {list.length} recibo{list.length !== 1 ? "s" : ""} pendiente{list.length !== 1 ? "s" : ""}
                </div>
              </div>
              <div className="text-right">
                <div className="text-xs tracking-widest uppercase text-red-700 font-semibold">Debe</div>
                <div className="font-serif text-xl font-bold text-red-700 leading-none">
                  ${clientDebt.toLocaleString()}
                </div>
              </div>
            </div>
            <div className="divide-y divide-stone-100">
              {list.map(inv => {
                const stateInfo = INVOICE_STATES[inv.state];
                return (
                  <div key={inv.id} className="p-3 flex items-center gap-3 flex-wrap">
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 flex-wrap">
                        <span className="font-mono text-xs font-semibold text-stone-700">{inv.number}</span>
                        <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded text-xs font-bold ${stateInfo.badge}`}>
                          {stateInfo.label}
                        </span>
                        {plansByInvoice[inv.id] && (
                          <span className="text-xs font-bold px-2 py-0.5 rounded-full bg-purple-100 text-purple-700 inline-flex items-center gap-1">
                            <Calendar size={9} /> En plan
                          </span>
                        )}
                      </div>
                      <div className="text-xs text-stone-500 mt-0.5">
                        Emitida {inv.issueDate} · Vence {inv.dueDate}
                      </div>
                    </div>
                    <div className="text-right">
                      <div className="text-xs text-stone-400">Saldo</div>
                      <div className="font-mono font-bold text-red-700">
                        ${(inv.balance ?? 0).toLocaleString()}
                      </div>
                    </div>
                    <div className="flex gap-1.5 flex-shrink-0">
                      <button
                        onClick={() => onSelect(inv)}
                        className="flex items-center gap-1 px-2.5 py-1.5 rounded-lg bg-white border border-stone-200 hover:border-orange-400 text-stone-700 hover:text-orange-700 text-xs font-semibold transition"
                        title="Ver detalle de la recibo"
                      >
                        <Eye size={11} /> Detalle
                      </button>
                      <button
                        onClick={() => onSelect(inv)}
                        className="flex items-center gap-1 px-3 py-1.5 rounded-lg bg-emerald-500 hover:bg-emerald-600 text-white text-xs font-semibold transition"
                      >
                        <DollarSign size={11} /> Abonar
                      </button>
                      <button
                        onClick={() => onCreatePlan(inv)}
                        disabled={Boolean(plansByInvoice[inv.id])}
                        title={plansByInvoice[inv.id] ? "Esta recibo ya tiene un plan activo. Elimínalo desde la pestaña Planes para crear uno nuevo." : "Crear plan de pago"}
                        className={`flex items-center gap-1 px-3 py-1.5 rounded-lg text-xs font-semibold transition ${
                          plansByInvoice[inv.id]
                            ? "bg-stone-100 border border-stone-200 text-stone-400 cursor-not-allowed"
                            : "bg-white border border-stone-200 hover:border-orange-400 text-stone-700 hover:text-orange-700"
                        }`}
                      >
                        <Calendar size={11} /> Plan
                      </button>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        );
      })}
    </div>
  );
}

// ========== PLANES DE PAGO ==========

function SalesPaymentPlans({ plans, invoices, clientMap, onPayInstallment, onDeletePlan }) {
  const [voucherTarget, setVoucherTarget] = useState(null); // { planId, instId, instNumber, amount }
  const [confirmDeleteId, setConfirmDeleteId] = useState(null);

  const invoiceMap = useMemo(() => {
    const m = {};
    invoices.forEach(i => { m[i.id] = i; });
    return m;
  }, [invoices]);

  // Solo mostrar planes activos (no eliminados ni completados — los completados pasan al histórico)
  // También filtramos planes donde todas las cuotas están pagadas pero status no se actualizó (datos seed/legacy)
  const visiblePlans = plans.filter(p => {
    if (p.status === "deleted" || p.status === "completed") return false;
    if (p.installments.length > 0 && p.installments.every(i => i.paid)) return false;
    return true;
  });

  return (
    <div className="space-y-3">
      {visiblePlans.length === 0 && (
        <div className="bg-white border border-stone-200 rounded-2xl p-12 text-center">
          <Calendar size={32} className="text-stone-300 mx-auto mb-3" />
          <div className="text-base font-semibold text-stone-700">No hay planes de pago activos</div>
          <div className="text-sm text-stone-500 mt-1">
            Crea un plan desde la pestaña Deudores para cualquier deuda activa.
          </div>
        </div>
      )}
      {visiblePlans.map(plan => {
        const c = clientMap[plan.clientId];
        const inv = invoiceMap[plan.invoiceId];
        const totalPaid = plan.installments.filter(i => i.paid).reduce((s, i) => s + i.amount, 0);
        const totalRemaining = plan.totalAmount - totalPaid;
        const progress = (totalPaid / plan.totalAmount) * 100;
        const initials = c ? c.name.split(" ").slice(0, 2).map(s => s[0]).join("").toUpperCase() : "??";

        return (
          <div key={plan.id} className="bg-white border border-stone-200 rounded-2xl shadow-sm overflow-hidden">
            <div className="p-4 border-b border-stone-200 flex items-center gap-3 flex-wrap">
              <div className={`w-10 h-10 rounded-xl grid place-items-center text-white text-xs font-bold flex-shrink-0 ${
                c?.isOrg ? "bg-gradient-to-br from-stone-700 to-stone-900" : "bg-gradient-to-br from-orange-500 to-orange-700"
              }`}>
                {initials}
              </div>
              <div className="flex-1 min-w-0">
                <div className="font-semibold text-sm truncate">{c ? c.name : "—"}</div>
                <div className="text-xs text-stone-500 font-mono">
                  Recibo {inv ? inv.number : "—"}
                </div>
              </div>
              <div className="text-right">
                <div className="text-xs text-stone-400">Plan total</div>
                <div className="font-serif text-lg font-bold">
                  ${plan.totalAmount.toLocaleString()}
                </div>
              </div>
              {onDeletePlan && totalRemaining > 0 && (
                <button
                  onClick={() => setConfirmDeleteId(plan.id)}
                  title="Eliminar plan. La deuda restante volverá como saldo pendiente."
                  className="w-8 h-8 rounded-lg bg-white border border-stone-200 hover:border-red-400 hover:bg-red-50 grid place-items-center text-stone-500 hover:text-red-600 transition flex-shrink-0"
                >
                  <Trash2 size={13} />
                </button>
              )}
            </div>

            {/* Progress bar */}
            <div className="px-4 py-3 bg-stone-50">
              <div className="flex items-center justify-between mb-1.5">
                <span className="text-xs text-stone-600">
                  Pagado <strong className="text-emerald-700">${totalPaid.toLocaleString()}</strong> de ${plan.totalAmount.toLocaleString()}
                </span>
                <span className="text-xs font-semibold text-stone-700">{progress.toFixed(0)}%</span>
              </div>
              <div className="h-2 bg-stone-200 rounded-full overflow-hidden">
                <div
                  className="h-full bg-gradient-to-r from-emerald-400 to-emerald-600 transition-all"
                  style={{ width: `${progress}%` }}
                ></div>
              </div>
              {totalRemaining > 0 && (
                <div className="text-xs text-stone-500 mt-1.5">
                  Restan <strong className="text-red-700">${totalRemaining.toLocaleString()}</strong> en {plan.installments.filter(i => !i.paid).length} cuota{plan.installments.filter(i => !i.paid).length !== 1 ? "s" : ""}
                </div>
              )}
            </div>

            {/* Cuotas */}
            <div className="divide-y divide-stone-100">
              {plan.installments.map(inst => {
                const dueDate = new Date(inst.dueDate);
                const isOverdue = !inst.paid && dueDate < new Date();
                return (
                  <div key={inst.id} className="p-3 flex items-center gap-3 flex-wrap">
                    <div className={`w-8 h-8 rounded-full grid place-items-center text-xs font-bold flex-shrink-0 ${
                      inst.paid
                        ? "bg-emerald-500 text-white"
                        : isOverdue
                          ? "bg-red-100 text-red-700 border-2 border-red-300"
                          : "bg-stone-100 text-stone-600"
                    }`}>
                      {inst.paid ? <Check size={13} strokeWidth={3} /> : inst.number}
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="text-sm font-semibold">
                        Cuota {inst.number}
                        {inst.paid && (
                          <span className="ml-2 text-xs font-normal text-emerald-700">
                            Pagada el {inst.paidDate}
                          </span>
                        )}
                        {isOverdue && (
                          <span className="ml-2 text-xs font-bold text-red-700">VENCIDA</span>
                        )}
                      </div>
                      <div className="text-xs text-stone-500 mt-0.5 flex items-center gap-2 flex-wrap">
                        <span>Vence: {inst.dueDate}</span>
                        {inst.paid && inst.voucher && (
                          <span className="inline-flex items-center gap-1 px-1.5 py-0.5 rounded bg-emerald-100 text-emerald-800 font-mono">
                            <Receipt size={10} /> {inst.voucher}
                          </span>
                        )}
                      </div>
                    </div>
                    <div className="font-mono font-bold text-stone-800">
                      ${inst.amount.toLocaleString()}
                    </div>
                    {!inst.paid && (
                      <button
                        onClick={() => setVoucherTarget({
                          planId: plan.id,
                          instId: inst.id,
                          instNumber: inst.number,
                          amount: inst.amount,
                          clientName: c ? c.name : "—",
                        })}
                        className="flex items-center gap-1 px-3 py-1.5 rounded-lg bg-emerald-500 hover:bg-emerald-600 text-white text-xs font-semibold transition"
                      >
                        <Check size={11} strokeWidth={2.5} /> Marcar pagada
                      </button>
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        );
      })}

      {/* Modal: solicitar comprobante antes de marcar cuota como pagada */}
      {voucherTarget && (
        <VoucherModal
          target={voucherTarget}
          onClose={() => setVoucherTarget(null)}
          onConfirm={(voucher, method) => {
            onPayInstallment(voucherTarget.planId, voucherTarget.instId, voucher, method);
            setVoucherTarget(null);
          }}
        />
      )}

      {/* Confirmación de eliminación de plan */}
      {confirmDeleteId && (() => {
        const planToDelete = plans.find(p => p.id === confirmDeleteId);
        if (!planToDelete) return null;
        const paidSoFar = planToDelete.installments.filter(i => i.paid).reduce((s, i) => s + i.amount, 0);
        const debtRemaining = planToDelete.totalAmount - paidSoFar;
        const c = clientMap[planToDelete.clientId];
        return (
          <div onClick={() => setConfirmDeleteId(null)} className="fixed inset-0 bg-stone-900 z-50 flex justify-center items-center p-4">
            <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden">
              <div className="p-5 border-b border-red-200 bg-red-50 flex items-center gap-3">
                <div className="w-10 h-10 rounded-xl bg-red-500 text-white grid place-items-center shadow-lg">
                  <AlertTriangle size={18} />
                </div>
                <div className="flex-1 min-w-0">
                  <div className="text-xs tracking-widest uppercase text-red-700 font-bold">
                    Eliminar plan de pago
                  </div>
                  <h3 className="font-serif text-lg font-semibold mt-0.5">{c?.name || "Cliente"}</h3>
                </div>
              </div>

              <div className="p-5 space-y-3">
                <div className="text-sm text-stone-700 leading-relaxed">
                  Vas a eliminar el plan de pago de esta recibo. Las cuotas pagadas seguirán contadas como abonos parciales, pero la deuda restante volverá a aparecer como saldo pendiente sin estructura de cuotas.
                </div>

                <div className="bg-stone-50 border border-stone-200 rounded-xl p-3 space-y-1.5 text-xs">
                  <div className="flex justify-between">
                    <span className="text-stone-500">Plan total</span>
                    <span className="font-mono font-semibold">${planToDelete.totalAmount.toLocaleString()}</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-stone-500">Pagado</span>
                    <span className="font-mono font-semibold text-emerald-700">${paidSoFar.toLocaleString()}</span>
                  </div>
                  <div className="flex justify-between pt-1.5 border-t border-stone-200">
                    <span className="font-semibold">Saldo que quedará pendiente</span>
                    <span className="font-mono font-bold text-red-700">${debtRemaining.toLocaleString()}</span>
                  </div>
                </div>

                <div className="bg-amber-50 border border-amber-200 rounded-xl p-3 text-xs text-amber-900 flex items-start gap-2">
                  <Info size={13} className="text-amber-700 flex-shrink-0 mt-0.5" />
                  <div>
                    Después podrás <strong>abonar el saldo directamente</strong> o <strong>crear un plan nuevo</strong> con cuotas distintas.
                  </div>
                </div>
              </div>

              <div className="p-3 border-t border-stone-200 bg-stone-50 flex gap-2">
                <button
                  onClick={() => setConfirmDeleteId(null)}
                  className="flex-1 px-3 py-2.5 rounded-xl text-sm font-semibold bg-white border border-stone-200 hover:border-stone-400 text-stone-700"
                >
                  Cancelar
                </button>
                <button
                  onClick={() => { onDeletePlan(confirmDeleteId); setConfirmDeleteId(null); }}
                  className="flex-1 px-3 py-2.5 rounded-xl text-sm font-semibold bg-red-500 hover:bg-red-600 text-white shadow"
                >
                  <Trash2 size={13} className="inline" /> Eliminar plan
                </button>
              </div>
            </div>
          </div>
        );
      })()}
    </div>
  );
}

// ========== MODAL: comprobante de pago ==========

function VoucherModal({ target, onClose, onConfirm }) {
  const [voucher, setVoucher] = useState("");
  const [method, setMethod] = useState("Transferencia");
  const [skipped, setSkipped] = useState(false);

  const canSubmit = skipped || voucher.trim().length > 0;

  return (
    <div onClick={onClose} className="fixed inset-0 bg-stone-900 z-50 flex justify-center items-start p-4 overflow-y-auto">
      <div onClick={(e) => e.stopPropagation()} className="bg-stone-50 rounded-2xl w-full max-w-md shadow-2xl my-8 overflow-hidden">
        <div className="p-5 border-b border-stone-200 bg-gradient-to-r from-white to-emerald-50 flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-emerald-500 text-white grid place-items-center shadow-lg">
            <Receipt size={20} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase text-emerald-700 font-semibold">
              Confirmar pago
            </div>
            <h3 className="font-serif text-lg font-semibold mt-0.5 truncate">
              Cuota {target.instNumber} · ${target.amount.toLocaleString()}
            </h3>
          </div>
          <button onClick={onClose} className="w-9 h-9 rounded-full bg-white border border-stone-200 grid place-items-center text-stone-600 hover:text-orange-700">
            <X size={16} />
          </button>
        </div>

        <div className="p-5 space-y-3.5">
          <div className="bg-white border border-stone-200 rounded-xl p-3 text-xs text-stone-600">
            Vas a marcar como pagada la <strong className="text-stone-800">cuota {target.instNumber}</strong> de{" "}
            <strong className="text-stone-800">{target.clientName}</strong>.
          </div>

          <Field label="Método de pago">
            <div className="flex gap-1.5 flex-wrap">
              {PAY_METHODS.map(m => (
                <button
                  key={m}
                  onClick={() => setMethod(m)}
                  className={`px-3 py-1.5 rounded-full text-xs font-semibold transition ${
                    method === m ? "bg-stone-900 text-white" : "bg-white text-stone-600 border border-stone-200"
                  }`}
                >
                  {m}
                </button>
              ))}
            </div>
          </Field>

          <Field label="Número de comprobante o transacción *">
            <input
              value={voucher}
              onChange={(e) => { setVoucher(e.target.value); setSkipped(false); }}
              placeholder={method === "Efectivo" ? "Ej: REC-00284 (recibo de caja)" : "Ej: 4827193 (referencia bancaria)"}
              className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm font-mono outline-none focus:border-orange-500"
              autoFocus
              disabled={skipped}
            />
            <div className="text-xs text-stone-500 mt-1.5 leading-relaxed">
              Para efectivo, indica número de recibo de caja. Para transferencia/pago móvil, número de referencia bancaria.
            </div>
          </Field>

          <button
            onClick={() => { setSkipped(!skipped); if (!skipped) setVoucher(""); }}
            className={`w-full p-2.5 rounded-xl border flex items-center gap-2 text-xs transition ${
              skipped
                ? "bg-amber-50 border-amber-300 text-amber-900"
                : "bg-white border-stone-200 text-stone-600 hover:border-stone-300"
            }`}
          >
            <span className={`w-9 h-5 rounded-full relative transition flex-shrink-0 ${skipped ? "bg-amber-500" : "bg-stone-300"}`}>
              <span className={`absolute top-0.5 w-4 h-4 rounded-full bg-white shadow transition ${skipped ? "left-4" : "left-0.5"}`}></span>
            </span>
            <span className="text-left flex-1">
              <span className="font-semibold block">Registrar sin comprobante</span>
              <span className="text-xs opacity-80">Quedará pendiente de adjuntar</span>
            </span>
          </button>
        </div>

        <div className="p-3.5 px-5 border-t border-stone-200 bg-white flex justify-end gap-2">
          <button onClick={onClose} className="px-3 py-2 rounded-xl text-sm font-semibold bg-white text-stone-700 border border-stone-200">
            Cancelar
          </button>
          <button
            onClick={() => onConfirm(skipped ? null : voucher.trim(), method)}
            disabled={!canSubmit}
            className={`flex items-center gap-1.5 px-4 py-2 rounded-xl text-sm font-semibold bg-emerald-500 hover:bg-emerald-600 text-white transition ${
              canSubmit ? "" : "opacity-40 cursor-not-allowed"
            }`}
          >
            <Check size={14} strokeWidth={2.5} /> Confirmar pago
          </button>
        </div>
      </div>
    </div>
  );
}

// ========== MODAL: Detalle de recibo ==========

// === Catálogo de servicios para el InvoiceItemAdder ===
const INVOICE_SERVICE_CATALOG = [
  { id: "s-001", name: "Consulta general", price: 35, category: "Veterinaria" },
  { id: "s-002", name: "Consulta de control", price: 25, category: "Veterinaria" },
  { id: "s-003", name: "Vacuna polivalente DHPPi", price: 28, category: "Veterinaria" },
  { id: "s-004", name: "Vacuna antirrábica", price: 22, category: "Veterinaria" },
  { id: "s-005", name: "Vacuna triple felina", price: 30, category: "Veterinaria" },
  { id: "s-006", name: "Desparasitación interna", price: 18, category: "Veterinaria" },
  { id: "s-007", name: "Limpieza dental con anestesia", price: 95, category: "Veterinaria" },
  { id: "s-008", name: "Examen de laboratorio", price: 65, category: "Laboratorio" },
  { id: "s-009", name: "Ecografía abdominal", price: 80, category: "Veterinaria" },
  { id: "s-010", name: "Esterilización canina", price: 150, category: "Cirugía" },
  { id: "s-011", name: "Cirugía menor", price: 220, category: "Cirugía" },
  { id: "s-012", name: "Baño básico", price: 25, category: "Grooming" },
  { id: "s-013", name: "Baño + Corte completo", price: 45, category: "Grooming" },
  { id: "s-014", name: "Corte de uñas", price: 12, category: "Grooming" },
  { id: "s-015", name: "Spa completo", price: 65, category: "Grooming" },
];

// === Sub-component: añadir ítem a un recibo en borrador ===
// Modal compacto con tabs (Servicio / Producto / Medicina / Personalizado)
// + buscador de catálogo y entrada custom.
function InvoiceItemAdder({ onAdd, onCancel }) {
  const [mode, setMode] = useState("service"); // service | product | medicine | custom
  const [search, setSearch] = useState("");
  const [customDesc, setCustomDesc] = useState("");
  const [customQty, setCustomQty] = useState("1");
  const [customUnit, setCustomUnit] = useState("");

  const catalog = useMemo(() => {
    if (mode === "service") return INVOICE_SERVICE_CATALOG.map(s => ({
      key: s.id, description: s.name, unit: s.price, category: s.category, type: "service",
    }));
    if (mode === "product") return PRODUCT_CATALOG.map(p => ({
      key: p.id, description: p.name, unit: p.price, category: p.category, type: "product",
    }));
    if (mode === "medicine") return MEDICINE_CATALOG.map(m => ({
      key: m.id, description: m.name, unit: m.price, category: m.indication, type: "medicine",
      requiresRecipe: m.requiresRecipe, presentation: m.presentation,
    }));
    return [];
  }, [mode]);

  const filtered = useMemo(() => {
    const q = search.trim().toLowerCase();
    if (!q) return catalog;
    return catalog.filter(it =>
      it.description.toLowerCase().includes(q) ||
      (it.category || "").toLowerCase().includes(q)
    );
  }, [catalog, search]);

  const handlePick = (it) => {
    onAdd({
      description: it.description,
      qty: 1,
      unit: it.unit,
      total: it.unit,
      type: it.type,
      requiresRecipe: it.requiresRecipe || false,
    });
  };

  const handleAddCustom = () => {
    const qty = Number(customQty) || 0;
    const unit = Number(customUnit) || 0;
    if (!customDesc.trim() || qty <= 0 || unit <= 0) return;
    onAdd({
      description: customDesc.trim(),
      qty,
      unit,
      total: qty * unit,
      type: "custom",
    });
  };

  const TABS = [
    { id: "service",  label: "Servicios",   Icon: Stethoscope,  color: "orange" },
    { id: "product",  label: "Productos",   Icon: ShoppingBag,  color: "blue" },
    { id: "medicine", label: "Medicinas",   Icon: Pill,         color: "purple" },
    { id: "custom",   label: "Personalizado", Icon: Plus,        color: "stone" },
  ];

  return (
    <div className="mt-2 pt-2 border-t border-stone-200 space-y-2">
      {/* Tabs */}
      <div className="grid grid-cols-4 gap-1">
        {TABS.map(t => {
          const Ic = t.Icon;
          const active = mode === t.id;
          const colorMap = {
            orange: active ? "bg-orange-600 text-white" : "bg-stone-100 text-stone-600 hover:bg-stone-200",
            blue:   active ? "bg-blue-600 text-white"   : "bg-stone-100 text-stone-600 hover:bg-stone-200",
            purple: active ? "bg-purple-600 text-white" : "bg-stone-100 text-stone-600 hover:bg-stone-200",
            stone:  active ? "bg-stone-700 text-white"  : "bg-stone-100 text-stone-600 hover:bg-stone-200",
          };
          return (
            <button
              key={t.id}
              onClick={() => { setMode(t.id); setSearch(""); }}
              className={`flex flex-col items-center gap-0.5 py-1.5 rounded text-[10px] font-semibold transition ${colorMap[t.color]}`}
            >
              <Ic size={12} />
              <span>{t.label}</span>
            </button>
          );
        })}
      </div>

      {/* Custom mode */}
      {mode === "custom" ? (
        <div className="space-y-1.5">
          <input
            value={customDesc}
            onChange={(e) => setCustomDesc(e.target.value)}
            placeholder="Descripción del ítem"
            autoFocus
            className="w-full px-2 py-1.5 bg-stone-50 border border-stone-200 rounded text-xs outline-none focus:border-orange-500 focus:bg-white"
          />
          <div className="flex items-center gap-1.5 text-xs">
            <input
              type="number"
              min="1"
              value={customQty}
              onChange={(e) => setCustomQty(e.target.value)}
              placeholder="Cant."
              className="w-14 px-1.5 py-1.5 bg-stone-50 border border-stone-200 rounded text-center font-mono outline-none focus:border-orange-500 focus:bg-white"
            />
            <span className="text-stone-400">×</span>
            <span className="text-stone-400">$</span>
            <input
              type="number"
              min="0"
              step="0.01"
              value={customUnit}
              onChange={(e) => setCustomUnit(e.target.value)}
              placeholder="Precio"
              className="flex-1 min-w-0 px-1.5 py-1.5 bg-stone-50 border border-stone-200 rounded text-right font-mono outline-none focus:border-orange-500 focus:bg-white"
            />
          </div>
          <div className="flex gap-1.5">
            <button
              onClick={onCancel}
              className="flex-1 px-2 py-1.5 rounded text-xs font-semibold bg-white border border-stone-200 text-stone-600 hover:border-stone-400"
            >
              Cancelar
            </button>
            <button
              onClick={handleAddCustom}
              disabled={!customDesc.trim() || Number(customQty) <= 0 || Number(customUnit) <= 0}
              className="flex-1 px-2 py-1.5 rounded text-xs font-semibold bg-orange-600 hover:bg-orange-700 text-white disabled:bg-stone-200 disabled:text-stone-400 disabled:cursor-not-allowed"
            >
              Agregar
            </button>
          </div>
        </div>
      ) : (
        <>
          {/* Buscador catálogo */}
          <div className="relative">
            <Search size={11} className="absolute left-2 top-1/2 -translate-y-1/2 text-stone-400" />
            <input
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder="Buscar en el catálogo..."
              autoFocus
              className="w-full pl-7 pr-2 py-1.5 bg-stone-50 border border-stone-200 rounded text-xs outline-none focus:border-orange-500 focus:bg-white"
            />
          </div>
          {/* Resultados */}
          <div className="max-h-56 overflow-y-auto space-y-1 -mx-1 px-1">
            {filtered.length === 0 ? (
              <div className="text-center py-4 text-xs text-stone-400 italic">
                Sin resultados
              </div>
            ) : (
              filtered.slice(0, 20).map(it => (
                <button
                  key={it.key}
                  onClick={() => handlePick(it)}
                  className="w-full flex items-center justify-between gap-2 p-2 rounded-lg bg-white border border-stone-200 hover:border-orange-400 hover:bg-orange-50 transition text-left group"
                >
                  <div className="flex-1 min-w-0">
                    <div className="text-xs font-semibold text-stone-800 truncate flex items-center gap-1">
                      {it.description}
                      {it.requiresRecipe && (
                        <span className="inline-flex items-center px-1 py-px rounded bg-purple-100 text-purple-700 text-[8px] font-bold uppercase">
                          Recipe
                        </span>
                      )}
                    </div>
                    {it.category && <div className="text-[10px] text-stone-500 truncate">{it.category}</div>}
                  </div>
                  <span className="text-xs font-mono font-bold text-orange-700 whitespace-nowrap">
                    ${it.unit.toFixed(2)}
                  </span>
                  <Plus size={11} className="text-stone-300 group-hover:text-orange-600 flex-shrink-0" />
                </button>
              ))
            )}
          </div>
          <button
            onClick={onCancel}
            className="w-full px-2 py-1 rounded text-xs font-semibold bg-white border border-stone-200 text-stone-600 hover:border-stone-400"
          >
            Cancelar
          </button>
        </>
      )}
    </div>
  );
}

function InvoiceDetailModal({ invoice, client, invoices = [], onClose, onPayment, onCreatePlan, onMessageClient, readOnly, setInvoices, paymentPlans = [], setPaymentPlans, onUpdateSelected }) {
  const [showHistory, setShowHistory] = useState(false);
  const [viewingRecipe, setViewingRecipe] = useState(null); // item con recipe a ver en detalle
  const stateInfo = INVOICE_STATES[invoice.state];
  const isDraft = invoice.state === "borrador";
  // Solo se permite editar items si está en borrador
  const canEdit = isDraft && !readOnly && setInvoices;

  // State para agregar item rápido
  const [showAddItem, setShowAddItem] = useState(false);
  const [newItemDesc, setNewItemDesc] = useState("");
  const [newItemQty, setNewItemQty] = useState("1");
  const [newItemUnit, setNewItemUnit] = useState("");

  // ¿La recibo ya tiene un plan asociado? (activo o completado, no eliminados)
  const activePlan = paymentPlans.find(p => p.invoiceId === invoice.id && p.status !== "deleted");
  // Plan completado: status explícito o todas las cuotas pagadas (compatibilidad con seed/legacy)
  const planIsCompleted = activePlan && (
    activePlan.status === "completed" ||
    (activePlan.installments.length > 0 && activePlan.installments.every(i => i.paid))
  );

  // Helper: recalcular totales después de cualquier cambio en items
  const recalc = (items) => {
    const subtotal = items.reduce((a, it) => a + it.total, 0);
    const tax = Math.round(subtotal * 0.16);
    const total = subtotal + tax;
    return { items, subtotal, tax, total };
  };

  const updateItem = (index, patch) => {
    setInvoices(prev => prev.map(inv => {
      if (inv.id !== invoice.id) return inv;
      const items = inv.items.map((it, i) => {
        if (i !== index) return it;
        const next = { ...it, ...patch };
        if (patch.qty !== undefined || patch.unit !== undefined) {
          next.total = (next.qty || 0) * (next.unit || 0);
        }
        return next;
      });
      const r = recalc(items);
      const newBalance = r.total - inv.paid;
      const updated = { ...inv, ...r, balance: newBalance };
      onUpdateSelected?.(updated);
      return updated;
    }));
  };

  const removeItem = (index) => {
    setInvoices(prev => prev.map(inv => {
      if (inv.id !== invoice.id) return inv;
      const items = inv.items.filter((_, i) => i !== index);
      const r = recalc(items);
      const newBalance = r.total - inv.paid;
      const updated = { ...inv, ...r, balance: newBalance };
      onUpdateSelected?.(updated);
      return updated;
    }));
  };

  const addItem = () => {
    const qty = Number(newItemQty) || 0;
    const unit = Number(newItemUnit) || 0;
    if (!newItemDesc.trim() || qty <= 0 || unit <= 0) return;
    const newItem = {
      description: newItemDesc.trim(),
      qty,
      unit,
      total: qty * unit,
    };
    setInvoices(prev => prev.map(inv => {
      if (inv.id !== invoice.id) return inv;
      const items = [...inv.items, newItem];
      const r = recalc(items);
      const newBalance = r.total - inv.paid;
      const updated = { ...inv, ...r, balance: newBalance };
      onUpdateSelected?.(updated);
      return updated;
    }));
    setNewItemDesc("");
    setNewItemQty("1");
    setNewItemUnit("");
    setShowAddItem(false);
  };

  // Emitir recibo: pasar de borrador a emitido (queda inmutable)
  const emit = () => {
    setInvoices(prev => prev.map(inv => {
      if (inv.id !== invoice.id) return inv;
      const updated = { ...inv, state: "emitido", issueDate: new Date().toISOString().slice(0, 10) };
      onUpdateSelected?.(updated);
      return updated;
    }));
  };

  // Finalizar: pasar de pagado → finalizado (servicios entregados, cierre del ciclo)
  const finalize = () => {
    setInvoices(prev => prev.map(inv => {
      if (inv.id !== invoice.id) return inv;
      const updated = { ...inv, state: "finalizado", finalizedAt: new Date().toISOString().slice(0, 10) };
      onUpdateSelected?.(updated);
      return updated;
    }));
  };

  // Estados clave para decidir qué botones mostrar
  const isPaid = invoice.state === "pagado";
  const isFinalized = invoice.state === "finalizado";
  const canFinalize = isPaid && setInvoices && !readOnly;

  return (
    <>
      {/* Backdrop sutil — solo en mobile, no oscurece el resto del CRM */}
      <div
        onClick={onClose}
        className="fixed inset-0 bg-stone-900 z-40 sm:hidden"
      />

      {/* Drawer lateral derecho. Ancho objetivo ~30% del viewport en pantallas
          amplias, con un mínimo legible para que en ventanas angostas (p.ej. el
          navegador a media pantalla) no ocupe todo el ancho. Se usa min()/max()
          de CSS para acotar el rango sin depender del breakpoint `sm`. */}
      <aside
        className="fixed top-0 right-0 bottom-0 bg-stone-50 z-50 shadow-2xl flex flex-col border-l border-stone-200"
        style={{ width: "min(92vw, max(30vw, 380px))" }}
      >
        {/* Header */}
        <div className="bg-white border-b border-stone-200 flex-shrink-0">
          <div className="p-4 flex items-center gap-3">
            <button
              onClick={onClose}
              className="w-9 h-9 rounded-lg bg-stone-100 hover:bg-stone-200 grid place-items-center text-stone-600 transition"
            >
              <X size={16} />
            </button>
            <div className="w-9 h-9 rounded-xl bg-gradient-to-br from-orange-500 to-orange-700 text-white grid place-items-center shadow flex-shrink-0">
              <Receipt size={16} />
            </div>
            <div className="flex-1 min-w-0">
              <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold flex items-center gap-2">
                Recibo
                {readOnly && <span className="text-stone-400 font-normal">· Solo lectura</span>}
              </div>
              <div className="font-serif text-base font-semibold mt-0.5 font-mono leading-tight">
                {invoice.number}
              </div>
            </div>
          </div>
        </div>

        {/* Body scrollable */}
        <div className="flex-1 overflow-y-auto p-4 space-y-3">
          {/* Cliente + estado en cards apiladas (mejor para columna estrecha) */}
          <div className="bg-white border border-stone-200 rounded-xl p-3">
            <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold mb-1">Cliente</div>
            <div className="flex items-center gap-2">
              <div className={`w-9 h-9 rounded-lg grid place-items-center text-white text-xs font-bold flex-shrink-0 ${
                client?.isOrg
                  ? "bg-gradient-to-br from-stone-700 to-stone-900"
                  : "bg-gradient-to-br from-orange-500 to-orange-700"
              }`}>
                {client ? client.name.split(" ").slice(0, 2).map(s => s[0]).join("").toUpperCase() : "?"}
              </div>
              <div className="flex-1 min-w-0">
                <div className="font-semibold text-sm truncate">{client ? client.name : "—"}</div>
                <div className="text-xs text-stone-500 font-mono truncate">{client ? client.cedula : ""}</div>
              </div>
              {/* Botón de historial del cliente */}
              {client && (
                <button
                  onClick={() => setShowHistory(!showHistory)}
                  title="Ver historial de servicios del cliente"
                  className={`w-8 h-8 rounded-lg grid place-items-center transition flex-shrink-0 ${
                    showHistory
                      ? "bg-orange-600 text-white"
                      : "bg-stone-100 hover:bg-orange-100 text-stone-500 hover:text-orange-700"
                  }`}
                >
                  <Search size={13} />
                </button>
              )}
            </div>

            {/* Panel de historial de servicios del cliente */}
            {showHistory && client && (() => {
              const clientInvoices = invoices
                .filter(inv => inv.clientId === client.id && inv.id !== invoice.id)
                .sort((a, b) => (b.issueDate || "").localeCompare(a.issueDate || ""));
              const allItems = clientInvoices.flatMap(inv =>
                (inv.items || []).map(it => ({ ...it, invoiceNumber: inv.number, invoiceDate: inv.issueDate, invoiceState: inv.state }))
              );
              return (
                <div className="mt-3 border-t border-stone-100 pt-3">
                  <div className="flex items-center justify-between mb-2">
                    <div className="text-xs font-bold text-stone-700 tracking-wide uppercase flex items-center gap-1.5">
                      <FileText size={11} /> Historial de servicios
                    </div>
                    <span className="text-[10px] font-bold px-1.5 py-px rounded-full bg-orange-100 text-orange-700">
                      {clientInvoices.length} recibo{clientInvoices.length !== 1 ? "s" : ""}
                    </span>
                  </div>
                  {clientInvoices.length === 0 ? (
                    <div className="text-xs text-stone-400 italic py-2 text-center">
                      Esta es la primera recibo del cliente.
                    </div>
                  ) : (
                    <div className="max-h-48 overflow-y-auto space-y-1.5 pr-1">
                      {clientInvoices.map(inv => (
                        <div key={inv.id} className="bg-stone-50 rounded-lg p-2 border border-stone-100">
                          <div className="flex items-center justify-between mb-1">
                            <span className="text-xs font-mono font-bold text-stone-700">{inv.number}</span>
                            <div className="flex items-center gap-1.5">
                              <span className="text-[10px] text-stone-400">{inv.issueDate}</span>
                              <InvoiceStateBadge state={inv.state} />
                            </div>
                          </div>
                          <div className="space-y-0.5">
                            {(inv.items || []).map((it, i) => (
                              <div key={i} className="flex items-center justify-between text-xs">
                                <span className="text-stone-600 truncate flex-1 min-w-0">{it.description}</span>
                                <span className="text-stone-700 font-semibold flex-shrink-0 ml-2">${(it.total || 0).toFixed(0)}</span>
                              </div>
                            ))}
                          </div>
                          <div className="text-right text-xs font-bold text-orange-700 mt-1">
                            Total: ${(inv.total || 0).toFixed(2)}
                          </div>
                        </div>
                      ))}
                      {/* Resumen */}
                      <div className="bg-orange-50 border border-orange-200 rounded-lg p-2 text-center">
                        <div className="text-xs text-orange-800">
                          <span className="font-bold">{allItems.length}</span> servicio{allItems.length !== 1 ? "s" : ""} en{" "}
                          <span className="font-bold">{clientInvoices.length}</span> recibo{clientInvoices.length !== 1 ? "s" : ""} ·{" "}
                          Histórico: <span className="font-bold">${clientInvoices.reduce((s, inv) => s + (inv.total || 0), 0).toFixed(2)}</span>
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              );
            })()}
          </div>

          <div className="bg-white border border-stone-200 rounded-xl p-3">
            <div className="flex items-center justify-between mb-2">
              <span className="text-xs tracking-widest uppercase text-stone-500 font-semibold">Estado</span>
              <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded text-xs font-bold ${stateInfo.badge}`}>
                {stateInfo.label}
              </span>
            </div>
            <div className="grid grid-cols-2 gap-2 text-xs">
              <div>
                <div className="text-stone-400">Emitida</div>
                <div className="font-semibold text-stone-700">{invoice.issueDate}</div>
              </div>
              <div>
                <div className="text-stone-400">Vence</div>
                <div className="font-semibold text-stone-700">{invoice.dueDate}</div>
              </div>
            </div>
          </div>

          {/* Banner: recibo modificada por propuesta aprobada */}
          {invoice.modifiedByProposal && (
            <div className="bg-emerald-50 border border-emerald-300 rounded-xl p-3 flex items-start gap-2.5">
              <div className="w-8 h-8 rounded-lg bg-emerald-500 text-white grid place-items-center flex-shrink-0">
                <Scissors size={13} strokeWidth={2} />
              </div>
              <div className="flex-1 min-w-0">
                <div className="text-xs tracking-widest uppercase text-emerald-700 font-bold">
                  Aumentada desde Grooming
                </div>
                <div className="text-xs text-emerald-900 mt-0.5 leading-relaxed">
                  Se agregaron insumos por <span className="font-mono font-bold">${invoice.modifiedByProposal.addedAmount?.toLocaleString()}</span> a partir de una propuesta aprobada.
                </div>
              </div>
            </div>
          )}

          {/* Banner: recibo creada desde propuesta */}
          {invoice.fromProposal && !invoice.modifiedByProposal && (
            <div className="bg-emerald-50 border border-emerald-300 rounded-xl p-3 flex items-start gap-2.5">
              <div className="w-8 h-8 rounded-lg bg-emerald-500 text-white grid place-items-center flex-shrink-0">
                <Scissors size={13} strokeWidth={2} />
              </div>
              <div className="flex-1 min-w-0">
                <div className="text-xs tracking-widest uppercase text-emerald-700 font-bold">
                  Generada desde Grooming
                </div>
                <div className="text-xs text-emerald-900 mt-0.5 leading-relaxed">
                  Esta recibo fue aprobada a partir de una propuesta del módulo de grooming.
                </div>
              </div>
            </div>
          )}

          {/* Items con desglose compacto */}
          <div className="bg-white border border-stone-200 rounded-xl p-3">
            <div className="flex items-center justify-between mb-2">
              <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold">Desglose</div>
              {canEdit && (
                <span className="text-xs font-bold px-2 py-0.5 rounded-full bg-amber-100 text-amber-800 inline-flex items-center gap-1">
                  <Edit3 size={9} /> Editable
                </span>
              )}
            </div>
            <div className="divide-y divide-stone-100">
              {invoice.items.map((it, i) => (
                <div key={i} className="py-2 first:pt-0">
                  {canEdit ? (
                    <div className="space-y-1.5">
                      <div className="flex items-start gap-2">
                        <input
                          value={it.description}
                          onChange={(e) => updateItem(i, { description: e.target.value })}
                          className="flex-1 min-w-0 px-2 py-1 bg-stone-50 border border-stone-200 rounded text-xs font-semibold outline-none focus:border-orange-500 focus:bg-white"
                        />
                        <button
                          onClick={() => removeItem(i)}
                          className="w-6 h-6 rounded grid place-items-center text-stone-400 hover:text-red-600 hover:bg-red-50 flex-shrink-0"
                          title="Eliminar item"
                        >
                          <X size={12} />
                        </button>
                      </div>
                      <div className="flex items-center gap-1.5 text-xs">
                        <input
                          type="number"
                          min="1"
                          value={it.qty}
                          onChange={(e) => updateItem(i, { qty: Number(e.target.value) || 0 })}
                          className="w-12 px-1.5 py-1 bg-stone-50 border border-stone-200 rounded text-center font-mono outline-none focus:border-orange-500 focus:bg-white"
                        />
                        <span className="text-stone-400">×</span>
                        <span className="text-stone-400">$</span>
                        <input
                          type="number"
                          min="0"
                          step="0.01"
                          value={it.unit}
                          onChange={(e) => updateItem(i, { unit: Number(e.target.value) || 0 })}
                          className="w-20 px-1.5 py-1 bg-stone-50 border border-stone-200 rounded text-right font-mono outline-none focus:border-orange-500 focus:bg-white"
                        />
                        <span className="ml-auto font-mono font-bold whitespace-nowrap">
                          ${(it.total ?? 0).toLocaleString()}
                        </span>
                      </div>
                      {/* Recipe attached (visible aún en modo edición) */}
                      {(it.recipe || it.recipePhoto || it.requiresRecipe) && (
                        <div className="bg-purple-50 border border-purple-200 rounded p-1.5 flex items-center gap-1.5">
                          <FileText size={10} className="text-purple-700 flex-shrink-0" />
                          <span className="text-[10px] font-bold text-purple-700 uppercase tracking-wider">Recipe</span>
                          {it.recipe?.medication && (
                            <span className="text-[10px] text-purple-900 truncate flex-1">
                              {it.recipe.medication}
                              {it.recipe.dose && ` · ${it.recipe.dose}`}
                            </span>
                          )}
                          <button
                            onClick={() => setViewingRecipe(it)}
                            title="Ver recipe completo"
                            className="w-5 h-5 rounded bg-purple-100 hover:bg-purple-200 text-purple-700 grid place-items-center transition flex-shrink-0"
                          >
                            <Search size={9} />
                          </button>
                        </div>
                      )}
                    </div>
                  ) : (
                    <div>
                      <div className="flex items-start justify-between gap-2">
                        <div className="min-w-0 flex-1">
                          <div className="font-semibold text-xs text-stone-800 leading-tight">{it.description}</div>
                          <div className="text-xs text-stone-500 mt-0.5">{it.qty} × ${(it.unit ?? 0).toLocaleString()}</div>
                        </div>
                        <span className="font-mono font-bold text-xs whitespace-nowrap">
                          ${(it.total ?? 0).toLocaleString()}
                        </span>
                      </div>
                      {/* Recipe adjunto al ítem (si es medicina con receta) */}
                      {(it.recipe || it.recipePhoto) && (
                        <div className="mt-1.5 bg-purple-50 border border-purple-200 rounded-lg p-2">
                          <div className="flex items-center justify-between mb-1">
                            <div className="text-[9px] tracking-widest uppercase text-purple-700 font-bold flex items-center gap-1">
                              <FileText size={9} /> Recipe adjunto
                              {it.requiresRecipe && <span className="text-red-600">(Requerido)</span>}
                            </div>
                            {/* Lupa para ver recipe en detalle */}
                            <button
                              onClick={() => setViewingRecipe(it)}
                              title="Ver recipe completo"
                              className="w-6 h-6 rounded-md bg-purple-100 hover:bg-purple-200 text-purple-700 grid place-items-center transition"
                            >
                              <Search size={11} />
                            </button>
                          </div>
                          {it.recipe && (
                            <div className="text-[11px] text-purple-900 space-y-0.5">
                              {it.recipe.medication && <div className="font-semibold">{it.recipe.medication}</div>}
                              <div className="text-purple-700">
                                {[it.recipe.dose, it.recipe.route, it.recipe.frequency, it.recipe.duration].filter(Boolean).join(" · ")}
                              </div>
                              {it.recipe.instructions && <div className="text-stone-600 italic">{it.recipe.instructions}</div>}
                            </div>
                          )}
                          {it.recipePhoto && (
                            <img
                              src={it.recipePhoto}
                              alt="Recipe"
                              onClick={() => setViewingRecipe(it)}
                              className="mt-1.5 w-full h-20 object-cover rounded border border-purple-200 cursor-pointer hover:opacity-90 transition"
                            />
                          )}
                        </div>
                      )}
                      {/* Indicador si requiere recipe pero no tiene */}
                      {it.requiresRecipe && !it.recipe && !it.recipePhoto && (
                        <div className="mt-1 flex items-center gap-1 text-[10px] text-red-600 font-semibold">
                          <AlertCircle size={10} /> Recipe requerido — sin adjuntar
                        </div>
                      )}
                    </div>
                  )}
                </div>
              ))}
            </div>

            {/* Agregar item rápido cuando está en borrador */}
            {canEdit && (
              <>
                {showAddItem ? (
                  <InvoiceItemAdder
                    onAdd={(item) => {
                      setInvoices(prev => prev.map(inv => {
                        if (inv.id !== invoice.id) return inv;
                        const items = [...inv.items, item];
                        const r = recalc(items);
                        const newBalance = r.total - inv.paid;
                        const updated = { ...inv, ...r, balance: newBalance };
                        onUpdateSelected?.(updated);
                        return updated;
                      }));
                      setShowAddItem(false);
                    }}
                    onCancel={() => setShowAddItem(false)}
                  />
                ) : (
                  <button
                    onClick={() => setShowAddItem(true)}
                    className="w-full mt-2 px-2 py-1.5 rounded text-xs font-semibold bg-orange-50 hover:bg-orange-100 border border-orange-200 text-orange-700 flex items-center justify-center gap-1 transition"
                  >
                    <Plus size={11} /> Agregar ítem
                  </button>
                )}
              </>
            )}

            <div className="border-t-2 border-stone-300 mt-2 pt-2 space-y-1 text-xs">
              <div className="flex justify-between text-stone-600">
                <span>Subtotal</span>
                <span className="font-mono">${(invoice.subtotal ?? 0).toLocaleString()}</span>
              </div>
              <div className="flex justify-between text-stone-600">
                <span>IVA 16%</span>
                <span className="font-mono">${(invoice.tax ?? 0).toLocaleString()}</span>
              </div>
              {/* Delivery cost line */}
              {invoice.delivery?.cost > 0 && (
                <div className="flex justify-between text-xs text-cyan-700">
                  <span className="flex items-center gap-1"><Truck size={10} /> Delivery</span>
                  <span className="font-mono">${invoice.delivery.cost.toLocaleString()}</span>
                </div>
              )}
              <div className="flex justify-between font-bold text-stone-900 pt-1 border-t border-stone-200">
                <span>Total</span>
                <span className="font-mono text-base text-orange-700">${(invoice.total ?? 0).toLocaleString()}</span>
              </div>
            </div>
          </div>

          {/* === Delivery tracker === */}
          {invoice.delivery && (
            <div className="bg-white border border-cyan-200 rounded-xl p-3 space-y-2.5">
              <div className="flex items-center justify-between">
                <div className="text-xs tracking-widest uppercase text-cyan-700 font-bold flex items-center gap-1.5">
                  <Truck size={12} /> Seguimiento de delivery
                </div>
                <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full ${
                  invoice.delivery.mode === "paid" ? "bg-cyan-100 text-cyan-700" : "bg-emerald-100 text-emerald-700"
                }`}>
                  {invoice.delivery.mode === "paid" ? `Envío $${invoice.delivery.cost}` : "Envío sin costo"}
                </span>
              </div>

              {/* Progress bar visual */}
              {(() => {
                const STAGES = [
                  { id: "preparando", label: "Preparando", icon: Package, color: "amber" },
                  { id: "en-camino",  label: "En camino",  icon: Truck,   color: "blue" },
                  { id: "entregado",  label: "Entregado",  icon: CheckCircle, color: "emerald" },
                ];
                const currentIdx = STAGES.findIndex(s => s.id === invoice.delivery.status);
                return (
                  <div className="space-y-2">
                    {/* Stage dots */}
                    <div className="flex items-center gap-0">
                      {STAGES.map((stage, i) => {
                        const Ic = stage.icon;
                        const reached = i <= currentIdx;
                        const isCurrent = i === currentIdx;
                        const isLast = i === STAGES.length - 1;
                        return (
                          <React.Fragment key={stage.id}>
                            <button
                              onClick={() => {
                                if (!setInvoices) return;
                                const now = new Date().toISOString().slice(0, 10);
                                const oldTimeline = invoice.delivery?.timeline || [];
                                const newTimeline = [...oldTimeline];
                                if (i > currentIdx) {
                                  for (let s = currentIdx + 1; s <= i; s++) {
                                    if (!newTimeline.find(t => t.status === STAGES[s].id)) {
                                      newTimeline.push({ status: STAGES[s].id, date: now, by: "Operador" });
                                    }
                                  }
                                }
                                const updatedDelivery = { ...invoice.delivery, status: stage.id, timeline: newTimeline };
                                setInvoices(prev => prev.map(inv =>
                                  inv.id === invoice.id ? { ...inv, delivery: updatedDelivery } : inv
                                ));
                                if (onUpdateSelected) onUpdateSelected({ delivery: updatedDelivery });
                              }}
                              title={`Marcar como "${stage.label}"`}
                              className={`w-9 h-9 rounded-full grid place-items-center flex-shrink-0 transition border-2 ${
                                isCurrent
                                  ? stage.color === "amber"
                                    ? "bg-amber-500 border-amber-500 text-white"
                                    : stage.color === "blue"
                                      ? "bg-blue-500 border-blue-500 text-white"
                                      : "bg-emerald-500 border-emerald-500 text-white"
                                  : reached
                                    ? "bg-emerald-100 border-emerald-300 text-emerald-600"
                                    : "bg-stone-100 border-stone-200 text-stone-400 hover:border-cyan-300 hover:text-cyan-600 cursor-pointer"
                              }`}
                            >
                              <Ic size={14} />
                            </button>
                            {!isLast && (
                              <div className={`flex-1 h-1 rounded-full mx-1 ${
                                i < currentIdx ? "bg-emerald-400" : "bg-stone-200"
                              }`} />
                            )}
                          </React.Fragment>
                        );
                      })}
                    </div>
                    {/* Labels */}
                    <div className="flex justify-between text-[10px]">
                      {STAGES.map((stage, i) => (
                        <span key={stage.id} className={`font-semibold ${
                          i <= currentIdx ? "text-stone-700" : "text-stone-400"
                        }`}>
                          {stage.label}
                        </span>
                      ))}
                    </div>
                  </div>
                );
              })()}

              {/* Timeline */}
              {invoice.delivery.timeline?.length > 0 && (
                <div className="border-t border-cyan-100 pt-2 space-y-1">
                  {invoice.delivery.timeline.map((t, i) => (
                    <div key={i} className="flex items-center justify-between text-[11px]">
                      <span className="text-stone-700 capitalize">
                        <span className="font-semibold">{t.status.replace("-", " ")}</span>
                        {t.by && <span className="text-stone-400"> · {t.by}</span>}
                      </span>
                      <span className="text-stone-400">{t.date}</span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* Plan de pago asociado (activo o completado) */}
          {activePlan && (
            <div className={`border rounded-xl p-3 ${
              planIsCompleted
                ? "bg-emerald-50 border-emerald-200"
                : "bg-purple-50 border-purple-200"
            }`}>
              <div className="flex items-center gap-2 mb-2">
                <Calendar size={13} className={planIsCompleted ? "text-emerald-700" : "text-purple-700"} />
                <span className={`text-xs tracking-widest uppercase font-bold ${
                  planIsCompleted ? "text-emerald-700" : "text-purple-700"
                }`}>
                  Plan de pago {planIsCompleted ? "completado" : "activo"}
                </span>
                {planIsCompleted && activePlan.completedAt && (
                  <span className="text-xs text-emerald-600 ml-auto">
                    Cerrado {activePlan.completedAt}
                  </span>
                )}
              </div>
              <div className="space-y-1">
                {activePlan.installments.map(inst => (
                  <div key={inst.id} className="bg-white rounded-lg border border-stone-200 p-2 flex items-start gap-2 text-xs">
                    <div className={`w-6 h-6 rounded-full grid place-items-center text-xs font-bold flex-shrink-0 ${
                      inst.paid ? "bg-emerald-500 text-white" : "bg-stone-100 text-stone-600"
                    }`}>
                      {inst.paid ? <Check size={11} strokeWidth={3} /> : inst.number}
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-1.5 flex-wrap">
                        <span className="font-semibold text-stone-800">Cuota {inst.number}</span>
                        <span className="font-mono text-stone-700">${inst.amount.toLocaleString()}</span>
                      </div>
                      <div className="text-stone-500 mt-0.5">
                        {inst.paid
                          ? <>Pagada el {inst.paidDate}{inst.method ? ` · ${inst.method}` : ""}</>
                          : <>Vence {inst.dueDate}</>
                        }
                      </div>
                      {inst.paid && (
                        inst.voucher ? (
                          <div className="mt-1 inline-flex items-center gap-1 px-1.5 py-0.5 rounded bg-emerald-100 text-emerald-800 font-mono text-xs">
                            <Receipt size={10} /> {inst.voucher}
                          </div>
                        ) : (
                          <div className="mt-1 text-xs text-stone-400 italic flex items-center gap-1">
                            <AlertCircle size={10} /> No se registró comprobante
                          </div>
                        )
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Resumen de pagos directos (los que NO vienen del plan) */}
          {(() => {
            // Si hay plan, separar pagos del plan vs abonos directos para no duplicar info
            const directPayments = activePlan
              ? invoice.payments.filter(p => !p.installmentId)
              : invoice.payments;
            if (directPayments.length === 0) return null;
            return (
              <div className="bg-emerald-50 border border-emerald-200 rounded-xl p-3">
                <div className="text-xs tracking-widest uppercase text-emerald-700 font-semibold mb-2">
                  {activePlan ? `Otros abonos (${directPayments.length})` : `Pagos (${directPayments.length})`}
                </div>
                <div className="space-y-1.5">
                  {directPayments.map(p => (
                    <div key={p.id} className="bg-white rounded-lg border border-emerald-100 p-2 flex items-start justify-between gap-2 text-xs">
                      <div className="min-w-0 flex-1">
                        <div className="font-semibold text-stone-800">{p.method}</div>
                        <div className="text-stone-500 truncate">{p.date}{p.note ? ` · ${p.note}` : ""}</div>
                        {p.voucher ? (
                          <div className="mt-1 inline-flex items-center gap-1 px-1.5 py-0.5 rounded bg-emerald-100 text-emerald-800 font-mono">
                            <Receipt size={10} /> {p.voucher}
                          </div>
                        ) : (
                          <div className="mt-1 text-xs text-stone-400 italic flex items-center gap-1">
                            <AlertCircle size={10} /> No se registró comprobante
                          </div>
                        )}
                      </div>
                      <span className="font-mono font-bold text-emerald-700 whitespace-nowrap">
                        ${p.amount.toLocaleString()}
                      </span>
                    </div>
                  ))}
                </div>
              </div>
            );
          })()}

          {/* Totales pagado / saldo */}
          {invoice.payments.length > 0 && (
            <div className="bg-white border border-stone-200 rounded-xl p-3 space-y-0.5">
              <div className="flex justify-between text-xs">
                <span className="font-semibold text-emerald-800">Pagado</span>
                <span className="font-mono font-bold text-emerald-800">${(invoice.paid ?? 0).toLocaleString()}</span>
              </div>
              {invoice.balance > 0 && (
                <div className="flex justify-between text-xs">
                  <span className="font-semibold text-red-800">Saldo pendiente</span>
                  <span className="font-mono font-bold text-red-700">${(invoice.balance ?? 0).toLocaleString()}</span>
                </div>
              )}
            </div>
          )}
        </div>

        {/* Footer con acciones */}
        <div className="border-t border-stone-200 bg-white p-3 flex-shrink-0 space-y-2">
          {/* Acción primaria: si está en borrador → Emitir / si está emitido y debe → Abonar */}
          {isDraft && canEdit && (
            <button
              onClick={emit}
              disabled={invoice.items.length === 0 || invoice.total <= 0}
              className={`w-full flex items-center justify-center gap-1.5 px-4 py-2.5 rounded-xl text-sm font-semibold transition shadow ${
                invoice.items.length === 0 || invoice.total <= 0
                  ? "bg-stone-200 text-stone-400 cursor-not-allowed"
                  : "bg-orange-600 hover:bg-orange-700 text-white"
              }`}
              title="Emitir recibo: pasa a estado emitido y ya no se podrá editar"
            >
              <Send size={14} strokeWidth={2.2} /> Emitir recibo
            </button>
          )}

          {!isDraft && !readOnly && invoice.balance > 0 && (
            <button
              onClick={onPayment}
              className="w-full flex items-center justify-center gap-1.5 px-4 py-2.5 rounded-xl text-sm font-semibold bg-emerald-500 hover:bg-emerald-600 text-white transition"
            >
              <DollarSign size={14} /> Registrar abono
            </button>
          )}

          {/* Pagado pero no finalizado → ofrecer cerrar el ciclo */}
          {canFinalize && (
            <button
              onClick={finalize}
              className="w-full flex items-center justify-center gap-1.5 px-4 py-2.5 rounded-xl text-sm font-semibold bg-stone-800 hover:bg-stone-900 text-white transition shadow"
              title="Marcar como finalizada: cierra el ciclo, ya no se admiten cambios."
            >
              <CheckCircle size={14} strokeWidth={2.2} /> Marcar como finalizada
            </button>
          )}

          {/* Estado finalizado: indicador con estilo lock */}
          {isFinalized && (
            <div className="w-full flex items-center justify-center gap-2 px-4 py-2.5 rounded-xl text-sm font-semibold bg-stone-100 text-stone-600 border border-stone-200">
              <Lock size={13} />
              <span>Recibo finalizada{invoice.finalizedAt ? ` el ${invoice.finalizedAt}` : ""}</span>
            </div>
          )}

          <div className="flex gap-2 flex-wrap">
            {!readOnly && !isDraft && invoice.balance > 0 && (
              <button
                onClick={onCreatePlan}
                disabled={Boolean(activePlan)}
                className={`flex-1 flex items-center justify-center gap-1.5 px-3 py-2 rounded-xl text-xs font-semibold transition ${
                  activePlan
                    ? "bg-stone-100 border border-stone-200 text-stone-400 cursor-not-allowed"
                    : "bg-white border border-orange-300 text-orange-700 hover:bg-orange-50"
                }`}
                title={activePlan ? "Esta recibo ya tiene un plan activo. Elimínalo primero." : "Crear plan de pago"}
              >
                <Calendar size={11} /> {activePlan ? "Con plan" : "Plan"}
              </button>
            )}
            {client && onMessageClient && (
              <button
                onClick={() => { onClose(); onMessageClient(client.id); }}
                className="flex-1 flex items-center justify-center gap-1.5 px-3 py-2 rounded-xl text-xs font-semibold bg-white border border-emerald-300 text-emerald-700 hover:bg-emerald-50 transition"
              >
                <MessageCircle size={11} /> Mensaje
              </button>
            )}
            <button className="flex-1 flex items-center justify-center gap-1.5 px-3 py-2 rounded-xl text-xs font-semibold bg-white text-stone-700 border border-stone-200 hover:border-orange-400 transition">
              <Printer size={11} /> Imprimir
            </button>
          </div>
        </div>
      </aside>

      {/* === Visor de recipe completo === */}
      {viewingRecipe && (
        <div onClick={() => setViewingRecipe(null)} className="fixed inset-0 bg-stone-900/80 z-[60] flex justify-center items-center p-4">
          <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden max-h-[90vh] flex flex-col">
            {/* Header */}
            <div className="p-4 bg-gradient-to-r from-purple-500 to-purple-600 text-white flex items-center gap-3 flex-shrink-0">
              <div className="w-10 h-10 rounded-xl bg-white/20 grid place-items-center flex-shrink-0">
                <FileText size={18} />
              </div>
              <div className="flex-1 min-w-0">
                <div className="text-[10px] tracking-widest uppercase opacity-80 font-semibold">Recipe médico</div>
                <h3 className="font-serif text-lg font-semibold truncate">
                  {viewingRecipe.recipe?.medication || viewingRecipe.description}
                </h3>
              </div>
              <button onClick={() => setViewingRecipe(null)} className="w-8 h-8 rounded-full bg-white/20 hover:bg-white/30 grid place-items-center transition">
                <X size={14} />
              </button>
            </div>

            {/* Body */}
            <div className="flex-1 overflow-y-auto p-4 space-y-3">
              {/* Datos del medicamento */}
              <div className="bg-purple-50 border border-purple-200 rounded-xl p-3 space-y-2">
                <div className="text-xs tracking-widest uppercase text-purple-700 font-bold">Prescripción</div>
                {viewingRecipe.recipe ? (
                  <div className="space-y-2">
                    <div className="grid grid-cols-2 gap-2">
                      <div>
                        <div className="text-[10px] text-purple-500 font-semibold uppercase">Medicamento</div>
                        <div className="text-sm font-bold text-purple-900">{viewingRecipe.recipe.medication || "—"}</div>
                      </div>
                      <div>
                        <div className="text-[10px] text-purple-500 font-semibold uppercase">Dosis</div>
                        <div className="text-sm font-semibold text-stone-800">{viewingRecipe.recipe.dose || "—"}</div>
                      </div>
                    </div>
                    <div className="grid grid-cols-3 gap-2">
                      <div>
                        <div className="text-[10px] text-purple-500 font-semibold uppercase">Vía</div>
                        <div className="text-sm text-stone-800">{viewingRecipe.recipe.route || "—"}</div>
                      </div>
                      <div>
                        <div className="text-[10px] text-purple-500 font-semibold uppercase">Frecuencia</div>
                        <div className="text-sm text-stone-800">{viewingRecipe.recipe.frequency || "—"}</div>
                      </div>
                      <div>
                        <div className="text-[10px] text-purple-500 font-semibold uppercase">Duración</div>
                        <div className="text-sm text-stone-800">{viewingRecipe.recipe.duration || "—"}</div>
                      </div>
                    </div>
                    {viewingRecipe.recipe.instructions && (
                      <div className="bg-white border border-purple-100 rounded-lg p-2.5">
                        <div className="text-[10px] text-purple-500 font-semibold uppercase mb-0.5">Indicaciones para el tutor</div>
                        <div className="text-sm text-stone-800 leading-relaxed">{viewingRecipe.recipe.instructions}</div>
                      </div>
                    )}
                  </div>
                ) : (
                  <div className="text-xs text-stone-500 italic">Sin datos de prescripción registrados.</div>
                )}
              </div>

              {/* Datos de la recibo */}
              <div className="bg-stone-50 border border-stone-200 rounded-xl p-3">
                <div className="text-xs tracking-widest uppercase text-stone-500 font-bold mb-1">Recibodo en</div>
                <div className="flex items-center justify-between text-sm">
                  <span className="font-mono font-bold text-stone-700">{invoice.number}</span>
                  <span className="text-stone-500">{invoice.issueDate}</span>
                </div>
                <div className="text-xs text-stone-500 mt-0.5">{client?.name || "—"}</div>
              </div>

              {/* Foto del recipe */}
              <div className="bg-stone-50 border border-stone-200 rounded-xl p-3">
                <div className="text-xs tracking-widest uppercase text-stone-500 font-bold mb-2">Foto del recipe</div>
                {viewingRecipe.recipePhoto ? (
                  <img
                    src={viewingRecipe.recipePhoto}
                    alt="Recipe"
                    className="w-full rounded-lg border border-stone-200 shadow-sm"
                  />
                ) : (
                  <div className="bg-white border-2 border-dashed border-stone-200 rounded-xl p-6 text-center">
                    <Camera size={24} className="text-stone-300 mx-auto mb-2" />
                    <div className="text-sm font-semibold text-stone-500">Sin foto adjunta</div>
                    <div className="text-xs text-stone-400 mt-0.5">
                      La foto del recipe se puede adjuntar desde Nueva Venta al momento de cobrar.
                    </div>
                  </div>
                )}
              </div>
            </div>

            {/* Footer */}
            <div className="p-3 border-t border-stone-200 bg-stone-50 flex-shrink-0">
              <button
                onClick={() => setViewingRecipe(null)}
                className="w-full px-3 py-2.5 rounded-xl text-sm font-semibold bg-purple-600 hover:bg-purple-700 text-white transition"
              >
                Cerrar
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
}

// ========== MODAL: Registrar abono ==========

function PaymentModal({ invoice, client, onClose, onSubmit }) {
  const [amount, setAmount] = useState(invoice.balance);
  const [method, setMethod] = useState("Efectivo");
  const [note, setNote] = useState("");
  const [voucher, setVoucher] = useState("");

  const isFullPayment = amount >= invoice.balance;
  const validAmount = amount > 0 && amount <= invoice.balance;

  return (
    <div onClick={onClose} className="fixed inset-0 bg-stone-900 z-50 flex justify-center items-start p-4 overflow-y-auto">
      <div onClick={(e) => e.stopPropagation()} className="bg-stone-50 rounded-2xl w-full max-w-md shadow-2xl my-8 overflow-hidden">
        <div className="p-5 border-b border-stone-200 bg-gradient-to-r from-white to-emerald-50 flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-emerald-500 text-white grid place-items-center shadow-lg">
            <DollarSign size={20} />
          </div>
          <div className="flex-1">
            <div className="text-xs tracking-widest uppercase text-emerald-700 font-semibold">
              Registrar abono
            </div>
            <h3 className="font-serif text-lg font-semibold mt-0.5">
              {client ? client.name : "—"}
            </h3>
          </div>
          <button onClick={onClose} className="w-9 h-9 rounded-full bg-white border border-stone-200 grid place-items-center text-stone-600 hover:text-orange-700">
            <X size={16} />
          </button>
        </div>

        <div className="p-5 space-y-3.5">
          <div className="bg-white border border-stone-200 rounded-xl p-3 flex justify-between items-center">
            <div>
              <div className="text-xs text-stone-500 font-mono">{invoice.number}</div>
              <div className="text-xs text-stone-600 mt-0.5">
                Total: <strong>${(invoice.total ?? 0).toLocaleString()}</strong> ·
                Pagado: <strong className="text-emerald-700">${(invoice.paid ?? 0).toLocaleString()}</strong>
              </div>
            </div>
            <div className="text-right">
              <div className="text-xs text-red-700">Saldo</div>
              <div className="font-mono font-bold text-red-700">${(invoice.balance ?? 0).toLocaleString()}</div>
            </div>
          </div>

          <Field label="Monto a abonar *">
            <div className="relative">
              <span className="absolute left-3 top-1/2 -translate-y-1/2 text-stone-500 font-bold">$</span>
              <input
                type="number"
                value={amount}
                onChange={(e) => setAmount(Number(e.target.value))}
                max={invoice.balance}
                className="w-full pl-7 pr-3 py-2.5 bg-white border border-stone-200 rounded-xl text-sm font-mono outline-none focus:border-orange-500"
                autoFocus
              />
            </div>
            <div className="flex gap-1.5 mt-2 flex-wrap">
              <button onClick={() => setAmount(invoice.balance)} className="text-xs font-semibold px-2.5 py-1 rounded-lg bg-emerald-100 text-emerald-700">
                Saldar total
              </button>
              <button onClick={() => setAmount(Math.round(invoice.balance / 2))} className="text-xs font-semibold px-2.5 py-1 rounded-lg bg-stone-100 text-stone-700">
                50%
              </button>
              <button onClick={() => setAmount(Math.round(invoice.balance / 4))} className="text-xs font-semibold px-2.5 py-1 rounded-lg bg-stone-100 text-stone-700">
                25%
              </button>
            </div>
          </Field>

          <Field label="Método de pago">
            <div className="flex gap-1.5 flex-wrap">
              {PAY_METHODS.map(m => (
                <button
                  key={m}
                  onClick={() => setMethod(m)}
                  className={`px-3 py-1.5 rounded-full text-xs font-semibold transition ${
                    method === m ? "bg-stone-900 text-white" : "bg-white text-stone-600 border border-stone-200"
                  }`}
                >
                  {m}
                </button>
              ))}
            </div>
          </Field>

          <Field label="Número de comprobante (opcional)">
            <input
              value={voucher}
              onChange={(e) => setVoucher(e.target.value)}
              placeholder={method === "Efectivo" ? "Ej: REC-00284 (recibo de caja)" : "Ej: 4827193 (referencia bancaria)"}
              className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm font-mono outline-none focus:border-orange-500"
            />
            <div className="text-xs text-stone-500 mt-1.5 leading-relaxed">
              Si lo dejas vacío, el pago quedará registrado <strong>sin comprobante</strong> en el histórico.
            </div>
          </Field>

          <Field label="Nota (opcional)">
            <input
              value={note}
              onChange={(e) => setNote(e.target.value)}
              placeholder="Ej: Abono parcial pactado"
              className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
            />
          </Field>

          {validAmount && (
            <div className={`p-3 rounded-xl border flex gap-2.5 text-xs ${
              isFullPayment
                ? "bg-emerald-50 border-emerald-200 text-emerald-900"
                : "bg-amber-50 border-amber-200 text-amber-900"
            }`}>
              {isFullPayment ? (
                <Check size={14} className="text-emerald-700 flex-shrink-0 mt-0.5" />
              ) : (
                <AlertCircle size={14} className="text-amber-700 flex-shrink-0 mt-0.5" />
              )}
              <div>
                {isFullPayment
                  ? <>Este abono <strong>salda totalmente</strong> la recibo. Pasará a estado <strong>Pagado</strong>.</>
                  : <>Saldo restante después del abono: <strong>${(invoice.balance - amount).toLocaleString()}</strong></>
                }
              </div>
            </div>
          )}
        </div>

        <div className="p-3.5 px-5 border-t border-stone-200 bg-white flex justify-end gap-2">
          <button onClick={onClose} className="px-3 py-2 rounded-xl text-sm font-semibold bg-white text-stone-700 border border-stone-200">
            Cancelar
          </button>
          <button
            onClick={() => onSubmit(amount, method, note, voucher.trim() || null)}
            disabled={!validAmount}
            className={`flex items-center gap-1.5 px-4 py-2 rounded-xl text-sm font-semibold bg-emerald-500 hover:bg-emerald-600 text-white transition ${
              validAmount ? "" : "opacity-40 cursor-not-allowed"
            }`}
          >
            <Check size={14} strokeWidth={2.5} /> Confirmar abono
          </button>
        </div>
      </div>
    </div>
  );
}

// ========== MODAL: Crear plan de pago ==========

function CreatePlanModal({ invoice, client, onClose, onSubmit }) {
  const [installmentsCount, setInstallmentsCount] = useState(3);
  const [intervalDays, setIntervalDays] = useState(30);
  const [firstDueDate, setFirstDueDate] = useState(() => {
    const d = new Date();
    d.setDate(d.getDate() + 30);
    return d.toISOString().slice(0, 10);
  });

  const installmentAmount = Math.round(invoice.balance / installmentsCount);
  const lastAdjustment = invoice.balance - (installmentAmount * (installmentsCount - 1));

  const installmentPreview = useMemo(() => {
    const list = [];
    const baseDate = new Date(firstDueDate);
    for (let i = 0; i < installmentsCount; i++) {
      const d = new Date(baseDate.getTime() + i * intervalDays * 24 * 3600 * 1000);
      list.push({
        id: `cuota-${invoice.id}-${i + 1}-${Date.now()}`,
        number: i + 1,
        dueDate: d.toISOString().slice(0, 10),
        amount: i === installmentsCount - 1 ? lastAdjustment : installmentAmount,
        paid: false,
        paidDate: null,
      });
    }
    return list;
  }, [installmentsCount, intervalDays, firstDueDate, invoice.balance, invoice.id, installmentAmount, lastAdjustment]);

  return (
    <div onClick={onClose} className="fixed inset-0 bg-stone-900 z-50 flex justify-center items-start p-4 overflow-y-auto">
      <div onClick={(e) => e.stopPropagation()} className="bg-stone-50 rounded-2xl w-full max-w-lg shadow-2xl my-8 overflow-hidden">
        <div className="p-5 border-b border-stone-200 bg-gradient-to-r from-white to-orange-50 flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-orange-600 text-white grid place-items-center shadow-lg">
            <Calendar size={20} />
          </div>
          <div className="flex-1">
            <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold">
              Plan de pago
            </div>
            <h3 className="font-serif text-lg font-semibold mt-0.5">
              {client ? client.name : "—"} · ${(invoice.balance ?? 0).toLocaleString()}
            </h3>
          </div>
          <button onClick={onClose} className="w-9 h-9 rounded-full bg-white border border-stone-200 grid place-items-center text-stone-600 hover:text-orange-700">
            <X size={16} />
          </button>
        </div>

        <div className="p-5 space-y-3.5 max-h-96 overflow-y-auto">
          <Field label="Número de cuotas">
            <div className="flex gap-1.5 flex-wrap">
              {[2, 3, 4, 6, 12].map(n => (
                <button
                  key={n}
                  onClick={() => setInstallmentsCount(n)}
                  className={`px-3 py-1.5 rounded-full text-xs font-semibold transition ${
                    installmentsCount === n ? "bg-orange-600 text-white" : "bg-white text-stone-600 border border-stone-200"
                  }`}
                >
                  {n} cuotas
                </button>
              ))}
            </div>
          </Field>

          <div className="grid grid-cols-2 gap-3">
            <Field label="Frecuencia (días entre cuotas)">
              <select
                value={intervalDays}
                onChange={(e) => setIntervalDays(Number(e.target.value))}
                className="w-full px-3 py-2.5 bg-white border border-stone-200 rounded-xl text-sm font-semibold outline-none cursor-pointer"
              >
                <option value={7}>Semanal (7 días)</option>
                <option value={15}>Quincenal (15 días)</option>
                <option value={30}>Mensual (30 días)</option>
              </select>
            </Field>
            <Field label="Primera cuota">
              <input
                type="date"
                value={firstDueDate}
                onChange={(e) => setFirstDueDate(e.target.value)}
                className="w-full px-3 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
              />
            </Field>
          </div>

          <div className="bg-white border border-stone-200 rounded-xl p-3">
            <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold mb-2">
              Vista previa del plan
            </div>
            <div className="space-y-1.5">
              {installmentPreview.map(inst => (
                <div key={inst.id} className="flex items-center justify-between text-xs p-2 rounded-lg bg-stone-50">
                  <span className="font-semibold text-stone-700">Cuota {inst.number}</span>
                  <span className="text-stone-500">{inst.dueDate}</span>
                  <span className="font-mono font-bold text-stone-800">${inst.amount.toLocaleString()}</span>
                </div>
              ))}
            </div>
            <div className="mt-2 pt-2 border-t border-stone-200 flex justify-between text-xs">
              <span className="font-semibold text-stone-700">Total del plan</span>
              <span className="font-mono font-bold text-orange-700">${(invoice.balance ?? 0).toLocaleString()}</span>
            </div>
          </div>
        </div>

        <div className="p-3.5 px-5 border-t border-stone-200 bg-white flex justify-end gap-2">
          <button onClick={onClose} className="px-3 py-2 rounded-xl text-sm font-semibold bg-white text-stone-700 border border-stone-200">
            Cancelar
          </button>
          <button
            onClick={() => onSubmit(installmentPreview)}
            className="flex items-center gap-1.5 px-4 py-2 rounded-xl text-sm font-semibold bg-orange-600 hover:bg-orange-700 text-white"
          >
            <Check size={14} strokeWidth={2.5} /> Crear plan
          </button>
        </div>
      </div>
    </div>
  );
}

