// === Tab catálogo: gestionar servicios + venta puntual rápida ===
function ServicesCatalogTab({ services, setServices, clients, passports, invoices, setInvoices, groomingBookings = [], setGroomingBookings, agendaEvents = [], setAgendaEvents, userName, modules = [], onSaleCreated, activeSedeId = null }) {
  const [showWizard, setShowWizard] = useState(false);
  const [editingService, setEditingService] = useState(null);
  const [sellingService, setSellingService] = useState(null);
  const [moduleFilter, setModuleFilter] = useState("all");
  const [searchQuery, setSearchQuery] = useState("");

  // === Filtro base por sede ===
  // El catálogo de servicios se filtra primero por la sede activa. Si el usuario
  // está parado en Pet 2, solo ve los servicios de Pet 2 (con su precio/horario).
  // Para el super sin contexto de sede, ve todos. Los servicios sin sedeId (legacy)
  // se ven solo cuando no hay sede activa, para no contaminar las vistas por sede.
  const servicesInSede = useMemo(() => {
    if (!activeSedeId) return services;
    return services.filter(s => s.sedeId === activeSedeId);
  }, [services, activeSedeId]);

  const filtered = useMemo(() => {
    let r = servicesInSede;
    if (moduleFilter !== "all") r = r.filter(s => s.module === moduleFilter);
    if (searchQuery.trim()) {
      const q = searchQuery.toLowerCase();
      r = r.filter(s =>
        s.name.toLowerCase().includes(q) ||
        s.description.toLowerCase().includes(q)
      );
    }
    return r;
  }, [servicesInSede, moduleFilter, searchQuery]);

  const stats = useMemo(() => ({
    total: servicesInSede.length,
    vet: servicesInSede.filter(s => s.module === "vet").length,
    grooming: servicesInSede.filter(s => s.module === "grooming").length,
    b2b: servicesInSede.filter(s => s.module === "b2b").length,
  }), [servicesInSede]);

  const handleSaveService = (data) => {
    if (editingService) {
      setServices(prev => prev.map(s => s.id === editingService.id ? { ...s, ...data } : s));
    } else {
      // Al crear, el servicio nace en la sede activa (si la hay).
      // Si no hay sede activa (raro), queda sin sedeId y solo se ve en la vista global.
      const newService = {
        ...data,
        id: `srv-${Date.now().toString(36)}`,
        soldCount: 0,
        active: true,
        sedeId: activeSedeId || null,
      };
      setServices(prev => [newService, ...prev]);
    }
    setShowWizard(false);
    setEditingService(null);
  };

  const handleEdit = (service) => {
    setEditingService(service);
    setShowWizard(true);
  };

  const handleToggleActive = (id) => {
    setServices(prev => prev.map(s => s.id === id ? { ...s, active: !s.active } : s));
  };

  // Venta puntual rápida (un solo servicio) — desde el catálogo.
  // Crea la recibo y, según el módulo, también crea el booking de grooming
  // (si la fecha es hoy) y/o el evento en la agenda. Todo queda enlazado por
  // invoiceNumber/invoiceId como hilo conductor.
  const handleConfirmQuickSale = (saleData) => {
    const { service, client, pet, scheduledDate, scheduledDateISO, scheduledTime, scheduledTimeEnd, frequency } = saleData;
    const lastNum = invoices.length === 0 ? 100
      : Math.max(...invoices.map(i => parseInt(i.number.split("-")[1] || "100")));
    const newNumber = `00-${String(lastNum + 1).padStart(7, "0")}`;
    const newInvoiceId = `inv-${Date.now().toString(36)}`;
    const itemDescription = pet ? `${service.name} (${pet.name})` : service.name;
    const subtotal = Math.round(service.price / 1.16);
    const tax = service.price - subtotal;
    const today = new Date();
    const dueDate = new Date(today);
    dueDate.setDate(today.getDate() + 30);
    const fmt = (d) => d.toISOString().slice(0, 10);
    const todayISO = fmt(today);

    // === 1. Crear recibo ===
    const newInvoice = {
      id: newInvoiceId,
      number: newNumber,
      clientId: client.id,
      issueDate: fmt(today),
      dueDate: fmt(dueDate),
      state: "borrador",
      items: [{ description: itemDescription, qty: 1, unit: subtotal, total: subtotal }],
      subtotal,
      tax,
      total: service.price,
      paid: 0,
      balance: service.price,
      payments: [],
      createdBy: userName || "Operador",
      // Trazabilidad: si hay agenda futura, también guardamos info de cuándo se prestará
      scheduledFor: scheduledDateISO || null,
      scheduledTime: scheduledTime || null,
      scheduledServiceModule: service.module,
      scheduledServiceId: service.id,
    };
    setInvoices(prev => [newInvoice, ...prev]);

    // === 2. Crear booking + evento agenda según el módulo ===
    const eventDateISO = scheduledDateISO || todayISO;
    const isToday = eventDateISO === todayISO;
    const evtId = `evt-${Date.now().toString(36)}-${Math.random().toString(36).slice(2,5)}`;

    // 2a. Si es grooming: crear booking en kanban (si es hoy) + evento agenda siempre
    if (service.module === "grooming" && setGroomingBookings) {
      if (isToday) {
        // Va al kanban "Por hacer". Si no hay mascota seleccionada, queda con
        // nombre "(sin nombre)" — el groomer puede editarlo después desde el drawer.
        const newBooking = {
          id: `gb-${Date.now().toString(36)}-${Math.random().toString(36).slice(2,5)}`,
          eventDate: eventDateISO,
          time: scheduledTime || "—",
          duration: service.duration || 60,
          pet: pet?.name || "",
          petCode: pet?.code || null,
          species: pet?.species || null,
          breed: pet?.breed || "",
          owner: client.name,
          clientId: client.id,
          service: service.name,
          reason: `Servicio vendido por ${userName || "Ventas"}.`,
          room: service.room || "Sala de grooming",
          status: "pending",
          supplies: [],
          notes: "",
          // Hilo conductor con la recibo
          invoiceNumber: newNumber,
          invoiceId: newInvoiceId,
          fromQuickSale: true,
          // Etiquetar con la INSTANCIA específica desde la que se vendió.
          // Resolver via el catálogo: el servicio tiene moduleId que apunta a la instancia.
          moduleId: resolveServiceModuleId(service) || "grooming-ops",
        };
        setGroomingBookings(prev => [newBooking, ...prev]);
      }
    }

    // 2b. En todos los casos (grooming, vet, b2b, otros): agregar evento a la agenda
    if (setAgendaEvents) {
      const evtType =
        service.module === "vet" ? "vet" :
        service.module === "grooming" ? "grooming" :
        service.module === "b2b" ? "b2b" : "other";
      const newEvent = {
        id: evtId,
        type: evtType,
        date: eventDateISO,
        time: scheduledTime || "10:00",
        duration: service.duration || 60,
        pet: pet?.name || "",
        petCode: pet?.code || null,
        species: pet?.species || null,
        breed: pet?.breed || "",
        owner: client.name,
        professional: null,
        title: service.name,
        reason: `Servicio agendado desde venta express. Recibo ${newNumber}.`,
        room: service.room || null,
        status: "confirmada",
        price: service.price,
        // Trazabilidad
        invoiceNumber: newNumber,
        invoiceId: newInvoiceId,
        clientId: client.id,
        // Etiquetar con la instancia origen
        moduleId: resolveServiceModuleId(service) || null,
      };
      setAgendaEvents(prev => [newEvent, ...prev]);
    }

    // === 3. Aumentar contador de soldCount del servicio ===
    setServices(prev => prev.map(s =>
      s.id === service.id ? { ...s, soldCount: (s.soldCount || 0) + 1 } : s
    ));

    setSellingService(null);
    onSaleCreated?.({
      number: newNumber,
      itemCount: 1,
      total: service.price,
      module: service.module,
      scheduledForToday: isToday,
    });
  };

  return (
    <div className="space-y-4">
      {/* Stats compactas */}
      <div className="bg-white border border-stone-200 rounded-2xl p-3 flex items-center gap-3 flex-wrap">
        <div className="flex items-center gap-2 text-sm">
          <span className="text-stone-500">Total</span>
          <span className="font-bold text-stone-900">{stats.total}</span>
        </div>
        <div className="text-stone-300">·</div>
        <div className="flex items-center gap-1 text-xs">
          <Stethoscope size={12} className="text-orange-700" />
          <span>Vet <strong>{stats.vet}</strong></span>
        </div>
        <div className="flex items-center gap-1 text-xs">
          <Scissors size={12} className="text-emerald-700" />
          <span>Grooming <strong>{stats.grooming}</strong></span>
        </div>
        <div className="flex items-center gap-1 text-xs">
          <Tag size={12} className="text-blue-700" />
          <span>B2B <strong>{stats.b2b}</strong></span>
        </div>
        <button
          onClick={() => { setEditingService(null); setShowWizard(true); }}
          className="ml-auto flex items-center gap-1.5 px-3 py-2 rounded-xl bg-orange-600 hover:bg-orange-700 text-white text-xs font-semibold transition shadow"
        >
          <Plus size={13} /> Crear servicio
        </button>
      </div>

      {/* Buscador y filtros */}
      <div className="flex flex-col sm:flex-row gap-3">
        <div className="relative flex-1">
          <Search size={15} className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-400" />
          <input
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            placeholder="Buscar servicio..."
            className="w-full pl-11 pr-3 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500 transition"
          />
        </div>
        <div className="flex gap-1.5 overflow-x-auto bg-white border border-stone-200 rounded-xl p-1">
          {[
            { id: "all", label: "Todos", count: stats.total },
            { id: "vet", label: "Vet", count: stats.vet },
            { id: "grooming", label: "Grooming", count: stats.grooming },
            { id: "b2b", label: "B2B", count: stats.b2b },
          ].map(f => {
            const active = moduleFilter === f.id;
            return (
              <button
                key={f.id}
                onClick={() => setModuleFilter(f.id)}
                className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-semibold whitespace-nowrap transition ${
                  active ? "bg-stone-900 text-white" : "text-stone-600 hover:text-stone-800"
                }`}
              >
                {f.label}
                <span className={`text-xs font-bold px-1.5 py-px rounded-full ${
                  active ? "bg-stone-700 text-white" : "bg-stone-100 text-stone-600"
                }`}>{f.count}</span>
              </button>
            );
          })}
        </div>
      </div>

      {/* Grid */}
      {filtered.length === 0 ? (
        <div className="bg-white border border-stone-200 rounded-2xl p-12 text-center">
          <Tag size={32} className="text-stone-300 mx-auto mb-3" />
          <div className="text-base font-semibold text-stone-700">Sin servicios</div>
          <div className="text-sm text-stone-500 mt-1">
            {searchQuery
              ? <>No encontramos coincidencias para "<strong>{searchQuery}</strong>".</>
              : "Empieza creando tu primer servicio."
            }
          </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
          {filtered.map(s => (
            <CatalogServiceCard
              key={s.id}
              service={s}
              onEdit={() => handleEdit(s)}
              onToggleActive={() => handleToggleActive(s.id)}
              onSell={() => setSellingService(s)}
            />
          ))}
        </div>
      )}

      {showWizard && (
        <NewServiceWizard
          editingService={editingService}
          onClose={() => { setShowWizard(false); setEditingService(null); }}
          onSave={handleSaveService}
        />
      )}

      {sellingService && (
        <SellServiceModal
          service={sellingService}
          clients={clients}
          passports={passports}
          onClose={() => setSellingService(null)}
          onConfirm={handleConfirmQuickSale}
        />
      )}
    </div>
  );
}

// === SaleBuilder: constructor de recibo personalizada ===
// === Helpers de programación de servicios ===
// Convierte "HH:MM" a minutos desde medianoche. Devuelve null si formato inválido.
function parseHHMM(str) {
  if (!str || typeof str !== "string") return null;
  const m = str.match(/^(\d{1,2}):(\d{2})$/);
  if (!m) return null;
  const h = Number(m[1]);
  const min = Number(m[2]);
  if (h < 0 || h > 23 || min < 0 || min > 59) return null;
  return h * 60 + min;
}
// Convierte minutos desde medianoche a "HH:MM"
function formatHHMM(minutes) {
  const total = Math.max(0, Math.min(23 * 60 + 59, Math.round(minutes)));
  const h = Math.floor(total / 60);
  const m = total % 60;
  return `${String(h).padStart(2, "0")}:${String(m).padStart(2, "0")}`;
}
// Hora actual del sistema redondeada al múltiplo de 5 minutos más cercano hacia arriba.
// Útil para "agendar ahora" sin caer exactamente en el segundo del click.
function nowHHMM() {
  const d = new Date();
  const total = d.getHours() * 60 + d.getMinutes();
  const rounded = Math.ceil(total / 5) * 5;
  return formatHHMM(rounded);
}
// Encuentra el primer slot libre a partir de una hora propuesta para un servicio
// de duración `durationMin`, considerando los eventos existentes de ese día
// (tomando `time` y `duration` de cada uno). Si la propuesta solapa con algún
// evento, se desliza al final de ese evento y se reitera (cascada). Devuelve "HH:MM".
//
// `existingEvents` es un array con shape mínimo { date|eventDate, time, duration }.
// `dateISO` es la fecha objetivo en formato YYYY-MM-DD.
// `proposedHHMM` es la hora deseada en formato "HH:MM".
function findNextFreeTime(existingEvents, dateISO, proposedHHMM, durationMin) {
  const dayBlocks = (existingEvents || [])
    .filter(e => e && (e.date === dateISO || e.eventDate === dateISO))
    .map(e => {
      const start = parseHHMM(e.time);
      if (start === null) return null;
      const dur = Number(e.duration) > 0 ? Number(e.duration) : 60;
      return { start, end: start + dur };
    })
    .filter(Boolean)
    .sort((a, b) => a.start - b.start);

  let proposedStart = parseHHMM(proposedHHMM);
  if (proposedStart === null) proposedStart = parseHHMM(nowHHMM()) || 0;
  const dur = Number(durationMin) > 0 ? Number(durationMin) : 60;
  let proposedEnd = proposedStart + dur;

  // Iteración con guard para evitar loop infinito en datos corruptos
  let safety = 100;
  let changed = true;
  while (changed && safety-- > 0) {
    changed = false;
    for (const block of dayBlocks) {
      // Solapamiento: la propuesta empieza antes de que termine el bloque
      // y termina después de que el bloque empieza.
      if (proposedStart < block.end && proposedEnd > block.start) {
        proposedStart = block.end;
        proposedEnd = proposedStart + dur;
        changed = true;
        break; // re-iterar desde el principio para que la cascada respete el orden
      }
    }
  }
  return formatHHMM(proposedStart);
}

function SaleBuilder({ services, supplies = [], clients, passports, invoices, setInvoices, groomingBookings = [], setGroomingBookings, agendaEvents = [], setAgendaEvents, userName, modules = [], onSaleCreated, preselectedClient = null, onClearPreselected, sedes = [], activeSedeId = null, userSedeIds = [], inventoryItems = [], paymentMethods = [] }) {
  const [client, setClient] = useState(preselectedClient);
  const [pet, setPet] = useState(null);
  const [items, setItems] = useState([]);
  // === Sede de la recibo ===
  // Reglas de autoselección:
  // 1. Si el usuario tiene UNA sola sede asignada, se autoselecciona (no se puede cambiar)
  // 2. Si está navegando dentro de una sede del CRM (activeSedeId), arranca con esa
  // 3. Si no, queda null y el usuario debe elegir antes de emitir
  const [saleSedeId, setSaleSedeId] = useState(() => {
    if (userSedeIds && userSedeIds.length === 1) return userSedeIds[0];
    if (activeSedeId) return activeSedeId;
    if (sedes && sedes.length === 1) return sedes[0].id;
    return null;
  });
  const [showItemPicker, setShowItemPicker] = useState(null); // service | product | medicine | custom
  const [clientSearch, setClientSearch] = useState("");
  // Modalidad de pago: full (paga todo) | partial (abono) | deferred (paga al finalizar)
  const [paymentMode, setPaymentMode] = useState("full");
  const [partialAmount, setPartialAmount] = useState("");
  const [paymentMethod, setPaymentMethod] = useState("efectivo");

  // === Delivery ===
  // "none" = sin delivery, "paid" = delivery con costo, "free" = seguimiento sin costo
  const [deliveryMode, setDeliveryMode] = useState("none");
  const [deliveryCost, setDeliveryCost] = useState(5); // costo por defecto si es pagado
  const DELIVERY_STAGES = ["preparando", "en-camino", "entregado"]; // efectivo | tarjeta | transferencia | pago-movil

  // Limpiar la preselección del padre una vez que se montó (para que si el usuario
  // luego cambia de cliente y vuelve a Nueva Venta, no se vuelva a forzar el viejo)
  useEffect(() => {
    if (preselectedClient && onClearPreselected) {
      onClearPreselected();
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Búsqueda de clientes — filtrada por la sede de la recibo.
  // Si seleccionas Pet 2 como sede, solo aparecen clientes de Pet 2. Los legacy
  // sin sedeOrigenId no aparecen — para evitar fugas entre sedes.
  const filteredClients = useMemo(() => {
    let base = clients;
    if (saleSedeId) {
      base = clients.filter(c => c.sedeOrigenId === saleSedeId);
    }
    if (!clientSearch.trim()) return base.slice(0, 8);
    const q = clientSearch.toLowerCase();
    return base.filter(c =>
      (c.name || "").toLowerCase().includes(q) ||
      (c.cedula || "").toLowerCase().includes(q) ||
      (c.phone || "").includes(q)
    ).slice(0, 12);
  }, [clientSearch, clients, saleSedeId]);

  // Mascotas del cliente
  const clientPets = useMemo(() => {
    if (!client || !client.petCodes) return [];
    return client.petCodes
      .map(code => passports.find(p => p.code === code))
      .filter(Boolean);
  }, [client, passports]);

  // Auto-seleccionar la mascota si el cliente tiene exactamente una.
  // Útil cuando venimos del wizard "Crear ficha + recibo": la mascota recién
  // registrada es la única del tutor, no tiene sentido pedir un click extra.
  // No corre si ya hay mascota seleccionada (respeta cambios manuales del usuario).
  useEffect(() => {
    if (client && !pet && clientPets.length === 1) {
      setPet(clientPets[0]);
    }
  }, [client, pet, clientPets]);

  // Si el cliente seleccionado no pertenece a la sede activa, lo deseleccionamos.
  // Esto pasa por ejemplo si el usuario primero eligió un cliente y luego cambió
  // la sede a una diferente — el cliente queda inconsistente con la sede.
  useEffect(() => {
    if (client && saleSedeId && client.sedeOrigenId && client.sedeOrigenId !== saleSedeId) {
      setClient(null);
      setPet(null);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [saleSedeId]);

  // Cálculos
  const subtotal = useMemo(() => items.reduce((acc, it) => acc + it.total, 0), [items]);
  const tax = useMemo(() => Math.round(subtotal * 0.16), [subtotal]);
  const deliveryAmount = deliveryMode === "paid" ? (Number(deliveryCost) || 0) : 0;
  const total = subtotal + tax + deliveryAmount;

  const addItem = (item) => {
    setItems(prev => [...prev, {
      ...item,
      lineId: `line-${Date.now()}-${Math.random().toString(36).slice(2,5)}`,
      // Programación opcional para servicios. null = "hoy a la hora actual"
      // (la hora real se calcula en handleEmit aplicando detección de conflictos).
      scheduledDate: null,
      scheduledTime: null,
    }]);
    setShowItemPicker(null);
  };

  const removeItem = (lineId) => {
    setItems(prev => prev.filter(it => it.lineId !== lineId));
  };

  const updateQty = (lineId, qty) => {
    const safe = Math.max(1, Number(qty) || 1);
    setItems(prev => prev.map(it =>
      it.lineId === lineId ? { ...it, qty: safe, total: safe * it.unit } : it
    ));
  };

  const updateUnit = (lineId, unit) => {
    const safe = Math.max(0, Number(unit) || 0);
    setItems(prev => prev.map(it =>
      it.lineId === lineId ? { ...it, unit: safe, total: it.qty * safe } : it
    ));
  };

  // Actualizar fecha/hora programada de un servicio. Recibe un patch parcial:
  // { scheduledDate } o { scheduledTime } o ambos. Si llega cadena vacía, se
  // normaliza a null (= "hoy a la hora actual" al emitir).
  const updateScheduled = (lineId, patch) => {
    const norm = {};
    if ("scheduledDate" in patch) norm.scheduledDate = patch.scheduledDate || null;
    if ("scheduledTime" in patch) norm.scheduledTime = patch.scheduledTime || null;
    setItems(prev => prev.map(it =>
      it.lineId === lineId ? { ...it, ...norm } : it
    ));
  };

  // Actualizar recipe de un ítem de medicina. Recibe un patch parcial:
  // { recipe: { medication, dose, ... } } y/o { recipePhoto: base64 }
  const updateRecipe = (lineId, patch) => {
    setItems(prev => prev.map(it => {
      if (it.lineId !== lineId) return it;
      const updated = { ...it };
      if ("recipe" in patch) {
        updated.recipe = patch.recipe ? { ...(it.recipe || {}), ...patch.recipe } : null;
      }
      if ("recipePhoto" in patch) {
        updated.recipePhoto = patch.recipePhoto;
      }
      return updated;
    }));
  };

  const reset = () => {
    setClient(null);
    setPet(null);
    setItems([]);
    setClientSearch("");
    setPaymentMode("full");
    setPartialAmount("");
    setPaymentMethod("efectivo");
    // saleSedeId NO se resetea — la sede del usuario/contexto persiste para la siguiente recibo
  };

  // Validación del monto del abono (debe ser positivo y menor al total)
  const partialNum = Number(partialAmount) || 0;
  const partialValid = paymentMode !== "partial" || (partialNum > 0 && partialNum < total);

  // Para emitir hace falta cliente, items, total y SEDE seleccionada (si el sistema tiene sedes)
  const sedeRequired = sedes && sedes.length > 1;
  const canEmit = client && items.length > 0 && total > 0 && partialValid && (!sedeRequired || !!saleSedeId);

  // Detectar si hay servicios de grooming/vet pendientes en los items.
  // Si los hay, el botón "pagado" no cierra realmente la recibo — el servicio aún
  // debe prestarse y se podrían agregar insumos extra durante la atención.
  const pendingServiceModules = useMemo(() => {
    const modules = items
      .filter(it => it.type === "service" && it.sourceId)
      .map(it => {
        const def = (services || []).find(s => s.id === it.sourceId);
        return def?.module;
      })
      .filter(m => m === "grooming" || m === "vet");
    return [...new Set(modules)];
  }, [items, services]);
  const hasPendingService = pendingServiceModules.length > 0;

  const handleEmit = () => {
    if (!canEmit) return;

    const lastNum = invoices.length === 0 ? 100
      : Math.max(...invoices.map(i => parseInt(i.number.split("-")[1] || "100")));
    const newNumber = `00-${String(lastNum + 1).padStart(7, "0")}`;
    const newInvoiceId = `inv-${Date.now().toString(36)}`;
    const today = new Date();
    const dueDate = new Date(today);
    dueDate.setDate(today.getDate() + 30);
    const fmt = (d) => d.toISOString().slice(0, 10);
    const todayISO = fmt(today);

    // === Detectar si hay servicios pendientes de prestación ===
    // Un servicio (no producto, no medicina, no insumo) se considera "pendiente"
    // si está incluido en la recibo. Resolvemos su módulo contra el catálogo.
    // Si hay al menos un servicio de grooming/vet, la recibo no debe cerrarse al pagar:
    // queda en "emitido" hasta que el área correspondiente preste el servicio.
    const serviceItemsWithModule = items
      .filter(it => it.type === "service" && it.sourceId)
      .map(it => {
        const def = (services || []).find(s => s.id === it.sourceId);
        return { item: it, module: def?.module || null, def };
      });
    const hasPendingService = serviceItemsWithModule.some(s =>
      s.module === "grooming" || s.module === "vet"
    );

    // Convertir items a formato invoice
    const invoiceItems = items.map(it => {
      let description = it.name;
      if (it.type === "service" && pet) description = `${it.name} (${pet.name})`;
      if (it.note) description += ` — ${it.note}`;
      return {
        description,
        qty: it.qty,
        unit: it.unit,
        total: it.total,
      };
    });

    // Calcular pago inicial según modalidad
    let paid = 0;
    let payments = [];
    let state = "borrador";
    let paidInAdvance = false; // marca cuando el cliente paga antes de recibir el servicio

    if (paymentMode === "full") {
      paid = total;
      payments = [{
        id: `pay-${Date.now().toString(36)}`,
        date: fmt(today),
        amount: total,
        method: paymentMethod,
        receivedBy: userName || "Operador",
        note: hasPendingService ? "Pago anticipado del servicio" : "Pago al momento de emisión",
      }];
      // Si hay un servicio pendiente, NO se marca como pagada todavía: el servicio aún no
      // se prestó y puede que se agreguen insumos extra durante la atención.
      // Queda en "emitido" + paid=total + balance=0 hasta que grooming/vet la cierre.
      if (hasPendingService) {
        state = "emitido";
        paidInAdvance = true;
      } else {
        state = "pagado";
      }
    } else if (paymentMode === "partial") {
      paid = partialNum;
      state = "emitido"; // emitida con saldo pendiente
      payments = [{
        id: `pay-${Date.now().toString(36)}`,
        date: fmt(today),
        amount: partialNum,
        method: paymentMethod,
        receivedBy: userName || "Operador",
        note: "Abono inicial",
      }];
    } else {
      // deferred — paga al finalizar
      state = "emitido";
    }

    const balance = total - paid;

    const newInvoice = {
      id: newInvoiceId,
      number: newNumber,
      clientId: client.id,
      issueDate: fmt(today),
      dueDate: fmt(dueDate),
      state,
      items: invoiceItems,
      subtotal,
      tax,
      total,
      paid,
      balance,
      payments,
      paymentMode, // mantener trazabilidad de qué se eligió
      paidInAdvance, // flag clave: ya se cobró pero el servicio aún está pendiente
      createdBy: userName || "Operador",
      // === moduleId: instancia de módulo a la que pertenece esta recibo ===
      // Tomamos el moduleId del primer servicio (ítem que tenía el botón "module:"
      // al agregarse al SaleBuilder). Si no hay servicios — solo productos/medicinas —
      // queda null = recibo del tronco (no pertenece a ningún módulo en particular).
      moduleId: items.find(it => it.moduleId)?.moduleId || null,
      // === sedeId: sede a la que pertenece esta recibo ===
      // Se asigna desde el selector de sede del SaleBuilder.
      // Sirve para filtrar recibos por sede en la vista de Ventas.
      sedeId: saleSedeId || null,
      // === Delivery ===
      delivery: deliveryMode !== "none" ? {
        mode: deliveryMode,        // "paid" | "free"
        cost: deliveryAmount,      // $ si es paid, 0 si es free
        status: "preparando",      // preparando → en-camino → entregado
        timeline: [
          { status: "preparando", date: fmt(today), by: userName || "Operador" },
        ],
      } : null,
      // Datos del primer servicio detectado (si hay) para trazabilidad
      scheduledFor: hasPendingService ? todayISO : null,
      scheduledServiceModule: serviceItemsWithModule[0]?.module || null,
      scheduledServiceId: serviceItemsWithModule[0]?.def?.id || null,
    };

    setInvoices(prev => [newInvoice, ...prev]);

    // === Crear bookings de grooming + eventos de agenda para los servicios ===
    // Acumulamos in-memory los slots ya ocupados *durante esta emisión* para que
    // si la misma recibo tiene 2 servicios en el mismo día, el segundo no caiga
    // sobre el primero (los nuevos eventos aún no están en groomingBookings/agendaEvents).
    const provisionalGroomingBlocks = []; // { date, time, duration }
    const provisionalAgendaBlocks = [];   // { date, time, duration } — solo type=vet
    // Resumen de programación para devolver al callback (útil para mostrar al usuario qué se reagendó).
    const scheduledSummary = [];

    serviceItemsWithModule.forEach((entry, idx) => {
      const { item, module, def } = entry;
      if (!def) return;
      const evtId = `evt-${Date.now().toString(36)}-${idx}-${Math.random().toString(36).slice(2,4)}`;
      const duration = def.duration || 60;

      // === Resolver fecha y hora del servicio ===
      // Si el item trae scheduledDate/Time, los respetamos. Si no, usamos hoy + ahora.
      // Luego aplicamos detección de conflictos contra los eventos existentes
      // (del módulo correspondiente) + los provisionales de esta misma emisión.
      const requestedDate = item.scheduledDate || todayISO;
      const requestedTime = item.scheduledTime || nowHHMM();
      const wasUserScheduled = !!(item.scheduledDate || item.scheduledTime);

      let finalTime;
      if (module === "grooming") {
        const blocks = [
          ...(groomingBookings || []).filter(b => b.eventDate === requestedDate && b.time && b.time !== "—")
            .map(b => ({ date: b.eventDate, time: b.time, duration: b.duration || 60 })),
          ...provisionalGroomingBlocks.filter(b => b.date === requestedDate),
        ];
        finalTime = findNextFreeTime(
          blocks.map(b => ({ date: b.date, time: b.time, duration: b.duration })),
          requestedDate, requestedTime, duration
        );
        provisionalGroomingBlocks.push({ date: requestedDate, time: finalTime, duration });
      } else if (module === "vet") {
        const blocks = [
          ...(agendaEvents || []).filter(e => e.type === "vet" && e.date === requestedDate && e.time)
            .map(e => ({ date: e.date, time: e.time, duration: e.duration || 60 })),
          ...provisionalAgendaBlocks.filter(b => b.date === requestedDate),
        ];
        finalTime = findNextFreeTime(
          blocks.map(b => ({ date: b.date, time: b.time, duration: b.duration })),
          requestedDate, requestedTime, duration
        );
        provisionalAgendaBlocks.push({ date: requestedDate, time: finalTime, duration });
      } else {
        finalTime = requestedTime;
      }

      const wasShifted = finalTime !== requestedTime;
      scheduledSummary.push({
        name: def.name,
        module,
        date: requestedDate,
        time: finalTime,
        wasUserScheduled,
        wasShifted,
      });

      // Booking de grooming si el servicio es de grooming
      if (module === "grooming" && setGroomingBookings) {
        const newBooking = {
          id: `gb-${Date.now().toString(36)}-${idx}-${Math.random().toString(36).slice(2,4)}`,
          eventDate: requestedDate,
          time: finalTime,
          duration,
          pet: pet?.name || "",
          petCode: pet?.code || null,
          species: pet?.species || null,
          breed: pet?.breed || "",
          owner: client.name,
          clientId: client.id,
          service: def.name,
          reason: `Servicio recibodo (${newNumber}). ${paidInAdvance ? "Pago anticipado." : ""}`.trim(),
          room: def.room || "Sala de grooming",
          status: "pending",
          supplies: [],
          notes: "",
          // Hilo conductor
          invoiceNumber: newNumber,
          invoiceId: newInvoiceId,
          fromQuickSale: true,
          paidInAdvance,
          // Etiquetar con la instancia origen del servicio
          moduleId: resolveServiceModuleId(def) || "grooming-ops",
        };
        setGroomingBookings(prev => [newBooking, ...prev]);
      }

      // Evento de agenda para todos los servicios (grooming/vet/b2b)
      if (setAgendaEvents) {
        const evtType =
          module === "vet" ? "vet" :
          module === "grooming" ? "grooming" :
          module === "b2b" ? "b2b" : "other";
        const newEvent = {
          id: evtId,
          type: evtType,
          date: requestedDate,
          time: finalTime,
          duration,
          pet: pet?.name || "",
          petCode: pet?.code || null,
          species: pet?.species || null,
          breed: pet?.breed || "",
          owner: client.name,
          professional: null,
          title: def.name,
          reason: `Servicio recibodo en ${newNumber}.`,
          room: def.room || null,
          status: "confirmada",
          price: def.price,
          invoiceNumber: newNumber,
          invoiceId: newInvoiceId,
          clientId: client.id,
          // Etiquetar con la instancia origen del servicio
          moduleId: resolveServiceModuleId(def) || null,
        };
        setAgendaEvents(prev => [newEvent, ...prev]);
      }
    });

    onSaleCreated?.({
      number: newNumber,
      itemCount: items.length,
      total,
      paymentMode,
      paid,
      balance,
      hasPendingService,
      // Lista de servicios con su fecha/hora finales — incluye los que se deslizaron
      // por conflicto (wasShifted=true) y los explícitamente programados (wasUserScheduled=true).
      scheduledServices: scheduledSummary,
    });
    reset();
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
      {/* COLUMNA 1: Cliente */}
      <div className="lg:col-span-1 bg-white border border-stone-200 rounded-2xl shadow-sm overflow-hidden self-start">
        <div className="p-4 border-b border-stone-200 bg-gradient-to-br from-white to-orange-50">
          <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold flex items-center gap-2">
            <User size={12} /> Cliente
          </div>
          <div className="font-serif text-lg font-semibold mt-0.5">¿A quién recibos?</div>
        </div>

        <div className="p-3 space-y-3">
          {/* === Selector de sede ===
              Solo se muestran las sedes a las que el usuario tiene acceso.
              Si el usuario tiene 1 sola sede, no se muestra el selector entero
              (la sede queda autoseleccionada). El super (sin restricción) ve todas. */}
          {(() => {
            // Calcular sedes a las que este usuario puede cobrar
            const userRestricted = userSedeIds && userSedeIds.length > 0;
            const availableSedes = userRestricted
              ? (sedes || []).filter(s => userSedeIds.includes(s.id))
              : (sedes || []);
            // Si hay 0 o 1 sede disponible, no mostramos el selector
            if (availableSedes.length <= 1) return null;
            return (
              <div className="bg-stone-50 border border-stone-200 rounded-xl p-3">
                <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold mb-2 flex items-center gap-1.5">
                  <MapPin size={11} />
                  Sede de la recibo *
                </div>
                <div className="flex flex-wrap gap-1.5">
                  {availableSedes.map(sede => {
                    const active = saleSedeId === sede.id;
                    return (
                      <button
                        key={sede.id}
                        onClick={() => setSaleSedeId(sede.id)}
                        className={`text-xs font-semibold px-3 py-1.5 rounded-lg transition flex items-center gap-1 ${
                          active
                            ? "bg-orange-600 text-white shadow"
                            : "bg-white border border-stone-200 text-stone-700 hover:border-orange-400"
                        }`}
                      >
                        <MapPin size={10} />
                        {sede.name}
                      </button>
                    );
                  })}
                </div>
                {!saleSedeId && (
                  <div className="text-[11px] text-amber-700 mt-2 italic">
                    Selecciona una sede antes de cobrar.
                  </div>
                )}
              </div>
            );
          })()}

          {/* Cliente seleccionado */}
          {client ? (
            <>
              <div className="bg-emerald-50 border border-emerald-300 rounded-xl p-3 flex items-center gap-3">
                <div className={`w-10 h-10 rounded-xl grid place-items-center text-white text-xs font-bold flex-shrink-0 ${
                  client.isOrg
                    ? "bg-gradient-to-br from-stone-700 to-stone-900"
                    : "bg-gradient-to-br from-orange-500 to-orange-700"
                }`}>
                  {client.name.split(" ").slice(0, 2).map(s => s[0]).join("").toUpperCase()}
                </div>
                <div className="flex-1 min-w-0">
                  <div className="font-semibold text-sm truncate">{client.name}</div>
                  <div className="text-xs text-stone-500 font-mono truncate">{client.cedula}</div>
                </div>
                <button
                  onClick={() => { setClient(null); setPet(null); }}
                  className="w-7 h-7 rounded-lg bg-white border border-stone-200 hover:border-red-300 grid place-items-center text-stone-500 hover:text-red-600 transition flex-shrink-0"
                  title="Cambiar"
                >
                  <X size={11} />
                </button>
              </div>

              {/* Mascotas (opcional) */}
              {clientPets.length > 0 && (
                <div>
                  <div className="text-xs text-stone-500 font-semibold mb-1.5">
                    ¿Asociar a una mascota? <span className="text-stone-400 font-normal">(opcional)</span>
                  </div>
                  <div className="space-y-1">
                    {clientPets.map(p => {
                      const Ic = ANIMAL_ICONS[p.species] || PawPrint;
                      const active = pet?.id === p.id;
                      return (
                        <button
                          key={p.id}
                          onClick={() => setPet(active ? null : p)}
                          className={`w-full flex items-center gap-2 p-2 rounded-lg border transition text-left ${
                            active
                              ? "bg-orange-50 border-orange-400 ring-1 ring-orange-300"
                              : "bg-white border-stone-200 hover:border-orange-300"
                          }`}
                        >
                          <div className="w-7 h-7 rounded-lg bg-gradient-to-br from-orange-200 to-orange-100 grid place-items-center text-orange-800 flex-shrink-0">
                            <Ic size={12} strokeWidth={1.8} />
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="font-semibold text-xs truncate">{p.name}</div>
                            <div className="text-xs text-stone-500 truncate">{p.breed}</div>
                          </div>
                          {active && <Check size={11} className="text-orange-600 flex-shrink-0" />}
                        </button>
                      );
                    })}
                  </div>
                </div>
              )}
            </>
          ) : (
            <>
              <div className="relative">
                <Search size={14} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-stone-400" />
                <input
                  value={clientSearch}
                  onChange={(e) => setClientSearch(e.target.value)}
                  placeholder="Nombre, cédula o teléfono..."
                  className="w-full pl-10 pr-3 py-2 bg-stone-50 border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500 focus:bg-white"
                />
              </div>
              <div className="bg-white border border-stone-200 rounded-xl divide-y divide-stone-100 max-h-72 overflow-y-auto">
                {filteredClients.length === 0 ? (
                  <div className="p-4 text-center text-sm text-stone-500">Sin resultados.</div>
                ) : (
                  filteredClients.map(c => (
                    <button
                      key={c.id}
                      onClick={() => setClient(c)}
                      className="w-full flex items-center gap-2 p-2 hover:bg-orange-50 transition text-left"
                    >
                      <div className={`w-8 h-8 rounded-lg grid place-items-center text-white text-xs font-bold flex-shrink-0 ${
                        c.isOrg
                          ? "bg-gradient-to-br from-stone-700 to-stone-900"
                          : "bg-gradient-to-br from-orange-500 to-orange-700"
                      }`}>
                        {c.name.split(" ").slice(0, 2).map(s => s[0]).join("").toUpperCase()}
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="font-semibold text-sm truncate">{c.name}</div>
                        <div className="text-xs text-stone-500 font-mono truncate">{c.cedula}</div>
                      </div>
                    </button>
                  ))
                )}
              </div>
            </>
          )}
        </div>
      </div>

      {/* COLUMNA 2-3: Recibo en construcción */}
      <div className="lg:col-span-2 bg-white border border-stone-200 rounded-2xl shadow-sm overflow-hidden flex flex-col">
        <div className="p-4 border-b border-stone-200 bg-gradient-to-br from-white to-orange-50 flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-orange-500 to-orange-700 text-white grid place-items-center flex-shrink-0 shadow">
            <Receipt size={17} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold">
              Recibo en construcción
            </div>
            <div className="font-serif text-lg font-semibold mt-0.5">
              {items.length === 0 ? "Sin ítems aún" : `${items.length} ${items.length === 1 ? "ítem" : "ítems"}`}
            </div>
          </div>
          {items.length > 0 && (
            <button
              onClick={() => setItems([])}
              className="text-xs text-stone-500 hover:text-red-600 font-semibold transition"
            >
              Vaciar
            </button>
          )}
        </div>

        {/* Botones agregar — dinámicos según módulos instalados.
            Servicio (vet) y Grooming aparecen solo si su módulo NO está eliminado.
            Producto, Medicina y Personalizado son del tronco — siempre presentes. */}
        <div className="p-3 grid grid-cols-2 lg:grid-cols-5 gap-2 border-b border-stone-200 bg-stone-50">
          {(() => {
            // Generar UN botón por cada módulo instalado de tipo vet/grooming/custom.
            // Filtramos por sede activa de la recibo: si saleSedeId === "sede-pet1",
            // solo aparecen los CRMs de Pet 1. Esto evita que veas "Veterinaria Pet 2"
            // cuando estás cobrando en Pet 1. Si aún no hay sede seleccionada,
            // mostramos todos los CRMs (el usuario aún no decidió).
            const buttons = [];
            const installedModules = (modules || []).filter(m => {
              if (m.removed) return false;
              if (m.kind !== "vet" && m.kind !== "grooming") return false;
              // Filtro estricto por sede de la recibo
              if (saleSedeId && m.sedeId && m.sedeId !== saleSedeId) return false;
              return true;
            });

            installedModules.forEach(m => {
              const isVet = m.kind === "vet";
              buttons.push({
                id: `module:${m.id}`,            // ← prefijo "module:" para diferenciar de tronco
                moduleId: m.id,                  // se usa para filtrar catálogo
                label: m.shortName || m.name,
                Icon: isVet ? Stethoscope : Bath,
                color: isVet ? "orange" : "emerald",
              });
            });
            // Tronco fijo: producto, medicina, personalizado
            buttons.push({ id: "product", label: "Producto", Icon: ShoppingBag, color: "blue" });
            buttons.push({ id: "medicine", label: "Medicina", Icon: Pill, color: "purple" });
            buttons.push({ id: "custom", label: "Personalizado", Icon: Plus, color: "stone" });
            return buttons;
          })().map(t => {
            const Ic = t.Icon;
            const colorClass = {
              orange: "border-orange-200 hover:border-orange-400 text-orange-700 hover:bg-orange-50",
              emerald: "border-emerald-200 hover:border-emerald-400 text-emerald-700 hover:bg-emerald-50",
              blue: "border-blue-200 hover:border-blue-400 text-blue-700 hover:bg-blue-50",
              purple: "border-purple-200 hover:border-purple-400 text-purple-700 hover:bg-purple-50",
              stone: "border-stone-200 hover:border-stone-400 text-stone-700 hover:bg-stone-50",
            }[t.color];
            return (
              <button
                key={t.id}
                // Si el botón es de un módulo (id="module:xxx"), pasamos un objeto
                // con type + moduleId al picker. Si es tronco, solo el type.
                onClick={() => {
                  if (t.id.startsWith("module:")) {
                    setShowItemPicker({ type: "module", moduleId: t.moduleId });
                  } else {
                    setShowItemPicker(t.id);
                  }
                }}
                className={`flex flex-col items-center gap-1 px-2 py-2.5 rounded-xl bg-white border-2 text-xs font-semibold transition ${colorClass}`}
              >
                <Ic size={14} strokeWidth={1.8} />
                <span className="truncate max-w-full">{t.label}</span>
              </button>
            );
          })}
        </div>

        {/* Lista de ítems */}
        <div className="flex-1 overflow-y-auto max-h-96">
          {items.length === 0 ? (
            <div className="p-8 text-center">
              <Receipt size={28} className="text-stone-300 mx-auto mb-2" />
              <div className="text-sm font-semibold text-stone-700">La recibo está vacía</div>
              <div className="text-xs text-stone-500 mt-1">
                Usa los botones de arriba para agregar servicios, productos o medicinas.
              </div>
            </div>
          ) : (
            <div className="divide-y divide-stone-100">
              {items.map(it => (
                <SaleItemRow
                  key={it.lineId}
                  item={it}
                  onUpdateQty={(qty) => updateQty(it.lineId, qty)}
                  onUpdateUnit={(unit) => updateUnit(it.lineId, unit)}
                  onUpdateScheduled={(patch) => updateScheduled(it.lineId, patch)}
                  onUpdateRecipe={(patch) => updateRecipe(it.lineId, patch)}
                  onRemove={() => removeItem(it.lineId)}
                />
              ))}
            </div>
          )}
        </div>

        {/* Resumen + modalidad de pago + emitir */}
        <div className="border-t border-stone-200 p-4 space-y-3 bg-stone-50">
          <div className="space-y-1 text-sm">
            <div className="flex justify-between text-stone-600">
              <span>Subtotal</span>
              <span className="font-mono">${subtotal.toLocaleString()}</span>
            </div>
            <div className="flex justify-between text-stone-600">
              <span>IVA 16%</span>
              <span className="font-mono">${tax.toLocaleString()}</span>
            </div>
            {deliveryAmount > 0 && (
              <div className="flex justify-between text-cyan-700">
                <span className="flex items-center gap-1"><Truck size={12} /> Delivery</span>
                <span className="font-mono">${deliveryAmount.toLocaleString()}</span>
              </div>
            )}
            <div className="flex justify-between font-bold text-lg pt-2 border-t border-stone-300">
              <span>Total</span>
              <span className="font-mono text-orange-700">${total.toLocaleString()}</span>
            </div>
          </div>

          {/* === Delivery === */}
          <div className="bg-white border border-stone-200 rounded-xl p-3 space-y-2">
            <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold flex items-center gap-1.5">
              <Truck size={11} /> Delivery
            </div>
            <div className="grid grid-cols-3 gap-1.5">
              {[
                { id: "none", label: "Sin delivery",         desc: "Retira en sede",     color: "stone" },
                { id: "paid", label: "Delivery con costo",   desc: "Envío cobrado",      color: "cyan" },
                { id: "free", label: "Solo seguimiento",     desc: "Envío sin costo",    color: "emerald" },
              ].map(opt => {
                const active = deliveryMode === opt.id;
                return (
                  <button
                    key={opt.id}
                    type="button"
                    onClick={() => setDeliveryMode(opt.id)}
                    className={`p-2.5 rounded-xl border-2 text-left transition ${
                      active
                        ? opt.color === "cyan"
                          ? "border-cyan-500 bg-cyan-50"
                          : opt.color === "emerald"
                            ? "border-emerald-500 bg-emerald-50"
                            : "border-stone-400 bg-stone-50"
                        : "border-stone-200 bg-white hover:border-stone-300"
                    }`}
                  >
                    <div className="flex items-center gap-1.5 mb-0.5">
                      <div className={`w-4 h-4 rounded-full border-2 flex-shrink-0 grid place-items-center ${
                        active
                          ? opt.color === "cyan" ? "border-cyan-500 bg-cyan-500" : opt.color === "emerald" ? "border-emerald-500 bg-emerald-500" : "border-stone-500 bg-stone-500"
                          : "border-stone-300"
                      }`}>
                        {active && <Check size={8} className="text-white" strokeWidth={3} />}
                      </div>
                      <span className="text-xs font-semibold text-stone-800">{opt.label}</span>
                    </div>
                    <div className="text-[10px] text-stone-500 pl-5">{opt.desc}</div>
                  </button>
                );
              })}
            </div>
            {deliveryMode === "paid" && (
              <div className="flex items-center gap-2 pt-1">
                <span className="text-xs text-stone-600 font-semibold">Costo del envío:</span>
                <div className="flex items-center gap-0.5 bg-stone-100 rounded-lg px-2 py-1">
                  <span className="text-xs font-mono text-stone-500">$</span>
                  <input
                    type="number"
                    value={deliveryCost}
                    onChange={(e) => setDeliveryCost(e.target.value)}
                    className="w-16 bg-transparent text-xs font-mono font-bold outline-none text-right"
                    min="0"
                  />
                </div>
              </div>
            )}
            {deliveryMode !== "none" && (
              <div className="bg-cyan-50 border border-cyan-200 rounded-lg p-2 text-[11px] text-cyan-800 flex items-center gap-1.5">
                <Info size={11} className="flex-shrink-0" />
                {deliveryMode === "paid"
                  ? "Se agregará el costo del envío al total. El recibo incluirá un tracker de seguimiento."
                  : "El recibo incluirá un tracker de seguimiento de delivery sin costo adicional."}
              </div>
            )}
          </div>

          {/* Modalidad de pago — solo visible cuando hay total > 0 */}
          {total > 0 && (
            <div className="bg-white border border-stone-200 rounded-xl p-3 space-y-3">
              <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold flex items-center gap-1.5">
                <Wallet size={11} /> Modalidad de pago
              </div>

              {/* 3 opciones grandes */}
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-2">
                {[
                  { id: "full",     label: "Pago total",       desc: "Cliente paga ahora",         Icon: Check,    color: "emerald" },
                  { id: "partial",  label: "Abono inicial",    desc: "Paga parte ahora",           Icon: Coins,    color: "amber" },
                  { id: "deferred", label: "Pago al finalizar", desc: "Cobrar al entregar",         Icon: Clock,    color: "stone" },
                ].map(m => {
                  const Ic = m.Icon;
                  const active = paymentMode === m.id;
                  const colors = {
                    emerald: { bg: "bg-emerald-50", border: "border-emerald-400", text: "text-emerald-700", iconBg: "bg-emerald-100" },
                    amber:   { bg: "bg-amber-50",   border: "border-amber-400",   text: "text-amber-700",   iconBg: "bg-amber-100" },
                    stone:   { bg: "bg-stone-100",  border: "border-stone-400",   text: "text-stone-700",   iconBg: "bg-stone-200" },
                  }[m.color];
                  return (
                    <button
                      key={m.id}
                      onClick={() => setPaymentMode(m.id)}
                      className={`p-2.5 rounded-lg border-2 text-left transition ${
                        active ? `${colors.bg} ${colors.border}` : "bg-white border-stone-200 hover:border-stone-400"
                      }`}
                    >
                      <div className={`w-7 h-7 rounded-lg grid place-items-center mb-1.5 ${
                        active ? colors.iconBg : "bg-stone-100"
                      } ${active ? colors.text : "text-stone-500"}`}>
                        <Ic size={13} strokeWidth={2} />
                      </div>
                      <div className={`font-semibold text-xs ${active ? colors.text : "text-stone-800"}`}>
                        {m.label}
                      </div>
                      <div className="text-xs text-stone-500 leading-tight mt-0.5">{m.desc}</div>
                    </button>
                  );
                })}
              </div>

              {/* Campo de monto del abono (solo en modo partial) */}
              {paymentMode === "partial" && (
                <div className="bg-amber-50 border border-amber-200 rounded-lg p-3 space-y-2">
                  <label className="text-xs font-semibold text-amber-900 block">
                    ¿Cuánto abona ahora? <span className="text-amber-600">(menor a ${total.toLocaleString()})</span>
                  </label>
                  <div className="relative">
                    <span className="absolute left-3 top-1/2 -translate-y-1/2 text-stone-400 font-mono">$</span>
                    <input
                      type="number"
                      min="0"
                      max={total}
                      step="0.01"
                      value={partialAmount}
                      onChange={(e) => setPartialAmount(e.target.value)}
                      placeholder="0"
                      className="w-full pl-7 pr-3 py-2 bg-white border border-amber-300 rounded-lg text-sm font-mono outline-none focus:border-amber-500"
                    />
                  </div>
                  {/* Atajos de % */}
                  <div className="flex gap-1.5">
                    {[25, 50, 75].map(pct => (
                      <button
                        key={pct}
                        onClick={() => setPartialAmount(String(Math.round(total * pct / 100)))}
                        className="flex-1 px-2 py-1 rounded-lg text-xs font-bold bg-white border border-amber-200 text-amber-700 hover:bg-amber-100 transition"
                      >
                        {pct}%
                      </button>
                    ))}
                  </div>
                  {partialNum > 0 && (
                    <div className="text-xs text-amber-900 flex justify-between pt-1">
                      <span>Saldo pendiente:</span>
                      <span className="font-mono font-bold">${(total - partialNum).toLocaleString()}</span>
                    </div>
                  )}
                  {partialNum >= total && partialAmount && (
                    <div className="text-xs text-red-700 bg-red-50 border border-red-200 rounded p-2">
                      El abono no puede ser igual o mayor al total. Si paga todo, usa "Pago total".
                    </div>
                  )}
                </div>
              )}

              {/* Método de pago (cuando hay pago inicial) */}
              {(paymentMode === "full" || paymentMode === "partial") && (
                <div>
                  <div className="text-xs font-semibold text-stone-700 mb-1.5">Método</div>
                  <div className="grid grid-cols-2 sm:grid-cols-4 gap-1.5">
                    {(() => {
                      // Mapa de iconos: el ajuste guarda un nombre string para
                      // que sea serializable; aquí lo resolvemos al componente real.
                      const ICON_MAP = {
                        Banknote, CreditCard, ArrowRightLeft, Smartphone, Wallet, Coins,
                      };
                      // Si vienen métodos configurados, usamos esos (filtrando los habilitados).
                      // Si no, fallback al hardcoded para compatibilidad con vistas que no pasen el prop.
                      const enabled = (paymentMethods && paymentMethods.length > 0)
                        ? paymentMethods.filter(m => m.enabled).map(m => ({
                            id: m.id, label: m.label, Icon: ICON_MAP[m.iconName] || Wallet, source: m,
                          }))
                        : [
                            { id: "efectivo",      label: "Efectivo",     Icon: Banknote },
                            { id: "tarjeta",       label: "Tarjeta",      Icon: CreditCard },
                            { id: "transferencia", label: "Transf.",      Icon: ArrowRightLeft },
                            { id: "pago-movil",    label: "Pago móvil",   Icon: Smartphone },
                          ];
                      return enabled.map(m => {
                        const Ic = m.Icon;
                        const active = paymentMethod === m.id;
                        return (
                          <button
                            key={m.id}
                            onClick={() => setPaymentMethod(m.id)}
                            className={`flex flex-col items-center gap-1 p-2 rounded-lg border text-xs font-semibold transition ${
                              active
                                ? "bg-stone-900 border-stone-900 text-white"
                                : "bg-white border-stone-200 text-stone-600 hover:border-stone-400"
                            }`}
                          >
                            <Ic size={12} strokeWidth={1.8} />
                            {m.label}
                          </button>
                        );
                      });
                    })()}
                  </div>

                  {/* === Detalles del método seleccionado === */}
                  {(() => {
                    const selectedMethod = (paymentMethods || []).find(m => m.id === paymentMethod);
                    if (!selectedMethod) return null;
                    const rows = renderPaymentMethodDetails(selectedMethod);
                    if (!rows || rows.length === 0) {
                      // Si no hay datos cargados, mostrar aviso al admin
                      const isCash = selectedMethod.id === "efectivo";
                      if (isCash) return null;
                      return (
                        <div className="mt-2 bg-amber-50 border border-amber-200 rounded-lg p-2.5 text-xs text-amber-800 flex items-start gap-2">
                          <AlertCircle size={11} className="flex-shrink-0 mt-0.5" />
                          <div>
                            <strong className="block">Sin datos configurados</strong>
                            <span>El admin debe completar los datos de este método en Ajustes → Métodos de pago para que se puedan enviar al cliente.</span>
                          </div>
                        </div>
                      );
                    }
                    return (
                      <div className="mt-2 bg-blue-50 border border-blue-200 rounded-lg p-2.5 space-y-1.5">
                        <div className="flex items-center gap-1.5 text-[10px] tracking-widest uppercase text-blue-700 font-bold">
                          <Info size={10} /> Datos para el cliente
                        </div>
                        <div className="space-y-1">
                          {rows.map((r, i) => (
                            <div key={i} className="flex items-baseline justify-between gap-2 text-xs">
                              <span className={`text-stone-600 ${r.alert ? "font-bold text-red-700" : ""}`}>{r.label}:</span>
                              <span className={`text-stone-900 font-semibold text-right break-all ${r.mono ? "font-mono" : ""}`}>{r.value}</span>
                            </div>
                          ))}
                        </div>
                      </div>
                    );
                  })()}
                </div>
              )}

              {/* Resumen del estado final */}
              <div className={`rounded-lg p-2.5 text-xs ${
                paymentMode === "full" && hasPendingService ? "bg-blue-50 text-blue-900 border border-blue-200" :
                paymentMode === "full" ? "bg-emerald-50 text-emerald-900 border border-emerald-200" :
                paymentMode === "partial" ? "bg-amber-50 text-amber-900 border border-amber-200" :
                "bg-stone-100 text-stone-700 border border-stone-200"
              }`}>
                {paymentMode === "full" && hasPendingService && (
                  <>
                    <strong>Pago anticipado.</strong> La recibo quedará en <strong>emitido</strong> hasta que {pendingServiceModules.includes("grooming") ? "Grooming" : "Veterinaria"} complete el servicio. Si se agregan insumos, se cobrará la diferencia al cierre.
                  </>
                )}
                {paymentMode === "full" && !hasPendingService && <>La recibo se emitirá como <strong>pagada</strong>. Saldo: $0.</>}
                {paymentMode === "partial" && (
                  <>La recibo se emitirá <strong>parcialmente pagada</strong>.{partialNum > 0 && partialNum < total && <> Saldo pendiente: <span className="font-mono font-bold">${(total - partialNum).toLocaleString()}</span>.</>}</>
                )}
                {paymentMode === "deferred" && <>La recibo se emitirá <strong>pendiente</strong>. Saldo: <span className="font-mono font-bold">${total.toLocaleString()}</span>.</>}
              </div>
            </div>
          )}

          <button
            onClick={handleEmit}
            disabled={!canEmit}
            className={`w-full flex items-center justify-center gap-2 px-4 py-3 rounded-xl text-sm font-semibold transition shadow ${
              canEmit
                ? "bg-emerald-500 hover:bg-emerald-600 text-white"
                : "bg-stone-200 text-stone-400 cursor-not-allowed"
            }`}
          >
            <Check size={14} strokeWidth={2.5} />
            {!client ? "Selecciona un cliente" :
             items.length === 0 ? "Agrega al menos un ítem" :
             paymentMode === "partial" && !partialValid ? "Indica el monto del abono" :
             paymentMode === "full" ? "Emitir recibo y cobrar" :
             paymentMode === "partial" ? `Emitir y cobrar abono $${partialNum.toLocaleString()}` :
             "Emitir recibo (cobro pendiente)"}
          </button>
        </div>
      </div>

      {/* Modal selector de ítems */}
      {showItemPicker && (
        <ItemPickerModal
          type={typeof showItemPicker === "object" ? showItemPicker.type : showItemPicker}
          moduleId={typeof showItemPicker === "object" ? showItemPicker.moduleId : null}
          modules={modules}
          services={services}
          supplies={supplies}
          inventoryItems={inventoryItems}
          onClose={() => setShowItemPicker(null)}
          onAdd={addItem}
        />
      )}
    </div>
  );
}

// === Fila de ítem en la recibo en construcción ===
function SaleItemRow({ item, onUpdateQty, onUpdateUnit, onUpdateScheduled, onUpdateRecipe, onRemove }) {
  const typeColors = {
    service:  { bg: "bg-orange-100",  text: "text-orange-700",  Icon: Stethoscope, label: "Servicio" },
    product:  { bg: "bg-blue-100",    text: "text-blue-700",    Icon: ShoppingBag, label: "Producto" },
    medicine: { bg: "bg-purple-100",  text: "text-purple-700",  Icon: Pill,        label: "Medicina" },
    custom:   { bg: "bg-stone-100",   text: "text-stone-700",   Icon: Plus,        label: "Personalizado" },
  }[item.type] || { bg: "bg-stone-100", text: "text-stone-700", Icon: Tag, label: "Ítem" };
  const Ic = typeColors.Icon;

  const isMedicine = item.type === "medicine";
  const [showRecipe, setShowRecipe] = useState(false);

  // Solo los servicios pueden programarse — productos/medicinas/insumos no agendan.
  const isSchedulable = item.type === "service";
  // Hoy en formato YYYY-MM-DD para el min del input de fecha
  const todayISO = new Date().toISOString().slice(0, 10);

  // Handler para foto de recipe
  const handleRecipePhoto = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      onUpdateRecipe?.({ recipePhoto: ev.target.result });
    };
    reader.readAsDataURL(file);
    e.target.value = "";
  };

  return (
    <div className="p-3 flex items-start gap-3">
      <div className={`w-8 h-8 rounded-lg ${typeColors.bg} ${typeColors.text} grid place-items-center flex-shrink-0`}>
        <Ic size={13} strokeWidth={1.8} />
      </div>
      <div className="flex-1 min-w-0">
        <div className="flex items-baseline justify-between gap-2 flex-wrap">
          <span className="font-semibold text-sm truncate">{item.name}</span>
          <div className="flex items-center gap-1.5">
            {isMedicine && item.requiresRecipe && (
              <span className="text-[9px] font-bold px-1.5 py-px rounded bg-red-100 text-red-700 uppercase">Recipe</span>
            )}
            <span className={`text-xs font-bold uppercase tracking-wide ${typeColors.text}`}>
              {typeColors.label}
            </span>
          </div>
        </div>
        {item.note && (
          <div className="text-xs text-stone-500 mt-0.5 italic truncate">{item.note}</div>
        )}
        <div className="flex items-center gap-2 mt-2 flex-wrap">
          {/* Cantidad */}
          <div className="flex items-center gap-1 bg-stone-100 rounded-lg p-0.5">
            <button
              onClick={() => onUpdateQty(item.qty - 1)}
              className="w-6 h-6 rounded grid place-items-center hover:bg-white text-stone-600 transition"
            >
              <ChevronLeft size={11} />
            </button>
            <input
              type="number"
              value={item.qty}
              onChange={(e) => onUpdateQty(e.target.value)}
              className="w-10 text-center bg-transparent text-xs font-mono font-bold outline-none"
            />
            <button
              onClick={() => onUpdateQty(item.qty + 1)}
              className="w-6 h-6 rounded grid place-items-center hover:bg-white text-stone-600 transition"
            >
              <ChevronRight size={11} />
            </button>
          </div>
          <span className="text-stone-400 text-xs">×</span>
          {/* Precio unitario editable */}
          <div className="flex items-center gap-0.5 bg-stone-100 rounded-lg px-2 py-1">
            <span className="text-xs font-mono text-stone-500">$</span>
            <input
              type="number"
              value={item.unit}
              onChange={(e) => onUpdateUnit(e.target.value)}
              className="w-14 bg-transparent text-xs font-mono font-bold outline-none text-right"
            />
          </div>
          <span className="ml-auto font-mono text-sm font-bold text-stone-900">
            ${item.total.toLocaleString()}
          </span>
        </div>

        {/* === Recipe para medicinas === */}
        {isMedicine && onUpdateRecipe && (
          <div className="mt-2 pt-2 border-t border-stone-100">
            <button
              type="button"
              onClick={() => setShowRecipe(!showRecipe)}
              className={`flex items-center gap-1.5 text-xs font-semibold transition ${
                showRecipe || item.recipe || item.recipePhoto
                  ? "text-purple-700"
                  : item.requiresRecipe
                    ? "text-red-600 hover:text-red-700"
                    : "text-stone-500 hover:text-purple-600"
              }`}
            >
              <FileText size={11} />
              {item.recipe || item.recipePhoto
                ? "📋 Recipe adjunto"
                : item.requiresRecipe
                  ? "⚠️ Adjuntar recipe (requerido)"
                  : "+ Adjuntar recipe (opcional)"}
              <ChevronDown size={10} className={`transition ${showRecipe ? "rotate-180" : ""}`} />
            </button>

            {showRecipe && (
              <div className="mt-2 space-y-2 bg-purple-50 border border-purple-200 rounded-xl p-2.5">
                {/* Campos de receta */}
                <input
                  type="text"
                  value={item.recipe?.medication || item.name}
                  onChange={(e) => onUpdateRecipe({ recipe: { ...(item.recipe || {}), medication: e.target.value } })}
                  placeholder="Medicamento"
                  className="w-full px-2.5 py-1.5 border border-stone-200 rounded-lg text-xs outline-none focus:border-purple-400 bg-white font-semibold"
                />
                <div className="grid grid-cols-2 gap-1.5">
                  <input type="text" value={item.recipe?.dose || ""}
                    onChange={(e) => onUpdateRecipe({ recipe: { ...(item.recipe || {}), dose: e.target.value } })}
                    placeholder="Dosis" className="px-2.5 py-1.5 border border-stone-200 rounded-lg text-xs outline-none focus:border-purple-400 bg-white" />
                  <input type="text" value={item.recipe?.frequency || ""}
                    onChange={(e) => onUpdateRecipe({ recipe: { ...(item.recipe || {}), frequency: e.target.value } })}
                    placeholder="Frecuencia (c/8h)" className="px-2.5 py-1.5 border border-stone-200 rounded-lg text-xs outline-none focus:border-purple-400 bg-white" />
                </div>
                <div className="grid grid-cols-2 gap-1.5">
                  <input type="text" value={item.recipe?.duration || ""}
                    onChange={(e) => onUpdateRecipe({ recipe: { ...(item.recipe || {}), duration: e.target.value } })}
                    placeholder="Duración (7 días)" className="px-2.5 py-1.5 border border-stone-200 rounded-lg text-xs outline-none focus:border-purple-400 bg-white" />
                  <input type="text" value={item.recipe?.route || ""}
                    onChange={(e) => onUpdateRecipe({ recipe: { ...(item.recipe || {}), route: e.target.value } })}
                    placeholder="Vía (oral, IM)" className="px-2.5 py-1.5 border border-stone-200 rounded-lg text-xs outline-none focus:border-purple-400 bg-white" />
                </div>
                <textarea value={item.recipe?.instructions || ""}
                  onChange={(e) => onUpdateRecipe({ recipe: { ...(item.recipe || {}), instructions: e.target.value } })}
                  placeholder="Indicaciones para el tutor..."
                  rows={2} className="w-full px-2.5 py-1.5 border border-stone-200 rounded-lg text-xs outline-none focus:border-purple-400 bg-white resize-none" />

                {/* Foto del recipe */}
                <div>
                  <div className="text-[10px] font-semibold text-purple-700 uppercase tracking-wider mb-1">Foto del recipe</div>
                  {item.recipePhoto ? (
                    <div className="relative rounded-lg overflow-hidden border border-purple-200">
                      <img src={item.recipePhoto} alt="Recipe" className="w-full h-24 object-cover" />
                      <button
                        onClick={() => onUpdateRecipe({ recipePhoto: null })}
                        className="absolute top-1 right-1 w-6 h-6 rounded-full bg-red-600 text-white grid place-items-center"
                      >
                        <X size={10} />
                      </button>
                    </div>
                  ) : (
                    <label className="flex items-center justify-center gap-1.5 px-3 py-2 rounded-lg border-2 border-dashed border-purple-200 hover:border-purple-400 text-purple-600 hover:text-purple-700 cursor-pointer transition text-xs font-semibold">
                      <Camera size={12} /> Subir foto del recipe
                      <input type="file" accept="image/*" onChange={handleRecipePhoto} className="hidden" />
                    </label>
                  )}
                </div>
              </div>
            )}
          </div>
        )}

        {/* === Programación de servicio (solo aplica a items de tipo "service") ===
            Permite elegir fecha y hora del servicio. Si ambos quedan vacíos,
            al emitir la recibo se asume "hoy a la hora actual" y, si la slot
            está ocupada, se desliza al siguiente slot libre del día. */}
        {isSchedulable && onUpdateScheduled && (
          <div className="mt-2 pt-2 border-t border-stone-100">
            <div className="flex items-center gap-2 flex-wrap text-xs">
              <span className="flex items-center gap-1 text-stone-500 font-medium">
                <CalendarClock size={12} /> Programar:
              </span>
              <input
                type="date"
                value={item.scheduledDate || ""}
                min={todayISO}
                onChange={(e) => onUpdateScheduled({ scheduledDate: e.target.value })}
                className="bg-stone-50 border border-stone-200 rounded-md px-1.5 py-1 text-xs font-mono outline-none focus:border-orange-400 focus:bg-white transition"
              />
              <input
                type="time"
                value={item.scheduledTime || ""}
                onChange={(e) => onUpdateScheduled({ scheduledTime: e.target.value })}
                className="bg-stone-50 border border-stone-200 rounded-md px-1.5 py-1 text-xs font-mono outline-none focus:border-orange-400 focus:bg-white transition"
              />
              {(item.scheduledDate || item.scheduledTime) && (
                <button
                  onClick={() => onUpdateScheduled({ scheduledDate: null, scheduledTime: null })}
                  className="text-xs text-stone-400 hover:text-stone-700 underline transition"
                  title="Limpiar para usar 'hoy a la hora actual'"
                >
                  Limpiar
                </button>
              )}
            </div>
            {!item.scheduledDate && !item.scheduledTime && (
              <div className="text-[11px] text-stone-400 italic mt-1 ml-1">
                Sin programar → hoy en este momento (siguiente slot libre).
              </div>
            )}
          </div>
        )}
      </div>
      <button
        onClick={onRemove}
        className="w-7 h-7 rounded-lg bg-white border border-stone-200 hover:border-red-300 hover:bg-red-50 grid place-items-center text-stone-500 hover:text-red-600 transition flex-shrink-0"
      >
        <Trash2 size={11} />
      </button>
    </div>
  );
}

// === Modal selector de ítems para agregar ===
function ItemPickerModal({ type, moduleId = null, modules = [], services, supplies = [], inventoryItems = [], onClose, onAdd }) {
  const [search, setSearch] = useState("");
  const [customName, setCustomName] = useState("");
  const [customPrice, setCustomPrice] = useState("");
  const [customNote, setCustomNote] = useState("");
  // Para tipo grooming: subtab servicios | insumos
  const [groomingSubtab, setGroomingSubtab] = useState("services"); // services | supplies

  // Resolver el módulo activo si type === "module"
  const activeModule = useMemo(
    () => moduleId ? (modules || []).find(m => m.id === moduleId) : null,
    [modules, moduleId]
  );
  const isGroomingModule = activeModule?.kind === "grooming";

  // Servicios FILTRADOS por moduleId (cada instancia tiene su propio catálogo)
  const moduleServices = useMemo(
    () => moduleId ? getServicesForModule(services, moduleId).filter(s => s.active) : [],
    [services, moduleId]
  );
  // Servicios solo de grooming (legacy: cuando se llama con type="grooming")
  const groomingServices = useMemo(
    () => services.filter(s => s.active && s.module === "grooming"),
    [services]
  );
  // Insumos activos
  const activeSupplies = useMemo(() => supplies.filter(s => s.active !== false), [supplies]);

  // Para tipo "module": si es grooming-kind, mostramos también un subtab de insumos
  const config = type === "module" ? {
    title: `Agregar de ${activeModule?.name || "módulo"}`,
    source: isGroomingModule && groomingSubtab === "supplies" ? activeSupplies : moduleServices,
    color: isGroomingModule ? "emerald" : "orange",
    showSupplyTab: isGroomingModule, // solo grooming tiene insumos
  } : {
    service:  { title: "Agregar servicio del catálogo", source: services.filter(s => s.active && s.module !== "grooming"), color: "orange" },
    grooming: { title: "Agregar de Grooming", source: groomingSubtab === "services" ? groomingServices : activeSupplies, color: "emerald" },
    product:  { title: "Agregar producto", source: inventoryItems.filter(i => i.isProduct && i.category !== "Medicamento" && !i.hidden), color: "blue" },
    medicine: { title: "Agregar medicina", source: inventoryItems.filter(i => i.isProduct && i.category === "Medicamento" && !i.hidden), color: "purple" },
    custom:   { title: "Agregar ítem personalizado", source: [], color: "stone" },
  }[type];

  const filtered = useMemo(() => {
    if (!config.source.length) return [];
    if (!search.trim()) return config.source.slice(0, 30);
    const q = search.toLowerCase();
    return config.source.filter(s =>
      s.name.toLowerCase().includes(q) ||
      (s.description || "").toLowerCase().includes(q) ||
      (s.category || "").toLowerCase().includes(q) ||
      (s.indication || "").toLowerCase().includes(q)
    );
  }, [config.source, search]);

  const handleAddPredefined = (item) => {
    // Detectar si es un insumo (tab de insumos en grooming legacy o module-kind grooming)
    const isSupplyTab =
      (type === "grooming" && groomingSubtab === "supplies") ||
      (type === "module" && isGroomingModule && groomingSubtab === "supplies");
    if (isSupplyTab) {
      const qty = item.defaultQty || 1;
      const total = item.price || 0;
      onAdd({
        type: "supply",
        sourceId: item.id,
        name: `${item.name} (${qty} ${item.unit})`,
        qty: 1,
        unit: total,
        total,
        note: item.category || "",
        // Etiquetar el insumo con el módulo origen para trazabilidad multi-sede
        moduleId: moduleId || null,
      });
      return;
    }
    // Servicio: el `type` interno del ítem refleja qué motor lo usará. Para module
    // es "service" si vet/standard, "grooming-service" si grooming. Esto preserva
    // el comportamiento actual de los íconos en SaleItemRow.
    const itemType = type === "module"
      ? (isGroomingModule ? "service" : "service")
      : (type === "grooming" ? "service" : type);
    onAdd({
      type: itemType,
      sourceId: item.id,
      name: item.name,
      qty: 1,
      unit: item.price,
      total: item.price,
      note: item.presentation || item.category || "",
      // Etiquetar con moduleId para que la recibo herede esa pertenencia
      moduleId: type === "module" ? moduleId : (item.moduleId || resolveServiceModuleId(item) || null),
      // Medicinas: flag de recipe + datos vacíos para rellenar
      requiresRecipe: item.requiresRecipe || false,
      recipe: null,   // se llena desde SaleItemRow si aplica
      recipePhoto: null,
    });
  };

  const handleAddCustom = () => {
    const price = Number(customPrice) || 0;
    if (!customName.trim() || price <= 0) return;
    onAdd({
      type: "custom",
      name: customName.trim(),
      qty: 1,
      unit: price,
      total: price,
      note: customNote.trim() || null,
    });
  };

  return (
    <div onClick={onClose} className="fixed inset-0 bg-stone-900 z-50 flex justify-center items-start p-4 overflow-y-auto">
      <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl w-full max-w-2xl shadow-2xl my-8 overflow-hidden flex flex-col max-h-screen">
        <div className="sticky top-0 z-10 p-4 border-b border-stone-200 flex items-center gap-3 bg-white">
          <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold flex-1">
            {config.title}
          </div>
          <button onClick={onClose} className="w-9 h-9 rounded-full bg-stone-100 hover:bg-stone-200 grid place-items-center text-stone-600 transition">
            <X size={15} />
          </button>
        </div>

        {/* Sub-switcher para grooming: servicios vs insumos.
            Aparece tanto en el flujo legacy (type="grooming") como en el flujo
            multi-instancia (type="module" + activeModule.kind="grooming"). */}
        {(type === "grooming" || (type === "module" && isGroomingModule)) && (
          <div className="px-4 py-2 border-b border-stone-200 bg-emerald-50 flex gap-1">
            <button
              onClick={() => setGroomingSubtab("services")}
              className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-semibold transition ${
                groomingSubtab === "services"
                  ? "bg-emerald-600 text-white shadow"
                  : "bg-white border border-emerald-200 text-emerald-700 hover:bg-emerald-100"
              }`}
            >
              <Bath size={11} /> Servicios ({type === "module" ? moduleServices.length : groomingServices.length})
            </button>
            <button
              onClick={() => setGroomingSubtab("supplies")}
              className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-semibold transition ${
                groomingSubtab === "supplies"
                  ? "bg-emerald-600 text-white shadow"
                  : "bg-white border border-emerald-200 text-emerald-700 hover:bg-emerald-100"
              }`}
            >
              <Droplets size={11} /> Insumos ({activeSupplies.length})
            </button>
          </div>
        )}

        {type === "custom" ? (
          /* === Formulario de ítem personalizado === */
          <div className="p-5 space-y-3 overflow-y-auto">
            <div className="bg-stone-50 border border-stone-200 rounded-xl p-3 text-xs text-stone-600">
              Para ítems que no están en el catálogo: cargos especiales, descuentos negativos, copago, etc.
            </div>
            <div>
              <label className="text-xs font-semibold text-stone-700 block mb-1.5">Descripción del ítem</label>
              <input
                value={customName}
                onChange={(e) => setCustomName(e.target.value)}
                placeholder="Ej: Hospitalización 1 noche"
                className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
              />
            </div>
            <div>
              <label className="text-xs font-semibold text-stone-700 block mb-1.5">Precio</label>
              <div className="relative">
                <span className="absolute left-3.5 top-1/2 -translate-y-1/2 text-stone-400 font-mono">$</span>
                <input
                  type="number"
                  min="0"
                  step="0.01"
                  value={customPrice}
                  onChange={(e) => setCustomPrice(e.target.value)}
                  placeholder="0"
                  className="w-full pl-8 pr-3 py-2.5 bg-white border border-stone-200 rounded-xl text-sm font-mono outline-none focus:border-orange-500"
                />
              </div>
            </div>
            <div>
              <label className="text-xs font-semibold text-stone-700 block mb-1.5">
                Nota <span className="text-stone-400 font-normal">(opcional)</span>
              </label>
              <input
                value={customNote}
                onChange={(e) => setCustomNote(e.target.value)}
                placeholder="Ej: Tarifa especial cliente recurrente"
                className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
              />
            </div>
          </div>
        ) : (
          /* === Lista de ítems del catálogo === */
          <>
            <div className="p-3 border-b border-stone-200">
              <div className="relative">
                <Search size={14} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-stone-400" />
                <input
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                  placeholder="Buscar..."
                  autoFocus
                  className="w-full pl-10 pr-3 py-2 bg-stone-50 border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500 focus:bg-white"
                />
              </div>
            </div>
            <div className="flex-1 overflow-y-auto divide-y divide-stone-100">
              {filtered.length === 0 ? (
                <div className="p-8 text-center text-sm text-stone-500">
                  Sin resultados.
                </div>
              ) : (
                filtered.map(s => (
                  <button
                    key={s.id}
                    onClick={() => handleAddPredefined(s)}
                    className="w-full p-3 hover:bg-orange-50 transition text-left flex items-start gap-3"
                  >
                    <div className="flex-1 min-w-0">
                      <div className="font-semibold text-sm truncate">{s.name}</div>
                      <div className="text-xs text-stone-500 mt-0.5 truncate">
                        {type === "service" && (
                          <>
                            {SERVICE_MODULES[s.module]?.label}
                            {s.duration && ` · ${s.duration} min`}
                          </>
                        )}
                        {type === "product" && (
                          <span className="flex items-center gap-1">
                            {s.category}
                            {s.stock != null && (
                              <span className={`text-[10px] font-bold px-1.5 py-px rounded ${
                                s.stock <= (s.minStock || 0) ? "bg-red-100 text-red-700" : "bg-emerald-100 text-emerald-700"
                              }`}>
                                Stock: {s.stock}
                              </span>
                            )}
                          </span>
                        )}
                        {type === "medicine" && (
                          <span className="flex items-center gap-1 flex-wrap">
                            {s.presentation && <>{s.presentation} · </>}
                            {s.indication || ""}
                            {s.stock != null && (
                              <span className={`text-[10px] font-bold px-1.5 py-px rounded ${
                                s.stock <= (s.minStock || 0) ? "bg-red-100 text-red-700" : "bg-emerald-100 text-emerald-700"
                              }`}>
                                Stock: {s.stock}
                              </span>
                            )}
                            {s.requiresRecipe && (
                              <span className="inline-flex items-center gap-0.5 px-1.5 py-px rounded bg-red-100 text-red-700 text-[9px] font-bold uppercase">
                                <FileText size={8} /> Recipe
                              </span>
                            )}
                          </span>
                        )}
                      </div>
                    </div>
                    <div className="text-right flex-shrink-0">
                      <div className="font-mono text-base font-bold text-emerald-700">
                        ${s.price > 0 ? s.price : "—"}
                      </div>
                      <Plus size={11} className="text-stone-400 ml-auto mt-1" />
                    </div>
                  </button>
                ))
              )}
            </div>
          </>
        )}

        {/* Footer */}
        <div className="border-t border-stone-200 p-3 flex justify-end gap-2">
          <button onClick={onClose} className="px-3 py-2 rounded-xl text-sm font-semibold bg-white border border-stone-200 hover:border-stone-400 text-stone-700">
            Cancelar
          </button>
          {type === "custom" && (
            <button
              onClick={handleAddCustom}
              disabled={!customName.trim() || !(Number(customPrice) > 0)}
              className={`flex items-center gap-1.5 px-4 py-2 rounded-xl text-sm font-semibold transition ${
                customName.trim() && Number(customPrice) > 0
                  ? "bg-emerald-500 hover:bg-emerald-600 text-white shadow"
                  : "bg-stone-200 text-stone-400 cursor-not-allowed"
              }`}
            >
              <Plus size={13} /> Agregar a la recibo
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

// === Card de servicio en el catálogo ===
function CatalogServiceCard({ service, onEdit, onToggleActive, onSell }) {
  const moduleInfo = SERVICE_MODULES[service.module];
  const ModuleIcon = moduleInfo.Icon;
  const moduleColors = {
    orange:  { bg: "bg-orange-50",  text: "text-orange-700",  border: "border-orange-200",  accent: "from-orange-500 to-orange-700" },
    emerald: { bg: "bg-emerald-50", text: "text-emerald-700", border: "border-emerald-200", accent: "from-emerald-500 to-emerald-700" },
    blue:    { bg: "bg-blue-50",    text: "text-blue-700",    border: "border-blue-200",    accent: "from-blue-500 to-blue-700" },
  }[moduleInfo.color];

  return (
    <div className={`bg-white border rounded-2xl shadow-sm overflow-hidden transition ${
      service.active ? "border-stone-200 hover:shadow-md" : "border-stone-200 opacity-60"
    }`}>
      {/* Cabecera con gradiente del módulo */}
      <div className={`p-4 ${moduleColors.bg} border-b ${moduleColors.border} flex items-start gap-3`}>
        <div className={`w-10 h-10 rounded-xl bg-gradient-to-br ${moduleColors.accent} text-white grid place-items-center flex-shrink-0 shadow`}>
          <ModuleIcon size={17} strokeWidth={1.8} />
        </div>
        <div className="flex-1 min-w-0">
          <div className={`text-xs tracking-widest uppercase ${moduleColors.text} font-semibold flex items-center gap-2`}>
            {moduleInfo.label}
            {!service.active && (
              <span className="bg-stone-200 text-stone-600 px-1.5 py-px rounded text-xs font-bold">Inactivo</span>
            )}
          </div>
          <h3 className="font-serif text-lg font-semibold leading-tight mt-0.5 truncate">
            {service.name}
          </h3>
        </div>
        <div className="text-right flex-shrink-0">
          {service.price > 0 ? (
            <>
              <div className="font-mono text-2xl font-bold text-stone-900 leading-none">
                ${service.price}
              </div>
              <div className="text-xs text-stone-500 mt-0.5">por servicio</div>
            </>
          ) : (
            <span className="text-xs font-semibold px-2 py-1 rounded-full bg-blue-100 text-blue-700">
              Por contrato
            </span>
          )}
        </div>
      </div>

      {/* Body con info */}
      <div className="p-4 space-y-2.5">
        <p className="text-sm text-stone-600 leading-snug line-clamp-2">{service.description}</p>

        <div className="flex flex-wrap gap-x-4 gap-y-1.5 text-xs">
          <div className="flex items-center gap-1.5 text-stone-600">
            <Clock size={11} className="text-stone-400" />
            <span><strong className="text-stone-800">{service.duration}</strong> min</span>
          </div>
          <div className="flex items-center gap-1.5 text-stone-600">
            <Calendar size={11} className="text-stone-400" />
            <span>{service.daysAvailable.length} días/sem</span>
          </div>
          <div className="flex items-center gap-1.5 text-stone-600">
            <Clock size={11} className="text-stone-400" />
            <span><strong className="text-stone-800">{service.timeStart}–{service.timeEnd}</strong></span>
          </div>
          {service.bookingType === "drop_off" && (
            <div className="flex items-center gap-1.5 text-emerald-700">
              <PawPrint size={11} />
              <span className="font-semibold">Deja la mascota</span>
            </div>
          )}
          {service.bookingType === "fixed_slot" && (
            <div className="flex items-center gap-1.5 text-orange-700">
              <Stethoscope size={11} />
              <span className="font-semibold">Hora fija</span>
            </div>
          )}
        </div>

        {/* Días de la semana visualizados */}
        <div className="flex gap-1 pt-1">
          {WEEKDAYS.map(d => {
            const enabled = service.daysAvailable.includes(d.id);
            return (
              <div
                key={d.id}
                className={`flex-1 text-center py-1 rounded text-xs font-bold transition ${
                  enabled
                    ? `${moduleColors.bg} ${moduleColors.text}`
                    : "bg-stone-50 text-stone-300"
                }`}
              >
                {d.short}
              </div>
            );
          })}
        </div>

        {/* Footer con métricas y acciones */}
        <div className="pt-2 mt-2 border-t border-stone-100 space-y-2">
          <div className="flex items-center justify-between gap-2">
            <span className="text-xs text-stone-500">
              <strong className="text-stone-800">{service.soldCount}</strong> ventas totales
            </span>
            <div className="flex items-center gap-1">
              <button
                onClick={onToggleActive}
                className="px-2.5 py-1.5 rounded-lg text-xs font-semibold bg-white border border-stone-200 hover:border-orange-300 text-stone-600 hover:text-orange-700 transition"
                title={service.active ? "Desactivar" : "Activar"}
              >
                {service.active ? "Desactivar" : "Activar"}
              </button>
              <button
                onClick={onEdit}
                className="px-2.5 py-1.5 rounded-lg text-xs font-semibold bg-white border border-stone-200 hover:border-stone-400 text-stone-700 transition"
              >
                Editar
              </button>
            </div>
          </div>
          {service.active && onSell && (
            <button
              onClick={onSell}
              className="w-full flex items-center justify-center gap-1.5 px-3 py-2 rounded-xl text-sm font-semibold bg-emerald-500 hover:bg-emerald-600 text-white transition shadow-sm"
            >
              <DollarSign size={13} /> Vender ahora
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

// === Modal de venta puntual: registra una venta concreta del servicio ===
function SellServiceModal({ service, clients, passports, onClose, onConfirm }) {
  const [step, setStep] = useState(1);
  const [clientSearch, setClientSearch] = useState("");
  const [selectedClient, setSelectedClient] = useState(null);
  const [selectedPet, setSelectedPet] = useState(null);
  const [selectedDate, setSelectedDate] = useState("");
  const [selectedTime, setSelectedTime] = useState("");
  const [frequency, setFrequency] = useState("monthly");

  const moduleInfo = SERVICE_MODULES[service.module];
  const ModuleIcon = moduleInfo.Icon;
  const moduleColors = {
    orange:  { bg: "bg-orange-50",  text: "text-orange-700",  accent: "from-orange-500 to-orange-700" },
    emerald: { bg: "bg-emerald-50", text: "text-emerald-700", accent: "from-emerald-500 to-emerald-700" },
    blue:    { bg: "bg-blue-50",    text: "text-blue-700",    accent: "from-blue-500 to-blue-700" },
  }[moduleInfo.color];

  // Búsqueda de clientes
  const filteredClients = useMemo(() => {
    if (!clientSearch.trim()) return clients.slice(0, 8);
    const q = clientSearch.toLowerCase();
    return clients.filter(c =>
      (c.name || "").toLowerCase().includes(q) ||
      (c.cedula || "").toLowerCase().includes(q) ||
      (c.phone || "").includes(q)
    ).slice(0, 12);
  }, [clientSearch, clients]);

  // Mascotas del cliente seleccionado (resuelve códigos a pasaportes)
  const clientPets = useMemo(() => {
    if (!selectedClient || !selectedClient.petCodes) return [];
    return selectedClient.petCodes
      .map(code => passports.find(p => p.code === code))
      .filter(Boolean);
  }, [selectedClient, passports]);

  // Generar fechas disponibles según daysAvailable del servicio (próximos 14 días)
  const availableDates = useMemo(() => {
    const dates = [];
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const dayMap = ["sun", "mon", "tue", "wed", "thu", "fri", "sat"];
    for (let i = 0; i < 21; i++) {
      const d = new Date(today);
      d.setDate(today.getDate() + i);
      const weekdayShort = dayMap[d.getDay()];
      if (service.daysAvailable.includes(weekdayShort)) {
        dates.push(d);
      }
    }
    return dates.slice(0, 12);
  }, [service.daysAvailable]);

  // Generar slots de hora según el tipo de booking
  const availableSlots = useMemo(() => {
    if (!selectedDate) return [];
    const slots = [];
    let rangeStart, rangeEnd, step;

    if (service.bookingType === "drop_off" && service.dropOffWindow) {
      rangeStart = service.dropOffWindow.start;
      rangeEnd = service.dropOffWindow.end;
      step = 15; // grooming: cada 15 min
    } else {
      rangeStart = service.timeStart;
      rangeEnd = service.timeEnd;
      step = service.duration || 30;
    }

    const [sH, sM] = rangeStart.split(":").map(Number);
    const [eH, eM] = rangeEnd.split(":").map(Number);
    let cur = sH * 60 + sM;
    const end = eH * 60 + eM;
    while (cur < end) {
      const h = Math.floor(cur / 60);
      const m = cur % 60;
      slots.push(`${String(h).padStart(2, "0")}:${String(m).padStart(2, "0")}`);
      cur += step;
    }
    return slots;
  }, [selectedDate, service]);

  // Hora calculada de pickup para grooming
  const pickupTime = useMemo(() => {
    if (service.bookingType !== "drop_off" || !selectedTime) return null;
    const [h, m] = selectedTime.split(":").map(Number);
    const totalMin = h * 60 + m + service.duration;
    return `${String(Math.floor(totalMin / 60)).padStart(2, "0")}:${String(totalMin % 60).padStart(2, "0")}`;
  }, [selectedTime, service]);

  const canAdvance = useMemo(() => {
    if (step === 1) return Boolean(selectedClient);
    if (step === 2) {
      if (service.bookingType === "recurring") return Boolean(frequency);
      return Boolean(selectedDate && selectedTime);
    }
    return true;
  }, [step, selectedClient, selectedDate, selectedTime, frequency, service.bookingType]);

  const handleSubmit = () => {
    const dateLabel = selectedDate
      ? new Date(selectedDate + "T00:00:00").toLocaleDateString("es", { weekday: "long", day: "2-digit", month: "long" })
      : null;

    onConfirm({
      service,
      client: selectedClient,
      pet: selectedPet,
      scheduledDate: dateLabel,        // legible para mostrar al usuario
      scheduledDateISO: selectedDate,  // YYYY-MM-DD para comparaciones y persistencia
      scheduledTime: selectedTime,
      scheduledTimeEnd: pickupTime,
      frequency: service.bookingType === "recurring" ? (
        frequency === "weekly" ? "Semanal" :
        frequency === "biweekly" ? "Quincenal" :
        "Mensual"
      ) : null,
    });
  };

  const stepInfo = [
    { num: 1, label: "Cliente", Icon: User },
    { num: 2, label: "Agenda",  Icon: Calendar },
    { num: 3, label: "Confirmar", Icon: Check },
  ];

  return (
    <div onClick={onClose} className="fixed inset-0 bg-stone-900 z-50 flex justify-center items-start p-4 overflow-y-auto">
      <div onClick={(e) => e.stopPropagation()} className="bg-stone-50 rounded-2xl w-full max-w-2xl shadow-2xl my-8">
        {/* Header con info del servicio */}
        <div className="sticky top-0 z-10 bg-white border-b border-stone-200 rounded-t-2xl">
          <div className="p-4 flex items-center gap-3">
            <button onClick={onClose} className="w-9 h-9 rounded-lg bg-stone-100 hover:bg-stone-200 grid place-items-center text-stone-600 transition">
              <X size={16} />
            </button>
            <div className={`w-10 h-10 rounded-xl bg-gradient-to-br ${moduleColors.accent} text-white grid place-items-center flex-shrink-0 shadow`}>
              <ModuleIcon size={17} strokeWidth={1.8} />
            </div>
            <div className="flex-1 min-w-0">
              <div className={`text-xs tracking-widest uppercase ${moduleColors.text} font-semibold`}>
                Vender · {moduleInfo.label}
              </div>
              <div className="font-serif text-base font-semibold leading-tight truncate">{service.name}</div>
            </div>
            <div className="text-right flex-shrink-0">
              {service.price > 0 ? (
                <div className="font-mono text-xl font-bold text-emerald-700 leading-none">${service.price}</div>
              ) : (
                <span className="text-xs px-2 py-0.5 rounded-full bg-blue-100 text-blue-700 font-semibold">Por contrato</span>
              )}
            </div>
          </div>

          {/* Stepper */}
          <div className="px-5 pb-3 flex items-center gap-1.5 overflow-x-auto">
            {stepInfo.map((s, i) => {
              const Ic = s.Icon;
              const active = step === s.num;
              const done = step > s.num;
              return (
                <Fragment key={s.num}>
                  <div className={`flex items-center gap-1.5 px-2.5 py-1 rounded-lg text-xs font-semibold flex-shrink-0 ${
                    active ? "bg-orange-600 text-white" :
                    done ? "bg-emerald-100 text-emerald-700" :
                    "bg-stone-100 text-stone-500"
                  }`}>
                    <span className={`w-4 h-4 rounded-full grid place-items-center text-xs font-bold ${
                      active ? "bg-white text-orange-600" :
                      done ? "bg-emerald-600 text-white" :
                      "bg-white text-stone-500"
                    }`}>
                      {done ? <Check size={9} strokeWidth={3} /> : s.num}
                    </span>
                    <span>{s.label}</span>
                  </div>
                  {i < stepInfo.length - 1 && <div className="flex-1 h-px bg-stone-200 min-w-4"></div>}
                </Fragment>
              );
            })}
          </div>
        </div>

        {/* Body */}
        <div className="p-5">
          {/* === STEP 1: Cliente y mascota === */}
          {step === 1 && (
            <div className="space-y-3">
              <div className="bg-white border border-stone-200 rounded-2xl p-4 space-y-3">
                <div>
                  <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold">Paso 1 · Cliente</div>
                  <h3 className="font-serif text-lg font-semibold mt-0.5">¿A qué cliente se le vende?</h3>
                </div>
                <div className="relative">
                  <Search size={14} className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-400" />
                  <input
                    value={clientSearch}
                    onChange={(e) => setClientSearch(e.target.value)}
                    placeholder="Buscar por nombre, cédula o teléfono..."
                    className="w-full pl-11 pr-3 py-2.5 bg-stone-50 border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500 focus:bg-white"
                  />
                </div>

                {/* Cliente seleccionado destacado */}
                {selectedClient && (
                  <div className="bg-emerald-50 border border-emerald-300 rounded-xl p-3 flex items-center gap-3">
                    <div className={`w-10 h-10 rounded-xl grid place-items-center text-white text-xs font-bold flex-shrink-0 ${
                      selectedClient.isOrg
                        ? "bg-gradient-to-br from-stone-700 to-stone-900"
                        : "bg-gradient-to-br from-orange-500 to-orange-700"
                    }`}>
                      {selectedClient.name.split(" ").slice(0, 2).map(s => s[0]).join("").toUpperCase()}
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="font-semibold text-sm truncate">{selectedClient.name}</div>
                      <div className="text-xs text-stone-500 font-mono truncate">
                        {selectedClient.cedula} · {selectedClient.phone}
                      </div>
                    </div>
                    <Check size={16} className="text-emerald-700 flex-shrink-0" strokeWidth={2.5} />
                  </div>
                )}

                {/* Lista de resultados */}
                {!selectedClient && (
                  <div className="bg-white border border-stone-200 rounded-xl divide-y divide-stone-100 max-h-72 overflow-y-auto">
                    {filteredClients.length === 0 ? (
                      <div className="p-4 text-center text-sm text-stone-500">Sin resultados.</div>
                    ) : (
                      filteredClients.map(c => (
                        <button
                          key={c.id}
                          onClick={() => { setSelectedClient(c); setSelectedPet(null); }}
                          className={`w-full flex items-center gap-3 p-2.5 hover:bg-orange-50 transition text-left ${
                            c.isNew ? "bg-emerald-50" : ""
                          }`}
                        >
                          <div className={`w-8 h-8 rounded-lg grid place-items-center text-white text-xs font-bold flex-shrink-0 ${
                            c.isOrg
                              ? "bg-gradient-to-br from-stone-700 to-stone-900"
                              : "bg-gradient-to-br from-orange-500 to-orange-700"
                          }`}>
                            {c.name.split(" ").slice(0, 2).map(s => s[0]).join("").toUpperCase()}
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-1.5 flex-wrap">
                              <span className="font-semibold text-sm truncate">{c.name}</span>
                              {c.isNew && (
                                <span className="text-xs font-bold px-1.5 py-px rounded-full bg-emerald-500 text-white">
                                  Nuevo
                                </span>
                              )}
                            </div>
                            <div className="text-xs text-stone-500 font-mono truncate">{c.cedula}</div>
                          </div>
                          <ChevronRight size={13} className="text-stone-400 flex-shrink-0" />
                        </button>
                      ))
                    )}
                  </div>
                )}
              </div>

              {/* Mascota (solo si vet o grooming y hay cliente con mascotas) */}
              {selectedClient && service.module !== "b2b" && clientPets.length > 0 && (
                <div className="bg-white border border-stone-200 rounded-2xl p-4 space-y-3">
                  <div>
                    <div className={`text-xs tracking-widest uppercase ${moduleColors.text} font-semibold`}>
                      ¿Para qué mascota?
                    </div>
                    <p className="text-xs text-stone-500 mt-0.5">Opcional. Si no aplica, deja en blanco.</p>
                  </div>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                    {clientPets.map(pet => {
                      const Ic = ANIMAL_ICONS[pet.species] || PawPrint;
                      const active = selectedPet?.id === pet.id;
                      return (
                        <button
                          key={pet.id}
                          onClick={() => setSelectedPet(active ? null : pet)}
                          className={`flex items-center gap-2.5 p-2.5 rounded-xl border transition text-left ${
                            active
                              ? "bg-orange-50 border-orange-400 ring-1 ring-orange-300"
                              : "bg-white border-stone-200 hover:border-orange-300"
                          }`}
                        >
                          <div className="w-9 h-9 rounded-lg bg-gradient-to-br from-orange-200 to-orange-100 grid place-items-center text-orange-800 flex-shrink-0">
                            <Ic size={15} strokeWidth={1.8} />
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="font-semibold text-sm truncate">{pet.name}</div>
                            <div className="text-xs text-stone-500 truncate">{pet.breed} · {pet.age}</div>
                          </div>
                          {active && <Check size={13} className="text-orange-600 flex-shrink-0" />}
                        </button>
                      );
                    })}
                  </div>
                </div>
              )}

              {/* Cliente sin mascotas registradas */}
              {selectedClient && service.module !== "b2b" && clientPets.length === 0 && (
                <div className="bg-amber-50 border border-amber-200 rounded-2xl p-3 flex items-start gap-2.5">
                  <Info size={14} className="text-amber-700 flex-shrink-0 mt-0.5" />
                  <div className="text-xs text-amber-900 leading-relaxed">
                    <strong>{selectedClient.name}</strong> no tiene mascotas registradas. La venta se procesará y el área de {service.module === "grooming" ? "grooming" : "atención"} podrá agregar el nombre de la mascota al recibirla.
                  </div>
                </div>
              )}
            </div>
          )}

          {/* === STEP 2: Agenda (varía por bookingType) === */}
          {step === 2 && (
            <div className="bg-white border border-stone-200 rounded-2xl p-4 space-y-4">
              {/* B2B: solo elige frecuencia */}
              {service.bookingType === "recurring" ? (
                <>
                  <div>
                    <div className={`text-xs tracking-widest uppercase ${moduleColors.text} font-semibold`}>Paso 2 · Recurrencia</div>
                    <h3 className="font-serif text-lg font-semibold mt-0.5">¿Con qué frecuencia se entrega?</h3>
                  </div>
                  <div className="space-y-2">
                    {[
                      { id: "weekly", label: "Semanal", desc: "Cada 7 días" },
                      { id: "biweekly", label: "Quincenal", desc: "Cada 15 días" },
                      { id: "monthly", label: "Mensual", desc: "Cada mes" },
                    ].map(f => {
                      const active = frequency === f.id;
                      return (
                        <button
                          key={f.id}
                          onClick={() => setFrequency(f.id)}
                          className={`w-full flex items-center gap-3 p-3 rounded-xl border transition text-left ${
                            active ? "bg-blue-50 border-blue-300 ring-1 ring-blue-200" : "bg-white border-stone-200 hover:border-stone-400"
                          }`}
                        >
                          <div className={`w-9 h-9 rounded-lg grid place-items-center flex-shrink-0 ${
                            active ? "bg-blue-100 text-blue-700" : "bg-stone-100 text-stone-500"
                          }`}>
                            <Calendar size={15} />
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="font-semibold text-sm">{f.label}</div>
                            <div className="text-xs text-stone-500">{f.desc}</div>
                          </div>
                          {active && <Check size={14} className="text-blue-600" />}
                        </button>
                      );
                    })}
                  </div>
                </>
              ) : (
                <>
                  {/* Vet o Grooming: fecha + hora */}
                  <div>
                    <div className={`text-xs tracking-widest uppercase ${moduleColors.text} font-semibold`}>
                      Paso 2 · Fecha {service.bookingType === "drop_off" ? "y entrega" : "y hora"}
                    </div>
                    <h3 className="font-serif text-lg font-semibold mt-0.5">
                      {service.bookingType === "drop_off"
                        ? "¿Cuándo deja la mascota?"
                        : "¿Qué fecha y hora?"
                      }
                    </h3>
                    {service.bookingType === "drop_off" && (
                      <p className="text-xs text-stone-500 mt-0.5">
                        Hora dentro de la ventana de drop-off ({service.dropOffWindow.start} – {service.dropOffWindow.end}).
                      </p>
                    )}
                  </div>

                  {/* Selector de fecha */}
                  <div>
                    <label className="text-xs font-semibold text-stone-700 block mb-2">Fecha</label>
                    <div className="grid grid-cols-3 sm:grid-cols-4 gap-2 max-h-44 overflow-y-auto pr-1">
                      {availableDates.map(d => {
                        const key = d.toISOString().slice(0, 10);
                        const active = selectedDate === key;
                        return (
                          <button
                            key={key}
                            onClick={() => { setSelectedDate(key); setSelectedTime(""); }}
                            className={`p-2 rounded-lg border text-center transition ${
                              active
                                ? `${moduleColors.bg} border-current ${moduleColors.text}`
                                : "bg-white border-stone-200 hover:border-stone-400"
                            }`}
                          >
                            <div className="text-xs uppercase tracking-wide font-semibold">
                              {d.toLocaleDateString("es", { weekday: "short" }).replace(".", "")}
                            </div>
                            <div className="font-serif text-xl font-bold leading-none mt-0.5">
                              {d.getDate()}
                            </div>
                            <div className="text-xs text-stone-500 mt-0.5">
                              {d.toLocaleDateString("es", { month: "short" }).replace(".", "")}
                            </div>
                          </button>
                        );
                      })}
                    </div>
                  </div>

                  {/* Selector de hora */}
                  {selectedDate && (
                    <div>
                      <label className="text-xs font-semibold text-stone-700 block mb-2">
                        {service.bookingType === "drop_off" ? "Hora de drop-off" : "Hora"}
                      </label>
                      <div className="grid grid-cols-4 sm:grid-cols-6 gap-1.5 max-h-32 overflow-y-auto">
                        {availableSlots.map(slot => {
                          const active = selectedTime === slot;
                          return (
                            <button
                              key={slot}
                              onClick={() => setSelectedTime(slot)}
                              className={`px-2 py-1.5 rounded-lg text-xs font-mono font-bold transition border ${
                                active
                                  ? `${moduleColors.bg} border-current ${moduleColors.text}`
                                  : "bg-white border-stone-200 hover:border-stone-400 text-stone-700"
                              }`}
                            >
                              {slot}
                            </button>
                          );
                        })}
                      </div>
                      {service.bookingType === "drop_off" && pickupTime && (
                        <div className="mt-3 p-3 rounded-xl bg-emerald-50 border border-emerald-200 flex items-start gap-2.5 text-xs">
                          <PawPrint size={13} className="text-emerald-700 flex-shrink-0 mt-0.5" />
                          <div className="text-emerald-900 leading-relaxed">
                            <strong>Retiro estimado:</strong> a las <span className="font-mono font-bold">{pickupTime}</span> (duración: {service.duration} min).
                            La mascota puede ser retirada dentro de la ventana de pick-up
                            {service.pickupWindow && ` (${service.pickupWindow.start} – ${service.pickupWindow.end})`}.
                          </div>
                        </div>
                      )}
                    </div>
                  )}
                </>
              )}
            </div>
          )}

          {/* === STEP 3: Confirmar === */}
          {step === 3 && (
            <div className="bg-white border border-stone-200 rounded-2xl p-5 space-y-4">
              <div>
                <div className="text-xs tracking-widest uppercase text-emerald-700 font-semibold">Paso 3 · Confirmar venta</div>
                <h3 className="font-serif text-lg font-semibold mt-0.5">Revisa los detalles</h3>
              </div>

              <div className="bg-stone-50 border border-stone-200 rounded-xl p-4 space-y-3">
                {/* Servicio */}
                <SaleSummaryRow label="Servicio" value={service.name} />
                <SaleSummaryRow label="Módulo" value={moduleInfo.label} />

                {/* Cliente */}
                <SaleSummaryRow label="Cliente" value={selectedClient.name} />
                {selectedPet && <SaleSummaryRow label="Mascota" value={`${selectedPet.name} · ${selectedPet.breed}`} mono={selectedPet.code} />}

                {/* Fecha/hora según tipo */}
                {service.bookingType === "recurring" ? (
                  <SaleSummaryRow label="Frecuencia" value={
                    frequency === "weekly" ? "Semanal" :
                    frequency === "biweekly" ? "Quincenal" : "Mensual"
                  } />
                ) : selectedDate && (
                  <>
                    <SaleSummaryRow label="Fecha" value={
                      new Date(selectedDate + "T00:00:00").toLocaleDateString("es", { weekday: "long", day: "2-digit", month: "long" })
                    } />
                    <SaleSummaryRow
                      label={service.bookingType === "drop_off" ? "Drop-off" : "Hora"}
                      value={selectedTime}
                      mono
                    />
                    {service.bookingType === "drop_off" && pickupTime && (
                      <SaleSummaryRow label="Retiro estimado" value={pickupTime} mono />
                    )}
                  </>
                )}
              </div>

              {/* Total */}
              <div className="bg-gradient-to-br from-emerald-50 to-white border-2 border-emerald-200 rounded-xl p-4">
                <div className="flex items-baseline justify-between">
                  <div>
                    <div className="text-xs tracking-widest uppercase text-emerald-700 font-semibold">Total a cobrar</div>
                    <div className="text-xs text-stone-500 mt-0.5">Subtotal + IVA 16%</div>
                  </div>
                  <div className="text-right">
                    {service.price > 0 ? (
                      <div className="font-mono text-3xl font-bold text-emerald-700">${service.price}</div>
                    ) : (
                      <span className="text-sm font-semibold px-3 py-1 rounded-full bg-blue-100 text-blue-700">
                        Por contrato
                      </span>
                    )}
                  </div>
                </div>
              </div>

              <div className="bg-amber-50 border border-amber-200 rounded-xl p-3 flex items-start gap-2.5 text-xs">
                <AlertCircle size={13} className="text-amber-700 flex-shrink-0 mt-0.5" />
                <div className="text-amber-900 leading-relaxed">
                  Al confirmar se crea una recibo en estado <strong>borrador</strong> en el módulo Ventas.
                  Podrás emitirla, registrar abonos o eliminarla desde ahí.
                </div>
              </div>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="sticky bottom-0 bg-white border-t border-stone-200 p-3 flex items-center justify-between gap-2 rounded-b-2xl">
          <button
            onClick={() => step === 1 ? onClose() : setStep(step - 1)}
            className="flex items-center gap-1.5 px-3 py-2 rounded-xl text-sm font-semibold bg-white border border-stone-200 hover:border-stone-400 text-stone-700"
          >
            <ChevronLeft size={13} /> {step === 1 ? "Cancelar" : "Atrás"}
          </button>
          <div className="text-xs text-stone-500 hidden sm:block">Paso {step} de 3</div>
          {step < 3 ? (
            <button
              onClick={() => setStep(step + 1)}
              disabled={!canAdvance}
              className={`flex items-center gap-1.5 px-4 py-2 rounded-xl text-sm font-semibold transition ${
                canAdvance ? "bg-orange-600 hover:bg-orange-700 text-white" : "bg-stone-200 text-stone-400 cursor-not-allowed"
              }`}
            >
              Siguiente <ChevronRight size={13} />
            </button>
          ) : (
            <button
              onClick={handleSubmit}
              className="flex items-center gap-1.5 px-4 py-2 rounded-xl text-sm font-semibold bg-emerald-500 hover:bg-emerald-600 text-white shadow"
            >
              <Check size={13} /> Confirmar venta
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

function SaleSummaryRow({ label, value, mono }) {
  return (
    <div className="flex items-baseline justify-between gap-3 text-sm">
      <span className="text-xs text-stone-500 flex-shrink-0">{label}</span>
      <span className={`font-semibold text-stone-800 text-right ${mono ? "font-mono" : ""}`}>
        {value}
      </span>
    </div>
  );
}

// === Wizard de creación / edición de servicio ===
function NewServiceWizard({ editingService, onClose, onSave }) {
  const [step, setStep] = useState(1);
  const [data, setData] = useState(() => editingService ? { ...editingService } : {
    name: "",
    description: "",
    module: "vet",
    price: "",
    duration: 30,
    daysAvailable: ["mon", "tue", "wed", "thu", "fri"],
    timeStart: "08:00",
    timeEnd: "18:00",
    requiresVet: true,
    room: "",
    bookingType: "fixed_slot",
    dropOffWindow: { start: "09:00", end: "11:00" },
    pickupWindow: { start: "14:00", end: "17:00" },
    contractRequired: false,
  });

  const update = (field, value) => setData(prev => ({ ...prev, [field]: value }));

  // Cambio de módulo: actualiza bookingType por defecto
  const setModule = (m) => {
    setData(prev => ({
      ...prev,
      module: m,
      bookingType: m === "vet" ? "fixed_slot" : m === "grooming" ? "drop_off" : "recurring",
      requiresVet: m === "vet",
      contractRequired: m === "b2b",
    }));
  };

  const toggleDay = (dayId) => {
    update("daysAvailable",
      data.daysAvailable.includes(dayId)
        ? data.daysAvailable.filter(d => d !== dayId)
        : [...data.daysAvailable, dayId]
    );
  };

  const canAdvance = useMemo(() => {
    if (step === 1) return data.name.trim() && data.price !== "" && Number(data.price) >= 0;
    if (step === 2) return Boolean(data.module);
    if (step === 3) return data.daysAvailable.length > 0 && data.timeStart && data.timeEnd;
    return true;
  }, [step, data]);

  const handleSubmit = () => {
    onSave({
      ...data,
      price: Number(data.price) || 0,
      duration: Number(data.duration) || 30,
    });
  };

  const moduleInfo = SERVICE_MODULES[data.module];

  const stepInfo = [
    { num: 1, label: "Datos", Icon: Tag },
    { num: 2, label: "Módulo", Icon: LayoutGrid },
    { num: 3, label: "Disponibilidad", Icon: Calendar },
    { num: 4, label: "Configuración", Icon: Settings },
  ];

  return (
    <div onClick={onClose} className="fixed inset-0 bg-stone-900 z-50 flex justify-center items-start p-4 overflow-y-auto">
      <div onClick={(e) => e.stopPropagation()} className="bg-stone-50 rounded-2xl w-full max-w-3xl shadow-2xl my-8">
        {/* Header */}
        <div className="sticky top-0 z-10 flex items-center justify-between p-4 border-b border-stone-200 bg-white rounded-t-2xl">
          <div className="flex items-center gap-3 min-w-0">
            <Tag size={18} className="text-orange-600 flex-shrink-0" />
            <div className="min-w-0">
              <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold">
                {editingService ? "Editar servicio" : "Nuevo servicio"}
              </div>
              <div className="text-sm font-semibold text-stone-700 truncate">
                {data.name || "Sin nombre"}
              </div>
            </div>
          </div>
          <button onClick={onClose} className="w-9 h-9 rounded-full bg-white border border-stone-200 grid place-items-center text-stone-600 hover:text-orange-700">
            <X size={16} />
          </button>
        </div>

        {/* Stepper */}
        <div className="px-5 pt-5">
          <div className="flex items-center gap-2 overflow-x-auto pb-2">
            {stepInfo.map((s, i) => {
              const StepIcon = s.Icon;
              const active = step === s.num;
              const done = step > s.num;
              return (
                <Fragment key={s.num}>
                  <button
                    onClick={() => setStep(s.num)}
                    className={`flex items-center gap-2 px-3 py-2 rounded-lg text-xs font-semibold transition flex-shrink-0 ${
                      active ? "bg-orange-600 text-white" :
                      done ? "bg-emerald-100 text-emerald-700" :
                      "bg-white border border-stone-200 text-stone-500"
                    }`}
                  >
                    <span className={`w-5 h-5 rounded-full grid place-items-center text-xs font-bold ${
                      active ? "bg-white text-orange-600" :
                      done ? "bg-emerald-600 text-white" :
                      "bg-stone-100 text-stone-500"
                    }`}>
                      {done ? <Check size={11} strokeWidth={3} /> : s.num}
                    </span>
                    <span className="hidden sm:inline">{s.label}</span>
                  </button>
                  {i < stepInfo.length - 1 && (
                    <ChevronRight size={13} className="text-stone-300 flex-shrink-0" />
                  )}
                </Fragment>
              );
            })}
          </div>
        </div>

        {/* Body por step */}
        <div className="p-5 space-y-4">
          {/* === STEP 1: Datos básicos === */}
          {step === 1 && (
            <div className="bg-white border border-stone-200 rounded-2xl p-5 space-y-4">
              <div>
                <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold">Paso 1 · Datos básicos</div>
                <h3 className="font-serif text-xl font-semibold mt-0.5">¿Qué servicio vas a vender?</h3>
                <p className="text-sm text-stone-600 mt-1">Define el nombre, lo que incluye y el precio.</p>
              </div>
              <div>
                <label className="text-xs font-semibold text-stone-700 block mb-1.5">Nombre del servicio</label>
                <input
                  value={data.name}
                  onChange={(e) => update("name", e.target.value)}
                  placeholder="Ej: Consulta veterinaria general"
                  className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
                />
              </div>
              <div>
                <label className="text-xs font-semibold text-stone-700 block mb-1.5">Descripción / qué incluye</label>
                <textarea
                  value={data.description}
                  onChange={(e) => update("description", e.target.value)}
                  placeholder="Examen físico completo, revisión de vacunas, orientación al tutor..."
                  rows={3}
                  className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500 resize-none"
                />
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-xs font-semibold text-stone-700 block mb-1.5">Precio (USD)</label>
                  <div className="relative">
                    <span className="absolute left-3.5 top-1/2 -translate-y-1/2 text-stone-400 font-mono">$</span>
                    <input
                      type="number"
                      min="0"
                      step="0.01"
                      value={data.price}
                      onChange={(e) => update("price", e.target.value)}
                      placeholder="0"
                      className="w-full pl-8 pr-3 py-2.5 bg-white border border-stone-200 rounded-xl text-sm font-mono outline-none focus:border-orange-500"
                    />
                  </div>
                  <div className="text-xs text-stone-500 mt-1">Usa 0 si es por contrato.</div>
                </div>
                <div>
                  <label className="text-xs font-semibold text-stone-700 block mb-1.5">Duración estimada (minutos)</label>
                  <input
                    type="number"
                    min="5"
                    step="5"
                    value={data.duration}
                    onChange={(e) => update("duration", e.target.value)}
                    placeholder="30"
                    className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm font-mono outline-none focus:border-orange-500"
                  />
                </div>
              </div>
            </div>
          )}

          {/* === STEP 2: Módulo === */}
          {step === 2 && (
            <div className="bg-white border border-stone-200 rounded-2xl p-5 space-y-4">
              <div>
                <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold">Paso 2 · Asignación a módulo</div>
                <h3 className="font-serif text-xl font-semibold mt-0.5">¿En qué módulo vivirá este servicio?</h3>
                <p className="text-sm text-stone-600 mt-1">El módulo determina cómo se reserva, quién lo presta y dónde aparece.</p>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                {Object.entries(SERVICE_MODULES).map(([id, info]) => {
                  const Ic = info.Icon;
                  const active = data.module === id;
                  const moduleColors = {
                    orange:  { bg: "bg-orange-50",  text: "text-orange-700",  border: "border-orange-300",  accent: "from-orange-500 to-orange-700" },
                    emerald: { bg: "bg-emerald-50", text: "text-emerald-700", border: "border-emerald-300", accent: "from-emerald-500 to-emerald-700" },
                    blue:    { bg: "bg-blue-50",    text: "text-blue-700",    border: "border-blue-300",    accent: "from-blue-500 to-blue-700" },
                  }[info.color];
                  return (
                    <button
                      key={id}
                      onClick={() => setModule(id)}
                      className={`p-4 rounded-2xl border-2 text-left transition ${
                        active
                          ? `${moduleColors.bg} ${moduleColors.border} ring-2 ring-offset-1 ring-current ${moduleColors.text}`
                          : "bg-white border-stone-200 hover:border-stone-400 text-stone-700"
                      }`}
                    >
                      <div className={`w-12 h-12 rounded-xl bg-gradient-to-br ${moduleColors.accent} text-white grid place-items-center mb-3 shadow`}>
                        <Ic size={20} strokeWidth={1.8} />
                      </div>
                      <div className="font-serif text-lg font-semibold leading-tight">{info.label}</div>
                      <div className={`text-xs mt-1 leading-snug ${active ? moduleColors.text : "text-stone-500"}`}>
                        {info.desc}
                      </div>
                      {active && (
                        <div className="mt-2 flex items-center gap-1 text-xs font-bold">
                          <Check size={12} strokeWidth={2.5} /> Seleccionado
                        </div>
                      )}
                    </button>
                  );
                })}
              </div>
            </div>
          )}

          {/* === STEP 3: Disponibilidad === */}
          {step === 3 && (
            <div className="bg-white border border-stone-200 rounded-2xl p-5 space-y-4">
              <div>
                <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold">Paso 3 · Disponibilidad</div>
                <h3 className="font-serif text-xl font-semibold mt-0.5">¿Cuándo se puede agendar?</h3>
                <p className="text-sm text-stone-600 mt-1">Días de la semana y rango horario en que el servicio está activo.</p>
              </div>
              <div>
                <label className="text-xs font-semibold text-stone-700 block mb-2">Días disponibles</label>
                <div className="flex gap-2">
                  {WEEKDAYS.map(d => {
                    const enabled = data.daysAvailable.includes(d.id);
                    return (
                      <button
                        key={d.id}
                        onClick={() => toggleDay(d.id)}
                        className={`flex-1 py-3 rounded-xl text-sm font-bold transition border-2 ${
                          enabled
                            ? "bg-orange-600 border-orange-600 text-white"
                            : "bg-white border-stone-200 text-stone-400 hover:border-stone-400"
                        }`}
                      >
                        <div>{d.short}</div>
                        <div className="text-xs font-normal mt-0.5 opacity-80">{d.full.slice(0, 3)}</div>
                      </button>
                    );
                  })}
                </div>
                <div className="text-xs text-stone-500 mt-2">
                  Toca cada día para activarlo. Mínimo uno.
                </div>
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-xs font-semibold text-stone-700 block mb-1.5">Hora de apertura</label>
                  <input
                    type="time"
                    value={data.timeStart}
                    onChange={(e) => update("timeStart", e.target.value)}
                    className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm font-mono outline-none focus:border-orange-500"
                  />
                </div>
                <div>
                  <label className="text-xs font-semibold text-stone-700 block mb-1.5">Hora de cierre</label>
                  <input
                    type="time"
                    value={data.timeEnd}
                    onChange={(e) => update("timeEnd", e.target.value)}
                    className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm font-mono outline-none focus:border-orange-500"
                  />
                </div>
              </div>
            </div>
          )}

          {/* === STEP 4: Config específica del módulo === */}
          {step === 4 && (
            <div className="bg-white border border-stone-200 rounded-2xl p-5 space-y-4">
              <div>
                <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold">Paso 4 · Configuración del módulo</div>
                <h3 className="font-serif text-xl font-semibold mt-0.5">
                  Detalles para {moduleInfo.label}
                </h3>
                <p className="text-sm text-stone-600 mt-1">{moduleInfo.desc}.</p>
              </div>

              {/* === Veterinaria: hora fija + sala === */}
              {data.module === "vet" && (
                <div className="space-y-3">
                  <div className="bg-orange-50 border border-orange-200 rounded-xl p-3 flex items-start gap-2.5 text-xs">
                    <Stethoscope size={14} className="text-orange-700 flex-shrink-0 mt-0.5" />
                    <div className="text-orange-900 leading-relaxed">
                      <strong>Tipo de reserva:</strong> hora fija. El cliente elige una hora exacta dentro del rango configurado y un veterinario se asigna a esa cita.
                    </div>
                  </div>
                  <div>
                    <label className="text-xs font-semibold text-stone-700 block mb-1.5">Sala / consultorio (opcional)</label>
                    <input
                      value={data.room}
                      onChange={(e) => update("room", e.target.value)}
                      placeholder="Ej: Consultorio 1, Quirófano, Sala de vacunación"
                      className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
                    />
                  </div>
                  <button
                    onClick={() => update("requiresVet", !data.requiresVet)}
                    className={`w-full flex items-center gap-3 p-3 rounded-xl border transition text-left ${
                      data.requiresVet ? "bg-orange-50 border-orange-200" : "bg-white border-stone-200"
                    }`}
                  >
                    <div className={`w-9 h-9 rounded-lg grid place-items-center flex-shrink-0 ${
                      data.requiresVet ? "bg-orange-100 text-orange-700" : "bg-stone-100 text-stone-500"
                    }`}>
                      <Stethoscope size={15} />
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="font-semibold text-sm">Requiere veterinario asignado</div>
                      <div className="text-xs text-stone-500 mt-0.5">Si se desactiva, podrá reservarse sin profesional preasignado.</div>
                    </div>
                    <span className={`w-10 h-5 rounded-full relative transition flex-shrink-0 ${data.requiresVet ? "bg-orange-600" : "bg-stone-300"}`}>
                      <span className={`absolute top-0.5 w-4 h-4 rounded-full bg-white shadow transition ${data.requiresVet ? "left-5" : "left-0.5"}`}></span>
                    </span>
                  </button>
                </div>
              )}

              {/* === Grooming: ventana de drop-off / pick-up === */}
              {data.module === "grooming" && (
                <div className="space-y-3">
                  <div className="bg-emerald-50 border border-emerald-200 rounded-xl p-3 flex items-start gap-2.5 text-xs">
                    <PawPrint size={14} className="text-emerald-700 flex-shrink-0 mt-0.5" />
                    <div className="text-emerald-900 leading-relaxed">
                      <strong>Tipo de reserva:</strong> drop-off. El cliente deja la mascota dentro de una ventana horaria y la retira más tarde.
                    </div>
                  </div>
                  <div>
                    <div className="text-xs font-semibold text-stone-700 mb-2 flex items-center gap-1.5">
                      <PawPrint size={11} className="text-emerald-700" /> Ventana de entrega (drop-off)
                    </div>
                    <div className="grid grid-cols-2 gap-2">
                      <div>
                        <label className="text-xs text-stone-500 block mb-1">Desde</label>
                        <input
                          type="time"
                          value={data.dropOffWindow.start}
                          onChange={(e) => update("dropOffWindow", { ...data.dropOffWindow, start: e.target.value })}
                          className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm font-mono outline-none focus:border-emerald-500"
                        />
                      </div>
                      <div>
                        <label className="text-xs text-stone-500 block mb-1">Hasta</label>
                        <input
                          type="time"
                          value={data.dropOffWindow.end}
                          onChange={(e) => update("dropOffWindow", { ...data.dropOffWindow, end: e.target.value })}
                          className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm font-mono outline-none focus:border-emerald-500"
                        />
                      </div>
                    </div>
                  </div>
                  <div>
                    <div className="text-xs font-semibold text-stone-700 mb-2 flex items-center gap-1.5">
                      <Check size={11} className="text-emerald-700" /> Ventana de retiro (pick-up)
                    </div>
                    <div className="grid grid-cols-2 gap-2">
                      <div>
                        <label className="text-xs text-stone-500 block mb-1">Desde</label>
                        <input
                          type="time"
                          value={data.pickupWindow.start}
                          onChange={(e) => update("pickupWindow", { ...data.pickupWindow, start: e.target.value })}
                          className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm font-mono outline-none focus:border-emerald-500"
                        />
                      </div>
                      <div>
                        <label className="text-xs text-stone-500 block mb-1">Hasta</label>
                        <input
                          type="time"
                          value={data.pickupWindow.end}
                          onChange={(e) => update("pickupWindow", { ...data.pickupWindow, end: e.target.value })}
                          className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm font-mono outline-none focus:border-emerald-500"
                        />
                      </div>
                    </div>
                  </div>
                </div>
              )}

              {/* === B2B === */}
              {data.module === "b2b" && (
                <div className="space-y-3">
                  <div className="bg-blue-50 border border-blue-200 rounded-xl p-3 flex items-start gap-2.5 text-xs">
                    <Tag size={14} className="text-blue-700 flex-shrink-0 mt-0.5" />
                    <div className="text-blue-900 leading-relaxed">
                      <strong>Tipo de reserva:</strong> recurrente. Pensado para distribuidores y pet shops con pedidos periódicos.
                    </div>
                  </div>
                  <button
                    onClick={() => update("contractRequired", !data.contractRequired)}
                    className={`w-full flex items-center gap-3 p-3 rounded-xl border transition text-left ${
                      data.contractRequired ? "bg-blue-50 border-blue-200" : "bg-white border-stone-200"
                    }`}
                  >
                    <div className={`w-9 h-9 rounded-lg grid place-items-center flex-shrink-0 ${
                      data.contractRequired ? "bg-blue-100 text-blue-700" : "bg-stone-100 text-stone-500"
                    }`}>
                      <FileText size={15} />
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="font-semibold text-sm">Requiere contrato firmado</div>
                      <div className="text-xs text-stone-500 mt-0.5">Solo se puede activar tras subir el contrato comercial.</div>
                    </div>
                    <span className={`w-10 h-5 rounded-full relative transition flex-shrink-0 ${data.contractRequired ? "bg-blue-600" : "bg-stone-300"}`}>
                      <span className={`absolute top-0.5 w-4 h-4 rounded-full bg-white shadow transition ${data.contractRequired ? "left-5" : "left-0.5"}`}></span>
                    </span>
                  </button>
                </div>
              )}

              {/* === Vista previa final === */}
              <div className="border-t border-stone-200 pt-4">
                <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold mb-2">
                  Vista previa
                </div>
                <CatalogServiceCard
                  service={{
                    ...data,
                    price: Number(data.price) || 0,
                    duration: Number(data.duration) || 30,
                    soldCount: editingService ? editingService.soldCount : 0,
                    active: true,
                  }}
                  onEdit={() => {}}
                  onToggleActive={() => {}}
                />
              </div>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="sticky bottom-0 bg-white border-t border-stone-200 p-3 flex items-center justify-between gap-2 rounded-b-2xl">
          <button
            onClick={() => step === 1 ? onClose() : setStep(step - 1)}
            className="flex items-center gap-1.5 px-3 py-2 rounded-xl text-sm font-semibold bg-white border border-stone-200 hover:border-stone-400 text-stone-700"
          >
            <ChevronLeft size={13} /> {step === 1 ? "Cancelar" : "Atrás"}
          </button>
          <div className="text-xs text-stone-500 hidden sm:block">
            Paso {step} de 4
          </div>
          {step < 4 ? (
            <button
              onClick={() => setStep(step + 1)}
              disabled={!canAdvance}
              className={`flex items-center gap-1.5 px-4 py-2 rounded-xl text-sm font-semibold transition ${
                canAdvance
                  ? "bg-orange-600 hover:bg-orange-700 text-white"
                  : "bg-stone-200 text-stone-400 cursor-not-allowed"
              }`}
            >
              Siguiente <ChevronRight size={13} />
            </button>
          ) : (
            <button
              onClick={handleSubmit}
              className="flex items-center gap-1.5 px-4 py-2 rounded-xl text-sm font-semibold bg-emerald-500 hover:bg-emerald-600 text-white shadow"
            >
              <Check size={13} /> {editingService ? "Guardar cambios" : "Crear servicio"}
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

// ========== VISTA: ATENCIÓN GROOMING (operación en sala) ==========
// Vista táctil simplificada para que el groomer trabaje su día.
// Sin precios, sin recibos detallada — solo flujo de servicio + insumos.

function GroomingOpsView({ clients, passports, invoices, setInvoices, userRole, proposals, setProposals, services, setServices, supplies, setSupplies, onMessageClient, canMessage = false, conversations = {}, onSendMessage, bookings: bookingsProp, setBookings: setBookingsProp, petUpdates = [], onSubmitPetUpdate, setPassports, userName, permissions = {}, modules = [], activeModule = null }) {
  const isAdmin = userRole === "super";
  // Modal flotante con calendario
  const [showCalendarModal, setShowCalendarModal] = useState(false);

  // === Features y cardFields del módulo ===
  // Valores con fallback a los defaults de Pet 1 para que cualquier instancia
  // (clon, sede nueva, etc.) tenga paridad funcional por defecto. El admin puede
  // sobreescribirlos desde "Configurar módulo".
  const features = useMemo(() => ({
    suppliesDuringService: true,
    beforeAfterPhotos: true,
    floatingCalendar: true,
    chatWithTutor: true,
    invoiceLink: true,
    dragAndDrop: true,
    ...(activeModule?.features || {}),
  }), [activeModule]);

  const cardFields = useMemo(() => ({
    petName: true,
    petCode: false,
    breed: true,
    age: false,
    tutorName: true,
    time: true,
    invoiceNumber: true,
    statusBadge: false,
    ...(activeModule?.cardFields || {}),
  }), [activeModule]);

  // === Override de columnas desde el módulo ===
  // Si nos pasaron un activeModule (clon como "Grooming 2"), leemos sus columnas.
  // Si no, usamos el módulo "grooming-ops" base. Permite que múltiples instancias
  // del mismo motor tengan columnas distintas.
  const effectiveStates = useMemo(() => {
    const myModule = activeModule || (modules || []).find(m => m.id === "grooming-ops");
    const customCols = myModule?.columns;
    if (!customCols || customCols.length < 3) return GROOMING_STATES;
    // Mapeamos las primeras 3 columnas custom a pending/active/done
    return {
      pending: { ...GROOMING_STATES.pending, label: customCols[0].label || GROOMING_STATES.pending.label },
      active:  { ...GROOMING_STATES.active,  label: customCols[1].label || GROOMING_STATES.active.label },
      done:    { ...GROOMING_STATES.done,    label: customCols[2].label || GROOMING_STATES.done.label },
    };
  }, [modules, activeModule]);

  // Bookings: viene como prop (estado global en App) para que sobreviva al cambiar de vista.
  // Si por alguna razón no se pasa, fallback a state local construido perezosamente.
  const [localBookings, setLocalBookings] = useState(() => bookingsProp || buildInitialGroomingBookings());
  const allBookings = bookingsProp !== undefined ? bookingsProp : localBookings;
  const setBookings = setBookingsProp || setLocalBookings;

  // === Filtrado por instancia ===
  // Cada módulo grooming (base "grooming-ops" + clones "grooming-xxxx") ve solo sus bookings.
  // Bookings sin moduleId (legacy) se asignan a la instancia base "grooming-ops".
  const myModuleId = activeModule?.id || "grooming-ops";
  const bookings = useMemo(
    () => allBookings.filter(b => (b.moduleId || "grooming-ops") === myModuleId),
    [allBookings, myModuleId]
  );

  const [activeBookingId, setActiveBookingId] = useState(null);

  // === Barra de búsqueda y filtro por especie ===
  const [groomSearch, setGroomSearch] = useState("");
  const [groomSpecies, setGroomSpecies] = useState("all");

  // Especies presentes en los bookings de hoy (para las pills)
  const speciesList = useMemo(() => {
    const counts = {};
    bookings.forEach(b => {
      const sp = b.species || "dog";
      counts[sp] = (counts[sp] || 0) + 1;
    });
    return Object.entries(counts).sort((a, b) => b[1] - a[1]);
  }, [bookings]);

  // Bookings filtrados por búsqueda + especie
  const filteredBookings = useMemo(() => {
    let result = bookings;
    if (groomSpecies !== "all") {
      result = result.filter(b => (b.species || "dog") === groomSpecies);
    }
    if (groomSearch.trim()) {
      const q = groomSearch.toLowerCase().trim();
      result = result.filter(b =>
        (b.pet || "").toLowerCase().includes(q) ||
        (b.breed || "").toLowerCase().includes(q) ||
        (b.owner || "").toLowerCase().includes(q) ||
        (b.service || "").toLowerCase().includes(q) ||
        (b.petCode || "").includes(q)
      );
    }
    return result;
  }, [bookings, groomSearch, groomSpecies]);

  // === Drag & drop entre columnas (cambia status del booking) ===
  const [dragOverColumnId, setDragOverColumnId] = useState(null);
  const dragDataRef = useRef(null);
  // Pendiente de confirmación: cuando arrastran un booking a "Terminado" se abre un modal
  // que pide confirmación antes de cerrar y emitir recibo.
  const [pendingFinishBookingId, setPendingFinishBookingId] = useState(null);

  const handleDragStart = (e, bookingId, fromStatus) => {
    if (!bookingId) return;
    dragDataRef.current = { bookingId, fromStatus };
    if (e.dataTransfer) {
      e.dataTransfer.effectAllowed = "move";
      try { e.dataTransfer.setData("text/plain", String(bookingId)); } catch (_) {}
    }
  };
  const handleDragEnd = () => {
    dragDataRef.current = null;
    setDragOverColumnId(null);
  };
  const handleColumnDragOver = (e, columnId) => {
    if (!dragDataRef.current) return;
    // Bloquear visualmente: una card en "done" no se puede regresar
    if (dragDataRef.current.fromStatus === "done") return;
    e.preventDefault();
    if (e.dataTransfer) e.dataTransfer.dropEffect = "move";
    if (dragOverColumnId !== columnId) setDragOverColumnId(columnId);
  };
  const handleColumnDrop = (e, columnId) => {
    e.preventDefault();
    const data = dragDataRef.current;
    setDragOverColumnId(null);
    dragDataRef.current = null;
    if (!data) return;
    if (data.fromStatus === columnId) return;
    // Si la card venía de "done", no permitir retroceso
    if (data.fromStatus === "done") return;
    // Si va a "done": confirmar antes y emitir recibo al confirmar
    if (columnId === "done") {
      setPendingFinishBookingId(data.bookingId);
      return;
    }
    // Cualquier otra transición (pending↔active): aplicar directo
    setBookings(prev => prev.map(b => b.id === data.bookingId ? { ...b, status: columnId } : b));
  };
  // Confirmar el cierre del servicio: marca como "done" y emite recibo
  const confirmFinishBooking = () => {
    const id = pendingFinishBookingId;
    if (!id) return;
    const booking = bookings.find(b => b.id === id);
    if (!booking) {
      setPendingFinishBookingId(null);
      return;
    }
    // Marcar como done
    setBookings(prev => prev.map(b => b.id === id ? { ...b, status: "done" } : b));
    // Emitir recibo ligera con el servicio + insumos.
    // Detecta cliente del booking (mismo match que GroomingAttendanceDrawer).
    const norm = (s) => (s || "").toLowerCase().replace(/[.,]/g, "").trim();
    const target = norm(booking.owner);
    const matchedClient =
      clients.find(c => Array.isArray(c.petCodes) && booking.petCode && c.petCodes.includes(booking.petCode)) ||
      clients.find(c => norm(c.name) === target) ||
      null;
    if (setInvoices) {
      // Resolver precio del SERVICIO desde el catálogo (services).
      // Match por nombre exacto contra services activos del módulo grooming.
      // Si no se encuentra, fallback a 0 (raro: el booking se creó desde un servicio del catálogo).
      const svcDef = (services || []).find(s =>
        s.module === "grooming" && (s.name || "").toLowerCase().trim() === (booking.service || "").toLowerCase().trim()
      );
      const servicePrice = svcDef?.price ?? 0;

      // Resolver precio de cada INSUMO desde el catálogo (supplies).
      // Cada insumo del booking tiene { id, name, qty, unit }. Buscamos el insumo
      // por id en el catálogo y calculamos: precio_unitario = price / defaultQty,
      // luego total_línea = precio_unitario * qty_usada.
      const suppliesCatalog = supplies || GROOMING_SUPPLIES;
      const supplyItems = (booking.supplies || []).map((s, idx) => {
        const def = suppliesCatalog.find(g => g.id === s.id) || GROOMING_SUPPLIES.find(g => g.id === s.id);
        const unitPrice = def ? def.price / def.defaultQty : 0;
        const lineTotal = Math.round(unitPrice * s.qty * 100) / 100;
        return {
          id: `${s.id || "sup"}-${idx}`,
          description: `${s.name} (${s.qty} ${s.unit || ""})`.trim(),
          qty: 1, // representamos la línea como 1 ítem ya cuantificado en la descripción
          unit: lineTotal,
          total: lineTotal,
        };
      });

      const items = [
        { id: "svc", description: booking.service, qty: 1, unit: servicePrice, total: servicePrice },
        ...supplyItems,
      ];
      const subtotal = items.reduce((sum, it) => sum + (it.total || 0), 0);
      const tax = Math.round(subtotal * 0.16 * 100) / 100;
      const total = Math.round((subtotal + tax) * 100) / 100;

      // Si el booking ya viene asociado a una recibo (vino desde venta express),
      // ACTUALIZAMOS esa recibo agregando los insumos al detalle. Si no, creamos una nueva.
      if (booking.invoiceId) {
        setInvoices(prev => prev.map(inv => {
          if (inv.id !== booking.invoiceId) return inv;
          // Conservamos los ítems originales y agregamos los insumos.
          // Recalculamos totales. Si la recibo ya estaba pagada por adelantado y no
          // hay insumos extra, queda como pagada. Si hay insumos, el saldo se vuelve
          // pendiente para cobrar la diferencia.
          const existingItems = inv.items || [];
          const newItems = [...existingItems, ...supplyItems];
          const newSubtotal = newItems.reduce((s, it) => s + (it.total || 0), 0);
          const newTax = Math.round(newSubtotal * 0.16 * 100) / 100;
          const newTotal = Math.round((newSubtotal + newTax) * 100) / 100;
          const newBalance = Math.max(0, newTotal - (inv.paid || 0));

          // Determinar nuevo state:
          // - Si balance === 0 (ya cubierto): pasa a "pagado"
          // - Si balance > 0: queda en "emitido" (Ventas debe cobrar la diferencia)
          // - Si era "borrador": pasa a "emitido" (servicio prestado, ya hay que cobrar)
          let newState = inv.state;
          if (newBalance === 0 && (inv.paid || 0) > 0) {
            newState = "pagado";
          } else if (newBalance > 0) {
            newState = "emitido";
          } else if (inv.state === "borrador") {
            newState = "emitido";
          }

          return {
            ...inv,
            items: newItems,
            subtotal: newSubtotal,
            tax: newTax,
            total: newTotal,
            balance: newBalance,
            state: newState,
            // Marcar como concluido (cinta visual en kanban Sales)
            serviceCompleted: true,
            // Una vez prestado el servicio, ya no es "pago anticipado" — fue pago efectivo
            paidInAdvance: false,
            notes: [
              inv.notes,
              `Servicio concluido. ${supplyItems.length > 0 ? `Insumos agregados: ${supplyItems.length}. Saldo nuevo: $${newBalance.toFixed(2)}.` : "Sin insumos extra."}`,
            ].filter(Boolean).join(" "),
            fromGroomingBooking: { bookingId: booking.id, pet: booking.pet, petCode: booking.petCode },
          };
        }));
      } else {
        // Booking sin recibo previa (creado manualmente en grooming) — emitir una nueva.
        const newInvoice = {
          id: `inv-${Date.now()}-${Math.random().toString(36).slice(2,7)}`,
          number: `00-${String(Date.now()).slice(-6)}`,
          clientId: matchedClient?.id || null,
          clientName: matchedClient?.name || booking.owner || "—",
          issueDate: new Date().toISOString().slice(0, 10),
          dueDate: new Date().toISOString().slice(0, 10),
          items,
          subtotal,
          tax,
          total,
          paid: 0,
          balance: total,
          payments: [],
          state: "emitido",
          serviceCompleted: true,
          notes: `Servicio de grooming concluido para ${booking.pet}. Precios calculados desde el catálogo. Ventas debe gestionar el cobro.`,
          fromGroomingBooking: { bookingId: booking.id, pet: booking.pet, petCode: booking.petCode },
        };
        setInvoices(prev => [newInvoice, ...prev]);
      }
    }
    setPendingFinishBookingId(null);
  };
  const cancelFinishBooking = () => setPendingFinishBookingId(null);

  // Cola de drawers minimizados (máximo 3, FIFO)
  const MAX_MINIMIZED = 3;
  const [minimizedDrawers, setMinimizedDrawers] = useState([]);

  // Click en card → abre directamente el drawer.
  // Si ya había uno abierto, lo manda a la cola de minimizadas.
  const openBooking = (bookingId) => {
    if (activeBookingId === bookingId) return;
    if (activeBookingId) {
      setMinimizedDrawers(prev => {
        const dedup = prev.filter(d => d.id !== activeBookingId && d.id !== bookingId);
        return [...dedup, { id: activeBookingId }].slice(-MAX_MINIMIZED);
      });
    } else {
      setMinimizedDrawers(prev => prev.filter(d => d.id !== bookingId));
    }
    setActiveBookingId(bookingId);
  };
  const minimizeCurrent = () => {
    if (!activeBookingId) return;
    setMinimizedDrawers(prev => {
      const dedup = prev.filter(d => d.id !== activeBookingId);
      return [...dedup, { id: activeBookingId }].slice(-MAX_MINIMIZED);
    });
    setActiveBookingId(null);
  };
  const restoreMinimized = (bookingId) => {
    if (activeBookingId) {
      setMinimizedDrawers(prev => {
        const dedup = prev.filter(d => d.id !== activeBookingId && d.id !== bookingId);
        return [...dedup, { id: activeBookingId }].slice(-MAX_MINIMIZED);
      });
    } else {
      setMinimizedDrawers(prev => prev.filter(d => d.id !== bookingId));
    }
    setActiveBookingId(bookingId);
  };
  const closeMinimized = (bookingId) => {
    setMinimizedDrawers(prev => prev.filter(d => d.id !== bookingId));
  };

  const activeBooking = bookings.find(b => b.id === activeBookingId);

  // Buckets por estado
  const byStatus = useMemo(() => {
    const r = { pending: [], active: [], done: [] };
    filteredBookings.forEach(b => { r[b.status]?.push(b); });
    return r;
  }, [filteredBookings]);

  const updateBooking = (id, updates) => {
    setBookings(prev => prev.map(b => b.id === id ? { ...b, ...updates } : b));
  };

  const advanceStatus = (id) => {
    const order = ["pending", "active", "done"];
    setBookings(prev => prev.map(b => {
      if (b.id !== id) return b;
      const idx = order.indexOf(b.status);
      const next = order[Math.min(idx + 1, order.length - 1)];
      return { ...b, status: next };
    }));
  };

  const addSupply = (bookingId, supply, qty) => {
    setBookings(prev => prev.map(b => {
      if (b.id !== bookingId) return b;
      // Si ya está, sumar cantidad
      const existing = b.supplies.find(s => s.id === supply.id);
      if (existing) {
        return {
          ...b,
          supplies: b.supplies.map(s =>
            s.id === supply.id ? { ...s, qty: s.qty + qty } : s
          ),
        };
      }
      return {
        ...b,
        supplies: [...b.supplies, { ...supply, qty }],
      };
    }));
  };

  const removeSupply = (bookingId, supplyId) => {
    setBookings(prev => prev.map(b =>
      b.id === bookingId
        ? { ...b, supplies: b.supplies.filter(s => s.id !== supplyId) }
        : b
    ));
  };

  return (
    <div className="space-y-4">
      {/* === Vista única: operación del día === */}
      {/* Header del día */}
      <div className="bg-gradient-to-br from-white via-emerald-50 to-emerald-100 border border-stone-200 rounded-2xl p-5">
        <div className="flex items-center gap-4 flex-wrap">
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase text-emerald-700 font-semibold mb-1">
              Sala de grooming
            </div>
            <h2 className="font-serif text-2xl sm:text-3xl font-semibold leading-tight">
              <span className="text-emerald-700">{bookings.length}</span> servicios hoy
            </h2>
            <p className="text-sm text-stone-600 mt-1">
              Toca cualquier mascota para iniciar o continuar su atención.
            </p>
          </div>
          <button
            onClick={() => setShowCalendarModal(true)}
            className={`flex items-center gap-1.5 px-3 py-2 rounded-xl bg-white border border-emerald-300 text-emerald-700 text-sm font-semibold hover:bg-emerald-50 transition shadow-sm flex-shrink-0 ${features.floatingCalendar === false ? "hidden" : ""}`}
            title="Ver calendario completo de citas grooming"
          >
            <Calendar size={14} /> Calendario
          </button>
          <div className="flex gap-1.5">
            {Object.entries(effectiveStates).map(([id, info]) => {
              const count = byStatus[id]?.length || 0;
              const colors = {
                stone:   "bg-stone-100   text-stone-700",
                blue:    "bg-blue-100    text-blue-700",
                amber:   "bg-amber-100   text-amber-700",
                emerald: "bg-emerald-100 text-emerald-700",
              }[info.color];
              return (
                <div key={id} className={`px-3 py-2 rounded-xl ${colors} text-center`}>
                  <div className="font-serif text-2xl font-bold leading-none">{count}</div>
                  <div className="text-xs uppercase font-semibold tracking-wider mt-0.5">{info.label}</div>
                </div>
              );
            })}
          </div>
        </div>
      </div>

      {/* === Barra de búsqueda + filtros de especie === */}
      <div className="bg-white border border-stone-200 rounded-2xl shadow-sm p-3 flex flex-col sm:flex-row gap-3 items-stretch sm:items-center">
        {/* Buscador */}
        <div className="relative flex-1 min-w-0">
          <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-stone-400" />
          <input
            value={groomSearch}
            onChange={(e) => setGroomSearch(e.target.value)}
            placeholder="Buscar mascota, tutor, raza o servicio..."
            className="w-full pl-9 pr-8 py-2 bg-stone-50 border border-stone-200 rounded-xl text-sm outline-none focus:border-emerald-400 focus:bg-white transition"
          />
          {groomSearch && (
            <button
              onClick={() => setGroomSearch("")}
              className="absolute right-2 top-1/2 -translate-y-1/2 w-5 h-5 rounded-full bg-stone-200 hover:bg-stone-300 grid place-items-center text-stone-500 transition"
            >
              <X size={9} />
            </button>
          )}
        </div>
        {/* Filtros de especie */}
        <div className="flex gap-1 flex-shrink-0 overflow-x-auto">
          <button
            onClick={() => setGroomSpecies("all")}
            className={`flex items-center gap-1 px-2.5 py-1.5 rounded-xl text-xs font-semibold whitespace-nowrap transition border ${
              groomSpecies === "all"
                ? "bg-emerald-600 text-white border-emerald-600"
                : "bg-white border-stone-200 text-stone-600 hover:border-emerald-300"
            }`}
          >
            Todos
            <span className={`text-[10px] font-bold px-1.5 py-px rounded-full ${
              groomSpecies === "all" ? "bg-emerald-700 text-white" : "bg-stone-100 text-stone-600"
            }`}>{bookings.length}</span>
          </button>
          {speciesList.map(([sp, count]) => {
            const speciesInfo = {
              dog: { label: "Perros", icon: "🐕" },
              cat: { label: "Gatos", icon: "🐈" },
              bird: { label: "Aves", icon: "🦜" },
              rabbit: { label: "Conejos", icon: "🐇" },
              hamster: { label: "Roedores", icon: "🐹" },
              reptile: { label: "Reptiles", icon: "🦎" },
            }[sp] || { label: sp, icon: "🐾" };
            return (
              <button
                key={sp}
                onClick={() => setGroomSpecies(sp)}
                className={`flex items-center gap-1 px-2.5 py-1.5 rounded-xl text-xs font-semibold whitespace-nowrap transition border ${
                  groomSpecies === sp
                    ? "bg-emerald-600 text-white border-emerald-600"
                    : "bg-white border-stone-200 text-stone-600 hover:border-emerald-300"
                }`}
              >
                <span className="text-sm">{speciesInfo.icon}</span>
                {speciesInfo.label}
                <span className={`text-[10px] font-bold px-1.5 py-px rounded-full ${
                  groomSpecies === sp ? "bg-emerald-700 text-white" : "bg-stone-100 text-stone-600"
                }`}>{count}</span>
              </button>
            );
          })}
        </div>
        {/* Indicador de filtro activo */}
        {(groomSearch || groomSpecies !== "all") && (
          <div className="flex items-center gap-1.5 text-xs text-emerald-700 font-semibold flex-shrink-0">
            <Filter size={11} />
            {filteredBookings.length} de {bookings.length}
            <button
              onClick={() => { setGroomSearch(""); setGroomSpecies("all"); }}
              className="ml-1 text-stone-400 hover:text-red-500 transition"
              title="Limpiar filtros"
            >
              <X size={11} />
            </button>
          </div>
        )}
      </div>

      {/* Tres columnas con etapas */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
        {Object.entries(effectiveStates).map(([statusId, info]) => {
          const list = byStatus[statusId] || [];
          const colors = {
            stone:   { header: "bg-stone-100   text-stone-700",   accent: "border-stone-300" },
            blue:    { header: "bg-blue-100    text-blue-700",    accent: "border-blue-300" },
            amber:   { header: "bg-amber-100   text-amber-700",   accent: "border-amber-300" },
            emerald: { header: "bg-emerald-100 text-emerald-700", accent: "border-emerald-300" },
          }[info.color];

          return (
            <div
              key={statusId}
              onDragOver={(e) => handleColumnDragOver(e, statusId)}
              onDragLeave={() => { if (dragOverColumnId === statusId) setDragOverColumnId(null); }}
              onDrop={(e) => handleColumnDrop(e, statusId)}
              className={`bg-white border border-stone-200 rounded-2xl overflow-hidden flex flex-col transition ${
                dragOverColumnId === statusId ? "ring-2 ring-emerald-400 ring-offset-2 scale-[1.005]" : ""
              }`}
            >
              <div className={`p-3 ${colors.header} border-b border-stone-200`}>
                <div className="text-xs tracking-widest uppercase font-bold flex items-center justify-between">
                  <span>{info.label}</span>
                  <span className="font-mono">{list.length}</span>
                </div>
              </div>
              <div className="p-2 space-y-2 min-h-32 flex-1">
                {list.length === 0 ? (
                  <div className="text-xs text-stone-400 text-center py-6 leading-relaxed">
                    {statusId === "pending" && "Sin citas pendientes"}
                    {statusId === "active" && "Ninguno en proceso"}
                    {statusId === "done" && "Aún no se ha terminado nada"}
                  </div>
                ) : (
                  list.map(b => (
                    <button
                      key={b.id}
                      draggable={features.dragAndDrop !== false && statusId !== "done"}
                      onDragStart={(e) => features.dragAndDrop !== false && statusId !== "done" && handleDragStart(e, b.id, statusId)}
                      onDragEnd={handleDragEnd}
                      onClick={() => openBooking(b.id)}
                      className={`w-full text-left bg-white border-2 ${colors.accent} rounded-xl p-3 hover:shadow-md transition ${
                        features.dragAndDrop !== false && statusId !== "done" ? "cursor-grab active:cursor-grabbing" : "cursor-pointer"
                      }`}
                    >
                      <div className="flex items-center gap-2 mb-1.5">
                        <div className="w-9 h-9 rounded-lg bg-gradient-to-br from-emerald-200 to-emerald-100 grid place-items-center text-emerald-800 flex-shrink-0">
                          <PawPrint size={15} strokeWidth={1.8} />
                        </div>
                        <div className="flex-1 min-w-0">
                          {cardFields.petName !== false && (
                            <div className={`font-bold text-sm truncate ${!b.pet ? "text-amber-700 italic" : ""}`}>
                              {b.pet || "Sin nombre"}
                              {cardFields.petCode && b.petCode && (
                                <span className="ml-1.5 font-mono text-xs text-emerald-700 font-bold">#{b.petCode}</span>
                              )}
                            </div>
                          )}
                          {cardFields.breed !== false && (
                            <div className="text-xs text-stone-500 truncate">{b.breed || (!b.pet ? "Pendiente: agregar nombre" : "")}</div>
                          )}
                        </div>
                        {cardFields.time !== false && (
                          <span className="font-mono text-xs font-bold text-stone-700 bg-stone-100 px-2 py-1 rounded">
                            {b.time}
                          </span>
                        )}
                      </div>
                      <div className="text-xs font-semibold text-stone-700 mb-1">{b.service}</div>
                      {cardFields.tutorName !== false && (
                        <div className="text-xs text-stone-500 truncate">{b.owner}</div>
                      )}
                      {/* Número de recibo asociado (hilo conductor con Ventas) */}
                      {cardFields.invoiceNumber !== false && b.invoiceNumber && (
                        <div className="mt-1.5 flex items-center gap-1 text-xs text-orange-700 font-mono font-semibold">
                          <Receipt size={11} strokeWidth={2} />
                          {b.invoiceNumber}
                        </div>
                      )}
                      {(b.supplies?.length || 0) > 0 && (
                        <div className="mt-1.5 flex items-center gap-1 text-xs text-emerald-700 font-semibold">
                          <Check size={11} strokeWidth={2.5} />
                          {b.supplies.length} insumo{b.supplies.length === 1 ? "" : "s"}
                        </div>
                      )}
                    </button>
                  ))
                )}
              </div>
            </div>
          );
        })}
      </div>

      {/* Drawer de atención */}
      {activeBooking && (
        <GroomingAttendanceDrawer
          booking={activeBooking}
          clients={clients}
          passports={passports}
          setPassports={setPassports}
          invoices={invoices}
          setInvoices={setInvoices}
          setProposals={setProposals}
          userRole={userRole}
          supplies={supplies}
          onClose={() => setActiveBookingId(null)}
          onMinimize={minimizeCurrent}
          onAdvance={() => advanceStatus(activeBooking.id)}
          onAddSupply={(supply, qty) => addSupply(activeBooking.id, supply, qty)}
          onRemoveSupply={(supplyId) => removeSupply(activeBooking.id, supplyId)}
          onUpdateBooking={(updates) => updateBooking(activeBooking.id, updates)}
          canMessage={canMessage}
          conversations={conversations}
          onSendMessage={onSendMessage}
          petUpdates={petUpdates}
          onSubmitPetUpdate={onSubmitPetUpdate}
          userName={userName}
          permissions={permissions}
        />
      )}

      {/* Stack de drawers minimizados (hasta 3 pills) */}
      {minimizedDrawers.length > 0 && (
        <MinimizedDrawerStack
          drawers={minimizedDrawers}
          resolvePatient={(id) => bookings.find(b => b.id === id)}
          resolveTutor={(booking) => {
            if (!booking?.owner) return null;
            const norm = (s) => (s || "").toLowerCase().replace(/[.,]/g, "").trim();
            const target = norm(booking.owner);
            return clients.find(c => Array.isArray(c.petCodes) && booking.petCode && c.petCodes.includes(booking.petCode))
                || clients.find(c => norm(c.name) === target)
                || null;
          }}
          onRestore={restoreMinimized}
          onCloseOne={closeMinimized}
          accent="emerald"
          icon="grooming"
        />
      )}

      {/* Modal de calendario */}
      {showCalendarModal && (
        <GroomingCalendarModal onClose={() => setShowCalendarModal(false)} />
      )}

      {/* Confirmación al arrastrar a "Terminado": cierra servicio + emite recibo */}
      {pendingFinishBookingId && (() => {
        const b = bookings.find(x => x.id === pendingFinishBookingId);
        if (!b) return null;
        return (
          <div onClick={cancelFinishBooking} className="fixed inset-0 z-50 bg-stone-900 grid place-items-center p-4">
            <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl shadow-2xl max-w-md w-full overflow-hidden">
              <div className="p-5 border-b border-stone-200 flex items-start gap-3">
                <div className="w-11 h-11 rounded-xl bg-emerald-100 text-emerald-700 grid place-items-center flex-shrink-0">
                  <Check size={20} strokeWidth={2} />
                </div>
                <div className="flex-1 min-w-0">
                  <h3 className="font-serif text-lg font-bold leading-tight">¿Terminar servicio de {b.pet}?</h3>
                  <p className="text-xs text-stone-500 mt-1 leading-relaxed">
                    Marcar como terminado <strong>cierra el servicio</strong> y <strong>emite una recibo</strong>{" "}
                    automáticamente. Una vez en "Terminado" no se puede regresar a otra etapa.
                  </p>
                </div>
              </div>
              <div className="p-4 bg-stone-50 space-y-1.5 text-xs">
                <div className="flex items-center justify-between">
                  <span className="text-stone-500">Servicio</span>
                  <span className="font-semibold">{b.service}</span>
                </div>
                <div className="flex items-center justify-between">
                  <span className="text-stone-500">Tutor</span>
                  <span className="font-semibold">{b.owner}</span>
                </div>
                {b.supplies && b.supplies.length > 0 && (
                  <div className="flex items-center justify-between">
                    <span className="text-stone-500">Insumos usados</span>
                    <span className="font-semibold">{b.supplies.length}</span>
                  </div>
                )}
              </div>
              <div className="p-4 flex gap-2 border-t border-stone-200">
                <button
                  onClick={cancelFinishBooking}
                  className="flex-1 px-4 py-2.5 rounded-xl border border-stone-200 hover:bg-stone-50 text-stone-700 text-sm font-semibold transition"
                >
                  Cancelar
                </button>
                <button
                  onClick={confirmFinishBooking}
                  className="flex-1 px-4 py-2.5 rounded-xl bg-emerald-600 hover:bg-emerald-700 text-white text-sm font-semibold shadow transition flex items-center justify-center gap-1.5"
                >
                  <Check size={14} strokeWidth={2.4} /> Sí, terminar y cobrar
                </button>
              </div>
            </div>
          </div>
        );
      })()}
    </div>
  );
}

// ========== VENTANA FLOTANTE: Calendario de Grooming ==========
// Mini-app arrastrable: el usuario puede moverla, minimizarla y maximizarla
// sin bloquear la interacción con el kanban de fondo.
function GroomingCalendarModal({ onClose }) {
  const [calView, setCalView] = useState("week"); // day | week | month
  const [selectedDate, setSelectedDate] = useState(new Date());

  // Estado de la ventana flotante
  const [position, setPosition] = useState({ x: 80, y: 60 });
  const [size, setSize] = useState({ w: 720, h: 560 });
  const [minimized, setMinimized] = useState(false);
  const [maximized, setMaximized] = useState(false);
  // Para restaurar al desmaximizar
  const prevState = useRef({ position, size });
  // Drag tracking
  const dragRef = useRef(null);

  const onDragStart = (e) => {
    if (maximized) return;
    if (e.target.closest("button")) return; // ignorar clicks en los dots/botones del header
    const startX = e.clientX;
    const startY = e.clientY;
    const startPos = { ...position };
    const handleMove = (ev) => {
      setPosition({
        x: Math.max(0, startPos.x + (ev.clientX - startX)),
        y: Math.max(0, startPos.y + (ev.clientY - startY)),
      });
    };
    const handleUp = () => {
      window.removeEventListener("mousemove", handleMove);
      window.removeEventListener("mouseup", handleUp);
    };
    window.addEventListener("mousemove", handleMove);
    window.addEventListener("mouseup", handleUp);
  };

  const toggleMaximize = () => {
    if (maximized) {
      // Restaurar
      setPosition(prevState.current.position);
      setSize(prevState.current.size);
      setMaximized(false);
    } else {
      // Guardar y maximizar
      prevState.current = { position, size };
      setPosition({ x: 16, y: 16 });
      // Tamaño grande pero dejando margen
      setSize({ w: typeof window !== "undefined" ? window.innerWidth - 32 : 1200, h: typeof window !== "undefined" ? window.innerHeight - 32 : 720 });
      setMaximized(true);
      setMinimized(false);
    }
  };

  // Filtrar solo eventos grooming
  const eventsByDate = useMemo(() => {
    const map = {};
    AGENDA_EVENTS.filter(e => e.type === "grooming").forEach(e => {
      if (!map[e.date]) map[e.date] = [];
      map[e.date].push(e);
    });
    return map;
  }, []);

  const totalGroomingCount = useMemo(
    () => AGENDA_EVENTS.filter(e => e.type === "grooming").length,
    []
  );

  const navigatePrev = () => {
    const d = new Date(selectedDate);
    if (calView === "day") d.setDate(d.getDate() - 1);
    else if (calView === "week") d.setDate(d.getDate() - 7);
    else d.setMonth(d.getMonth() - 1);
    setSelectedDate(d);
  };
  const navigateNext = () => {
    const d = new Date(selectedDate);
    if (calView === "day") d.setDate(d.getDate() + 1);
    else if (calView === "week") d.setDate(d.getDate() + 7);
    else d.setMonth(d.getMonth() + 1);
    setSelectedDate(d);
  };
  const goToToday = () => setSelectedDate(new Date());

  const periodLabel = useMemo(() => {
    if (calView === "day") {
      return selectedDate.toLocaleDateString("es", { weekday: "long", day: "numeric", month: "long" });
    }
    if (calView === "week") {
      const start = new Date(selectedDate);
      start.setDate(start.getDate() - start.getDay() + 1);
      const end = new Date(start);
      end.setDate(end.getDate() + 6);
      return `${start.getDate()} ${start.toLocaleDateString("es", { month: "short" })} – ${end.getDate()} ${end.toLocaleDateString("es", { month: "short" })}`;
    }
    return selectedDate.toLocaleDateString("es", { month: "long", year: "numeric" });
  }, [selectedDate, calView]);

  // Cuando está minimizada: barra al pie de la pantalla
  if (minimized) {
    return (
      <div
        className="fixed bottom-4 right-4 z-50 bg-stone-900 text-white rounded-xl shadow-2xl flex items-center gap-2 pl-3 pr-1 py-1 cursor-pointer hover:bg-stone-800 transition"
        onClick={() => setMinimized(false)}
      >
        <Calendar size={14} className="text-emerald-400" />
        <span className="text-xs font-semibold">Calendario Grooming</span>
        <button
          onClick={(e) => { e.stopPropagation(); onClose(); }}
          className="w-7 h-7 rounded-lg hover:bg-stone-700 grid place-items-center text-stone-400 hover:text-white"
        >
          <X size={12} />
        </button>
      </div>
    );
  }

  return (
    <div
      ref={dragRef}
      className="fixed z-50 bg-white rounded-2xl shadow-2xl flex flex-col border border-stone-300 overflow-hidden"
      style={{
        left: position.x,
        top: position.y,
        width: size.w,
        height: size.h,
        maxWidth: "calc(100vw - 16px)",
        maxHeight: "calc(100vh - 16px)",
      }}
    >
      {/* Title bar arrastrable */}
      <div
        onMouseDown={onDragStart}
        onDoubleClick={toggleMaximize}
        className={`px-3 py-2 bg-gradient-to-r from-stone-800 to-stone-900 text-white flex items-center gap-2 flex-shrink-0 ${
          maximized ? "cursor-default" : "cursor-move"
        } select-none`}
      >
        <div className="flex items-center gap-1.5 mr-1">
          <button
            onClick={(e) => { e.stopPropagation(); onClose(); }}
            title="Cerrar"
            className="w-3 h-3 rounded-full bg-red-400 hover:bg-red-500 transition"
          ></button>
          <button
            onClick={(e) => { e.stopPropagation(); setMinimized(true); }}
            title="Minimizar"
            className="w-3 h-3 rounded-full bg-amber-400 hover:bg-amber-500 transition"
          ></button>
          <button
            onClick={(e) => { e.stopPropagation(); toggleMaximize(); setMinimized(false); }}
            title={maximized ? "Restaurar" : "Maximizar"}
            className="w-3 h-3 rounded-full bg-emerald-400 hover:bg-emerald-500 transition"
          ></button>
        </div>
        <Calendar size={13} className="text-emerald-400 flex-shrink-0" />
        <span className="text-xs font-semibold flex-1 truncate">
          Calendario · Grooming <span className="text-stone-400 font-normal">— {periodLabel}</span>
        </span>
        <div className="flex items-center gap-0.5 flex-shrink-0">
          <button
            onClick={() => setMinimized(true)}
            title="Minimizar"
            className="w-6 h-6 rounded grid place-items-center text-stone-300 hover:bg-stone-700 hover:text-white transition"
          >
            <Minus size={12} />
          </button>
          <button
            onClick={toggleMaximize}
            title={maximized ? "Restaurar" : "Maximizar"}
            className="w-6 h-6 rounded grid place-items-center text-stone-300 hover:bg-stone-700 hover:text-white transition"
          >
            {maximized ? <Minimize2 size={11} /> : <Maximize2 size={11} />}
          </button>
          <button
            onClick={onClose}
            title="Cerrar"
            className="w-6 h-6 rounded grid place-items-center text-stone-300 hover:bg-red-600 hover:text-white transition"
          >
            <X size={12} />
          </button>
        </div>
      </div>

      {/* Toolbar */}
      <div className="px-3 py-2 border-b border-stone-200 bg-stone-50 flex items-center gap-2 flex-wrap flex-shrink-0">
        {/* Switcher día/semana/mes */}
        <div className="bg-white rounded-lg p-0.5 flex gap-0.5 border border-stone-200">
          {[
            { id: "day", label: "Día" },
            { id: "week", label: "Semana" },
            { id: "month", label: "Mes" },
          ].map(opt => (
            <button
              key={opt.id}
              onClick={() => setCalView(opt.id)}
              className={`px-2.5 py-1 rounded text-xs font-semibold transition ${
                calView === opt.id
                  ? "bg-stone-900 text-white"
                  : "text-stone-600 hover:text-stone-900"
              }`}
            >
              {opt.label}
            </button>
          ))}
        </div>

        {/* Navegación */}
        <div className="flex items-center gap-0.5">
          <button onClick={navigatePrev} className="w-7 h-7 rounded-lg bg-white border border-stone-200 hover:border-stone-400 grid place-items-center text-stone-600">
            <ChevronLeft size={13} />
          </button>
          <button onClick={goToToday} className="px-2.5 h-7 rounded-lg bg-white border border-stone-200 hover:border-stone-400 text-xs font-semibold text-stone-700">
            Hoy
          </button>
          <button onClick={navigateNext} className="w-7 h-7 rounded-lg bg-white border border-stone-200 hover:border-stone-400 grid place-items-center text-stone-600">
            <ChevronRight size={13} />
          </button>
        </div>

        <div className="ml-auto text-xs text-stone-500">
          <span className="font-mono font-bold text-emerald-700">{totalGroomingCount}</span> citas
        </div>
      </div>

      {/* Body con scroll */}
      <div className="flex-1 overflow-y-auto p-3 bg-stone-50">
        {calView === "day" && (
          <AgendaDay
            date={selectedDate}
            eventsByDate={eventsByDate}
            onSelectEvent={() => {}}
          />
        )}
        {calView === "week" && (
          <AgendaWeek
            date={selectedDate}
            eventsByDate={eventsByDate}
            onJumpToDay={(d) => { setSelectedDate(d); setCalView("day"); }}
            onSelectEvent={() => {}}
          />
        )}
        {calView === "month" && (
          <AgendaMonth
            date={selectedDate}
            eventsByDate={eventsByDate}
            onJumpToDay={(d) => { setSelectedDate(d); setCalView("day"); }}
            onSelectEvent={() => {}}
          />
        )}
      </div>

      {/* Handle de resize */}
      <WindowResizeHandle size={size} setSize={setSize} disabled={maximized} />
    </div>
  );
}

// ========== TAB: Catálogo de servicios + insumos (super) ==========
function GroomingCatalogManager({ services, setServices, supplies, setSupplies }) {
  const [section, setSection] = useState("services"); // services | supplies
  const [editingSupply, setEditingSupply] = useState(null); // null | "new" | <id>
  const [editingService, setEditingService] = useState(null); // null | <id>

  // Solo servicios del módulo grooming
  const groomingServices = useMemo(
    () => services.filter(s => s.module === "grooming"),
    [services]
  );

  const supplyDraftBlank = { name: "", category: "Higiene", unit: "ml", defaultQty: 50, price: 0, active: true };
  const [supplyDraft, setSupplyDraft] = useState(supplyDraftBlank);

  const startNewSupply = () => {
    setSupplyDraft(supplyDraftBlank);
    setEditingSupply("new");
  };
  const startEditSupply = (s) => {
    setSupplyDraft({ ...s });
    setEditingSupply(s.id);
  };

  const saveSupply = () => {
    if (!supplyDraft.name.trim() || supplyDraft.price < 0) return;
    if (editingSupply === "new") {
      const newSupply = {
        ...supplyDraft,
        id: `gs-${Date.now().toString(36)}`,
        defaultQty: Number(supplyDraft.defaultQty) || 1,
        price: Number(supplyDraft.price) || 0,
      };
      setSupplies(prev => [...prev, newSupply]);
    } else {
      setSupplies(prev => prev.map(s => s.id === editingSupply ? {
        ...s,
        ...supplyDraft,
        defaultQty: Number(supplyDraft.defaultQty) || 1,
        price: Number(supplyDraft.price) || 0,
      } : s));
    }
    setEditingSupply(null);
  };

  const toggleSupplyActive = (id) => {
    setSupplies(prev => prev.map(s => s.id === id ? { ...s, active: s.active === false ? true : false } : s));
  };

  const deleteSupply = (id) => {
    setSupplies(prev => prev.filter(s => s.id !== id));
  };

  const categories = ["Higiene", "Aroma", "Decoración", "Otro"];
  const units = ["ml", "gr", "spray", "unidad", "aplic."];

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="bg-gradient-to-br from-white via-stone-50 to-orange-50 border border-stone-200 rounded-2xl p-5">
        <div className="flex items-start gap-4 flex-wrap">
          <div className="w-12 h-12 rounded-xl bg-orange-500 text-white grid place-items-center shadow-lg flex-shrink-0">
            <Scissors size={20} strokeWidth={1.8} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold">
              Administración · super usuario
            </div>
            <h2 className="font-serif text-2xl font-semibold leading-tight">
              Catálogo de <span className="italic text-orange-700">grooming</span>
            </h2>
            <p className="text-sm text-stone-600 mt-1">
              Gestiona los servicios disponibles y los insumos que el groomer puede usar (con sus precios internos para recibos).
            </p>
          </div>
        </div>
      </div>

      {/* Sub-tabs */}
      <div className="bg-white border border-stone-200 rounded-2xl shadow-sm p-1.5 flex gap-1">
        <button
          onClick={() => setSection("services")}
          className={`flex-1 flex items-center justify-center gap-2 px-3 py-2 rounded-xl text-sm font-semibold transition ${
            section === "services" ? "bg-orange-50 text-orange-800" : "bg-transparent text-stone-600 hover:bg-stone-50"
          }`}
        >
          <Bath size={13} /> Servicios ({groomingServices.length})
        </button>
        <button
          onClick={() => setSection("supplies")}
          className={`flex-1 flex items-center justify-center gap-2 px-3 py-2 rounded-xl text-sm font-semibold transition ${
            section === "supplies" ? "bg-orange-50 text-orange-800" : "bg-transparent text-stone-600 hover:bg-stone-50"
          }`}
        >
          <Droplets size={13} /> Insumos ({supplies.length})
        </button>
      </div>

      {/* SERVICIOS */}
      {section === "services" && (
        <div className="space-y-3">
          {groomingServices.length === 0 && (
            <div className="bg-white border border-stone-200 rounded-2xl p-12 text-center">
              <Bath size={32} className="text-stone-300 mx-auto mb-3" />
              <div className="text-base font-semibold text-stone-700">Sin servicios de grooming</div>
              <div className="text-sm text-stone-500 mt-1">Crea uno desde Nueva venta &gt; Catálogo de servicios.</div>
            </div>
          )}
          {groomingServices.map(svc => (
            <div key={svc.id} className="bg-white border border-stone-200 rounded-2xl p-4 flex items-center gap-3">
              <div className="w-10 h-10 rounded-xl bg-emerald-100 text-emerald-700 grid place-items-center flex-shrink-0">
                <Bath size={16} strokeWidth={1.8} />
              </div>
              <div className="flex-1 min-w-0">
                <div className="font-semibold text-sm">{svc.name}</div>
                <div className="text-xs text-stone-500 mt-0.5">
                  {svc.duration ? `${svc.duration} min · ` : ""}
                  {svc.description || "Sin descripción"}
                </div>
              </div>
              <div className="text-right">
                <div className="text-xs text-stone-400">Precio</div>
                <div className="font-mono font-bold text-orange-700">${svc.price}</div>
              </div>
              <button
                onClick={() => setEditingService(svc.id)}
                className="w-9 h-9 rounded-lg bg-stone-100 hover:bg-orange-100 grid place-items-center text-stone-600 hover:text-orange-700 transition flex-shrink-0"
                title="Editar precio"
              >
                <Edit3 size={13} />
              </button>
            </div>
          ))}

          {/* Modal de edición de servicio (solo precio inline) */}
          {editingService && (() => {
            const svc = services.find(s => s.id === editingService);
            if (!svc) return null;
            return (
              <div onClick={() => setEditingService(null)} className="fixed inset-0 bg-stone-900 z-50 flex justify-center items-center p-4">
                <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl w-full max-w-sm shadow-2xl overflow-hidden">
                  <div className="p-4 border-b border-stone-200 bg-orange-50">
                    <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold">
                      Editar servicio
                    </div>
                    <h3 className="font-serif text-lg font-semibold mt-0.5">{svc.name}</h3>
                  </div>
                  <div className="p-5 space-y-3">
                    <div>
                      <label className="text-xs font-semibold text-stone-700 block mb-1.5">Nombre</label>
                      <input
                        value={svc.name}
                        onChange={(e) => setServices(prev => prev.map(s => s.id === svc.id ? { ...s, name: e.target.value } : s))}
                        className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
                      />
                    </div>
                    <div className="grid grid-cols-2 gap-2">
                      <div>
                        <label className="text-xs font-semibold text-stone-700 block mb-1.5">Precio ($)</label>
                        <input
                          type="number"
                          min="0"
                          step="0.01"
                          value={svc.price}
                          onChange={(e) => setServices(prev => prev.map(s => s.id === svc.id ? { ...s, price: Number(e.target.value) || 0 } : s))}
                          className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500 font-mono"
                        />
                      </div>
                      <div>
                        <label className="text-xs font-semibold text-stone-700 block mb-1.5">Duración (min)</label>
                        <input
                          type="number"
                          min="0"
                          value={svc.duration || 0}
                          onChange={(e) => setServices(prev => prev.map(s => s.id === svc.id ? { ...s, duration: Number(e.target.value) || 0 } : s))}
                          className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500 font-mono"
                        />
                      </div>
                    </div>
                    <div>
                      <label className="text-xs font-semibold text-stone-700 block mb-1.5">Descripción</label>
                      <textarea
                        value={svc.description || ""}
                        onChange={(e) => setServices(prev => prev.map(s => s.id === svc.id ? { ...s, description: e.target.value } : s))}
                        rows={2}
                        className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500 resize-none"
                      />
                    </div>
                  </div>
                  <div className="p-3 border-t border-stone-200 bg-stone-50 flex justify-end gap-2">
                    <button onClick={() => setEditingService(null)} className="px-3 py-2 rounded-xl text-sm font-semibold bg-orange-600 hover:bg-orange-700 text-white shadow">
                      <Check size={13} className="inline" /> Listo
                    </button>
                  </div>
                </div>
              </div>
            );
          })()}
        </div>
      )}

      {/* INSUMOS */}
      {section === "supplies" && (
        <div className="space-y-2">
          <button
            onClick={startNewSupply}
            className="w-full flex items-center justify-center gap-1.5 px-3 py-2.5 rounded-xl bg-emerald-500 hover:bg-emerald-600 text-white text-sm font-semibold shadow transition"
          >
            <Plus size={13} /> Agregar insumo nuevo
          </button>

          {/* Agrupar por categoría */}
          {categories.map(cat => {
            const list = supplies.filter(s => (s.category || "Otro") === cat);
            if (list.length === 0) return null;
            return (
              <div key={cat}>
                <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold mt-3 mb-1.5 px-1">
                  {cat}
                </div>
                <div className="space-y-1.5">
                  {list.map(s => (
                    <div
                      key={s.id}
                      className={`bg-white border rounded-xl p-3 flex items-center gap-3 ${
                        s.active === false ? "border-stone-200 opacity-60" : "border-stone-200"
                      }`}
                    >
                      <div className={`w-9 h-9 rounded-lg grid place-items-center flex-shrink-0 ${
                        s.active === false ? "bg-stone-100 text-stone-400" : "bg-emerald-50 text-emerald-700 border border-emerald-200"
                      }`}>
                        <Droplets size={14} strokeWidth={1.8} />
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="font-semibold text-sm flex items-center gap-2">
                          {s.name}
                          {s.active === false && (
                            <span className="text-xs font-bold px-1.5 py-px rounded bg-stone-200 text-stone-600">Inactivo</span>
                          )}
                        </div>
                        <div className="text-xs text-stone-500 mt-0.5">
                          Por defecto: {s.defaultQty} {s.unit}
                        </div>
                      </div>
                      <div className="text-right flex-shrink-0">
                        <div className="text-xs text-stone-400">Precio</div>
                        <div className="font-mono font-bold text-orange-700">${s.price}</div>
                      </div>
                      <div className="flex gap-1 flex-shrink-0">
                        <button
                          onClick={() => startEditSupply(s)}
                          className="w-8 h-8 rounded-lg bg-stone-100 hover:bg-orange-100 grid place-items-center text-stone-600 hover:text-orange-700 transition"
                          title="Editar"
                        >
                          <Edit3 size={12} />
                        </button>
                        <button
                          onClick={() => toggleSupplyActive(s.id)}
                          className="w-8 h-8 rounded-lg bg-stone-100 hover:bg-amber-100 grid place-items-center text-stone-600 hover:text-amber-700 transition"
                          title={s.active === false ? "Activar" : "Desactivar"}
                        >
                          {s.active === false ? <Eye size={12} /> : <EyeOff size={12} />}
                        </button>
                        <button
                          onClick={() => deleteSupply(s.id)}
                          className="w-8 h-8 rounded-lg bg-stone-100 hover:bg-red-100 grid place-items-center text-stone-600 hover:text-red-700 transition"
                          title="Eliminar"
                        >
                          <Trash2 size={12} />
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            );
          })}

          {/* Modal de edición/creación de insumo */}
          {editingSupply && (
            <div onClick={() => setEditingSupply(null)} className="fixed inset-0 bg-stone-900 z-50 flex justify-center items-center p-4">
              <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden">
                <div className="p-4 border-b border-stone-200 bg-emerald-50 flex items-center gap-3">
                  <div className="w-10 h-10 rounded-xl bg-emerald-500 text-white grid place-items-center shadow-lg flex-shrink-0">
                    <Droplets size={17} />
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="text-xs tracking-widest uppercase text-emerald-700 font-semibold">
                      {editingSupply === "new" ? "Nuevo insumo" : "Editar insumo"}
                    </div>
                    <h3 className="font-serif text-lg font-semibold mt-0.5">
                      {supplyDraft.name || "Sin nombre"}
                    </h3>
                  </div>
                </div>
                <div className="p-5 space-y-3">
                  <div>
                    <label className="text-xs font-semibold text-stone-700 block mb-1.5">Nombre *</label>
                    <input
                      value={supplyDraft.name}
                      onChange={(e) => setSupplyDraft({ ...supplyDraft, name: e.target.value })}
                      placeholder="Ej: Champú hipoalergénico"
                      autoFocus
                      className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-emerald-500"
                    />
                  </div>
                  <div className="grid grid-cols-2 gap-2">
                    <div>
                      <label className="text-xs font-semibold text-stone-700 block mb-1.5">Categoría</label>
                      <select
                        value={supplyDraft.category}
                        onChange={(e) => setSupplyDraft({ ...supplyDraft, category: e.target.value })}
                        className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-emerald-500"
                      >
                        {categories.map(c => <option key={c} value={c}>{c}</option>)}
                      </select>
                    </div>
                    <div>
                      <label className="text-xs font-semibold text-stone-700 block mb-1.5">Unidad</label>
                      <select
                        value={supplyDraft.unit}
                        onChange={(e) => setSupplyDraft({ ...supplyDraft, unit: e.target.value })}
                        className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-emerald-500"
                      >
                        {units.map(u => <option key={u} value={u}>{u}</option>)}
                      </select>
                    </div>
                  </div>
                  <div className="grid grid-cols-2 gap-2">
                    <div>
                      <label className="text-xs font-semibold text-stone-700 block mb-1.5">
                        Cantidad por defecto
                      </label>
                      <input
                        type="number"
                        min="0"
                        step="0.5"
                        value={supplyDraft.defaultQty}
                        onChange={(e) => setSupplyDraft({ ...supplyDraft, defaultQty: e.target.value })}
                        className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-emerald-500 font-mono"
                      />
                    </div>
                    <div>
                      <label className="text-xs font-semibold text-stone-700 block mb-1.5">
                        Precio por defecto ($)
                      </label>
                      <input
                        type="number"
                        min="0"
                        step="0.01"
                        value={supplyDraft.price}
                        onChange={(e) => setSupplyDraft({ ...supplyDraft, price: e.target.value })}
                        className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-emerald-500 font-mono"
                      />
                    </div>
                  </div>
                  <div className="bg-stone-50 border border-stone-200 rounded-xl p-2.5 text-xs text-stone-600 leading-relaxed">
                    <Info size={11} className="inline mr-1" />
                    El precio es el costo asociado a la cantidad por defecto. Si pones $4 por 50ml, cada ml costará $0.08.
                  </div>
                </div>
                <div className="p-3 border-t border-stone-200 bg-stone-50 flex gap-2">
                  <button
                    onClick={() => setEditingSupply(null)}
                    className="flex-1 px-3 py-2 rounded-xl text-sm font-semibold bg-white border border-stone-200 hover:border-stone-400 text-stone-700"
                  >
                    Cancelar
                  </button>
                  <button
                    onClick={saveSupply}
                    disabled={!supplyDraft.name.trim()}
                    className={`flex-1 px-3 py-2 rounded-xl text-sm font-semibold transition shadow ${
                      supplyDraft.name.trim()
                        ? "bg-emerald-500 hover:bg-emerald-600 text-white"
                        : "bg-stone-200 text-stone-400 cursor-not-allowed"
                    }`}
                  >
                    <Check size={13} className="inline" strokeWidth={2.5} />
                    {editingSupply === "new" ? " Crear" : " Guardar"}
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

// === Drawer de atención: el groomer trabaja desde aquí ===
function GroomingAttendanceDrawer({
  booking, clients, passports, setPassports, invoices, setInvoices, setProposals, userRole, supplies = GROOMING_SUPPLIES,
  onClose, onMinimize, onAdvance, onAddSupply, onRemoveSupply, onUpdateBooking,
  canMessage = false, conversations = {}, onSendMessage,
  petUpdates = [], onSubmitPetUpdate, userName,
  permissions = {},
}) {
  const [showSupplyPicker, setShowSupplyPicker] = useState(false);
  const [showFinishModal, setShowFinishModal] = useState(false);
  // Helper: pregunta el nivel del rol actual sobre un campo del CRM grooming.
  // IMPORTANTE: las secciones "tutor", "pet" y "messaging" son conceptos transversales
  // que viven en el CRM "clients" (no se duplican por cada CRM). Por eso esas tres
  // secciones se consultan contra "clients" — así, ocultar el tutor o la mensajería
  // en "Clientes" lo oculta en TODOS los servicios. Las secciones específicas
  // (service) sí se consultan contra el CRM grooming.
  const fieldLevel = (sectionId, fieldId) => {
    const transversal = (sectionId === "tutor" || sectionId === "pet" || sectionId === "messaging");
    const targetCrm = transversal ? "clients" : "grooming";
    // Las secciones "tutor"/"pet"/"messaging" en clients se llaman "tutor"/"pets"/"messaging"
    const targetSection = (targetCrm === "clients" && sectionId === "pet") ? "pets" : sectionId;
    return getFieldLevel(permissions, userRole, targetCrm, targetSection, fieldId);
  };
  const showField = (sectionId, fieldId) => fieldLevel(sectionId, fieldId) !== "hidden";
  const canEditField = (sectionId, fieldId) => fieldLevel(sectionId, fieldId) === "edit";

  // Compatibilidad: el flag isGroomer sigue siendo útil para detalles cosméticos
  // que no califican como "campo" en el schema (ej. badge segmento, etc.)
  const isGroomer = userRole === "grooming";

  // Detectar el cliente desde el owner del booking.
  // Match flexible: nombre exacto, o primer nombre + inicial del apellido (ej: "Elena V." → "Elena Velásquez")
  const matchedClient = useMemo(() => {
    if (!booking.owner) return null;
    const norm = (s) => s.toLowerCase().replace(/[.,]/g, "").trim();
    const target = norm(booking.owner);

    // 1. Match exacto
    let m = clients.find(c => norm(c.name) === target);
    if (m) return m;

    // 2. Match por "Primer Nombre Inicial." → busca cliente cuyo primer nombre coincida
    //    y cuyo apellido empiece con la inicial dada
    const parts = target.split(/\s+/);
    if (parts.length >= 2) {
      const firstName = parts[0];
      const initial = parts[parts.length - 1].charAt(0);
      m = clients.find(c => {
        const cParts = norm(c.name).split(/\s+/);
        return cParts[0] === firstName && (cParts[1] || "").charAt(0) === initial;
      });
      if (m) return m;
    }

    // 3. Match solo por primer nombre (último recurso, podría dar falsos positivos)
    if (parts.length >= 1) {
      m = clients.find(c => norm(c.name).split(/\s+/)[0] === parts[0]);
      if (m) return m;
    }

    return null;
  }, [booking.owner, clients]);

  // Recibos abiertas (borrador o emitido) del cliente
  const openInvoices = useMemo(() => {
    if (!matchedClient) return [];
    return invoices.filter(inv =>
      inv.clientId === matchedClient.id &&
      (inv.state === "borrador" || inv.state === "emitido")
    );
  }, [matchedClient, invoices]);

  const status = booking.status;
  const stateInfo = GROOMING_STATES[status];

  // Botón principal según estado
  const advanceLabel = {
    pending: { label: "Iniciar servicio",    Icon: Bath },
    active:  { label: "Terminar servicio",   Icon: BadgeCheck },
    done:    { label: "Servicio completado", Icon: Check },
  }[status];

  const handleAdvanceClick = () => {
    // En "active" → "done" pasamos por el modal de finalización
    if (status === "active") {
      setShowFinishModal(true);
      return;
    }
    if (status !== "done") onAdvance();
  };

  const colors = {
    stone:   { bg: "bg-stone-50",   border: "border-stone-300",   text: "text-stone-700",   button: "bg-stone-700 hover:bg-stone-800" },
    blue:    { bg: "bg-blue-50",    border: "border-blue-300",    text: "text-blue-700",    button: "bg-blue-600 hover:bg-blue-700" },
    amber:   { bg: "bg-amber-50",   border: "border-amber-300",   text: "text-amber-700",   button: "bg-amber-600 hover:bg-amber-700" },
    emerald: { bg: "bg-emerald-50", border: "border-emerald-300", text: "text-emerald-700", button: "bg-emerald-600 hover:bg-emerald-700" },
  }[stateInfo.color];

  // Buscar pasaporte por código (para mini-perfil de mascota)
  const matchedPassport = useMemo(() => {
    if (!booking.petCode) return null;
    return passports.find(p => p.code === booking.petCode) || null;
  }, [booking.petCode, passports]);
  const [showPetInfo, setShowPetInfo] = useState(false);

  // === Estado de ventana flotante (dots macOS, draggable, maximizable) ===
  // La minimización la maneja el padre (cola de hasta 3).
  const [position, setPosition] = useState({ x: 100, y: 30 });
  const [size, setSize] = useState({ w: 1100, h: 660 });
  const [maximized, setMaximized] = useState(false);
  const prevState = useRef({ position, size });

  // === Layout móvil ===
  // En móvil la ventana ocupa toda la pantalla (no draggable, no maximizable),
  // y los dos paneles (chat / ficha) se vuelven tabs en lugar de columnas.
  const isMobile = useIsMobile();
  const [mobileTab, setMobileTab] = useState("ficha"); // "chat" | "ficha"

  const onDragStart = (e) => {
    if (maximized) return;
    if (e.target.closest("button")) return;
    const startX = e.clientX, startY = e.clientY;
    const startPos = { ...position };
    const handleMove = (ev) => {
      setPosition({
        x: Math.max(0, startPos.x + (ev.clientX - startX)),
        y: Math.max(0, startPos.y + (ev.clientY - startY)),
      });
    };
    const handleUp = () => {
      window.removeEventListener("mousemove", handleMove);
      window.removeEventListener("mouseup", handleUp);
    };
    window.addEventListener("mousemove", handleMove);
    window.addEventListener("mouseup", handleUp);
  };

  const toggleMaximize = () => {
    if (maximized) {
      setPosition(prevState.current.position);
      setSize(prevState.current.size);
      setMaximized(false);
    } else {
      prevState.current = { position, size };
      setPosition({ x: 16, y: 16 });
      setSize({
        w: typeof window !== "undefined" ? window.innerWidth - 32 : 1200,
        h: typeof window !== "undefined" ? window.innerHeight - 32 : 720,
      });
      setMaximized(true);
    }
  };

  // === Estado del chat ===
  const tutorConversation = matchedClient ? (conversations[matchedClient.id] || []) : [];
  const [chatDraft, setChatDraft] = useState("");
  const [chatChannel, setChatChannel] = useState("whatsapp");
  const channelMessages = useMemo(
    () => tutorConversation.filter(m => m.channel === chatChannel),
    [tutorConversation, chatChannel]
  );
  const channelStats = useMemo(() => {
    const m = {};
    tutorConversation.forEach(msg => { m[msg.channel] = (m[msg.channel] || 0) + 1; });
    return m;
  }, [tutorConversation]);
  const handleChatSend = () => {
    if (!chatDraft.trim() || !matchedClient || !onSendMessage) return;
    onSendMessage(matchedClient.id, chatChannel, chatDraft.trim());
    setChatDraft("");
  };
  const handleChatKeyDown = (e) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleChatSend();
    }
  };

  // === Adjuntos del chat (foto / recibo) ===
  // Menú "+" del composer y sus modales. Mismo patrón que la consola
  // veterinaria y el módulo de Mensajes.
  const [showChatAttachMenu, setShowChatAttachMenu] = useState(false);
  const [showChatImagePicker, setShowChatImagePicker] = useState(false);
  const [showChatInvoicePicker, setShowChatInvoicePicker] = useState(false);
  // Permiso de enviar recibo por chat — específico del CRM Grooming. Se
  // resuelve contra el CRM "grooming" (no transversal): cada CRM controla su
  // propio envío de recibos. Las fotos no requieren este permiso.
  const canSendInvoice = showField("service", "send-invoice");

  const handleChatSendImage = (imageDataUrl, caption = "") => {
    if (!matchedClient || !onSendMessage) return;
    const body = caption || "📎 Imagen adjunta";
    onSendMessage(matchedClient.id, chatChannel, body, {
      attachment: { type: "image", url: imageDataUrl, caption },
    });
    setShowChatImagePicker(false);
    setShowChatAttachMenu(false);
  };
  const handleChatSendInvoice = (inv, messageText = null) => {
    if (!matchedClient || !onSendMessage) return;
    // Defensa en profundidad: sin permiso no se envía aunque se invoque.
    if (!canSendInvoice) return;
    if (messageText) {
      onSendMessage(matchedClient.id, chatChannel, messageText);
    }
    const body = `📄 Recibo ${inv.number} · $${(inv.total ?? 0).toFixed(2)}`;
    onSendMessage(matchedClient.id, chatChannel, body, {
      attachment: { type: "invoice", invoiceId: inv.id },
    });
    setShowChatInvoicePicker(false);
    setShowChatAttachMenu(false);
  };

  return (
    <>
      <div
        className={isMobile
          ? "fixed inset-0 z-50 bg-stone-50 flex flex-col overflow-hidden"
          : "fixed z-50 bg-stone-50 rounded-2xl shadow-2xl flex flex-col border border-stone-300 overflow-hidden"
        }
        style={isMobile ? undefined : {
          left: position.x,
          top: position.y,
          width: size.w,
          height: size.h,
          maxWidth: "calc(100vw - 16px)",
          maxHeight: "calc(100vh - 16px)",
        }}
      >
        {/* Title bar (en móvil sin drag/maximize, solo cerrar) */}
        <div
          onMouseDown={isMobile ? undefined : onDragStart}
          onDoubleClick={isMobile ? undefined : toggleMaximize}
          className={`px-3 py-2 bg-gradient-to-r from-stone-800 to-stone-900 text-white flex items-center gap-2 flex-shrink-0 ${
            isMobile ? "cursor-default" : (maximized ? "cursor-default" : "cursor-move")
          } select-none`}
        >
          {isMobile ? (
            // Móvil: botón de cerrar grande + minimizar
            <>
              <button
                onClick={(e) => { e.stopPropagation(); onClose(); }}
                className="w-8 h-8 rounded-lg hover:bg-stone-700 grid place-items-center text-white -ml-1"
                title="Cerrar"
              >
                <X size={16} />
              </button>
              {onMinimize && (
                <button
                  onClick={(e) => { e.stopPropagation(); onMinimize(); }}
                  className="w-8 h-8 rounded-lg hover:bg-stone-700 grid place-items-center text-white"
                  title="Minimizar"
                >
                  <Minus size={16} />
                </button>
              )}
            </>
          ) : (
            <div className="flex items-center gap-1.5 mr-1">
              <button onClick={(e) => { e.stopPropagation(); onClose(); }} title="Cerrar"
                className="w-3 h-3 rounded-full bg-red-400 hover:bg-red-500 transition"></button>
              <button onClick={(e) => { e.stopPropagation(); onMinimize ? onMinimize() : onClose(); }} title="Minimizar"
                className="w-3 h-3 rounded-full bg-amber-400 hover:bg-amber-500 transition"></button>
              <button onClick={(e) => { e.stopPropagation(); toggleMaximize(); }} title={maximized ? "Restaurar" : "Maximizar"}
                className="w-3 h-3 rounded-full bg-emerald-400 hover:bg-emerald-500 transition"></button>
            </div>
          )}
          <Scissors size={13} className="text-emerald-400 flex-shrink-0" />
          <span className="text-xs font-semibold flex-1 truncate uppercase tracking-wider">
            Servicio · {booking.pet}
            {matchedClient && !isMobile && <span className="text-stone-400 normal-case tracking-normal ml-2">· {matchedClient.name}</span>}
          </span>
        </div>

        {/* En móvil: tabs Ficha / Chat (chat solo si hay tutor) */}
        {isMobile && matchedClient && onSendMessage && showField("messaging", "chat-read") && (
          <div className="flex bg-white border-b border-stone-200 flex-shrink-0">
            <button
              onClick={() => setMobileTab("ficha")}
              className={`flex-1 py-2.5 text-xs font-bold uppercase tracking-wider transition flex items-center justify-center gap-1.5 ${
                mobileTab === "ficha" ? "text-emerald-700 border-b-2 border-emerald-600 bg-emerald-50" : "text-stone-500 border-b-2 border-transparent"
              }`}
            >
              <PawPrint size={12} strokeWidth={2.2} /> Servicio
            </button>
            <button
              onClick={() => setMobileTab("chat")}
              className={`flex-1 py-2.5 text-xs font-bold uppercase tracking-wider transition flex items-center justify-center gap-1.5 ${
                mobileTab === "chat" ? "text-emerald-700 border-b-2 border-emerald-600 bg-emerald-50" : "text-stone-500 border-b-2 border-transparent"
              }`}
            >
              <MessageCircle size={12} strokeWidth={2.2} /> Chat
              {tutorConversation.filter(m => m.direction === "in" && m.status !== "read").length > 0 && (
                <span className="text-xs font-bold px-1.5 py-px rounded-full bg-emerald-600 text-white">
                  {tutorConversation.filter(m => m.direction === "in" && m.status !== "read").length}
                </span>
              )}
            </button>
          </div>
        )}

        {/* Cuerpo: en desktop = 2 columnas, en móvil = panel activo */}
        <div className={`flex-1 overflow-hidden ${isMobile ? "flex flex-col" : "flex"}`}>

          {/* === Panel chat (izquierda) — solo si hay tutor identificado === */}
          {matchedClient && onSendMessage && showField("messaging", "chat-read") && (!isMobile || mobileTab === "chat") && (
            <div
              className={isMobile
                ? "flex-1 flex flex-col bg-white overflow-hidden"
                : "flex flex-col bg-white border-r border-stone-200 flex-shrink-0"
              }
              style={isMobile ? undefined : { width: 380 }}
            >
              {/* Header del tutor */}
              <div className="p-3 border-b border-stone-200 bg-gradient-to-r from-white to-emerald-50 flex items-center gap-2 flex-shrink-0">
                <div className={`w-9 h-9 rounded-full grid place-items-center text-white text-xs font-bold flex-shrink-0 ${
                  matchedClient.isOrg ? "bg-gradient-to-br from-stone-700 to-stone-900" : "bg-gradient-to-br from-emerald-500 to-emerald-700"
                }`}>
                  {matchedClient.name.split(" ").slice(0, 2).map(s => s[0]).join("").toUpperCase()}
                </div>
                <div className="flex-1 min-w-0">
                  <div className="font-semibold text-xs truncate">{matchedClient.name}</div>
                  {showField("tutor", "phone") && matchedClient.phone && (
                    <div className="text-xs text-stone-500 truncate font-mono">{matchedClient.phone}</div>
                  )}
                </div>
                {!canMessage && (
                  <span title="Mensajería deshabilitada para tu rol" className="text-stone-400">
                    <Lock size={11} />
                  </span>
                )}
              </div>

              {/* Tabs canal */}
              <div className="flex gap-0.5 px-2 pt-2 bg-stone-50 border-b border-stone-200 overflow-x-auto flex-shrink-0">
                {Object.entries(CHAT_CHANNELS).map(([id, info]) => {
                  const Icon = info.icon;
                  const active = chatChannel === id;
                  const count = channelStats[id] || 0;
                  const colors = CHAT_CHANNEL_CLASSES[info.color];
                  return (
                    <button
                      key={id}
                      onClick={() => setChatChannel(id)}
                      className={`flex items-center gap-1.5 px-3 py-1.5 text-xs font-semibold rounded-t-lg transition border-b-2 flex-shrink-0 ${
                        active ? `bg-white ${colors.text} border-current` : "text-stone-500 hover:text-stone-700 border-transparent"
                      }`}
                    >
                      <Icon size={11} strokeWidth={1.8} />
                      {info.label}
                      {count > 0 && (
                        <span className={`text-xs font-bold px-1.5 py-px rounded-full ${
                          active ? colors.bg : "bg-stone-200 text-stone-600"
                        }`}>{count}</span>
                      )}
                    </button>
                  );
                })}
              </div>

              {/* Mensajes */}
              <div className="flex-1 overflow-y-auto p-3 space-y-2 bg-stone-50">
                {channelMessages.length === 0 ? (
                  <div className="flex flex-col items-center justify-center h-full text-stone-400">
                    <MessageCircle size={28} className="mb-2 opacity-30" />
                    <span className="text-xs">No hay mensajes en este canal todavía.</span>
                    <span className="text-xs mt-0.5">Escribe el primero abajo.</span>
                  </div>
                ) : (
                  channelMessages.map(msg => (
                    <div key={msg.id} className={`flex ${msg.direction === "out" ? "justify-end" : "justify-start"}`}>
                      <div className={`max-w-xs rounded-2xl px-3 py-1.5 text-xs ${
                        msg.direction === "out"
                          ? "bg-emerald-600 text-white rounded-br-md"
                          : "bg-white border border-stone-200 text-stone-800 rounded-bl-md"
                      }`}>
                        <div className="leading-relaxed">{msg.body}</div>
                        <div className={`text-xs mt-0.5 flex items-center gap-1 ${
                          msg.direction === "out" ? "text-emerald-100 justify-end" : "text-stone-400"
                        }`}>
                          <span className="font-mono opacity-80">
                            {new Date(msg.timestamp).toLocaleTimeString("es", { hour: "2-digit", minute: "2-digit" })}
                          </span>
                          {msg.direction === "out" && msg.status && (
                            <span className="ml-0.5">
                              {msg.status === "sent" && "✓"}
                              {msg.status === "delivered" && "✓✓"}
                              {msg.status === "read" && <span className="text-emerald-300">✓✓</span>}
                            </span>
                          )}
                        </div>
                      </div>
                    </div>
                  ))
                )}
              </div>

              {/* Composer */}
              <div className="p-2 border-t border-stone-200 bg-white flex-shrink-0 flex items-end gap-2">
                {/* Botón "+" para adjuntar foto o recibo. La opción "Recibo"
                    depende del permiso send-invoice del CRM Grooming; "Foto"
                    siempre está disponible (para mostrarle al tutor cómo va
                    quedando su mascota). */}
                <div className="relative flex-shrink-0">
                  <button
                    onClick={() => setShowChatAttachMenu(v => !v)}
                    disabled={!canMessage}
                    title="Adjuntar"
                    className={`w-9 h-9 rounded-xl grid place-items-center transition ${
                      !canMessage
                        ? "bg-stone-100 text-stone-300 cursor-not-allowed"
                        : showChatAttachMenu
                          ? "bg-emerald-500 text-white rotate-45"
                          : "bg-stone-100 hover:bg-stone-200 text-stone-600"
                    }`}
                  >
                    <Plus size={14} />
                  </button>
                  {showChatAttachMenu && canMessage && (
                    <>
                      <div onClick={() => setShowChatAttachMenu(false)} className="fixed inset-0 z-30"></div>
                      <div className="absolute left-0 bottom-full mb-2 w-56 bg-white border border-stone-200 rounded-xl shadow-2xl z-40 overflow-hidden">
                        <button
                          onClick={() => { setShowChatAttachMenu(false); setShowChatImagePicker(true); }}
                          className={`w-full flex items-start gap-2.5 p-3 hover:bg-emerald-50 transition text-left ${
                            canSendInvoice ? "border-b border-stone-100" : ""
                          }`}
                        >
                          <div className="w-8 h-8 rounded-lg bg-blue-100 text-blue-700 grid place-items-center flex-shrink-0">
                            <Camera size={13} />
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="font-semibold text-sm">Foto</div>
                            <div className="text-xs text-stone-500 leading-snug">
                              Muéstrale al tutor cómo va quedando.
                            </div>
                          </div>
                        </button>
                        {canSendInvoice && (
                          <button
                            onClick={() => { setShowChatAttachMenu(false); setShowChatInvoicePicker(true); }}
                            className="w-full flex items-start gap-2.5 p-3 hover:bg-emerald-50 transition text-left"
                          >
                            <div className="w-8 h-8 rounded-lg bg-orange-100 text-orange-700 grid place-items-center flex-shrink-0">
                              <Receipt size={13} />
                            </div>
                            <div className="flex-1 min-w-0">
                              <div className="font-semibold text-sm">Recibo</div>
                              <div className="text-xs text-stone-500 leading-snug">
                                Comparte cualquier recibo existente.
                              </div>
                            </div>
                          </button>
                        )}
                      </div>
                    </>
                  )}
                </div>
                <textarea
                  value={chatDraft}
                  onChange={(e) => setChatDraft(e.target.value)}
                  onKeyDown={handleChatKeyDown}
                  placeholder={canMessage ? `Mensaje por ${CHAT_CHANNELS[chatChannel]?.label || chatChannel}…` : "Mensajería deshabilitada para tu rol"}
                  rows={1}
                  disabled={!canMessage}
                  className="flex-1 resize-none px-3 py-2 bg-stone-50 border border-stone-200 rounded-xl text-xs outline-none focus:border-emerald-400 focus:bg-white transition disabled:opacity-50"
                  style={{ maxHeight: 80 }}
                />
                <button
                  onClick={handleChatSend}
                  disabled={!chatDraft.trim() || !canMessage}
                  className={`w-9 h-9 rounded-xl grid place-items-center transition flex-shrink-0 ${
                    chatDraft.trim() && canMessage
                      ? "bg-emerald-600 hover:bg-emerald-700 text-white shadow"
                      : "bg-stone-200 text-stone-400 cursor-not-allowed"
                  }`}
                  title="Enviar mensaje"
                >
                  <Send size={13} strokeWidth={2.2} />
                </button>
              </div>
            </div>
          )}

          {/* === Panel ficha grooming (derecha en desktop / tab "ficha" en móvil) === */}
          {(!isMobile || mobileTab === "ficha" || !matchedClient || !onSendMessage || !showField("messaging", "chat-read")) && (
          <div className="flex-1 min-w-0 bg-stone-50 flex flex-col overflow-hidden">
          <div className={`p-4 ${colors.bg} border-b ${colors.border} flex items-start gap-3 flex-shrink-0`}>
          <div className="flex-1 min-w-0">
            <div className={`text-xs tracking-widest uppercase ${colors.text} font-bold flex items-center gap-1.5`}>
              <span className={`w-2 h-2 rounded-full ${
                stateInfo.color === "emerald" ? "bg-emerald-500" :
                stateInfo.color === "amber"   ? "bg-amber-500 animate-pulse" :
                stateInfo.color === "blue"    ? "bg-blue-500" :
                "bg-stone-500"
              }`}></span>
              {stateInfo.label}
            </div>
            <div className="flex items-center gap-2 mt-0.5 flex-wrap">
              {booking.pet ? (
                <h2 className="font-serif text-xl font-bold leading-tight">{booking.pet}</h2>
              ) : (
                <input
                  type="text"
                  defaultValue=""
                  placeholder="Escribe el nombre de la mascota..."
                  onBlur={(e) => {
                    const val = e.target.value.trim();
                    if (val && onUpdateBooking) onUpdateBooking(booking.id, { pet: val });
                  }}
                  onKeyDown={(e) => {
                    if (e.key === "Enter") {
                      e.target.blur();
                    }
                  }}
                  className="font-serif text-lg font-bold leading-tight bg-white border-2 border-amber-400 rounded-lg px-3 py-1 outline-none focus:border-amber-500 placeholder:text-amber-600 placeholder:italic"
                  autoFocus
                />
              )}
              {booking.petCode && (
                <span className="font-mono text-sm font-bold text-orange-700 bg-white px-2 py-0.5 rounded-md border border-orange-200">
                  #{booking.petCode}
                </span>
              )}
              <button
                onClick={() => setShowPetInfo(true)}
                title="Ver perfil de la mascota"
                className="w-7 h-7 rounded-lg bg-white border border-stone-200 hover:border-orange-400 grid place-items-center text-stone-600 hover:text-orange-700 transition flex-shrink-0"
              >
                <Search size={12} />
              </button>
            </div>
            {!booking.pet && (
              <div className="text-xs text-amber-700 font-semibold mt-1 flex items-center gap-1">
                <Info size={11} /> Mascota sin nombre. Escribe arriba para registrarla en este servicio.
              </div>
            )}
            <div className="text-xs text-stone-600 mt-1">
              {booking.breed || (booking.pet ? "" : "")} · <span className="font-mono">{booking.time}</span>
              {booking.invoiceNumber && (
                <> · <span className="font-mono text-orange-700">Recibo {booking.invoiceNumber}</span></>
              )}
            </div>
          </div>
        </div>

        {/* Body scrollable */}
        <div className="flex-1 overflow-y-auto p-4 space-y-3">
          {/* Datos del servicio */}
          <div className="bg-white border border-stone-200 rounded-xl p-3 space-y-2">
            <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold">Servicio</div>
            <div>
              <div className="font-semibold text-base">{booking.service}</div>
              {booking.reason && (
                <div className="text-xs text-stone-600 mt-1 leading-snug">{booking.reason}</div>
              )}
            </div>
            <div className="grid grid-cols-2 gap-2 pt-2 border-t border-stone-100 text-xs">
              {booking.room && (
                <div>
                  <div className="text-stone-500">Sala</div>
                  <div className="font-semibold">{booking.room}</div>
                </div>
              )}
              <div>
                <div className="text-stone-500">Duración</div>
                <div className="font-semibold">{booking.duration} min</div>
              </div>
              {booking.petCode && (
                <div>
                  <div className="text-stone-500">Código</div>
                  <div className="font-mono font-bold text-emerald-700">#{booking.petCode}</div>
                </div>
              )}
            </div>
          </div>

          {/* === Mascota (editable) === */}
          {/* Misma sección que en el drawer de Vet — permite editar datos del
              pasaporte directamente desde grooming. Solo se renderiza si hay
              pasaporte vinculado al booking. */}
          {matchedPassport && (
            <div className="bg-white border border-stone-200 rounded-xl overflow-hidden">
              <PetEditableSection
                patient={{
                  name: matchedPassport.name,
                  code: matchedPassport.code,
                  species: matchedPassport.species,
                  breed: matchedPassport.breed,
                  age: matchedPassport.age,
                  gender: matchedPassport.gender,
                }}
                passport={matchedPassport}
                onUpdatePassport={canEditField("service", "edit-pet") ? (updates) => {
                  setPassports && setPassports(prev => prev.map(p =>
                    p.code === matchedPassport.code ? { ...p, ...updates } : p
                  ));
                  // También sincronizar campos del booking si cambiaron
                  if (onUpdateBooking && (updates.name !== matchedPassport.name || updates.breed !== matchedPassport.breed)) {
                    onUpdateBooking({
                      ...(updates.name && { pet: updates.name }),
                      ...(updates.breed && { breed: updates.breed }),
                    });
                  }
                } : null}
              />
            </div>
          )}

          {/* Ficha del tutor — datos administrativos.
              Cada campo se muestra/oculta según los permisos por CRM definidos en Roles. */}
          <div className="bg-white border border-stone-200 rounded-xl p-3">
            <div className="text-xs tracking-widest uppercase text-emerald-700 font-semibold mb-2 flex items-center justify-between">
              <span>Tutor</span>
              {showField("tutor", "segment") && matchedClient?.segment && (
                <span className={`text-xs font-bold px-1.5 py-0.5 rounded ${
                  matchedClient.segment === "Premium" ? "bg-purple-100 text-purple-700" :
                  matchedClient.segment === "Frecuente" ? "bg-blue-100 text-blue-700" :
                  matchedClient.segment === "Nuevo" ? "bg-emerald-100 text-emerald-700" :
                  "bg-stone-100 text-stone-700"
                }`}>
                  {matchedClient.segment}
                </span>
              )}
            </div>
            <div className="flex items-start gap-3">
              <div className={`w-11 h-11 rounded-xl grid place-items-center text-white text-xs font-bold flex-shrink-0 ${
                matchedClient?.isOrg ? "bg-gradient-to-br from-stone-700 to-stone-900" : "bg-gradient-to-br from-emerald-500 to-emerald-700"
              }`}>
                {(matchedClient?.name || booking.owner || "??").split(" ").slice(0, 2).map(s => s[0]).join("").toUpperCase()}
              </div>
              <div className="flex-1 min-w-0">
                {showField("tutor", "name") && (
                  <div className="font-semibold text-sm text-stone-900 leading-tight">
                    {matchedClient?.name || booking.owner || "Tutor sin registrar"}
                  </div>
                )}
                {/* Detalles administrativos: cada campo según su permiso */}
                {matchedClient ? (() => {
                  const visibleAdmin = ["cedula", "phone", "email", "address"].filter(f => showField("tutor", f));
                  if (visibleAdmin.length === 0) {
                    return (
                      <div className="mt-1 text-xs text-stone-400 italic flex items-center gap-1.5">
                        <Lock size={10} /> Datos administrativos restringidos
                      </div>
                    );
                  }
                  return (
                    <div className="mt-1 space-y-0.5 text-xs text-stone-600">
                      {showField("tutor", "cedula") && matchedClient.cedula && (
                        <div className="font-mono">{matchedClient.cedula}</div>
                      )}
                      {showField("tutor", "phone") && matchedClient.phone && (
                        <div className="flex items-center gap-1.5">
                          <Phone size={10} className="text-stone-400 flex-shrink-0" />
                          <span className="font-mono">{matchedClient.phone}</span>
                        </div>
                      )}
                      {showField("tutor", "email") && matchedClient.email && (
                        <div className="flex items-center gap-1.5 truncate">
                          <Mail size={10} className="text-stone-400 flex-shrink-0" />
                          <span className="truncate">{matchedClient.email}</span>
                        </div>
                      )}
                      {showField("tutor", "address") && matchedClient.address && (
                        <div className="flex items-center gap-1.5 truncate">
                          <MapPin size={10} className="text-stone-400 flex-shrink-0" />
                          <span className="truncate">{matchedClient.address}</span>
                        </div>
                      )}
                    </div>
                  );
                })() : (
                  <div className="mt-1 text-xs text-stone-400 italic">
                    Datos administrativos pendientes (los completará ventas).
                  </div>
                )}
              </div>
            </div>

            {matchedClient && !onSendMessage && (
              <div className="mt-2 text-xs text-stone-400 italic flex items-center gap-1.5">
                <Lock size={10} /> Chat no disponible en este contexto
              </div>
            )}
          </div>

          {/* Insumos usados */}
          <div className="bg-white border border-stone-200 rounded-xl p-3">
            <div className="flex items-center justify-between mb-2">
              <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold flex items-center gap-1.5">
                <Droplets size={11} /> Insumos usados
              </div>
              <span className="text-xs font-bold text-stone-700 bg-stone-100 px-2 py-0.5 rounded-full">
                {booking.supplies.length}
              </span>
            </div>

            {booking.supplies.length === 0 ? (
              <div className="text-xs text-stone-400 text-center py-3">
                Aún no has agregado insumos.
              </div>
            ) : (
              <div className="space-y-1.5">
                {booking.supplies.map(s => (
                  <div key={s.id} className="flex items-center gap-2 p-2 bg-stone-50 rounded-lg">
                    <div className="w-7 h-7 rounded-lg bg-emerald-100 text-emerald-700 grid place-items-center flex-shrink-0">
                      <Droplets size={11} strokeWidth={1.8} />
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="font-semibold text-xs truncate">{s.name}</div>
                      <div className="text-xs text-stone-500">
                        {s.qty} {s.unit}
                      </div>
                    </div>
                    {status !== "done" && (
                      <button
                        onClick={() => onRemoveSupply(s.id)}
                        className="w-6 h-6 rounded grid place-items-center text-stone-400 hover:text-red-600 hover:bg-red-50 transition flex-shrink-0"
                      >
                        <X size={11} />
                      </button>
                    )}
                  </div>
                ))}
              </div>
            )}

            {status === "active" && (
              <button
                onClick={() => setShowSupplyPicker(true)}
                className="w-full mt-2 flex items-center justify-center gap-1.5 px-3 py-2 rounded-xl bg-emerald-50 hover:bg-emerald-100 border border-emerald-200 text-emerald-700 text-sm font-semibold transition"
              >
                <Plus size={13} /> Agregar insumo
              </button>
            )}
          </div>

          {/* Notas opcionales */}
          {status === "active" && (
            <div className="bg-white border border-stone-200 rounded-xl p-3">
              <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold mb-2">
                Notas del servicio
              </div>
              <textarea
                value={booking.notes}
                onChange={(e) => onUpdateBooking({ notes: e.target.value })}
                placeholder="Observaciones para el tutor o próxima cita..."
                rows={3}
                className="w-full px-3 py-2 bg-stone-50 border border-stone-200 rounded-lg text-sm outline-none focus:border-emerald-500 focus:bg-white resize-none"
              />
            </div>
          )}

          {status === "done" && booking.notes && (
            <div className="bg-emerald-50 border border-emerald-200 rounded-xl p-3">
              <div className="text-xs tracking-widest uppercase text-emerald-700 font-semibold mb-1">Notas</div>
              <div className="text-sm text-stone-700 leading-relaxed">{booking.notes}</div>
            </div>
          )}
        </div>

        {/* Footer con botón de avance */}
        <div className="p-3 border-t border-stone-200 bg-white flex-shrink-0">
          {status !== "done" ? (
            <button
              onClick={handleAdvanceClick}
              className={`w-full flex items-center justify-center gap-2 px-4 py-3.5 rounded-xl text-base font-bold ${colors.button} text-white shadow-lg transition`}
            >
              <advanceLabel.Icon size={17} strokeWidth={2.2} />
              {advanceLabel.label}
            </button>
          ) : (
            <div className="bg-emerald-50 border border-emerald-200 rounded-xl p-3 flex items-center gap-2.5">
              <div className="w-9 h-9 rounded-full bg-emerald-500 text-white grid place-items-center flex-shrink-0">
                <Check size={15} strokeWidth={2.5} />
              </div>
              <div className="flex-1 min-w-0">
                <div className="font-bold text-sm text-emerald-900">Servicio terminado</div>
                <div className="text-xs text-emerald-800 mt-0.5">La mascota está lista para entrega.</div>
              </div>
            </div>
          )}
        </div>
          </div>
          )}
        </div>

        {/* Handle de resize en esquina inferior derecha (oculto en móvil y cuando está maximizado) */}
        <WindowResizeHandle
          size={size}
          setSize={setSize}
          disabled={isMobile || maximized}
        />
      </div>

      {/* Modal selector de insumos */}
      {showSupplyPicker && (
        <SupplyPickerModal
          onClose={() => setShowSupplyPicker(false)}
          onAdd={(supply, qty) => { onAddSupply(supply, qty); setShowSupplyPicker(false); }}
          alreadyAdded={booking.supplies.map(s => s.id)}
          supplies={supplies}
        />
      )}

      {/* Modal de finalización (decide cómo cobrar) */}
      {showFinishModal && (
        <FinishGroomingModal
          booking={booking}
          matchedClient={matchedClient}
          openInvoices={openInvoices}
          setProposals={setProposals}
          setInvoices={setInvoices}
          userRole={userRole}
          userName={userName}
          onClose={() => setShowFinishModal(false)}
          onConfirm={() => { setShowFinishModal(false); onAdvance(); }}
        />
      )}

      {/* Mini-perfil de mascota (info básica, sin datos clínicos) */}
      {showPetInfo && (
        <PetMiniProfileModal
          pet={matchedPassport}
          fallbackBooking={booking}
          matchedClient={matchedClient}
          setPassports={setPassports}
          setInvoices={setInvoices}
          onUpdateBooking={onUpdateBooking}
          onClose={() => setShowPetInfo(false)}
          petUpdates={petUpdates}
          onSubmitUpdate={onSubmitPetUpdate}
          userName={userName}
          userRole={userRole}
        />
      )}

      {/* === Modales de adjuntos del chat === */}
      {showChatImagePicker && (
        <ChatImagePickerModal
          onClose={() => setShowChatImagePicker(false)}
          onSend={handleChatSendImage}
        />
      )}
      {showChatInvoicePicker && matchedClient && canSendInvoice && (
        <ChatInvoicePickerModal
          invoices={invoices}
          activeClientId={matchedClient.id}
          clients={clients}
          onClose={() => setShowChatInvoicePicker(false)}
          onSend={handleChatSendInvoice}
        />
      )}
    </>
  );
}

// ========== MODAL: Mini-perfil de mascota (sin clínica) ==========
// Ventana flotante con info básica visible para el groomer:
// foto/avatar, nombre, código, especie, raza, edad, peso, color, tutor.
// NO muestra historial médico, vacunas, medicaciones ni notas clínicas.
function PetMiniProfileModal({ pet, fallbackBooking, matchedClient, setPassports, setInvoices, onUpdateBooking, onClose, petUpdates = [], onSubmitUpdate, userName, userRole }) {
  // Si no hay pasaporte registrado, usar datos del booking como fallback
  const data = pet || {
    name: fallbackBooking?.pet || "Mascota",
    code: fallbackBooking?.petCode || null,
    species: fallbackBooking?.species || "dog",
    breed: fallbackBooking?.breed || "—",
    age: null, gender: null, color: null, weight: null, sterilized: null,
    tutors: fallbackBooking?.owner ? [{ id: "tmp", name: fallbackBooking.owner, relation: "Tutor" }] : [],
  };

  // Emoji + paleta según especie
  const speciesConfig = {
    dog:    { emoji: "🐕", label: "Perro",   bg: "from-orange-100 to-amber-100", text: "text-orange-800" },
    cat:    { emoji: "🐈", label: "Gato",    bg: "from-purple-100 to-pink-100",  text: "text-purple-800" },
    bird:   { emoji: "🐦", label: "Ave",     bg: "from-sky-100 to-cyan-100",     text: "text-sky-800" },
    rabbit: { emoji: "🐰", label: "Conejo",  bg: "from-emerald-100 to-teal-100", text: "text-emerald-800" },
    other:  { emoji: "🐾", label: "Otro",    bg: "from-stone-100 to-stone-200",  text: "text-stone-800" },
  };
  const sp = speciesConfig[data.species] || speciesConfig.other;

  const primaryTutor = (data.tutors || [])[0];

  // === Sistema de propuestas de edición ===
  // El groomer/vet puede proponer cambios a campos no-sensibles (raza, edad, peso, color).
  // Microchip y tutores quedan reservados al super.
  // El cambio se envía como propuesta a `petUpdates`, el super la aprueba y se aplica.
  // Aquí mostramos:
  // - Botón "Editar" si hay un pasaporte real (no fallback) y el usuario no es invitado
  // - Si ya hay propuesta pendiente para esta mascota: badge informativo
  // - Última modificación aprobada: "Editado por X · hace Y"
  const isRealPet = !!pet?.id;
  const canPropose = isRealPet && !!onSubmitUpdate && (userRole === "grooming" || userRole === "vet" || userRole === "sales" || userRole === "super");
  const isSuper = userRole === "super";

  // Filtrar propuestas para esta mascota
  const myPetUpdates = useMemo(() => {
    if (!isRealPet) return [];
    return petUpdates.filter(u => u.passportId === pet.id);
  }, [petUpdates, pet, isRealPet]);
  const pendingUpdate = myPetUpdates.find(u => u.status === "pending");
  const lastApproved = myPetUpdates
    .filter(u => u.status === "approved")
    .sort((a, b) => (b.approvedAt || "").localeCompare(a.approvedAt || ""))[0];

  // Modo edición
  const [editMode, setEditMode] = useState(false);
  const [draft, setDraft] = useState(null);
  // Modo "crear pasaporte" — disponible solo cuando NO hay pet real (isRealPet === false).
  // El groomer rellena los datos básicos y se persiste un pasaporte nuevo, vinculado
  // al cliente actual (matchedClient) y a la recibo/booking. Esto resuelve el caso
  // de venta express donde Sales no registró la mascota.
  const [createMode, setCreateMode] = useState(false);

  // Especies disponibles para elegir al crear
  const SPECIES_OPTIONS = [
    { id: "dog",    label: "Perro" },
    { id: "cat",    label: "Gato" },
    { id: "bird",   label: "Ave" },
    { id: "rabbit", label: "Conejo" },
    { id: "other",  label: "Otro" },
  ];

  // Permisos: solo se puede crear pasaporte si tenemos setPassports y un cliente vinculado
  const canCreatePassport = !isRealPet && !!setPassports && !!matchedClient && (userRole === "grooming" || userRole === "vet" || userRole === "sales" || userRole === "super");

  const enterCreate = () => {
    setDraft({
      // Si en el header del drawer ya escribieron un nombre, lo prellenamos
      name: data.name && data.name !== "Mascota" ? data.name : (fallbackBooking?.pet || ""),
      species: data.species || "dog",
      breed: data.breed && data.breed !== "—" ? data.breed : "",
      age: "", gender: "", sterilized: false, weight: "", color: "",
    });
    setCreateMode(true);
  };

  const cancelCreate = () => {
    setCreateMode(false);
    setDraft(null);
  };

  // Persistir un pasaporte nuevo. Calcula código único, agrega al cliente vinculado
  // (en su array petCodes) y enlaza al booking (booking.petCode = code) y a la recibo
  // si tenía petCode null. Después cierra el modal.
  const submitCreate = () => {
    if (!draft || !draft.name?.trim() || !setPassports || !matchedClient) return;
    // Generar código único de 6 dígitos
    const code = String(Math.floor(100000 + Math.random() * 900000));
    const newPassport = {
      id: `pet-${Date.now().toString(36)}`,
      code,
      name: draft.name.trim(),
      species: draft.species || "dog",
      speciesOther: draft.speciesOther || "",
      breed: draft.breed.trim() || "—",
      age: draft.age.trim() || null,
      gender: draft.gender || null,
      sterilized: !!draft.sterilized,
      weight: draft.weight.trim() || null,
      color: draft.color.trim() || null,
      microchip: draft.microchip || "",
      birthdate: draft.birthdate || null,
      photo: null,
      // Campos clínicos de la ficha extendida — inicializados vacíos para que
      // FichaClinicaCard pueda editarlos sin tener que crear el campo on-the-fly.
      allergies: "",
      chronicConditions: "",
      diet: "",
      behavior: "",
      notes: "",
      // Vincular al cliente actual como tutor principal
      tutors: [{ id: matchedClient.id, name: matchedClient.name, relation: "Tutor" }],
      // Histórico vacío (recién creado)
      events: [],
      vaccinations: [],
      medications: [],
      visits: [],
      // Trazabilidad
      createdAt: new Date().toISOString(),
      createdBy: userName || userRole || "grooming",
      createdFromBooking: fallbackBooking?.id || null,
    };
    setPassports(prev => [...prev, newPassport]);

    // Enlazar al booking: ahora tiene petCode y los datos se ven en cards
    if (onUpdateBooking) {
      onUpdateBooking({
        pet: newPassport.name,
        petCode: code,
        species: newPassport.species,
        breed: newPassport.breed,
      });
    }

    // Si la recibo asociada tenía petCode null, actualizar también para trazabilidad
    if (setInvoices && fallbackBooking?.invoiceId) {
      setInvoices(prev => prev.map(inv =>
        inv.id === fallbackBooking.invoiceId
          ? { ...inv, fromGroomingBooking: { ...(inv.fromGroomingBooking || {}), petCode: code, pet: newPassport.name } }
          : inv
      ));
    }

    setCreateMode(false);
    setDraft(null);
    onClose?.();
  };

  const enterEdit = () => {
    setDraft({
      name: data.name || "",
      breed: data.breed || "",
      age: data.age || "",
      gender: data.gender || "",
      sterilized: !!data.sterilized,
      weight: data.weight || "",
      color: data.color || "",
    });
    setEditMode(true);
  };
  const cancelEdit = () => {
    setEditMode(false);
    setDraft(null);
  };

  // Comparar draft con data original para detectar cambios
  const changedFields = useMemo(() => {
    if (!draft) return [];
    const fields = [];
    if (draft.name !== (data.name || ""))           fields.push("name");
    if (draft.breed !== (data.breed || ""))         fields.push("breed");
    if (draft.age !== (data.age || ""))             fields.push("age");
    if (draft.gender !== (data.gender || ""))       fields.push("gender");
    if (draft.sterilized !== !!data.sterilized)     fields.push("sterilized");
    if (draft.weight !== (data.weight || ""))       fields.push("weight");
    if (draft.color !== (data.color || ""))         fields.push("color");
    return fields;
  }, [draft, data]);

  const submitProposal = () => {
    if (!draft || changedFields.length === 0 || !onSubmitUpdate) return;
    onSubmitUpdate({
      passportId: pet.id,
      passportCode: pet.code,
      passportName: pet.name,
      proposed: { ...draft },
      changedFields,
      submittedBy: userName || userRole,
    });
    setEditMode(false);
    setDraft(null);
  };

  // Helper para "hace X" en español
  const relativeTime = (iso) => {
    if (!iso) return "";
    const diffMs = Date.now() - new Date(iso).getTime();
    const min = Math.floor(diffMs / 60000);
    if (min < 1) return "ahora mismo";
    if (min < 60) return `hace ${min} min`;
    const hr = Math.floor(min / 60);
    if (hr < 24) return `hace ${hr} h`;
    const days = Math.floor(hr / 24);
    if (days < 7) return `hace ${days} d`;
    const weeks = Math.floor(days / 7);
    if (weeks < 4) return `hace ${weeks} sem`;
    return new Date(iso).toLocaleDateString("es", { day: "numeric", month: "short", year: "numeric" });
  };

  return (
    <div onClick={onClose} className="fixed inset-0 bg-stone-900 z-50 flex justify-center items-center p-4">
      <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl w-full max-w-sm shadow-2xl overflow-hidden max-h-[90vh] flex flex-col">
        {/* Hero con avatar */}
        <div className={`bg-gradient-to-br ${sp.bg} p-5 text-center relative flex-shrink-0`}>
          <button
            onClick={onClose}
            className="absolute top-3 right-3 w-8 h-8 rounded-full bg-white hover:bg-stone-100 shadow grid place-items-center text-stone-600"
          >
            <X size={14} />
          </button>
          <div className="text-xs tracking-widest uppercase text-stone-700 font-bold mb-2">
            {editMode ? "Editar perfil" : "Perfil de mascota"}
          </div>
          <div className="text-7xl leading-none my-1">{sp.emoji}</div>
          <h2 className="font-serif text-2xl font-bold leading-tight mt-2">{data.name}</h2>
          {data.code && (
            <div className="font-mono text-sm font-bold text-orange-700 bg-white inline-block px-2.5 py-0.5 rounded-md mt-1.5 shadow-sm">
              #{data.code}
            </div>
          )}
        </div>

        {/* Contenido scrollable */}
        <div className="flex-1 overflow-y-auto">

        {/* === MODO CREAR PASAPORTE === */}
        {createMode ? (
          <div className="p-5 space-y-3">
            <div className="bg-emerald-50 border border-emerald-200 rounded-lg p-3 flex items-start gap-2 text-xs text-emerald-900">
              <Info size={12} className="flex-shrink-0 mt-0.5 text-emerald-700" />
              <span>
                Crearás un pasaporte nuevo para esta mascota. El tutor <strong>{matchedClient?.name}</strong> ya está asignado por la recibo.
              </span>
            </div>

            <div className="grid grid-cols-2 gap-2.5">
              <div className="col-span-2">
                <label className="text-xs font-semibold text-stone-600 mb-1 block">Nombre <span className="text-red-500">*</span></label>
                <input
                  value={draft.name}
                  onChange={(e) => setDraft({ ...draft, name: e.target.value })}
                  autoFocus
                  placeholder="Ej: Pepe, Luna..."
                  className="w-full px-3 py-2 bg-stone-50 border border-stone-200 rounded-lg text-sm outline-none focus:border-emerald-400 focus:bg-white"
                />
              </div>
              <div>
                <label className="text-xs font-semibold text-stone-600 mb-1 block">Especie</label>
                <select
                  value={draft.species}
                  onChange={(e) => setDraft({ ...draft, species: e.target.value })}
                  className="w-full px-3 py-2 bg-stone-50 border border-stone-200 rounded-lg text-sm outline-none focus:border-emerald-400 focus:bg-white"
                >
                  {SPECIES_OPTIONS.map(o => (
                    <option key={o.id} value={o.id}>{o.label}</option>
                  ))}
                </select>
              </div>
              <div>
                <label className="text-xs font-semibold text-stone-600 mb-1 block">Raza</label>
                <input
                  value={draft.breed}
                  onChange={(e) => setDraft({ ...draft, breed: e.target.value })}
                  placeholder="Ej: Bulldog Inglés"
                  className="w-full px-3 py-2 bg-stone-50 border border-stone-200 rounded-lg text-sm outline-none focus:border-emerald-400 focus:bg-white"
                />
              </div>
              <div>
                <label className="text-xs font-semibold text-stone-600 mb-1 block">Edad</label>
                <input
                  value={draft.age}
                  onChange={(e) => setDraft({ ...draft, age: e.target.value })}
                  placeholder="Ej: 3 años"
                  className="w-full px-3 py-2 bg-stone-50 border border-stone-200 rounded-lg text-sm outline-none focus:border-emerald-400 focus:bg-white"
                />
              </div>
              <div>
                <label className="text-xs font-semibold text-stone-600 mb-1 block">Sexo</label>
                <select
                  value={draft.gender}
                  onChange={(e) => setDraft({ ...draft, gender: e.target.value })}
                  className="w-full px-3 py-2 bg-stone-50 border border-stone-200 rounded-lg text-sm outline-none focus:border-emerald-400 focus:bg-white"
                >
                  <option value="">—</option>
                  <option value="M">Macho</option>
                  <option value="H">Hembra</option>
                </select>
              </div>
              <div>
                <label className="text-xs font-semibold text-stone-600 mb-1 block">Peso</label>
                <input
                  value={draft.weight}
                  onChange={(e) => setDraft({ ...draft, weight: e.target.value })}
                  placeholder="Ej: 6.8 kg"
                  className="w-full px-3 py-2 bg-stone-50 border border-stone-200 rounded-lg text-sm outline-none focus:border-emerald-400 focus:bg-white"
                />
              </div>
              <div className="col-span-2">
                <label className="text-xs font-semibold text-stone-600 mb-1 block">Color</label>
                <input
                  value={draft.color}
                  onChange={(e) => setDraft({ ...draft, color: e.target.value })}
                  placeholder="Ej: Atigrado, blanco con manchas..."
                  className="w-full px-3 py-2 bg-stone-50 border border-stone-200 rounded-lg text-sm outline-none focus:border-emerald-400 focus:bg-white"
                />
              </div>
              <div className="col-span-2 flex items-center gap-2 mt-1">
                <input
                  type="checkbox"
                  id="sterilized-create"
                  checked={draft.sterilized}
                  onChange={(e) => setDraft({ ...draft, sterilized: e.target.checked })}
                  className="w-4 h-4 accent-emerald-600"
                />
                <label htmlFor="sterilized-create" className="text-xs font-semibold text-stone-700 cursor-pointer">
                  Esterilizado/a
                </label>
              </div>
            </div>

            <div className="text-xs text-stone-500 leading-relaxed pt-2 border-t border-stone-100">
              Solo el nombre es obligatorio. El resto de los campos puedes completarlos ahora o después desde el pasaporte.
            </div>
          </div>
        ) :

        /* === MODO EDIT === */
        editMode ? (
          <div className="p-5 space-y-3">
            {/* Aviso de aprobación */}
            <div className={`text-xs p-2.5 rounded-lg flex items-start gap-2 ${
              isSuper ? "bg-emerald-50 text-emerald-900 border border-emerald-200"
                      : "bg-amber-50 text-amber-900 border border-amber-200"
            }`}>
              <Info size={11} className="flex-shrink-0 mt-0.5" />
              <span>
                {isSuper
                  ? "Como super usuario tus cambios se aplicarán al instante."
                  : "Tu edición se enviará a aprobación del super usuario antes de aplicarse al pasaporte."}
              </span>
            </div>

            {/* Form */}
            <div className="grid grid-cols-2 gap-2.5">
              <div className="col-span-2">
                <label className="text-xs font-semibold text-stone-600 mb-1 block">Nombre</label>
                <input value={draft.name} onChange={(e) => setDraft({ ...draft, name: e.target.value })}
                  className="w-full px-3 py-2 bg-stone-50 border border-stone-200 rounded-lg text-sm outline-none focus:border-orange-400 focus:bg-white" />
              </div>
              <div>
                <label className="text-xs font-semibold text-stone-600 mb-1 block">Raza</label>
                <input value={draft.breed} onChange={(e) => setDraft({ ...draft, breed: e.target.value })}
                  className="w-full px-3 py-2 bg-stone-50 border border-stone-200 rounded-lg text-sm outline-none focus:border-orange-400 focus:bg-white" />
              </div>
              <div>
                <label className="text-xs font-semibold text-stone-600 mb-1 block">Edad</label>
                <input value={draft.age} onChange={(e) => setDraft({ ...draft, age: e.target.value })}
                  placeholder="Ej: 3 años"
                  className="w-full px-3 py-2 bg-stone-50 border border-stone-200 rounded-lg text-sm outline-none focus:border-orange-400 focus:bg-white" />
              </div>
              <div>
                <label className="text-xs font-semibold text-stone-600 mb-1 block">Sexo</label>
                <select value={draft.gender} onChange={(e) => setDraft({ ...draft, gender: e.target.value })}
                  className="w-full px-3 py-2 bg-stone-50 border border-stone-200 rounded-lg text-sm outline-none focus:border-orange-400 focus:bg-white">
                  <option value="">—</option>
                  <option value="M">Macho</option>
                  <option value="H">Hembra</option>
                </select>
              </div>
              <div>
                <label className="text-xs font-semibold text-stone-600 mb-1 block">Peso</label>
                <input value={draft.weight} onChange={(e) => setDraft({ ...draft, weight: e.target.value })}
                  placeholder="Ej: 6.8 kg"
                  className="w-full px-3 py-2 bg-stone-50 border border-stone-200 rounded-lg text-sm outline-none focus:border-orange-400 focus:bg-white" />
              </div>
              <div className="col-span-2">
                <label className="text-xs font-semibold text-stone-600 mb-1 block">Color</label>
                <input value={draft.color} onChange={(e) => setDraft({ ...draft, color: e.target.value })}
                  className="w-full px-3 py-2 bg-stone-50 border border-stone-200 rounded-lg text-sm outline-none focus:border-orange-400 focus:bg-white" />
              </div>
              <div className="col-span-2 flex items-center gap-2 mt-1">
                <input type="checkbox" id="sterilized-mini" checked={draft.sterilized}
                  onChange={(e) => setDraft({ ...draft, sterilized: e.target.checked })}
                  className="w-4 h-4 accent-orange-600" />
                <label htmlFor="sterilized-mini" className="text-xs font-semibold text-stone-700 cursor-pointer">
                  Esterilizado/a
                </label>
              </div>
            </div>

            {/* Resumen cambios */}
            {changedFields.length > 0 && (
              <div className="text-xs text-stone-600 bg-stone-50 rounded-lg p-2 border border-stone-200">
                <strong>{changedFields.length}</strong> campo{changedFields.length === 1 ? "" : "s"} modificado{changedFields.length === 1 ? "" : "s"}.
              </div>
            )}
          </div>
        ) : (
          // === MODO VISTA ===
          <div className="p-5 space-y-3">
            {/* Aviso si hay propuesta pendiente */}
            {pendingUpdate && (
              <div className="text-xs p-2.5 rounded-lg bg-amber-50 text-amber-900 border border-amber-200 flex items-start gap-2">
                <Clock size={11} className="flex-shrink-0 mt-0.5" />
                <div className="flex-1">
                  <div className="font-semibold">Edición pendiente de aprobación</div>
                  <div className="text-xs mt-0.5 leading-snug">
                    Enviada por <strong>{pendingUpdate.submittedBy}</strong> · {relativeTime(pendingUpdate.submittedAt)}.
                    {" "}{(pendingUpdate.changedFields || []).length} campo{(pendingUpdate.changedFields || []).length === 1 ? "" : "s"}.
                  </div>
                </div>
              </div>
            )}

            <div className="grid grid-cols-2 gap-3 text-sm">
              <div>
                <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold mb-0.5">Especie</div>
                <div className="font-semibold">{sp.label}</div>
              </div>
              <div>
                <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold mb-0.5">Raza</div>
                <div className="font-semibold truncate">{data.breed || "—"}</div>
              </div>
              {data.age && (
                <div>
                  <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold mb-0.5">Edad</div>
                  <div className="font-semibold">{data.age}</div>
                </div>
              )}
              {data.gender && (
                <div>
                  <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold mb-0.5">Sexo</div>
                  <div className="font-semibold">
                    {data.gender === "M" ? "Macho" : data.gender === "F" || data.gender === "H" ? "Hembra" : data.gender}
                    {data.sterilized && <span className="text-xs text-stone-500 ml-1">· Esterilizado</span>}
                  </div>
                </div>
              )}
              {data.weight && (
                <div>
                  <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold mb-0.5">Peso</div>
                  <div className="font-semibold">{data.weight}</div>
                </div>
              )}
              {data.color && (
                <div>
                  <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold mb-0.5">Color</div>
                  <div className="font-semibold truncate">{data.color}</div>
                </div>
              )}
            </div>

            {/* Tutor (sin profundizar — no se ve historial clínico) */}
            {primaryTutor && (
              <div className="pt-3 border-t border-stone-200">
                <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold mb-1.5">
                  Tutor principal
                </div>
                <div className="flex items-center gap-2">
                  <div className="w-8 h-8 rounded-full bg-orange-500 text-white text-xs font-bold grid place-items-center flex-shrink-0">
                    {primaryTutor.name.split(" ").slice(0, 2).map(s => s[0]).join("").toUpperCase()}
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="font-semibold text-sm truncate">{primaryTutor.name}</div>
                    {primaryTutor.relation && (
                      <div className="text-xs text-stone-500">{primaryTutor.relation}</div>
                    )}
                  </div>
                </div>
              </div>
            )}

            {/* Historial: última modificación aprobada */}
            {lastApproved && (
              <div className="pt-3 border-t border-stone-200">
                <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold mb-1.5">
                  Última modificación
                </div>
                <div className="text-xs text-stone-600 leading-relaxed bg-stone-50 rounded-lg p-2 border border-stone-200">
                  Editado por <strong className="text-stone-800">{lastApproved.submittedBy}</strong>
                  {lastApproved.approvedBy && lastApproved.approvedBy !== lastApproved.submittedBy && (
                    <> · aprobado por <strong className="text-stone-800">{lastApproved.approvedBy}</strong></>
                  )}
                  {" "}· {relativeTime(lastApproved.approvedAt || lastApproved.submittedAt)}
                  {(lastApproved.changedFields || []).length > 0 && (
                    <div className="mt-1 text-xs text-stone-500">
                      Campos: {(lastApproved.changedFields || []).join(", ")}
                    </div>
                  )}
                </div>
              </div>
            )}

            {!pet && (
              <div className="pt-3 border-t border-stone-200 bg-amber-50 -mx-5 -mb-5 px-5 py-3 text-xs text-amber-900 flex items-start gap-2">
                <Info size={12} className="text-amber-700 flex-shrink-0 mt-0.5" />
                <span>
                  Esta mascota aún no tiene pasaporte registrado en la biblioteca.
                  {canCreatePassport && <> Usa el botón <strong>Crear pasaporte</strong> abajo para registrarla con el tutor ya vinculado.</>}
                </span>
              </div>
            )}
          </div>
        )}

        </div>

        {/* Footer con acciones */}
        <div className="px-5 py-3 border-t border-stone-200 bg-stone-50 flex items-center gap-2 flex-shrink-0">
          {createMode ? (
            <>
              <button
                onClick={cancelCreate}
                className="flex-1 px-3 py-2 rounded-lg border border-stone-200 hover:bg-white text-stone-700 text-xs font-semibold transition"
              >
                Cancelar
              </button>
              <button
                onClick={submitCreate}
                disabled={!draft?.name?.trim()}
                className={`flex-[2] px-3 py-2 rounded-lg text-xs font-semibold transition flex items-center justify-center gap-1.5 ${
                  draft?.name?.trim()
                    ? "bg-emerald-600 hover:bg-emerald-700 text-white shadow"
                    : "bg-stone-200 text-stone-400 cursor-not-allowed"
                }`}
              >
                <Check size={11} strokeWidth={2.4} /> Crear pasaporte
              </button>
            </>
          ) : editMode ? (
            <>
              <button
                onClick={cancelEdit}
                className="flex-1 px-3 py-2 rounded-lg border border-stone-200 hover:bg-white text-stone-700 text-xs font-semibold transition"
              >
                Cancelar
              </button>
              <button
                onClick={submitProposal}
                disabled={changedFields.length === 0}
                className={`flex-1 px-3 py-2 rounded-lg text-xs font-semibold transition flex items-center justify-center gap-1.5 ${
                  changedFields.length > 0
                    ? (isSuper ? "bg-emerald-600 hover:bg-emerald-700 text-white shadow" : "bg-orange-600 hover:bg-orange-700 text-white shadow")
                    : "bg-stone-200 text-stone-400 cursor-not-allowed"
                }`}
              >
                {isSuper
                  ? <><Check size={11} strokeWidth={2.4} /> Guardar cambios</>
                  : <><Send size={11} strokeWidth={2.4} /> Enviar a aprobación</>
                }
              </button>
            </>
          ) : (
            <>
              <div className="flex-1 text-xs text-stone-500 flex items-center gap-1.5 min-w-0">
                <Info size={11} className="flex-shrink-0" />
                <span className="truncate">
                  {isRealPet ? "Solo información básica." : "Sin pasaporte registrado."}
                </span>
              </div>
              {/* Botón "Crear pasaporte" cuando no hay pasaporte real y tenemos cliente vinculado */}
              {canCreatePassport && (
                <button
                  onClick={enterCreate}
                  className="px-3 py-1.5 rounded-lg bg-emerald-600 hover:bg-emerald-700 text-white text-xs font-semibold transition flex items-center gap-1.5 shadow-sm"
                >
                  <Plus size={11} strokeWidth={2.4} /> Crear pasaporte
                </button>
              )}
              {canPropose && !pendingUpdate && (
                <button
                  onClick={enterEdit}
                  className="px-3 py-1.5 rounded-lg bg-white border border-stone-200 hover:border-orange-400 hover:text-orange-700 text-stone-700 text-xs font-semibold transition flex items-center gap-1.5"
                >
                  <Edit3 size={11} strokeWidth={2.2} /> Editar
                </button>
              )}
              {canPropose && pendingUpdate && (
                <button
                  disabled
                  title="Hay una propuesta pendiente. Espera la aprobación o ve a Clientes › Actualizar pasaporte."
                  className="px-3 py-1.5 rounded-lg bg-stone-100 border border-stone-200 text-stone-400 text-xs font-semibold cursor-not-allowed flex items-center gap-1.5"
                >
                  <Clock size={11} strokeWidth={2.2} /> En revisión
                </button>
              )}
            </>
          )}
        </div>
      </div>
    </div>
  );
}

// === Modal selector de insumos (catálogo sin precios para grooming) ===
function SupplyPickerModal({ onClose, onAdd, alreadyAdded = [], supplies = GROOMING_SUPPLIES }) {
  const [search, setSearch] = useState("");
  const [selected, setSelected] = useState(null);
  const [qty, setQty] = useState("");

  // Solo insumos activos
  const activeSupplies = useMemo(() => supplies.filter(s => s.active !== false), [supplies]);

  const filtered = useMemo(() => {
    if (!search.trim()) return activeSupplies;
    const q = search.toLowerCase();
    return activeSupplies.filter(s =>
      s.name.toLowerCase().includes(q) ||
      s.category.toLowerCase().includes(q)
    );
  }, [search, activeSupplies]);

  const handleSelect = (supply) => {
    setSelected(supply);
    setQty(String(supply.defaultQty));
  };

  const handleAdd = () => {
    if (!selected) return;
    const numQty = Number(qty) || 0;
    if (numQty <= 0) return;
    onAdd({ id: selected.id, name: selected.name, unit: selected.unit }, numQty);
  };

  return (
    <div onClick={onClose} className="fixed inset-0 bg-stone-900 z-50 flex justify-center items-start p-4 overflow-y-auto">
      <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl w-full max-w-md shadow-2xl my-8 overflow-hidden flex flex-col max-h-screen">
        <div className="p-4 border-b border-stone-200 flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-emerald-100 text-emerald-700 grid place-items-center flex-shrink-0">
            <Droplets size={17} strokeWidth={1.8} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase text-emerald-700 font-semibold">
              Catálogo
            </div>
            <h3 className="font-serif text-lg font-semibold mt-0.5">Agregar insumo</h3>
          </div>
          <button onClick={onClose} className="w-9 h-9 rounded-full bg-stone-100 hover:bg-stone-200 grid place-items-center text-stone-600">
            <X size={15} />
          </button>
        </div>

        {selected ? (
          /* Vista detalle: confirmar cantidad */
          <div className="p-5 space-y-4">
            <div className="bg-emerald-50 border border-emerald-200 rounded-xl p-4">
              <div className="text-xs tracking-widest uppercase text-emerald-700 font-semibold">
                {selected.category}
              </div>
              <div className="font-serif text-xl font-semibold mt-0.5">{selected.name}</div>
            </div>

            <div>
              <label className="text-xs font-semibold text-stone-700 block mb-2">
                Cantidad usada ({selected.unit})
              </label>
              <div className="flex items-center gap-2">
                <button
                  onClick={() => setQty(String(Math.max(0, Number(qty) - (selected.unit === "ml" || selected.unit === "gr" ? 5 : 1))))}
                  className="w-12 h-12 rounded-xl bg-stone-100 hover:bg-stone-200 grid place-items-center text-stone-700 font-bold text-lg transition"
                >
                  −
                </button>
                <input
                  type="number"
                  value={qty}
                  onChange={(e) => setQty(e.target.value)}
                  min="0"
                  step="any"
                  className="flex-1 px-3 py-3 bg-white border-2 border-stone-200 rounded-xl text-center text-2xl font-bold font-mono outline-none focus:border-emerald-500"
                />
                <button
                  onClick={() => setQty(String(Number(qty) + (selected.unit === "ml" || selected.unit === "gr" ? 5 : 1)))}
                  className="w-12 h-12 rounded-xl bg-stone-100 hover:bg-stone-200 grid place-items-center text-stone-700 font-bold text-lg transition"
                >
                  +
                </button>
              </div>
              <div className="text-xs text-stone-500 text-center mt-1">
                {selected.unit}
              </div>
            </div>

            <div className="flex gap-2">
              <button
                onClick={() => setSelected(null)}
                className="flex-1 px-3 py-3 rounded-xl text-sm font-semibold bg-white border border-stone-200 hover:border-stone-400 text-stone-700"
              >
                <ChevronLeft size={13} className="inline" /> Atrás
              </button>
              <button
                onClick={handleAdd}
                disabled={!(Number(qty) > 0)}
                className={`flex-1 px-3 py-3 rounded-xl text-sm font-semibold transition shadow ${
                  Number(qty) > 0
                    ? "bg-emerald-500 hover:bg-emerald-600 text-white"
                    : "bg-stone-200 text-stone-400 cursor-not-allowed"
                }`}
              >
                <Check size={13} className="inline" strokeWidth={2.5} /> Agregar
              </button>
            </div>
          </div>
        ) : (
          /* Vista lista de insumos */
          <>
            <div className="p-3 border-b border-stone-200">
              <div className="relative">
                <Search size={14} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-stone-400" />
                <input
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                  placeholder="Buscar insumo..."
                  autoFocus
                  className="w-full pl-10 pr-3 py-2 bg-stone-50 border border-stone-200 rounded-xl text-sm outline-none focus:border-emerald-500 focus:bg-white"
                />
              </div>
            </div>
            <div className="flex-1 overflow-y-auto divide-y divide-stone-100">
              {filtered.length === 0 ? (
                <div className="p-8 text-center text-sm text-stone-500">Sin resultados.</div>
              ) : (
                filtered.map(s => {
                  const already = alreadyAdded.includes(s.id);
                  return (
                    <button
                      key={s.id}
                      onClick={() => handleSelect(s)}
                      className="w-full p-3 hover:bg-emerald-50 transition text-left flex items-center gap-3"
                    >
                      <div className="w-9 h-9 rounded-lg bg-emerald-50 text-emerald-700 grid place-items-center flex-shrink-0 border border-emerald-200">
                        <Droplets size={14} strokeWidth={1.8} />
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="font-semibold text-sm truncate flex items-center gap-1.5">
                          {s.name}
                          {already && <Check size={11} className="text-emerald-600" strokeWidth={2.5} />}
                        </div>
                        <div className="text-xs text-stone-500">
                          {s.category} · sugerido: {s.defaultQty} {s.unit}
                        </div>
                      </div>
                      <ChevronRight size={13} className="text-stone-400" />
                    </button>
                  );
                })
              )}
            </div>
          </>
        )}
      </div>
    </div>
  );
}

// === Modal de finalización: decidir cómo se recibo ===
function FinishGroomingModal({
  booking, matchedClient, openInvoices, setProposals, setInvoices, userRole, userName,
  onClose, onConfirm
}) {
  // Caso especial: si NO hay insumos, el flujo es muy simple. El groomer no decide
  // cómo cobrar — solo notifica a Ventas que terminó. Si el cliente ya pagó al
  // reservar, no hay cargos nuevos; si no, Ventas hace el cobro.
  const hasSupplies = (booking.supplies || []).length > 0;

  // Sin insumos: el choice queda fijado a "notify-completion" automáticamente.
  // Con insumos: el groomer elige entre las dos opciones de recibos.
  const [choice, setChoice] = useState(hasSupplies ? null : "notify-completion");
  const [targetInvoiceId, setTargetInvoiceId] = useState(openInvoices[0]?.id || null);

  const sourceModule = "grooming"; // este modal se usa solo desde grooming

  const handleConfirm = () => {
    if (!setProposals) {
      onConfirm();
      return;
    }

    // === RAMA notify-completion: solo notifica el cierre, sin items ===
    // Ventas la recibe como una propuesta liviana. Si el cliente ya pagó al reservar,
    // se archiva sin cambios. Si no, Ventas crea recibo y cobra.
    if (choice === "notify-completion") {
      const proposal = {
        id: `prop-${Date.now().toString(36)}`,
        sourceModule,
        createdAt: new Date().toISOString(),
        createdBy: userRole === "grooming" ? "Groomer" : userRole === "vet" ? "Veterinario" : "Operador",
        pet: { name: booking.pet, code: booking.petCode, breed: booking.breed, species: booking.species },
        service: booking.service,
        bookingId: booking.id,
        suggestedClientId: matchedClient?.id || null,
        suggestedClientName: matchedClient?.name || booking.owner,
        items: [], // sin insumos, solo el aviso del cierre
        target: "notify-completion",
        targetInvoiceId: null,
        notes: booking.notes || null,
        status: "pending",
      };
      setProposals(prev => [proposal, ...prev]);
      onConfirm();
      return;
    }

    // Crear propuesta para que Ventas la apruebe (con insumos)
    const proposal = {
      id: `prop-${Date.now().toString(36)}`,
      sourceModule,
      createdAt: new Date().toISOString(),
      createdBy: userRole === "grooming" ? "Groomer" : userRole === "vet" ? "Veterinario" : "Operador",
      pet: { name: booking.pet, code: booking.petCode, breed: booking.breed, species: booking.species },
      service: booking.service,
      bookingId: booking.id,
      // Cliente sugerido (si se identificó por owner) — Ventas lo confirma
      suggestedClientId: matchedClient?.id || null,
      suggestedClientName: matchedClient?.name || booking.owner,
      // Items propuestos: servicio + insumos
      items: [
        ...(booking.supplies || []).map(s => ({
          type: "supply",
          sourceId: s.id,
          name: s.name,
          qty: s.qty,
          unit: s.unit,
        })),
      ],
      // Modalidad propuesta
      target: choice, // 'add-to-invoice' | 'new-invoice'
      targetInvoiceId: choice === "add-to-invoice" ? targetInvoiceId : null,
      notes: booking.notes || null,
      status: "pending",
    };

    setProposals(prev => [proposal, ...prev]);
    onConfirm();
  };

  return (
    <div onClick={onClose} className="fixed inset-0 bg-stone-900 z-50 flex justify-center items-center p-4 overflow-y-auto">
      <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl w-full max-w-md shadow-2xl my-8 overflow-hidden">
        <div className="p-4 border-b border-stone-200 bg-gradient-to-br from-emerald-50 to-white flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-emerald-500 text-white grid place-items-center shadow-lg flex-shrink-0">
            <BadgeCheck size={17} strokeWidth={2} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase text-emerald-700 font-semibold">
              Finalizar servicio
            </div>
            <h3 className="font-serif text-lg font-semibold mt-0.5 truncate">
              {booking.pet} · {booking.service}
            </h3>
          </div>
          <button onClick={onClose} className="w-9 h-9 rounded-full bg-white border border-stone-200 grid place-items-center text-stone-600 flex-shrink-0">
            <X size={15} />
          </button>
        </div>

        <div className="p-5 space-y-3">
          <div className="bg-blue-50 border border-blue-200 rounded-xl p-3 flex items-start gap-2.5 text-xs text-blue-900 leading-relaxed">
            <Info size={13} className="text-blue-700 flex-shrink-0 mt-0.5" />
            <div>
              {hasSupplies ? (
                <>Esta solicitud se enviará al equipo de <strong>Ventas</strong> para revisión y recibos. Tú no manejas precios.</>
              ) : (
                <>El servicio se marcará como <strong>terminado</strong>. Ventas recibirá el aviso: si el cliente ya pagó al reservar, no hay cargos nuevos; si no, Ventas se encarga del cobro.</>
              )}
            </div>
          </div>

          {/* Solo mostramos la pregunta y las dos opciones cuando hay insumos */}
          {hasSupplies && (
            <div className="text-sm text-stone-600 leading-relaxed">
              ¿Cómo debería registrarse este servicio?
            </div>
          )}

          {/* Opción 1: Agregar a recibo existente — solo cuando hay insumos */}
          {hasSupplies && openInvoices.length > 0 && (
            <button
              onClick={() => setChoice("add-to-invoice")}
              className={`w-full p-3 rounded-xl border-2 text-left transition ${
                choice === "add-to-invoice"
                  ? "bg-blue-50 border-blue-400"
                  : "bg-white border-stone-200 hover:border-stone-400"
              }`}
            >
              <div className="flex items-start gap-3">
                <div className={`w-9 h-9 rounded-lg grid place-items-center flex-shrink-0 ${
                  choice === "add-to-invoice" ? "bg-blue-100 text-blue-700" : "bg-stone-100 text-stone-500"
                }`}>
                  <Receipt size={15} />
                </div>
                <div className="flex-1 min-w-0">
                  <div className="font-semibold text-sm">Sumar a recibo existente</div>
                  <div className="text-xs text-stone-500 mt-0.5">
                    El cliente tiene {openInvoices.length} recibo{openInvoices.length === 1 ? "" : "s"} abierta{openInvoices.length === 1 ? "" : "s"}.
                  </div>
                  {choice === "add-to-invoice" && openInvoices.length > 1 && (
                    <select
                      value={targetInvoiceId || ""}
                      onChange={(e) => setTargetInvoiceId(e.target.value)}
                      onClick={(e) => e.stopPropagation()}
                      className="mt-2 w-full px-2 py-1.5 bg-white border border-blue-300 rounded-lg text-xs font-mono outline-none focus:border-blue-500"
                    >
                      {openInvoices.map(inv => (
                        <option key={inv.id} value={inv.id}>
                          {inv.number} · {inv.state}
                        </option>
                      ))}
                    </select>
                  )}
                  {choice === "add-to-invoice" && openInvoices.length === 1 && (
                    <div className="mt-2 text-xs font-mono font-bold text-blue-700">
                      Recibo {openInvoices[0].number}
                    </div>
                  )}
                </div>
              </div>
            </button>
          )}

          {/* Opción 2: Crear recibo nueva — solo cuando hay insumos */}
          {hasSupplies && (
          <button
            onClick={() => setChoice("new-invoice")}
            className={`w-full p-3 rounded-xl border-2 text-left transition ${
              choice === "new-invoice"
                ? "bg-emerald-50 border-emerald-400"
                : "bg-white border-stone-200 hover:border-stone-400"
            }`}
          >
            <div className="flex items-start gap-3">
              <div className={`w-9 h-9 rounded-lg grid place-items-center flex-shrink-0 ${
                choice === "new-invoice" ? "bg-emerald-100 text-emerald-700" : "bg-stone-100 text-stone-500"
              }`}>
                <Plus size={15} />
              </div>
              <div className="flex-1 min-w-0">
                <div className="font-semibold text-sm">Solicitar recibo nueva</div>
                <div className="text-xs text-stone-500 mt-0.5">
                  Para el tutor de {booking.pet}, con servicio + insumos.
                </div>
                {!matchedClient && choice === "new-invoice" && (
                  <div className="mt-2 text-xs text-amber-800 bg-amber-50 border border-amber-200 rounded p-2 leading-relaxed">
                    <Info size={11} className="inline mr-1" />
                    No identificamos al cliente automáticamente. Ventas lo confirmará al aprobar la propuesta.
                  </div>
                )}
              </div>
            </div>
          </button>
          )}

          {/* Caso sin insumos: una sola tarjeta resumen visual.
              No es seleccionable porque ya hay un único camino: concluir y notificar. */}
          {!hasSupplies && (
            <div className="w-full p-4 rounded-xl border-2 border-emerald-300 bg-emerald-50">
              <div className="flex items-start gap-3">
                <div className="w-10 h-10 rounded-lg bg-emerald-100 text-emerald-700 grid place-items-center flex-shrink-0">
                  <BadgeCheck size={17} strokeWidth={2} />
                </div>
                <div className="flex-1 min-w-0">
                  <div className="font-semibold text-sm">Concluir servicio</div>
                  <div className="text-xs text-stone-600 mt-0.5 leading-snug">
                    Sin insumos extra. Ventas verá una notificación de cierre del servicio para gestionar el cobro pendiente si lo hay.
                  </div>
                  {!matchedClient && (
                    <div className="mt-2 text-xs text-amber-800 bg-amber-50 border border-amber-200 rounded p-2 leading-relaxed">
                      <Info size={11} className="inline mr-1" />
                      No identificamos al cliente automáticamente. Ventas lo confirmará al recibir el aviso.
                    </div>
                  )}
                </div>
              </div>
            </div>
          )}

          {/* Resumen de insumos */}
          {booking.supplies.length > 0 && choice && (
            <div className="bg-stone-50 border border-stone-200 rounded-xl p-3">
              <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold mb-2">
                Insumos a registrar
              </div>
              <div className="space-y-1 text-xs">
                {booking.supplies.map(s => (
                  <div key={s.id} className="flex justify-between text-stone-700">
                    <span className="truncate">{s.name}</span>
                    <span className="font-mono flex-shrink-0">{s.qty} {s.unit}</span>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>

        <div className="p-3 border-t border-stone-200 bg-stone-50 flex gap-2">
          <button
            onClick={onClose}
            className="flex-1 px-3 py-2.5 rounded-xl text-sm font-semibold bg-white border border-stone-200 hover:border-stone-400 text-stone-700"
          >
            Cancelar
          </button>
          <button
            onClick={handleConfirm}
            disabled={!choice || (choice === "add-to-invoice" && !targetInvoiceId)}
            className={`flex-1 px-3 py-2.5 rounded-xl text-sm font-semibold transition shadow ${
              choice && (choice !== "add-to-invoice" || targetInvoiceId)
                ? "bg-emerald-500 hover:bg-emerald-600 text-white"
                : "bg-stone-200 text-stone-400 cursor-not-allowed"
            }`}
          >
            <Check size={13} className="inline" strokeWidth={2.5} /> {choice === "notify-completion" ? "Concluir servicio" : "Enviar a Ventas"}
          </button>
        </div>
      </div>
    </div>
  );
}

// ========== MODAL: PROPUESTAS DE RECIBOS (revisión por Ventas) ==========

function ProposalsReviewModal({ proposals, setProposals, clients, invoices, setInvoices, services = INITIAL_SERVICES, onClose }) {
  const [activeProposalId, setActiveProposalId] = useState(null);
  const pending = proposals.filter(p => p.status === "pending");
  const recent = proposals.filter(p => p.status !== "pending").slice(0, 5);

  const activeProposal = proposals.find(p => p.id === activeProposalId);

  // Aprobar: convierte la propuesta en recibo (nueva o agregando a existente)
  const approveProposal = (proposal, decision) => {
    // decision: { action: 'add-to-invoice'|'new-invoice', targetInvoiceId, clientId }
    const supplyItems = (proposal.items || []).map(it => {
      const def = GROOMING_SUPPLIES.find(g => g.id === it.sourceId);
      const unitPrice = def ? def.price / def.defaultQty : 0;
      return {
        description: `${it.name} (${it.qty} ${it.unit})`,
        qty: 1,
        unit: Math.round(unitPrice * it.qty),
        total: Math.round(unitPrice * it.qty),
      };
    });

    if (decision.action === "add-to-invoice" && decision.targetInvoiceId) {
      setInvoices(prev => prev.map(inv => {
        if (inv.id !== decision.targetInvoiceId) return inv;
        const newItems = [...inv.items, ...supplyItems];
        const newSubtotal = newItems.reduce((a, it) => a + it.total, 0);
        const newTax = Math.round(newSubtotal * 0.16);
        const newTotal = newSubtotal + newTax;
        return {
          ...inv,
          items: newItems,
          subtotal: newSubtotal,
          tax: newTax,
          total: newTotal,
          balance: newTotal - inv.paid,
          // Marca distintiva: recibo modificada por propuesta aprobada
          modifiedByProposal: {
            proposalId: proposal.id,
            sourceModule: proposal.sourceModule,
            addedAt: new Date().toISOString(),
            addedAmount: supplyItems.reduce((a, it) => a + it.total, 0),
          },
        };
      }));
    } else if (decision.action === "new-invoice" && decision.clientId) {
      const lastNum = invoices.length === 0 ? 100
        : Math.max(...invoices.map(i => parseInt(i.number.split("-")[1] || "100")));
      const newNumber = `00-${String(lastNum + 1).padStart(7, "0")}`;
      const today = new Date();
      const dueDate = new Date(today);
      dueDate.setDate(today.getDate() + 30);
      const fmt = (d) => d.toISOString().slice(0, 10);

      // Buscar precio del servicio en el catálogo en vez de hardcodear $25.
      const svcDef = (services || []).find(s =>
        (s.name || "").toLowerCase().trim() === (proposal.service || "").toLowerCase().trim()
      );
      const servicePrice = svcDef?.price ?? 25; // fallback a $25 si no se encuentra
      const serviceItems = [{
        description: `${proposal.service} (${proposal.pet.name})`,
        qty: 1,
        unit: servicePrice,
        total: servicePrice,
      }];
      const allItems = [...serviceItems, ...supplyItems];
      const subtotal = allItems.reduce((a, it) => a + it.total, 0);
      const tax = Math.round(subtotal * 0.16);
      const total = subtotal + tax;

      setInvoices(prev => [{
        id: `inv-${Date.now().toString(36)}`,
        number: newNumber,
        clientId: decision.clientId,
        issueDate: fmt(today),
        dueDate: fmt(dueDate),
        state: "borrador",
        items: allItems,
        subtotal,
        tax,
        total,
        paid: 0,
        balance: total,
        payments: [],
        paymentMode: "deferred",
        createdBy: `Aprobado de ${proposal.sourceModule}`,
        fromProposal: proposal.id,
      }, ...prev]);
    }

    setProposals(prev => prev.map(p =>
      p.id === proposal.id ? { ...p, status: "approved", approvedAt: new Date().toISOString() } : p
    ));
    setActiveProposalId(null);
  };

  const rejectProposal = (proposal) => {
    setProposals(prev => prev.map(p =>
      p.id === proposal.id ? { ...p, status: "rejected", rejectedAt: new Date().toISOString() } : p
    ));
    setActiveProposalId(null);
  };

  return (
    <div onClick={onClose} className="fixed inset-0 bg-stone-900 z-50 flex justify-center items-start p-4 overflow-y-auto">
      <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl w-full max-w-3xl shadow-2xl my-8 overflow-hidden flex flex-col max-h-screen">
        {/* Header */}
        <div className="p-4 border-b border-stone-200 bg-gradient-to-br from-orange-50 to-white flex items-center gap-3 flex-shrink-0">
          <div className="w-10 h-10 rounded-xl bg-orange-500 text-white grid place-items-center shadow-lg flex-shrink-0">
            <Bell size={17} strokeWidth={2} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold">
              Bandeja de revisión
            </div>
            <h3 className="font-serif text-xl font-semibold mt-0.5">
              Propuestas de recibos
            </h3>
            <div className="text-xs text-stone-500 mt-0.5">
              {pending.length} pendiente{pending.length === 1 ? "" : "s"} de aprobación
            </div>
          </div>
          <button onClick={onClose} className="w-9 h-9 rounded-full bg-stone-100 hover:bg-stone-200 grid place-items-center text-stone-600 flex-shrink-0">
            <X size={15} />
          </button>
        </div>

        {/* Body */}
        <div className="flex-1 overflow-y-auto p-4 space-y-4">
          {activeProposal ? (
            <ProposalDetailReview
              proposal={activeProposal}
              clients={clients}
              invoices={invoices}
              onBack={() => setActiveProposalId(null)}
              onApprove={(decision) => approveProposal(activeProposal, decision)}
              onReject={() => rejectProposal(activeProposal)}
            />
          ) : (
            <>
              {pending.length === 0 ? (
                <div className="text-center py-12">
                  <div className="w-14 h-14 rounded-full bg-stone-100 grid place-items-center mx-auto mb-3 text-stone-400">
                    <Bell size={22} />
                  </div>
                  <div className="font-semibold text-stone-700">Sin propuestas pendientes</div>
                  <div className="text-sm text-stone-500 mt-1">
                    Cuando el equipo de grooming o veterinaria finalice un servicio, aparecerá aquí.
                  </div>
                </div>
              ) : (
                <div>
                  <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold mb-2">
                    Pendientes ({pending.length})
                  </div>
                  <div className="space-y-2">
                    {pending.map(p => (
                      <ProposalCard key={p.id} proposal={p} onClick={() => setActiveProposalId(p.id)} />
                    ))}
                  </div>
                </div>
              )}

              {recent.length > 0 && (
                <div>
                  <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold mb-2 mt-4">
                    Recientes
                  </div>
                  <div className="space-y-2">
                    {recent.map(p => (
                      <ProposalCard key={p.id} proposal={p} onClick={() => setActiveProposalId(p.id)} compact />
                    ))}
                  </div>
                </div>
              )}
            </>
          )}
        </div>
      </div>
    </div>
  );
}

// === Card de propuesta en la bandeja ===
function ProposalCard({ proposal, onClick, compact }) {
  const moduleColors = {
    grooming: { bg: "bg-emerald-50", text: "text-emerald-700", label: "Grooming",     Icon: Scissors },
    vet:      { bg: "bg-orange-50",  text: "text-orange-700",  label: "Veterinaria",  Icon: Stethoscope },
  }[proposal.sourceModule] || { bg: "bg-stone-50", text: "text-stone-700", label: "Otro", Icon: Tag };
  const Ic = moduleColors.Icon;

  const statusColors = {
    pending:  { bg: "bg-orange-100",  text: "text-orange-700",  label: "Pendiente" },
    approved: { bg: "bg-emerald-100", text: "text-emerald-700", label: "Aprobada" },
    rejected: { bg: "bg-stone-100",   text: "text-stone-600",   label: "Rechazada" },
  }[proposal.status] || { bg: "bg-stone-100", text: "text-stone-600", label: "—" };

  const itemCount = proposal.items?.length || 0;

  return (
    <button
      onClick={onClick}
      className={`w-full text-left bg-white border-2 rounded-xl p-3 hover:shadow-md transition ${
        proposal.status === "pending" ? "border-orange-200 hover:border-orange-400" : "border-stone-200"
      }`}
    >
      <div className="flex items-start gap-3">
        <div className={`w-10 h-10 rounded-lg ${moduleColors.bg} ${moduleColors.text} grid place-items-center flex-shrink-0`}>
          <Ic size={16} strokeWidth={1.8} />
        </div>
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 flex-wrap">
            <span className="font-bold text-sm">{proposal.pet.name}</span>
            {proposal.pet.code && (
              <span className="font-mono text-xs font-bold text-stone-700">#{proposal.pet.code}</span>
            )}
            <span className={`text-xs font-bold px-2 py-0.5 rounded-full ${moduleColors.bg} ${moduleColors.text}`}>
              {moduleColors.label}
            </span>
          </div>
          <div className="text-sm text-stone-700 mt-0.5">{proposal.service}</div>
          {!compact && (
            <div className="text-xs text-stone-500 mt-1">
              {itemCount > 0 && <>{itemCount} insumo{itemCount === 1 ? "" : "s"} · </>}
              {proposal.target === "add-to-invoice"
                ? <>Sugerencia: agregar a recibo existente</>
                : proposal.target === "new-invoice"
                  ? <>Sugerencia: recibo nueva</>
                  : proposal.target === "notify-completion"
                    ? <span className="font-semibold text-blue-700">Aviso: servicio concluido (sin insumos)</span>
                    : null
              }
            </div>
          )}
        </div>
        <span className={`text-xs font-bold px-2 py-1 rounded-full ${statusColors.bg} ${statusColors.text} flex-shrink-0`}>
          {statusColors.label}
        </span>
      </div>
    </button>
  );
}

// === Detalle de revisión de propuesta ===
function ProposalDetailReview({ proposal, clients, invoices, onBack, onApprove, onReject }) {
  const [selectedClientId, setSelectedClientId] = useState(proposal.suggestedClientId);
  const [action, setAction] = useState(proposal.target || "new-invoice");
  const [targetInvoiceId, setTargetInvoiceId] = useState(proposal.targetInvoiceId);
  const [clientSearch, setClientSearch] = useState("");

  const selectedClient = clients.find(c => c.id === selectedClientId);

  const clientOpenInvoices = useMemo(() => {
    if (!selectedClientId) return [];
    return invoices.filter(inv =>
      inv.clientId === selectedClientId &&
      (inv.state === "borrador" || inv.state === "emitido")
    );
  }, [selectedClientId, invoices]);

  // Si la sugerencia era "add-to-invoice" pero no hay recibos abiertas, forzar new-invoice
  useEffect(() => {
    if (action === "add-to-invoice" && clientOpenInvoices.length === 0) {
      setAction("new-invoice");
    } else if (action === "add-to-invoice" && !targetInvoiceId && clientOpenInvoices.length > 0) {
      setTargetInvoiceId(clientOpenInvoices[0].id);
    }
  }, [action, clientOpenInvoices, targetInvoiceId]);

  const filteredClients = useMemo(() => {
    if (!clientSearch.trim()) return clients.slice(0, 8);
    const q = clientSearch.toLowerCase();
    return clients.filter(c =>
      (c.name || "").toLowerCase().includes(q) ||
      (c.cedula || "").toLowerCase().includes(q)
    ).slice(0, 12);
  }, [clientSearch, clients]);

  // Total estimado para mostrar a Ventas
  const supplyEstimate = useMemo(() => {
    return (proposal.items || []).reduce((acc, s) => {
      const def = GROOMING_SUPPLIES.find(g => g.id === s.sourceId);
      if (!def) return acc;
      const unitPrice = def.price / def.defaultQty;
      return acc + (s.qty * unitPrice);
    }, 0);
  }, [proposal.items]);

  const canApprove = selectedClientId && (
    action === "new-invoice" ||
    (action === "add-to-invoice" && targetInvoiceId)
  );

  const moduleColors = proposal.sourceModule === "grooming"
    ? { bg: "bg-emerald-50", text: "text-emerald-700", border: "border-emerald-200", Icon: Scissors, label: "Grooming" }
    : { bg: "bg-orange-50", text: "text-orange-700", border: "border-orange-200", Icon: Stethoscope, label: "Veterinaria" };
  const Ic = moduleColors.Icon;

  return (
    <div className="space-y-4">
      <button onClick={onBack} className="flex items-center gap-1.5 text-sm text-stone-600 hover:text-orange-700 font-semibold">
        <ChevronLeft size={14} /> Volver a la bandeja
      </button>

      {/* Header de la propuesta */}
      <div className={`${moduleColors.bg} border ${moduleColors.border} rounded-2xl p-4`}>
        <div className="flex items-start gap-3">
          <div className={`w-12 h-12 rounded-xl bg-white ${moduleColors.text} grid place-items-center shadow flex-shrink-0`}>
            <Ic size={20} strokeWidth={1.8} />
          </div>
          <div className="flex-1 min-w-0">
            <div className={`text-xs tracking-widest uppercase ${moduleColors.text} font-bold`}>
              Propuesta · {moduleColors.label}
            </div>
            <h3 className="font-serif text-2xl font-semibold leading-tight">{proposal.pet.name}</h3>
            <div className="text-sm text-stone-600">
              {proposal.pet.breed}
              {proposal.pet.code && (
                <> · <span className="font-mono font-bold">#{proposal.pet.code}</span></>
              )}
            </div>
            <div className="text-sm font-semibold mt-1">{proposal.service}</div>
          </div>
        </div>
      </div>

      {/* Items */}
      <div className="bg-white border border-stone-200 rounded-xl p-3">
        <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold mb-2">
          Items propuestos
        </div>
        <div className="space-y-1.5">
          {(proposal.items || []).length === 0 ? (
            <div className="text-xs text-stone-400 text-center py-3">Sin insumos. Solo el servicio base.</div>
          ) : (
            (proposal.items || []).map((it, i) => {
              const def = GROOMING_SUPPLIES.find(g => g.id === it.sourceId);
              const unitPrice = def ? def.price / def.defaultQty : 0;
              const total = Math.round(unitPrice * it.qty);
              return (
                <div key={i} className="flex items-center justify-between gap-2 p-2 bg-stone-50 rounded-lg text-sm">
                  <div className="flex-1 min-w-0">
                    <div className="font-semibold truncate">{it.name}</div>
                    <div className="text-xs text-stone-500">{it.qty} {it.unit}</div>
                  </div>
                  <div className="font-mono text-sm font-bold text-emerald-700 flex-shrink-0">
                    ${total}
                  </div>
                </div>
              );
            })
          )}
        </div>
        {(proposal.items || []).length > 0 && (
          <div className="mt-2 pt-2 border-t border-stone-100 flex justify-between text-xs font-bold">
            <span>Estimado insumos</span>
            <span className="font-mono text-emerald-700">${Math.round(supplyEstimate)}</span>
          </div>
        )}
      </div>

      {/* Cliente */}
      <div className="bg-white border border-stone-200 rounded-xl p-3">
        <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold mb-2">
          Cliente {!selectedClient && <span className="text-red-600">*</span>}
        </div>
        {selectedClient ? (
          <div className="bg-emerald-50 border border-emerald-300 rounded-xl p-3 flex items-center gap-3">
            <div className={`w-10 h-10 rounded-xl grid place-items-center text-white text-xs font-bold flex-shrink-0 bg-gradient-to-br from-orange-500 to-orange-700`}>
              {selectedClient.name.split(" ").slice(0, 2).map(s => s[0]).join("").toUpperCase()}
            </div>
            <div className="flex-1 min-w-0">
              <div className="font-semibold text-sm truncate">{selectedClient.name}</div>
              <div className="text-xs text-stone-500 font-mono">{selectedClient.cedula}</div>
            </div>
            <button
              onClick={() => setSelectedClientId(null)}
              className="text-xs text-stone-500 hover:text-red-600 font-semibold"
            >
              Cambiar
            </button>
          </div>
        ) : (
          <>
            {proposal.suggestedClientName && (
              <div className="text-xs text-amber-700 bg-amber-50 border border-amber-200 rounded-lg p-2 mb-2">
                Sugerido por {proposal.sourceModule}: <strong>{proposal.suggestedClientName}</strong>
              </div>
            )}
            <div className="relative mb-2">
              <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-stone-400" />
              <input
                value={clientSearch}
                onChange={(e) => setClientSearch(e.target.value)}
                placeholder="Buscar cliente..."
                className="w-full pl-9 pr-3 py-2 bg-stone-50 border border-stone-200 rounded-lg text-sm outline-none focus:border-orange-500 focus:bg-white"
              />
            </div>
            <div className="max-h-40 overflow-y-auto bg-stone-50 rounded-lg divide-y divide-stone-200">
              {filteredClients.map(c => (
                <button
                  key={c.id}
                  onClick={() => setSelectedClientId(c.id)}
                  className="w-full p-2 hover:bg-orange-50 transition text-left flex items-center gap-2"
                >
                  <div className="w-7 h-7 rounded-md grid place-items-center text-white text-xs font-bold bg-gradient-to-br from-orange-500 to-orange-700 flex-shrink-0">
                    {c.name.split(" ").slice(0, 2).map(s => s[0]).join("").toUpperCase()}
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="font-semibold text-xs truncate">{c.name}</div>
                    <div className="text-xs text-stone-500 font-mono truncate">{c.cedula}</div>
                  </div>
                </button>
              ))}
            </div>
          </>
        )}
      </div>

      {/* Acción */}
      {selectedClient && (
        <div className="bg-white border border-stone-200 rounded-xl p-3">
          <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold mb-2">
            ¿Cómo cobrar?
          </div>
          <div className="space-y-2">
            {clientOpenInvoices.length > 0 && (
              <button
                onClick={() => setAction("add-to-invoice")}
                className={`w-full p-3 rounded-xl border-2 text-left transition ${
                  action === "add-to-invoice"
                    ? "bg-blue-50 border-blue-400"
                    : "bg-white border-stone-200 hover:border-stone-400"
                }`}
              >
                <div className="font-semibold text-sm">Sumar a recibo abierta</div>
                <div className="text-xs text-stone-500 mt-0.5">
                  Se marcará con cinta visual indicando el aumento.
                </div>
                {action === "add-to-invoice" && (
                  <select
                    value={targetInvoiceId || ""}
                    onChange={(e) => { e.stopPropagation(); setTargetInvoiceId(e.target.value); }}
                    onClick={(e) => e.stopPropagation()}
                    className="mt-2 w-full px-2 py-1.5 bg-white border border-blue-300 rounded-lg text-xs font-mono outline-none"
                  >
                    {clientOpenInvoices.map(inv => (
                      <option key={inv.id} value={inv.id}>
                        {inv.number} · {inv.state} · ${inv.total}
                      </option>
                    ))}
                  </select>
                )}
              </button>
            )}
            <button
              onClick={() => setAction("new-invoice")}
              className={`w-full p-3 rounded-xl border-2 text-left transition ${
                action === "new-invoice"
                  ? "bg-emerald-50 border-emerald-400"
                  : "bg-white border-stone-200 hover:border-stone-400"
              }`}
            >
              <div className="font-semibold text-sm">Crear recibo nueva</div>
              <div className="text-xs text-stone-500 mt-0.5">
                Para clientes que pagan al finalizar o por adelantado.
              </div>
            </button>
          </div>
        </div>
      )}

      {/* Acciones */}
      <div className="flex gap-2 pt-2">
        <button
          onClick={onReject}
          className="flex-1 px-3 py-3 rounded-xl text-sm font-semibold bg-white border-2 border-stone-200 hover:border-red-400 text-stone-700 hover:text-red-700 transition"
        >
          <X size={13} className="inline" /> Rechazar
        </button>
        <button
          onClick={() => onApprove({ action, targetInvoiceId, clientId: selectedClientId })}
          disabled={!canApprove}
          className={`flex-1 px-3 py-3 rounded-xl text-sm font-semibold transition shadow ${
            canApprove
              ? "bg-emerald-500 hover:bg-emerald-600 text-white"
              : "bg-stone-200 text-stone-400 cursor-not-allowed"
          }`}
        >
          <Check size={13} className="inline" strokeWidth={2.5} /> Aprobar y cobrar
        </button>
      </div>
    </div>
  );
}

// ========== VISTA: BANDEJA DE MENSAJES (módulo completo) ==========

function MessagesView({ clients, setClients, passports = [], setPassports, conversations, onSendMessage, invoices = [], setInvoices, onGoToInvoice, user = null, userRole = "super", permissions = {}, agendaEvents = [], setAgendaEvents, modules = [], sedes = [], services = [], groomingBookings = [], setGroomingBookings, msgTemplate = {}, setMsgTemplate, onOpenMsgConfig, paymentMethods = [] }) {
  // ¿Puede el usuario configurar la plantilla global de mensajes?
  const canConfigMsgTemplate = userRole === "super" || getFieldLevel(permissions, userRole, "clients", "messaging", "msg-config") !== "hidden";
  // Filtrar conversaciones por sede del usuario. Si el usuario tiene sedeIds restringidos,
  // solo ve conversaciones de clientes cuya sedeOrigenId esté en sus sedes (o sin sede = legacy).
  // El super (sedeIds vacío) ve todas. Esto se hace ANTES de pasar conversations al render.
  const filteredConversations = useMemo(() => {
    if (userRole === "super" || !user?.sedeIds || user.sedeIds.length === 0) {
      return conversations;
    }
    // Estricto: solo clientes con sedeOrigenId explícito en las sedes del usuario.
    // Los clientes sin sedeOrigenId (legacy) NO son accesibles para roles con sede.
    const allowedClientIds = new Set(
      clients.filter(c => c.sedeOrigenId && user.sedeIds.includes(c.sedeOrigenId))
        .map(c => c.id)
    );
    const filtered = {};
    Object.keys(conversations || {}).forEach(key => {
      if (allowedClientIds.has(key)) filtered[key] = conversations[key];
    });
    return filtered;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [conversations, clients, user, userRole]);

  // Reemplaza `conversations` por la versión filtrada en todo el cuerpo
  conversations = filteredConversations;
  const [activeClientId, setActiveClientId] = useState(null);
  const [searchQuery, setSearchQuery] = useState("");
  const [channelFilter, setChannelFilter] = useState("all"); // all | whatsapp | instagram | facebook | web
  const [draft, setDraft] = useState("");
  const [activeChannel, setActiveChannel] = useState("whatsapp");

  // Menú "+" del input (foto / recibo)
  const [showAttachMenu, setShowAttachMenu] = useState(false);
  // Modal de selector de imagen y modal selector de recibo
  const [showImagePicker, setShowImagePicker] = useState(false);
  const [showInvoicePicker, setShowInvoicePicker] = useState(false);
  // Modal de selector de método de pago para enviar datos al cliente
  const [showPaymentPicker, setShowPaymentPicker] = useState(false);
  // Menú "..." del header del chat
  const [showHeaderMenu, setShowHeaderMenu] = useState(false);
  // Modal: vincular cliente desde chat (cuando es visitante / sin cliente)
  const [showLinkClient, setShowLinkClient] = useState(false);
  // Modal para asociar recibos existentes al cliente del chat actual.
  // Útil cuando el cliente tiene varios números de teléfono o creó recibos
  // como visitante antes de asociar el chat.
  const [showAssociateInvoice, setShowAssociateInvoice] = useState(false);
  const [associateSearch, setAssociateSearch] = useState("");
  // === Panel lateral de ficha (cliente o mascota) sobre el chat ===
  // Se abre desde los botones del header sin salir de la conversación.
  // null = cerrado, "client" = ficha del tutor, "pet" = ficha de mascota
  const [sidePanelTab, setSidePanelTab] = useState(null);
  // Si hay varias mascotas, dejamos al usuario elegir cuál ver
  const [sidePanelPetCode, setSidePanelPetCode] = useState(null);
  // Pestañas de recibos abiertas con detalle dentro del chat
  // Cada tab tiene { id, invoiceId } — no se persisten más allá de la sesión
  const [openInvoiceTabs, setOpenInvoiceTabs] = useState([]); // [{ id, invoiceId }]
  const [activeInvoiceTabId, setActiveInvoiceTabId] = useState(null);

  // === Ventana flotante "Agendar cita" ===
  // Se mantiene abierta mientras se sigue conversando. El usuario puede
  // chatear y llenar el formulario al mismo tiempo.
  const [showAppointmentFloat, setShowAppointmentFloat] = useState(false);
  // Cuando se abre desde "Configurar mensaje" en el menú, la ventana flotante
  // arranca con el panel de configuración expandido.
  const [appointmentAutoConfig, setAppointmentAutoConfig] = useState(false);

  // Filtro por sede. Los usuarios no-super solo ven clientes de sus sedes
  // (se aplica siempre, sin toggle). El super ve todo por defecto y tiene
  // pills para filtrar voluntariamente.
  const [sedeFilter, setSedeFilter] = useState("all"); // "all" | sedeId

  // Construir lista de conversaciones con metadata útil
  const conversationsList = useMemo(() => {
    const list = [];
    Object.entries(conversations || {}).forEach(([clientId, msgs]) => {
      if (!msgs || msgs.length === 0) return;
      const client = clients.find(c => c.id === clientId);
      if (!client) return;
      const last = msgs[msgs.length - 1];
      const lastIn = [...msgs].reverse().find(m => m.direction === "in");
      const lastInTime = lastIn ? new Date(lastIn.timestamp).getTime() : 0;
      const lastOutAfter = lastIn ? msgs.some(m => m.direction === "out" && new Date(m.timestamp).getTime() > lastInTime) : true;
      const unread = lastIn && !lastOutAfter;
      list.push({
        client,
        messages: msgs,
        lastMessage: last,
        unread,
        timestamp: last.timestamp,
        // Canales únicos usados con este cliente
        channels: [...new Set(msgs.map(m => m.channel))],
      });
    });
    // Ordenar por timestamp descendente (más reciente primero)
    return list.sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp));
  }, [conversations, clients]);

  // Filtrado (canal + búsqueda + sede)
  const isSuper = userRole === "super";
  const userSedeIds = user?.sedeIds || [];
  const filtered = useMemo(() => {
    let r = conversationsList;
    // === Filtro por sede ===
    // Non-super: solo ven clientes de sus propias sedes (user.sedeIds).
    // Un array vacío = "todas las sedes" (legacy, igual que super).
    if (!isSuper && userSedeIds.length > 0) {
      r = r.filter(c => {
        const clientSede = c.client.sedeOrigenId;
        return !clientSede || userSedeIds.includes(clientSede);
      });
    }
    // Super: filtro voluntario por sede (pills).
    if (isSuper && sedeFilter !== "all") {
      r = r.filter(c => c.client.sedeOrigenId === sedeFilter);
    }
    if (channelFilter !== "all") {
      r = r.filter(c => c.channels.includes(channelFilter));
    }
    if (searchQuery.trim()) {
      const q = searchQuery.toLowerCase();
      r = r.filter(c =>
        c.client.name.toLowerCase().includes(q) ||
        c.client.phone.includes(q) ||
        c.lastMessage.body.toLowerCase().includes(q)
      );
    }
    return r;
  }, [conversationsList, channelFilter, searchQuery, sedeFilter, isSuper, userSedeIds]);

  const activeConvo = filtered.find(c => c.client.id === activeClientId)
    || conversationsList.find(c => c.client.id === activeClientId);
  const activeMessages = useMemo(() =>
    activeConvo ? activeConvo.messages.filter(m => m.channel === activeChannel) : [],
    [activeConvo, activeChannel]
  );

  // Auto-seleccionar primer chat en escritorio
  useEffect(() => {
    if (!activeClientId && filtered.length > 0) {
      setActiveClientId(filtered[0].client.id);
    }
  }, [filtered, activeClientId]);

  // Stats
  const stats = useMemo(() => {
    const totalUnread = conversationsList.filter(c => c.unread).length;
    const byChannel = {};
    conversationsList.forEach(c => c.channels.forEach(ch => { byChannel[ch] = (byChannel[ch] || 0) + 1; }));
    return { total: conversationsList.length, unread: totalUnread, byChannel };
  }, [conversationsList]);

  const handleSend = () => {
    if (!draft.trim() || !activeConvo) return;
    onSendMessage(activeConvo.client.id, activeChannel, draft.trim());
    setDraft("");
  };

  // Enviar adjunto: imagen o recibo (estos requieren un onSendMessage extendido en el padre,
  // pero para que sea robusto enviamos un body de texto que represente el adjunto)
  const handleSendImage = (imageDataUrl, caption = "") => {
    if (!activeConvo) return;
    const body = caption || "📎 Imagen adjunta";
    onSendMessage(activeConvo.client.id, activeChannel, body, {
      attachment: { type: "image", url: imageDataUrl, caption }
    });
    setShowImagePicker(false);
    setShowAttachMenu(false);
  };
  const handleSendInvoice = (invoice, messageText = null) => {
    if (!activeConvo) return;
    // Si hay mensaje de acompañamiento, lo enviamos como mensaje separado PRIMERO
    // (así aparece arriba de la recibo adjunta en la conversación)
    if (messageText) {
      onSendMessage(activeConvo.client.id, activeChannel, messageText);
    }
    // Enviamos la recibo como adjunto. El "body" textual es solo fallback;
    // la UI del chat renderiza el adjunto como documento embebido.
    const body = `📄 Recibo ${invoice.number} · $${(invoice.total ?? 0).toFixed(2)}`;
    onSendMessage(activeConvo.client.id, activeChannel, body, {
      attachment: { type: "invoice", invoiceId: invoice.id }
    });
    setShowInvoicePicker(false);
    setShowAttachMenu(false);
  };

  // Pestañas: abrir / cerrar / activar
  const openInvoiceTab = (invoiceId) => {
    const existing = openInvoiceTabs.find(t => t.invoiceId === invoiceId);
    if (existing) {
      setActiveInvoiceTabId(existing.id);
      return;
    }
    const tabId = `tab-${Date.now().toString(36)}`;
    setOpenInvoiceTabs(prev => [...prev, { id: tabId, invoiceId }]);
    setActiveInvoiceTabId(tabId);
  };
  const closeInvoiceTab = (tabId) => {
    setOpenInvoiceTabs(prev => prev.filter(t => t.id !== tabId));
    setActiveInvoiceTabId(curr => {
      if (curr !== tabId) return curr;
      const remaining = openInvoiceTabs.filter(t => t.id !== tabId);
      return remaining[remaining.length - 1]?.id || null;
    });
  };

  // Recibos asociadas al cliente activo:
  // - Las que tienen clientId === este cliente (su dueño original)
  // - Las que están vinculadas vía linkedClientIds (vínculo manual creado desde el chat)
  // Los vínculos no transfieren la recibo, solo la hacen visible aquí. La recibo
  // original sigue perteneciendo a su clientId. Esto preserva la fuente de verdad y
  // permite que la misma recibo aparezca en varias fichas (ej. cliente con dos teléfonos).
  const activeClientInvoices = useMemo(() => {
    if (!activeConvo) return [];
    const cid = activeConvo.client.id;
    return invoices.filter(inv =>
      inv.clientId === cid ||
      (Array.isArray(inv.linkedClientIds) && inv.linkedClientIds.includes(cid))
    );
  }, [invoices, activeConvo]);

  // Vincular cliente real al chat (cuando es visitante)
  // Crea un cliente nuevo en la tabla y reasigna las conversaciones del visitante
  const handleLinkClient = (data) => {
    if (!setClients || !activeConvo) return;
    // Verificar si la cédula ya existe → vincular al existente
    const existing = clients.find(c =>
      c.documentId && data.documentId && c.documentId === data.documentId
    );
    if (existing) {
      setShowLinkClient(false);
      setActiveClientId(existing.id);
      return;
    }
    // Crear cliente nuevo con datos del chat
    const newClientId = `cli-${Date.now().toString(36)}`;
    const newClient = {
      id: newClientId,
      name: data.name,
      documentId: data.documentId,
      phone: activeConvo.client.phone || data.phone || "",
      email: data.email || "",
      address: "",
      type: "person",
      tags: ["from-chat"],
      pets: [],
      registeredAt: new Date().toISOString().slice(0, 10),
    };

    // Si hay datos de mascota → crear pasaporte ligado al cliente
    let petCode = null;
    if (data.pet?.name && setPassports) {
      petCode = String(Math.floor(Math.random() * 1000000)).padStart(6, "0");
      const newPet = {
        id: `pet-${Date.now().toString(36)}`,
        code: petCode,
        name: data.pet.name,
        species: data.pet.species || "dog",
        speciesOther: data.pet.speciesOther || "",
        breed: data.pet.breed || "—",
        age: data.pet.age || "—",
        weight: null,
        color: "",
        gender: data.pet.gender || "—",
        sterilized: false,
        microchip: "",
        birthdate: null,
        photo: null,
        // Campos clínicos de la ficha extendida — inicializados vacíos para
        // que FichaClinicaCard pueda editarlos.
        allergies: "",
        chronicConditions: "",
        diet: "",
        behavior: "",
        notes: "",
        tutors: [{ clientId: newClientId, name: data.name, phone: newClient.phone, documentId: data.documentId, primary: true }],
        events: [],
        clinicHistory: [],
        vaccines: [],
        medications: [],
      };
      setPassports(prev => [...prev, newPet]);
      newClient.pets = [petCode];
    }

    setClients(prev => [...prev, newClient]);
    setShowLinkClient(false);
    setActiveClientId(newClientId);
  };

  return (
    <div className="space-y-4">
      {/* Layout principal: lista a la izquierda, conversación a la derecha.
          Altura adaptable: en mobile fuerza 75vh con mínimo de 500px para que el
          composer (input + botón enviar) siempre quede visible al fondo, incluso
          en pantallas cortas. En desktop hasta 700px. */}
      <div className="bg-white border border-stone-200 rounded-2xl shadow-sm overflow-hidden">
        <div className="flex h-screen-90 flex-col md:flex-row" style={{ height: "min(700px, max(75vh, 500px))" }}>
          {/* Columna izquierda: lista */}
          <div className={`md:w-80 md:flex-shrink-0 border-r border-stone-200 flex flex-col ${
            activeClientId ? "hidden md:flex" : "flex flex-1"
          }`}>
            {/* Buscador */}
            <div className="p-3 border-b border-stone-200 flex-shrink-0 space-y-2">
              <div className="flex items-center gap-2">
                <div className="relative flex-1">
                  <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-stone-400" />
                  <input
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    placeholder="Buscar conversación..."
                    className="w-full pl-9 pr-3 py-2 bg-stone-50 border border-stone-200 rounded-lg text-sm outline-none focus:border-orange-500 focus:bg-white"
                  />
                </div>
                {canConfigMsgTemplate && onOpenMsgConfig && (
                  <button
                    onClick={onOpenMsgConfig}
                    title="Configurar plantilla de mensaje de reserva"
                    className="w-9 h-9 rounded-lg bg-stone-50 border border-stone-200 hover:bg-orange-50 hover:border-orange-300 hover:text-orange-700 text-stone-500 transition grid place-items-center flex-shrink-0"
                  >
                    <Settings size={14} />
                  </button>
                )}
              </div>
              {/* Filtro por canal */}
              <div className="flex gap-1 overflow-x-auto">
                <button
                  onClick={() => setChannelFilter("all")}
                  className={`flex items-center gap-1 px-2.5 py-1 rounded-full text-xs font-semibold whitespace-nowrap transition ${
                    channelFilter === "all" ? "bg-stone-900 text-white" : "bg-stone-100 text-stone-600"
                  }`}
                >
                  Todos · {stats.total}
                </button>
                {Object.entries(CHAT_CHANNELS).map(([id, info]) => {
                  const Icon = info.icon;
                  const count = stats.byChannel[id] || 0;
                  if (count === 0) return null;
                  const colors = CHAT_CHANNEL_CLASSES[info.color];
                  const active = channelFilter === id;
                  return (
                    <button
                      key={id}
                      onClick={() => setChannelFilter(id)}
                      className={`flex items-center gap-1 px-2.5 py-1 rounded-full text-xs font-semibold whitespace-nowrap transition ${
                        active ? `${colors.bg} ${colors.text}` : "bg-stone-100 text-stone-500"
                      }`}
                    >
                      <Icon size={11} strokeWidth={1.8} />
                      {count}
                    </button>
                  );
                })}
              </div>

              {/* Filtro por sede — solo visible para super usuario.
                  Permite filtrar las conversaciones por la sede de origen
                  del cliente. Los no-super ya ven solo sus sedes por
                  la restricción automática aplicada en el memo `filtered`. */}
              {isSuper && sedes.length > 1 && (
                <div className="flex gap-1 overflow-x-auto">
                  <button
                    onClick={() => setSedeFilter("all")}
                    className={`flex items-center gap-1 px-2.5 py-1 rounded-full text-xs font-semibold whitespace-nowrap transition ${
                      sedeFilter === "all"
                        ? "bg-orange-600 text-white"
                        : "bg-orange-50 text-orange-700 hover:bg-orange-100"
                    }`}
                  >
                    <MapPin size={10} strokeWidth={2.4} />
                    Todas
                  </button>
                  {sedes.map(s => {
                    const count = conversationsList.filter(c => c.client.sedeOrigenId === s.id).length;
                    return (
                      <button
                        key={s.id}
                        onClick={() => setSedeFilter(s.id)}
                        className={`flex items-center gap-1 px-2.5 py-1 rounded-full text-xs font-semibold whitespace-nowrap transition ${
                          sedeFilter === s.id
                            ? "bg-orange-600 text-white"
                            : "bg-orange-50 text-orange-700 hover:bg-orange-100"
                        }`}
                      >
                        {s.name}
                        <span className={`text-[10px] font-bold px-1 rounded-full ${
                          sedeFilter === s.id ? "bg-orange-700 text-white" : "bg-orange-100 text-orange-600"
                        }`}>{count}</span>
                      </button>
                    );
                  })}
                </div>
              )}
            </div>
            {/* Lista de conversaciones */}
            <div className="flex-1 overflow-y-auto">
              {filtered.length === 0 ? (
                <div className="p-8 text-center text-stone-400 text-sm">
                  Sin conversaciones para este filtro.
                </div>
              ) : (
                filtered.map(c => (
                  <ConversationListItem
                    key={c.client.id}
                    conversation={c}
                    active={c.client.id === activeClientId}
                    onClick={() => setActiveClientId(c.client.id)}
                    sedes={sedes}
                  />
                ))
              )}
            </div>
          </div>

          {/* Columna derecha: conversación abierta */}
          <div className={`flex-1 min-w-0 flex flex-col relative ${
            !activeClientId ? "hidden md:flex" : "flex"
          }`}>
            {!activeConvo ? (
              <div className="flex-1 grid place-items-center text-center p-6">
                <div>
                  <MessageCircle size={40} className="text-stone-300 mx-auto mb-3" />
                  <div className="text-base font-semibold text-stone-700">Selecciona una conversación</div>
                  <div className="text-sm text-stone-500 mt-1">
                    O busca un cliente en la lista de la izquierda.
                  </div>
                </div>
              </div>
            ) : (
              <>
                {/* Header con info del cliente */}
                <div className="flex items-center gap-3 p-3 border-b border-stone-200 flex-shrink-0">
                  <button
                    onClick={() => setActiveClientId(null)}
                    className="md:hidden w-9 h-9 rounded-lg bg-stone-100 grid place-items-center text-stone-600"
                  >
                    <ChevronLeft size={15} />
                  </button>
                  <div className={`w-10 h-10 rounded-full grid place-items-center text-white text-xs font-bold flex-shrink-0 ${
                    activeConvo.client.isOrg
                      ? "bg-gradient-to-br from-stone-700 to-stone-900"
                      : activeConvo.client.isVisitor
                      ? "bg-gradient-to-br from-stone-400 to-stone-600"
                      : "bg-gradient-to-br from-orange-500 to-orange-700"
                  }`}>
                    {activeConvo.client.name.split(" ").slice(0, 2).map(s => s[0]).join("").toUpperCase()}
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="font-semibold text-sm truncate flex items-center gap-1.5">
                      {activeConvo.client.name}
                      {activeConvo.client.isVisitor && (
                        <span className="text-xs font-bold px-1.5 py-px rounded bg-amber-100 text-amber-800">Visitante</span>
                      )}
                    </div>
                    <div className="text-xs text-stone-500 truncate flex items-center gap-1.5">
                      <Phone size={9} /> {activeConvo.client.phone || "Sin teléfono"}
                      {activeConvo.client.documentId && (
                        <span className="ml-1.5">· {activeConvo.client.documentId}</span>
                      )}
                    </div>
                  </div>

                  {/* === Botones flotantes al lado del nombre ===
                      Lupita = abre ficha del cliente en panel lateral
                      Patita = abre ficha de mascota
                      Ambos se renderizan sobre el chat, sin salir de la conversación. */}
                  {!activeConvo.client.isVisitor && (
                    <div className="flex items-center gap-1 bg-white border border-stone-200 rounded-lg p-0.5 flex-shrink-0">
                      <button
                        onClick={() => {
                          setSidePanelTab(sidePanelTab === "client" ? null : "client");
                          if (sidePanelTab !== "client") setSidePanelPetCode(null);
                        }}
                        title="Ver ficha del cliente"
                        className={`w-8 h-8 rounded-md grid place-items-center transition ${
                          sidePanelTab === "client"
                            ? "bg-orange-600 text-white"
                            : "text-stone-600 hover:bg-stone-100 hover:text-orange-700"
                        }`}
                      >
                        <Search size={14} />
                      </button>
                      <button
                        onClick={() => {
                          if (sidePanelTab === "pet") {
                            setSidePanelTab(null);
                            return;
                          }
                          // Si solo hay una mascota, la seleccionamos directo. Si hay varias,
                          // arranca con la primera y desde el panel se puede cambiar.
                          const firstPetCode = (activeConvo.client.petCodes || [])[0];
                          if (firstPetCode) {
                            setSidePanelPetCode(firstPetCode);
                            setSidePanelTab("pet");
                          }
                        }}
                        title={(activeConvo.client.petCodes || []).length === 0 ? "Sin mascotas registradas" : "Ver ficha de mascota"}
                        disabled={(activeConvo.client.petCodes || []).length === 0}
                        className={`w-8 h-8 rounded-md grid place-items-center transition ${
                          sidePanelTab === "pet"
                            ? "bg-orange-600 text-white"
                            : (activeConvo.client.petCodes || []).length === 0
                            ? "text-stone-300 cursor-not-allowed"
                            : "text-stone-600 hover:bg-stone-100 hover:text-orange-700"
                        }`}
                      >
                        <PawPrint size={14} />
                      </button>
                    </div>
                  )}

                  {/* Pestañas de recibos abiertas (estilo browser) */}
                  {openInvoiceTabs.length > 0 && (
                    <div className="hidden lg:flex items-center gap-1 max-w-md overflow-x-auto">
                      {openInvoiceTabs.map(tab => {
                        const inv = invoices.find(i => i.id === tab.invoiceId);
                        if (!inv) return null;
                        const active = tab.id === activeInvoiceTabId;
                        return (
                          <div
                            key={tab.id}
                            onClick={() => setActiveInvoiceTabId(tab.id)}
                            className={`flex items-center gap-1.5 pl-2 pr-1 py-1 rounded-lg border text-xs cursor-pointer transition flex-shrink-0 ${
                              active ? "bg-orange-50 border-orange-300 text-orange-800" : "bg-white border-stone-200 text-stone-600 hover:border-stone-400"
                            }`}
                          >
                            <Receipt size={10} />
                            <span className="font-mono font-bold">{inv.number.slice(-5)}</span>
                            <button
                              onClick={(e) => { e.stopPropagation(); closeInvoiceTab(tab.id); }}
                              title="Cerrar pestaña"
                              className="w-5 h-5 rounded hover:bg-stone-200 grid place-items-center text-stone-500 hover:text-stone-800"
                            >
                              <X size={9} />
                            </button>
                          </div>
                        );
                      })}
                    </div>
                  )}

                  {/* Botón "Agendar cita" — abre una ventana flotante
                      que se mantiene abierta mientras se sigue conversando.
                      Pre-rellena el cliente actual. */}
                  <button
                    onClick={() => setShowAppointmentFloat(true)}
                    title="Agendar cita para este cliente"
                    className={`w-9 h-9 rounded-lg grid place-items-center transition ${
                      showAppointmentFloat
                        ? "bg-orange-600 text-white"
                        : "bg-white border border-stone-200 hover:border-orange-300 text-stone-600"
                    }`}
                  >
                    <CalendarPlus size={14} />
                  </button>

                  {/* Menú "..." */}
                  <div className="relative">
                    <button
                      onClick={() => setShowHeaderMenu(v => !v)}
                      className="w-9 h-9 rounded-lg bg-white border border-stone-200 hover:border-orange-300 grid place-items-center text-stone-600 transition"
                      title="Más acciones"
                    >
                      <MoreHorizontal size={14} />
                    </button>
                    {showHeaderMenu && (
                      <>
                        <div onClick={() => setShowHeaderMenu(false)} className="fixed inset-0 z-30"></div>
                        <div className="absolute right-0 top-full mt-1 w-64 bg-white border border-stone-200 rounded-xl shadow-2xl z-40 overflow-hidden">
                          {/* Vincular cliente solo si es visitante */}
                          {activeConvo.client.isVisitor && (
                            <button
                              onClick={() => { setShowHeaderMenu(false); setShowLinkClient(true); }}
                              className="w-full flex items-start gap-2.5 p-3 hover:bg-orange-50 transition text-left border-b border-stone-100"
                            >
                              <div className="w-8 h-8 rounded-lg bg-emerald-100 text-emerald-700 grid place-items-center flex-shrink-0">
                                <UserPlus size={13} />
                              </div>
                              <div className="flex-1 min-w-0">
                                <div className="font-semibold text-sm">Vincular cliente</div>
                                <div className="text-xs text-stone-500 leading-snug">
                                  Asociar este chat a una cédula registrada o crear cliente nuevo.
                                </div>
                              </div>
                            </button>
                          )}

                          {/* Agendar reserva desde el chat */}
                          <button
                            onClick={() => { setShowHeaderMenu(false); setShowAppointmentFloat(true); }}
                            className="w-full flex items-start gap-2.5 p-3 hover:bg-orange-50 transition text-left border-b border-stone-100"
                          >
                            <div className="w-8 h-8 rounded-lg bg-orange-100 text-orange-700 grid place-items-center flex-shrink-0">
                              <CalendarPlus size={13} />
                            </div>
                            <div className="flex-1 min-w-0">
                              <div className="font-semibold text-sm">Agendar reserva</div>
                              <div className="text-xs text-stone-500 leading-snug">
                                Crear cita + recibo borrador y enviar confirmación.
                              </div>
                            </div>
                          </button>

                          {/* Configurar plantilla de mensaje — solo con permiso msg-config */}
                          {(userRole === "super" || getFieldLevel(permissions, userRole, "clients", "messaging", "msg-config") !== "hidden") && (
                            <button
                              onClick={() => { setShowHeaderMenu(false); setShowAppointmentFloat(true); setAppointmentAutoConfig(true); }}
                              className="w-full flex items-start gap-2.5 p-3 hover:bg-orange-50 transition text-left border-b border-stone-100"
                            >
                              <div className="w-8 h-8 rounded-lg bg-stone-100 text-stone-600 grid place-items-center flex-shrink-0">
                                <Settings size={13} />
                              </div>
                              <div className="flex-1 min-w-0">
                                <div className="font-semibold text-sm">Configurar mensaje de reserva</div>
                                <div className="text-xs text-stone-500 leading-snug">
                                  Elige qué información incluir en el mensaje de confirmación.
                                </div>
                              </div>
                            </button>
                          )}

                          <div className="px-3 py-2 border-b border-stone-100 bg-stone-50">
                            <div className="text-xs tracking-widest uppercase text-stone-500 font-bold flex items-center justify-between">
                              <span>Recibos del cliente</span>
                              <div className="flex items-center gap-1">
                                <span className="text-xs font-bold px-1.5 py-px rounded-full bg-stone-200 text-stone-700">
                                  {activeClientInvoices.length}
                                </span>
                                {/* Botón para abrir el modal de asociación de recibos.
                                    Permite vincular recibos existentes de otros clientes (ej. cliente
                                    con varios números). Reasigna clientId, no clona. */}
                                <button
                                  onClick={() => { setShowHeaderMenu(false); setShowAssociateInvoice(true); }}
                                  title="Asociar más recibos a este cliente"
                                  className="w-5 h-5 rounded-full bg-orange-600 hover:bg-orange-700 text-white grid place-items-center transition ml-0.5"
                                >
                                  <Plus size={11} strokeWidth={2.5} />
                                </button>
                              </div>
                            </div>
                          </div>
                          <div className="max-h-64 overflow-y-auto">
                            {activeClientInvoices.length === 0 ? (
                              <div className="p-4 text-center text-xs text-stone-500">
                                Este contacto no tiene recibos registradas.
                              </div>
                            ) : (
                              activeClientInvoices.map(inv => {
                                const isOpen = openInvoiceTabs.some(t => t.invoiceId === inv.id);
                                // Una recibo es "vinculada" si su dueño original (clientId)
                                // no es el cliente actual. Aparece acá porque está en linkedClientIds.
                                const isLinked = inv.clientId !== activeConvo.client.id;
                                const ownerClient = isLinked ? clients.find(c => c.id === inv.clientId) : null;
                                return (
                                  <div
                                    key={inv.id}
                                    className={`w-full flex items-center gap-2 p-2.5 transition text-left border-b border-stone-100 last:border-0 ${
                                      isOpen ? "bg-orange-50" : "hover:bg-stone-50"
                                    }`}
                                  >
                                    <button
                                      onClick={() => { setShowHeaderMenu(false); openInvoiceTab(inv.id); }}
                                      disabled={isOpen}
                                      className="flex items-center gap-2 flex-1 min-w-0 text-left disabled:cursor-default"
                                    >
                                      <div className={`w-7 h-7 rounded-lg grid place-items-center flex-shrink-0 ${
                                        isLinked ? "bg-cyan-100 text-cyan-700" : "bg-orange-100 text-orange-700"
                                      }`}>
                                        <Receipt size={11} />
                                      </div>
                                      <div className="flex-1 min-w-0">
                                        <div className="flex items-baseline gap-1.5 flex-wrap">
                                          <span className="font-mono text-xs font-bold text-stone-700">{inv.number}</span>
                                          <InvoiceStateBadge state={inv.state} />
                                          {isLinked && (
                                            <span className="text-[9px] font-bold uppercase px-1 py-px rounded bg-cyan-100 text-cyan-700" title={`Vinculada desde ${ownerClient?.name || "otro cliente"}`}>
                                              vinculada
                                            </span>
                                          )}
                                        </div>
                                        <div className="text-xs text-stone-500">
                                          ${inv.total.toFixed(2)} · {inv.issueDate}
                                          {isLinked && ownerClient && (
                                            <span className="ml-1">· de {ownerClient.name}</span>
                                          )}
                                        </div>
                                      </div>
                                    </button>
                                    {isLinked ? (
                                      // Botón quitar vínculo (solo en recibos vinculadas, no en propias)
                                      <button
                                        onClick={(e) => {
                                          e.stopPropagation();
                                          if (confirm(`¿Quitar el vínculo de la recibo ${inv.number}?\n\nDejará de aparecer en la ficha de ${activeConvo.client.name} pero seguirá perteneciendo a ${ownerClient?.name || "su dueño"}.`)) {
                                            setInvoices(prev => prev.map(i =>
                                              i.id === inv.id
                                                ? { ...i, linkedClientIds: (i.linkedClientIds || []).filter(x => x !== activeConvo.client.id) }
                                                : i
                                            ));
                                          }
                                        }}
                                        title="Quitar vínculo (la recibo seguirá existiendo en su dueño original)"
                                        className="w-6 h-6 rounded-md bg-stone-100 hover:bg-red-100 hover:text-red-700 text-stone-500 grid place-items-center flex-shrink-0"
                                      >
                                        <X size={10} />
                                      </button>
                                    ) : isOpen ? (
                                      <span className="text-xs font-semibold text-orange-700">Abierto</span>
                                    ) : (
                                      <ChevronRight size={11} className="text-stone-400" />
                                    )}
                                  </div>
                                );
                              })
                            )}
                          </div>
                        </div>
                      </>
                    )}
                  </div>
                </div>

                {/* Tabs de canal */}
                <div className="flex gap-0.5 px-2 pt-2 bg-stone-50 border-b border-stone-200 overflow-x-auto flex-shrink-0">
                  {Object.entries(CHAT_CHANNELS).map(([id, info]) => {
                    const Icon = info.icon;
                    const active = activeChannel === id;
                    const count = activeConvo.messages.filter(m => m.channel === id).length;
                    const colors = CHAT_CHANNEL_CLASSES[info.color];
                    return (
                      <button
                        key={id}
                        onClick={() => setActiveChannel(id)}
                        className={`flex items-center gap-1.5 px-3 py-2 text-xs font-semibold rounded-t-lg transition border-b-2 flex-shrink-0 ${
                          active
                            ? `bg-white ${colors.text} border-current`
                            : "text-stone-500 hover:text-stone-700 border-transparent"
                        }`}
                      >
                        <Icon size={12} strokeWidth={1.8} />
                        {info.short || info.label.split(" ")[0]}
                        {count > 0 && (
                          <span className={`text-xs font-bold px-1.5 py-px rounded-full ${
                            active ? colors.bg : "bg-stone-200 text-stone-600"
                          }`}>{count}</span>
                        )}
                      </button>
                    );
                  })}
                </div>

                {/* Lista de mensajes */}
                <div
                  className="flex-1 overflow-y-auto p-4 space-y-2"
                  style={{ background: "linear-gradient(to bottom, #fafaf9, #f5f5f4)" }}
                >
                  {activeMessages.length === 0 ? (
                    <div className="text-center py-12">
                      <MessageCircle size={28} className="text-stone-300 mx-auto mb-2" />
                      <div className="text-sm font-semibold text-stone-700">
                        Sin mensajes en {CHAT_CHANNELS[activeChannel].label}
                      </div>
                      <div className="text-xs text-stone-500 mt-1">
                        Envía el primero para iniciar la conversación.
                      </div>
                    </div>
                  ) : (
                    activeMessages.map((msg, i) => {
                      const showDate = i === 0 ||
                        new Date(activeMessages[i - 1].timestamp).toDateString() !== new Date(msg.timestamp).toDateString();
                      return (
                        <Fragment key={msg.id}>
                          {showDate && (
                            <div className="text-center my-3">
                              <span className="inline-block px-3 py-1 rounded-full bg-white text-xs text-stone-600 font-semibold shadow-sm border border-stone-200">
                                {formatChatDate(msg.timestamp)}
                              </span>
                            </div>
                          )}
                          <ChatBubble message={msg} invoices={invoices} onOpenInvoice={openInvoiceTab} clients={clients} />
                        </Fragment>
                      );
                    })
                  )}
                </div>

                {/* Input */}
                <div className="border-t border-stone-200 p-3 flex items-end gap-2 bg-white flex-shrink-0 relative">
                  <div className="relative">
                    <button
                      onClick={() => setShowAttachMenu(v => !v)}
                      title="Adjuntar"
                      className={`w-9 h-9 rounded-lg grid place-items-center transition flex-shrink-0 ${
                        showAttachMenu ? "bg-orange-500 text-white rotate-45" : "bg-stone-100 hover:bg-stone-200 text-stone-600"
                      }`}
                    >
                      <Plus size={14} />
                    </button>
                    {showAttachMenu && (
                      <>
                        <div onClick={() => setShowAttachMenu(false)} className="fixed inset-0 z-30"></div>
                        <div className="absolute left-0 bottom-full mb-2 w-64 bg-white border border-stone-200 rounded-xl shadow-2xl z-40 overflow-hidden">
                          <button
                            onClick={() => { setShowAttachMenu(false); setShowImagePicker(true); }}
                            className="w-full flex items-start gap-2.5 p-3 hover:bg-orange-50 transition text-left border-b border-stone-100"
                          >
                            <div className="w-8 h-8 rounded-lg bg-blue-100 text-blue-700 grid place-items-center flex-shrink-0">
                              <Camera size={13} />
                            </div>
                            <div className="flex-1 min-w-0">
                              <div className="font-semibold text-sm">Foto</div>
                              <div className="text-xs text-stone-500 leading-snug">
                                Sube una imagen desde tu equipo.
                              </div>
                            </div>
                          </button>
                          <button
                            onClick={() => { setShowAttachMenu(false); setShowInvoicePicker(true); }}
                            className="w-full flex items-start gap-2.5 p-3 hover:bg-orange-50 transition text-left border-b border-stone-100"
                          >
                            <div className="w-8 h-8 rounded-lg bg-orange-100 text-orange-700 grid place-items-center flex-shrink-0">
                              <Receipt size={13} />
                            </div>
                            <div className="flex-1 min-w-0">
                              <div className="font-semibold text-sm">Recibo</div>
                              <div className="text-xs text-stone-500 leading-snug">
                                Comparte cualquier recibo existente.
                              </div>
                            </div>
                          </button>
                          <button
                            onClick={() => { setShowAttachMenu(false); setShowPaymentPicker(true); }}
                            className="w-full flex items-start gap-2.5 p-3 hover:bg-orange-50 transition text-left"
                          >
                            <div className="w-8 h-8 rounded-lg bg-emerald-100 text-emerald-700 grid place-items-center flex-shrink-0">
                              <Wallet size={13} />
                            </div>
                            <div className="flex-1 min-w-0">
                              <div className="font-semibold text-sm">Enviar método de pago</div>
                              <div className="text-xs text-stone-500 leading-snug">
                                Envía datos bancarios o wallet al cliente.
                              </div>
                            </div>
                          </button>
                        </div>
                      </>
                    )}
                  </div>
                  <textarea
                    value={draft}
                    onChange={(e) => setDraft(e.target.value)}
                    onKeyDown={(e) => {
                      if (e.key === "Enter" && !e.shiftKey) {
                        e.preventDefault();
                        handleSend();
                      }
                    }}
                    placeholder={`Mensaje vía ${CHAT_CHANNELS[activeChannel].label}...`}
                    rows={1}
                    className="flex-1 px-3 py-2 bg-stone-50 border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500 focus:bg-white resize-none"
                  />
                  <button
                    onClick={handleSend}
                    disabled={!draft.trim()}
                    className={`w-10 h-10 rounded-xl grid place-items-center text-white flex-shrink-0 transition ${
                      draft.trim()
                        ? "bg-emerald-500 hover:bg-emerald-600"
                        : "bg-stone-300 cursor-not-allowed"
                    }`}
                  >
                    <Send size={14} />
                  </button>
                </div>
              </>
            )}

            {/* === Panel lateral de ficha (cliente o mascota) ===
                Se superpone al chat sin cerrarlo. Click fuera o en X lo cierra.
                Pensado como vista de referencia rápida sin perder el contexto. */}
            {sidePanelTab && activeConvo && (
              <div className="absolute inset-0 bg-stone-900/30 z-20 flex justify-end" onClick={() => setSidePanelTab(null)}>
                <div
                  onClick={(e) => e.stopPropagation()}
                  className="bg-white w-full max-w-sm h-full shadow-2xl flex flex-col border-l border-stone-200 animate-in slide-in-from-right"
                >
                  {/* Header del panel */}
                  <div className="p-4 border-b border-stone-200 flex items-center gap-3 flex-shrink-0">
                    <div className={`w-10 h-10 rounded-xl grid place-items-center text-white flex-shrink-0 ${
                      sidePanelTab === "client"
                        ? "bg-gradient-to-br from-orange-500 to-orange-700"
                        : "bg-gradient-to-br from-emerald-500 to-emerald-700"
                    }`}>
                      {sidePanelTab === "client" ? <Search size={17} /> : <PawPrint size={17} />}
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="text-[10px] tracking-widest uppercase text-stone-500 font-bold">
                        {sidePanelTab === "client" ? "Ficha del cliente" : "Ficha de mascota"}
                      </div>
                      <div className="font-serif text-base font-semibold truncate">
                        {sidePanelTab === "client"
                          ? activeConvo.client.name
                          : (passports.find(p => p.code === sidePanelPetCode)?.name || "Mascota")}
                      </div>
                    </div>
                    <button
                      onClick={() => setSidePanelTab(null)}
                      className="w-8 h-8 rounded-lg bg-stone-100 hover:bg-stone-200 grid place-items-center text-stone-600"
                    >
                      <X size={14} />
                    </button>
                  </div>

                  {/* Body */}
                  <div className="flex-1 overflow-y-auto p-4 space-y-4">
                    {sidePanelTab === "client" && (
                      <>
                        {/* Datos de contacto */}
                        <div className="space-y-2">
                          <div className="text-[10px] tracking-widest uppercase text-stone-500 font-bold">Datos de contacto</div>
                          <div className="bg-stone-50 rounded-xl p-3 space-y-2 text-sm">
                            {activeConvo.client.phone && (
                              <div className="flex items-center gap-2">
                                <Phone size={12} className="text-stone-400 flex-shrink-0" />
                                <span className="text-stone-700">{activeConvo.client.phone}</span>
                              </div>
                            )}
                            {activeConvo.client.email && (
                              <div className="flex items-center gap-2">
                                <Mail size={12} className="text-stone-400 flex-shrink-0" />
                                <span className="text-stone-700 truncate">{activeConvo.client.email}</span>
                              </div>
                            )}
                            {activeConvo.client.cedula && (
                              <div className="flex items-center gap-2">
                                <UserCheck size={12} className="text-stone-400 flex-shrink-0" />
                                <span className="text-stone-700 font-mono">{activeConvo.client.cedula}</span>
                              </div>
                            )}
                            {activeConvo.client.address && (
                              <div className="flex items-start gap-2">
                                <MapPin size={12} className="text-stone-400 flex-shrink-0 mt-0.5" />
                                <span className="text-stone-700">{activeConvo.client.address}</span>
                              </div>
                            )}
                          </div>
                        </div>

                        {/* Resumen económico */}
                        {(activeConvo.client.segment || activeConvo.client.totalSpent != null) && (
                          <div className="space-y-2">
                            <div className="text-[10px] tracking-widest uppercase text-stone-500 font-bold">Resumen</div>
                            <div className="grid grid-cols-2 gap-2">
                              {activeConvo.client.segment && (
                                <div className="bg-stone-50 rounded-xl p-3">
                                  <div className="text-[10px] uppercase text-stone-500 font-semibold">Segmento</div>
                                  <div className="text-sm font-semibold mt-0.5">{activeConvo.client.segment}</div>
                                </div>
                              )}
                              {activeConvo.client.totalSpent != null && (
                                <div className="bg-stone-50 rounded-xl p-3">
                                  <div className="text-[10px] uppercase text-stone-500 font-semibold">Recibodo</div>
                                  <div className="text-sm font-semibold mt-0.5">${activeConvo.client.totalSpent.toLocaleString()}</div>
                                </div>
                              )}
                            </div>
                          </div>
                        )}

                        {/* Mascotas asociadas */}
                        {(activeConvo.client.petCodes || []).length > 0 && (
                          <div className="space-y-2">
                            <div className="text-[10px] tracking-widest uppercase text-stone-500 font-bold">
                              Mascotas ({(activeConvo.client.petCodes || []).length})
                            </div>
                            {(activeConvo.client.petCodes || []).map(code => {
                              const pet = passports.find(p => p.code === code);
                              if (!pet) return null;
                              return (
                                <button
                                  key={code}
                                  onClick={() => {
                                    setSidePanelPetCode(code);
                                    setSidePanelTab("pet");
                                  }}
                                  className="w-full bg-stone-50 hover:bg-emerald-50 rounded-xl p-3 flex items-center gap-3 text-left transition"
                                >
                                  <div className="w-9 h-9 rounded-lg bg-emerald-100 text-emerald-700 grid place-items-center flex-shrink-0">
                                    <PawPrint size={15} />
                                  </div>
                                  <div className="flex-1 min-w-0">
                                    <div className="font-semibold text-sm truncate">{pet.name}</div>
                                    <div className="text-xs text-stone-500 truncate">
                                      {pet.breed} · {pet.age || "edad N/D"}
                                    </div>
                                  </div>
                                  <ChevronRight size={14} className="text-stone-400 flex-shrink-0" />
                                </button>
                              );
                            })}
                          </div>
                        )}
                      </>
                    )}

                    {sidePanelTab === "pet" && (() => {
                      const pet = passports.find(p => p.code === sidePanelPetCode);
                      if (!pet) {
                        return <div className="text-sm text-stone-500 italic">Mascota no encontrada.</div>;
                      }
                      return (
                        <>
                          {/* Selector de mascota (si hay varias) */}
                          {(activeConvo.client.petCodes || []).length > 1 && (
                            <div className="flex flex-wrap gap-1.5">
                              {(activeConvo.client.petCodes || []).map(code => {
                                const p = passports.find(pp => pp.code === code);
                                if (!p) return null;
                                const active = code === sidePanelPetCode;
                                return (
                                  <button
                                    key={code}
                                    onClick={() => setSidePanelPetCode(code)}
                                    className={`text-xs font-semibold px-3 py-1.5 rounded-lg transition ${
                                      active
                                        ? "bg-emerald-600 text-white"
                                        : "bg-stone-100 text-stone-700 hover:bg-stone-200"
                                    }`}
                                  >
                                    {p.name}
                                  </button>
                                );
                              })}
                            </div>
                          )}

                          {/* Datos de la mascota */}
                          <div className="space-y-2">
                            <div className="text-[10px] tracking-widest uppercase text-stone-500 font-bold">Identidad</div>
                            <div className="bg-stone-50 rounded-xl p-3 space-y-2 text-sm">
                              <div className="flex justify-between">
                                <span className="text-stone-500">Código</span>
                                <span className="font-mono font-semibold">{pet.code}</span>
                              </div>
                              {pet.species && (
                                <div className="flex justify-between">
                                  <span className="text-stone-500">Especie</span>
                                  <span className="font-semibold">{pet.species}</span>
                                </div>
                              )}
                              {pet.breed && (
                                <div className="flex justify-between">
                                  <span className="text-stone-500">Raza</span>
                                  <span className="font-semibold">{pet.breed}</span>
                                </div>
                              )}
                              {pet.age && (
                                <div className="flex justify-between">
                                  <span className="text-stone-500">Edad</span>
                                  <span className="font-semibold">{pet.age}</span>
                                </div>
                              )}
                              {pet.weight && (
                                <div className="flex justify-between">
                                  <span className="text-stone-500">Peso</span>
                                  <span className="font-semibold">{pet.weight}</span>
                                </div>
                              )}
                              {pet.sex && (
                                <div className="flex justify-between">
                                  <span className="text-stone-500">Sexo</span>
                                  <span className="font-semibold">{pet.sex}</span>
                                </div>
                              )}
                            </div>
                          </div>

                          {/* Notas / observaciones */}
                          {pet.notes && (
                            <div className="space-y-2">
                              <div className="text-[10px] tracking-widest uppercase text-stone-500 font-bold">Notas</div>
                              <div className="bg-stone-50 rounded-xl p-3 text-sm text-stone-700">
                                {pet.notes}
                              </div>
                            </div>
                          )}
                        </>
                      );
                    })()}
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* === Modal: subir imagen === */}
      {showImagePicker && (
        <ChatImagePickerModal
          onClose={() => setShowImagePicker(false)}
          onSend={handleSendImage}
        />
      )}

      {/* === Modal: seleccionar recibo para enviar === */}
      {showInvoicePicker && activeConvo && (
        <ChatInvoicePickerModal
          invoices={invoices}
          activeClientId={activeConvo.client.id}
          clients={clients}
          onClose={() => setShowInvoicePicker(false)}
          onSend={handleSendInvoice}
        />
      )}

      {/* === Modal: seleccionar método de pago para enviar al cliente === */}
      {showPaymentPicker && activeConvo && (
        <ChatPaymentMethodPickerModal
          paymentMethods={paymentMethods}
          onClose={() => setShowPaymentPicker(false)}
          onSend={(method) => {
            const message = buildPaymentMethodMessage(method);
            // Enviar como mensaje regular del operador (canal activo)
            if (onSendMessage) onSendMessage(activeConvo.client.id, activeChannel, message);
            setShowPaymentPicker(false);
          }}
        />
      )}

      {/* === Modal: vincular cliente al chat === */}
      {showLinkClient && activeConvo && (
        <ChatLinkClientModal
          existingClients={clients}
          chatPhone={activeConvo.client.phone}
          onClose={() => setShowLinkClient(false)}
          onLink={handleLinkClient}
        />
      )}

      {/* === Modal: asociar recibos existentes al cliente del chat ===
          Lista TODAS las recibos del sistema agrupadas por cliente original.
          Reasigna clientId al cliente actual del chat (la recibo se "muda" de cliente).
          Útil para resolver casos donde un cliente con varios teléfonos generó recibos
          como visitante y queremos consolidar todo en su ficha real. */}
      {showAssociateInvoice && activeConvo && setInvoices && (
        <div
          onClick={() => { setShowAssociateInvoice(false); setAssociateSearch(""); }}
          className="fixed inset-0 bg-stone-900/80 z-50 flex justify-center items-center p-4"
        >
          <div
            onClick={(e) => e.stopPropagation()}
            className="bg-white rounded-2xl w-full max-w-2xl max-h-[85vh] shadow-2xl overflow-hidden flex flex-col"
          >
            {/* Header */}
            <div className="p-5 border-b border-stone-200 bg-orange-50 flex items-center gap-3">
              <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-orange-500 to-orange-700 text-white grid place-items-center flex-shrink-0">
                <Receipt size={18} />
              </div>
              <div className="flex-1 min-w-0">
                <div className="text-xs tracking-widest uppercase text-orange-700 font-bold">
                  Vincular recibo
                </div>
                <h3 className="font-serif text-lg font-semibold truncate">
                  Asociar a {activeConvo.client.name}
                </h3>
              </div>
              <button
                onClick={() => { setShowAssociateInvoice(false); setAssociateSearch(""); }}
                className="w-9 h-9 rounded-lg bg-white hover:bg-stone-100 border border-stone-200 grid place-items-center text-stone-600"
              >
                <X size={14} />
              </button>
            </div>

            {/* Body */}
            <div className="flex-1 overflow-y-auto">
              <div className="p-4 border-b border-stone-200 bg-stone-50 sticky top-0 z-10">
                <div className="relative">
                  <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-stone-400" />
                  <input
                    autoFocus
                    value={associateSearch}
                    onChange={(e) => setAssociateSearch(e.target.value)}
                    placeholder="Buscar por número de recibo, cliente o monto..."
                    className="w-full pl-10 pr-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
                  />
                </div>
                <div className="text-[11px] text-stone-500 mt-2 italic">
                  La recibo sigue perteneciendo a su cliente original y solo se hace visible también en esta ficha. Útil para clientes con varios números o que también pagaron recibos de otros.
                </div>
              </div>

              <div className="divide-y divide-stone-100">
                {(() => {
                  // Excluir tanto las del cliente como las que ya están vinculadas
                  const cid = activeConvo.client.id;
                  const q = associateSearch.toLowerCase().trim();
                  const otherInvoices = invoices.filter(inv =>
                    inv.clientId !== cid &&
                    !(Array.isArray(inv.linkedClientIds) && inv.linkedClientIds.includes(cid))
                  );
                  const matched = q
                    ? otherInvoices.filter(inv => {
                        const ownerClient = clients.find(c => c.id === inv.clientId);
                        return (
                          (inv.number || "").toLowerCase().includes(q) ||
                          (ownerClient?.name || "").toLowerCase().includes(q) ||
                          String(inv.total || "").includes(q)
                        );
                      })
                    : otherInvoices;

                  if (matched.length === 0) {
                    return (
                      <div className="p-10 text-center text-sm text-stone-500 italic">
                        {q ? "Ninguna recibo coincide con la búsqueda." : "No hay recibos disponibles para asociar."}
                      </div>
                    );
                  }

                  return matched.slice(0, 50).map(inv => {
                    const ownerClient = clients.find(c => c.id === inv.clientId);
                    return (
                      <div key={inv.id} className="p-3 flex items-center gap-3 hover:bg-stone-50 transition">
                        <div className="w-9 h-9 rounded-lg bg-stone-100 text-stone-600 grid place-items-center flex-shrink-0">
                          <Receipt size={14} />
                        </div>
                        <div className="flex-1 min-w-0">
                          <div className="flex items-baseline gap-2">
                            <span className="font-mono text-sm font-bold text-stone-800">{inv.number}</span>
                            <InvoiceStateBadge state={inv.state} />
                          </div>
                          <div className="text-xs text-stone-500 mt-0.5">
                            Cliente actual: <span className="font-semibold text-stone-700">{ownerClient?.name || "Sin cliente"}</span> · {inv.issueDate}
                          </div>
                        </div>
                        <div className="text-right flex-shrink-0">
                          <div className="font-bold text-sm text-stone-900">${(inv.total || 0).toFixed(2)}</div>
                          <div className="text-[10px] text-stone-500">{inv.items?.length || 0} ítems</div>
                        </div>
                        <button
                          onClick={() => {
                            // Crear vínculo: agregamos el id del cliente actual al array
                            // linkedClientIds de la recibo. La recibo sigue siendo del
                            // dueño original — solo aparece también en la vista del cliente
                            // actual. Es un modelo de "shadow link", no de reasignación.
                            setInvoices(prev => prev.map(i => {
                              if (i.id !== inv.id) return i;
                              const existing = Array.isArray(i.linkedClientIds) ? i.linkedClientIds : [];
                              if (existing.includes(activeConvo.client.id)) return i;
                              return { ...i, linkedClientIds: [...existing, activeConvo.client.id] };
                            }));
                            setAssociateSearch("");
                            setShowAssociateInvoice(false);
                          }}
                          className="px-3 py-2 rounded-lg bg-orange-600 hover:bg-orange-700 text-white text-xs font-semibold flex items-center gap-1 flex-shrink-0"
                        >
                          <Plus size={11} strokeWidth={2.5} />
                          Vincular
                        </button>
                      </div>
                    );
                  });
                })()}
              </div>
            </div>

            {/* Footer */}
            <div className="p-3 border-t border-stone-200 bg-stone-50 text-center text-[11px] text-stone-500">
              Mostrando primeras 50 recibos. Usa la búsqueda para filtrar.
            </div>
          </div>
        </div>
      )}

      {/* === Ventana flotante: Agendar cita ===
          Se mantiene abierta mientras se sigue conversando. Posicionada en la
          esquina inferior izquierda para no tapar el composer ni la recibo
          flotante (que está abajo-derecha). */}
      {showAppointmentFloat && activeConvo && (() => {
        const canConfigMsg = userRole === "super" || getFieldLevel(permissions, userRole, "clients", "messaging", "msg-config") !== "hidden";
        return (
        <FloatingAppointmentForm
          client={activeConvo.client}
          passports={passports}
          agendaEvents={agendaEvents}
          setAgendaEvents={setAgendaEvents}
          modules={modules}
          sedes={sedes}
          services={services}
          invoices={invoices}
          setInvoices={setInvoices}
          groomingBookings={groomingBookings}
          setGroomingBookings={setGroomingBookings}
          onClose={() => setShowAppointmentFloat(false)}
          onSendConfirmation={(text) => {
            if (activeConvo && onSendMessage) {
              const channel = activeChannel || "whatsapp";
              onSendMessage(activeConvo.client.id, channel, text);
            }
          }}
          userName={user?.name || ""}
          msgTemplate={msgTemplate}
          setMsgTemplate={setMsgTemplate}
          canConfigMessages={canConfigMsg}
          initialShowConfig={appointmentAutoConfig}
          onConfigConsumed={() => setAppointmentAutoConfig(false)}
        />
        );
      })()}

      {/* === Panel flotante: detalle de recibo abierta en pestaña === */}
      {activeInvoiceTabId && (() => {
        const tab = openInvoiceTabs.find(t => t.id === activeInvoiceTabId);
        const inv = tab && invoices.find(i => i.id === tab.invoiceId);
        if (!inv) return null;
        return (
          <div className="fixed bottom-4 right-4 w-full max-w-sm bg-white border border-stone-200 rounded-2xl shadow-2xl z-40 overflow-hidden">
            <div className="p-3 border-b border-stone-200 bg-orange-50 flex items-center gap-2">
              <Receipt size={13} className="text-orange-700 flex-shrink-0" />
              <div className="flex-1 min-w-0">
                <div className="font-mono text-sm font-bold text-stone-800">{inv.number}</div>
                <div className="text-xs text-stone-500 truncate">{inv.clientName}</div>
              </div>
              <button
                onClick={() => closeInvoiceTab(tab.id)}
                className="w-7 h-7 rounded hover:bg-orange-100 grid place-items-center text-stone-500"
              >
                <X size={11} />
              </button>
            </div>
            <div className="p-4 space-y-3 max-h-96 overflow-y-auto">
              <div className="flex items-center justify-between gap-2">
                <InvoiceStateBadge state={inv.state} />
                <span className="text-xs text-stone-500 font-mono">{inv.issueDate}</span>
              </div>
              <div className="space-y-1.5">
                {inv.items.map(item => (
                  <div key={item.id} className="flex items-baseline justify-between text-sm">
                    <span className="text-stone-700 truncate flex-1">{item.description}</span>
                    <span className="font-mono font-semibold text-stone-800 ml-2">${item.subtotal.toFixed(2)}</span>
                  </div>
                ))}
              </div>
              <div className="pt-2 border-t border-stone-200 flex items-baseline justify-between">
                <span className="text-xs tracking-widest uppercase text-stone-500 font-bold">Total</span>
                <span className="font-serif text-xl font-bold text-orange-700">${inv.total.toFixed(2)}</span>
              </div>
              {inv.balance > 0 && (
                <div className="bg-amber-50 border border-amber-200 rounded-lg p-2 text-xs text-amber-900">
                  Saldo pendiente: <strong>${inv.balance.toFixed(2)}</strong>
                </div>
              )}
              <button
                onClick={() => onGoToInvoice && onGoToInvoice(inv.id)}
                className="w-full px-3 py-2 rounded-lg bg-stone-900 hover:bg-stone-800 text-white text-xs font-semibold flex items-center justify-center gap-1.5 transition"
              >
                <ExternalLink size={11} /> Abrir en Ventas
              </button>
            </div>
          </div>
        );
      })()}
    </div>
  );
}

// === Ventana flotante: Agendar cita desde el chat ===
// Se mantiene abierta sin bloquear la conversación. Se puede chatear y llenar
// el formulario al mismo tiempo. Posición: esquina inferior izquierda, con
// drag para moverla si estorba.
// === Modal global: Configurar plantilla de mensaje de reserva ===
// Se abre desde el botón ⚙️ del header. Los cambios son inmediatos y aplican
// a todas las reservas que se creen después. Esto permite al admin/super
// definir de manera centralizada qué se incluye (ej. ocultar precio para que
// los vendedores no lo compartan por error).
function MsgTemplateConfigModal({ msgTemplate, setMsgTemplate, onClose }) {
  const FIELDS = [
    { key: "showPetName",  label: "Nombre de mascota", icon: "🐾", desc: "Incluye el nombre de la mascota en el saludo." },
    { key: "showDate",     label: "Fecha de la cita",  icon: "📅", desc: "Día de la semana y fecha." },
    { key: "showTime",     label: "Hora",              icon: "🕐", desc: "Hora programada de la cita." },
    { key: "showServices", label: "Lista de servicios", icon: "📋", desc: "Nombres de los servicios agendados." },
    { key: "showPrice",    label: "Precio estimado",   icon: "💰", desc: "Monto total estimado. Desactívalo si no quieres que el cliente vea precios." },
    { key: "showDuration", label: "Duración total",    icon: "⏱️", desc: "Suma de duración de todos los servicios." },
    { key: "showNotes",    label: "Notas / indicaciones", icon: "📝", desc: "Indicaciones especiales escritas al agendar." },
  ];

  // Preview de ejemplo
  const previewParts = [];
  if (msgTemplate.showGreeting) {
    let line = msgTemplate.greeting || "✅ Reserva confirmada";
    if (msgTemplate.showPetName) line += " para Toby";
    if (msgTemplate.showDate) line += ": jueves 2026-05-15";
    if (msgTemplate.showTime) line += " a las 10:00";
    line += ".";
    previewParts.push(line);
  }
  if (msgTemplate.showServices) previewParts.push("📋 Servicios: Consulta general, Vacuna polivalente");
  if (msgTemplate.showPrice) previewParts.push("💰 Estimado: $77.00");
  if (msgTemplate.showDuration) previewParts.push("⏱️ Duración: 60 minutos");
  if (msgTemplate.showNotes) previewParts.push("📝 Notas: Traer cartilla de vacunación");
  if (msgTemplate.showClosing && msgTemplate.closing) previewParts.push(msgTemplate.closing);
  const previewText = previewParts.join("\n");

  return (
    <div onClick={onClose} className="fixed inset-0 bg-stone-900/60 z-50 flex justify-center items-start p-4 sm:p-12 overflow-y-auto">
      <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl w-full max-w-lg shadow-2xl overflow-hidden flex flex-col" style={{ maxHeight: "calc(100vh - 6rem)" }}>
        {/* Header */}
        <div className="p-5 bg-gradient-to-br from-orange-500 to-orange-600 text-white flex items-center gap-3 flex-shrink-0">
          <div className="w-11 h-11 rounded-xl bg-white/20 backdrop-blur grid place-items-center flex-shrink-0">
            <Settings size={20} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase opacity-90 font-semibold">Configuración global</div>
            <h3 className="font-serif text-xl font-semibold mt-0.5">Mensaje de reserva</h3>
          </div>
          <button onClick={onClose} className="w-8 h-8 rounded-full bg-white/20 hover:bg-white/30 grid place-items-center transition flex-shrink-0">
            <X size={14} />
          </button>
        </div>

        {/* Body */}
        <div className="flex-1 overflow-y-auto p-5 space-y-4">
          <div className="bg-orange-50 border border-orange-200 rounded-xl p-3 text-xs text-orange-900 leading-relaxed">
            <span className="font-semibold">Plantilla global.</span> Estos ajustes definen qué información se incluye
            en el mensaje de confirmación que se envía al cliente al agendar una reserva desde el chat.
            Los cambios aplican a todos los usuarios de inmediato.
          </div>

          {/* Saludo */}
          <div className="space-y-2">
            <div className="flex items-center gap-3">
              <ToggleSwitch on={msgTemplate.showGreeting} onChange={(v) => setMsgTemplate(p => ({ ...p, showGreeting: v }))} />
              <div>
                <div className="text-sm font-semibold text-stone-800">Saludo</div>
                <div className="text-xs text-stone-500">Primera línea del mensaje.</div>
              </div>
            </div>
            {msgTemplate.showGreeting && (
              <input
                type="text"
                value={msgTemplate.greeting}
                onChange={(e) => setMsgTemplate(p => ({ ...p, greeting: e.target.value }))}
                className="w-full px-3 py-2 border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-400"
                placeholder="Ej: ✅ Reserva confirmada"
              />
            )}
          </div>

          {/* Campos individuales */}
          <div className="space-y-1">
            {FIELDS.map(f => (
              <div key={f.key} className={`flex items-center gap-3 p-2.5 rounded-xl transition ${
                msgTemplate[f.key] ? "bg-orange-50" : "hover:bg-stone-50"
              }`}>
                <ToggleSwitch on={msgTemplate[f.key]} onChange={(v) => setMsgTemplate(p => ({ ...p, [f.key]: v }))} />
                <div className="flex-1 min-w-0">
                  <div className="text-sm text-stone-800 flex items-center gap-1.5">
                    <span>{f.icon}</span>
                    <span className="font-semibold">{f.label}</span>
                    {f.key === "showPrice" && !msgTemplate.showPrice && (
                      <span className="text-[9px] font-bold px-1.5 py-px rounded bg-red-100 text-red-700">OCULTO</span>
                    )}
                  </div>
                  <div className="text-xs text-stone-500">{f.desc}</div>
                </div>
              </div>
            ))}
          </div>

          {/* Despedida */}
          <div className="space-y-2">
            <div className="flex items-center gap-3">
              <ToggleSwitch on={msgTemplate.showClosing} onChange={(v) => setMsgTemplate(p => ({ ...p, showClosing: v }))} />
              <div>
                <div className="text-sm font-semibold text-stone-800">Despedida</div>
                <div className="text-xs text-stone-500">Última línea del mensaje.</div>
              </div>
            </div>
            {msgTemplate.showClosing && (
              <input
                type="text"
                value={msgTemplate.closing}
                onChange={(e) => setMsgTemplate(p => ({ ...p, closing: e.target.value }))}
                className="w-full px-3 py-2 border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-400"
                placeholder="Ej: ¡Te esperamos!"
              />
            )}
          </div>

          {/* Vista previa */}
          <div>
            <div className="text-[10px] tracking-widest uppercase text-stone-400 font-bold mb-1.5">Vista previa del mensaje</div>
            <div className="bg-emerald-50 border border-emerald-200 rounded-xl p-3.5 text-sm text-emerald-900 whitespace-pre-line leading-relaxed">
              {previewText || <span className="italic text-stone-400">Activa al menos un campo para generar el mensaje.</span>}
            </div>
          </div>
        </div>

        {/* Footer */}
        <div className="p-3 border-t border-stone-200 bg-stone-50 flex gap-2 flex-shrink-0">
          <button
            onClick={onClose}
            className="flex-1 px-3 py-2.5 rounded-xl text-sm font-semibold bg-orange-600 hover:bg-orange-700 text-white transition flex items-center justify-center gap-2"
          >
            <Check size={14} /> Guardar configuración
          </button>
        </div>
      </div>
    </div>
  );
}

// Mini-toggle reutilizable en formularios compactos
function ToggleSwitch({ on, onChange }) {
  return (
    <button
      type="button"
      onClick={() => onChange(!on)}
      className={`w-7 h-4 rounded-full relative transition flex-shrink-0 ${on ? "bg-orange-500" : "bg-stone-300"}`}
    >
      <span className={`absolute top-0.5 w-3 h-3 rounded-full bg-white shadow transition ${on ? "left-3.5" : "left-0.5"}`}></span>
    </button>
  );
}

function FloatingAppointmentForm({ client, passports = [], agendaEvents = [], setAgendaEvents, modules = [], sedes = [], services = [], invoices = [], setInvoices, groomingBookings = [], setGroomingBookings, onClose, onSendConfirmation, userName = "", msgTemplate = {}, setMsgTemplate, canConfigMessages = false, initialShowConfig = false, onConfigConsumed }) {
  const clientPets = useMemo(() => {
    const codes = client?.petCodes || [];
    return passports.filter(p => codes.includes(p.code));
  }, [client, passports]);

  const tomorrow = new Date();
  tomorrow.setDate(tomorrow.getDate() + 1);
  const pad = (n) => String(n).padStart(2, "0");
  const defaultDate = `${tomorrow.getFullYear()}-${pad(tomorrow.getMonth() + 1)}-${pad(tomorrow.getDate())}`;

  const [type, setType] = useState("vet");
  const [petCode, setPetCode] = useState(clientPets[0]?.code || "");
  const [date, setDate] = useState(defaultDate);
  const [time, setTime] = useState("10:00");
  const [reason, setReason] = useState("");
  const [sendConfirm, setSendConfirm] = useState(true);
  const [saved, setSaved] = useState(false);
  const [showConfig, setShowConfig] = useState(initialShowConfig);

  // Si se abrió desde "Configurar mensaje", expandir el panel de config al montar
  useEffect(() => {
    if (initialShowConfig) {
      setShowConfig(true);
      onConfigConsumed?.();
    }
  }, []);

  // === Servicios seleccionados ===
  // Filtrados por tipo (vet/grooming) y activos. El usuario puede agregar
  // varios servicios; cada uno se convierte en un ítem de la recibo.
  const [selectedServiceIds, setSelectedServiceIds] = useState([]);
  const [showServicePicker, setShowServicePicker] = useState(false);

  const availableServices = useMemo(() => {
    const moduleType = type === "vet" ? "vet" : type === "grooming" ? "grooming" : null;
    if (!moduleType) return [];
    return services.filter(s => s.module === moduleType && s.active !== false);
  }, [services, type]);

  const selectedServices = availableServices.filter(s => selectedServiceIds.includes(s.id));
  const totalPrice = selectedServices.reduce((sum, s) => sum + (s.price || 0), 0);
  const totalDuration = selectedServices.reduce((sum, s) => sum + (s.duration || 30), 0);

  const toggleService = (svcId) => {
    setSelectedServiceIds(prev =>
      prev.includes(svcId) ? prev.filter(id => id !== svcId) : [...prev, svcId]
    );
  };

  // Al cambiar tipo, limpiar servicios seleccionados (cambia el catálogo)
  const changeType = (t) => {
    if (t !== type) { setType(t); setSelectedServiceIds([]); }
  };

  // Drag — posición inicial en la zona visible del chat (no detrás del sidebar)
  const [pos, setPos] = useState({ x: 360, top: null });
  const dragRef = useRef(null);
  const onDragStart = (e) => {
    e.preventDefault();
    const el = dragRef.current;
    if (!el) return;
    const rect = el.getBoundingClientRect();
    const offX = e.clientX - rect.left;
    const offY = e.clientY - rect.top;
    const handleMove = (ev) => {
      setPos({ x: Math.max(0, ev.clientX - offX), top: Math.max(0, ev.clientY - offY) });
    };
    const handleUp = () => {
      window.removeEventListener("mousemove", handleMove);
      window.removeEventListener("mouseup", handleUp);
      document.body.style.cursor = "";
      document.body.style.userSelect = "";
    };
    document.body.style.cursor = "grabbing";
    document.body.style.userSelect = "none";
    window.addEventListener("mousemove", handleMove);
    window.addEventListener("mouseup", handleUp);
  };

  const pet = passports.find(p => p.code === petCode);
  const valid = date && time && selectedServices.length > 0;

  // Construye el mensaje de confirmación según la plantilla configurada.
  // Declarado DESPUÉS de selectedServices y pet para evitar TDZ.
  const buildConfirmMessage = (svcsArg, petArg) => {
    const t = msgTemplate;
    const parts = [];
    const petObj = petArg || pet;
    const svcs = svcsArg || selectedServices;
    const dayNames = ["domingo","lunes","martes","miércoles","jueves","viernes","sábado"];
    const d = new Date(date + "T" + (time || "10:00"));
    const dayName = dayNames[d.getDay()] || "";

    if (t.showGreeting) {
      let line = t.greeting || "✅ Reserva confirmada";
      if (t.showPetName && petObj?.name) line += ` para ${petObj.name}`;
      if (t.showDate) line += `: ${dayName} ${date}`;
      if (t.showTime) line += ` a las ${time}`;
      line += ".";
      parts.push(line);
    }
    if (t.showServices && svcs.length > 0) {
      parts.push(`📋 Servicios: ${svcs.map(s => s.name).join(", ")}`);
    }
    if (t.showPrice && svcs.length > 0) {
      const price = svcs.reduce((sum, s) => sum + (s.price || 0), 0);
      parts.push(`💰 Estimado: $${price.toFixed(2)}`);
    }
    if (t.showDuration && svcs.length > 0) {
      const dur = svcs.reduce((sum, s) => sum + (s.duration || 0), 0);
      parts.push(`⏱️ Duración: ${dur} minutos`);
    }
    if (t.showNotes && reason.trim()) {
      parts.push(`📝 Notas: ${reason.trim()}`);
    }
    if (t.showClosing && t.closing) {
      parts.push(t.closing);
    }
    return parts.join("\n");
  };

  // Preview en vivo del mensaje
  const messagePreview = useMemo(
    () => buildConfirmMessage(selectedServices, pet),
    [msgTemplate, selectedServices, pet, date, time, reason]
  );

  const handleCreate = () => {
    const ts = Date.now().toString(36);
    const evtId = `evt-chat-${ts}`;
    const invoiceId = `inv-chat-${ts}`;
    const invoiceNumber = `CH-${String(Math.floor(Math.random() * 100000)).padStart(5, "0")}`;
    const mainService = selectedServices[0];
    const titleText = selectedServices.length === 1
      ? mainService.name
      : `${mainService.name} +${selectedServices.length - 1}`;

    // 1. Evento de agenda con flag source:"chat" para que los kanbans lo detecten
    const newEvent = {
      id: evtId,
      type,
      date,
      time,
      duration: totalDuration,
      pet: pet?.name || "",
      petCode: pet?.code || null,
      species: pet?.species || null,
      breed: pet?.breed || "",
      owner: client.name,
      professional: userName || null,
      title: titleText,
      reason: reason.trim() || selectedServices.map(s => s.name).join(", "),
      room: mainService?.room || null,
      status: "confirmada",
      price: totalPrice,
      clientId: client.id,
      invoiceId,
      invoiceNumber,
      moduleId: null,
      // Flag clave: indica que este evento se creó desde el chat y debe generar
      // una reserva en el kanban + un borrador de recibo. Los módulos vet y
      // grooming lo detectan vía useEffect y crean la entrada correspondiente.
      source: "chat",
      serviceIds: selectedServiceIds,
    };
    setAgendaEvents(prev => [newEvent, ...prev]);

    // 2. Recibo borrador con los servicios seleccionados
    if (setInvoices) {
      const items = selectedServices.map((s, i) => ({
        id: `item-${i}`,
        description: s.name,
        qty: 1,
        unit: s.price || 0,
        total: s.price || 0,
        subtotal: s.price || 0,
      }));
      const subtotal = items.reduce((a, it) => a + it.total, 0);
      const tax = Math.round(subtotal * 0.16);
      const total = subtotal + tax;
      const newInvoice = {
        id: invoiceId,
        number: invoiceNumber,
        clientId: client.id,
        clientName: client.name,
        state: "borrador",
        issueDate: new Date().toISOString().slice(0, 10),
        dueDate: date,
        items,
        subtotal,
        tax,
        total,
        paid: 0,
        balance: total,
        payments: [],
        source: "chat",
        appointmentDate: date,
        appointmentTime: time,
        sedeId: client.sedeOrigenId || null,
      };
      setInvoices(prev => [...prev, newInvoice]);
    }

    // 3. Booking de grooming (si es tipo grooming) — para que aparezca en el
    //    kanban de GroomingOpsView como "Por hacer" el día de la cita.
    if (type === "grooming" && setGroomingBookings) {
      const bookingId = `bk-chat-${ts}`;
      // Heredar moduleId del servicio seleccionado. Si el servicio no lo trae
      // (catálogo legacy), fallback al grooming base "grooming-ops". Sin esto
      // el booking quedaría huérfano y solo aparecería en Pet 1.
      const groomingModuleId = mainService?.moduleId || "grooming-ops";
      const newBooking = {
        id: bookingId,
        clientId: client.id,
        petName: pet?.name || "Sin nombre",
        petCode: pet?.code || null,
        species: pet?.species || "dog",
        breed: pet?.breed || "",
        owner: client.name,
        date,
        dropOff: time,
        pickup: null,
        status: "pending",
        services: selectedServices.map(s => s.name),
        suppliesUsed: [],
        notes: reason.trim() || "",
        professional: userName || null,
        invoiceId,
        source: "chat",
        moduleId: groomingModuleId,
        sedeId: client.sedeOrigenId || null,
      };
      setGroomingBookings(prev => [...prev, newBooking]);
    }

    // 4. Mensaje de confirmación (usa la plantilla configurable)
    if (sendConfirm && onSendConfirmation) {
      const msg = buildConfirmMessage(selectedServices, pet);
      onSendConfirmation(msg);
    }

    setSaved(true);
    setTimeout(() => { setSaved(false); onClose(); }, 2200);
  };

  const TYPE_OPTIONS = [
    { id: "vet",      label: "Veterinaria", icon: Stethoscope, color: "bg-orange-100 text-orange-700 border-orange-300" },
    { id: "grooming", label: "Grooming",    icon: Scissors, color: "bg-emerald-100 text-emerald-700 border-emerald-300" },
  ];

  return (
    <>
    {/* Backdrop sutil (click para cerrar) */}
    <div onClick={onClose} className="fixed inset-0 bg-stone-900/30 z-40" />
    <div
      ref={dragRef}
      className="fixed top-0 right-0 bottom-0 z-50 w-96 bg-white border-l border-stone-200 shadow-2xl flex flex-col"
    >
      {/* Header */}
      <div
        className="p-3 bg-gradient-to-r from-orange-500 to-orange-600 text-white flex items-center gap-2 flex-shrink-0 select-none"
      >
        <div className="w-8 h-8 rounded-lg bg-white/20 grid place-items-center flex-shrink-0">
          <CalendarPlus size={15} />
        </div>
        <div className="flex-1 min-w-0">
          <div className="text-[10px] tracking-widest uppercase opacity-80 font-semibold">Agendar reserva</div>
          <div className="text-sm font-semibold truncate">{client.name}</div>
        </div>
        {selectedServices.length > 0 && (
          <span className="text-xs font-bold bg-white/20 px-2 py-0.5 rounded-full">
            ${totalPrice.toFixed(0)}
          </span>
        )}
        <button onClick={onClose} className="w-7 h-7 rounded-full bg-white/20 hover:bg-white/30 grid place-items-center transition flex-shrink-0">
          <X size={12} />
        </button>
      </div>

      {/* Body */}
      <div className="flex-1 overflow-y-auto p-3 space-y-3">
        {saved ? (
          <div className="py-6 text-center">
            <div className="w-12 h-12 rounded-full bg-emerald-100 text-emerald-600 grid place-items-center mx-auto mb-2">
              <CheckCircle size={22} />
            </div>
            <div className="font-semibold text-emerald-800">¡Reserva agendada!</div>
            <div className="text-xs text-stone-500 mt-1">Recibo en borrador creada · Evento en agenda.</div>
          </div>
        ) : (
          <>
            {/* Tipo */}
            <div className="flex gap-1.5">
              {TYPE_OPTIONS.map(t => {
                const Ic = t.icon;
                return (
                  <button
                    key={t.id}
                    type="button"
                    onClick={() => changeType(t.id)}
                    className={`flex-1 flex items-center justify-center gap-1.5 text-xs font-semibold py-2 rounded-xl border transition ${
                      type === t.id ? t.color : "bg-white border-stone-200 text-stone-500 hover:border-stone-300"
                    }`}
                  >
                    <Ic size={13} /> {t.label}
                  </button>
                );
              })}
            </div>

            {/* Servicios seleccionados */}
            <div>
              <div className="flex items-center justify-between mb-1.5">
                <label className="text-[10px] tracking-widest uppercase text-stone-500 font-semibold">
                  Servicios {selectedServices.length > 0 && `· ${selectedServices.length}`}
                </label>
                <button
                  type="button"
                  onClick={() => setShowServicePicker(!showServicePicker)}
                  className="text-[11px] font-semibold text-orange-600 hover:text-orange-700 flex items-center gap-0.5"
                >
                  <Plus size={11} /> Agregar
                </button>
              </div>
              {/* Servicios ya seleccionados */}
              {selectedServices.length > 0 && (
                <div className="space-y-1 mb-2">
                  {selectedServices.map(s => (
                    <div key={s.id} className="flex items-center gap-2 p-2 bg-orange-50 border border-orange-200 rounded-lg">
                      <div className="flex-1 min-w-0">
                        <div className="text-xs font-semibold text-stone-800 truncate">{s.name}</div>
                        <div className="text-[10px] text-stone-500">{s.duration}min · ${s.price}</div>
                      </div>
                      <button
                        onClick={() => toggleService(s.id)}
                        className="w-5 h-5 rounded bg-white border border-stone-200 hover:border-red-300 grid place-items-center text-stone-400 hover:text-red-500 flex-shrink-0"
                      >
                        <X size={9} />
                      </button>
                    </div>
                  ))}
                  <div className="flex items-center justify-between px-1 text-[11px] text-stone-500">
                    <span>Duración total: {totalDuration}min</span>
                    <span className="font-semibold text-orange-700">Estimado: ${totalPrice.toFixed(2)}</span>
                  </div>
                </div>
              )}
              {/* Picker desplegable */}
              {showServicePicker && (
                <div className="border border-stone-200 rounded-xl overflow-hidden mb-2 max-h-40 overflow-y-auto">
                  {availableServices.length === 0 ? (
                    <div className="p-3 text-xs text-stone-400 text-center italic">No hay servicios configurados para este tipo.</div>
                  ) : (
                    availableServices.map(s => {
                      const picked = selectedServiceIds.includes(s.id);
                      return (
                        <button
                          key={s.id}
                          type="button"
                          onClick={() => { toggleService(s.id); }}
                          className={`w-full flex items-center gap-2 px-3 py-2 text-left transition border-b border-stone-100 last:border-0 ${
                            picked ? "bg-orange-50" : "hover:bg-stone-50"
                          }`}
                        >
                          <div className={`w-4 h-4 rounded flex-shrink-0 grid place-items-center border ${
                            picked ? "bg-orange-600 border-orange-600" : "border-stone-300"
                          }`}>
                            {picked && <Check size={10} className="text-white" strokeWidth={3} />}
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="text-xs font-semibold text-stone-700 truncate">{s.name}</div>
                          </div>
                          <div className="text-[10px] text-stone-500 flex-shrink-0">{s.duration}m</div>
                          <div className="text-xs font-bold text-stone-700 flex-shrink-0">${s.price}</div>
                        </button>
                      );
                    })
                  )}
                </div>
              )}
              {selectedServices.length === 0 && !showServicePicker && (
                <button
                  type="button"
                  onClick={() => setShowServicePicker(true)}
                  className="w-full p-3 rounded-xl border-2 border-dashed border-stone-200 hover:border-orange-300 text-center text-xs text-stone-400 hover:text-orange-600 transition"
                >
                  Haz clic en "+ Agregar" para seleccionar servicios del catálogo
                </button>
              )}
            </div>

            {/* Mascota */}
            {clientPets.length > 0 && (
              <div>
                <label className="text-[10px] tracking-widest uppercase text-stone-500 font-semibold block mb-1">Mascota</label>
                <select
                  value={petCode}
                  onChange={(e) => setPetCode(e.target.value)}
                  className="w-full px-2.5 py-2 border border-stone-200 rounded-lg text-sm outline-none focus:border-orange-400"
                >
                  <option value="">— Sin mascota —</option>
                  {clientPets.map(p => (
                    <option key={p.code} value={p.code}>{p.name} · {p.species}</option>
                  ))}
                </select>
              </div>
            )}

            {/* Fecha + Hora */}
            <div className="grid grid-cols-2 gap-2">
              <div>
                <label className="text-[10px] tracking-widest uppercase text-stone-500 font-semibold block mb-1">Fecha</label>
                <input type="date" value={date} onChange={(e) => setDate(e.target.value)}
                  className="w-full px-2.5 py-2 border border-stone-200 rounded-lg text-sm outline-none focus:border-orange-400" />
              </div>
              <div>
                <label className="text-[10px] tracking-widest uppercase text-stone-500 font-semibold block mb-1">Hora</label>
                <input type="time" value={time} onChange={(e) => setTime(e.target.value)}
                  className="w-full px-2.5 py-2 border border-stone-200 rounded-lg text-sm outline-none focus:border-orange-400" />
              </div>
            </div>

            {/* Notas */}
            <div>
              <label className="text-[10px] tracking-widest uppercase text-stone-500 font-semibold block mb-1">Notas (opcional)</label>
              <textarea value={reason} onChange={(e) => setReason(e.target.value)}
                placeholder="Indicaciones especiales..."
                rows={2} className="w-full px-2.5 py-2 border border-stone-200 rounded-lg text-sm outline-none focus:border-orange-400 resize-none" />
            </div>

            {/* Toggle confirmación + botón config */}
            <div className="space-y-2">
              <div className="flex items-center gap-2">
                <button type="button" onClick={() => setSendConfirm(!sendConfirm)}
                  className="flex-1 flex items-center gap-2 p-2 rounded-lg bg-stone-50 hover:bg-stone-100 transition text-left">
                  <div className={`w-8 h-5 rounded-full relative transition flex-shrink-0 ${sendConfirm ? "bg-emerald-500" : "bg-stone-300"}`}>
                    <span className={`absolute top-0.5 w-4 h-4 rounded-full bg-white shadow transition ${sendConfirm ? "left-3.5" : "left-0.5"}`}></span>
                  </div>
                  <span className="text-xs font-semibold text-stone-700">Enviar confirmación</span>
                </button>
                {/* Botón de configuración — solo visible si el rol tiene el
                    permiso msg-config (gateado por canConfigMessages). */}
                {canConfigMessages && (
                  <button
                    type="button"
                    onClick={() => setShowConfig(!showConfig)}
                    title="Configurar plantilla del mensaje"
                    className={`w-9 h-9 rounded-lg grid place-items-center transition flex-shrink-0 ${
                      showConfig
                        ? "bg-orange-600 text-white"
                        : "bg-stone-100 hover:bg-stone-200 text-stone-500"
                    }`}
                  >
                    <Settings size={14} />
                  </button>
                )}
              </div>

              {/* Preview del mensaje */}
              {sendConfirm && selectedServices.length > 0 && !showConfig && (
                <div className="bg-emerald-50 border border-emerald-200 rounded-xl p-2.5 text-xs text-emerald-900 whitespace-pre-line leading-relaxed">
                  <div className="text-[9px] tracking-widest uppercase text-emerald-600 font-bold mb-1">Vista previa</div>
                  {messagePreview}
                </div>
              )}

              {/* Panel de configuración de plantilla */}
              {showConfig && (
                <div className="border border-orange-200 rounded-xl overflow-hidden bg-orange-50/50">
                  <div className="px-3 py-2 bg-orange-100 border-b border-orange-200 flex items-center gap-2">
                    <Settings size={12} className="text-orange-700" />
                    <span className="text-xs font-bold text-orange-800">Configurar mensaje</span>
                  </div>
                  <div className="p-3 space-y-2">
                    {/* Saludo */}
                    <div>
                      <div className="flex items-center gap-2 mb-1">
                        <ToggleSwitch on={msgTemplate.showGreeting} onChange={(v) => setMsgTemplate(p => ({ ...p, showGreeting: v }))} />
                        <span className="text-xs font-semibold text-stone-700">Saludo</span>
                      </div>
                      {msgTemplate.showGreeting && (
                        <input
                          type="text"
                          value={msgTemplate.greeting}
                          onChange={(e) => setMsgTemplate(p => ({ ...p, greeting: e.target.value }))}
                          className="w-full px-2 py-1.5 border border-stone-200 rounded-lg text-xs outline-none focus:border-orange-400"
                        />
                      )}
                    </div>
                    {/* Toggles de campos */}
                    {[
                      { key: "showPetName",  label: "Nombre de mascota", icon: "🐾" },
                      { key: "showDate",     label: "Fecha",             icon: "📅" },
                      { key: "showTime",     label: "Hora",              icon: "🕐" },
                      { key: "showServices", label: "Lista de servicios",icon: "📋" },
                      { key: "showPrice",    label: "Precio estimado",   icon: "💰" },
                      { key: "showDuration", label: "Duración total",    icon: "⏱️" },
                      { key: "showNotes",    label: "Notas / indicaciones", icon: "📝" },
                    ].map(item => (
                      <div key={item.key} className="flex items-center gap-2">
                        <ToggleSwitch on={msgTemplate[item.key]} onChange={(v) => setMsgTemplate(p => ({ ...p, [item.key]: v }))} />
                        <span className="text-xs text-stone-600">{item.icon} {item.label}</span>
                      </div>
                    ))}
                    {/* Despedida */}
                    <div>
                      <div className="flex items-center gap-2 mb-1">
                        <ToggleSwitch on={msgTemplate.showClosing} onChange={(v) => setMsgTemplate(p => ({ ...p, showClosing: v }))} />
                        <span className="text-xs font-semibold text-stone-700">Despedida</span>
                      </div>
                      {msgTemplate.showClosing && (
                        <input
                          type="text"
                          value={msgTemplate.closing}
                          onChange={(e) => setMsgTemplate(p => ({ ...p, closing: e.target.value }))}
                          className="w-full px-2 py-1.5 border border-stone-200 rounded-lg text-xs outline-none focus:border-orange-400"
                        />
                      )}
                    </div>
                  </div>
                  {/* Preview dentro de la config */}
                  {selectedServices.length > 0 && (
                    <div className="px-3 pb-3">
                      <div className="bg-white border border-stone-200 rounded-xl p-2.5 text-xs text-stone-700 whitespace-pre-line leading-relaxed">
                        <div className="text-[9px] tracking-widest uppercase text-stone-400 font-bold mb-1">Vista previa</div>
                        {messagePreview || <span className="italic text-stone-400">Selecciona al menos un campo para incluir en el mensaje.</span>}
                      </div>
                    </div>
                  )}
                </div>
              )}
            </div>
          </>
        )}
      </div>

      {/* Footer */}
      {!saved && (
        <div className="p-2.5 border-t border-stone-200 bg-stone-50 flex-shrink-0 space-y-1.5">
          {selectedServices.length > 0 && (
            <div className="text-[11px] text-stone-500 text-center">
              {selectedServices.length} servicio{selectedServices.length !== 1 ? "s" : ""} · {totalDuration}min · Recibo borrador ${totalPrice.toFixed(2)} + IVA
            </div>
          )}
          <button
            onClick={handleCreate}
            disabled={!valid}
            className={`w-full flex items-center justify-center gap-2 px-3 py-2.5 rounded-xl text-sm font-semibold transition shadow ${
              valid ? "bg-orange-600 hover:bg-orange-700 text-white" : "bg-stone-200 text-stone-400 cursor-not-allowed"
            }`}
          >
            <CalendarCheck size={14} /> Confirmar reserva
          </button>
        </div>
      )}
    </div>
    </>
  );
}

// === Badge para estado de recibo (reusable en chat) ===
function InvoiceStateBadge({ state }) {
  const config = {
    borrador:   { label: "Borrador",   bg: "bg-slate-200",   text: "text-slate-700" },
    emitido:    { label: "Emitido",    bg: "bg-blue-100",    text: "text-blue-700" },
    pagado:     { label: "Pagado",     bg: "bg-emerald-100", text: "text-emerald-800" },
    finalizado: { label: "Finalizado", bg: "bg-stone-100",   text: "text-stone-600" },
    vencido:    { label: "Vencida",    bg: "bg-red-100",     text: "text-red-700" },
  };
  const c = config[state] || config.borrador;
  return (
    <span className={`inline-block text-xs font-bold px-1.5 py-px rounded ${c.bg} ${c.text}`}>
      {c.label}
    </span>
  );
}

// === Item de la lista de conversaciones (sidebar izquierdo de Mensajes) ===
function ConversationListItem({ conversation, active, onClick, sedes = [] }) {
  const { client, lastMessage, unread, channels } = conversation;
  const initials = client.name.split(" ").slice(0, 2).map(s => s[0]).join("").toUpperCase();
  const lastChannel = lastMessage.channel;
  const channelInfo = CHAT_CHANNELS[lastChannel];
  const ChannelIcon = channelInfo.icon;
  const colors = CHAT_CHANNEL_CLASSES[channelInfo.color];

  // Sede del cliente — para el badge visual. Si no tiene, no se muestra.
  const sede = sedes.find(s => s.id === client.sedeOrigenId);
  // Abreviatura corta de la sede (primeras 2 palabras significativas).
  const sedeShort = sede ? sede.name.split(" ").slice(0, 2).join(" ") : null;

  // Tiempo relativo simple
  const timeAgo = useMemo(() => {
    const ms = Date.now() - new Date(lastMessage.timestamp).getTime();
    const min = Math.floor(ms / 60000);
    if (min < 60) return `${min}m`;
    const h = Math.floor(min / 60);
    if (h < 24) return `${h}h`;
    const d = Math.floor(h / 24);
    return `${d}d`;
  }, [lastMessage.timestamp]);

  return (
    <button
      onClick={onClick}
      className={`w-full flex items-center gap-3 p-3 border-b border-stone-100 transition text-left border-l-4 ${
        active
          ? "bg-orange-50 border-l-orange-600"
          : unread
            ? "bg-emerald-50 border-l-emerald-500 hover:bg-emerald-100"
            : "border-l-transparent hover:bg-stone-50"
      }`}
    >
      <div className="relative flex-shrink-0">
        <div className={`w-10 h-10 rounded-full grid place-items-center text-white text-xs font-bold ${
          client.isOrg
            ? "bg-gradient-to-br from-stone-700 to-stone-900"
            : "bg-gradient-to-br from-orange-500 to-orange-700"
        }`}>
          {initials}
        </div>
        {/* Punto de canal en esquina */}
        <div className={`absolute -bottom-1 -right-1 w-5 h-5 rounded-full ${colors.bg} ${colors.text} grid place-items-center border-2 border-white`}>
          <ChannelIcon size={9} strokeWidth={2.2} />
        </div>
      </div>
      <div className="flex-1 min-w-0">
        <div className="flex items-baseline justify-between gap-2 mb-0.5">
          <span className={`font-semibold text-sm truncate ${unread ? "text-stone-900" : "text-stone-700"}`}>
            {client.name}
          </span>
          <span className={`text-xs whitespace-nowrap flex-shrink-0 ${unread ? "text-emerald-700 font-bold" : "text-stone-400"}`}>
            {timeAgo}
          </span>
        </div>
        {/* Sede del cliente — chip pequeño entre el nombre y el preview */}
        {sedeShort && (
          <div className="mb-0.5">
            <span className="inline-flex items-center gap-0.5 px-1.5 py-px rounded text-[9px] font-bold bg-orange-100 text-orange-700">
              <MapPin size={7} strokeWidth={2.5} />
              {sedeShort}
            </span>
          </div>
        )}
        <div className="flex items-center gap-1.5">
          {lastMessage.direction === "out" && (
            <span className="text-stone-400 text-xs flex-shrink-0">→</span>
          )}
          <span className={`text-xs truncate ${unread ? "text-stone-700 font-semibold" : "text-stone-500"}`}>
            {lastMessage.body}
          </span>
        </div>
      </div>
      {unread && (
        <span className="w-2 h-2 rounded-full bg-emerald-500 flex-shrink-0"></span>
      )}
    </button>
  );
}

// ========== Sección reutilizable: Mediciones físicas con historial ==========
// Muestra peso y altura del paciente con tabla cronológica + mini-gráfica de evolución.
// Permite registrar nuevas mediciones desde un modal sencillo. Las mediciones se
// persisten en passport.measurements (array de {id, date, weightKg, heightCm, note, recordedBy}).
//
// Para retrocompatibilidad: si el pasaporte tiene `weight` legacy ("28 kg") y NO tiene
// measurements, fabricamos una entrada virtual basada en ese peso para mostrar "algo".
// Cuando el usuario añade una medición real, la primera entrada legacy se persiste también.
function PhysicalMeasurements({ passport, setPassports, userName = "Operador" }) {
  const [showAddModal, setShowAddModal] = useState(false);

  // Resolver historial. Si no existe pero hay weight legacy, fabricamos una entrada virtual.
  const measurements = useMemo(() => {
    const real = passport.measurements || [];
    if (real.length > 0) return real;
    // Fabricar entrada virtual desde weight legacy
    if (passport.weight) {
      const match = String(passport.weight).match(/([\d.,]+)/);
      const num = match ? parseFloat(match[1].replace(",", ".")) : null;
      if (num && !isNaN(num)) {
        return [{
          id: "virtual-legacy",
          date: passport.issuedAt || "Fecha desconocida",
          weightKg: num,
          heightCm: null,
          note: "Registro inicial (importado del pasaporte)",
          recordedBy: "Sistema",
          isVirtual: true,
        }];
      }
    }
    return [];
  }, [passport]);

  // Ordenar de más reciente a más antigua. Las fechas vienen como string "DD MMM YYYY"
  // o ISO. Aplicamos parser tolerante para sort.
  const sorted = useMemo(() => {
    const parseDate = (str) => {
      if (!str) return 0;
      // ISO yyyy-mm-dd
      if (/^\d{4}-\d{2}-\d{2}/.test(str)) return new Date(str).getTime();
      // "DD MMM YYYY"
      const months = { ene:0, feb:1, mar:2, abr:3, may:4, jun:5, jul:6, ago:7, sep:8, oct:9, nov:10, dic:11, abril:3, agosto:7, junio:5, julio:6 };
      const parts = str.toLowerCase().split(/\s+/);
      if (parts.length >= 3) {
        const day = parseInt(parts[0]);
        const month = months[parts[1].slice(0, 3)] ?? 0;
        const year = parseInt(parts[2]);
        if (!isNaN(day) && !isNaN(year)) return new Date(year, month, day).getTime();
      }
      return 0;
    };
    return [...measurements].sort((a, b) => parseDate(b.date) - parseDate(a.date));
  }, [measurements]);

  const latest = sorted[0];
  const previous = sorted[1];

  // Calcular delta (cambio) respecto a medición anterior
  const weightDelta = latest && previous && latest.weightKg && previous.weightKg
    ? latest.weightKg - previous.weightKg
    : null;
  const heightDelta = latest && previous && latest.heightCm && previous.heightCm
    ? latest.heightCm - previous.heightCm
    : null;

  // Handler: registrar nueva medición
  const handleAddMeasurement = (data) => {
    if (!setPassports) return;
    const newEntry = {
      id: `meas-${Date.now().toString(36)}`,
      date: data.date,
      weightKg: data.weightKg,
      heightCm: data.heightCm,
      note: data.note || "",
      recordedBy: userName,
    };
    setPassports(prev => prev.map(p => {
      if (p.id !== passport.id) return p;
      // Si tenía solo entrada virtual, materializamos
      const existing = (p.measurements || []).filter(m => !m.isVirtual);
      // Si no había entradas reales pero sí virtual, agregamos esa primero
      const baseMeasurements = (p.measurements || []).length > 0
        ? existing
        : (sorted.find(m => m.isVirtual) ? [{ ...sorted.find(m => m.isVirtual), id: `meas-legacy-${p.id}` }] : []);
      return {
        ...p,
        measurements: [...baseMeasurements, newEntry],
        // Actualizar también weight string para compatibilidad con vistas viejas
        weight: `${data.weightKg} kg`,
      };
    }));
    setShowAddModal(false);
  };

  // === Mini-gráfica de evolución de peso ===
  // SVG simple, datos cronológicos (más antiguo a la izquierda). Solo si hay 2+ mediciones.
  const chartPoints = useMemo(() => {
    if (sorted.length < 2) return null;
    const chrono = [...sorted].reverse(); // antiguo → reciente
    const weights = chrono.filter(m => m.weightKg).map(m => m.weightKg);
    if (weights.length < 2) return null;
    const min = Math.min(...weights);
    const max = Math.max(...weights);
    const range = max - min || 1;
    const w = 100, h = 30, padTop = 4, padBottom = 4;
    const usableH = h - padTop - padBottom;
    return chrono.filter(m => m.weightKg).map((m, i, arr) => ({
      x: arr.length === 1 ? w / 2 : (i / (arr.length - 1)) * w,
      y: padTop + (1 - (m.weightKg - min) / range) * usableH,
      weight: m.weightKg,
    }));
  }, [sorted]);

  // Estado para mostrar/ocultar el historial completo (oculto por defecto)
  const [showHistory, setShowHistory] = useState(false);

  return (
    <>
      <div className="bg-white border border-stone-200 rounded-xl shadow-sm overflow-hidden">
        {/* Header compacto en una sola línea */}
        <div className="px-3.5 py-2 border-b border-stone-200 flex items-center justify-between gap-2 bg-stone-50">
          <div className="flex items-center gap-2 min-w-0">
            <Activity size={13} className="text-orange-700 flex-shrink-0" />
            <span className="text-xs tracking-wider uppercase text-stone-700 font-semibold">
              Antropometría
            </span>
            {sorted.length > 0 && (
              <span className="text-[10px] text-stone-400">
                · {sorted.length} {sorted.length === 1 ? "registro" : "registros"}
              </span>
            )}
          </div>
          <button
            onClick={() => setShowAddModal(true)}
            className="flex items-center gap-1 px-2.5 py-1 rounded-lg bg-orange-600 hover:bg-orange-700 text-white text-[11px] font-semibold transition flex-shrink-0"
          >
            <Plus size={11} strokeWidth={2.4} />
            Registrar
          </button>
        </div>

        {sorted.length === 0 ? (
          <div className="px-4 py-3 text-center">
            <p className="text-xs text-stone-500">
              <Activity size={11} className="inline mr-1 text-stone-400" />
              Sin mediciones registradas
            </p>
          </div>
        ) : (
          <div className="p-3 space-y-2">
            {/* Última medición: una sola fila con peso + altura + gráfica inline */}
            <div className="grid grid-cols-2 gap-2">
              {/* Peso */}
              <div className="bg-orange-50 border border-orange-200 rounded-lg p-2.5 flex items-center gap-2.5">
                <div className="w-8 h-8 rounded-lg bg-orange-600 grid place-items-center text-white flex-shrink-0">
                  <Activity size={13} strokeWidth={1.8} />
                </div>
                <div className="min-w-0 flex-1">
                  <div className="text-[9px] tracking-widest uppercase text-orange-700 font-semibold leading-none">
                    Peso
                  </div>
                  <div className="font-serif text-xl font-bold text-stone-900 leading-none mt-0.5">
                    {latest?.weightKg ?? "—"}<span className="text-xs text-stone-500 ml-0.5">kg</span>
                  </div>
                  {weightDelta !== null && (
                    <div className={`text-[10px] font-semibold leading-none mt-0.5 ${
                      weightDelta > 0 ? "text-emerald-700" : weightDelta < 0 ? "text-red-700" : "text-stone-500"
                    }`}>
                      {weightDelta > 0 ? "↑" : weightDelta < 0 ? "↓" : "→"} {Math.abs(weightDelta).toFixed(1)} kg
                    </div>
                  )}
                </div>
              </div>

              {/* Altura */}
              <div className="bg-blue-50 border border-blue-200 rounded-lg p-2.5 flex items-center gap-2.5">
                <div className="w-8 h-8 rounded-lg bg-blue-600 grid place-items-center text-white flex-shrink-0">
                  <BarChart3 size={13} strokeWidth={1.8} />
                </div>
                <div className="min-w-0 flex-1">
                  <div className="text-[9px] tracking-widest uppercase text-blue-700 font-semibold leading-none">
                    Altura
                  </div>
                  <div className="font-serif text-xl font-bold text-stone-900 leading-none mt-0.5">
                    {latest?.heightCm ?? "—"}<span className="text-xs text-stone-500 ml-0.5">cm</span>
                  </div>
                  {heightDelta !== null ? (
                    <div className={`text-[10px] font-semibold leading-none mt-0.5 ${
                      heightDelta > 0 ? "text-emerald-700" : heightDelta < 0 ? "text-red-700" : "text-stone-500"
                    }`}>
                      {heightDelta > 0 ? "↑" : heightDelta < 0 ? "↓" : "→"} {Math.abs(heightDelta).toFixed(1)} cm
                    </div>
                  ) : !latest?.heightCm ? (
                    <div className="text-[10px] text-stone-400 italic leading-none mt-0.5">sin registro</div>
                  ) : null}
                </div>
              </div>
            </div>

            {/* Mini-gráfica de evolución de peso (si hay 2+ mediciones), inline y compacta */}
            {chartPoints && chartPoints.length >= 2 && (
              <div className="flex items-center gap-2 px-2 py-1.5 bg-stone-50 border border-stone-200 rounded-lg">
                <span className="text-[10px] tracking-wider uppercase text-stone-500 font-semibold flex-shrink-0">
                  Evolución
                </span>
                <svg viewBox="0 0 100 20" className="flex-1 h-8" preserveAspectRatio="none">
                  <polygon
                    points={`${chartPoints[0].x},20 ${chartPoints.map(p => `${p.x},${p.y * 0.65}`).join(" ")} ${chartPoints[chartPoints.length - 1].x},20`}
                    fill="#ea580c"
                    opacity="0.12"
                  />
                  <polyline
                    points={chartPoints.map(p => `${p.x},${p.y * 0.65}`).join(" ")}
                    fill="none"
                    stroke="#ea580c"
                    strokeWidth="0.8"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                  />
                  {chartPoints.map((p, i) => (
                    <circle key={i} cx={p.x} cy={p.y * 0.65} r="0.9" fill="#ea580c" stroke="white" strokeWidth="0.3" />
                  ))}
                </svg>
                <span className="text-[10px] text-stone-400 flex-shrink-0">
                  {chartPoints.length} mediciones
                </span>
              </div>
            )}

            {/* Toggle "Ver historial" — colapsado por defecto para no ocupar espacio */}
            <button
              onClick={() => setShowHistory(s => !s)}
              className="w-full flex items-center justify-between px-2 py-1.5 rounded-lg hover:bg-stone-50 text-stone-600 hover:text-stone-900 transition text-[11px] font-semibold"
            >
              <span className="flex items-center gap-1.5">
                <History size={11} />
                Ver historial completo ({sorted.length})
              </span>
              <ChevronRight
                size={12}
                className={`transition-transform ${showHistory ? "rotate-90" : ""}`}
              />
            </button>

            {showHistory && (
              <div className="border border-stone-200 rounded-lg overflow-hidden">
                {/* Tabla con flexbox en lugar de grid (más confiable para anchos variables) */}
                <div className="flex items-center px-2.5 py-1.5 bg-stone-50 border-b border-stone-200 text-[9px] tracking-wider uppercase text-stone-500 font-semibold">
                  <div className="flex-1 min-w-0">Fecha</div>
                  <div className="w-14 text-right">Peso</div>
                  <div className="w-14 text-right">Altura</div>
                  <div className="hidden sm:block w-20 text-right">Por</div>
                </div>
                <div className="divide-y divide-stone-100 max-h-40 overflow-y-auto">
                  {sorted.map((m, idx) => (
                    <div
                      key={m.id}
                      className={`flex items-center px-2.5 py-1.5 text-[11px] hover:bg-stone-50 transition ${
                        idx === 0 ? "bg-orange-50/60" : ""
                      }`}
                    >
                      <div className="flex-1 min-w-0 pr-2">
                        <div className="font-semibold text-stone-800 truncate">{m.date}</div>
                        {m.note && (
                          <div className="text-[10px] text-stone-500 truncate" title={m.note}>{m.note}</div>
                        )}
                      </div>
                      <div className="w-14 text-right font-mono font-semibold text-stone-800">
                        {m.weightKg ? `${m.weightKg}kg` : "—"}
                      </div>
                      <div className="w-14 text-right font-mono font-semibold text-stone-800">
                        {m.heightCm ? `${m.heightCm}cm` : "—"}
                      </div>
                      <div className="hidden sm:block w-20 text-right text-[10px] text-stone-500 truncate" title={m.recordedBy}>
                        {m.recordedBy}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}
      </div>

      {showAddModal && (
        <AddMeasurementModal
          petName={passport.name}
          onCancel={() => setShowAddModal(false)}
          onConfirm={handleAddMeasurement}
        />
      )}
    </>
  );
}

// ========== Modal: Registrar nueva medición ==========
function AddMeasurementModal({ petName, onCancel, onConfirm }) {
  // Default a hoy
  const today = useMemo(() => {
    const d = new Date();
    const months = ["Ene", "Feb", "Mar", "Abr", "May", "Jun", "Jul", "Ago", "Sep", "Oct", "Nov", "Dic"];
    return `${String(d.getDate()).padStart(2, "0")} ${months[d.getMonth()]} ${d.getFullYear()}`;
  }, []);

  const [date, setDate] = useState(today);
  const [weightKg, setWeightKg] = useState("");
  const [heightCm, setHeightCm] = useState("");
  const [note, setNote] = useState("");

  const valid = weightKg.trim() !== "" || heightCm.trim() !== "";

  const handleConfirm = () => {
    if (!valid) return;
    const wParsed = weightKg.trim() ? parseFloat(weightKg.replace(",", ".")) : null;
    const hParsed = heightCm.trim() ? parseFloat(heightCm.replace(",", ".")) : null;
    onConfirm({
      date: date.trim() || today,
      weightKg: wParsed && !isNaN(wParsed) ? wParsed : null,
      heightCm: hParsed && !isNaN(hParsed) ? hParsed : null,
      note: note.trim(),
    });
  };

  return (
    <div onClick={onCancel} className="fixed inset-0 bg-stone-900/80 z-[60] flex justify-center items-start p-4 sm:p-12 overflow-y-auto">
      <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden">
        <div className="p-5 bg-gradient-to-br from-orange-500 to-orange-700 text-white flex items-center gap-3">
          <div className="w-11 h-11 rounded-xl bg-white/20 backdrop-blur grid place-items-center flex-shrink-0">
            <Activity size={20} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase opacity-90 font-semibold">
              Nueva medición
            </div>
            <h3 className="font-serif text-xl font-semibold mt-0.5 truncate">{petName}</h3>
          </div>
          <button onClick={onCancel} className="w-8 h-8 rounded-full bg-white/20 hover:bg-white/30 grid place-items-center transition flex-shrink-0">
            <X size={14} />
          </button>
        </div>
        <div className="p-5 space-y-4">
          <div>
            <label className="text-xs tracking-widest uppercase text-stone-500 font-semibold block mb-1.5">
              Fecha
            </label>
            <input
              type="text"
              value={date}
              onChange={(e) => setDate(e.target.value)}
              placeholder="Ej: 07 May 2026"
              className="w-full px-3.5 py-2.5 bg-white border-2 border-stone-200 focus:border-orange-400 rounded-xl text-sm outline-none transition"
            />
          </div>
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="text-xs tracking-widest uppercase text-stone-500 font-semibold block mb-1.5">
                Peso (kg)
              </label>
              <input
                type="text"
                inputMode="decimal"
                value={weightKg}
                onChange={(e) => setWeightKg(e.target.value)}
                placeholder="Ej: 28.5"
                autoFocus
                className="w-full px-3.5 py-2.5 bg-white border-2 border-stone-200 focus:border-orange-400 rounded-xl text-sm outline-none transition font-mono"
              />
            </div>
            <div>
              <label className="text-xs tracking-widest uppercase text-stone-500 font-semibold block mb-1.5">
                Altura (cm)
              </label>
              <input
                type="text"
                inputMode="decimal"
                value={heightCm}
                onChange={(e) => setHeightCm(e.target.value)}
                placeholder="Ej: 55"
                className="w-full px-3.5 py-2.5 bg-white border-2 border-stone-200 focus:border-orange-400 rounded-xl text-sm outline-none transition font-mono"
              />
            </div>
          </div>
          <div>
            <label className="text-xs tracking-widest uppercase text-stone-500 font-semibold block mb-1.5">
              Nota clínica (opcional)
            </label>
            <textarea
              value={note}
              onChange={(e) => setNote(e.target.value)}
              rows={2}
              placeholder="Ej: Control rutinario · Peso saludable"
              className="w-full px-3.5 py-2.5 bg-white border-2 border-stone-200 focus:border-orange-400 rounded-xl text-sm outline-none transition resize-none"
            />
          </div>
          <div className="bg-amber-50 border border-amber-200 rounded-lg p-2.5 text-[11px] text-amber-900 leading-relaxed flex items-start gap-1.5">
            <Info size={11} className="text-amber-700 flex-shrink-0 mt-0.5" />
            <span>Al menos uno de los dos campos (peso o altura) debe estar lleno.</span>
          </div>
        </div>
        <div className="p-3 border-t border-stone-200 bg-stone-50 flex gap-2">
          <button
            onClick={onCancel}
            className="flex-1 px-3 py-2.5 rounded-xl text-sm font-semibold bg-white border border-stone-200 hover:border-stone-400 text-stone-700"
          >
            Cancelar
          </button>
          <button
            onClick={handleConfirm}
            disabled={!valid}
            className={`flex-[2] px-3 py-2.5 rounded-xl text-sm font-semibold transition shadow flex items-center justify-center gap-2 ${
              valid
                ? "bg-orange-600 hover:bg-orange-700 text-white"
                : "bg-stone-200 text-stone-400 cursor-not-allowed"
            }`}
          >
            <Check size={13} strokeWidth={2.4} />
            Guardar medición
          </button>
        </div>
      </div>
    </div>
  );
}

// ========== VISTA: PASAPORTE CLÍNICO (vista del veterinario) ==========
// Igual que el pasaporte normal pero sin datos del cliente (solo nombre del tutor).
// Enfocado en historia clínica, tratamientos, vacunas y veterinarios que atendieron.

function VetPassportView({ passports, setPassports, initialSearch, onClearInitialSearch, userName = "Operador", userRole = "super", permissions = {} }) {
  const [selectedId, setSelectedId] = useState(null);
  const [searchQuery, setSearchQuery] = useState("");
  const [speciesFilter, setSpeciesFilter] = useState("all");

  // Auto-cargar el código + abrir el modal cuando llega initialSearch
  useEffect(() => {
    if (initialSearch && initialSearch.trim()) {
      const q = initialSearch.replace("#", "").trim();
      setSearchQuery(q);
      // Si hay coincidencia exacta por código, auto-abrir su modal
      const match = passports.find(p => p.code === q);
      if (match) {
        setSelectedId(match.id);
      }
      onClearInitialSearch && onClearInitialSearch();
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [initialSearch]);

  const filtered = useMemo(() => {
    let result = passports;
    if (speciesFilter !== "all") {
      result = result.filter(p => p.species === speciesFilter);
    }
    if (searchQuery.trim()) {
      const q = searchQuery.toLowerCase().replace("#", "").trim();
      result = result.filter(p =>
        p.name.toLowerCase().includes(q) ||
        p.code.includes(q) ||
        p.breed.toLowerCase().includes(q)
      );
    }
    return result;
  }, [passports, speciesFilter, searchQuery]);

  const selected = filtered.find(p => p.id === selectedId)
    || passports.find(p => p.id === selectedId);

  const speciesChips = [
    { id: "all", label: "Todas", count: passports.length },
    { id: "dog", label: "Perros", count: passports.filter(p => p.species === "dog").length },
    { id: "cat", label: "Gatos", count: passports.filter(p => p.species === "cat").length },
    { id: "bird", label: "Aves", count: passports.filter(p => p.species === "bird").length },
    { id: "rabbit", label: "Conejos", count: passports.filter(p => p.species === "rabbit").length },
  ].filter(c => c.count > 0);

  return (
    <div className="space-y-5">
      {/* Aviso de privacidad — antes vivía dentro del hero, ahora es banner independiente.
          Es info legal/regulatoria que el usuario debe ver al entrar a esta vista. */}
      <div className="p-3 rounded-xl bg-orange-50 border border-orange-200 flex items-start gap-2.5 text-xs text-stone-700">
        <Lock size={14} className="text-orange-700 flex-shrink-0 mt-0.5" />
        <div>
          <strong className="text-stone-900">Vista clínica:</strong> esta sección oculta datos administrativos del cliente (cédula, dirección, recibos). Para gestión completa del cliente, dirígete al módulo Pasaportes.
        </div>
      </div>

      {/* Buscador */}
      <div className="bg-white border border-stone-200 rounded-2xl shadow-sm p-3 flex flex-col lg:flex-row gap-3 items-stretch lg:items-center">
        <div className="relative flex-1">
          <Search size={17} className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-400" />
          <input
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            placeholder="Buscar por nombre, código de pasaporte o raza..."
            className="w-full pl-12 pr-11 py-3 bg-stone-50 border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500 focus:bg-white transition"
          />
          {searchQuery && (
            <button
              onClick={() => setSearchQuery("")}
              className="absolute right-3 top-1/2 -translate-y-1/2 w-7 h-7 rounded-md bg-stone-100 hover:bg-stone-200 grid place-items-center text-stone-500 transition"
            >
              <X size={13} />
            </button>
          )}
        </div>
        <div className="flex items-center gap-2 px-2 text-xs text-stone-500 lg:border-l lg:border-stone-200 lg:pl-4">
          <Filter size={13} />
          <span className="font-semibold tracking-wide">{filtered.length} resultados</span>
        </div>
      </div>

      {/* Filtros por especie */}
      <div className="flex gap-2 flex-wrap">
        {speciesChips.map(s => {
          const active = speciesFilter === s.id;
          return (
            <button
              key={s.id}
              onClick={() => setSpeciesFilter(s.id)}
              className={`flex items-center gap-2 px-3.5 py-2 rounded-full text-sm font-semibold transition ${
                active ? "bg-stone-900 text-white shadow-lg" : "bg-white text-stone-700 border border-stone-200 hover:border-orange-300"
              }`}
            >
              {s.label}
              <span className={`text-xs font-bold px-2 py-px rounded-full ${
                active ? "bg-stone-700 text-white" : "bg-stone-100 text-stone-600"
              }`}>
                {s.count}
              </span>
            </button>
          );
        })}
      </div>

      {/* Grid de tarjetas */}
      {filtered.length === 0 ? (
        <div className="bg-white border border-stone-200 rounded-2xl p-12 text-center">
          <BookOpen size={32} className="text-stone-300 mx-auto mb-3" />
          <div className="text-base font-semibold text-stone-700">Sin resultados</div>
          <div className="text-sm text-stone-500 mt-1">
            {searchQuery
              ? <>No encontramos pasaportes para "<strong>{searchQuery}</strong>".</>
              : "No hay pasaportes para este filtro."
            }
          </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-3">
          {filtered.map(p => (
            <VetPassportCard
              key={p.id}
              passport={p}
              onOpen={() => setSelectedId(p.id)}
            />
          ))}
        </div>
      )}

      {/* Modal de detalle */}
      {selected && (
        <VetPassportDetailModal
          passport={selected}
          setPassports={setPassports}
          userName={userName}
          userRole={userRole}
          permissions={permissions}
          onClose={() => setSelectedId(null)}
        />
      )}
    </div>
  );
}

function VetPassportCard({ passport, onOpen }) {
  const Icon = ANIMAL_ICONS[passport.species] || PawPrint;
  const lastEvent = passport.events[0];

  return (
    <button
      onClick={onOpen}
      className="text-left bg-white border border-stone-200 hover:border-orange-300 hover:-translate-y-0.5 hover:shadow-lg rounded-2xl p-4 transition relative overflow-hidden"
    >
      {/* Barra naranja de "lomo de libro" */}
      <span className="absolute left-0 top-0 bottom-0 w-1 bg-gradient-to-b from-orange-500 to-orange-700"></span>

      <div className="flex items-start gap-3 mb-3 pl-1">
        <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-orange-200 to-orange-100 grid place-items-center text-orange-800 flex-shrink-0 border border-orange-200">
          <Icon size={22} strokeWidth={1.8} />
        </div>
        <div className="flex-1 min-w-0">
          <div className="font-serif text-xl font-semibold leading-tight">{passport.name}</div>
          <div className="text-xs text-stone-500 mt-0.5">
            {passport.breed} · {passport.gender === "M" ? "♂" : "♀"} {passport.age}
          </div>
        </div>
      </div>

      <div className="border-t border-stone-100 pt-2 pl-1">
        <div className="text-xs tracking-widest uppercase text-stone-400 font-semibold">
          Código de pasaporte
        </div>
        <div className="font-mono text-base font-bold text-orange-700 mt-0.5">
          {passport.code}
        </div>
      </div>

      <div className="flex items-center gap-3 mt-3 pt-3 border-t border-stone-100 pl-1">
        <span className="inline-flex items-center gap-1 text-xs text-stone-500">
          <History size={11} /> {passport.events.length} eventos
        </span>
        {lastEvent && (
          <span className="text-xs text-stone-500 truncate">
            · {lastEvent.date}
          </span>
        )}
        <ChevronRight size={13} className="text-stone-400 ml-auto" />
      </div>
    </button>
  );
}

// === Modal con historial clínico completo (sin datos del cliente) ===
function VetPassportDetailModal({ passport, onClose, setPassports, userName = "Operador", userRole = "super", permissions = {} }) {
  const [filter, setFilter] = useState("all");
  // Modal de detalle de un evento clínico específico (lupa)
  const [eventDetail, setEventDetail] = useState(null);
  // Ref a la timeline para hacer scroll cuando se cliquea "Ver historial" en una category card
  const timelineRef = useRef(null);
  // Editor de evento clínico (crear o editar). null = cerrado.
  // Cuando está abierto: { type, eventId | null }. eventId=null significa "crear nuevo".
  const [editorState, setEditorState] = useState(null);

  // === Niveles de permiso por categoría clínica ===
  // Resolvemos hidden/view/edit para cada uno de los 3 campos del schema vet.passport.
  // El super siempre tiene "edit". Si no hay permissions configurados, fallback a "view".
  const dewormingLevel    = getFieldLevel(permissions, userRole, "vet", "passport", "deworming");
  const vaccinationLevel  = getFieldLevel(permissions, userRole, "vet", "passport", "vaccination");
  const consultationLevel = getFieldLevel(permissions, userRole, "vet", "passport", "consultation");

  const filteredEvents = useMemo(() => {
    if (filter === "all") return passport.events;
    return passport.events.filter(e => e.type === filter);
  }, [passport.events, filter]);

  // Solo el nombre del tutor responsable (sin email, teléfono, dirección, etc.)
  const tutorName = passport.tutors?.[0]?.name || "Tutor responsable";

  // Veterinarios únicos que han atendido a este paciente
  const vetsList = useMemo(() => {
    const vets = new Set();
    passport.events.forEach(e => {
      if (e.author && (e.type === "vet" || e.type === "consulta" || e.author.toLowerCase().includes("dr"))) {
        vets.add(e.author);
      }
    });
    return Array.from(vets);
  }, [passport.events]);

  const eventTypeFilters = useMemo(() => {
    const types = new Set();
    passport.events.forEach(e => types.add(e.type));
    return [
      { id: "all", label: "Todos", count: passport.events.length },
      ...Array.from(types).map(t => ({
        id: t,
        label: t === "vet" || t === "consulta" || t === "consultation" ? "Consultas" :
               t === "vacuna" || t === "vaccination" ? "Vacunas" :
               t === "tratamiento" || t === "treatment" ? "Tratamientos" :
               t === "deworming" || t === "desparasitacion" ? "Desparasitación" :
               t === "cirugia" || t === "cirugía" || t === "surgery" ? "Cirugías" :
               t === "examen" || t === "examination" ? "Exámenes" :
               t.charAt(0).toUpperCase() + t.slice(1),
        count: passport.events.filter(e => e.type === t).length,
      })),
    ];
  }, [passport.events]);

  const Icon = ANIMAL_ICONS[passport.species] || PawPrint;

  return (
    <div onClick={onClose} className="fixed inset-0 bg-stone-900 z-40 flex justify-center items-start p-4 overflow-y-auto">
      <div onClick={(e) => e.stopPropagation()} className="bg-stone-50 rounded-2xl w-full max-w-3xl shadow-2xl my-8">
        {/* Header sticky */}
        <div className="sticky top-0 z-10 flex items-center justify-between p-4 border-b border-stone-200 bg-white rounded-t-2xl">
          <div className="flex items-center gap-3 min-w-0">
            <BookOpen size={18} className="text-orange-600 flex-shrink-0" />
            <div className="min-w-0">
              <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold">
                Pasaporte clínico
              </div>
              <div className="text-sm font-semibold text-stone-700 flex items-center gap-2">
                {passport.name} · <span className="font-mono text-orange-700">#{passport.code}</span>
              </div>
            </div>
          </div>
          <button onClick={onClose} className="w-9 h-9 rounded-full bg-white border border-stone-200 grid place-items-center text-stone-600 hover:text-orange-700">
            <X size={16} />
          </button>
        </div>

        <div className="p-5 space-y-4">
          {/* Hero clínico (sin datos del cliente) */}
          <div className="bg-white border border-stone-200 rounded-2xl shadow-sm p-6 flex items-center gap-5 flex-wrap">
            <div className="w-20 h-20 rounded-2xl bg-gradient-to-br from-orange-200 to-orange-100 grid place-items-center text-orange-800 flex-shrink-0 border-2 border-orange-200">
              <Icon size={40} strokeWidth={1.6} />
            </div>
            <div className="flex-1 min-w-0">
              <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold">
                Paciente
              </div>
              <h2 className="font-serif text-3xl font-semibold leading-tight mt-0.5">
                {passport.name}
              </h2>
              <div className="flex items-center gap-2 mt-1.5 flex-wrap text-sm text-stone-600">
                <span>{passport.breed}</span>
                <span className="text-stone-300">·</span>
                <span>{passport.gender === "M" ? "♂ Macho" : "♀ Hembra"}</span>
                <span className="text-stone-300">·</span>
                <span>{passport.age}</span>
              </div>
            </div>
            <div className="text-right">
              <div className="text-xs tracking-widest uppercase text-stone-400 font-semibold">
                Código único
              </div>
              <div className="font-mono text-2xl font-bold text-orange-700 mt-0.5">
                {passport.code}
              </div>
            </div>
          </div>

          {/* Datos clínicos (sin info admin del cliente) */}
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
            <ClinicalKpi label="Especie" value={
              passport.species === "dog" ? "Canino" :
              passport.species === "cat" ? "Felino" :
              passport.species === "bird" ? "Ave" :
              passport.species === "rabbit" ? "Conejo" :
              passport.species
            } />
            <ClinicalKpi label="Esterilizado" value={passport.sterilized ? "Sí" : "No"} accent={passport.sterilized ? "emerald" : "stone"} />
            <ClinicalKpi label="Microchip" value={passport.microchip || "—"} mono />
            <ClinicalKpi label="Eventos clínicos" value={passport.events.length} accent="orange" />
          </div>

          {/* Solo nombre del tutor responsable */}
          <div className="bg-stone-100 border border-stone-200 rounded-xl p-3 flex items-center gap-2.5">
            <Users size={14} className="text-stone-500 flex-shrink-0" />
            <span className="text-xs text-stone-600">Tutor responsable:</span>
            <span className="text-sm font-semibold text-stone-800">{tutorName}</span>
            <span className="ml-auto text-xs text-stone-400 italic">Datos administrativos restringidos</span>
          </div>

          {/* === Mediciones físicas (peso, altura) con historial === */}
          <PhysicalMeasurements
            passport={passport}
            setPassports={setPassports}
            userName={userName}
          />

          {/* === FICHA CLÍNICA EDITABLE === */}
          {/* Datos básicos + identificación + antecedentes/comportamiento.
              Mismo componente que se usa en PassportDetailModal del módulo Clientes.
              Acá lo incluimos también para que el veterinario pueda editar la ficha
              clínica directamente desde la vista clínica sin abrir Clientes. */}
          <FichaClinicaCard
            passport={passport}
            onUpdatePassport={(getFieldLevel(permissions, userRole, "vet", "passport", "edit-ficha") === "edit") ? (updates) => {
              setPassports && setPassports(prev => prev.map(p =>
                p.id === passport.id ? { ...p, ...updates } : p
              ));
            } : null}
          />

          {/* === Secciones-resumen por categoría clínica ===
              3 cards visibles siempre (incluso vacías) que dan acceso directo a
              cada tipo de evento clínico. Click en "Ver historial" activa el
              filtro correspondiente en la timeline de abajo y hace scroll.
              Visibilidad y edición controladas por permisos del rol actual. */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
            <ClinicalCategoryCard
              events={passport.events}
              types={["deworming", "desparasitacion"]}
              label="Desparasitación"
              Icon={ShieldCheck}
              accent="emerald"
              level={dewormingLevel}
              onView={() => {
                setFilter("deworming");
                if (timelineRef.current) timelineRef.current.scrollIntoView({ behavior: "smooth", block: "start" });
              }}
              onRegister={() => setEditorState({ type: "deworming", eventId: null })}
            />
            <ClinicalCategoryCard
              events={passport.events}
              types={["vacuna", "vaccination"]}
              label="Vacunación"
              Icon={Syringe}
              accent="blue"
              level={vaccinationLevel}
              onView={() => {
                setFilter("vacuna");
                if (timelineRef.current) timelineRef.current.scrollIntoView({ behavior: "smooth", block: "start" });
              }}
              onRegister={() => setEditorState({ type: "vacuna", eventId: null })}
            />
            <ClinicalCategoryCard
              events={passport.events}
              types={["consulta", "consultation", "vet"]}
              label="Consultas clínicas"
              Icon={Stethoscope}
              accent="orange"
              level={consultationLevel}
              onView={() => {
                setFilter("consulta");
                if (timelineRef.current) timelineRef.current.scrollIntoView({ behavior: "smooth", block: "start" });
              }}
              onRegister={() => setEditorState({ type: "consulta", eventId: null })}
            />
          </div>

          {/* Veterinarios que han atendido */}
          {vetsList.length > 0 && (
            <div className="bg-white border border-stone-200 rounded-2xl shadow-sm p-5">
              <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold mb-3">
                Equipo médico que ha atendido
              </div>
              <div className="flex gap-2 flex-wrap">
                {vetsList.map((vet, i) => (
                  <div key={i} className="flex items-center gap-2 px-3 py-2 rounded-xl bg-orange-50 border border-orange-200">
                    <div className="w-8 h-8 rounded-full bg-gradient-to-br from-orange-500 to-orange-700 grid place-items-center text-white text-xs font-bold flex-shrink-0">
                      {vet.split(" ").slice(0, 2).map(s => s[0]).join("").toUpperCase()}
                    </div>
                    <div>
                      <div className="text-sm font-semibold text-stone-800">{vet}</div>
                      <div className="text-xs text-stone-500">
                        {passport.events.filter(e => e.author === vet).length} consultas
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Filtros de tipo de evento */}
          <div ref={timelineRef} className="bg-white border border-stone-200 rounded-2xl shadow-sm p-5">
            <div className="flex items-center justify-between mb-4 flex-wrap gap-3">
              <div>
                <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold">
                  Línea de tiempo clínica
                </div>
                <h3 className="font-serif text-xl font-semibold mt-0.5">Historia médica completa</h3>
              </div>
              <div className="flex gap-1.5 flex-wrap">
                {eventTypeFilters.map(f => {
                  const active = filter === f.id;
                  return (
                    <button
                      key={f.id}
                      onClick={() => setFilter(f.id)}
                      className={`px-3 py-1.5 rounded-full text-xs font-semibold transition ${
                        active
                          ? "bg-stone-900 text-white"
                          : "bg-white text-stone-600 border border-stone-200 hover:border-orange-300"
                      }`}
                    >
                      {f.label}
                      <span className={`ml-1.5 text-xs font-bold px-1.5 rounded ${
                        active ? "bg-stone-700" : "bg-stone-100"
                      }`}>{f.count}</span>
                    </button>
                  );
                })}
              </div>
            </div>

            {/* Timeline de eventos */}
            {filteredEvents.length === 0 ? (
              <div className="text-center py-12 text-stone-400 text-sm">
                Sin eventos para este filtro.
              </div>
            ) : (
              <div className="space-y-2 relative">
                {/* Línea vertical decorativa */}
                <div className="absolute left-3 top-2 bottom-2 w-0.5 bg-gradient-to-b from-orange-300 via-orange-200 to-stone-200"></div>

                {filteredEvents.map((event, i) => {
                  // Resolver el nivel de permiso para este evento según su tipo.
                  // Si es "edit" → mostramos lápiz para editar (clickeable).
                  // Si es "view"/"hidden" → solo lectura.
                  const lvl =
                    (event.type === "deworming" || event.type === "desparasitacion") ? dewormingLevel :
                    (event.type === "vacuna" || event.type === "vaccination")        ? vaccinationLevel :
                    (event.type === "consulta" || event.type === "consultation" || event.type === "vet") ? consultationLevel :
                    "view";
                  // Normalizar el type del evento al type que el editor maneja
                  const editorType =
                    (event.type === "deworming" || event.type === "desparasitacion") ? "deworming" :
                    (event.type === "vacuna" || event.type === "vaccination")        ? "vacuna" :
                    "consulta";
                  const handleEdit = lvl === "edit"
                    ? () => setEditorState({ type: editorType, eventId: event.id })
                    : undefined;
                  return (
                    <ClinicalTimelineEvent
                      key={event.id || i}
                      event={event}
                      onView={(ev) => setEventDetail(ev)}
                      onEdit={handleEdit}
                    />
                  );
                })}
              </div>
            )}
          </div>
        </div>

        {/* Footer fijo con acciones (solo lectura clínica) */}
        <div className="sticky bottom-0 bg-white border-t border-stone-200 p-3 flex justify-end gap-2 rounded-b-2xl">
          <button onClick={onClose} className="px-3 py-2 rounded-xl text-sm font-semibold bg-white text-stone-700 border border-stone-200 hover:border-orange-400">
            Cerrar
          </button>
          <button className="flex items-center gap-1.5 px-3 py-2 rounded-xl text-sm font-semibold bg-white text-stone-700 border border-stone-200 hover:border-orange-400">
            <Printer size={13} /> Imprimir historia
          </button>
          <button className="flex items-center gap-1.5 px-4 py-2 rounded-xl text-sm font-semibold bg-orange-600 hover:bg-orange-700 text-white">
            <Plus size={13} /> Nuevo evento clínico
          </button>
        </div>
      </div>

      {/* Modal: detalle completo de un evento clínico (lupa) */}
      {eventDetail && (
        <ClinicalEventDetailModal
          event={eventDetail}
          patientName={passport.name}
          patientCode={passport.code}
          onClose={() => setEventDetail(null)}
        />
      )}

      {/* Modal: editor de evento clínico (crear o editar).
          Maneja desparasitación, vacunación y consulta clínica. */}
      {editorState && (
        <ClinicalEventEditorModal
          type={editorState.type}
          event={editorState.eventId ? passport.events.find(e => e.id === editorState.eventId) : null}
          passport={passport}
          userName={userName}
          onClose={() => setEditorState(null)}
          onSave={(eventData, isEdit) => {
            // Actualizar el pasaporte: si es edición, reemplazar el evento con
            // el mismo id; si es creación, prepend al array de events.
            setPassports(prev => prev.map(p => {
              if (p.code !== passport.code) return p;
              if (isEdit) {
                return {
                  ...p,
                  events: p.events.map(e => e.id === eventData.id ? eventData : e),
                };
              }
              return { ...p, events: [eventData, ...p.events] };
            }));
            setEditorState(null);
          }}
        />
      )}
    </div>
  );
}

function ClinicalKpi({ label, value, accent, mono }) {
  const colors = {
    orange:  "bg-orange-50 border-orange-200 text-orange-800",
    emerald: "bg-emerald-50 border-emerald-200 text-emerald-800",
    stone:   "bg-stone-50 border-stone-200 text-stone-700",
  }[accent || "stone"];

  return (
    <div className={`p-3 rounded-xl border ${colors}`}>
      <div className="text-xs tracking-widest uppercase font-semibold opacity-70">{label}</div>
      <div className={`font-serif text-lg font-semibold leading-tight mt-0.5 ${mono ? "font-mono text-sm" : ""}`}>
        {value}
      </div>
    </div>
  );
}

// === Card de categoría clínica ===
// Sección-resumen siempre visible para una categoría de eventos (Desparasitación,
// Vacunación, Consultas). Muestra conteo + último registro + botón "Ver historial"
// que activa el filtro correspondiente en la timeline. Cuando level === "edit",
// además muestra "+ Registrar" para crear un evento nuevo.
//
// Visibilidad por nivel:
//   - "hidden": no se renderiza (return null)
//   - "view":   solo botón "Ver historial"
//   - "edit":   "Ver historial" + "+ Registrar"
function ClinicalCategoryCard({ events = [], types = [], label, Icon, accent = "stone", onView, onRegister, level = "edit" }) {
  // Eventos que matchean cualquiera de los aliases de tipo aceptados
  const matched = useMemo(
    () => (events || []).filter(e => types.includes(e.type)),
    [events, types]
  );
  // Último evento (más reciente por fecha). Si no hay date, queda al final.
  const latest = useMemo(() => {
    if (!matched.length) return null;
    return [...matched].sort((a, b) => {
      const da = a.date || "";
      const db = b.date || "";
      return db.localeCompare(da);
    })[0];
  }, [matched]);

  // Permiso oculto → no mostrar ni la card
  if (level === "hidden") return null;

  const accentMap = {
    emerald: { bg: "bg-emerald-50", border: "border-emerald-200", iconBg: "bg-emerald-100", iconText: "text-emerald-700", count: "text-emerald-700", btn: "text-emerald-700 hover:bg-emerald-100 border-emerald-200", btnSolid: "bg-emerald-600 hover:bg-emerald-700" },
    blue:    { bg: "bg-blue-50",    border: "border-blue-200",    iconBg: "bg-blue-100",    iconText: "text-blue-700",    count: "text-blue-700",    btn: "text-blue-700 hover:bg-blue-100 border-blue-200",       btnSolid: "bg-blue-600 hover:bg-blue-700" },
    orange:  { bg: "bg-orange-50",  border: "border-orange-200",  iconBg: "bg-orange-100",  iconText: "text-orange-700",  count: "text-orange-700",  btn: "text-orange-700 hover:bg-orange-100 border-orange-200", btnSolid: "bg-orange-600 hover:bg-orange-700" },
    stone:   { bg: "bg-stone-50",   border: "border-stone-200",   iconBg: "bg-stone-100",   iconText: "text-stone-700",   count: "text-stone-700",   btn: "text-stone-700 hover:bg-stone-100 border-stone-200",    btnSolid: "bg-stone-600 hover:bg-stone-700" },
  }[accent] || {};

  const isEmpty = matched.length === 0;
  const canEdit = level === "edit";

  return (
    <div className={`${accentMap.bg} border ${accentMap.border} rounded-2xl p-4 flex flex-col gap-3`}>
      <div className="flex items-center gap-2.5">
        <div className={`w-9 h-9 rounded-xl ${accentMap.iconBg} ${accentMap.iconText} grid place-items-center flex-shrink-0`}>
          <Icon size={17} strokeWidth={1.8} />
        </div>
        <div className="flex-1 min-w-0">
          <div className={`text-xs tracking-widest uppercase font-semibold ${accentMap.iconText}`}>
            {label}
          </div>
          <div className={`font-serif text-2xl font-bold leading-tight ${accentMap.count}`}>
            {matched.length}
            <span className="text-xs font-sans font-normal text-stone-500 ml-1.5">
              {matched.length === 1 ? "registro" : "registros"}
            </span>
          </div>
        </div>
      </div>

      {/* Último registro o estado vacío */}
      <div className="text-xs text-stone-600 min-h-[2.5rem]">
        {isEmpty ? (
          <span className="italic text-stone-400">Sin registros aún.</span>
        ) : (
          <>
            <div className="text-[10px] tracking-widest uppercase text-stone-400 font-semibold">
              Último
            </div>
            <div className="truncate font-medium text-stone-700">{latest.title}</div>
            {latest.date && (
              <div className="text-[11px] text-stone-500 font-mono">{latest.date}</div>
            )}
          </>
        )}
      </div>

      {/* Botones de acción. Si canEdit, mostramos los dos en grid 2-col.
          Si solo view, solo "Ver historial" a ancho completo. */}
      <div className={canEdit ? "grid grid-cols-2 gap-1.5" : ""}>
        <button
          onClick={onView}
          disabled={isEmpty}
          className={`w-full px-3 py-2 rounded-xl text-xs font-semibold border bg-white transition flex items-center justify-center gap-1.5 ${
            isEmpty
              ? "text-stone-400 border-stone-200 cursor-not-allowed"
              : accentMap.btn
          }`}
        >
          <BookOpen size={12} strokeWidth={2} />
          Ver historial
        </button>
        {canEdit && (
          <button
            onClick={onRegister}
            className={`w-full px-3 py-2 rounded-xl text-xs font-semibold text-white transition flex items-center justify-center gap-1.5 ${accentMap.btnSolid}`}
          >
            <Plus size={12} strokeWidth={2.5} />
            Registrar
          </button>
        )}
      </div>
    </div>
  );
}

// === Editor de evento clínico (crear o editar) ===
// Modal compartido para crear o editar un registro de Desparasitación, Vacunación
// o Consulta clínica. Reutiliza la idea de los pasos del wizard NewClientModal
// pero como modal independiente, accionado desde el pasaporte clínico.
//
// Props:
// - type: "deworming" | "vacuna" | "consulta"
// - event: evento existente para editar (null = crear nuevo)
// - passport: pasaporte de la mascota (para context y autor)
// - userName: nombre del usuario logueado (queda como `author`)
// - onClose: cerrar sin guardar
// - onSave: (eventData) => persiste en setPassports
function ClinicalEventEditorModal({ type, event = null, passport, userName = "Operador", onClose, onSave }) {
  // Estado del formulario, inicializado desde el evento existente o vacío.
  // Cada tipo tiene campos distintos pero todos comparten {date, notes, title}.
  const [form, setForm] = useState(() => {
    if (event) {
      // Editar: reconstruir el form desde el evento existente (que puede tener
      // campos estructurados nuevos o solo `note` legacy).
      const base = {
        date: event.date || "",
        title: event.title || "",
        notes: "",
      };
      if (type === "deworming") {
        return { ...base, product: event.product || event.title || "", weight: event.weight || "", vet: event.author || "", nextDate: event.nextDate || "" };
      }
      if (type === "vacuna") {
        return { ...base, vaccine: event.vaccine || event.title || "", batch: event.batch || "", nextDate: event.nextDate || "" };
      }
      // consulta
      return {
        ...base,
        reason: event.title || "",
        fc: event.vitals?.fc || "",
        fr: event.vitals?.fr || "",
        temp: event.vitals?.temp || "",
        findings: event.findings || "",
        treatment: event.treatment || "",
      };
    }
    // Crear nuevo
    const today = new Date().toISOString().slice(0, 10);
    if (type === "deworming") return { date: today, product: "", weight: "", vet: "", nextDate: "", notes: "" };
    if (type === "vacuna")    return { date: today, vaccine: "", batch: "", nextDate: "", notes: "" };
    return { date: today, reason: "", fc: "", fr: "", temp: "", findings: "", treatment: "", notes: "" };
  });

  const upd = (k, v) => setForm(prev => ({ ...prev, [k]: v }));

  const titleByType = {
    deworming: event ? "Editar desparasitación" : "Registrar desparasitación",
    vacuna:    event ? "Editar vacunación"      : "Registrar vacunación",
    consulta:  event ? "Editar consulta clínica": "Registrar consulta clínica",
  };
  const accentByType = {
    deworming: { bg: "bg-emerald-100", text: "text-emerald-700", btn: "bg-emerald-600 hover:bg-emerald-700", Icon: ShieldCheck },
    vacuna:    { bg: "bg-blue-100",    text: "text-blue-700",    btn: "bg-blue-600 hover:bg-blue-700",       Icon: Syringe },
    consulta:  { bg: "bg-orange-100",  text: "text-orange-700",  btn: "bg-orange-600 hover:bg-orange-700",   Icon: Stethoscope },
  }[type];
  const HeaderIcon = accentByType.Icon;

  // Validación básica: al menos un campo significativo lleno (no solo fecha).
  const canSave = useMemo(() => {
    const significant = type === "deworming" ? [form.product, form.weight, form.vet, form.nextDate, form.notes]
                      : type === "vacuna"    ? [form.vaccine, form.batch, form.nextDate, form.notes]
                      :                        [form.reason, form.fc, form.fr, form.temp, form.findings, form.treatment, form.notes];
    return significant.some(v => v && String(v).trim());
  }, [form, type]);

  const handleSave = () => {
    if (!canSave) return;
    // Construir el objeto de evento. Reutilizamos la misma forma que persist()
    // del wizard para que la timeline lo renderice igual.
    const today = new Date().toISOString().slice(0, 10);
    const baseId = event?.id || `ev-${Date.now()}-${type[0]}`;

    let built;
    if (type === "deworming") {
      const noteParts = [
        form.weight && `Peso: ${form.weight} kg`,
        form.vet && `Veterinario: ${form.vet}`,
        form.nextDate && `Próxima dosis: ${form.nextDate}`,
        form.notes,
      ].filter(Boolean);
      built = {
        id: baseId, type: "deworming",
        date: form.date || today,
        title: form.product?.trim() || "Desparasitación registrada",
        note: noteParts.join(" · ") || "Sin detalles adicionales.",
        author: form.vet?.trim() || userName,
        product: form.product || null,
        weight: form.weight || null,
        nextDate: form.nextDate || null,
      };
    } else if (type === "vacuna") {
      const noteParts = [
        form.batch && `Lote: ${form.batch}`,
        form.nextDate && `Repetir: ${form.nextDate}`,
        form.notes,
      ].filter(Boolean);
      built = {
        id: baseId, type: "vacuna",
        date: form.date || today,
        title: form.vaccine?.trim() || "Vacunación registrada",
        note: noteParts.join(" · ") || "Sin detalles adicionales.",
        author: userName,
        vaccine: form.vaccine || null,
        batch: form.batch || null,
        nextDate: form.nextDate || null,
      };
    } else {
      const vitals = [
        form.fc && `FC ${form.fc} lpm`,
        form.fr && `FR ${form.fr} rpm`,
        form.temp && `T° ${form.temp}°C`,
      ].filter(Boolean).join(" · ");
      const noteParts = [
        vitals,
        form.findings && `Diagnóstico: ${form.findings}`,
        form.treatment && `Tratamiento: ${form.treatment}`,
        form.notes,
      ].filter(Boolean);
      built = {
        id: baseId, type: "consulta",
        date: form.date || today,
        title: form.reason?.trim() || "Consulta clínica",
        note: noteParts.join(" · ") || "Sin detalles adicionales.",
        author: userName,
        vitals: { fc: form.fc || null, fr: form.fr || null, temp: form.temp || null },
        findings: form.findings || null,
        treatment: form.treatment || null,
      };
    }

    onSave(built, !!event); // segundo arg = isEdit
  };

  const inputCls = "w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500";

  return (
    <div onClick={onClose} className="fixed inset-0 bg-stone-900/80 z-50 flex justify-center items-start p-4 overflow-y-auto">
      <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl w-full max-w-xl shadow-2xl my-8 overflow-hidden">
        {/* Header */}
        <div className="p-4 border-b border-stone-200 flex items-center gap-3">
          <div className={`w-10 h-10 rounded-xl ${accentByType.bg} ${accentByType.text} grid place-items-center flex-shrink-0`}>
            <HeaderIcon size={18} strokeWidth={1.8} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold">
              Pasaporte de {passport?.name || "—"} · #{passport?.code}
            </div>
            <h3 className="font-serif text-lg font-semibold mt-0.5">{titleByType[type]}</h3>
          </div>
          <button onClick={onClose} className="w-9 h-9 rounded-full bg-stone-100 hover:bg-stone-200 grid place-items-center text-stone-600 transition flex-shrink-0">
            <X size={15} />
          </button>
        </div>

        {/* Body — formulario por tipo */}
        <div className="p-5 space-y-3 max-h-[60vh] overflow-y-auto">
          {type === "deworming" && (
            <>
              <Field label="Desparasitante aplicado">
                <select value={form.product} onChange={(e) => upd("product", e.target.value)} className={inputCls}>
                  <option value="">Seleccionar...</option>
                  <option>Drontal Plus</option>
                  <option>Milbemax</option>
                  <option>NexGard Spectra</option>
                  <option>Bravecto Plus</option>
                </select>
              </Field>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                <Field label="Peso"><input type="number" value={form.weight} onChange={(e) => upd("weight", e.target.value)} className={inputCls} placeholder="kg" /></Field>
                <Field label="Veterinario responsable"><input value={form.vet} onChange={(e) => upd("vet", e.target.value)} className={inputCls} placeholder="Dr/a..." /></Field>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                <Field label="Fecha"><input type="date" value={form.date} onChange={(e) => upd("date", e.target.value)} className={inputCls} /></Field>
                <Field label="Próxima dosis"><input type="date" value={form.nextDate} onChange={(e) => upd("nextDate", e.target.value)} className={inputCls} /></Field>
              </div>
              <Field label="Notas"><textarea rows={2} value={form.notes} onChange={(e) => upd("notes", e.target.value)} className={`${inputCls} resize-none`} placeholder="Observaciones..." /></Field>
            </>
          )}

          {type === "vacuna" && (
            <>
              <Field label="Tipo de vacuna">
                <select value={form.vaccine} onChange={(e) => upd("vaccine", e.target.value)} className={inputCls}>
                  <option value="">Seleccionar...</option>
                  <option>Polivalente (DHPPi)</option>
                  <option>Antirrábica</option>
                  <option>Triple felina</option>
                  <option>Leucemia felina</option>
                </select>
              </Field>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                <Field label="Fecha aplicada"><input type="date" value={form.date} onChange={(e) => upd("date", e.target.value)} className={inputCls} /></Field>
                <Field label="Repetir"><input type="date" value={form.nextDate} onChange={(e) => upd("nextDate", e.target.value)} className={inputCls} /></Field>
                <Field label="Lote"><input value={form.batch} onChange={(e) => upd("batch", e.target.value)} className={inputCls} placeholder="VL-23984" /></Field>
              </div>
              <Field label="Notas"><textarea rows={2} value={form.notes} onChange={(e) => upd("notes", e.target.value)} className={`${inputCls} resize-none`} placeholder="Reacciones, observaciones..." /></Field>
            </>
          )}

          {type === "consulta" && (
            <>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                <Field label="Fecha"><input type="date" value={form.date} onChange={(e) => upd("date", e.target.value)} className={inputCls} /></Field>
                <Field label="Motivo de la consulta"><input value={form.reason} onChange={(e) => upd("reason", e.target.value)} className={inputCls} placeholder="Ej: Vómito" /></Field>
              </div>
              <div>
                <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold pb-2 border-b border-stone-200 mb-3">Evaluación física</div>
                <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
                  <Field label="FC (lpm)"><input type="number" value={form.fc} onChange={(e) => upd("fc", e.target.value)} className={inputCls} /></Field>
                  <Field label="FR (rpm)"><input type="number" value={form.fr} onChange={(e) => upd("fr", e.target.value)} className={inputCls} /></Field>
                  <Field label="Temperatura (°C)"><input type="number" step="0.1" value={form.temp} onChange={(e) => upd("temp", e.target.value)} className={inputCls} /></Field>
                </div>
              </div>
              <Field label="Diagnóstico"><textarea rows={2} value={form.findings} onChange={(e) => upd("findings", e.target.value)} className={`${inputCls} resize-none`} placeholder="Diagnóstico presuntivo..." /></Field>
              <Field label="Tratamiento"><textarea rows={3} value={form.treatment} onChange={(e) => upd("treatment", e.target.value)} className={`${inputCls} resize-none`} placeholder="Medicación, dosis, indicaciones..." /></Field>
              <Field label="Notas internas"><textarea rows={2} value={form.notes} onChange={(e) => upd("notes", e.target.value)} className={`${inputCls} resize-none`} placeholder="Observaciones..." /></Field>
            </>
          )}
        </div>

        {/* Footer */}
        <div className="p-3 border-t border-stone-200 bg-stone-50 flex justify-end gap-2">
          <button onClick={onClose} className="px-4 py-2 rounded-xl text-sm font-semibold bg-white text-stone-700 border border-stone-200 hover:border-stone-400 transition">
            Cancelar
          </button>
          <button
            onClick={handleSave}
            disabled={!canSave}
            className={`px-4 py-2 rounded-xl text-sm font-semibold text-white transition flex items-center gap-1.5 ${
              canSave ? accentByType.btn : "bg-stone-300 cursor-not-allowed"
            }`}
          >
            <Check size={14} strokeWidth={2.5} />
            {event ? "Guardar cambios" : "Registrar"}
          </button>
        </div>
      </div>
    </div>
  );
}

function ClinicalTimelineEvent({ event, onView, onEdit }) {
  const typeInfo = {
    vet:           { label: "Consulta",        Icon: Stethoscope, color: "orange"  },
    consulta:      { label: "Consulta",        Icon: Stethoscope, color: "orange"  },
    vacuna:        { label: "Vacunación",      Icon: Syringe,     color: "blue"    },
    vaccination:   { label: "Vacunación",      Icon: Syringe,     color: "blue"    },
    tratamiento:   { label: "Tratamiento",     Icon: Pill,        color: "purple"  },
    treatment:     { label: "Tratamiento",     Icon: Pill,        color: "purple"  },
    deworming:     { label: "Desparasitación", Icon: Pill,        color: "emerald" },
    desparasitacion: { label: "Desparasitación", Icon: Pill,      color: "emerald" },
    cirugía:       { label: "Cirugía",         Icon: Scissors,    color: "red"     },
    cirugia:       { label: "Cirugía",         Icon: Scissors,    color: "red"     },
    surgery:       { label: "Cirugía",         Icon: Scissors,    color: "red"     },
    examen:        { label: "Examen",          Icon: FlaskConical,color: "blue"    },
    examination:   { label: "Examen",          Icon: FlaskConical,color: "blue"    },
  }[event.type] || { label: event.type, Icon: Stethoscope, color: "stone" };

  const colorClasses = {
    orange:  { bg: "bg-orange-100",  text: "text-orange-700",  border: "border-orange-200",  pill: "bg-orange-50 text-orange-700"  },
    blue:    { bg: "bg-blue-100",    text: "text-blue-700",    border: "border-blue-200",    pill: "bg-blue-50 text-blue-700"    },
    purple:  { bg: "bg-purple-100",  text: "text-purple-700",  border: "border-purple-200",  pill: "bg-purple-50 text-purple-700"  },
    emerald: { bg: "bg-emerald-100", text: "text-emerald-700", border: "border-emerald-200", pill: "bg-emerald-50 text-emerald-700" },
    red:     { bg: "bg-red-100",     text: "text-red-700",     border: "border-red-200",     pill: "bg-red-50 text-red-700"     },
    stone:   { bg: "bg-stone-100",   text: "text-stone-700",   border: "border-stone-200",   pill: "bg-stone-100 text-stone-700"   },
  }[typeInfo.color];

  const Icon = typeInfo.Icon;

  return (
    <div className="flex gap-3 relative pl-0">
      <div className={`w-6 h-6 rounded-full ${colorClasses.bg} ${colorClasses.text} grid place-items-center flex-shrink-0 mt-1 border-2 border-white relative z-10`}>
        <Icon size={11} strokeWidth={2} />
      </div>
      <div className={`flex-1 min-w-0 p-3 rounded-xl bg-white border ${colorClasses.border} hover:shadow transition`}>
        <div className="flex items-center justify-between gap-2 flex-wrap mb-1">
          <div className="flex items-center gap-2 flex-wrap">
            <span className={`text-xs font-bold uppercase tracking-wider ${colorClasses.text}`}>
              {typeInfo.label}
            </span>
            {event.title && (
              <>
                <span className="text-stone-300">·</span>
                <span className="text-sm font-semibold text-stone-800">{event.title}</span>
              </>
            )}
          </div>
          <div className="flex items-center gap-2 flex-shrink-0">
            <span className="text-xs text-stone-500 whitespace-nowrap">{event.date}</span>
            {/* Lapiz para editar (solo si hay permiso de edit para este tipo) */}
            {onEdit && (
              <button
                onClick={() => onEdit(event)}
                title="Editar este registro"
                className="w-7 h-7 rounded-lg bg-stone-100 hover:bg-orange-100 grid place-items-center text-stone-600 hover:text-orange-700 transition"
              >
                <Edit3 size={11} />
              </button>
            )}
            {/* Lupa para abrir el detalle completo del evento */}
            {onView && (
              <button
                onClick={() => onView(event)}
                title="Ver detalle completo"
                className="w-7 h-7 rounded-lg bg-stone-100 hover:bg-orange-100 grid place-items-center text-stone-600 hover:text-orange-700 transition"
              >
                <Search size={11} />
              </button>
            )}
          </div>
        </div>
        {event.note && (
          <div className="text-sm text-stone-700 leading-relaxed mt-1">
            {event.note}
          </div>
        )}
        {event.author && (
          <div className="flex items-center gap-2 mt-2 pt-2 border-t border-stone-100">
            <div className="w-5 h-5 rounded-full bg-gradient-to-br from-orange-500 to-orange-700 grid place-items-center text-white text-xs font-bold">
              {event.author.split(" ").slice(0, 2).map(s => s[0]).join("").toUpperCase()}
            </div>
            <span className="text-xs text-stone-600">
              Atendido por <strong className="text-stone-800">{event.author}</strong>
            </span>
          </div>
        )}
      </div>
    </div>
  );
}

// ========== VISTA: PERFIL DE USUARIO ==========
// Disponible para todos los roles. Cada usuario configura su perfil profesional.

function UserProfileView({ user, setUser }) {
  const [activeTab, setActiveTab] = useState("personal"); // personal | professional | preferences | security
  // Separamos cualquier título embebido en el nombre ("Dra. Romero" → "Romero")
  // para que el nombre/apellido y el selector de título no se dupliquen.
  const { title: _initialTitle, baseName: _baseName } = splitNameTitle(user?.name || "");
  const [profile, setProfile] = useState(() => ({
    avatar: null, // URL o base64
    avatarInitials: user?.initials || "??",

    // Personal
    title: user?.title || _initialTitle || "", // título profesional (Dr., Lic., etc.)
    firstName: _baseName.split(" ")[0] || "",
    lastName: _baseName.split(" ").slice(1).join(" ") || "",
    displayName: _baseName || user?.name || "",
    pronouns: "",
    bio: "",
    birthdate: "",

    // Contacto
    email: user?.email || `${(user?.name || "user").toLowerCase().replace(/\s/g, ".")}@cricket.vet`,
    phone: "",
    address: "",
    city: "Caracas",
    country: "Venezuela",

    // Profesional
    role: user?.roleLabel || "",
    department: "",
    licenseNumber: "",
    specialties: [],
    yearsOfExperience: "",
    education: "",
    certifications: "",
    languages: ["Español"],

    // Redes sociales / web
    website: "",
    linkedin: "",
    instagram: "",

    // Preferencias
    notificationsEmail: true,
    notificationsPush: true,
    notificationsWhatsApp: false,
    weekStart: "monday",
    timezone: "America/Caracas",
    language: "es",
    theme: "light",
  }));

  const [saved, setSaved] = useState(false);
  const [unsavedChanges, setUnsavedChanges] = useState(false);

  const update = (field, value) => {
    setProfile(prev => ({ ...prev, [field]: value }));
    setUnsavedChanges(true);
    setSaved(false);
  };

  const toggleSpecialty = (sp) => {
    const current = profile.specialties;
    update("specialties", current.includes(sp) ? current.filter(s => s !== sp) : [...current, sp]);
  };

  const toggleLanguage = (lang) => {
    const current = profile.languages;
    update("languages", current.includes(lang) ? current.filter(l => l !== lang) : [...current, lang]);
  };

  const handleAvatarChange = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    // En producción: subir a Supabase Storage y guardar la URL
    const reader = new FileReader();
    reader.onload = () => update("avatar", reader.result);
    reader.readAsDataURL(file);
  };

  const handleSave = () => {
    // En producción: PATCH /api/users/me con el perfil completo.
    // Por ahora persistimos al state global lo que afecta a otras vistas:
    // el título profesional y el nombre para mostrar (que alimentan, entre
    // otros, el saludo del dashboard).
    if (setUser) {
      const cleanName = (profile.displayName || "").trim()
        || `${profile.firstName} ${profile.lastName}`.trim();
      // Recalcular iniciales a partir del nombre limpio (sin título)
      const initials = cleanName
        .split(/\s+/)
        .filter(Boolean)
        .slice(0, 2)
        .map(w => w[0]?.toUpperCase() || "")
        .join("") || (user?.initials || "??");
      setUser(prev => ({
        ...prev,
        name: cleanName || prev?.name,
        title: profile.title || "",
        initials,
      }));
    }
    setSaved(true);
    setUnsavedChanges(false);
    setTimeout(() => setSaved(false), 3000);
  };

  const SPECIALTIES_BY_ROLE = {
    "Veterinario": ["Cirugía", "Dermatología", "Cardiología", "Oftalmología", "Odontología", "Oncología", "Etología", "Medicina interna", "Animales exóticos"],
    "Groomer": ["Razas grandes", "Razas pequeñas", "Cortes por estándar", "Spa relajante", "Tratamiento dérmico", "Felinos"],
    "Ventas": ["Atención al cliente", "Negociación B2B", "Recobro", "Inventario"],
    "Super usuario": ["Administración general", "Gestión de equipos", "Estrategia"],
  };

  const availableSpecialties = SPECIALTIES_BY_ROLE[profile.role] || [];

  const tabs = [
    { id: "personal",     label: "Personal",     Icon: User },
    { id: "professional", label: "Profesional",  Icon: BadgeCheck },
    { id: "preferences",  label: "Preferencias", Icon: Settings },
    { id: "security",     label: "Seguridad",    Icon: Lock },
  ];

  return (
    <div className="space-y-5">
      {/* Hero del perfil */}
      <div className="relative p-6 rounded-2xl bg-gradient-to-br from-white via-orange-50 to-orange-100 border border-stone-200 overflow-hidden">
        <div className="flex items-center gap-5 flex-wrap">
          {/* Avatar grande con upload */}
          <div className="relative flex-shrink-0">
            <div className="w-24 h-24 rounded-2xl bg-gradient-to-br from-orange-500 to-orange-700 grid place-items-center text-white text-3xl font-bold shadow-xl border-4 border-white overflow-hidden">
              {profile.avatar ? (
                <img src={profile.avatar} alt="Avatar" className="w-full h-full object-cover" />
              ) : (
                <span className="font-serif">{profile.avatarInitials}</span>
              )}
            </div>
            <label className="absolute -bottom-1 -right-1 w-9 h-9 rounded-xl bg-stone-900 hover:bg-stone-700 text-white grid place-items-center cursor-pointer shadow-lg transition" title="Cambiar foto">
              <input type="file" accept="image/*" className="hidden" onChange={handleAvatarChange} />
              <Camera size={14} />
            </label>
          </div>

          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold mb-1">
              Mi cuenta
            </div>
            <h2 className="font-serif text-3xl font-semibold leading-tight">
              {`${profile.title ? profile.title + " " : ""}${profile.displayName || "Sin nombre"}`}
            </h2>
            <div className="flex items-center gap-3 mt-2 flex-wrap text-sm text-stone-600">
              <span className="flex items-center gap-1.5">
                <BadgeCheck size={14} className="text-orange-600" />
                {profile.role}
              </span>
              {profile.email && (
                <span className="flex items-center gap-1.5">
                  <Mail size={13} />
                  {profile.email}
                </span>
              )}
            </div>
          </div>

          <div className="flex flex-col gap-2 items-end">
            {saved && (
              <div className="flex items-center gap-1.5 text-xs font-semibold text-emerald-700 bg-emerald-100 px-3 py-1.5 rounded-full">
                <Check size={12} strokeWidth={2.5} /> Guardado
              </div>
            )}
            <button
              onClick={handleSave}
              disabled={!unsavedChanges}
              className={`flex items-center gap-1.5 px-4 py-2.5 rounded-xl text-sm font-semibold transition ${
                unsavedChanges
                  ? "bg-orange-600 hover:bg-orange-700 text-white shadow-lg"
                  : "bg-white border border-stone-200 text-stone-400 cursor-not-allowed"
              }`}
            >
              <Check size={14} /> Guardar cambios
            </button>
          </div>
        </div>
      </div>

      {/* Tabs */}
      <div className="bg-white border border-stone-200 rounded-2xl shadow-sm p-1.5 flex gap-1 overflow-x-auto">
        {tabs.map(t => {
          const Ic = t.Icon;
          const active = activeTab === t.id;
          return (
            <button
              key={t.id}
              onClick={() => setActiveTab(t.id)}
              className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-semibold transition flex-shrink-0 ${
                active ? "bg-stone-900 text-white" : "text-stone-600 hover:bg-stone-50"
              }`}
            >
              <Ic size={14} />
              {t.label}
            </button>
          );
        })}
      </div>

      {/* Tab content */}
      {activeTab === "personal" && (
        <ProfileSection title="Información personal" desc="Cómo te identificas dentro y fuera del sistema.">
          <ProfileField label="Título profesional" hint="Opcional. Se antepone a tu nombre en el saludo del dashboard.">
            <select
              value={profile.title}
              onChange={(e) => update("title", e.target.value)}
              className="w-full sm:max-w-xs px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500 cursor-pointer"
            >
              {USER_TITLES.map(t => (
                <option key={t.value || "none"} value={t.value}>{t.label}</option>
              ))}
            </select>
          </ProfileField>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            <ProfileField label="Nombre">
              <input
                value={profile.firstName}
                onChange={(e) => update("firstName", e.target.value)}
                className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
              />
            </ProfileField>
            <ProfileField label="Apellido">
              <input
                value={profile.lastName}
                onChange={(e) => update("lastName", e.target.value)}
                className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
              />
            </ProfileField>
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            <ProfileField label="Nombre para mostrar" hint="Cómo aparecerás en el CRM y notificaciones.">
              <input
                value={profile.displayName}
                onChange={(e) => update("displayName", e.target.value)}
                className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
              />
            </ProfileField>
            <ProfileField label="Pronombres" hint="Opcional. Ej: ella/her, él/him, elle/them.">
              <input
                value={profile.pronouns}
                onChange={(e) => update("pronouns", e.target.value)}
                placeholder="ella/her"
                className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
              />
            </ProfileField>
          </div>
          <ProfileField label="Bio breve" hint="Una línea sobre vos. Visible para el equipo.">
            <textarea
              value={profile.bio}
              onChange={(e) => update("bio", e.target.value)}
              placeholder="Veterinaria especializada en cardiología canina con 8 años de experiencia."
              rows={2}
              className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500 resize-none"
            />
          </ProfileField>
          <ProfileField label="Fecha de nacimiento">
            <input
              type="date"
              value={profile.birthdate}
              onChange={(e) => update("birthdate", e.target.value)}
              className="w-full sm:max-w-xs px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
            />
          </ProfileField>
        </ProfileSection>
      )}

      {activeTab === "personal" && (
        <ProfileSection title="Contacto" desc="Cómo te pueden ubicar dentro y fuera de la oficina.">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            <ProfileField label="Email corporativo" hint="No editable. Contacta a admin.">
              <input
                value={profile.email}
                disabled
                className="w-full px-3.5 py-2.5 bg-stone-100 border border-stone-200 rounded-xl text-sm text-stone-500 cursor-not-allowed"
              />
            </ProfileField>
            <ProfileField label="Teléfono / WhatsApp">
              <input
                value={profile.phone}
                onChange={(e) => update("phone", e.target.value)}
                placeholder="0414-1234567"
                className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
              />
            </ProfileField>
          </div>
          <ProfileField label="Dirección">
            <input
              value={profile.address}
              onChange={(e) => update("address", e.target.value)}
              placeholder="Av. Principal de Las Mercedes"
              className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
            />
          </ProfileField>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            <ProfileField label="Ciudad">
              <input
                value={profile.city}
                onChange={(e) => update("city", e.target.value)}
                className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
              />
            </ProfileField>
            <ProfileField label="País">
              <input
                value={profile.country}
                onChange={(e) => update("country", e.target.value)}
                className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
              />
            </ProfileField>
          </div>
        </ProfileSection>
      )}

      {activeTab === "professional" && (
        <ProfileSection title="Información profesional" desc="Tu rol, credenciales y experiencia. Visible para clientes en la landing.">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            <ProfileField label="Rol" hint="Asignado por el administrador.">
              <input
                value={profile.role}
                disabled
                className="w-full px-3.5 py-2.5 bg-stone-100 border border-stone-200 rounded-xl text-sm text-stone-500 cursor-not-allowed font-semibold"
              />
            </ProfileField>
            <ProfileField label="Departamento / equipo">
              <input
                value={profile.department}
                onChange={(e) => update("department", e.target.value)}
                placeholder="Clínica veterinaria · Turno mañana"
                className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
              />
            </ProfileField>
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            <ProfileField label="Número de colegiación / matrícula" hint="Visible en el pasaporte de mascotas y certificados.">
              <input
                value={profile.licenseNumber}
                onChange={(e) => update("licenseNumber", e.target.value)}
                placeholder="MV-12345"
                className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm font-mono outline-none focus:border-orange-500"
              />
            </ProfileField>
            <ProfileField label="Años de experiencia">
              <input
                type="number"
                min={0}
                max={70}
                value={profile.yearsOfExperience}
                onChange={(e) => update("yearsOfExperience", e.target.value)}
                placeholder="8"
                className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
              />
            </ProfileField>
          </div>

          {availableSpecialties.length > 0 && (
            <ProfileField label="Especialidades" hint={`Áreas de práctica para ${profile.role.toLowerCase()}.`}>
              <div className="flex gap-1.5 flex-wrap">
                {availableSpecialties.map(sp => {
                  const active = profile.specialties.includes(sp);
                  return (
                    <button
                      key={sp}
                      onClick={() => toggleSpecialty(sp)}
                      className={`px-3 py-1.5 rounded-full text-xs font-semibold transition ${
                        active
                          ? "bg-orange-600 text-white"
                          : "bg-white text-stone-600 border border-stone-200 hover:border-orange-300"
                      }`}
                    >
                      {active && <Check size={11} strokeWidth={2.5} className="inline mr-1" />}
                      {sp}
                    </button>
                  );
                })}
              </div>
            </ProfileField>
          )}

          <ProfileField label="Educación" hint="Universidad, postgrados, especializaciones.">
            <textarea
              value={profile.education}
              onChange={(e) => update("education", e.target.value)}
              placeholder="Lic. en Medicina Veterinaria · Universidad Central de Venezuela (2018)"
              rows={2}
              className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500 resize-none"
            />
          </ProfileField>

          <ProfileField label="Certificaciones" hint="Una por línea.">
            <textarea
              value={profile.certifications}
              onChange={(e) => update("certifications", e.target.value)}
              placeholder="WSAVA Member 2020&#10;Curso Ecocardiografía Veterinaria · UBA 2022"
              rows={3}
              className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500 resize-none"
            />
          </ProfileField>

          <ProfileField label="Idiomas que hablas">
            <div className="flex gap-1.5 flex-wrap">
              {["Español", "Inglés", "Portugués", "Francés", "Italiano", "Lengua de señas"].map(lang => {
                const active = profile.languages.includes(lang);
                return (
                  <button
                    key={lang}
                    onClick={() => toggleLanguage(lang)}
                    className={`px-3 py-1.5 rounded-full text-xs font-semibold transition ${
                      active
                        ? "bg-stone-900 text-white"
                        : "bg-white text-stone-600 border border-stone-200 hover:border-stone-400"
                    }`}
                  >
                    {active && <Check size={11} strokeWidth={2.5} className="inline mr-1" />}
                    {lang}
                  </button>
                );
              })}
            </div>
          </ProfileField>
        </ProfileSection>
      )}

      {activeTab === "professional" && (
        <ProfileSection title="Presencia online" desc="Enlaces a tus perfiles profesionales.">
          <ProfileField label="Sitio web personal">
            <div className="relative">
              <ExternalLink size={13} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-stone-400" />
              <input
                value={profile.website}
                onChange={(e) => update("website", e.target.value)}
                placeholder="https://mipagina.com"
                className="w-full pl-9 pr-3 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
              />
            </div>
          </ProfileField>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            <ProfileField label="LinkedIn">
              <div className="relative">
                <Facebook size={13} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-blue-600" />
                <input
                  value={profile.linkedin}
                  onChange={(e) => update("linkedin", e.target.value)}
                  placeholder="linkedin.com/in/usuario"
                  className="w-full pl-9 pr-3 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
                />
              </div>
            </ProfileField>
            <ProfileField label="Instagram">
              <div className="relative">
                <Instagram size={13} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-pink-600" />
                <input
                  value={profile.instagram}
                  onChange={(e) => update("instagram", e.target.value)}
                  placeholder="@miusuario"
                  className="w-full pl-9 pr-3 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
                />
              </div>
            </ProfileField>
          </div>
        </ProfileSection>
      )}

      {activeTab === "preferences" && (
        <>
          <ProfileSection title="Notificaciones" desc="Cómo te avisamos de eventos del sistema.">
            <ToggleRow
              icon={Mail}
              label="Email"
              desc="Recordatorios de citas, reportes diarios, asignaciones."
              checked={profile.notificationsEmail}
              onChange={() => update("notificationsEmail", !profile.notificationsEmail)}
            />
            <ToggleRow
              icon={Bell}
              label="Notificaciones push del navegador"
              desc="Alertas en tiempo real cuando estés con el CRM abierto."
              checked={profile.notificationsPush}
              onChange={() => update("notificationsPush", !profile.notificationsPush)}
            />
            <ToggleRow
              icon={MessageCircle}
              label="WhatsApp Business"
              desc="Recibir alertas urgentes (emergencias, mensajes sin respuesta)."
              checked={profile.notificationsWhatsApp}
              onChange={() => update("notificationsWhatsApp", !profile.notificationsWhatsApp)}
            />
          </ProfileSection>

          <ProfileSection title="Preferencias regionales" desc="Cómo se muestran fechas, horas e idioma del sistema.">
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              <ProfileField label="Inicio de semana">
                <select
                  value={profile.weekStart}
                  onChange={(e) => update("weekStart", e.target.value)}
                  className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm font-semibold outline-none cursor-pointer"
                >
                  <option value="monday">Lunes</option>
                  <option value="sunday">Domingo</option>
                </select>
              </ProfileField>
              <ProfileField label="Zona horaria">
                <select
                  value={profile.timezone}
                  onChange={(e) => update("timezone", e.target.value)}
                  className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm font-semibold outline-none cursor-pointer"
                >
                  <option value="America/Caracas">America/Caracas (UTC-4)</option>
                  <option value="America/Bogota">America/Bogota (UTC-5)</option>
                  <option value="America/Mexico_City">America/Mexico_City (UTC-6)</option>
                  <option value="America/Argentina/Buenos_Aires">Argentina/Buenos_Aires (UTC-3)</option>
                  <option value="Europe/Madrid">Europe/Madrid (UTC+1)</option>
                </select>
              </ProfileField>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              <ProfileField label="Idioma del sistema">
                <select
                  value={profile.language}
                  onChange={(e) => update("language", e.target.value)}
                  className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm font-semibold outline-none cursor-pointer"
                >
                  <option value="es">Español</option>
                  <option value="en">English</option>
                  <option value="pt">Português</option>
                </select>
              </ProfileField>
              <ProfileField label="Tema visual">
                <div className="flex gap-2">
                  {[
                    { id: "light", label: "Claro", Icon: Sparkles },
                    { id: "dark",  label: "Oscuro", Icon: Settings },
                    { id: "auto",  label: "Auto",   Icon: Clock },
                  ].map(opt => {
                    const Ic = opt.Icon;
                    const active = profile.theme === opt.id;
                    return (
                      <button
                        key={opt.id}
                        onClick={() => update("theme", opt.id)}
                        className={`flex-1 flex flex-col items-center gap-1 py-2 rounded-xl border transition ${
                          active ? "bg-orange-50 border-orange-400 text-orange-700" : "bg-white border-stone-200 text-stone-600"
                        }`}
                      >
                        <Ic size={14} />
                        <span className="text-xs font-semibold">{opt.label}</span>
                      </button>
                    );
                  })}
                </div>
              </ProfileField>
            </div>
          </ProfileSection>
        </>
      )}

      {activeTab === "security" && (
        <>
          <ProfileSection title="Cambio de contraseña" desc="Recomendamos contraseñas largas con palabras memorables.">
            <ProfileField label="Contraseña actual">
              <input
                type="password"
                placeholder="••••••••"
                className="w-full sm:max-w-md px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
              />
            </ProfileField>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              <ProfileField label="Nueva contraseña">
                <input
                  type="password"
                  placeholder="••••••••"
                  className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
                />
              </ProfileField>
              <ProfileField label="Confirmar nueva contraseña">
                <input
                  type="password"
                  placeholder="••••••••"
                  className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
                />
              </ProfileField>
            </div>
            <button className="flex items-center gap-1.5 px-4 py-2 rounded-xl bg-stone-900 hover:bg-stone-700 text-white text-sm font-semibold transition w-full sm:w-auto">
              <Lock size={13} /> Actualizar contraseña
            </button>
          </ProfileSection>

          <ProfileSection title="Autenticación de dos factores" desc="Capa extra de seguridad para tu cuenta.">
            <div className="bg-amber-50 border border-amber-200 rounded-xl p-4 flex items-start gap-3">
              <ShieldCheck size={18} className="text-amber-700 flex-shrink-0 mt-0.5" />
              <div className="flex-1">
                <div className="font-semibold text-sm text-amber-900">2FA aún no configurado</div>
                <div className="text-xs text-amber-800 mt-0.5">
                  Activá la autenticación con app autenticadora (Google Authenticator, 1Password, Authy).
                </div>
              </div>
              <button className="px-3 py-1.5 rounded-lg bg-amber-600 hover:bg-amber-700 text-white text-xs font-semibold transition">
                Activar
              </button>
            </div>
          </ProfileSection>

          <ProfileSection title="Sesiones activas" desc="Dispositivos donde tienes la sesión iniciada.">
            <div className="bg-white border border-stone-200 rounded-xl divide-y divide-stone-100">
              <div className="p-3 flex items-center gap-3">
                <div className="w-9 h-9 rounded-lg bg-emerald-100 text-emerald-700 grid place-items-center flex-shrink-0">
                  <ShieldCheck size={14} />
                </div>
                <div className="flex-1 min-w-0">
                  <div className="text-sm font-semibold flex items-center gap-2">
                    Esta sesión
                    <span className="text-xs font-bold px-1.5 py-px rounded bg-emerald-100 text-emerald-700">
                      Actual
                    </span>
                  </div>
                  <div className="text-xs text-stone-500">Chrome · macOS · Caracas, Venezuela · Hoy a las 14:32</div>
                </div>
              </div>
              <div className="p-3 flex items-center gap-3">
                <div className="w-9 h-9 rounded-lg bg-stone-100 text-stone-600 grid place-items-center flex-shrink-0">
                  <Phone size={14} />
                </div>
                <div className="flex-1 min-w-0">
                  <div className="text-sm font-semibold">iPhone (Safari)</div>
                  <div className="text-xs text-stone-500">Caracas, Venezuela · Hace 2 días</div>
                </div>
                <button className="text-xs font-semibold text-red-600 hover:underline">
                  Cerrar
                </button>
              </div>
            </div>
            <button className="text-xs font-semibold text-red-600 hover:underline mt-2">
              Cerrar todas las demás sesiones
            </button>
          </ProfileSection>

          <ProfileSection title="Zona peligrosa" desc="Acciones irreversibles. Pensá dos veces.">
            <div className="bg-red-50 border border-red-200 rounded-xl p-4 flex items-start gap-3">
              <AlertTriangle size={18} className="text-red-700 flex-shrink-0 mt-0.5" />
              <div className="flex-1">
                <div className="font-semibold text-sm text-red-900">Eliminar mi cuenta</div>
                <div className="text-xs text-red-800 mt-0.5 leading-relaxed">
                  Tu acceso será revocado y los datos asociados pasarán a un estado anonimizado. Las recibos y registros médicos firmados se conservan por requerimiento legal.
                </div>
              </div>
              <button className="px-3 py-1.5 rounded-lg bg-white border border-red-300 text-red-700 hover:bg-red-100 text-xs font-semibold transition flex-shrink-0">
                Solicitar baja
              </button>
            </div>
          </ProfileSection>
        </>
      )}
    </div>
  );
}

function ProfileSection({ title, desc, children }) {
  return (
    <div className="bg-white border border-stone-200 rounded-2xl shadow-sm p-5 space-y-3">
      <div>
        <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold">{title}</div>
        {desc && <div className="text-xs text-stone-500 mt-0.5">{desc}</div>}
      </div>
      {children}
    </div>
  );
}

function ProfileField({ label, hint, children }) {
  return (
    <div>
      <label className="text-xs font-semibold text-stone-700 block mb-1.5">{label}</label>
      {children}
      {hint && <div className="text-xs text-stone-500 mt-1">{hint}</div>}
    </div>
  );
}

function ToggleRow({ icon: Icon, label, desc, checked, onChange }) {
  return (
    <button
      onClick={onChange}
      className={`w-full flex items-center gap-3 p-3 rounded-xl border transition text-left ${
        checked
          ? "bg-orange-50 border-orange-200"
          : "bg-white border-stone-200 hover:border-stone-300"
      }`}
    >
      <div className={`w-9 h-9 rounded-lg grid place-items-center flex-shrink-0 ${
        checked ? "bg-orange-100 text-orange-700" : "bg-stone-100 text-stone-500"
      }`}>
        <Icon size={15} strokeWidth={1.8} />
      </div>
      <div className="flex-1 min-w-0">
        <div className="font-semibold text-sm">{label}</div>
        <div className="text-xs text-stone-500 mt-0.5">{desc}</div>
      </div>
      <span className={`w-10 h-5 rounded-full relative transition flex-shrink-0 ${checked ? "bg-orange-600" : "bg-stone-300"}`}>
        <span className={`absolute top-0.5 w-4 h-4 rounded-full bg-white shadow transition ${checked ? "left-5" : "left-0.5"}`}></span>
      </span>
    </button>
  );
}

// ========== PLACEHOLDER: VISTAS EN DESARROLLO ==========

// ========== CRM HUB UNIFICADO (Veterinaria + Grooming + B2B por rol) ==========
// Reemplaza al sidebar antiguo donde cada CRM era un ítem independiente.
// Las secciones disponibles dependen de los permisos del rol actual.
// El super admin ve todas y puede cambiar de "vista de rol" para previsualizar
// cómo se ve la app desde otro rol — útil para QA y onboarding.
function CRMHubView({ userRole, perm, permissions = {}, modules = [], onSelectSection, vetProps, groomingOpsProps, standardProps, salesProps, onGoToManager, sedes = [], setSedes = null, activeSedeId = null, setActiveSedeId = null, user = null }) {
  // ¿Puede el rol acceder al ajuste de CRM?
  const canManageCRM = userRole === "super" ||
    getFieldLevel(permissions, userRole, "config", "modules", "view-manager") !== "hidden";
  // Lookup helper: ¿el módulo X está instalado y NO removido?
  const isInstalled = (id) => {
    if (id === "sales") return true; // sales es parte del tronco fijo, siempre presente
    const m = modules.find(mm => mm.id === id);
    return !m || !m.removed;
  };
  // Resolver nombre dinámico desde el registro de módulos (renombrable desde Manager)
  const moduleName = (id, fallback) => {
    const m = modules.find(mm => mm.id === id);
    return m?.name || fallback;
  };

  // === Sedes visibles según el rol del usuario ===
  // Super ve todas. Otros roles solo ven sus sedes asignadas (user.sedeIds).
  // Si el usuario no tiene sedeIds, le mostramos todas (fallback retrocompatible).
  const visibleSedes = useMemo(() => {
    if (userRole === "super" || !user?.sedeIds || user.sedeIds.length === 0) {
      return (sedes || []).filter(s => s.active !== false);
    }
    return (sedes || []).filter(s => s.active !== false && user.sedeIds.includes(s.id));
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [sedes, userRole, user]);

  // Si la sede activa no es visible para este usuario, saltar a la primera
  useEffect(() => {
    if (visibleSedes.length === 0) return;
    if (!activeSedeId || !visibleSedes.find(s => s.id === activeSedeId)) {
      setActiveSedeId && setActiveSedeId(visibleSedes[0].id);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [visibleSedes, activeSedeId]);

  // Mapa kind → metadatos visuales (icon, accent, descripción base).
  // Los módulos clonados desde una plantilla (ej. "Veterinaria 2") heredan estos
  // valores según su `kind`. Esto permite que CUALQUIER módulo creado se vea
  // y se comporte como una pestaña más, sin tener que tocar este código.
  const KIND_VISUALS = {
    vet:      { Icon: Stethoscope, accent: "from-orange-500 to-orange-700",  desc: "Consultas, fichas clínicas, sugerencias de medicina por diagnóstico." },
    grooming: { Icon: Bath,        accent: "from-emerald-500 to-emerald-700", desc: "Agenda diaria, recepción de mascotas, fotos antes/después." },
    standard: { Icon: Tag,         accent: "from-blue-500 to-blue-700",      desc: "Pipeline configurable con embudo de ventas y campos personalizados." },
    custom:   { Icon: LayoutGrid,  accent: "from-stone-500 to-stone-700",    desc: "CRM personalizado con campos y reglas propias." },
  };

  // Secciones visibles para el rol Y que pertenecen a la sede activa.
  // Sales es transversal (siempre aparece). Vet/Grooming/Standard se filtran
  // por su sedeId. Si un módulo no tiene sedeId (legacy), aparece en todas las sedes.
  const sections = useMemo(() => {
    const list = [];
    // Ventas va primero — es el flujo de cierre que más se consulta a diario.
    if (canAccess(perm, "sales")) {
      list.push({ id: "sales", label: "Ventas", Icon: ShoppingBag, accent: "from-purple-500 to-purple-700", desc: "Recibos, pagos, planes de crédito y comprobantes." });
    }
    // Iteramos sobre los módulos instalados filtrando por sede activa.
    (modules || []).filter(m => !m.removed).forEach(m => {
      // Si tenemos sede activa, solo módulos de esa sede (o sin sede = legacy)
      if (activeSedeId && m.sedeId && m.sedeId !== activeSedeId) return;
      if (!canAccess(perm, m.id, modules)) return;

      const visuals = KIND_VISUALS[m.kind] || KIND_VISUALS.custom;
      list.push({
        id: m.id,
        kind: m.kind,
        label: m.name || m.shortName || m.id,
        Icon: visuals.Icon,
        accent: m.accent ? `from-${m.accent.split(' ')[0].replace('from-', '')} ${m.accent.split(' ')[1]}` : visuals.accent,
        desc: m.description || visuals.desc,
      });
    });
    return list;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [perm, modules, activeSedeId]);

  // Vista por defecto: la primera sección a la que el rol tiene acceso
  const [activeSection, setActiveSection] = useState(sections[0]?.id || null);

  // Si el rol cambia y ya no tiene permiso a la sección activa, saltar a la primera disponible
  useEffect(() => {
    if (activeSection && !sections.find(s => s.id === activeSection)) {
      setActiveSection(sections[0]?.id || null);
    }
  }, [sections, activeSection]);

  if (sections.length === 0) {
    return (
      <div className="max-w-2xl mx-auto pt-8">
        <div className="bg-white border border-stone-200 rounded-2xl shadow-sm p-10 text-center">
          <div className="w-16 h-16 rounded-2xl bg-stone-100 grid place-items-center text-stone-500 mx-auto mb-5">
            <LayoutGrid size={28} strokeWidth={1.6} />
          </div>
          <h2 className="font-serif text-2xl font-semibold mb-2">Sin acceso a CRM</h2>
          <p className="text-sm text-stone-600 max-w-md mx-auto">
            Tu rol no tiene permisos para ver ninguna sección operativa del CRM.
            Contacta al administrador si esto debería cambiar.
          </p>
        </div>
      </div>
    );
  }

  // Sólo una sección disponible: render directo, sin tabs
  if (sections.length === 1) {
    const onlySection = sections[0];
    const targetModule = (modules || []).find(m => m.id === onlySection.id);
    return renderSection(onlySection, vetProps, groomingOpsProps, standardProps, salesProps, targetModule);
  }

  return (
    <div className="space-y-4">
      {/* Card con doble nivel de pestañas + botón de ajustes */}
      <div className="bg-white border border-stone-200 rounded-2xl shadow-sm overflow-hidden">

        {/* === NIVEL 1: PESTAÑAS DE SEDE ===
            Cada sede agrupa sus propios módulos (Vet, Grooming, B2B, etc.).
            A la derecha, botón "Ajuste de CRM" que abre el manager de módulos/sedes. */}
        {visibleSedes.length > 0 && (
          <div className="px-3 py-2 flex items-center gap-1 bg-stone-100 border-b border-stone-200 overflow-x-auto">
            {visibleSedes.map(sede => {
              const active = sede.id === activeSedeId;
              return (
                <button
                  key={sede.id}
                  onClick={() => setActiveSedeId && setActiveSedeId(sede.id)}
                  className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-semibold transition flex-shrink-0 ${
                    active
                      ? "bg-stone-900 text-white shadow-md"
                      : "text-stone-600 hover:bg-white"
                  }`}
                >
                  <MapPin size={13} strokeWidth={active ? 2.2 : 1.8} />
                  {sede.name}
                  {sede.isDefault && (
                    <span className={`text-[10px] font-bold uppercase px-1.5 py-px rounded ${
                      active ? "bg-white/20 text-white" : "bg-orange-100 text-orange-700"
                    }`}>
                      Principal
                    </span>
                  )}
                </button>
              );
            })}
            {/* Botón "Ajuste de CRM" alineado a la derecha — abre el manager.
                Visible para super y para roles que tengan el permiso config.modules.view-manager. */}
            {canManageCRM && (
              <button
                onClick={onGoToManager}
                title="Configurar sedes y módulos"
                className="ml-auto flex items-center gap-1.5 px-3 py-2 rounded-xl text-xs font-semibold bg-white border border-stone-200 hover:border-orange-400 hover:text-orange-700 text-stone-600 transition flex-shrink-0"
              >
                <Settings size={13} />
                Ajuste de CRM
              </button>
            )}
          </div>
        )}

        {/* === NIVEL 2: PESTAÑAS DE MÓDULO (filtrados a la sede activa) === */}
        <div className="px-3 py-2 flex gap-1 overflow-x-auto bg-stone-50">
          {sections.map(s => {
            const Icon = s.Icon;
            const active = activeSection === s.id;
            return (
              <button
                key={s.id}
                onClick={() => setActiveSection(s.id)}
                className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-semibold transition flex-shrink-0 ${
                  active
                    ? `bg-gradient-to-br ${s.accent} text-white shadow-md`
                    : "text-stone-600 hover:bg-white"
                }`}
              >
                <Icon size={14} strokeWidth={active ? 2.2 : 1.8} />
                {s.label}
              </button>
            );
          })}
          {sections.length === 0 && (
            <div className="px-3 py-2 text-xs text-stone-500 italic">
              Esta sede no tiene módulos configurados. {userRole === "super" && "Click en 'Ajuste de CRM' para agregar uno."}
            </div>
          )}
        </div>
      </div>

      {/* Contenido de la sección activa */}
      <div>
        {(() => {
          const activeSec = sections.find(s => s.id === activeSection);
          if (!activeSec) return null;
          // Sales y los IDs core conservan su comportamiento. Para módulos clonados
          // (ej. "vet-lxabc123" con kind="vet"), pasamos el módulo concreto al motor
          // para que sus features y columnas se apliquen correctamente.
          const targetModule = (modules || []).find(m => m.id === activeSection);
          return renderSection(activeSec, vetProps, groomingOpsProps, standardProps, salesProps, targetModule);
        })()}
      </div>
    </div>
  );
}

// Renderiza la sección activa según su kind. Para módulos clonados (mismo kind, otro id)
// inyectamos `module={...}` para que el motor lea las features de esa instancia.
function renderSection(section, vetProps, groomingOpsProps, standardProps, salesProps, targetModule) {
  if (section.id === "sales")        return <SalesView {...salesProps} />;
  if (section.kind === "vet")        return <VetCRM {...vetProps} activeModule={targetModule} />;
  if (section.kind === "grooming")   return <GroomingOpsView {...groomingOpsProps} activeModule={targetModule} />;
  if (section.kind === "standard")   return <StandardCRM {...standardProps} activeModule={targetModule} />;
  // Custom: usa el mismo motor que standard. La diferencia es semántica
  // (columnas y campos definidos por el cliente).
  if (section.kind === "custom")     return <StandardCRM title={targetModule?.name || section.name || "CRM"} customFields={targetModule?.fields} activeModule={targetModule} />;
  // Fallbacks por id legacy
  if (section.id === "vet")          return <VetCRM {...vetProps} />;
  if (section.id === "grooming-ops") return <GroomingOpsView {...groomingOpsProps} />;
  if (section.id === "standard")     return <StandardCRM {...standardProps} />;
  return null;
}

// ========== PRODUCTOS HUB (Inventario + Catálogos en Ajustes) ==========
// Agrupa todo lo "configurable" de la oferta del negocio: stock + servicios.
function ProductsHubView({ userRole, can, vetCatalogProps, groomingProps }) {
  const sections = useMemo(() => {
    const list = [];
    if (can("inventory") || userRole === "super")    list.push({ id: "inventory",   label: "Inventario",          Icon: Package,    desc: "Stock de productos, lotes y vencimientos." });
    if (can("vet-catalog") || userRole === "super")  list.push({ id: "vet-catalog", label: "Catálogo Veterinaria", Icon: Pill,       desc: "Servicios y medicinas de la clínica." });
    if (can("grooming") || userRole === "super")     list.push({ id: "grooming",    label: "Catálogo Grooming",    Icon: Scissors,   desc: "Servicios e insumos de peluquería." });
    return list;
  }, [userRole, can]);

  const [activeSection, setActiveSection] = useState(sections[0]?.id || null);
  useEffect(() => {
    if (activeSection && !sections.find(s => s.id === activeSection)) {
      setActiveSection(sections[0]?.id || null);
    }
  }, [sections, activeSection]);

  if (sections.length === 0) {
    return <ComingSoon view="inventory" />;
  }

  return (
    <div className="space-y-4">
      <div className="bg-white border border-stone-200 rounded-2xl shadow-sm overflow-hidden">
        <div className="px-5 py-4 border-b border-stone-200">
          <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold mb-1">
            Ajustes · Productos
          </div>
          <h2 className="font-serif text-2xl font-semibold leading-tight">
            Inventario y catálogos
          </h2>
          <p className="text-xs text-stone-500 mt-1">
            Configura todo lo que tu tienda ofrece: stock, servicios y medicinas.
          </p>
        </div>

        <div className="px-3 py-2 flex gap-1 overflow-x-auto bg-stone-50">
          {sections.map(s => {
            const Icon = s.Icon;
            const active = activeSection === s.id;
            return (
              <button
                key={s.id}
                onClick={() => setActiveSection(s.id)}
                className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-semibold transition flex-shrink-0 ${
                  active
                    ? "bg-stone-900 text-white shadow-md"
                    : "text-stone-600 hover:bg-white"
                }`}
              >
                <Icon size={14} strokeWidth={active ? 2.2 : 1.8} />
                {s.label}
              </button>
            );
          })}
        </div>
      </div>

      <div>
        {activeSection === "inventory" && <ComingSoon view="inventory" />}
        {activeSection === "vet-catalog" && <VetCatalogView {...vetCatalogProps} />}
        {activeSection === "grooming" && <GroomingCRM {...groomingProps} />}
      </div>
    </div>
  );
}

// ============================================================================
// DASHBOARD GENERAL — Panorama operativo del negocio
// ============================================================================
// Muestra KPIs financieros, citas próximas, alertas operativas y actividad
// reciente. Adapta el contenido según el rol: super ve todo el negocio,
// veterinarios solo su clínica, groomers solo grooming, ventas solo recibos.
//
// Cada sección agrega "valor en 5 segundos" — el usuario debería poder entender
// el estado del negocio sin scroll. Las alertas son accionables: un click navega
// a la vista correspondiente.
function DashboardView({
  user, userRole, userName,
  invoices = [], clients = [], passports = [],
  agendaEvents = [], groomingBookings = [],
  modules = [], customRoles = [], users = [],
  conversations = {}, supplies = [], vetSupplies = [],
  onNavigate, permissions = {},
}) {
  // Helper: ISO fecha de hoy
  const todayISO = useMemo(() => {
    const d = new Date();
    return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(d.getDate()).padStart(2, "0")}`;
  }, []);
  const now = useMemo(() => new Date(), []);

  // === Permisos por rol ===
  // Super y sales ven KPIs financieros completos. Vet/grooming ven datos operativos
  // de su área pero sin totales de recibos (privacidad).
  const isSuper = userRole === "super";
  const isSales = userRole === "sales" || isSuper;
  const isVet = userRole === "vet" || isSuper;
  const isGrooming = userRole === "grooming" || isSuper;
  // Roles custom: heredan permisos de su base (vet/grooming/sales). Por simplicidad
  // mostramos lo más amplio según los views permitidos.
  const myCustomRole = (customRoles || []).find(r => r.id === userRole);
  // Un rol custom puede heredar de VARIOS roles base a la vez (inheritFromList).
  // Antes esto miraba solo `inheritFrom` singular, así que un rol "Vet + Groomer"
  // no veía el área de grooming aquí. Caemos a `inheritFrom` para roles creados
  // con versiones anteriores que no tienen la lista.
  const myInheritedBases = myCustomRole
    ? (myCustomRole.inheritFromList?.length
        ? myCustomRole.inheritFromList
        : [myCustomRole.inheritFrom])
    : [];
  const customSeesSales = myInheritedBases.includes("sales") || isSales;
  const customSeesVet = myInheritedBases.includes("vet") || isVet;
  const customSeesGrooming = myInheritedBases.includes("grooming") || isGrooming;

  // === KPIs financieros del día ===
  const todayInvoices = useMemo(
    () => invoices.filter(inv => inv.issueDate === todayISO),
    [invoices, todayISO]
  );

  // Ingresos de hoy (sumando todos los pagos hechos hoy, no solo recibos emitidas hoy).
  // Esto refleja flujo de caja real, incluyendo pagos parciales de recibos viejas.
  const todayRevenue = useMemo(() => {
    let total = 0;
    invoices.forEach(inv => {
      (inv.payments || []).forEach(p => {
        if (p.date === todayISO) total += (p.amount ?? 0);
      });
    });
    return total;
  }, [invoices, todayISO]);

  const totalDebt = useMemo(
    () => invoices.reduce((s, i) => s + (i.balance ?? 0), 0),
    [invoices]
  );
  const overdueCount = useMemo(
    () => invoices.filter(i => i.state === "vencido").length,
    [invoices]
  );
  const draftCount = useMemo(
    () => invoices.filter(i => i.state === "borrador").length,
    [invoices]
  );

  // === Citas próximas (próximas 24 horas) ===
  // Filtra eventos vet/grooming con date >= hoy. Ordena por fecha y hora.
  const upcomingEvents = useMemo(() => {
    const tomorrow = new Date(now);
    tomorrow.setDate(tomorrow.getDate() + 1);
    const tomorrowISO = `${tomorrow.getFullYear()}-${String(tomorrow.getMonth() + 1).padStart(2, "0")}-${String(tomorrow.getDate()).padStart(2, "0")}`;
    return (agendaEvents || [])
      .filter(e => {
        if (!e.date) return false;
        // Hoy o mañana
        if (e.date !== todayISO && e.date !== tomorrowISO) return false;
        // Filtrar por rol
        if (e.type === "vet" && !customSeesVet) return false;
        if (e.type === "grooming" && !customSeesGrooming) return false;
        if (e.type === "b2b" && !customSeesSales) return false;
        return true;
      })
      .sort((a, b) => {
        if (a.date !== b.date) return a.date.localeCompare(b.date);
        return (a.time || "").localeCompare(b.time || "");
      })
      .slice(0, 6);
  }, [agendaEvents, todayISO, now, customSeesVet, customSeesGrooming, customSeesSales]);

  // === Citas de hoy (counter para Hero) ===
  const todayEventsCount = useMemo(
    () => (agendaEvents || []).filter(e => e.date === todayISO).length,
    [agendaEvents, todayISO]
  );

  // === Alertas operativas ===
  // Cada alerta es accionable (navega a una vista). Ordenadas por severidad.
  const alerts = useMemo(() => {
    const list = [];

    // 1. Recibos vencidas
    if (overdueCount > 0 && customSeesSales) {
      list.push({
        id: "overdue",
        severity: "high",
        Icon: AlertTriangle,
        title: `${overdueCount} recibo${overdueCount > 1 ? "s" : ""} vencida${overdueCount > 1 ? "s" : ""}`,
        desc: "Requieren cobro urgente",
        action: () => onNavigate?.("sales"),
        actionLabel: "Ver Ventas",
      });
    }

    // 2. Borradores sin emitir
    if (draftCount > 0 && customSeesSales) {
      list.push({
        id: "drafts",
        severity: "medium",
        Icon: FileText,
        title: `${draftCount} recibo${draftCount > 1 ? "s" : ""} en borrador`,
        desc: "Sin emitir",
        action: () => onNavigate?.("sales"),
        actionLabel: "Revisar",
      });
    }

    // 3. Insumos bajos en grooming
    const lowSupplies = (supplies || []).filter(s => (s.stock ?? 100) <= (s.minStock ?? 10));
    if (lowSupplies.length > 0 && customSeesGrooming) {
      list.push({
        id: "low-supplies",
        severity: "medium",
        Icon: Droplets,
        title: `${lowSupplies.length} insumo${lowSupplies.length > 1 ? "s" : ""} bajo${lowSupplies.length > 1 ? "s" : ""}`,
        desc: "Stock por debajo del mínimo",
        action: () => onNavigate?.("grooming"),
        actionLabel: "Ver insumos",
      });
    }

    // 4. Insumos veterinarios bajos
    const lowVetSupplies = (vetSupplies || []).filter(s => (s.stock ?? 100) <= (s.minStock ?? 5));
    if (lowVetSupplies.length > 0 && customSeesVet) {
      list.push({
        id: "low-vet-supplies",
        severity: "medium",
        Icon: Pill,
        title: `${lowVetSupplies.length} medicamento${lowVetSupplies.length > 1 ? "s" : ""} bajo${lowVetSupplies.length > 1 ? "s" : ""}`,
        desc: "Stock crítico en consultorio",
        action: () => onNavigate?.("vet-catalog"),
        actionLabel: "Ver catálogo",
      });
    }

    // 5. Mensajes sin leer
    const unreadCount = Object.values(conversations || {}).reduce((sum, conv) => {
      return sum + (conv?.messages || []).filter(m => m.from === "client" && !m.read).length;
    }, 0);
    if (unreadCount > 0) {
      list.push({
        id: "unread-messages",
        severity: "low",
        Icon: MessageCircle,
        title: `${unreadCount} mensaje${unreadCount > 1 ? "s" : ""} sin leer`,
        desc: "Tutores esperando respuesta",
        action: () => onNavigate?.("messages"),
        actionLabel: "Ir a Mensajes",
      });
    }

    return list;
  }, [overdueCount, draftCount, supplies, vetSupplies, conversations, customSeesSales, customSeesVet, customSeesGrooming, onNavigate]);

  // === Saludo dinámico según hora ===
  const greeting = useMemo(() => {
    const h = now.getHours();
    if (h < 12) return "Buenos días";
    if (h < 19) return "Buenas tardes";
    return "Buenas noches";
  }, [now]);

  // === Conteo de módulos activos ===
  const activeModulesCount = (modules || []).filter(m => !m.removed).length;

  // === Top clientes del mes (por volumen recibodo) ===
  const topClients = useMemo(() => {
    if (!customSeesSales) return [];
    const monthStart = new Date(now.getFullYear(), now.getMonth(), 1);
    const tally = {};
    invoices.forEach(inv => {
      if (!inv.issueDate) return;
      const d = new Date(inv.issueDate);
      if (d < monthStart) return;
      tally[inv.clientId] = (tally[inv.clientId] || 0) + (inv.total ?? 0);
    });
    return Object.entries(tally)
      .map(([cid, total]) => {
        const c = clients.find(cc => cc.id === cid);
        return c ? { client: c, total } : null;
      })
      .filter(Boolean)
      .sort((a, b) => b.total - a.total)
      .slice(0, 4);
  }, [invoices, clients, customSeesSales, now]);

  return (
    <div className="space-y-5 pb-8">
      {/* === Hero con saludo y resumen === */}
      <div className="relative overflow-hidden bg-gradient-to-br from-stone-900 via-orange-900 to-stone-900 text-white rounded-2xl p-6 shadow-xl">
        <div className="absolute -top-20 -right-20 w-60 h-60 bg-orange-500/20 rounded-full blur-3xl"></div>
        <div className="absolute -bottom-20 -left-20 w-60 h-60 bg-amber-500/10 rounded-full blur-3xl"></div>
        <div className="relative flex items-start justify-between gap-4 flex-wrap">
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase text-orange-300 font-semibold mb-1">
              Panorama operativo · {now.toLocaleDateString("es-ES", { weekday: "long", day: "numeric", month: "long" })}
            </div>
            <h2 className="font-serif text-3xl sm:text-4xl font-semibold leading-tight">
              {greeting},{" "}
              <span className="text-orange-300">
                {(() => {
                  // Nombre completo en el saludo (nombre + apellido), con el
                  // título profesional del usuario antepuesto si lo configuró.
                  // Si el nombre ya traía un título embebido (ej. "Dra. Romero"),
                  // lo separamos para no duplicarlo cuando hay título explícito.
                  const explicitTitle = user?.title || "";
                  const { title: embeddedTitle, baseName } = splitNameTitle(userName || "");
                  const effectiveTitle = explicitTitle || embeddedTitle;
                  const nameToShow = baseName || (userName || "");
                  return `${effectiveTitle ? effectiveTitle + " " : ""}${nameToShow}`.trim() || "—";
                })()}
              </span>
            </h2>
            <p className="text-sm text-stone-300 mt-2 max-w-md">
              {todayEventsCount > 0
                ? `Tienes ${todayEventsCount} cita${todayEventsCount > 1 ? "s" : ""} agendada${todayEventsCount > 1 ? "s" : ""} hoy.`
                : "No hay citas agendadas para hoy."}
              {alerts.length > 0 && ` ${alerts.length} alerta${alerts.length > 1 ? "s" : ""} pendiente${alerts.length > 1 ? "s" : ""}.`}
            </p>
          </div>
          {/* Stats compactas en el hero */}
          <div className="flex gap-3 flex-wrap">
            <DashboardHeroStat label="Citas hoy" value={todayEventsCount} Icon={Calendar} />
            {customSeesSales && (
              <DashboardHeroStat label="Hoy" value={`$${todayRevenue.toFixed(0)}`} Icon={DollarSign} />
            )}
            <DashboardHeroStat label="Clientes" value={clients.length} Icon={Users} />
          </div>
        </div>
      </div>

      {/* === KPIs principales === */}
      {customSeesSales && (
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
          <KpiCard
            label="Ingresos del día"
            value={`$${todayRevenue.toFixed(0)}`}
            sublabel={`${todayInvoices.length} recibo${todayInvoices.length !== 1 ? "s" : ""} emitida${todayInvoices.length !== 1 ? "s" : ""}`}
            Icon={TrendingUp}
            accent="emerald"
            onClick={() => onNavigate?.("sales")}
            info="Suma de TODOS los pagos registrados con fecha de hoy, sin importar cuándo se emitió la recibo. Incluye pagos parciales de recibos viejas. Los descuentos no se restan aquí — se reflejan en el total ya cobrado. Fuente: Ventas → registros de pago."
          />
          <KpiCard
            label="Por cobrar"
            value={`$${(totalDebt / 1000).toFixed(1)}k`}
            sublabel={`${invoices.filter(i => (i.balance ?? 0) > 0).length} con saldo pendiente`}
            Icon={Wallet}
            accent={totalDebt > 0 ? "amber" : "stone"}
            onClick={() => onNavigate?.("sales")}
            info="Suma de los saldos pendientes de TODAS las recibos activas (no incluye borradores). Cada recibo aporta el monto que aún falta cobrar = total - pagos recibidos. Se muestra en miles ($k). Fuente: Ventas → campo 'balance' por recibo."
          />
          <KpiCard
            label="Vencidas"
            value={overdueCount}
            sublabel="Requieren acción"
            Icon={AlertTriangle}
            accent={overdueCount > 0 ? "red" : "stone"}
            onClick={() => onNavigate?.("sales")}
            info="Cantidad de recibos en estado 'vencido' — aquellas cuya fecha de vencimiento ya pasó y aún tienen saldo pendiente. Hace falta gestionar el cobro o renegociar plazo. Fuente: Ventas → state='vencido'."
          />
          <KpiCard
            label="Citas hoy"
            value={todayEventsCount}
            sublabel={`${activeModulesCount} módulos activos`}
            Icon={Calendar}
            accent="blue"
            onClick={() => onNavigate?.("agenda")}
            info="Total de eventos en la agenda con fecha de hoy, de cualquier tipo (veterinaria, grooming, B2B, otros). El sublabel cuenta cuántos CRM/módulos hay activos en el sistema. Fuente: Agenda → eventos del día."
          />
        </div>
      )}

      {/* Para roles que NO ven recibos, mostramos KPIs operativos alternativos */}
      {!customSeesSales && (
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
          <KpiCard
            label="Citas hoy"
            value={todayEventsCount}
            sublabel="Agendadas para hoy"
            Icon={Calendar}
            accent="blue"
            onClick={() => onNavigate?.("agenda")}
            info="Total de eventos en la agenda con fecha de hoy. Filtra por tu rol: si eres veterinario solo cuentan citas tipo 'vet', si eres groomer solo 'grooming'. Fuente: Agenda → eventos del día."
          />
          <KpiCard
            label="Pasaportes"
            value={passports.length}
            sublabel="Pacientes registrados"
            Icon={Stamp}
            accent="orange"
            info="Cantidad total de pasaportes clínicos creados en el sistema. Cada pasaporte representa un paciente único con su historial médico, vacunas y tutores. Fuente: módulo Pasaportes."
          />
          <KpiCard
            label="Clientes"
            value={clients.length}
            sublabel="Tutores activos"
            Icon={Users}
            accent="emerald"
            onClick={() => onNavigate?.("clients")}
            info="Cantidad total de tutores (humanos dueños de mascotas) registrados. Un mismo tutor puede tener varias mascotas. Fuente: módulo Clientes."
          />
          <KpiCard
            label="Equipo"
            value={users.filter(u => u.active).length}
            sublabel="Usuarios activos"
            Icon={UserPlus}
            accent="purple"
            info="Cantidad de cuentas de empleados con estado activo (excluye los desactivados con el toggle gris). Solo super puede gestionar el equipo. Fuente: Ajustes → Usuarios."
          />
        </div>
      )}

      {/* === Layout de 2 columnas: Citas + Alertas === */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
        {/* Citas próximas */}
        <div className="lg:col-span-2 bg-white border border-stone-200 rounded-2xl shadow-sm overflow-hidden">
          <div className="px-5 py-4 border-b border-stone-200 flex items-center justify-between">
            <div>
              <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold">Agenda</div>
              <div className="font-serif text-lg font-semibold mt-0.5">Citas próximas</div>
            </div>
            <button
              onClick={() => onNavigate?.("agenda")}
              className="text-xs font-semibold text-orange-700 hover:text-orange-900 flex items-center gap-1"
            >
              Ver todas <ChevronRight size={12} />
            </button>
          </div>
          {upcomingEvents.length === 0 ? (
            <div className="p-8 text-center">
              <Calendar size={28} className="text-stone-300 mx-auto mb-2" />
              <p className="text-sm text-stone-500">No hay citas próximas en las siguientes 24h</p>
            </div>
          ) : (
            <div className="divide-y divide-stone-100">
              {upcomingEvents.map(ev => {
                const eventDateLabel = ev.date === todayISO ? "Hoy" : "Mañana";
                const typeColor = {
                  vet: "bg-orange-100 text-orange-700",
                  grooming: "bg-emerald-100 text-emerald-700",
                  b2b: "bg-blue-100 text-blue-700",
                  pet: "bg-amber-100 text-amber-700",
                }[ev.type] || "bg-stone-100 text-stone-600";
                const TypeIcon = ev.type === "vet" ? Stethoscope
                              : ev.type === "grooming" ? Bath
                              : ev.type === "b2b" ? Briefcase
                              : Calendar;
                return (
                  <div key={ev.id} className="px-5 py-3 hover:bg-stone-50 transition flex items-center gap-3">
                    <div className={`w-9 h-9 rounded-xl ${typeColor} grid place-items-center flex-shrink-0`}>
                      <TypeIcon size={15} strokeWidth={1.8} />
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 flex-wrap">
                        <span className="text-xs font-bold text-stone-700">{eventDateLabel}</span>
                        <span className="text-xs text-stone-500">·</span>
                        <span className="text-xs font-semibold text-stone-700">{ev.time || "—"}</span>
                        <span className="text-xs text-stone-400">·</span>
                        <span className="text-xs text-stone-500 truncate">{ev.duration}min</span>
                      </div>
                      <div className="text-sm font-semibold truncate">
                        {ev.pet ? `${ev.pet} · ` : ""}{ev.title || "Cita"}
                      </div>
                      <div className="text-xs text-stone-500 truncate">
                        {ev.owner || "Sin tutor"}{ev.professional ? ` · ${ev.professional}` : ""}
                      </div>
                    </div>
                    <div className={`hidden sm:block text-[10px] font-bold uppercase tracking-wider px-2 py-0.5 rounded ${typeColor}`}>
                      {ev.type}
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>

        {/* Alertas operativas */}
        <div className="bg-white border border-stone-200 rounded-2xl shadow-sm overflow-hidden">
          <div className="px-5 py-4 border-b border-stone-200">
            <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold">Sistema</div>
            <div className="font-serif text-lg font-semibold mt-0.5">
              Alertas {alerts.length > 0 && <span className="text-orange-700">({alerts.length})</span>}
            </div>
          </div>
          {alerts.length === 0 ? (
            <div className="p-8 text-center">
              <CheckCircle2 size={28} className="text-emerald-400 mx-auto mb-2" />
              <p className="text-sm font-semibold text-emerald-700">Todo en orden</p>
              <p className="text-xs text-stone-500 mt-1">No hay alertas pendientes</p>
            </div>
          ) : (
            <div className="divide-y divide-stone-100">
              {alerts.map(alert => {
                const Ic = alert.Icon;
                const sevColor = {
                  high: "bg-red-100 text-red-700",
                  medium: "bg-amber-100 text-amber-700",
                  low: "bg-blue-100 text-blue-700",
                }[alert.severity];
                return (
                  <button
                    key={alert.id}
                    onClick={alert.action}
                    className="w-full px-5 py-3 hover:bg-stone-50 transition flex items-start gap-3 text-left"
                  >
                    <div className={`w-9 h-9 rounded-xl ${sevColor} grid place-items-center flex-shrink-0 mt-0.5`}>
                      <Ic size={15} strokeWidth={1.8} />
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="text-sm font-semibold truncate">{alert.title}</div>
                      <div className="text-xs text-stone-500 truncate">{alert.desc}</div>
                      <div className="text-xs font-semibold text-orange-700 mt-1 flex items-center gap-1">
                        {alert.actionLabel} <ChevronRight size={10} />
                      </div>
                    </div>
                  </button>
                );
              })}
            </div>
          )}
        </div>
      </div>

      {/* === Top clientes del mes (solo si ve ventas) === */}
      {customSeesSales && topClients.length > 0 && (
        <div className="bg-white border border-stone-200 rounded-2xl shadow-sm overflow-hidden">
          <div className="px-5 py-4 border-b border-stone-200 flex items-center justify-between">
            <div>
              <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold">Clientes</div>
              <div className="font-serif text-lg font-semibold mt-0.5">Top del mes</div>
            </div>
            <button
              onClick={() => onNavigate?.("clients")}
              className="text-xs font-semibold text-orange-700 hover:text-orange-900 flex items-center gap-1"
            >
              Ver todos <ChevronRight size={12} />
            </button>
          </div>
          <div className="divide-y divide-stone-100">
            {topClients.map((tc, idx) => (
              <div key={tc.client.id} className="px-5 py-3 flex items-center gap-3 hover:bg-stone-50 transition">
                <div className={`w-8 h-8 rounded-lg grid place-items-center font-bold text-sm flex-shrink-0 ${
                  idx === 0 ? "bg-amber-100 text-amber-700" :
                  idx === 1 ? "bg-stone-200 text-stone-700" :
                  idx === 2 ? "bg-orange-100 text-orange-700" :
                  "bg-stone-100 text-stone-600"
                }`}>
                  {idx + 1}
                </div>
                <div className="flex-1 min-w-0">
                  <div className="text-sm font-semibold truncate">{tc.client.name}</div>
                  <div className="text-xs text-stone-500 truncate">{tc.client.cedula || tc.client.email || "—"}</div>
                </div>
                <div className="text-right flex-shrink-0">
                  <div className="text-sm font-bold text-emerald-700">${tc.total.toFixed(0)}</div>
                  <div className="text-[10px] text-stone-500 uppercase tracking-wider">Este mes</div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* === Footer info: módulos activos === */}
      {isSuper && (
        <div className="bg-stone-50 border border-stone-200 rounded-xl px-4 py-3 flex items-center gap-3 flex-wrap">
          <Info size={14} className="text-stone-500 flex-shrink-0" />
          <span className="text-xs text-stone-600">
            Sistema operando con <strong>{activeModulesCount}</strong> módulos activos · <strong>{users.filter(u => u.active).length}</strong> usuarios · <strong>{customRoles.filter(r => !r.isCoreOverride).length}</strong> roles personalizados
          </span>
        </div>
      )}
    </div>
  );
}

// Stat compacta en el Hero del Dashboard
function DashboardHeroStat({ label, value, Icon }) {
  return (
    <div className="bg-white/10 backdrop-blur border border-white/20 rounded-xl px-3 py-2 flex items-center gap-2">
      <Icon size={14} className="text-orange-300 flex-shrink-0" strokeWidth={2} />
      <div>
        <div className="text-[9px] tracking-widest uppercase text-stone-300 font-semibold">{label}</div>
        <div className="text-sm font-bold leading-tight">{value}</div>
      </div>
    </div>
  );
}

// Card de KPI clickable
function KpiCard({ label, value, sublabel, Icon, accent = "stone", onClick, info = null }) {
  const [showInfo, setShowInfo] = useState(false);
  const bgMap = {
    emerald: "from-emerald-50 to-emerald-100 border-emerald-200",
    amber: "from-amber-50 to-amber-100 border-amber-200",
    red: "from-red-50 to-red-100 border-red-200",
    blue: "from-blue-50 to-blue-100 border-blue-200",
    orange: "from-orange-50 to-orange-100 border-orange-200",
    purple: "from-purple-50 to-purple-100 border-purple-200",
    stone: "from-stone-50 to-stone-100 border-stone-200",
  };
  const iconMap = {
    emerald: "bg-emerald-600 text-white",
    amber: "bg-amber-600 text-white",
    red: "bg-red-600 text-white",
    blue: "bg-blue-600 text-white",
    orange: "bg-orange-600 text-white",
    purple: "bg-purple-600 text-white",
    stone: "bg-stone-500 text-white",
  };
  const Tag = onClick ? "button" : "div";
  return (
    <Tag
      onClick={onClick}
      className={`relative text-left bg-gradient-to-br ${bgMap[accent]} border rounded-2xl p-4 transition ${onClick ? "hover:shadow-md hover:scale-[1.01] cursor-pointer" : ""}`}
    >
      <div className="flex items-start justify-between gap-2 mb-2">
        <div className={`w-9 h-9 rounded-xl ${iconMap[accent]} grid place-items-center shadow flex-shrink-0`}>
          <Icon size={16} strokeWidth={2} />
        </div>
        <div className="flex items-center gap-1">
          {/* Ícono "i" con tooltip explicativo del KPI. Se renderiza solo si hay info.
              Usamos onMouseEnter/Leave en lugar de :hover CSS porque queremos posicionarlo
              de forma absoluta sin que el padre clicable interfiera. stopPropagation evita
              que un click en el ícono dispare el onClick del KPI (no se navega sin querer). */}
          {info && (
            <span
              role="button"
              tabIndex={0}
              onMouseEnter={() => setShowInfo(true)}
              onMouseLeave={() => setShowInfo(false)}
              onFocus={() => setShowInfo(true)}
              onBlur={() => setShowInfo(false)}
              onClick={(e) => { e.stopPropagation(); setShowInfo(s => !s); }}
              className="w-5 h-5 rounded-full bg-white/70 hover:bg-white border border-stone-300 grid place-items-center text-stone-500 hover:text-stone-800 transition cursor-help relative"
              title=""
            >
              <Info size={11} strokeWidth={2} />
              {/* Tooltip flotante. Se posiciona arriba a la derecha del ícono. z-20 para
                  quedar sobre las cards adyacentes. La flecha apunta al ícono. */}
              {showInfo && (
                <span className="absolute top-full right-0 mt-1.5 w-64 sm:w-72 p-3 rounded-xl bg-stone-900 text-white shadow-2xl z-20 cursor-default" onClick={(e) => e.stopPropagation()}>
                  <span className="block text-[10px] tracking-widest uppercase text-orange-300 font-semibold mb-1">
                    ¿Cómo se calcula?
                  </span>
                  <span className="block text-xs leading-relaxed text-stone-200 normal-case font-normal">
                    {info}
                  </span>
                  {/* Flecha del tooltip apuntando hacia arriba */}
                  <span className="absolute -top-1 right-2 w-2 h-2 bg-stone-900 rotate-45"></span>
                </span>
              )}
            </span>
          )}
          {onClick && <ChevronRight size={14} className="text-stone-400 mt-1 flex-shrink-0" />}
        </div>
      </div>
      <div className="text-[10px] tracking-widest uppercase text-stone-600 font-semibold mb-0.5">{label}</div>
      <div className="font-serif text-2xl font-bold text-stone-900 leading-tight">{value}</div>
      {sublabel && <div className="text-xs text-stone-500 mt-0.5 truncate">{sublabel}</div>}
    </Tag>
  );
}

// ========== VISTA: AJUSTES DE AGENDA ==========
// Configuración del flujo de agenda y citas. Por ahora solo contiene el toggle
// de auto-aprobación de citas web; se irá enriqueciendo con horarios de atención,
// días bloqueados, salas, recordatorios, etc.
// ========== AJUSTES: MÉTODOS DE PAGO ==========
// Configura qué métodos de pago aparecen en el constructor de recibos.
// El admin puede activar/desactivar, editar etiquetas, reordenar y marcar
// cuáles requieren comprobante (voucher) obligatorio.
function PaymentMethodsView({ paymentMethods = [], setPaymentMethods, userRole = "super", permissions = {} }) {
  // ¿Puede el usuario configurar (no solo ver) los métodos de pago?
  const canConfig = userRole === "super" ||
    getFieldLevel(permissions, userRole, "sales", "payment_methods", "config") === "edit";
  const readOnly = !canConfig;
  const [editingLabel, setEditingLabel] = useState(null);
  const [draftLabel, setDraftLabel] = useState("");
  // Método cuyos detalles están abriendo
  const [editingDetailsId, setEditingDetailsId] = useState(null);

  const ICON_OPTS = [
    { name: "Banknote",       Icon: Banknote,       label: "Efectivo" },
    { name: "CreditCard",     Icon: CreditCard,     label: "Tarjeta" },
    { name: "ArrowRightLeft", Icon: ArrowRightLeft, label: "Transferencia" },
    { name: "Smartphone",     Icon: Smartphone,     label: "Móvil" },
    { name: "Wallet",         Icon: Wallet,         label: "Billetera" },
    { name: "Coins",          Icon: Coins,          label: "Monedas" },
  ];

  const resolveIcon = (name) => ICON_OPTS.find(i => i.name === name)?.Icon || Wallet;

  const toggleEnabled = (id) => {
    setPaymentMethods(prev => prev.map(m =>
      m.id === id ? { ...m, enabled: !m.enabled } : m
    ));
  };

  const toggleVoucher = (id) => {
    setPaymentMethods(prev => prev.map(m =>
      m.id === id ? { ...m, requiresVoucher: !m.requiresVoucher } : m
    ));
  };

  const moveUp = (idx) => {
    if (idx === 0) return;
    setPaymentMethods(prev => {
      const next = [...prev];
      [next[idx - 1], next[idx]] = [next[idx], next[idx - 1]];
      return next;
    });
  };

  const moveDown = (idx) => {
    if (idx === paymentMethods.length - 1) return;
    setPaymentMethods(prev => {
      const next = [...prev];
      [next[idx], next[idx + 1]] = [next[idx + 1], next[idx]];
      return next;
    });
  };

  const changeIcon = (id, iconName) => {
    setPaymentMethods(prev => prev.map(m =>
      m.id === id ? { ...m, iconName } : m
    ));
  };

  const saveLabel = (id) => {
    if (!draftLabel.trim()) {
      setEditingLabel(null);
      return;
    }
    setPaymentMethods(prev => prev.map(m =>
      m.id === id ? { ...m, label: draftLabel.trim() } : m
    ));
    setEditingLabel(null);
    setDraftLabel("");
  };

  const addCustom = () => {
    const id = `pay-${Date.now().toString(36)}`;
    setPaymentMethods(prev => [...prev, {
      id, label: "Nuevo método", iconName: "Wallet", enabled: true, requiresVoucher: true,
    }]);
    setEditingLabel(id);
    setDraftLabel("Nuevo método");
  };

  const removeCustom = (id) => {
    // Solo permitir remover métodos custom (no los 4 base) para evitar errores
    // si un recibo viejo guardó la referencia.
    const isBuiltIn = ["efectivo", "tarjeta", "transferencia", "pago-movil"].includes(id);
    if (isBuiltIn) {
      if (!confirm("Este es un método estándar. Si lo eliminas, los recibos antiguos seguirán mostrándolo pero no podrá seleccionarse al cobrar. ¿Continuar?")) return;
    } else {
      if (!confirm("¿Eliminar este método de pago?")) return;
    }
    setPaymentMethods(prev => prev.filter(m => m.id !== id));
  };

  const enabledCount = paymentMethods.filter(m => m.enabled).length;

  return (
    <div className="max-w-4xl mx-auto pt-2 space-y-4">
      {readOnly && (
        <div className="bg-amber-50 border border-amber-200 rounded-xl p-3 flex items-start gap-2 text-xs text-amber-800">
          <Lock size={13} className="flex-shrink-0 mt-0.5" />
          <div>
            <strong className="block mb-0.5">Modo solo lectura</strong>
            Tu rol no tiene permiso para modificar los métodos de pago. Puedes consultar la configuración pero no editarla. Habla con un administrador si necesitas hacer cambios.
          </div>
        </div>
      )}
      <div className="bg-white border border-stone-200 rounded-2xl shadow-sm p-6">
        <div className="flex items-start gap-3 mb-2">
          <div className="w-10 h-10 rounded-xl bg-emerald-100 text-emerald-700 grid place-items-center flex-shrink-0">
            <Wallet size={18} />
          </div>
          <div>
            <div className="text-xs tracking-widest uppercase text-emerald-700 font-semibold">Configuración global</div>
            <h2 className="font-serif text-2xl font-semibold leading-tight">Métodos de pago</h2>
            <p className="text-sm text-stone-600 mt-1 max-w-prose">
              Estos métodos aparecen en el constructor de recibos cuando el cliente paga. Puedes activar/desactivar, cambiar la etiqueta, el orden y marcar cuáles requieren comprobante.
            </p>
          </div>
        </div>
        <div className="mt-3 px-3 py-2 bg-emerald-50 border border-emerald-200 rounded-lg text-xs text-emerald-800 inline-flex items-center gap-2">
          <Check size={12} /> {enabledCount} de {paymentMethods.length} métodos activos
        </div>
      </div>

      <div className="bg-white border border-stone-200 rounded-2xl shadow-sm overflow-hidden">
        <div className="px-4 py-3 border-b border-stone-200 bg-stone-50 flex items-center justify-between">
          <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold">Métodos disponibles</div>
          <button
            onClick={addCustom}
            disabled={readOnly}
            className={`flex items-center gap-1 px-2.5 py-1.5 rounded-lg text-xs font-semibold transition ${
              readOnly ? "bg-stone-200 text-stone-400 cursor-not-allowed" : "bg-emerald-600 hover:bg-emerald-700 text-white"
            }`}
          >
            <Plus size={11} /> Agregar método
          </button>
        </div>
        <div className="divide-y divide-stone-100">
          {paymentMethods.map((m, idx) => {
            const Ic = resolveIcon(m.iconName);
            const isEditing = editingLabel === m.id;
            return (
              <div key={m.id} className={`p-4 flex items-center gap-3 transition ${m.enabled ? "bg-white" : "bg-stone-50"}`}>
                {/* Reordenar */}
                <div className="flex flex-col gap-0.5 flex-shrink-0">
                  <button
                    onClick={() => moveUp(idx)}
                    disabled={idx === 0}
                    className="w-5 h-5 rounded grid place-items-center text-stone-400 hover:text-stone-700 hover:bg-stone-100 disabled:opacity-30 disabled:cursor-not-allowed"
                  >
                    <ChevronUp size={11} />
                  </button>
                  <button
                    onClick={() => moveDown(idx)}
                    disabled={idx === paymentMethods.length - 1}
                    className="w-5 h-5 rounded grid place-items-center text-stone-400 hover:text-stone-700 hover:bg-stone-100 disabled:opacity-30 disabled:cursor-not-allowed"
                  >
                    <ChevronDown size={11} />
                  </button>
                </div>

                {/* Icono */}
                <div className="relative group flex-shrink-0">
                  <div className={`w-11 h-11 rounded-xl grid place-items-center border-2 ${
                    m.enabled ? "bg-stone-900 border-stone-900 text-white" : "bg-stone-100 border-stone-200 text-stone-400"
                  }`}>
                    <Ic size={16} strokeWidth={1.8} />
                  </div>
                </div>

                {/* Nombre + iconos selector */}
                <div className="flex-1 min-w-0">
                  {isEditing ? (
                    <input
                      autoFocus
                      value={draftLabel}
                      onChange={(e) => setDraftLabel(e.target.value)}
                      onBlur={() => saveLabel(m.id)}
                      onKeyDown={(e) => {
                        if (e.key === "Enter") saveLabel(m.id);
                        if (e.key === "Escape") { setEditingLabel(null); setDraftLabel(""); }
                      }}
                      className="px-2 py-1 border border-orange-400 rounded text-sm font-semibold w-full max-w-xs outline-none focus:ring-2 focus:ring-orange-200"
                    />
                  ) : (
                    <div
                      onClick={() => { setEditingLabel(m.id); setDraftLabel(m.label); }}
                      className={`font-semibold text-sm cursor-pointer hover:text-orange-700 ${m.enabled ? "text-stone-900" : "text-stone-500"}`}
                      title="Click para editar"
                    >
                      {m.label}
                    </div>
                  )}
                  <div className="flex items-center gap-1 mt-1.5">
                    <span className="text-[10px] text-stone-400 uppercase tracking-wider font-semibold mr-1">Ícono:</span>
                    {ICON_OPTS.map(opt => {
                      const OptIc = opt.Icon;
                      const selected = m.iconName === opt.name;
                      return (
                        <button
                          key={opt.name}
                          onClick={() => changeIcon(m.id, opt.name)}
                          title={opt.label}
                          className={`w-6 h-6 rounded grid place-items-center transition ${
                            selected ? "bg-orange-100 text-orange-700 ring-1 ring-orange-400" : "text-stone-400 hover:bg-stone-100 hover:text-stone-700"
                          }`}
                        >
                          <OptIc size={11} strokeWidth={1.8} />
                        </button>
                      );
                    })}
                  </div>
                </div>

                {/* Requiere voucher */}
                <label className="flex items-center gap-1.5 cursor-pointer flex-shrink-0 px-2.5 py-1.5 rounded-lg hover:bg-stone-50">
                  <input
                    type="checkbox"
                    checked={!!m.requiresVoucher}
                    onChange={() => toggleVoucher(m.id)}
                    className="w-3.5 h-3.5 accent-orange-600"
                  />
                  <span className="text-xs text-stone-700">Pide comprobante</span>
                </label>

                {/* Datos del método (banco, cuenta, wallet, etc.) */}
                <button
                  onClick={() => setEditingDetailsId(m.id)}
                  title="Editar datos del método"
                  className={`flex items-center gap-1 px-2.5 py-1.5 rounded-lg text-xs font-semibold transition flex-shrink-0 ${
                    Object.values(m.details || {}).some(v => v && v !== "Corriente" && v !== "TRC-20")
                      ? "bg-blue-50 hover:bg-blue-100 border border-blue-200 text-blue-700"
                      : "bg-stone-50 hover:bg-stone-100 border border-stone-200 text-stone-500"
                  }`}
                >
                  <Info size={11} /> Datos
                </button>

                {/* Toggle enabled */}
                <button
                  onClick={() => toggleEnabled(m.id)}
                  title={m.enabled ? "Desactivar" : "Activar"}
                  className={`relative w-10 h-6 rounded-full transition flex-shrink-0 ${
                    m.enabled ? "bg-emerald-500" : "bg-stone-300"
                  }`}
                >
                  <span className={`absolute top-0.5 w-5 h-5 bg-white rounded-full shadow transition-all ${
                    m.enabled ? "left-4" : "left-0.5"
                  }`} />
                </button>

                {/* Eliminar */}
                <button
                  onClick={() => removeCustom(m.id)}
                  title="Eliminar"
                  className="w-7 h-7 rounded-lg grid place-items-center text-stone-400 hover:bg-red-50 hover:text-red-600 transition flex-shrink-0"
                >
                  <Trash2 size={12} />
                </button>
              </div>
            );
          })}
        </div>
      </div>

      <div className="bg-blue-50 border border-blue-200 rounded-xl p-3 flex items-start gap-2">
        <Info size={14} className="text-blue-700 mt-0.5 flex-shrink-0" />
        <div className="text-xs text-blue-800 leading-relaxed">
          <strong className="block">¿Cómo se conecta esto?</strong>
          Los métodos activos aparecen en el panel <strong>Modalidad de pago</strong> al construir un recibo. Si un método pide comprobante, el operador verá un campo obligatorio para ingresar la referencia (REF-xxxxx, AUTH-xxxxx, etc.) al cobrar.
        </div>
      </div>

      {/* === MODAL: editar datos del método de pago === */}
      {editingDetailsId && (() => {
        const m = paymentMethods.find(p => p.id === editingDetailsId);
        if (!m) return null;
        const Ic = resolveIcon(m.iconName);
        return (
          <PaymentMethodDetailsEditor
            method={m}
            Icon={Ic}
            onClose={() => setEditingDetailsId(null)}
            onSave={(details) => {
              setPaymentMethods(prev => prev.map(p =>
                p.id === editingDetailsId ? { ...p, details } : p
              ));
              setEditingDetailsId(null);
            }}
          />
        );
      })()}
    </div>
  );
}

// ========== EDITOR DE DATOS DE UN MÉTODO DE PAGO ==========
// Modal donde el admin captura los datos bancarios / de wallet / etc. para
// que el operador los vea al cobrar y para que se puedan enviar al cliente
// por chat. Los campos dependen del id del método:
//  - efectivo: solo notas
//  - tarjeta: banco, terminal, últimos dígitos
//  - transferencia: banco, cuenta, tipo, titular, cédula/RIF
//  - pago-movil: banco, teléfono, cédula
//  - zelle: email, teléfono, titular
//  - cripto: red blockchain, wallet, QR
function PaymentMethodDetailsEditor({ method, Icon, onClose, onSave }) {
  const [draft, setDraft] = useState({ ...(method.details || {}) });

  const upd = (key, value) => setDraft(d => ({ ...d, [key]: value }));

  // QR upload (base64) — para criptomonedas. Reutiliza el patrón de fotos clínicas.
  const handleQrUpload = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => upd("qrCode", ev.target.result);
    reader.readAsDataURL(file);
  };

  // Detectar qué campos pedir según el id del método. Para métodos custom
  // creados por el admin, mostramos un set genérico (banco, cuenta, titular,
  // notas) que cubre la mayoría de casos.
  const fields = (() => {
    const id = method.id;
    if (id === "efectivo") {
      return [
        { key: "notes", label: "Notas internas (opcional)", placeholder: "Caja chica, denominaciones aceptadas, etc.", multiline: true },
      ];
    }
    if (id === "tarjeta") {
      return [
        { key: "bank",       label: "Banco emisor",        placeholder: "Banco Mercantil, BBVA Provincial..." },
        { key: "terminal",   label: "Terminal / POS",      placeholder: "Marca o número del POS" },
        { key: "lastDigits", label: "Últimos 4 dígitos",   placeholder: "Opcional, por seguridad", mono: true },
      ];
    }
    if (id === "transferencia") {
      return [
        { key: "bank",          label: "Banco",                       placeholder: "Banco de Venezuela, Banesco..." },
        { key: "accountNumber", label: "Número de cuenta (20 dígitos)", placeholder: "0102-0000-00-00000000000", mono: true },
        { key: "accountType",   label: "Tipo de cuenta",              type: "select", options: ["Corriente", "Ahorros"] },
        { key: "holderName",    label: "Nombre del titular",          placeholder: "Razón social o nombre de persona" },
        { key: "holderId",      label: "Cédula / RIF",                placeholder: "V-12.345.678 o J-XXXXXXXX-X", mono: true },
      ];
    }
    if (id === "pago-movil") {
      return [
        { key: "bank",     label: "Banco",     placeholder: "Banco de Venezuela, Banesco..." },
        { key: "phone",    label: "Teléfono asociado", placeholder: "0414-1234567", mono: true },
        { key: "holderId", label: "Cédula / RIF",      placeholder: "V-12.345.678", mono: true },
      ];
    }
    if (id === "zelle") {
      return [
        { key: "email",      label: "Correo electrónico asociado", placeholder: "ejemplo@email.com", mono: true },
        { key: "phone",      label: "Teléfono asociado (opcional)",placeholder: "+1 555 555 5555",  mono: true },
        { key: "holderName", label: "Nombre del titular",          placeholder: "Como aparece en la cuenta Zelle" },
      ];
    }
    if (id === "binance" || id === "crypto" || id === "usdt") {
      return [
        { key: "network",       label: "Red / Blockchain (¡crítico!)", type: "select", options: ["TRC-20", "ERC-20", "BEP-20", "Polygon", "Solana", "Bitcoin"] },
        { key: "walletAddress", label: "Dirección de la wallet",       placeholder: "TXxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx", mono: true, multiline: true },
        { key: "qrCode",        label: "Código QR (opcional)",         type: "qr" },
      ];
    }
    // Custom: genérico
    return [
      { key: "bank",       label: "Entidad / Banco", placeholder: "Nombre de la entidad" },
      { key: "account",    label: "Cuenta / Identificador", placeholder: "Número, email, wallet..." },
      { key: "holderName", label: "Titular", placeholder: "Nombre o razón social" },
      { key: "notes",      label: "Notas adicionales", placeholder: "Cualquier dato relevante para el cliente", multiline: true },
    ];
  })();

  return (
    <div onClick={onClose} className="fixed inset-0 bg-stone-900/70 z-[60] flex justify-center items-start p-4 sm:p-12 overflow-y-auto">
      <div onClick={(e) => e.stopPropagation()} className="bg-stone-50 rounded-2xl w-full max-w-xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
        <div className="p-4 border-b border-stone-200 bg-gradient-to-br from-blue-50 to-white flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-stone-900 text-white grid place-items-center flex-shrink-0">
            <Icon size={16} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase text-blue-700 font-bold">Datos del método</div>
            <h3 className="font-serif text-lg font-semibold mt-0.5 leading-tight">{method.label}</h3>
          </div>
          <button onClick={onClose} className="w-8 h-8 rounded-lg bg-white hover:bg-stone-100 grid place-items-center text-stone-500 flex-shrink-0">
            <X size={14} />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-3">
          <p className="text-xs text-stone-500 leading-relaxed bg-blue-50 border border-blue-200 rounded-lg p-2.5">
            Estos datos los verá el operador al cobrar con este método y se incluirán al enviarlos al cliente desde el chat.
          </p>

          {fields.map(f => (
            <div key={f.key}>
              <label className="block text-xs tracking-widest uppercase text-stone-500 font-semibold mb-1.5">
                {f.label}
              </label>
              {f.type === "select" ? (
                <select
                  value={draft[f.key] || f.options[0]}
                  onChange={(e) => upd(f.key, e.target.value)}
                  className="w-full px-3 py-2 bg-white border border-stone-200 rounded-lg text-sm outline-none focus:border-orange-400"
                >
                  {f.options.map(opt => <option key={opt} value={opt}>{opt}</option>)}
                </select>
              ) : f.type === "qr" ? (
                <div>
                  {draft.qrCode ? (
                    <div className="space-y-2">
                      <img src={draft.qrCode} alt="QR" className="w-32 h-32 object-contain border border-stone-200 rounded-lg bg-white" />
                      <button onClick={() => upd("qrCode", null)} className="text-xs text-red-600 hover:text-red-700 font-semibold">
                        Eliminar QR
                      </button>
                    </div>
                  ) : (
                    <label className="flex items-center justify-center gap-2 w-full py-3 bg-white border-2 border-dashed border-stone-300 rounded-lg text-xs text-stone-500 hover:border-orange-400 hover:text-orange-700 cursor-pointer transition">
                      <Plus size={12} /> Subir imagen del QR
                      <input type="file" accept="image/*" onChange={handleQrUpload} className="hidden" />
                    </label>
                  )}
                </div>
              ) : f.multiline ? (
                <textarea
                  value={draft[f.key] || ""}
                  onChange={(e) => upd(f.key, e.target.value)}
                  placeholder={f.placeholder}
                  rows={2}
                  className={`w-full px-3 py-2 bg-white border border-stone-200 rounded-lg text-sm outline-none focus:border-orange-400 resize-y placeholder:text-stone-400 ${f.mono ? "font-mono" : ""}`}
                />
              ) : (
                <input
                  type="text"
                  value={draft[f.key] || ""}
                  onChange={(e) => upd(f.key, e.target.value)}
                  placeholder={f.placeholder}
                  className={`w-full px-3 py-2 bg-white border border-stone-200 rounded-lg text-sm outline-none focus:border-orange-400 placeholder:text-stone-400 ${f.mono ? "font-mono" : ""}`}
                />
              )}
            </div>
          ))}
        </div>

        <div className="p-3.5 border-t border-stone-200 bg-white flex justify-end gap-2">
          <button onClick={onClose} className="px-3 py-2 rounded-xl text-sm font-semibold bg-white border border-stone-200 hover:border-stone-400 text-stone-700">
            Cancelar
          </button>
          <button
            onClick={() => onSave(draft)}
            className="flex items-center gap-1.5 px-4 py-2 rounded-xl text-sm font-semibold bg-emerald-600 hover:bg-emerald-700 text-white"
          >
            <Check size={12} /> Guardar datos
          </button>
        </div>
      </div>
    </div>
  );
}

// ========== HELPERS: render compartido de datos de un método de pago ==========
// Función reutilizable que renderiza los detalles de un método para mostrarlos
// inline en el SaleBuilder o copiarlos a un mensaje de chat.
function renderPaymentMethodDetails(method) {
  if (!method || !method.details) return null;
  const d = method.details;
  const rows = [];
  const id = method.id;

  if (id === "transferencia") {
    if (d.bank) rows.push({ label: "Banco", value: d.bank });
    if (d.accountNumber) rows.push({ label: "Cuenta", value: d.accountNumber, mono: true });
    if (d.accountType) rows.push({ label: "Tipo", value: d.accountType });
    if (d.holderName) rows.push({ label: "Titular", value: d.holderName });
    if (d.holderId) rows.push({ label: "C.I./RIF", value: d.holderId, mono: true });
  } else if (id === "pago-movil") {
    if (d.bank) rows.push({ label: "Banco", value: d.bank });
    if (d.phone) rows.push({ label: "Teléfono", value: d.phone, mono: true });
    if (d.holderId) rows.push({ label: "C.I./RIF", value: d.holderId, mono: true });
  } else if (id === "zelle") {
    if (d.email) rows.push({ label: "Email", value: d.email, mono: true });
    if (d.phone) rows.push({ label: "Teléfono", value: d.phone, mono: true });
    if (d.holderName) rows.push({ label: "Titular", value: d.holderName });
  } else if (id === "binance" || id === "crypto" || id === "usdt") {
    if (d.network) rows.push({ label: "Red", value: d.network, alert: true });
    if (d.walletAddress) rows.push({ label: "Wallet", value: d.walletAddress, mono: true });
  } else if (id === "tarjeta") {
    if (d.bank) rows.push({ label: "Banco", value: d.bank });
    if (d.terminal) rows.push({ label: "Terminal", value: d.terminal });
    if (d.lastDigits) rows.push({ label: "Últimos 4", value: d.lastDigits, mono: true });
  } else {
    if (d.bank) rows.push({ label: "Entidad", value: d.bank });
    if (d.account) rows.push({ label: "Cuenta", value: d.account, mono: true });
    if (d.holderName) rows.push({ label: "Titular", value: d.holderName });
    if (d.notes) rows.push({ label: "Notas", value: d.notes });
  }
  return rows;
}

// Función que genera un string de mensaje para enviar por chat con los datos
// del método. Se usa en el "+" del chat → Enviar método de pago.
function buildPaymentMethodMessage(method) {
  if (!method) return "";
  const rows = renderPaymentMethodDetails(method);
  if (!rows || rows.length === 0) {
    return `💳 Método de pago: *${method.label}*`;
  }
  const lines = [`💳 *${method.label}*`, ""];
  rows.forEach(r => {
    lines.push(`*${r.label}:* ${r.value}`);
  });
  return lines.join("\n");
}

function AgendaSettingsView({ appointmentSettings = { autoApprove: true }, setAppointmentSettings, userRole = "super", agendaEvents = [] }) {
  const isSuper = userRole === "super";

  // Conteo de citas web pendientes para mostrar visibilidad de impacto
  const pendingCount = useMemo(
    () => (agendaEvents || []).filter(e => e.fromWeb === true && e.pendingApproval).length,
    [agendaEvents]
  );

  const toggleAutoApprove = () => {
    if (!setAppointmentSettings || !isSuper) return;
    setAppointmentSettings(prev => ({ ...prev, autoApprove: !prev.autoApprove }));
  };

  return (
    <div className="max-w-3xl mx-auto space-y-5">
      {/* Sección: flujo de citas web */}
      <div className="bg-white border border-stone-200 rounded-2xl shadow-sm overflow-hidden">
        <div className="p-5 border-b border-stone-200">
          <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold">
            Citas agendadas por web
          </div>
          <h3 className="font-serif text-lg font-semibold mt-0.5">Flujo de aprobación</h3>
          <p className="text-xs text-stone-500 mt-1">
            Decide qué pasa cuando un cliente reserva desde el sitio público.
          </p>
        </div>

        {/* Toggle: auto-aprobación */}
        <div className="p-5 flex items-start gap-4">
          <div className={`w-11 h-11 rounded-xl grid place-items-center flex-shrink-0 ${
            appointmentSettings.autoApprove
              ? "bg-emerald-100 text-emerald-700"
              : "bg-amber-100 text-amber-700"
          }`}>
            {appointmentSettings.autoApprove ? <CheckCircle size={20} strokeWidth={2} /> : <Clock size={20} strokeWidth={2} />}
          </div>
          <div className="flex-1 min-w-0">
            <div className="flex items-center gap-3 flex-wrap">
              <span className="font-semibold text-sm text-stone-800">Aprobación automática</span>
              {appointmentSettings.autoApprove ? (
                <span className="text-xs font-bold uppercase tracking-wider text-emerald-700 bg-emerald-50 px-2 py-0.5 rounded-full border border-emerald-200">
                  Activado
                </span>
              ) : (
                <span className="text-xs font-bold uppercase tracking-wider text-amber-700 bg-amber-50 px-2 py-0.5 rounded-full border border-amber-200">
                  Manual
                </span>
              )}
            </div>
            <div className="text-xs text-stone-600 mt-1.5 leading-relaxed">
              {appointmentSettings.autoApprove ? (
                <>Las citas reservadas desde la web se confirman <strong>al instante</strong>. Útil cuando tu agenda está abierta y confías en el filtrado de horarios.</>
              ) : (
                <>Las citas reservadas desde la web entran como <strong>pendientes</strong>. Tienes que aprobarlas manualmente desde la agenda antes de confirmárselas al cliente.</>
              )}
            </div>
            {pendingCount > 0 && !appointmentSettings.autoApprove && (
              <div className="mt-2 text-xs text-amber-700 bg-amber-50 border border-amber-200 rounded-lg px-2.5 py-1.5 inline-flex items-center gap-1.5">
                <AlertCircle size={12} />
                <span>Tenés {pendingCount} {pendingCount === 1 ? "cita pendiente" : "citas pendientes"} en este momento.</span>
              </div>
            )}
          </div>
          {/* Switch */}
          <button
            onClick={toggleAutoApprove}
            disabled={!isSuper || !setAppointmentSettings}
            title={isSuper ? "" : "Solo el super usuario puede modificar este ajuste"}
            className={`relative flex-shrink-0 w-12 h-7 rounded-full transition ${
              appointmentSettings.autoApprove ? "bg-emerald-500" : "bg-stone-300"
            } ${!isSuper ? "opacity-50 cursor-not-allowed" : ""}`}
          >
            <span className={`absolute top-1 w-5 h-5 bg-white rounded-full shadow transition-all ${
              appointmentSettings.autoApprove ? "left-6" : "left-1"
            }`} />
          </button>
        </div>

        {!isSuper && (
          <div className="px-5 pb-5">
            <div className="bg-stone-50 border border-stone-200 rounded-lg px-3 py-2 text-xs text-stone-600 flex items-center gap-2">
              <Lock size={12} />
              Solo el super usuario puede cambiar esta configuración.
            </div>
          </div>
        )}
      </div>

      {/* Placeholder para futuras secciones */}
      <div className="bg-stone-50 border border-stone-200 border-dashed rounded-2xl p-6 text-center">
        <Calendar size={20} className="text-stone-300 mx-auto mb-2" />
        <div className="text-sm text-stone-500">
          Próximamente: horarios de atención, salas y recordatorios.
        </div>
      </div>
    </div>
  );
}

