// ========== MODAL: AGENDAR CITA ==========

function AppointmentModal({ onClose, agendaEvents = [], setAgendaEvents, autoApprove = true, sedes = [] }) {
  // Sedes visibles al cliente — solo las activas
  const visibleSedes = useMemo(() => (sedes || []).filter(s => s.active !== false), [sedes]);
  // Si solo hay una sede, no preguntamos: arranca directo en "servicio" con esa sede.
  const needsSedeStep = visibleSedes.length > 1;

  const [step, setStep] = useState(needsSedeStep ? 0 : 1); // 0: sede, 1: servicio, 2: fecha/hora, 3: datos
  const [selectedSedeId, setSelectedSedeId] = useState(needsSedeStep ? null : (visibleSedes[0]?.id || null));
  const [serviceType, setServiceType] = useState(null); // "vet" | "grooming"
  const [selectedDate, setSelectedDate] = useState(null);
  const [selectedTime, setSelectedTime] = useState(null);
  const [weekOffset, setWeekOffset] = useState(0); // 0 = esta semana, 1 = próxima, etc.
  const [form, setForm] = useState({
    name: "", phone: "", email: "",
    petName: "", petSpecies: "dog", petSpeciesOther: "",
  });
  const [submitted, setSubmitted] = useState(false);

  // Duración hardcodeada de 1 hora para todos los servicios. En el futuro
  // se podría tomar del catálogo del servicio elegido.
  const APPOINTMENT_DURATION_MIN = 60;

  // Generar 30 días hacia adelante (empezando mañana)
  const availableDates = useMemo(() => {
    const dates = [];
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    for (let i = 1; i <= 30; i++) {
      const d = new Date(today);
      d.setDate(today.getDate() + i);
      dates.push(d);
    }
    return dates;
  }, []);

  // Días visibles según semana actual (7 por semana, ~5 semanas posibles)
  const totalWeeks = Math.ceil(availableDates.length / 7);
  const visibleDates = availableDates.slice(weekOffset * 7, (weekOffset + 1) * 7);

  // Rango de fechas mostrado
  const rangeLabel = useMemo(() => {
    if (visibleDates.length === 0) return "—";
    const first = visibleDates[0];
    const last = visibleDates[visibleDates.length - 1];
    const fmt = (d) => d.toLocaleDateString("es", { day: "2-digit", month: "short" });
    return `${fmt(first)} – ${fmt(last)}`;
  }, [visibleDates]);

  const allTimes = ["09:00", "10:00", "11:00", "12:00", "14:00", "15:00", "16:00", "17:00"];

  // === Helper: ¿está ocupado este slot? ===
  // Un slot se considera ocupado si hay algún evento en agenda que solape con él.
  // Solo contamos eventos del MISMO tipo (vet vs grooming) — si son tipos distintos
  // pueden coexistir (ej: vet y grooming pueden atender en paralelo).
  // Nota: ignoramos citas con pendingApproval=true ya que no están confirmadas todavía
  // (el cliente que reserva NO debe ver bloqueada una hora por una cita aún pendiente).
  const isSlotTaken = (dateISO, timeHHMM) => {
    if (!serviceType) return false;
    const proposed = parseHHMM(timeHHMM);
    if (proposed === null) return false;
    const proposedEnd = proposed + APPOINTMENT_DURATION_MIN;
    return (agendaEvents || []).some(e => {
      if (e.pendingApproval) return false; // citas pendientes no bloquean
      if (e.type !== serviceType) return false; // distinto departamento → no choca
      if (e.date !== dateISO) return false;
      const evtStart = parseHHMM(e.time);
      if (evtStart === null) return false;
      const evtEnd = evtStart + (e.duration || APPOINTMENT_DURATION_MIN);
      return proposed < evtEnd && proposedEnd > evtStart;
    });
  };

  // Lista de horas con flag de disponibilidad para la fecha seleccionada
  const availableTimes = useMemo(() => {
    if (!selectedDate) return allTimes.map(t => ({ time: t, taken: false }));
    const dateISO = selectedDate.toISOString().slice(0, 10);
    return allTimes.map(t => ({ time: t, taken: isSlotTaken(dateISO, t) }));
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [selectedDate, agendaEvents, serviceType]);

  // Si el slot que el usuario tenía elegido se acaba de ocupar (caso raro pero
  // posible si llega un evento mientras está abierto el modal), lo deseleccionamos.
  useEffect(() => {
    if (selectedTime && availableTimes.find(t => t.time === selectedTime)?.taken) {
      setSelectedTime(null);
    }
  }, [availableTimes, selectedTime]);

  const speciesOpts = [
    { id: "dog", label: "Perro", Icon: Dog },
    { id: "cat", label: "Gato", Icon: Cat },
    { id: "bird", label: "Ave", Icon: Bird },
    { id: "rabbit", label: "Conejo", Icon: Rabbit },
    { id: "other", label: "Otros", Icon: PawPrint },
  ];

  const phoneValid = useMemo(() => form.phone.replace(/\D/g, "").length >= 10, [form.phone]);
  const emailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email), [form.email]);
  const formValid = form.name.trim() && phoneValid && emailValid && form.petName.trim() &&
    (form.petSpecies !== "other" || form.petSpeciesOther.trim());

  const canAdvance = (s) => {
    if (s === 0) return !!selectedSedeId;
    if (s === 1) return !!serviceType;
    if (s === 2) return selectedDate && selectedTime;
    if (s === 3) return formValid;
    return false;
  };

  const submit = () => {
    if (!formValid || !setAgendaEvents) {
      // Sin setter no podemos persistir — solo mostramos éxito visual (modo standalone)
      setSubmitted(true);
      return;
    }
    // Persistir como evento de agenda. Marcamos fromWeb=true y aplicamos
    // pendingApproval según la configuración global.
    const dateISO = selectedDate.toISOString().slice(0, 10);
    const newEvent = {
      id: `web-${Date.now().toString(36)}-${Math.random().toString(36).slice(2,5)}`,
      type: serviceType, // "vet" | "grooming"
      date: dateISO,
      time: selectedTime,
      duration: APPOINTMENT_DURATION_MIN,
      pet: form.petName.trim(),
      petCode: null, // mascota nueva, sin código aún
      species: form.petSpecies,
      speciesOther: form.petSpecies === "other" ? form.petSpeciesOther.trim() : "",
      breed: "",
      owner: form.name.trim(),
      ownerPhone: form.phone.trim(),
      ownerEmail: form.email.trim(),
      professional: null,
      title: serviceType === "vet" ? "Consulta veterinaria (web)" : "Servicio de grooming (web)",
      reason: `Cita reservada desde el sitio web por ${form.name.trim()}.`,
      room: null,
      status: autoApprove ? "confirmada" : "pendiente",
      // Flags específicos del flujo web
      fromWeb: true,
      pendingApproval: !autoApprove,
      moduleId: serviceType === "vet" ? "vet" : "grooming-ops",
      // === Sede elegida por el cliente desde la web ===
      // Esta sede determina qué sucursal recibe la cita. Si la auto-aprobación
      // está activa, la cita queda visible directamente para el equipo de esa sede.
      sedeId: selectedSedeId || null,
    };
    setAgendaEvents(prev => [newEvent, ...prev]);
    setSubmitted(true);
  };

  if (submitted) {
    return <SuccessScreen onClose={onClose} form={form} serviceType={serviceType} date={selectedDate} time={selectedTime} pendingApproval={!autoApprove} />;
  }

  const fmtDate = (d) => d.toLocaleDateString("es", { weekday: "short", day: "2-digit", month: "short" });
  const fmtSelectedDate = (d) => d ? d.toLocaleDateString("es", { weekday: "long", day: "2-digit", month: "long", year: "numeric" }) : "—";

  return (
    <div onClick={onClose} className="fixed inset-0 bg-stone-900 z-50 flex justify-center items-start p-4 overflow-y-auto">
      <div onClick={(e) => e.stopPropagation()} className="bg-stone-50 rounded-2xl w-full max-w-2xl shadow-2xl my-8 overflow-hidden">
        {/* Header */}
        <div className="p-5 border-b border-stone-200 bg-gradient-to-r from-white to-orange-50 flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-orange-500 to-orange-700 text-white grid place-items-center shadow-lg">
            <Calendar size={20} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold">
              Agendar cita · Paso {needsSedeStep ? step + 1 : step} de {needsSedeStep ? 4 : 3}
            </div>
            <h3 className="font-serif text-xl font-semibold mt-0.5">
              {step === 0 && "¿En qué sede?"}
              {step === 1 && "¿Qué servicio necesitas?"}
              {step === 2 && "Elige fecha y hora"}
              {step === 3 && "Tus datos de contacto"}
            </h3>
          </div>
          <button onClick={onClose} className="w-9 h-9 rounded-full bg-white border border-stone-200 grid place-items-center text-stone-600 hover:text-orange-700">
            <X size={16} />
          </button>
        </div>

        {/* Stepper visual: si hay multi-sede empieza en 0 (Sede), sino arranca en 1. */}
        <div className="bg-white border-b border-stone-200 px-5 py-3 flex items-center gap-2 overflow-x-auto">
          {(needsSedeStep ? [0, 1, 2, 3] : [1, 2, 3]).map((n, i, arr) => {
            const isActive = step === n;
            const isDone = step > n;
            const label = n === 0 ? "Sede" : n === 1 ? "Servicio" : n === 2 ? "Fecha y hora" : "Datos";
            return (
              <Fragment key={n}>
                <div className="flex items-center gap-2 flex-shrink-0">
                  <span className={`w-6 h-6 rounded-full grid place-items-center text-xs font-bold transition ${
                    isActive ? "bg-orange-600 text-white" :
                    isDone ? "bg-emerald-500 text-white" :
                    "bg-stone-200 text-stone-600"
                  }`}>
                    {isDone ? <Check size={11} strokeWidth={3} /> : (i + 1)}
                  </span>
                  <span className={`text-xs font-semibold ${isActive ? "text-stone-900" : "text-stone-500"}`}>
                    {label}
                  </span>
                </div>
                {i < arr.length - 1 && <div className="flex-1 h-0.5 bg-stone-200 min-w-[10px]"></div>}
              </Fragment>
            );
          })}
        </div>

        {/* Body */}
        <div className="p-5 max-h-96 overflow-y-auto">
          {/* Step 0: sede (solo si hay multi-sede) */}
          {step === 0 && (
            <div className="space-y-3">
              <p className="text-sm text-stone-600 mb-3">
                Selecciona la sede a la que deseas ir.
              </p>
              {visibleSedes.map(sede => (
                <button
                  key={sede.id}
                  onClick={() => setSelectedSedeId(sede.id)}
                  className={`w-full text-left p-5 rounded-2xl border-2 transition flex items-start gap-4 ${
                    selectedSedeId === sede.id
                      ? "border-orange-500 bg-orange-50"
                      : "border-stone-200 bg-white hover:border-orange-300"
                  }`}
                >
                  <div className="w-14 h-14 rounded-2xl bg-gradient-to-br from-orange-500 to-orange-700 text-white grid place-items-center flex-shrink-0 shadow-lg">
                    <MapPin size={26} strokeWidth={1.6} />
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 flex-wrap">
                      <span className="font-serif text-lg font-semibold">{sede.name}</span>
                      {sede.isDefault && (
                        <span className="text-[10px] font-bold uppercase px-1.5 py-0.5 rounded bg-orange-100 text-orange-700">
                          Principal
                        </span>
                      )}
                    </div>
                    <div className="text-sm text-stone-600 leading-relaxed mt-0.5">
                      {sede.description || "Sucursal de Cricket."}
                    </div>
                  </div>
                  {selectedSedeId === sede.id && <Check size={20} className="text-orange-600 flex-shrink-0 mt-2" strokeWidth={2.5} />}
                </button>
              ))}
            </div>
          )}

          {/* Step 1: servicio */}
          {step === 1 && (
            <div className="space-y-3">
              <p className="text-sm text-stone-600 mb-3">
                Selecciona el tipo de servicio que necesitas para tu mascota.
              </p>
              <button
                onClick={() => setServiceType("vet")}
                className={`w-full text-left p-5 rounded-2xl border-2 transition flex items-start gap-4 ${
                  serviceType === "vet" ? "border-orange-500 bg-orange-50" : "border-stone-200 bg-white hover:border-orange-300"
                }`}
              >
                <div className="w-14 h-14 rounded-2xl bg-gradient-to-br from-orange-500 to-orange-700 text-white grid place-items-center flex-shrink-0 shadow-lg">
                  <Stethoscope size={26} strokeWidth={1.6} />
                </div>
                <div className="flex-1 min-w-0">
                  <div className="font-serif text-lg font-semibold mb-1">Clínica veterinaria</div>
                  <div className="text-sm text-stone-600 leading-relaxed">
                    Consulta general, vacunación, control, exámenes de laboratorio.
                  </div>
                </div>
                {serviceType === "vet" && <Check size={20} className="text-orange-600 flex-shrink-0 mt-2" strokeWidth={2.5} />}
              </button>

              <button
                onClick={() => setServiceType("grooming")}
                className={`w-full text-left p-5 rounded-2xl border-2 transition flex items-start gap-4 ${
                  serviceType === "grooming" ? "border-emerald-500 bg-emerald-50" : "border-stone-200 bg-white hover:border-emerald-300"
                }`}
              >
                <div className="w-14 h-14 rounded-2xl bg-gradient-to-br from-emerald-500 to-emerald-700 text-white grid place-items-center flex-shrink-0 shadow-lg">
                  <Scissors size={26} strokeWidth={1.6} />
                </div>
                <div className="flex-1 min-w-0">
                  <div className="font-serif text-lg font-semibold mb-1">Peluquería canina</div>
                  <div className="text-sm text-stone-600 leading-relaxed">
                    Baño, corte, spa, cepillado profundo, tratamiento antipulgas.
                  </div>
                </div>
                {serviceType === "grooming" && <Check size={20} className="text-emerald-600 flex-shrink-0 mt-2" strokeWidth={2.5} />}
              </button>
            </div>
          )}

          {/* Step 2: fecha y hora */}
          {step === 2 && (
            <div className="space-y-4">
              {/* Header del calendario con navegación de semana */}
              <div className="flex items-center justify-between gap-2 flex-wrap">
                <div>
                  <label className="text-xs tracking-widest uppercase text-orange-700 font-semibold block">
                    Fecha y hora
                  </label>
                  <div className="font-serif text-base font-semibold capitalize">{rangeLabel}</div>
                </div>
                <div className="flex items-center gap-1">
                  <button
                    onClick={() => setWeekOffset(Math.max(0, weekOffset - 1))}
                    disabled={weekOffset === 0}
                    className={`w-9 h-9 rounded-lg border grid place-items-center transition ${
                      weekOffset === 0
                        ? "bg-stone-100 border-stone-200 text-stone-300 cursor-not-allowed"
                        : "bg-white border-stone-200 hover:border-orange-400 text-stone-700"
                    }`}
                  >
                    <ChevronLeft size={15} />
                  </button>
                  <div className="px-3 py-2 rounded-lg bg-stone-100 text-xs font-semibold text-stone-700">
                    Semana {weekOffset + 1} de {totalWeeks}
                  </div>
                  <button
                    onClick={() => setWeekOffset(Math.min(totalWeeks - 1, weekOffset + 1))}
                    disabled={weekOffset >= totalWeeks - 1}
                    className={`w-9 h-9 rounded-lg border grid place-items-center transition ${
                      weekOffset >= totalWeeks - 1
                        ? "bg-stone-100 border-stone-200 text-stone-300 cursor-not-allowed"
                        : "bg-white border-stone-200 hover:border-orange-400 text-stone-700"
                    }`}
                  >
                    <ChevronRight size={15} />
                  </button>
                </div>
              </div>

              {/* Layout: fechas (izquierda) + horas (derecha) */}
              <div className="flex flex-col sm:flex-row gap-3">
                {/* Columna izquierda: fechas en grid de 7 (semanal) */}
                <div className="flex-1 min-w-0">
                  <div className="text-xs font-semibold text-stone-600 mb-2">Día</div>
                  <div className="grid grid-cols-7 sm:grid-cols-4 gap-1.5">
                    {visibleDates.map((d, i) => {
                      const isSelected = selectedDate?.getTime() === d.getTime();
                      return (
                        <button
                          key={i}
                          onClick={() => { setSelectedDate(d); setSelectedTime(null); }}
                          className={`p-2 rounded-lg border text-center transition ${
                            isSelected
                              ? "bg-orange-600 border-orange-600 text-white shadow-lg"
                              : "bg-white border-stone-200 hover:border-orange-300"
                          }`}
                        >
                          <div className={`text-xs uppercase font-semibold leading-none ${isSelected ? "text-white" : "text-stone-500"}`}>
                            {d.toLocaleDateString("es", { weekday: "short" }).replace(".", "")}
                          </div>
                          <div className={`font-serif text-xl font-semibold leading-none mt-1.5 ${isSelected ? "text-white" : "text-stone-900"}`}>
                            {d.getDate()}
                          </div>
                          <div className={`text-xs mt-0.5 ${isSelected ? "text-white" : "text-stone-400"}`}>
                            {d.toLocaleDateString("es", { month: "short" }).replace(".", "")}
                          </div>
                        </button>
                      );
                    })}
                  </div>
                </div>

                {/* Columna derecha: horas (ancho fijo en sm+) */}
                <div className="sm:w-36 flex-shrink-0">
                  <div className="text-xs font-semibold text-stone-600 mb-2">
                    {selectedDate ? "Hora" : "Selecciona una fecha"}
                  </div>
                  {selectedDate ? (
                    <>
                      <div className="grid grid-cols-4 sm:grid-cols-2 gap-1.5">
                        {availableTimes.map(({ time: t, taken }) => {
                          const isSelected = selectedTime === t;
                          return (
                            <button
                              key={t}
                              onClick={() => !taken && setSelectedTime(t)}
                              disabled={taken}
                              title={taken ? "Horario ocupado" : ""}
                              className={`px-2 py-2 rounded-lg border font-mono text-sm font-semibold transition relative ${
                                taken
                                  ? "bg-stone-100 border-stone-200 text-stone-400 line-through cursor-not-allowed"
                                  : isSelected
                                  ? "bg-orange-600 border-orange-600 text-white shadow-lg"
                                  : "bg-white border-stone-200 hover:border-orange-300"
                              }`}
                            >
                              {t}
                            </button>
                          );
                        })}
                      </div>
                      {availableTimes.every(t => t.taken) && (
                        <div className="mt-2 text-xs text-stone-500 italic">
                          Todos los horarios de este día están ocupados. Probá con otra fecha.
                        </div>
                      )}
                    </>
                  ) : (
                    <div className="bg-stone-50 border border-stone-200 border-dashed rounded-lg p-6 text-center">
                      <Clock size={20} className="text-stone-300 mx-auto mb-2" />
                      <div className="text-xs text-stone-500">
                        Elige un día primero
                      </div>
                    </div>
                  )}
                </div>
              </div>

              {/* Confirmación */}
              {selectedDate && selectedTime && (
                <div className="p-3 rounded-xl bg-emerald-50 border border-emerald-200 flex items-start gap-2.5">
                  <Check size={15} className="text-emerald-700 flex-shrink-0 mt-0.5" strokeWidth={2.5} />
                  <div className="text-sm text-emerald-900">
                    <strong>Cita seleccionada:</strong>{" "}
                    <span className="capitalize">{fmtSelectedDate(selectedDate)}</span>{" "}
                    a las <strong>{selectedTime}</strong>
                  </div>
                </div>
              )}
            </div>
          )}

          {/* Step 3: datos */}
          {step === 3 && (
            <div className="space-y-3.5">
              <p className="text-sm text-stone-600 mb-1">
                Para confirmar tu cita necesitamos tus datos. Te contactaremos por WhatsApp y email.
              </p>

              {/* Resumen */}
              <div className="p-3 rounded-xl bg-stone-100 border border-stone-200 text-xs text-stone-700">
                <strong className="font-semibold">Resumen:</strong> {serviceType === "vet" ? "Consulta veterinaria" : "Servicio de peluquería"} ·{" "}
                {fmtSelectedDate(selectedDate)} a las {selectedTime}
              </div>

              <div className="grid sm:grid-cols-2 gap-3">
                <FormField label="Nombre completo *">
                  <input
                    value={form.name}
                    onChange={(e) => setForm({...form, name: e.target.value})}
                    placeholder="Tu nombre"
                    className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
                    autoFocus
                  />
                </FormField>
                <FormField label="Teléfono / WhatsApp *">
                  <div className="relative">
                    <input
                      value={form.phone}
                      onChange={(e) => setForm({...form, phone: e.target.value})}
                      placeholder="0414-1234567"
                      className={`w-full px-3.5 py-2.5 pr-10 bg-white border rounded-xl text-sm outline-none ${
                        form.phone && !phoneValid ? "border-red-400" :
                        form.phone && phoneValid ? "border-emerald-400" :
                        "border-stone-200 focus:border-orange-500"
                      }`}
                    />
                    {form.phone && (
                      <span className={`absolute right-3 top-1/2 -translate-y-1/2 ${phoneValid ? "text-emerald-600" : "text-red-500"}`}>
                        {phoneValid ? <Check size={14} strokeWidth={2.5} /> : <AlertTriangle size={13} />}
                      </span>
                    )}
                  </div>
                </FormField>
              </div>

              <FormField label="Email *">
                <div className="relative">
                  <input
                    type="email"
                    value={form.email}
                    onChange={(e) => setForm({...form, email: e.target.value})}
                    placeholder="tu@correo.com"
                    className={`w-full px-3.5 py-2.5 pr-10 bg-white border rounded-xl text-sm outline-none ${
                      form.email && !emailValid ? "border-red-400" :
                      form.email && emailValid ? "border-emerald-400" :
                      "border-stone-200 focus:border-orange-500"
                    }`}
                  />
                  {form.email && (
                    <span className={`absolute right-3 top-1/2 -translate-y-1/2 ${emailValid ? "text-emerald-600" : "text-red-500"}`}>
                      {emailValid ? <Check size={14} strokeWidth={2.5} /> : <AlertTriangle size={13} />}
                    </span>
                  )}
                </div>
              </FormField>

              <div className="grid sm:grid-cols-2 gap-3">
                <FormField label="Nombre de tu mascota *">
                  <input
                    value={form.petName}
                    onChange={(e) => setForm({...form, petName: e.target.value})}
                    placeholder="Ej: Toby"
                    className="w-full px-3.5 py-2.5 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
                  />
                </FormField>
                <FormField label="Especie">
                  <div className="flex gap-1.5 flex-wrap">
                    {speciesOpts.map(s => {
                      const Ic = s.Icon;
                      const active = form.petSpecies === s.id;
                      return (
                        <button
                          key={s.id}
                          onClick={() => setForm({...form, petSpecies: s.id})}
                          className={`flex items-center gap-1.5 px-3 py-2 rounded-xl text-xs font-semibold transition ${
                            active ? "bg-orange-600 text-white" : "bg-white text-stone-600 border border-stone-200"
                          }`}
                        >
                          <Ic size={13} strokeWidth={1.8} />
                          {s.label}
                        </button>
                      );
                    })}
                  </div>
                  {form.petSpecies === "other" && (
                    <input
                      value={form.petSpeciesOther}
                      onChange={(e) => setForm({...form, petSpeciesOther: e.target.value})}
                      placeholder="¿Qué tipo de mascota? (ej: hurón, iguana, tortuga…)"
                      autoFocus
                      className="mt-2 w-full px-3.5 py-2.5 bg-white border border-orange-300 rounded-xl text-sm outline-none focus:border-orange-500"
                    />
                  )}
                </FormField>
              </div>

              <div className="p-3 rounded-xl bg-orange-50 border border-orange-200 flex gap-2.5 text-xs text-orange-900">
                <BadgeCheck size={14} className="text-orange-700 flex-shrink-0 mt-0.5" />
                <div>
                  Recibirás una <strong>confirmación inmediata por email</strong> y un mensaje por WhatsApp con los detalles de tu cita.
                </div>
              </div>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="p-3.5 px-5 border-t border-stone-200 bg-white flex justify-between gap-2 flex-wrap">
          {/* Atrás: aparece si hay paso anterior. Si multi-sede, el step 0 es alcanzable. */}
          {step > (needsSedeStep ? 0 : 1) ? (
            <button
              onClick={() => setStep(step - 1)}
              className="flex items-center gap-1.5 px-3 py-2 rounded-xl text-sm font-semibold bg-white text-stone-700 border border-stone-200 hover:border-orange-400"
            >
              <ChevronLeft size={14} /> Atrás
            </button>
          ) : <div />}

          <div className="flex gap-2 ml-auto">
            <button onClick={onClose} className="px-3 py-2 rounded-xl text-sm font-semibold bg-white text-stone-700 border border-stone-200">
              Cancelar
            </button>
            {step < 3 ? (
              <button
                onClick={() => setStep(step + 1)}
                disabled={!canAdvance(step)}
                className={`flex items-center gap-1.5 px-4 py-2 rounded-xl text-sm font-semibold bg-orange-600 hover:bg-orange-700 text-white transition ${
                  canAdvance(step) ? "" : "opacity-40 cursor-not-allowed"
                }`}
              >
                Continuar <ChevronRight size={14} />
              </button>
            ) : (
              <button
                onClick={submit}
                disabled={!formValid}
                className={`flex items-center gap-1.5 px-5 py-2 rounded-xl text-sm font-semibold bg-emerald-500 hover:bg-emerald-600 text-white transition ${
                  formValid ? "" : "opacity-40 cursor-not-allowed"
                }`}
              >
                <Check size={14} strokeWidth={2.5} /> Confirmar cita
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

function FormField({ label, children }) {
  return (
    <div>
      <label className="text-xs font-semibold text-stone-600 block mb-1.5">{label}</label>
      {children}
    </div>
  );
}

// ========== ÉXITO ==========

function SuccessScreen({ onClose, form, serviceType, date, time, pendingApproval = false }) {
  const fmtDate = (d) => d ? d.toLocaleDateString("es", { weekday: "long", day: "2-digit", month: "long", year: "numeric" }) : "—";

  return (
    <div onClick={onClose} className="fixed inset-0 bg-stone-900 z-50 flex justify-center items-start p-4 overflow-y-auto">
      <div onClick={(e) => e.stopPropagation()} className="bg-stone-50 rounded-2xl w-full max-w-md shadow-2xl my-8 overflow-hidden">
        <div className={`p-8 text-center ${pendingApproval ? "bg-gradient-to-br from-amber-50 via-white to-orange-50" : "bg-gradient-to-br from-emerald-50 via-white to-orange-50"}`}>
          <div className={`w-16 h-16 rounded-full grid place-items-center text-white mx-auto mb-4 shadow-lg ${pendingApproval ? "bg-amber-500" : "bg-emerald-500"}`}>
            {pendingApproval ? <Clock size={28} strokeWidth={2.5} /> : <Check size={32} strokeWidth={3} />}
          </div>
          <div className={`text-xs tracking-widest uppercase font-semibold mb-2 ${pendingApproval ? "text-amber-700" : "text-emerald-700"}`}>
            {pendingApproval ? "¡Solicitud recibida!" : "¡Cita confirmada!"}
          </div>
          <h3 className="font-serif text-2xl font-semibold leading-tight mb-3">
            {pendingApproval ? "Pronto te contactamos," : "Te esperamos,"} <span className="text-orange-700">{form.name.split(" ")[0]}</span>
          </h3>
          <p className="text-sm text-stone-600 leading-relaxed mb-5">
            {pendingApproval ? (
              <>Tu solicitud está en revisión. Te confirmaremos por WhatsApp a <strong>{form.phone}</strong> apenas la aprobemos.</>
            ) : (
              <>Acabamos de enviarte un email de confirmación a <strong>{form.email}</strong>. Te contactaremos por WhatsApp para recordarte la cita.</>
            )}
          </p>

          <div className="bg-white border border-stone-200 rounded-xl p-4 text-left space-y-2 mb-5">
            <div className="flex items-start gap-2.5">
              <Calendar size={14} className="text-orange-600 mt-0.5 flex-shrink-0" />
              <div>
                <div className="text-xs text-stone-500">Fecha y hora</div>
                <div className="text-sm font-semibold capitalize">
                  {fmtDate(date)} a las {time}
                </div>
              </div>
            </div>
            <div className="flex items-start gap-2.5">
              {serviceType === "vet" ? (
                <Stethoscope size={14} className="text-orange-600 mt-0.5 flex-shrink-0" />
              ) : (
                <Scissors size={14} className="text-orange-600 mt-0.5 flex-shrink-0" />
              )}
              <div>
                <div className="text-xs text-stone-500">Servicio</div>
                <div className="text-sm font-semibold">
                  {serviceType === "vet" ? "Clínica veterinaria" : "Peluquería canina"}
                </div>
              </div>
            </div>
            <div className="flex items-start gap-2.5">
              <PawPrint size={14} className="text-orange-600 mt-0.5 flex-shrink-0" />
              <div>
                <div className="text-xs text-stone-500">Mascota</div>
                <div className="text-sm font-semibold">{form.petName}</div>
              </div>
            </div>
          </div>

          <div className="flex gap-2">
            <button
              onClick={onClose}
              className="flex-1 px-4 py-2.5 rounded-xl bg-white border border-stone-200 hover:border-orange-300 text-stone-700 text-sm font-semibold transition"
            >
              Cerrar
            </button>
            <button className="flex-1 flex items-center justify-center gap-1.5 px-4 py-2.5 rounded-xl bg-emerald-500 hover:bg-emerald-600 text-white text-sm font-semibold transition">
              <MessageCircle size={13} /> Abrir WhatsApp
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

// SuccessScreen es el último componente del archivo

// ========== VISTA: CATÁLOGO VETERINARIA (solo super) ==========
// Espejo de Catálogo Grooming pero para servicios e insumos médicos.
// Categorías de insumos: Medicamento / Descartable / Vacuna / Otro.
function VetCatalogView({ services, setServices, vetSupplies, setVetSupplies, userRole }) {
  const isAdmin = userRole === "super";
  const [section, setSection] = useState("services"); // services | supplies

  // Edición/creación
  const [editingService, setEditingService] = useState(null); // null | <id>
  const [creatingService, setCreatingService] = useState(false);
  const serviceDraftBlank = { name: "", price: 0, duration: 30, description: "", module: "vet", active: true };
  const [serviceDraft, setServiceDraft] = useState(serviceDraftBlank);

  const [editingSupply, setEditingSupply] = useState(null); // null | "new" | <id>
  const supplyDraftBlank = { name: "", category: "Medicamento", unit: "ml", defaultQty: 1, price: 0, active: true };
  const [supplyDraft, setSupplyDraft] = useState(supplyDraftBlank);

  const [confirmDeleteService, setConfirmDeleteService] = useState(null);
  const [confirmDeleteSupply, setConfirmDeleteSupply] = useState(null);

  // === Calendario de citas vet ===
  const [calendarView, setCalendarView] = useState("week"); // day | week | month
  const [calendarDate, setCalendarDate] = useState(() => {
    const d = new Date();
    d.setHours(0, 0, 0, 0);
    return d;
  });
  // State local de eventos vet (drag&drop, reagendamiento)
  const [vetEventsState, setVetEventsState] = useState(() => AGENDA_EVENTS.filter(e => e.type === "vet"));
  const [selectedVetEventId, setSelectedVetEventId] = useState(null);

  // Eventos por fecha
  const eventsByDate = useMemo(() => {
    const m = {};
    vetEventsState.forEach(e => {
      if (!m[e.date]) m[e.date] = [];
      m[e.date].push(e);
    });
    Object.keys(m).forEach(k => m[k].sort((a, b) => a.time.localeCompare(b.time)));
    return m;
  }, [vetEventsState]);

  // Handlers de calendario
  const navigatePrev = () => {
    const d = new Date(calendarDate);
    if (calendarView === "day") d.setDate(d.getDate() - 1);
    else if (calendarView === "week") d.setDate(d.getDate() - 7);
    else d.setMonth(d.getMonth() - 1);
    setCalendarDate(d);
  };
  const navigateNext = () => {
    const d = new Date(calendarDate);
    if (calendarView === "day") d.setDate(d.getDate() + 1);
    else if (calendarView === "week") d.setDate(d.getDate() + 7);
    else d.setMonth(d.getMonth() + 1);
    setCalendarDate(d);
  };
  const goToToday = () => {
    const d = new Date();
    d.setHours(0, 0, 0, 0);
    setCalendarDate(d);
  };
  const jumpToCalendarDay = (d) => {
    const newDate = new Date(d);
    newDate.setHours(0, 0, 0, 0);
    setCalendarDate(newDate);
    setCalendarView("day");
  };

  const handleRescheduleVet = (eventId, newDate, newTime) => {
    setVetEventsState(prev => prev.map(e =>
      e.id === eventId ? { ...e, date: newDate, time: newTime || e.time } : e
    ));
  };
  const handleMoveVetEvent = (eventId, newDate) => {
    handleRescheduleVet(eventId, newDate, null);
  };
  const handleDeleteVetEvent = (eventId) => {
    setVetEventsState(prev => prev.filter(e => e.id !== eventId));
    setSelectedVetEventId(null);
  };
  const handleAssignVetToEvent = (eventId, vetName) => {
    setVetEventsState(prev => prev.map(e =>
      e.id === eventId ? { ...e, vet: vetName } : e
    ));
  };

  // Label del rango activo
  const dateLabel = useMemo(() => {
    if (calendarView === "day") {
      return calendarDate.toLocaleDateString("es", { weekday: "long", day: "2-digit", month: "long" });
    }
    if (calendarView === "week") {
      const monday = startOfWeek(calendarDate);
      const sunday = new Date(monday);
      sunday.setDate(sunday.getDate() + 6);
      return `${monday.getDate().toString().padStart(2, "0")} ${monday.toLocaleDateString("es", { month: "short" })} – ${sunday.getDate().toString().padStart(2, "0")} ${sunday.toLocaleDateString("es", { month: "short" })}`;
    }
    return calendarDate.toLocaleDateString("es", { month: "long", year: "numeric" });
  }, [calendarDate, calendarView]);

  // Categorías y unidades de insumos veterinarios (distintas a las de grooming)
  const categories = ["Medicamento", "Descartable", "Vacuna", "Otro"];
  const units = ["ml", "mg", "vial", "dosis", "unidad", "par", "comp."];

  // Servicios de veterinaria
  const vetServices = useMemo(
    () => services.filter(s => s.module === "vet"),
    [services]
  );

  // Si no es super, mostrar pantalla bloqueada (defensa en profundidad)
  if (!isAdmin) {
    return (
      <div className="bg-white border border-stone-200 rounded-2xl shadow-sm p-12 text-center">
        <Shield size={32} className="text-stone-300 mx-auto mb-3" />
        <div className="text-base font-semibold text-stone-700">Acceso restringido</div>
        <div className="text-sm text-stone-500 mt-1">Solo el super usuario puede gestionar el catálogo veterinario.</div>
      </div>
    );
  }

  const iconForVetSupply = (category) => {
    if (category === "Medicamento") return Pill;
    if (category === "Vacuna") return Syringe;
    if (category === "Descartable") return Package;
    return Box;
  };

  return (
    <div className="space-y-4">
      {/* Header con stats */}
      <div className="bg-gradient-to-br from-white via-stone-50 to-orange-50 border border-stone-200 rounded-2xl p-5">
        <div className="flex items-start gap-4 flex-wrap">
          <div className="w-12 h-12 rounded-xl bg-orange-500 text-white grid place-items-center shadow-lg flex-shrink-0">
            <Stethoscope size={20} strokeWidth={1.8} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold">
              Consultorio veterinario · administración
            </div>
            <h2 className="font-serif text-2xl font-semibold leading-tight">
              <span className="text-orange-700">{vetEventsState.length}</span> citas veterinarias
            </h2>
            <p className="text-sm text-stone-600 mt-1">
              Calendario unificado de consultas y cirugías · gestión del catálogo clínico y stock médico.
            </p>
          </div>
        </div>
      </div>

      {/* Toolbar calendario (igual que Catálogo Grooming) */}
      <div className="bg-white border border-stone-200 rounded-2xl shadow-sm p-3 flex items-center gap-2 flex-wrap">
        {/* Navegación */}
        <div className="flex items-center gap-1">
          <button onClick={navigatePrev} className="w-9 h-9 rounded-lg bg-stone-50 hover:bg-stone-100 grid place-items-center text-stone-600">
            <ChevronLeft size={15} />
          </button>
          <button onClick={goToToday} className="px-3 h-9 rounded-lg bg-orange-50 hover:bg-orange-100 text-xs font-semibold text-orange-700 border border-orange-200">
            Hoy
          </button>
          <button onClick={navigateNext} className="w-9 h-9 rounded-lg bg-stone-50 hover:bg-stone-100 grid place-items-center text-stone-600">
            <ChevronRight size={15} />
          </button>
        </div>
        <h3 className="font-serif text-lg font-semibold flex-1 min-w-0 capitalize px-2 truncate">
          {dateLabel}
        </h3>
        {/* Switcher día/semana/mes */}
        <div className="bg-stone-100 rounded-xl p-1 flex gap-1">
          {[
            { id: "day", label: "Día", Icon: Calendar },
            { id: "week", label: "Semana", Icon: Calendar },
            { id: "month", label: "Mes", Icon: LayoutGrid },
          ].map(v => {
            const Ic = v.Icon;
            return (
              <button
                key={v.id}
                onClick={() => setCalendarView(v.id)}
                className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-semibold transition ${
                  calendarView === v.id
                    ? "bg-white text-stone-900 shadow"
                    : "text-stone-600 hover:text-stone-900"
                }`}
              >
                <Ic size={11} /> {v.label}
              </button>
            );
          })}
        </div>
      </div>

      {/* Layout: calendario + panel catálogo lateral */}
      <div className="flex flex-col lg:flex-row gap-4">
        {/* Calendario */}
        <div className="flex-1 min-w-0">
          {calendarView === "day" && (
            <AgendaDay date={calendarDate} eventsByDate={eventsByDate} onSelectEvent={setSelectedVetEventId} />
          )}
          {calendarView === "week" && (
            <AgendaWeek date={calendarDate} eventsByDate={eventsByDate} onJumpToDay={jumpToCalendarDay} onSelectEvent={setSelectedVetEventId} onMoveEvent={handleMoveVetEvent} />
          )}
          {calendarView === "month" && (
            <AgendaMonth date={calendarDate} eventsByDate={eventsByDate} onJumpToDay={jumpToCalendarDay} onSelectEvent={setSelectedVetEventId} />
          )}
        </div>

        {/* Panel lateral: catálogo (servicios + insumos) */}
        <div className="bg-white border border-stone-200 rounded-2xl shadow-sm w-full lg:w-80 flex-shrink-0 self-start overflow-hidden">
          <div className="p-4 border-b border-stone-200">
            <div className="flex items-center justify-between gap-2">
              <div className="min-w-0">
                <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold">Catálogo</div>
                <h3 className="font-serif text-xl font-semibold leading-tight">
                  {section === "services" ? "Servicios clínicos" : "Insumos médicos"}
                </h3>
              </div>
              <span className="text-xs font-bold px-2 py-0.5 rounded-full bg-orange-100 text-orange-700 inline-flex items-center gap-1 flex-shrink-0">
                <Edit3 size={9} /> Editable
              </span>
            </div>

            {/* Sub-tabs servicios/insumos */}
            <div className="mt-3 bg-stone-100 rounded-lg p-0.5 flex gap-0.5">
              <button
                onClick={() => setSection("services")}
                className={`flex-1 flex items-center justify-center gap-1.5 px-2 py-1.5 rounded text-xs font-semibold transition ${
                  section === "services" ? "bg-white text-stone-900 shadow" : "text-stone-600 hover:text-stone-900"
                }`}
              >
                <Stethoscope size={11} /> Servicios ({vetServices.length})
              </button>
              <button
                onClick={() => setSection("supplies")}
                className={`flex-1 flex items-center justify-center gap-1.5 px-2 py-1.5 rounded text-xs font-semibold transition ${
                  section === "supplies" ? "bg-white text-stone-900 shadow" : "text-stone-600 hover:text-stone-900"
                }`}
              >
                <Pill size={11} /> Insumos ({vetSupplies.length})
              </button>
            </div>
          </div>

          {/* Body con scroll si crece */}
          <div className="max-h-screen overflow-y-auto">

      {/* === SERVICIOS === */}
      {section === "services" && (
        <div className="p-4 space-y-2">
          <button
            onClick={() => { setServiceDraft(serviceDraftBlank); setCreatingService(true); }}
            className="w-full flex items-center justify-center gap-1.5 px-2.5 py-2 rounded-xl bg-orange-500 hover:bg-orange-600 text-white text-xs font-semibold shadow transition"
          >
            <Plus size={11} /> Agregar servicio
          </button>

          {vetServices.length === 0 && (
            <div className="text-center py-6 text-sm text-stone-500">
              Sin servicios veterinarios aún.
            </div>
          )}

          {vetServices.map(svc => {
            const isInactive = svc.active === false;
            return (
              <div key={svc.id} className={`flex items-center gap-2 p-3 border rounded-xl transition ${
                isInactive ? "bg-stone-50 border-stone-200 opacity-60" : "bg-stone-50 hover:bg-orange-50 border-stone-200 hover:border-orange-300"
              }`}>
                <div className={`w-9 h-9 rounded-xl grid place-items-center flex-shrink-0 ${
                  isInactive ? "bg-stone-100 text-stone-400 border border-stone-200" : "bg-white border border-orange-200 text-orange-700"
                }`}>
                  <Stethoscope size={15} strokeWidth={1.8} />
                </div>
                <div className="flex-1 min-w-0">
                  <div className="font-semibold text-sm flex items-center gap-1.5">
                    <span className="truncate">{svc.name}</span>
                    {isInactive && <span className="text-xs px-1.5 py-px rounded bg-stone-200 text-stone-600">Inactivo</span>}
                  </div>
                  <div className="text-xs text-stone-400 mt-0.5">
                    {svc.duration ? `${svc.duration} min` : "—"}
                  </div>
                </div>
                <div className="text-right flex-shrink-0">
                  <div className="text-xs text-stone-400 leading-none">Precio</div>
                  <div className="font-serif text-base font-semibold text-orange-700">${svc.price}</div>
                </div>
                <div className="flex gap-0.5 flex-shrink-0">
                  <button onClick={() => setEditingService(svc.id)} title="Editar" className="w-7 h-7 rounded-lg bg-white border border-stone-200 hover:border-orange-400 grid place-items-center text-stone-600 hover:text-orange-700 transition">
                    <Edit3 size={11} />
                  </button>
                  <button onClick={() => setServices(prev => prev.map(x => x.id === svc.id ? { ...x, active: isInactive ? true : false } : x))} title={isInactive ? "Activar" : "Desactivar"} className="w-7 h-7 rounded-lg bg-white border border-stone-200 hover:border-amber-400 grid place-items-center text-stone-600 hover:text-amber-700 transition">
                    {isInactive ? <Eye size={11} /> : <EyeOff size={11} />}
                  </button>
                  <button onClick={() => setConfirmDeleteService(svc.id)} title="Eliminar" className="w-7 h-7 rounded-lg bg-white border border-stone-200 hover:border-red-400 grid place-items-center text-stone-600 hover:text-red-700 transition">
                    <Trash2 size={11} />
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* === INSUMOS === */}
      {section === "supplies" && (
        <div className="p-4 space-y-2">
          <button
            onClick={() => { setSupplyDraft(supplyDraftBlank); setEditingSupply("new"); }}
            className="w-full flex items-center justify-center gap-1.5 px-2.5 py-2 rounded-xl bg-emerald-500 hover:bg-emerald-600 text-white text-xs font-semibold shadow transition"
          >
            <Plus size={11} /> Agregar insumo
          </button>

          {vetSupplies.length === 0 && (
            <div className="text-center py-6 text-sm text-stone-500">
              Sin insumos médicos.
            </div>
          )}

          {categories.map(cat => {
            const list = vetSupplies.filter(s => (s.category || "Otro") === cat);
            if (list.length === 0) return null;
            const Icon = iconForVetSupply(cat);
            return (
              <div key={cat}>
                <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold mt-3 mb-1.5 px-1 flex items-center gap-1.5">
                  <Icon size={11} /> {cat}
                </div>
                <div className="space-y-1.5">
                  {list.map(s => {
                    const isInactive = s.active === false;
                    return (
                      <div key={s.id} className={`flex items-center gap-2 p-2.5 border rounded-xl transition ${
                        isInactive ? "bg-stone-50 border-stone-200 opacity-60" : "bg-stone-50 border-stone-200 hover:border-emerald-300"
                      }`}>
                        <div className={`w-8 h-8 rounded-lg grid place-items-center flex-shrink-0 ${
                          isInactive ? "bg-stone-100 text-stone-400" : "bg-emerald-50 text-emerald-700 border border-emerald-200"
                        }`}>
                          <Icon size={13} strokeWidth={1.8} />
                        </div>
                        <div className="flex-1 min-w-0">
                          <div className="font-semibold text-xs truncate">{s.name}</div>
                          <div className="text-xs text-stone-400 mt-0.5">
                            {s.defaultQty} {s.unit}
                          </div>
                        </div>
                        <div className="text-right flex-shrink-0">
                          <div className="font-serif text-sm font-semibold text-orange-700">${s.price}</div>
                        </div>
                        <div className="flex gap-0.5 flex-shrink-0">
                          <button onClick={() => { setSupplyDraft({ ...s }); setEditingSupply(s.id); }} title="Editar" className="w-7 h-7 rounded-lg bg-white border border-stone-200 hover:border-orange-400 grid place-items-center text-stone-600 hover:text-orange-700 transition">
                            <Edit3 size={10} />
                          </button>
                          <button onClick={() => setVetSupplies(prev => prev.map(x => x.id === s.id ? { ...x, active: isInactive ? true : false } : x))} title={isInactive ? "Activar" : "Desactivar"} className="w-7 h-7 rounded-lg bg-white border border-stone-200 hover:border-amber-400 grid place-items-center text-stone-600 hover:text-amber-700 transition">
                            {isInactive ? <Eye size={10} /> : <EyeOff size={10} />}
                          </button>
                          <button onClick={() => setConfirmDeleteSupply(s.id)} title="Eliminar" className="w-7 h-7 rounded-lg bg-white border border-stone-200 hover:border-red-400 grid place-items-center text-stone-600 hover:text-red-700 transition">
                            <Trash2 size={10} />
                          </button>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            );
          })}
        </div>
      )}
          </div>
        </div>
      </div>

      {/* === MODALES === */}

      {/* MODAL: Crear servicio */}
      {creatingService && (
        <div onClick={() => setCreatingService(false)} className="fixed inset-0 bg-stone-900 z-50 flex justify-center items-center p-4">
          <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl w-full max-w-sm shadow-2xl overflow-hidden">
            <div className="p-4 border-b border-stone-200 bg-orange-50 flex items-center gap-3">
              <div className="w-10 h-10 rounded-xl bg-orange-500 text-white grid place-items-center shadow-lg flex-shrink-0">
                <Plus size={17} strokeWidth={2.2} />
              </div>
              <div className="flex-1 min-w-0">
                <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold">Nuevo servicio veterinario</div>
                <h3 className="font-serif text-lg font-semibold mt-0.5 truncate">{serviceDraft.name || "Sin nombre"}</h3>
              </div>
            </div>
            <div className="p-5 space-y-3">
              <div>
                <label className="text-xs font-semibold text-stone-700 block mb-1.5">Nombre <span className="text-red-500">*</span></label>
                <input
                  value={serviceDraft.name}
                  onChange={(e) => setServiceDraft({ ...serviceDraft, name: e.target.value })}
                  placeholder="Ej: Consulta general"
                  autoFocus
                  className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
                />
              </div>
              <div className="grid grid-cols-2 gap-2">
                <div>
                  <label className="text-xs font-semibold text-stone-700 block mb-1.5">Precio ($)</label>
                  <input type="number" min="0" step="0.01" value={serviceDraft.price} onChange={(e) => setServiceDraft({ ...serviceDraft, price: e.target.value })} className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500 font-mono" />
                </div>
                <div>
                  <label className="text-xs font-semibold text-stone-700 block mb-1.5">Duración (min)</label>
                  <input type="number" min="0" value={serviceDraft.duration} onChange={(e) => setServiceDraft({ ...serviceDraft, duration: e.target.value })} className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500 font-mono" />
                </div>
              </div>
              <div>
                <label className="text-xs font-semibold text-stone-700 block mb-1.5">Descripción</label>
                <textarea value={serviceDraft.description} onChange={(e) => setServiceDraft({ ...serviceDraft, description: e.target.value })} rows={2} placeholder="Qué incluye el servicio" className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500 resize-none" />
              </div>
            </div>
            <div className="p-3 border-t border-stone-200 bg-stone-50 flex gap-2">
              <button onClick={() => setCreatingService(false)} className="flex-1 px-3 py-2 rounded-xl text-sm font-semibold bg-white border border-stone-200 hover:border-stone-400 text-stone-700">Cancelar</button>
              <button
                onClick={() => {
                  if (!serviceDraft.name.trim()) return;
                  setServices(prev => [...prev, {
                    id: `svc-${Date.now().toString(36)}`,
                    name: serviceDraft.name.trim(),
                    price: Number(serviceDraft.price) || 0,
                    duration: Number(serviceDraft.duration) || 0,
                    description: serviceDraft.description.trim(),
                    module: "vet",
                    active: true,
                  }]);
                  setCreatingService(false);
                }}
                disabled={!serviceDraft.name.trim()}
                className={`flex-1 px-3 py-2 rounded-xl text-sm font-semibold transition shadow ${
                  serviceDraft.name.trim() ? "bg-orange-600 hover:bg-orange-700 text-white" : "bg-stone-200 text-stone-400 cursor-not-allowed"
                }`}
              >
                <Check size={13} className="inline" strokeWidth={2.5} /> Crear
              </button>
            </div>
          </div>
        </div>
      )}

      {/* MODAL: Editar servicio */}
      {editingService && (() => {
        const svc = services.find(s => s.id === editingService);
        if (!svc) return null;
        return (
          <div onClick={() => setEditingService(null)} className="fixed inset-0 bg-stone-900 z-50 flex justify-center items-center p-4">
            <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl w-full max-w-sm shadow-2xl overflow-hidden">
              <div className="p-4 border-b border-stone-200 bg-orange-50 flex items-center gap-3">
                <div className="w-10 h-10 rounded-xl bg-orange-500 text-white grid place-items-center shadow-lg flex-shrink-0">
                  <Edit3 size={16} />
                </div>
                <div className="flex-1 min-w-0">
                  <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold">Editar servicio</div>
                  <h3 className="font-serif text-lg font-semibold mt-0.5 truncate">{svc.name}</h3>
                </div>
              </div>
              <div className="p-5 space-y-3">
                <div>
                  <label className="text-xs font-semibold text-stone-700 block mb-1.5">Nombre</label>
                  <input value={svc.name} onChange={(e) => setServices(prev => prev.map(s => s.id === svc.id ? { ...s, name: e.target.value } : s))} className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500" />
                </div>
                <div className="grid grid-cols-2 gap-2">
                  <div>
                    <label className="text-xs font-semibold text-stone-700 block mb-1.5">Precio ($)</label>
                    <input type="number" min="0" step="0.01" value={svc.price} onChange={(e) => setServices(prev => prev.map(s => s.id === svc.id ? { ...s, price: Number(e.target.value) || 0 } : s))} className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500 font-mono" />
                  </div>
                  <div>
                    <label className="text-xs font-semibold text-stone-700 block mb-1.5">Duración (min)</label>
                    <input type="number" min="0" value={svc.duration || 0} onChange={(e) => setServices(prev => prev.map(s => s.id === svc.id ? { ...s, duration: Number(e.target.value) || 0 } : s))} className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500 font-mono" />
                  </div>
                </div>
                <div>
                  <label className="text-xs font-semibold text-stone-700 block mb-1.5">Descripción</label>
                  <textarea value={svc.description || ""} onChange={(e) => setServices(prev => prev.map(s => s.id === svc.id ? { ...s, description: e.target.value } : s))} rows={2} className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500 resize-none" />
                </div>
              </div>
              <div className="p-3 border-t border-stone-200 bg-stone-50 flex justify-end">
                <button onClick={() => setEditingService(null)} className="px-4 py-2 rounded-xl text-sm font-semibold bg-orange-600 hover:bg-orange-700 text-white shadow">
                  <Check size={13} className="inline" strokeWidth={2.5} /> Listo
                </button>
              </div>
            </div>
          </div>
        );
      })()}

      {/* MODAL: Editar/crear insumo */}
      {editingSupply && (
        <div onClick={() => setEditingSupply(null)} className="fixed inset-0 bg-stone-900 z-50 flex justify-center items-center p-4">
          <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden">
            <div className="p-4 border-b border-stone-200 bg-emerald-50 flex items-center gap-3">
              <div className="w-10 h-10 rounded-xl bg-emerald-500 text-white grid place-items-center shadow-lg flex-shrink-0">
                <Pill size={17} />
              </div>
              <div className="flex-1 min-w-0">
                <div className="text-xs tracking-widest uppercase text-emerald-700 font-semibold">
                  {editingSupply === "new" ? "Nuevo insumo médico" : "Editar insumo"}
                </div>
                <h3 className="font-serif text-lg font-semibold mt-0.5 truncate">{supplyDraft.name || "Sin nombre"}</h3>
              </div>
            </div>
            <div className="p-5 space-y-3">
              <div>
                <label className="text-xs font-semibold text-stone-700 block mb-1.5">Nombre <span className="text-red-500">*</span></label>
                <input value={supplyDraft.name} onChange={(e) => setSupplyDraft({ ...supplyDraft, name: e.target.value })} placeholder="Ej: Tramadol 50mg/ml" autoFocus className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-emerald-500" />
              </div>
              <div className="grid grid-cols-2 gap-2">
                <div>
                  <label className="text-xs font-semibold text-stone-700 block mb-1.5">Categoría</label>
                  <select value={supplyDraft.category} onChange={(e) => setSupplyDraft({ ...supplyDraft, category: e.target.value })} className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-emerald-500">
                    {categories.map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                </div>
                <div>
                  <label className="text-xs font-semibold text-stone-700 block mb-1.5">Unidad</label>
                  <select value={supplyDraft.unit} onChange={(e) => setSupplyDraft({ ...supplyDraft, unit: e.target.value })} className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-emerald-500">
                    {units.map(u => <option key={u} value={u}>{u}</option>)}
                  </select>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-2">
                <div>
                  <label className="text-xs font-semibold text-stone-700 block mb-1.5">Cant. por defecto</label>
                  <input type="number" min="0" step="0.5" value={supplyDraft.defaultQty} onChange={(e) => setSupplyDraft({ ...supplyDraft, defaultQty: e.target.value })} className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-emerald-500 font-mono" />
                </div>
                <div>
                  <label className="text-xs font-semibold text-stone-700 block mb-1.5">Precio ($)</label>
                  <input type="number" min="0" step="0.01" value={supplyDraft.price} onChange={(e) => setSupplyDraft({ ...supplyDraft, price: e.target.value })} className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-emerald-500 font-mono" />
                </div>
              </div>
              <div className="bg-stone-50 border border-stone-200 rounded-xl p-2.5 text-xs text-stone-600 flex items-start gap-2">
                <Info size={11} className="text-stone-500 flex-shrink-0 mt-0.5" />
                <span>El precio corresponde a la cantidad por defecto. Para medicamentos, suele ser el costo del vial completo o por dosis estándar.</span>
              </div>
            </div>
            <div className="p-3 border-t border-stone-200 bg-stone-50 flex gap-2">
              <button onClick={() => setEditingSupply(null)} className="flex-1 px-3 py-2 rounded-xl text-sm font-semibold bg-white border border-stone-200 hover:border-stone-400 text-stone-700">Cancelar</button>
              <button
                onClick={() => {
                  if (!supplyDraft.name.trim()) return;
                  const cleaned = {
                    ...supplyDraft,
                    defaultQty: Number(supplyDraft.defaultQty) || 1,
                    price: Number(supplyDraft.price) || 0,
                  };
                  if (editingSupply === "new") {
                    setVetSupplies(prev => [...prev, { ...cleaned, id: `vs-${Date.now().toString(36)}` }]);
                  } else {
                    setVetSupplies(prev => prev.map(s => s.id === editingSupply ? { ...s, ...cleaned } : s));
                  }
                  setEditingSupply(null);
                }}
                disabled={!supplyDraft.name.trim()}
                className={`flex-1 px-3 py-2 rounded-xl text-sm font-semibold transition shadow ${
                  supplyDraft.name.trim() ? "bg-emerald-500 hover:bg-emerald-600 text-white" : "bg-stone-200 text-stone-400 cursor-not-allowed"
                }`}
              >
                <Check size={13} className="inline" strokeWidth={2.5} />
                {editingSupply === "new" ? " Crear" : " Guardar"}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Confirmaciones */}
      {confirmDeleteService && (() => {
        const svc = services.find(s => s.id === confirmDeleteService);
        if (!svc) return null;
        return (
          <div onClick={() => setConfirmDeleteService(null)} className="fixed inset-0 bg-stone-900 z-50 flex justify-center items-center p-4">
            <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl w-full max-w-sm shadow-2xl overflow-hidden">
              <div className="p-4 border-b border-red-200 bg-red-50 flex items-center gap-3">
                <div className="w-10 h-10 rounded-xl bg-red-500 text-white grid place-items-center shadow-lg flex-shrink-0">
                  <AlertTriangle size={17} />
                </div>
                <div className="flex-1 min-w-0">
                  <div className="text-xs tracking-widest uppercase text-red-700 font-bold">Eliminar servicio</div>
                  <h3 className="font-serif text-lg font-semibold mt-0.5 truncate">{svc.name}</h3>
                </div>
              </div>
              <div className="p-5 text-sm text-stone-700 leading-relaxed space-y-3">
                <p>Esto removerá <strong>"{svc.name}"</strong> del catálogo. El historial de consultas y recibos que lo mencionan no se modifica.</p>
                <div className="bg-amber-50 border border-amber-200 rounded-xl p-2.5 text-xs text-amber-900 flex items-start gap-2">
                  <Info size={11} className="text-amber-700 flex-shrink-0 mt-0.5" />
                  <span>Si solo quieres dejar de ofrecerlo pero conservar el historial, usa <strong>Desactivar</strong>.</span>
                </div>
              </div>
              <div className="p-3 border-t border-stone-200 bg-stone-50 flex gap-2">
                <button onClick={() => setConfirmDeleteService(null)} className="flex-1 px-3 py-2 rounded-xl text-sm font-semibold bg-white border border-stone-200 hover:border-stone-400 text-stone-700">Cancelar</button>
                <button onClick={() => { setServices(prev => prev.filter(x => x.id !== confirmDeleteService)); setConfirmDeleteService(null); }} className="flex-1 px-3 py-2 rounded-xl text-sm font-semibold bg-red-500 hover:bg-red-600 text-white shadow">
                  <Trash2 size={11} className="inline" /> Eliminar
                </button>
              </div>
            </div>
          </div>
        );
      })()}

      {confirmDeleteSupply && (() => {
        const sup = vetSupplies.find(s => s.id === confirmDeleteSupply);
        if (!sup) return null;
        return (
          <div onClick={() => setConfirmDeleteSupply(null)} className="fixed inset-0 bg-stone-900 z-50 flex justify-center items-center p-4">
            <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl w-full max-w-sm shadow-2xl overflow-hidden">
              <div className="p-4 border-b border-red-200 bg-red-50 flex items-center gap-3">
                <div className="w-10 h-10 rounded-xl bg-red-500 text-white grid place-items-center shadow-lg flex-shrink-0">
                  <AlertTriangle size={17} />
                </div>
                <div className="flex-1 min-w-0">
                  <div className="text-xs tracking-widest uppercase text-red-700 font-bold">Eliminar insumo</div>
                  <h3 className="font-serif text-lg font-semibold mt-0.5 truncate">{sup.name}</h3>
                </div>
              </div>
              <div className="p-5 text-sm text-stone-700 leading-relaxed space-y-3">
                <p>Esto removerá <strong>"{sup.name}"</strong> del catálogo de insumos médicos. Las recetas e historiales que lo mencionan permanecen intactos.</p>
                <div className="bg-amber-50 border border-amber-200 rounded-xl p-2.5 text-xs text-amber-900 flex items-start gap-2">
                  <Info size={11} className="text-amber-700 flex-shrink-0 mt-0.5" />
                  <span>Si solo quieres ocultarlo de las nuevas consultas pero conservarlo, usa <strong>Desactivar</strong>.</span>
                </div>
              </div>
              <div className="p-3 border-t border-stone-200 bg-stone-50 flex gap-2">
                <button onClick={() => setConfirmDeleteSupply(null)} className="flex-1 px-3 py-2 rounded-xl text-sm font-semibold bg-white border border-stone-200 hover:border-stone-400 text-stone-700">Cancelar</button>
                <button onClick={() => { setVetSupplies(prev => prev.filter(x => x.id !== confirmDeleteSupply)); setConfirmDeleteSupply(null); }} className="flex-1 px-3 py-2 rounded-xl text-sm font-semibold bg-red-500 hover:bg-red-600 text-white shadow">
                  <Trash2 size={11} className="inline" /> Eliminar
                </button>
              </div>
            </div>
          </div>
        );
      })()}

      {/* Drawer de detalle de cita: aparece al hacer click en una card del calendario */}
      {selectedVetEventId && (() => {
        const ev = vetEventsState.find(e => e.id === selectedVetEventId);
        if (!ev) return null;
        return (
          <EventDetailDrawer
            event={ev}
            onClose={() => setSelectedVetEventId(null)}
            onAssignVet={handleAssignVetToEvent}
            onDelete={handleDeleteVetEvent}
            onReschedule={handleRescheduleVet}
            onOpenPassport={() => {}}
          />
        );
      })()}
    </div>
  );
}

// ========== VISTA: ACTUALIZACIÓN DE PASAPORTES ==========
// Layout 2 columnas:
//  - Izquierda: buscador por código → formulario edición → enviar a cola
//  - Derecha: cola paginada de cambios pendientes (todos ven; super aprueba)
function PassportUpdatesView({ passports, setPassports, petUpdates, setPetUpdates, userRole, userName, embedded = false }) {
  const isAdmin = userRole === "super";
  // Solo super y sales pueden ver/editar microchip y tutores (datos sensibles del cliente).
  // Vet, grooming y otros roles ven todo el resto pero no esos dos bloques.
  const canEditSensitive = userRole === "super" || userRole === "sales";
  const [searchCode, setSearchCode] = useState("");
  const [foundPet, setFoundPet] = useState(null);
  const [draft, setDraft] = useState(null); // patch en construcción
  const [editingUpdateId, setEditingUpdateId] = useState(null); // para reenvío

  // Paginación de cola
  const [page, setPage] = useState(0);
  const PAGE_SIZE = 5;

  const speciesOpts = [
    { id: "dog", label: "Perro", Icon: Dog },
    { id: "cat", label: "Gato", Icon: Cat },
    { id: "bird", label: "Ave", Icon: Bird },
    { id: "rabbit", label: "Conejo", Icon: Rabbit },
    { id: "rodent", label: "Roedor", Icon: Rat },
    { id: "fish", label: "Pez", Icon: Fish },
    { id: "other", label: "Otros", Icon: PawPrint },
  ];

  const handleSearch = () => {
    const code = searchCode.replace(/\D/g, "").trim();
    if (!code) {
      setFoundPet(null);
      return;
    }
    const p = passports.find(x => x.code === code);
    if (p) {
      setFoundPet(p);
      // Inicializar draft con datos actuales (solo campos no-clínicos)
      setDraft({
        name: p.name,
        species: p.species,
        breed: p.breed,
        color: p.color || "",
        weight: p.weight || "",
        gender: p.gender || "",
        sterilized: p.sterilized || false,
        microchip: p.microchip || "",
        birthdate: p.birthdate || "",
        photo: p.photo || null,
        // Clonado profundo de tutores para edición independiente
        tutors: (p.tutors || []).map(t => ({ ...t })),
      });
      setEditingUpdateId(null);
    } else {
      setFoundPet(null);
      setDraft(null);
    }
  };

  // Abrir un cambio pendiente para editarlo (su autor o el super)
  const loadUpdateForEdit = (update) => {
    const p = passports.find(x => x.id === update.passportId);
    if (!p) return;
    setFoundPet(p);
    setSearchCode(p.code);
    // Si el usuario no puede editar campos sensibles, descartamos los cambios en
    // microchip/tutores del proposed y dejamos los del pasaporte original.
    // Esto preserva los cambios buenos sin exponer ni permitir tocar los sensibles.
    if (canEditSensitive) {
      setDraft({ ...update.proposed });
    } else {
      setDraft({
        ...update.proposed,
        microchip: p.microchip || "",
        tutors: (p.tutors || []).map(t => ({ ...t })),
      });
    }
    setEditingUpdateId(update.id);
    setPage(0);
  };

  // Detectar campos que cambiaron respecto al pasaporte actual
  const changedFields = useMemo(() => {
    if (!foundPet || !draft) return [];
    const fields = [
      { key: "name", label: "Nombre" },
      { key: "species", label: "Especie" },
      { key: "breed", label: "Raza" },
      { key: "color", label: "Color" },
      { key: "weight", label: "Peso" },
      { key: "gender", label: "Género" },
      { key: "sterilized", label: "Esterilizado" },
      { key: "microchip", label: "Microchip" },
      { key: "birthdate", label: "Fecha de nacimiento" },
      { key: "photo", label: "Foto" },
    ];
    const result = fields.filter(f => {
      const cur = foundPet[f.key] ?? (f.key === "sterilized" ? false : "");
      const next = draft[f.key] ?? (f.key === "sterilized" ? false : "");
      return cur !== next;
    });
    // Detectar cambios en tutores (comparación profunda básica)
    const curTutors = JSON.stringify(foundPet.tutors || []);
    const nextTutors = JSON.stringify(draft.tutors || []);
    if (curTutors !== nextTutors) {
      result.push({ key: "tutors", label: "Tutores" });
    }
    return result;
  }, [foundPet, draft]);

  const submitUpdate = () => {
    if (!foundPet || !draft || changedFields.length === 0) return;

    if (editingUpdateId) {
      // Reenviar: mantener id, actualizar payload, volver a "pending"
      setPetUpdates(prev => prev.map(u => u.id === editingUpdateId ? {
        ...u,
        proposed: { ...draft },
        changedFields: changedFields.map(f => f.key),
        status: "pending",
        resubmittedAt: new Date().toISOString(),
        resubmittedBy: userName || userRole,
      } : u));
    } else {
      // Crear nueva propuesta
      const newUpdate = {
        id: `upd-${Date.now().toString(36)}`,
        passportId: foundPet.id,
        passportCode: foundPet.code,
        passportName: foundPet.name,
        proposed: { ...draft },
        changedFields: changedFields.map(f => f.key),
        status: "pending",
        submittedBy: userName || userRole,
        submittedAt: new Date().toISOString(),
      };
      setPetUpdates(prev => [newUpdate, ...prev]);
    }
    // Reset
    setFoundPet(null);
    setDraft(null);
    setSearchCode("");
    setEditingUpdateId(null);
  };

  const approveUpdate = (updateId) => {
    const upd = petUpdates.find(u => u.id === updateId);
    if (!upd) return;
    // Aplicar cambios al pasaporte
    setPassports(prev => prev.map(p => p.id === upd.passportId ? { ...p, ...upd.proposed } : p));
    // Marcar como aprobado
    setPetUpdates(prev => prev.map(u => u.id === updateId ? {
      ...u,
      status: "approved",
      approvedBy: userName || userRole,
      approvedAt: new Date().toISOString(),
    } : u));
  };

  const rejectUpdate = (updateId) => {
    setPetUpdates(prev => prev.map(u => u.id === updateId ? {
      ...u,
      status: "rejected",
      rejectedBy: userName || userRole,
      rejectedAt: new Date().toISOString(),
    } : u));
  };

  const cancelUpdate = (updateId) => {
    setPetUpdates(prev => prev.filter(u => u.id !== updateId));
  };

  // Cola visible: pendientes primero, luego recientes
  // Si el usuario NO puede editar campos sensibles (microchip/tutores),
  // ocultamos las propuestas que SOLO modifican esos campos — no son asunto suyo.
  const sortedUpdates = useMemo(() => {
    const SENSITIVE_KEYS = new Set(["microchip", "tutors"]);
    const filtered = canEditSensitive
      ? petUpdates
      : petUpdates.filter(u => {
          const fields = u.changedFields || [];
          // Mostrar solo si tiene al menos un campo NO sensible
          return fields.some(f => !SENSITIVE_KEYS.has(f));
        });
    return [...filtered].sort((a, b) => {
      const order = { pending: 0, approved: 1, rejected: 2 };
      const oa = order[a.status] ?? 3;
      const ob = order[b.status] ?? 3;
      if (oa !== ob) return oa - ob;
      return new Date(b.submittedAt).getTime() - new Date(a.submittedAt).getTime();
    });
  }, [petUpdates, canEditSensitive]);

  const pagedUpdates = sortedUpdates.slice(page * PAGE_SIZE, (page + 1) * PAGE_SIZE);
  const totalPages = Math.ceil(sortedUpdates.length / PAGE_SIZE);
  const pendingCount = petUpdates.filter(u => u.status === "pending").length;

  // Formato fecha relativa
  const fmtDate = (iso) => {
    if (!iso) return "";
    const d = new Date(iso);
    return d.toLocaleString("es", { day: "2-digit", month: "short", hour: "2-digit", minute: "2-digit" });
  };

  return (
    <div className="space-y-4">
      {/* Header — se oculta cuando la vista está embebida dentro del tab "Actualizaciones"
          de Clientes, porque el contexto ya lo da el tab activo. */}
      {!embedded && (
      <div className="bg-gradient-to-br from-white via-stone-50 to-orange-50 border border-stone-200 rounded-2xl p-5">
        <div className="flex items-start gap-4 flex-wrap">
          <div className="w-12 h-12 rounded-xl bg-orange-500 text-white grid place-items-center shadow-lg flex-shrink-0">
            <History size={20} strokeWidth={1.8} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold">
              Mantenimiento · información básica
            </div>
            <h2 className="font-serif text-2xl font-semibold leading-tight">
              Actualizar <span className="italic text-orange-700">pasaporte</span>
            </h2>
            <p className="text-sm text-stone-600 mt-1">
              Busca un pasaporte por código y propón cambios a la información básica. Los cambios pasan por una cola que el super usuario aprueba.
            </p>
          </div>
          {pendingCount > 0 && (
            <div className="text-right">
              <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold">Pendientes</div>
              <div className="font-serif text-3xl font-bold text-orange-700">{pendingCount}</div>
            </div>
          )}
        </div>
      </div>
      )}

      {/* Layout 2 columnas */}
      <div className="flex flex-col lg:flex-row gap-4">
        {/* === IZQ: buscador + editor === */}
        <div className="flex-1 min-w-0 bg-white border border-stone-200 rounded-2xl shadow-sm overflow-hidden">
          <div className="p-4 border-b border-stone-200 bg-stone-50">
            <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold mb-2">
              Buscar pasaporte
            </div>
            <div className="flex gap-2">
              <div className="relative flex-1">
                <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-stone-400" />
                <input
                  value={searchCode}
                  onChange={(e) => setSearchCode(e.target.value)}
                  onKeyDown={(e) => { if (e.key === "Enter") handleSearch(); }}
                  placeholder="Código de 6 dígitos (ej: 178805)"
                  className="w-full pl-9 pr-3 py-2.5 bg-white border border-stone-200 rounded-xl text-sm font-mono outline-none focus:border-orange-500"
                />
              </div>
              <button
                onClick={handleSearch}
                className="px-4 py-2.5 rounded-xl bg-stone-900 hover:bg-stone-800 text-white text-sm font-semibold transition"
              >
                Buscar
              </button>
            </div>
            {searchCode && !foundPet && searchCode.replace(/\D/g, "").length >= 1 && (
              <div className="text-xs text-red-600 mt-2 flex items-center gap-1.5">
                <AlertTriangle size={11} />
                Sin resultados. Verifica el código.
              </div>
            )}
          </div>

          {/* Formulario de edición */}
          {foundPet && draft ? (
            <div className="p-4 space-y-3">
              {editingUpdateId && (
                <div className="bg-amber-50 border border-amber-200 rounded-xl p-3 text-xs text-amber-900 flex items-start gap-2">
                  <Edit3 size={12} className="text-amber-700 flex-shrink-0 mt-0.5" />
                  <div>
                    <strong>Editando una propuesta existente.</strong> Al guardar volverá a entrar en cola como pendiente.
                  </div>
                </div>
              )}

              {/* Cabecera del pasaporte encontrado */}
              <div className="bg-stone-50 border border-stone-200 rounded-xl p-3 flex items-center gap-3">
                <div className="w-12 h-12 rounded-xl bg-white border-2 border-orange-200 grid place-items-center text-orange-700 flex-shrink-0 overflow-hidden">
                  {draft.photo ? (
                    <img src={draft.photo} alt="" className="w-full h-full object-cover" />
                  ) : (
                    <BookOpen size={20} strokeWidth={1.6} />
                  )}
                </div>
                <div className="flex-1 min-w-0">
                  <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold">Pasaporte</div>
                  <div className="font-serif text-lg font-bold leading-tight">{foundPet.name}</div>
                  <div className="font-mono text-xs font-bold text-orange-700">#{foundPet.code}</div>
                </div>
              </div>

              {/* Foto editable */}
              <div>
                <label className="text-xs font-semibold text-stone-700 block mb-1.5">Foto</label>
                {draft.photo ? (
                  <div className="flex items-center gap-3 p-3 bg-orange-50 border-2 border-orange-300 rounded-xl">
                    <img src={draft.photo} alt="" className="w-16 h-16 rounded-lg object-cover flex-shrink-0" />
                    <div className="flex-1 min-w-0">
                      <div className="text-sm font-semibold text-stone-800">Foto cargada</div>
                      <div className="text-xs text-stone-500">Listo para enviar</div>
                    </div>
                    <button onClick={() => setDraft({ ...draft, photo: null })} className="px-2.5 py-1.5 rounded-lg bg-white border border-stone-200 hover:border-red-400 text-stone-600 hover:text-red-600 text-xs font-semibold transition">
                      <X size={11} className="inline" /> Quitar
                    </button>
                  </div>
                ) : (
                  <label className="border-2 border-dashed border-stone-300 hover:border-orange-400 rounded-xl p-4 flex flex-col items-center justify-center gap-1.5 cursor-pointer text-stone-500 hover:text-orange-700 hover:bg-orange-50 transition">
                    <Camera size={20} />
                    <div className="text-xs font-semibold">Subir foto</div>
                    <input
                      type="file"
                      accept="image/*"
                      className="hidden"
                      onChange={(e) => {
                        const file = e.target.files?.[0];
                        if (!file) return;
                        const reader = new FileReader();
                        reader.onload = () => setDraft(d => ({ ...d, photo: reader.result }));
                        reader.readAsDataURL(file);
                      }}
                    />
                  </label>
                )}
              </div>

              <div>
                <label className="text-xs font-semibold text-stone-700 block mb-1.5">Nombre</label>
                <input
                  value={draft.name}
                  onChange={(e) => setDraft({ ...draft, name: e.target.value })}
                  className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
                />
              </div>

              <div>
                <label className="text-xs font-semibold text-stone-700 block mb-1.5">Especie</label>
                <div className="flex gap-1.5 flex-wrap">
                  {speciesOpts.map(s => {
                    const Ic = s.Icon;
                    const active = draft.species === s.id;
                    return (
                      <button
                        key={s.id}
                        onClick={() => setDraft({ ...draft, species: s.id })}
                        className={`flex items-center gap-1.5 px-2.5 py-1.5 rounded-full text-xs font-semibold transition ${
                          active ? "bg-orange-600 text-white" : "bg-white text-stone-600 border border-stone-200 hover:border-orange-300"
                        }`}
                      >
                        <Ic size={12} strokeWidth={1.8} /> {s.label}
                      </button>
                    );
                  })}
                </div>
              </div>

              <div className="grid grid-cols-2 gap-2">
                <div>
                  <label className="text-xs font-semibold text-stone-700 block mb-1.5">Raza</label>
                  <input value={draft.breed} onChange={(e) => setDraft({ ...draft, breed: e.target.value })} className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500" />
                </div>
                <div>
                  <label className="text-xs font-semibold text-stone-700 block mb-1.5">Color</label>
                  <input value={draft.color} onChange={(e) => setDraft({ ...draft, color: e.target.value })} className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500" />
                </div>
                <div>
                  <label className="text-xs font-semibold text-stone-700 block mb-1.5">Peso</label>
                  <input value={draft.weight} onChange={(e) => setDraft({ ...draft, weight: e.target.value })} placeholder="Ej: 5.1 kg" className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500" />
                </div>
                <div>
                  <label className="text-xs font-semibold text-stone-700 block mb-1.5">Fecha nacimiento</label>
                  <input value={draft.birthdate} onChange={(e) => setDraft({ ...draft, birthdate: e.target.value })} placeholder="DD/MM/AAAA" className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500 font-mono" />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-2">
                <div>
                  <label className="text-xs font-semibold text-stone-700 block mb-1.5">Género</label>
                  <div className="flex gap-1">
                    {[{v:"M",l:"Macho"},{v:"F",l:"Hembra"}].map(g => (
                      <button
                        key={g.v}
                        onClick={() => setDraft({ ...draft, gender: g.v })}
                        className={`flex-1 px-2 py-2 rounded-lg text-xs font-semibold transition ${
                          draft.gender === g.v ? "bg-stone-900 text-white" : "bg-white text-stone-600 border border-stone-200"
                        }`}
                      >
                        {g.l}
                      </button>
                    ))}
                  </div>
                </div>
                <div>
                  <label className="text-xs font-semibold text-stone-700 block mb-1.5">Esterilizado</label>
                  <button
                    onClick={() => setDraft({ ...draft, sterilized: !draft.sterilized })}
                    className={`w-full px-3 py-2 rounded-lg border text-xs font-semibold transition ${
                      draft.sterilized ? "bg-emerald-50 border-emerald-400 text-emerald-800" : "bg-white border-stone-200 text-stone-600"
                    }`}
                  >
                    {draft.sterilized ? "Sí" : "No"}
                  </button>
                </div>
              </div>

              {/* === ZONA SENSIBLE: solo super y sales === */}
              {canEditSensitive && (
                <>
                  <div>
                    <label className="text-xs font-semibold text-stone-700 block mb-1.5 flex items-center gap-1.5">
                      <Shield size={10} className="text-orange-600" /> Microchip
                      <span className="text-xs text-stone-400 font-normal">(restringido)</span>
                    </label>
                    <input value={draft.microchip} onChange={(e) => setDraft({ ...draft, microchip: e.target.value })} placeholder="Ej: 985 112 776655443" className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500 font-mono" />
                  </div>

                  {/* Editor de tutores */}
                  <div className="pt-2 border-t border-stone-200">
                <div className="flex items-center justify-between mb-2">
                  <div>
                    <label className="text-xs font-semibold text-stone-700 block">Tutores asociados</label>
                    <span className="text-xs text-stone-500">Hasta 3 tutores por mascota</span>
                  </div>
                  {(draft.tutors || []).length < 3 && (
                    <button
                      onClick={() => setDraft({
                        ...draft,
                        tutors: [...(draft.tutors || []), { id: `t-${Date.now().toString(36)}`, name: "", relation: "", phone: "", since: "" }],
                      })}
                      className="px-2 py-1 rounded-lg bg-orange-50 hover:bg-orange-100 border border-orange-200 text-orange-700 text-xs font-semibold flex items-center gap-1"
                    >
                      <Plus size={10} /> Añadir
                    </button>
                  )}
                </div>

                <div className="space-y-2">
                  {(draft.tutors || []).map((t, idx) => (
                    <div key={t.id || idx} className="bg-stone-50 border border-stone-200 rounded-xl p-3 space-y-2">
                      <div className="flex items-center gap-2">
                        <div className="w-7 h-7 rounded-full bg-orange-500 text-white text-xs font-bold grid place-items-center flex-shrink-0">
                          {(t.name || "?").split(" ").slice(0, 2).map(s => s[0] || "").join("").toUpperCase() || "?"}
                        </div>
                        <span className="text-xs font-bold text-stone-700">Tutor {idx + 1}</span>
                        <button
                          onClick={() => setDraft({ ...draft, tutors: draft.tutors.filter((_, i) => i !== idx) })}
                          title="Quitar tutor"
                          className="ml-auto w-6 h-6 rounded-lg bg-white border border-stone-200 hover:border-red-400 grid place-items-center text-stone-500 hover:text-red-600"
                        >
                          <X size={10} />
                        </button>
                      </div>
                      <div className="grid grid-cols-2 gap-2">
                        <input
                          value={t.name || ""}
                          onChange={(e) => {
                            const newTutors = [...draft.tutors];
                            newTutors[idx] = { ...t, name: e.target.value };
                            setDraft({ ...draft, tutors: newTutors });
                          }}
                          placeholder="Nombre completo"
                          className="col-span-2 px-2.5 py-1.5 bg-white border border-stone-200 rounded-lg text-xs outline-none focus:border-orange-500"
                        />
                        <input
                          value={t.relation || ""}
                          onChange={(e) => {
                            const newTutors = [...draft.tutors];
                            newTutors[idx] = { ...t, relation: e.target.value };
                            setDraft({ ...draft, tutors: newTutors });
                          }}
                          placeholder="Relación (ej: Tutor principal)"
                          className="px-2.5 py-1.5 bg-white border border-stone-200 rounded-lg text-xs outline-none focus:border-orange-500"
                        />
                        <input
                          value={t.phone || ""}
                          onChange={(e) => {
                            const newTutors = [...draft.tutors];
                            newTutors[idx] = { ...t, phone: e.target.value };
                            setDraft({ ...draft, tutors: newTutors });
                          }}
                          placeholder="Teléfono"
                          className="px-2.5 py-1.5 bg-white border border-stone-200 rounded-lg text-xs outline-none focus:border-orange-500 font-mono"
                        />
                      </div>
                    </div>
                  ))}
                  {(draft.tutors || []).length === 0 && (
                    <div className="text-center py-4 text-xs text-stone-500 border border-dashed border-stone-300 rounded-xl">
                      Esta mascota no tiene tutores registrados.
                    </div>
                  )}
                </div>
              </div>
                </>
              )}

              {/* Aviso para roles sin permiso a campos sensibles */}
              {!canEditSensitive && (
                <div className="bg-stone-50 border border-stone-200 rounded-xl p-3 text-xs text-stone-600 flex items-start gap-2">
                  <Shield size={11} className="text-stone-500 flex-shrink-0 mt-0.5" />
                  <div>
                    <strong>Microchip y tutores</strong> solo pueden ser editados por el equipo de ventas o el super usuario. Si necesitas actualizarlos, contacta a quien corresponda.
                  </div>
                </div>
              )}

              {/* Resumen de cambios detectados */}
              {changedFields.length > 0 && (
                <div className="bg-orange-50 border border-orange-200 rounded-xl p-3 text-xs text-orange-900">
                  <div className="font-semibold mb-1.5 flex items-center gap-1">
                    <Info size={11} /> {changedFields.length} {changedFields.length === 1 ? "cambio detectado" : "cambios detectados"}
                  </div>
                  <div className="flex flex-wrap gap-1">
                    {changedFields.map(f => (
                      <span key={f.key} className="px-2 py-0.5 rounded-full bg-white border border-orange-300 text-xs font-semibold">
                        {f.label}
                      </span>
                    ))}
                  </div>
                </div>
              )}

              <div className="flex gap-2 pt-1">
                <button
                  onClick={() => { setFoundPet(null); setDraft(null); setSearchCode(""); setEditingUpdateId(null); }}
                  className="flex-1 px-3 py-2.5 rounded-xl text-sm font-semibold bg-white border border-stone-200 hover:border-stone-400 text-stone-700"
                >
                  Cancelar
                </button>
                <button
                  onClick={submitUpdate}
                  disabled={changedFields.length === 0}
                  className={`flex-1 px-3 py-2.5 rounded-xl text-sm font-semibold transition shadow ${
                    changedFields.length > 0
                      ? "bg-orange-600 hover:bg-orange-700 text-white"
                      : "bg-stone-200 text-stone-400 cursor-not-allowed"
                  }`}
                >
                  <Send size={12} className="inline" />
                  {editingUpdateId ? " Reenviar a aprobación" : " Enviar a aprobación"}
                </button>
              </div>
            </div>
          ) : (
            <div className="p-12 text-center">
              <BookOpen size={36} className="text-stone-300 mx-auto mb-3" />
              <div className="text-base font-semibold text-stone-700">Busca un pasaporte para empezar</div>
              <div className="text-sm text-stone-500 mt-1">
                Ingresa el código de 6 dígitos arriba para cargar la información actual.
              </div>
            </div>
          )}
        </div>

        {/* === DER: cola de cambios === */}
        <div className="w-full lg:w-96 flex-shrink-0 bg-white border border-stone-200 rounded-2xl shadow-sm overflow-hidden self-start">
          <div className="p-4 border-b border-stone-200 bg-stone-50 flex items-center justify-between">
            <div>
              <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold">
                Cola de cambios
              </div>
              <h3 className="font-serif text-lg font-semibold leading-tight">
                {sortedUpdates.length === 0 ? "Sin actividad" :
                 pendingCount > 0 ? `${pendingCount} pendiente${pendingCount === 1 ? "" : "s"}` :
                 "Todo aprobado"}
              </h3>
            </div>
            {isAdmin && pendingCount > 0 && (
              <span className="text-xs font-bold px-2 py-0.5 rounded-full bg-orange-100 text-orange-700 inline-flex items-center gap-1">
                <Shield size={9} /> Aprobar
              </span>
            )}
          </div>

          {/* Lista paginada */}
          <div className="p-3 space-y-2 min-h-64">
            {sortedUpdates.length === 0 && (
              <div className="text-center py-8 text-sm text-stone-500">
                Aún no hay propuestas de cambio.
              </div>
            )}

            {pagedUpdates.map(u => {
              const isPending = u.status === "pending";
              const isApproved = u.status === "approved";
              const isRejected = u.status === "rejected";
              const isMine = u.submittedBy === (userName || userRole);
              const canEdit = isPending && (isMine || isAdmin);

              return (
                <div key={u.id} className={`border rounded-xl p-3 ${
                  isPending  ? "bg-amber-50 border-amber-200" :
                  isApproved ? "bg-emerald-50 border-emerald-200" :
                               "bg-stone-50 border-stone-200 opacity-75"
                }`}>
                  {/* Header del item */}
                  <div className="flex items-start gap-2 mb-2">
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-1.5 flex-wrap">
                        <span className="font-mono text-xs font-bold text-orange-700">#{u.passportCode}</span>
                        <span className="font-semibold text-sm">{u.passportName}</span>
                      </div>
                      {/* Autor con avatar de iniciales */}
                      <div className="flex items-center gap-1.5 mt-1">
                        <div className="w-5 h-5 rounded-full bg-stone-700 text-white text-xs font-bold grid place-items-center flex-shrink-0">
                          {(u.submittedBy || "?").split(" ").slice(0, 2).map(s => s[0] || "").join("").toUpperCase() || "?"}
                        </div>
                        <span className="text-xs text-stone-700">
                          <strong>{u.submittedBy}</strong>
                          {u.submittedBy === (userName || userRole) && (
                            <span className="ml-1 px-1.5 py-px rounded-full bg-orange-100 text-orange-700 text-xs font-bold">tú</span>
                          )}
                        </span>
                        <span className="text-xs text-stone-400">· {fmtDate(u.submittedAt)}</span>
                      </div>
                    </div>
                    {/* Status badge */}
                    {isPending && (
                      <span className="text-xs font-bold px-2 py-0.5 rounded-full bg-amber-100 text-amber-800 inline-flex items-center gap-1 flex-shrink-0">
                        <span className="w-1.5 h-1.5 rounded-full bg-amber-500 animate-pulse"></span>
                        Pendiente
                      </span>
                    )}
                    {isApproved && (
                      <span className="text-xs font-bold px-2 py-0.5 rounded-full bg-emerald-100 text-emerald-800 inline-flex items-center gap-1 flex-shrink-0">
                        <Check size={9} strokeWidth={3} /> Aprobado
                      </span>
                    )}
                    {isRejected && (
                      <span className="text-xs font-bold px-2 py-0.5 rounded-full bg-stone-200 text-stone-700 inline-flex items-center gap-1 flex-shrink-0">
                        <X size={9} /> Rechazado
                      </span>
                    )}
                  </div>

                  {/* Campos cambiados (filtrar sensibles si el viewer no tiene permiso) */}
                  <div className="flex flex-wrap gap-1 mb-2">
                    {(u.changedFields || [])
                      .filter(f => canEditSensitive || (f !== "microchip" && f !== "tutors"))
                      .map(f => {
                        const labels = { name: "Nombre", species: "Especie", breed: "Raza", color: "Color", weight: "Peso", gender: "Género", sterilized: "Esterilizado", microchip: "Microchip", birthdate: "Nacimiento", photo: "Foto", tutors: "Tutores" };
                        return (
                          <span key={f} className="px-2 py-px rounded-full bg-white border border-stone-200 text-xs font-semibold text-stone-700">
                            {labels[f] || f}
                          </span>
                        );
                      })}
                    {/* Si hay campos sensibles ocultados, indicarlo de forma genérica */}
                    {!canEditSensitive && (u.changedFields || []).some(f => f === "microchip" || f === "tutors") && (
                      <span className="px-2 py-px rounded-full bg-stone-100 border border-stone-200 text-xs font-semibold text-stone-500 inline-flex items-center gap-1">
                        <Shield size={9} /> + datos restringidos
                      </span>
                    )}
                  </div>

                  {/* Reenvío */}
                  {u.resubmittedAt && (
                    <div className="text-xs text-stone-500 mb-2 italic">
                      Reenviado por {u.resubmittedBy} · {fmtDate(u.resubmittedAt)}
                    </div>
                  )}

                  {/* Acciones */}
                  <div className="flex gap-1.5 flex-wrap">
                    {canEdit && (
                      <button
                        onClick={() => loadUpdateForEdit(u)}
                        className="flex-1 px-2 py-1.5 rounded-lg bg-white border border-stone-200 hover:border-orange-400 text-stone-700 hover:text-orange-700 text-xs font-semibold transition flex items-center justify-center gap-1"
                      >
                        <Edit3 size={10} /> Editar
                      </button>
                    )}
                    {isPending && isAdmin && (
                      <>
                        <button
                          onClick={() => rejectUpdate(u.id)}
                          className="flex-1 px-2 py-1.5 rounded-lg bg-white border border-stone-200 hover:border-red-400 text-stone-700 hover:text-red-700 text-xs font-semibold transition flex items-center justify-center gap-1"
                        >
                          <X size={10} /> Rechazar
                        </button>
                        <button
                          onClick={() => approveUpdate(u.id)}
                          className="flex-1 px-2 py-1.5 rounded-lg bg-emerald-500 hover:bg-emerald-600 text-white text-xs font-semibold shadow flex items-center justify-center gap-1"
                        >
                          <Check size={10} strokeWidth={3} /> Aprobar
                        </button>
                      </>
                    )}
                    {isPending && !isAdmin && isMine && (
                      <button
                        onClick={() => cancelUpdate(u.id)}
                        className="flex-1 px-2 py-1.5 rounded-lg bg-white border border-stone-200 hover:border-red-400 text-stone-700 hover:text-red-700 text-xs font-semibold transition flex items-center justify-center gap-1"
                      >
                        <Trash2 size={10} /> Cancelar mi propuesta
                      </button>
                    )}
                  </div>

                  {/* Status approvers */}
                  {(isApproved || isRejected) && (
                    <div className="text-xs text-stone-500 mt-2 italic">
                      {isApproved && `Aprobado por ${u.approvedBy} · ${fmtDate(u.approvedAt)}`}
                      {isRejected && `Rechazado por ${u.rejectedBy} · ${fmtDate(u.rejectedAt)}`}
                    </div>
                  )}
                </div>
              );
            })}
          </div>

          {/* Paginación */}
          {totalPages > 1 && (
            <div className="p-3 border-t border-stone-200 bg-stone-50 flex items-center justify-between">
              <button
                onClick={() => setPage(Math.max(0, page - 1))}
                disabled={page === 0}
                className="px-2 py-1 rounded-lg bg-white border border-stone-200 hover:border-stone-400 disabled:opacity-40 disabled:cursor-not-allowed text-xs font-semibold flex items-center gap-1"
              >
                <ChevronLeft size={11} /> Anterior
              </button>
              <span className="text-xs text-stone-600 font-mono">
                {page + 1} / {totalPages}
              </span>
              <button
                onClick={() => setPage(Math.min(totalPages - 1, page + 1))}
                disabled={page >= totalPages - 1}
                className="px-2 py-1 rounded-lg bg-white border border-stone-200 hover:border-stone-400 disabled:opacity-40 disabled:cursor-not-allowed text-xs font-semibold flex items-center gap-1"
              >
                Siguiente <ChevronRight size={11} />
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// ========== VET CRM: KANBAN DE PACIENTES POR STATUS ==========
// Cada columna agrupa pacientes según su estado clínico actual.
// Es el "tablero principal" de la veterinaria — el equivalente a Trello/kanban
// para gestionar a los pacientes activos.
function VetPatientsKanban({ patients, activePatientId, onSelectPatient, onRequestWalkInPassport, onMoveStatus, vetEvents = [], activeModule = null }) {
  // ¿El módulo permite drag&drop entre columnas? Defaults a true.
  const dragEnabled = activeModule?.features?.dragAndDrop !== false;
  // Configuración de qué campos se muestran en cada card. Default: todo visible.
  const cardFields = {
    petName: true, petCode: true, breed: true, age: true,
    tutorName: true, time: true, invoiceNumber: true, statusBadge: true,
    ...(activeModule?.cardFields || {}),
  };
  // Reloj actual: tick cada minuto para detectar citas que se retrasan
  // Si la hora de la cita ya pasó y el paciente sigue en "Reserva hoy",
  // mostramos un reloj indicando "llega tarde" y el tiempo de retraso.
  const [currentMinute, setCurrentMinute] = useState(() => Date.now());
  useEffect(() => {
    const t = setInterval(() => setCurrentMinute(Date.now()), 60 * 1000);
    return () => clearInterval(t);
  }, []);

  // === Drag & drop: mover pacientes entre columnas para cambiar su estado ===
  // dragOverColumnId: highlight de la columna sobre la que se está arrastrando.
  // dragData: { patientId, fromStatus } al iniciar el drag.
  const [dragOverColumnId, setDragOverColumnId] = useState(null);
  const dragDataRef = useRef(null);
  const handleDragStart = (e, patientId, fromStatus) => {
    if (!dragEnabled) { e.preventDefault?.(); return; }
    if (!patientId || !fromStatus) return;
    dragDataRef.current = { patientId, fromStatus };
    // dataTransfer es necesario en algunos browsers para que el drag inicie
    if (e.dataTransfer) {
      e.dataTransfer.effectAllowed = "move";
      try { e.dataTransfer.setData("text/plain", String(patientId)); } catch (_) {}
    }
  };
  const handleDragEnd = () => {
    dragDataRef.current = null;
    setDragOverColumnId(null);
  };
  const handleColumnDragOver = (e, columnId) => {
    if (!dragDataRef.current) return;
    e.preventDefault();
    if (e.dataTransfer) e.dataTransfer.dropEffect = "move";
    if (dragOverColumnId !== columnId) setDragOverColumnId(columnId);
  };
  const handleColumnDrop = (e, columnId) => {
    e.preventDefault();
    const data = dragDataRef.current;
    setDragOverColumnId(null);
    dragDataRef.current = null;
    if (!data) return;
    if (data.fromStatus === columnId) return;
    onMoveStatus && onMoveStatus(data.patientId, columnId);
  };

  // Agrupación por status, con orden definido y colores semánticos
  // Flujo natural del día: reserva → consulta → (tratamiento en sede) → finalizado
  // Control y Vacuna están agrupados en una sola columna con calendario propio.
  // Los IDs internos son fijos (el status del paciente los referencia) pero las
  // ETIQUETAS visibles pueden venir del módulo configurado (ej: una clínica que
  // prefiere llamar "Reserva hoy" como "Citas del día").
  const COLUMN_DEFS = useMemo(() => {
    // Mapeo de IDs del módulo (vienen del wizard) → IDs internos del kanban
    const MODULE_TO_INTERNAL = {
      "reserva-hoy":   "reserva",
      "en-consulta":   "consulta",
      "tratamiento":   "tratamiento_sede",
      "control":       "control",
      "finalizado":    "finalizado",
    };
    const defaults = [
      { id: "reserva",         label: "Reserva hoy",       color: "stone",   description: "Citas agendadas para hoy" },
      { id: "consulta",        label: "En consulta",       color: "blue",    description: "Atención activa con el veterinario" },
      { id: "tratamiento_sede", label: "Tratamiento en sede", color: "amber",  description: "Hospitalizado · agregando insumos a recibo" },
      { id: "control",         label: "Control / Vacunación", color: "orange", description: "Seguimiento programado · calendario propio" },
      { id: "finalizado",      label: "Finalizado",         color: "stone",   description: "Atención cerrada y reciboda" },
    ];
    // Si el módulo trae columnas custom, sobrescribimos labels manteniendo el orden
    // y el id interno (necesario para que el drag & drop siga funcionando).
    const moduleCols = activeModule?.columns;
    if (!moduleCols || moduleCols.length === 0) return defaults;
    return defaults.map(def => {
      // Buscar columna del módulo cuyo id se mapea a este id interno
      const match = moduleCols.find(c => MODULE_TO_INTERNAL[c.id] === def.id);
      return match ? { ...def, label: match.label || def.label } : def;
    });
  }, [activeModule]);

  const columnColors = {
    stone:   { dot: "bg-stone-500",   border: "border-stone-200",   bg: "bg-stone-50",   headerBg: "bg-stone-100",   text: "text-stone-700" },
    blue:    { dot: "bg-blue-500",    border: "border-blue-200",    bg: "bg-blue-50",    headerBg: "bg-blue-100",    text: "text-blue-700" },
    amber:   { dot: "bg-amber-500",   border: "border-amber-200",   bg: "bg-amber-50",   headerBg: "bg-amber-100",   text: "text-amber-700" },
    orange:  { dot: "bg-orange-500",  border: "border-orange-200",  bg: "bg-orange-50",  headerBg: "bg-orange-100",  text: "text-orange-700" },
    emerald: { dot: "bg-emerald-500", border: "border-emerald-200", bg: "bg-emerald-50", headerBg: "bg-emerald-100", text: "text-emerald-700" },
  };

  // Reservas de HOY: cruzar eventos vet del día con pacientes
  // Un mismo paciente puede aparecer aquí Y en otra columna (ej: Toby está en tratamiento y tiene control hoy)
  const todayReservations = useMemo(() => {
    const todayStr = new Date().toISOString().slice(0, 10);
    const todayEvents = vetEvents.filter(e => e.date === todayStr);
    // Match por petCode (más confiable que nombre)
    return todayEvents.map(ev => {
      const matchByCode = ev.petCode && patients.find(p => p.code === ev.petCode);
      const matchByName = !matchByCode && ev.pet && patients.find(p =>
        p.name.toLowerCase() === ev.pet.toLowerCase()
      );
      const patient = matchByCode || matchByName;
      // Si no hay match, sintetizar un "paciente walk-in" desde el evento
      return {
        eventId: ev.id,
        time: ev.time,
        title: ev.title,
        reason: ev.reason || ev.notes || null,
        // Si hay match, usar datos del paciente; si no, datos del evento
        id: patient?.id ?? `walkin-${ev.id}`,
        code: patient?.code ?? ev.petCode,
        name: patient?.name ?? ev.pet ?? "Sin asignar",
        species: patient?.species ?? "dog",
        breed: patient?.breed ?? "—",
        age: patient?.age ?? null,
        owner: patient?.owner ?? ev.owner,
        isPatientRegistered: !!patient,
      };
    }).sort((a, b) => a.time.localeCompare(b.time));
  }, [vetEvents, patients]);

  const grouped = useMemo(() => {
    const m = {};
    COLUMN_DEFS.forEach(c => { m[c.id] = []; });

    // Pacientes activos por status (excluyendo "reserva" — esa columna se construye desde eventos)
    patients.forEach(p => {
      if (p.status === "reserva") return;
      if (m[p.status]) m[p.status].push(p);
      else if (m.consulta) m.consulta.push(p);
    });

    // IDs de pacientes que YA están en alguna columna activa (consulta, tratamiento, control, finalizado)
    // Esos NO deben aparecer también en "Reserva" — el paciente ya entró, su cita pasó al CRM.
    const inActiveColumn = new Set();
    Object.entries(m).forEach(([colId, items]) => {
      if (colId === "reserva") return;
      items.forEach(it => inActiveColumn.add(it.id));
    });

    // Reserva: solo eventos cuyo paciente NO está ya en otra columna activa.
    // Si Coco entró en consulta, su cita en la agenda deja de mostrarse aquí.
    m.reserva = todayReservations.filter(r => !inActiveColumn.has(r.id));

    return m;
  }, [patients, todayReservations]);

  return (
    <div className="bg-white border border-stone-200 rounded-2xl shadow-sm overflow-hidden">
      <div className="p-4 border-b border-stone-200 bg-stone-50">
        <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold">CRM clínico</div>
        <div className="flex items-baseline gap-2">
          <h3 className="font-serif text-xl font-semibold">Pacientes por estado</h3>
          <span className="text-xs text-stone-500">— arrastra entre columnas para cambiar de etapa</span>
        </div>
      </div>

      {/* Columnas con scroll horizontal en desktop, stack vertical en mobile */}
      <div className="overflow-x-auto">
        <div className="flex gap-3 p-3 min-w-fit">
          {COLUMN_DEFS.map(col => {
            const colors = columnColors[col.color];
            const items = grouped[col.id] || [];
            const isDropTarget = dragOverColumnId === col.id;
            return (
              <div
                key={col.id}
                onDragOver={(e) => handleColumnDragOver(e, col.id)}
                onDragLeave={() => { if (dragOverColumnId === col.id) setDragOverColumnId(null); }}
                onDrop={(e) => handleColumnDrop(e, col.id)}
                className={`w-64 flex-shrink-0 rounded-xl border ${colors.border} ${colors.bg} transition ${
                  isDropTarget ? "ring-2 ring-orange-400 ring-offset-2 scale-[1.01]" : ""
                }`}
              >
                {/* Header columna */}
                <div className={`p-2.5 border-b ${colors.border} ${colors.headerBg} rounded-t-xl flex items-center gap-2`}>
                  <span className={`w-1.5 h-1.5 rounded-full ${colors.dot} flex-shrink-0`}></span>
                  <div className="flex-1 min-w-0">
                    <div className={`text-xs font-bold ${colors.text} truncate`}>{col.label}</div>
                    <div className="text-xs text-stone-500 truncate">{col.description}</div>
                  </div>
                  <span className={`text-xs font-bold px-1.5 py-px rounded-full bg-white ${colors.text} flex-shrink-0`}>
                    {items.length}
                  </span>
                </div>

                {/* Items */}
                <div className="p-2 space-y-1.5 min-h-32">
                  {items.length === 0 ? (
                    <div className="text-center py-6 text-xs text-stone-400 italic">
                      {col.id === "reserva" ? "Sin citas hoy" : "Sin pacientes en esta etapa"}
                    </div>
                  ) : col.id === "reserva" ? (
                    // Cards de reserva: la hora es lo más importante
                    items.map(p => {
                      const active = activePatientId === p.id;
                      // Calcular si la cita ya está retrasada
                      // currentMinute fuerza re-render cada minuto sin estar en deps
                      const _tick = currentMinute;
                      const now = new Date();
                      const [hh, mm] = (p.time || "00:00").split(":").map(Number);
                      const apptDate = new Date();
                      apptDate.setHours(hh, mm, 0, 0);
                      const diffMin = Math.floor((now - apptDate) / 60000);
                      const isLate = diffMin > 0;
                      const lateLabel = isLate
                        ? (diffMin < 60 ? `${diffMin} min tarde` : `${Math.floor(diffMin / 60)}h ${diffMin % 60}m tarde`)
                        : null;
                      return (
                        <button
                          key={p.eventId || p.id}
                          draggable={dragEnabled && p.isPatientRegistered}
                          onDragStart={(e) => dragEnabled && p.isPatientRegistered && handleDragStart(e, p.id, "reserva")}
                          onDragEnd={handleDragEnd}
                          onClick={() => {
                            if (!p.isPatientRegistered) {
                              // Walk-in: forzar creación de pasaporte primero
                              onRequestWalkInPassport && onRequestWalkInPassport({
                                eventId: p.eventId,
                                time: p.time,
                                title: p.title,
                                reason: p.reason || null,
                                prefilled: {
                                  name: p.name && p.name !== "Sin asignar" ? p.name : "",
                                  species: p.species,
                                  breed: p.breed && p.breed !== "—" ? p.breed : "",
                                  age: p.age || "",
                                  owner: p.owner || "",
                                },
                              });
                              return;
                            }
                            // Paciente con pasaporte: abrir drawer de reserva normal
                            onSelectPatient && onSelectPatient(p.id, {
                              fromReservation: true,
                              eventId: p.eventId,
                              time: p.time,
                            });
                          }}
                          className={`w-full p-2 rounded-lg border bg-white text-left transition relative ${
                            active ? "border-orange-500 ring-1 ring-orange-300 shadow" :
                            isLate ? "border-red-300 ring-1 ring-red-100 hover:border-red-400" :
                            p.isPatientRegistered ? "border-stone-200 hover:border-orange-300 hover:shadow-sm" :
                            "border-dashed border-amber-300 hover:border-amber-500 hover:bg-amber-50"
                          }`}
                        >
                          {/* Hora destacada arriba con badge de tardanza si aplica */}
                          {cardFields.time && (
                          <div className="flex items-center gap-1.5 mb-1">
                            <Clock size={10} className={isLate ? "text-red-600 animate-pulse flex-shrink-0" : "text-stone-500 flex-shrink-0"} />
                            <span className={`font-mono text-xs font-bold ${isLate ? "text-red-700" : "text-stone-800"}`}>{p.time}</span>
                            {isLate ? (
                              <span className="text-xs font-bold px-1.5 py-px rounded bg-red-100 text-red-700 flex items-center gap-0.5">
                                <AlertCircle size={9} />
                                {lateLabel}
                              </span>
                            ) : (
                              <span className="text-xs text-stone-400 truncate">· {p.title}</span>
                            )}
                          </div>
                          )}
                          <div className="flex items-start gap-2">
                            <PetAvatar species={p.species} small />
                            <div className="flex-1 min-w-0">
                              <div className="flex items-baseline gap-1">
                                {cardFields.petName && <span className="font-semibold text-xs truncate">{p.name}</span>}
                                {cardFields.petCode && p.code && p.code !== "—" && (
                                  <span className="font-mono text-xs text-orange-700 font-bold">#{p.code}</span>
                                )}
                              </div>
                              {/* Si está tarde mostrar el motivo aquí, sino abajo */}
                              {isLate && p.title && (
                                <div className="text-xs text-stone-500 truncate">
                                  {p.title}
                                </div>
                              )}
                              {cardFields.breed && p.breed && p.breed !== "—" && (
                                <div className="text-xs text-stone-500 truncate">
                                  {p.breed}{cardFields.age && p.age ? ` · ${p.age}` : ""}
                                </div>
                              )}
                              {cardFields.tutorName && p.owner && (
                                <div className="text-xs text-stone-400 truncate">
                                  Tutor: {p.owner}
                                </div>
                              )}
                              {p.reason && (
                                <div className="text-xs text-blue-600 mt-0.5 truncate flex items-center gap-1">
                                  <Info size={9} className="flex-shrink-0" />
                                  {p.reason}
                                </div>
                              )}
                              {!p.isPatientRegistered && (
                                <div className="text-xs text-amber-700 italic mt-0.5 flex items-center gap-1">
                                  <UserPlus size={9} /> Click para registrar pasaporte
                                </div>
                              )}
                            </div>
                          </div>
                        </button>
                      );
                    })
                  ) : (
                    items.map(p => {
                      const active = activePatientId === p.id;
                      return (
                        <button
                          key={p.id}
                          draggable={dragEnabled}
                          onDragStart={(e) => dragEnabled && handleDragStart(e, p.id, col.id)}
                          onDragEnd={handleDragEnd}
                          onClick={() => onSelectPatient && onSelectPatient(p.id)}
                          className={`w-full flex items-start gap-2 p-2 rounded-lg border bg-white text-left transition ${
                            dragEnabled ? "cursor-grab active:cursor-grabbing" : "cursor-pointer"
                          } ${
                            active ? "border-orange-500 ring-1 ring-orange-300 shadow" : "border-stone-200 hover:border-orange-300 hover:shadow-sm"
                          }`}
                        >
                          <PetAvatar species={p.species} small />
                          <div className="flex-1 min-w-0">
                            <div className="flex items-baseline gap-1">
                              {cardFields.petName && <span className="font-semibold text-xs truncate">{p.name}</span>}
                              {cardFields.petCode && p.code && (
                                <span className="font-mono text-xs text-orange-700 font-bold">#{p.code}</span>
                              )}
                            </div>
                            {(cardFields.breed || cardFields.age) && (
                            <div className="text-xs text-stone-500 truncate">
                              {cardFields.breed && p.breed}{cardFields.breed && cardFields.age && p.age ? " · " : ""}{cardFields.age && p.age}
                            </div>
                            )}
                            <div className="text-xs text-stone-400 mt-1 italic truncate">
                              {p.lastVisit}
                            </div>
                          </div>
                        </button>
                      );
                    })
                  )}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

// ========== VET AGENDA MODAL: ventana flotante con calendario ==========
// Mismo patrón que GroomingCalendarModal pero para citas vet.
// Permite mantener el CRM como vista principal y consultar agenda solo cuando hace falta.
function VetAgendaModal({ onClose, vetEvents, onMoveEvent, onSelectEvent }) {
  const [calView, setCalView] = useState("week");
  const [selectedDate, setSelectedDate] = useState(() => {
    const d = new Date();
    d.setHours(0, 0, 0, 0);
    return d;
  });
  const [maximized, setMaximized] = useState(false);
  const [minimized, setMinimized] = useState(false);

  // Posición de la ventana (drag desde el header)
  const [position, setPosition] = useState({ x: 80, y: 80 });
  const [dragging, setDragging] = useState(false);
  const dragOffsetRef = useRef({ x: 0, y: 0 });

  const eventsByDate = useMemo(() => {
    const m = {};
    vetEvents.forEach(e => {
      if (!m[e.date]) m[e.date] = [];
      m[e.date].push(e);
    });
    Object.keys(m).forEach(k => m[k].sort((a, b) => a.time.localeCompare(b.time)));
    return m;
  }, [vetEvents]);

  const navigatePrev = () => {
    const d = new Date(selectedDate);
    if (calView === "day") d.setDate(d.getDate() - 1);
    else if (calView === "week") d.setDate(d.getDate() - 7);
    else d.setMonth(d.getMonth() - 1);
    setSelectedDate(d);
  };
  const navigateNext = () => {
    const d = new Date(selectedDate);
    if (calView === "day") d.setDate(d.getDate() + 1);
    else if (calView === "week") d.setDate(d.getDate() + 7);
    else d.setMonth(d.getMonth() + 1);
    setSelectedDate(d);
  };
  const goToToday = () => {
    const d = new Date();
    d.setHours(0, 0, 0, 0);
    setSelectedDate(d);
  };

  const dateLabel = useMemo(() => {
    if (calView === "day") {
      return selectedDate.toLocaleDateString("es", { weekday: "short", day: "2-digit", month: "short" });
    }
    if (calView === "week") {
      const monday = startOfWeek(selectedDate);
      const sunday = new Date(monday);
      sunday.setDate(sunday.getDate() + 6);
      return `${monday.getDate().toString().padStart(2, "0")} ${monday.toLocaleDateString("es", { month: "short" })} – ${sunday.getDate().toString().padStart(2, "0")} ${sunday.toLocaleDateString("es", { month: "short" })}`;
    }
    return selectedDate.toLocaleDateString("es", { month: "long", year: "numeric" });
  }, [selectedDate, calView]);

  // === Drag de la ventana flotante ===
  const handleHeaderMouseDown = (e) => {
    if (maximized || minimized) return;
    if (e.target.closest("button")) return; // ignorar clicks en botones
    dragOffsetRef.current = { x: e.clientX - position.x, y: e.clientY - position.y };
    setDragging(true);
  };
  useEffect(() => {
    if (!dragging) return;
    const onMove = (e) => {
      setPosition({
        x: Math.max(0, Math.min(window.innerWidth - 200, e.clientX - dragOffsetRef.current.x)),
        y: Math.max(0, Math.min(window.innerHeight - 80, e.clientY - dragOffsetRef.current.y)),
      });
    };
    const onUp = () => setDragging(false);
    window.addEventListener("mousemove", onMove);
    window.addEventListener("mouseup", onUp);
    return () => {
      window.removeEventListener("mousemove", onMove);
      window.removeEventListener("mouseup", onUp);
    };
  }, [dragging]);

  // === Estilos según estado de ventana ===
  let style = {};
  let containerClass = "fixed z-40 bg-white rounded-xl shadow-2xl border border-stone-300 flex flex-col overflow-hidden";

  if (minimized) {
    containerClass += " bottom-4 right-4 w-64 h-12";
  } else if (maximized) {
    containerClass += " inset-4";
  } else {
    containerClass += " w-screen max-w-full max-h-screen";
    style = { left: position.x, top: position.y, width: 720, height: 560 };
  }

  return (
    <div className={containerClass} style={style}>
      {/* Title bar arrastrable */}
      <div
        onMouseDown={handleHeaderMouseDown}
        onDoubleClick={() => { if (!minimized) setMaximized(m => !m); }}
        className={`flex items-center gap-2 px-3 py-2 bg-stone-100 border-b border-stone-200 ${
          maximized || minimized ? "" : "cursor-move"
        } select-none`}
      >
        {/* Dots decorativos estilo macOS */}
        <div className="flex gap-1.5 mr-2">
          <button onClick={onClose} title="Cerrar" className="w-3 h-3 rounded-full bg-red-400 hover:bg-red-500 transition"></button>
          <button onClick={() => setMinimized(true)} title="Minimizar" className="w-3 h-3 rounded-full bg-amber-400 hover:bg-amber-500 transition"></button>
          <button onClick={() => { setMaximized(m => !m); setMinimized(false); }} title="Maximizar" className="w-3 h-3 rounded-full bg-emerald-400 hover:bg-emerald-500 transition"></button>
        </div>

        <Calendar size={13} className="text-stone-600 flex-shrink-0" />
        <div className="flex-1 min-w-0 flex items-center gap-2">
          <span className="font-serif font-semibold text-sm truncate">Agenda veterinaria</span>
          {!minimized && (
            <>
              <span className="text-stone-400">·</span>
              <span className="text-xs font-mono text-stone-600 truncate">{dateLabel}</span>
            </>
          )}
        </div>

        {minimized ? (
          <button
            onClick={() => setMinimized(false)}
            title="Restaurar"
            className="w-7 h-7 rounded grid place-items-center hover:bg-stone-200 text-stone-600"
          >
            <Maximize2 size={11} />
          </button>
        ) : (
          <button
            onClick={() => { setMaximized(m => !m); }}
            title={maximized ? "Restaurar" : "Maximizar"}
            className="w-7 h-7 rounded grid place-items-center hover:bg-stone-200 text-stone-600"
          >
            {maximized ? <Minimize2 size={11} /> : <Maximize2 size={11} />}
          </button>
        )}
      </div>

      {/* Body: solo se muestra si no está minimizada */}
      {!minimized && (
        <>
          {/* Toolbar */}
          <div className="flex items-center gap-2 px-3 py-2 border-b border-stone-200 bg-white flex-shrink-0">
            <button onClick={navigatePrev} className="w-8 h-8 rounded-lg hover:bg-stone-100 grid place-items-center text-stone-600">
              <ChevronLeft size={13} />
            </button>
            <button onClick={goToToday} className="px-3 h-8 rounded-lg bg-orange-50 hover:bg-orange-100 text-xs font-semibold text-orange-700 border border-orange-200">
              Hoy
            </button>
            <button onClick={navigateNext} className="w-8 h-8 rounded-lg hover:bg-stone-100 grid place-items-center text-stone-600">
              <ChevronRight size={13} />
            </button>

            <div className="ml-auto bg-stone-100 rounded-lg p-0.5 flex gap-0.5">
              {["day", "week", "month"].map(opt => {
                const labels = { day: "Día", week: "Semana", month: "Mes" };
                return (
                  <button
                    key={opt}
                    onClick={() => setCalView(opt)}
                    className={`px-2.5 py-1 rounded text-xs font-semibold transition ${
                      calView === opt ? "bg-white text-stone-900 shadow" : "text-stone-600 hover:text-stone-900"
                    }`}
                  >
                    {labels[opt]}
                  </button>
                );
              })}
            </div>
          </div>

          {/* Calendar body */}
          <div className="flex-1 overflow-y-auto p-3 bg-stone-50">
            {calView === "day" && (
              <AgendaDay date={selectedDate} eventsByDate={eventsByDate} onSelectEvent={onSelectEvent} />
            )}
            {calView === "week" && (
              <AgendaWeek
                date={selectedDate}
                eventsByDate={eventsByDate}
                onJumpToDay={(d) => { setSelectedDate(d); setCalView("day"); }}
                onSelectEvent={onSelectEvent}
                onMoveEvent={onMoveEvent}
              />
            )}
            {calView === "month" && (
              <AgendaMonth
                date={selectedDate}
                eventsByDate={eventsByDate}
                onJumpToDay={(d) => { setSelectedDate(d); setCalView("month"); }}
                onSelectEvent={onSelectEvent}
              />
            )}
          </div>
        </>
      )}

      {/* Handle de resize (oculto cuando está minimizado o maximizado) */}
      <WindowResizeHandle size={size} setSize={setSize} disabled={minimized || maximized} />
    </div>
  );
}

// Badge de status del paciente (reusable)
function StatusBadge({ status }) {
  const config = {
    reserva:           { label: "Reserva hoy",         bg: "bg-stone-100",   text: "text-stone-700",   dot: "bg-stone-500" },
    consulta:          { label: "En consulta",         bg: "bg-blue-100",    text: "text-blue-700",    dot: "bg-blue-500 animate-pulse" },
    tratamiento_sede:  { label: "Tratamiento en sede", bg: "bg-amber-100",   text: "text-amber-700",   dot: "bg-amber-500 animate-pulse" },
    control:           { label: "Control / Vacunación", bg: "bg-orange-100",  text: "text-orange-700",  dot: "bg-orange-500" },
    finalizado:        { label: "Finalizado",          bg: "bg-stone-100",   text: "text-stone-600",   dot: "bg-stone-400" },
  };
  const c = config[status] || config.consulta;
  return (
    <span className={`inline-flex items-center gap-1.5 text-xs font-bold px-2 py-0.5 rounded-full ${c.bg} ${c.text}`}>
      <span className={`w-1.5 h-1.5 rounded-full ${c.dot}`}></span>
      {c.label}
    </span>
  );
}

// ========== Mini-calendario de seguimiento (Tratamiento/Control) ==========
// Independiente del calendario general. Muestra solo las visitas/dosis programadas
// para este paciente específico. El vet añade entradas y las marca como hechas.
function FollowUpCalendar({ patient, kind, entries, onAdd, onToggleDone, onRemove }) {
  const isTreatment = kind === "tratamiento";
  const accentBg = isTreatment ? "bg-amber-50" : "bg-orange-50";
  const accentBorder = isTreatment ? "border-amber-200" : "border-orange-200";
  const accentText = isTreatment ? "text-amber-700" : "text-orange-700";
  const accentBtn = isTreatment ? "bg-amber-500 hover:bg-amber-600" : "bg-orange-500 hover:bg-orange-600";

  // Ordenar por fecha ascendente
  const sortedEntries = useMemo(() => {
    return [...entries].sort((a, b) => {
      const da = `${a.date}T${a.time || "00:00"}`;
      const db = `${b.date}T${b.time || "00:00"}`;
      return da.localeCompare(db);
    });
  }, [entries]);

  const todayStr = new Date().toISOString().slice(0, 10);
  const upcomingCount = sortedEntries.filter(e => !e.done && e.date >= todayStr).length;
  const overdueCount = sortedEntries.filter(e => !e.done && e.date < todayStr).length;

  return (
    <div className={`${accentBg} border ${accentBorder} rounded-xl overflow-hidden`}>
      <div className={`p-3 border-b ${accentBorder} flex items-center gap-2`}>
        <CalendarClock size={14} className={accentText} />
        <div className="flex-1 min-w-0">
          <div className={`text-xs tracking-widest uppercase font-bold ${accentText}`}>
            Calendario de {isTreatment ? "tratamiento" : "seguimiento"}
          </div>
          <div className="text-xs text-stone-600">
            {sortedEntries.length === 0 ? "Sin visitas programadas" :
             `${upcomingCount} próxima${upcomingCount === 1 ? "" : "s"}${overdueCount > 0 ? ` · ${overdueCount} vencida${overdueCount === 1 ? "" : "s"}` : ""}`}
          </div>
        </div>
        <button
          onClick={onAdd}
          className={`px-2.5 py-1.5 rounded-lg ${accentBtn} text-white text-xs font-semibold flex items-center gap-1 shadow`}
        >
          <CalendarPlus size={11} /> Añadir
        </button>
      </div>
      <div className="p-2 space-y-1.5 max-h-72 overflow-y-auto">
        {sortedEntries.length === 0 ? (
          <div className="text-center py-4 text-xs text-stone-500 italic">
            Añade fechas de medicación, controles o curaciones programadas.
          </div>
        ) : (
          sortedEntries.map(entry => {
            const isOverdue = !entry.done && entry.date < todayStr;
            const isToday = entry.date === todayStr;
            return (
              <div
                key={entry.id}
                className={`flex items-start gap-2 p-2 rounded-lg border transition ${
                  entry.done ? "bg-stone-50 border-stone-200 opacity-60" :
                  isOverdue ? "bg-red-50 border-red-200" :
                  isToday ? "bg-white border-orange-300 ring-1 ring-orange-200" :
                  "bg-white border-stone-200"
                }`}
              >
                <button
                  onClick={() => onToggleDone(entry.id)}
                  className={`w-5 h-5 rounded border grid place-items-center flex-shrink-0 transition ${
                    entry.done ? "bg-emerald-500 border-emerald-600 text-white" : "bg-white border-stone-300 hover:border-emerald-500"
                  }`}
                  title={entry.done ? "Hecho" : "Marcar como hecho"}
                >
                  {entry.done && <Check size={11} strokeWidth={3} />}
                </button>
                <div className="flex-1 min-w-0">
                  <div className="flex items-baseline gap-1.5 flex-wrap">
                    <span className={`text-xs font-bold ${entry.done ? "line-through text-stone-500" : "text-stone-800"}`}>
                      {entry.date}
                    </span>
                    {entry.time && (
                      <span className={`font-mono text-xs ${entry.done ? "text-stone-400" : "text-stone-600"}`}>
                        {entry.time}
                      </span>
                    )}
                    {isOverdue && !entry.done && (
                      <span className="text-xs font-bold px-1.5 py-px rounded bg-red-200 text-red-800">Vencida</span>
                    )}
                    {isToday && !entry.done && (
                      <span className="text-xs font-bold px-1.5 py-px rounded bg-orange-200 text-orange-800">Hoy</span>
                    )}
                  </div>
                  {entry.note && (
                    <div className={`text-xs mt-0.5 ${entry.done ? "text-stone-400" : "text-stone-700"}`}>
                      {entry.note}
                    </div>
                  )}
                </div>
                <button
                  onClick={() => onRemove(entry.id)}
                  className="w-6 h-6 rounded-md bg-white border border-stone-200 hover:border-red-400 grid place-items-center text-stone-500 hover:text-red-600 flex-shrink-0"
                  title="Eliminar"
                >
                  <X size={10} />
                </button>
              </div>
            );
          })
        )}
      </div>
    </div>
  );
}

// ========== Modal: añadir entrada al calendario de seguimiento ==========
function AddFollowUpEntryModal({ kind, onClose, onSubmit }) {
  const [date, setDate] = useState(() => {
    const d = new Date();
    d.setDate(d.getDate() + 1);
    return d.toISOString().slice(0, 10);
  });
  const [time, setTime] = useState("09:00");
  const [note, setNote] = useState("");

  const isTreatment = kind === "tratamiento";

  return (
    <div onClick={onClose} className="fixed inset-0 bg-stone-900 z-50 flex justify-center items-center p-4">
      <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl w-full max-w-sm shadow-2xl overflow-hidden">
        <div className={`p-4 border-b border-stone-200 ${isTreatment ? "bg-amber-50" : "bg-orange-50"} flex items-center gap-3`}>
          <div className={`w-10 h-10 rounded-xl ${isTreatment ? "bg-amber-500" : "bg-orange-500"} text-white grid place-items-center shadow-lg flex-shrink-0`}>
            <CalendarPlus size={17} />
          </div>
          <div className="flex-1 min-w-0">
            <div className={`text-xs tracking-widest uppercase font-semibold ${isTreatment ? "text-amber-700" : "text-orange-700"}`}>
              Nueva visita programada
            </div>
            <h3 className="font-serif text-lg font-semibold mt-0.5">
              {isTreatment ? "Calendario de tratamiento" : "Calendario de seguimiento"}
            </h3>
          </div>
        </div>
        <div className="p-5 space-y-3">
          <div className="grid grid-cols-2 gap-2">
            <div>
              <label className="text-xs font-semibold text-stone-700 block mb-1.5">Fecha</label>
              <input
                type="date"
                value={date}
                onChange={(e) => setDate(e.target.value)}
                className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500 font-mono"
              />
            </div>
            <div>
              <label className="text-xs font-semibold text-stone-700 block mb-1.5">Hora</label>
              <input
                type="time"
                value={time}
                onChange={(e) => setTime(e.target.value)}
                className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500 font-mono"
              />
            </div>
          </div>
          <div>
            <label className="text-xs font-semibold text-stone-700 block mb-1.5">Descripción</label>
            <textarea
              value={note}
              onChange={(e) => setNote(e.target.value)}
              rows={2}
              placeholder={isTreatment ? "Ej: Aplicar Cefazolina 1g IV" : "Ej: Revisar herida quirúrgica, retirar puntos"}
              className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500 resize-none"
            />
          </div>
        </div>
        <div className="p-3 border-t border-stone-200 bg-stone-50 flex gap-2">
          <button onClick={onClose} className="flex-1 px-3 py-2 rounded-xl text-sm font-semibold bg-white border border-stone-200 hover:border-stone-400 text-stone-700">
            Cancelar
          </button>
          <button
            onClick={() => onSubmit({ date, time, note: note.trim(), kind })}
            disabled={!date}
            className={`flex-1 px-3 py-2 rounded-xl text-sm font-semibold text-white shadow transition ${
              date ? (isTreatment ? "bg-amber-500 hover:bg-amber-600" : "bg-orange-500 hover:bg-orange-600") : "bg-stone-200 text-stone-400 cursor-not-allowed"
            }`}
          >
            <Check size={12} className="inline" strokeWidth={2.5} /> Programar
          </button>
        </div>
      </div>
    </div>
  );
}

// ========== Modal: selector de insumos veterinarios usados ==========
function VetSupplyPickerModal({ supplies, onClose, onAdd }) {
  const [search, setSearch] = useState("");
  const [selectedId, setSelectedId] = useState(null);
  const [qty, setQty] = useState(1);

  const filtered = useMemo(() => {
    const active = supplies.filter(s => s.active !== false);
    if (!search.trim()) return active;
    const q = search.toLowerCase();
    return active.filter(s =>
      s.name.toLowerCase().includes(q) ||
      (s.category || "").toLowerCase().includes(q)
    );
  }, [supplies, search]);

  const selected = filtered.find(s => s.id === selectedId);

  return (
    <div onClick={onClose} className="fixed inset-0 bg-stone-900 z-50 flex justify-center items-center p-4">
      <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden flex flex-col max-h-screen">
        <div className="p-4 border-b border-stone-200 bg-emerald-50 flex items-center gap-3 flex-shrink-0">
          <div className="w-10 h-10 rounded-xl bg-emerald-500 text-white grid place-items-center shadow-lg flex-shrink-0">
            <Pill size={17} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase text-emerald-700 font-semibold">Insumo médico usado</div>
            <h3 className="font-serif text-lg font-semibold mt-0.5">Agregar a la consulta</h3>
          </div>
        </div>

        <div className="p-3 border-b border-stone-200 flex-shrink-0">
          <div className="relative">
            <Search size={13} className="absolute left-3 top-1/2 -translate-y-1/2 text-stone-400" />
            <input
              autoFocus
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder="Buscar medicamento, descartable, vacuna..."
              className="w-full pl-9 pr-3 py-2 bg-stone-50 border border-stone-200 rounded-xl text-sm outline-none focus:border-emerald-500"
            />
          </div>
        </div>

        <div className="flex-1 overflow-y-auto">
          {filtered.length === 0 ? (
            <div className="p-8 text-center text-sm text-stone-500">
              {supplies.length === 0
                ? "Aún no hay insumos en el catálogo. Pídele al super que los agregue."
                : "Sin coincidencias para tu búsqueda."}
            </div>
          ) : (
            <div className="p-2 space-y-1">
              {filtered.map(s => {
                const active = s.id === selectedId;
                return (
                  <button
                    key={s.id}
                    onClick={() => { setSelectedId(s.id); setQty(s.defaultQty || 1); }}
                    className={`w-full flex items-center gap-2 p-2 rounded-lg text-left transition ${
                      active ? "bg-emerald-50 border border-emerald-300 ring-1 ring-emerald-200" : "border border-transparent hover:bg-stone-50"
                    }`}
                  >
                    <div className="w-8 h-8 rounded-lg bg-emerald-50 text-emerald-700 grid place-items-center flex-shrink-0 border border-emerald-200">
                      <Pill size={13} />
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="font-semibold text-xs truncate">{s.name}</div>
                      <div className="text-xs text-stone-500">{s.category} · {s.defaultQty} {s.unit}</div>
                    </div>
                  </button>
                );
              })}
            </div>
          )}
        </div>

        {/* Footer con cantidad + confirmar */}
        {selected && (
          <div className="p-3 border-t border-stone-200 bg-stone-50 flex items-center gap-2 flex-shrink-0">
            <div className="flex items-center gap-1">
              <button onClick={() => setQty(Math.max(0.5, qty - 0.5))} className="w-7 h-7 rounded bg-white border border-stone-200 hover:border-stone-400 grid place-items-center text-stone-700">
                <Minus size={11} />
              </button>
              <input
                type="number" min="0" step="0.5"
                value={qty}
                onChange={(e) => setQty(Number(e.target.value))}
                className="w-14 text-center px-1 py-1 bg-white border border-stone-200 rounded text-xs font-mono"
              />
              <button onClick={() => setQty(qty + 0.5)} className="w-7 h-7 rounded bg-white border border-stone-200 hover:border-stone-400 grid place-items-center text-stone-700">
                <Plus size={11} />
              </button>
              <span className="text-xs text-stone-500 ml-1">{selected.unit}</span>
            </div>
            <button
              onClick={() => onAdd(selected, qty)}
              className="flex-1 px-3 py-2 rounded-lg bg-emerald-500 hover:bg-emerald-600 text-white text-xs font-semibold shadow"
            >
              <Check size={11} className="inline" strokeWidth={2.5} /> Agregar a la consulta
            </button>
          </div>
        )}
      </div>
    </div>
  );
}


// ========== FICHA CLÍNICA: card que adapta acciones según etapa ==========
// El drawer cambia de funciones según el estado del paciente:
//   reserva          → ficha mínima + "Entrar en consulta"
//   consulta         → insumos + "Confirmar consulta" (crea recibo, mueve a tratamiento_sede o finalizado)
//   tratamiento_sede → seguir agregando insumos a la recibo abierta + "Cerrar atención"
//   control          → calendario propio (controles, vacunas, revisiones)
//   finalizado       → resumen, recibo visible, opción de reabrir
// ========== PET EDITABLE SECTION (drawer del CRM Veterinaria) ==========
// Sección "Mascota" del drawer con botón "Editar" inline. Permite modificar
// los datos básicos del pasaporte (nombre, especie, raza, edad, sexo, peso,
// color, microchip) sin tener que abrir la ficha completa.
function PetEditableSection({ patient, passport, onUpdatePassport }) {
  const [editing, setEditing] = useState(false);
  const initial = {
    name: passport?.name || patient.name || "",
    species: passport?.species || patient.species || "dog",
    breed: passport?.breed || patient.breed || "",
    age: passport?.age || patient.age || "",
    gender: passport?.gender || patient.gender || "M",
    weight: passport?.weight || "",
    color: passport?.color || "",
    microchip: passport?.microchip || "",
  };
  const [draft, setDraft] = useState(initial);

  const handleStart = () => {
    setDraft(initial);
    setEditing(true);
  };
  const handleCancel = () => {
    setDraft(initial);
    setEditing(false);
  };
  const handleSave = () => {
    if (onUpdatePassport) onUpdatePassport(draft);
    setEditing(false);
  };

  const SPECIES_LABEL = {
    dog: "Perro", cat: "Gato", bird: "Ave", rabbit: "Conejo",
    fish: "Pez", rodent: "Roedor", other: "Otros",
  };
  const speciesDisplay = SPECIES_LABEL[draft.species] || draft.species;

  if (editing) {
    return (
      <div className="p-3 bg-stone-50">
        <div className="flex items-center justify-between mb-2">
          <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold">
            Mascota · Editando
          </div>
          <div className="flex gap-1.5">
            <button
              onClick={handleCancel}
              className="px-2 py-1 rounded-md text-[10px] font-semibold bg-white border border-stone-200 hover:border-stone-400 text-stone-700 transition"
            >
              Cancelar
            </button>
            <button
              onClick={handleSave}
              className="flex items-center gap-1 px-2 py-1 rounded-md text-[10px] font-semibold bg-orange-600 hover:bg-orange-700 text-white transition"
            >
              <Check size={10} /> Guardar
            </button>
          </div>
        </div>
        <div className="grid grid-cols-2 gap-2 text-xs">
          <div>
            <label className="text-stone-400 block leading-none mb-0.5">Nombre</label>
            <input
              value={draft.name}
              onChange={(e) => setDraft({ ...draft, name: e.target.value })}
              className="w-full px-2 py-1 bg-white border border-stone-200 rounded text-xs outline-none focus:border-orange-400"
            />
          </div>
          <div>
            <label className="text-stone-400 block leading-none mb-0.5">Especie</label>
            <select
              value={draft.species}
              onChange={(e) => setDraft({ ...draft, species: e.target.value })}
              className="w-full px-2 py-1 bg-white border border-stone-200 rounded text-xs outline-none focus:border-orange-400"
            >
              <option value="dog">Perro</option>
              <option value="cat">Gato</option>
              <option value="bird">Ave</option>
              <option value="rabbit">Conejo</option>
              <option value="fish">Pez</option>
              <option value="rodent">Roedor</option>
              <option value="other">Otros</option>
            </select>
          </div>
          <div>
            <label className="text-stone-400 block leading-none mb-0.5">Raza</label>
            <input
              value={draft.breed}
              onChange={(e) => setDraft({ ...draft, breed: e.target.value })}
              placeholder="Ej: Labrador"
              className="w-full px-2 py-1 bg-white border border-stone-200 rounded text-xs outline-none focus:border-orange-400 placeholder:text-stone-400"
            />
          </div>
          <div>
            <label className="text-stone-400 block leading-none mb-0.5">Edad</label>
            <input
              value={draft.age}
              onChange={(e) => setDraft({ ...draft, age: e.target.value })}
              placeholder="Ej: 3 años"
              className="w-full px-2 py-1 bg-white border border-stone-200 rounded text-xs outline-none focus:border-orange-400 placeholder:text-stone-400"
            />
          </div>
          <div>
            <label className="text-stone-400 block leading-none mb-0.5">Sexo</label>
            <select
              value={draft.gender}
              onChange={(e) => setDraft({ ...draft, gender: e.target.value })}
              className="w-full px-2 py-1 bg-white border border-stone-200 rounded text-xs outline-none focus:border-orange-400"
            >
              <option value="M">♂ Macho</option>
              <option value="F">♀ Hembra</option>
              <option value="U">Desconocido</option>
            </select>
          </div>
          <div>
            <label className="text-stone-400 block leading-none mb-0.5">Peso</label>
            <input
              value={draft.weight}
              onChange={(e) => setDraft({ ...draft, weight: e.target.value })}
              placeholder="Ej: 15 kg"
              className="w-full px-2 py-1 bg-white border border-stone-200 rounded text-xs outline-none focus:border-orange-400 placeholder:text-stone-400"
            />
          </div>
          <div>
            <label className="text-stone-400 block leading-none mb-0.5">Color</label>
            <input
              value={draft.color}
              onChange={(e) => setDraft({ ...draft, color: e.target.value })}
              placeholder="Capa o color"
              className="w-full px-2 py-1 bg-white border border-stone-200 rounded text-xs outline-none focus:border-orange-400 placeholder:text-stone-400"
            />
          </div>
          <div className="col-span-2">
            <label className="text-stone-400 block leading-none mb-0.5">Microchip</label>
            <input
              value={draft.microchip}
              onChange={(e) => setDraft({ ...draft, microchip: e.target.value })}
              placeholder="Número de microchip"
              className="w-full px-2 py-1 bg-white border border-stone-200 rounded text-xs outline-none focus:border-orange-400 placeholder:text-stone-400 font-mono"
            />
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="p-3 bg-stone-50">
      <div className="flex items-center justify-between mb-2">
        <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold">
          Mascota
        </div>
        {onUpdatePassport && (
          <button
            onClick={handleStart}
            title="Editar datos de la mascota"
            className="flex items-center gap-1 px-2 py-1 rounded-md text-[10px] font-semibold bg-white border border-stone-200 hover:border-orange-400 hover:text-orange-700 text-stone-600 transition"
          >
            <Edit3 size={10} /> Editar
          </button>
        )}
      </div>
      <div className="grid grid-cols-2 gap-y-1.5 gap-x-3 text-xs">
        <div>
          <span className="text-stone-400 block leading-none">Nombre</span>
          <span className="font-semibold text-stone-800">{patient.name}</span>
        </div>
        <div>
          <span className="text-stone-400 block leading-none">Especie · Raza</span>
          <span className="font-semibold text-stone-800">
            {speciesDisplay}
            {patient.breed && ` · ${patient.breed}`}
          </span>
        </div>
        {patient.age && (
          <div>
            <span className="text-stone-400 block leading-none">Edad</span>
            <span className="font-semibold text-stone-800">{patient.age}</span>
          </div>
        )}
        {(passport?.gender || patient.gender) && (
          <div>
            <span className="text-stone-400 block leading-none">Sexo</span>
            <span className="font-semibold text-stone-800">
              {((passport?.gender || patient.gender) === "M" || (passport?.gender || patient.gender) === "macho") ? "♂ Macho" :
               ((passport?.gender || patient.gender) === "F" || (passport?.gender || patient.gender) === "hembra") ? "♀ Hembra" : "—"}
            </span>
          </div>
        )}
        {passport?.weight && (
          <div>
            <span className="text-stone-400 block leading-none">Peso</span>
            <span className="font-semibold text-stone-800">{passport.weight}</span>
          </div>
        )}
        {passport?.color && (
          <div>
            <span className="text-stone-400 block leading-none">Color</span>
            <span className="font-semibold text-stone-800">{passport.color}</span>
          </div>
        )}
        {passport?.microchip && (
          <div className="col-span-2">
            <span className="text-stone-400 block leading-none">Microchip</span>
            <span className="font-mono text-stone-800">{passport.microchip}</span>
          </div>
        )}
      </div>
    </div>
  );
}

function VetPatientCard({
  patient,
  forceReservationView = false,
  onClose,
  onMinimize,
  onOpenVetPassport,
  canAccessVetPassport,
  vetSupplies = [],
  onAdvance,
  onUpdateSupplies,
  onUpdateNotes,
  onPersistHistory,
  followUpEntries = [],
  onAddFollowUp,
  onToggleFollowUpDone,
  onRemoveFollowUp,
  activeInvoiceId,
  onUpsertInvoice,
  onCloseInvoice,
  onGoToSales,
  invoice,
  invoices = [],
  passport = null,
  clients = [],
  canMessage = false,
  conversation = [],
  onSendMessage,
  userRole = "vet",
  permissions = {},
  onUpdatePassport,
}) {
  const [showSupplyPicker, setShowSupplyPicker] = useState(false);
  const [showConfirmConsult, setShowConfirmConsult] = useState(false);
  const [showAddFollowUp, setShowAddFollowUp] = useState(false);
  const [showHistoryViewer, setShowHistoryViewer] = useState(false); // ventana flotante con historial

  // Helper de permisos por campo en el CRM "vet".
  // IMPORTANTE: las secciones "tutor", "pet" y "messaging" son conceptos transversales
  // del módulo Clientes — se consultan contra el CRM "clients" para que cambiar permisos
  // del tutor o del chat en Clientes aplique también dentro de Veterinaria. Las secciones
  // específicas del vet (clinical, billing) sí se consultan contra "vet".
  const fieldLevel = (sectionId, fieldId) => {
    const transversal = (sectionId === "tutor" || sectionId === "pet" || sectionId === "messaging");
    const targetCrm = transversal ? "clients" : "vet";
    const targetSection = (targetCrm === "clients" && sectionId === "pet") ? "pets" : sectionId;
    return getFieldLevel(permissions, userRole, targetCrm, targetSection, fieldId);
  };
  const showField = (sectionId, fieldId) => fieldLevel(sectionId, fieldId) !== "hidden";

  // Si abrimos desde Reserva, forzamos UI de reserva (botón "Entrar en consulta", sin recibo).
  // Esto cubre el caso donde el paciente tiene status legacy 'consulta' en VET_PATIENTS pero
  // su cita del día sigue pendiente — el vet aún no lo ha marcado como llegado.
  const status = forceReservationView ? "reserva" : (patient.status || "consulta");
  const supplies = patient._suppliesUsed || [];
  const notes = patient._notes || "";

  // === Resolver cliente/tutor de la mascota ===
  // Prioridad: 1) match por petCode en clients[].petCodes  2) fallback por nombre del owner
  const tutorClient = useMemo(() => {
    if (!patient) return null;
    if (patient.code) {
      const byCode = clients.find(c => Array.isArray(c.petCodes) && c.petCodes.includes(patient.code));
      if (byCode) return byCode;
    }
    if (patient.owner) {
      const byName = clients.find(c => c.name === patient.owner);
      if (byName) return byName;
    }
    return null;
  }, [patient, clients]);

  const tutorInitials = tutorClient
    ? tutorClient.name.split(" ").slice(0, 2).map(s => s[0]).join("").toUpperCase()
    : (patient.owner || "??").split(" ").slice(0, 2).map(s => s[0]).join("").toUpperCase();

  // Cuando se actualizan insumos, también re-sincronizar la recibo activa
  const updateSuppliesAndInvoice = (newSupplies) => {
    onUpdateSupplies(newSupplies);
    if (activeInvoiceId && onUpsertInvoice) {
      onUpsertInvoice(newSupplies, { includeConsultation: true });
    }
  };

  // Confirmar consulta:
  //  - Si NO hay tratamiento adicional → crear/finalizar recibo, mover a "finalizado"
  //  - Si hay tratamiento → mantener recibo abierta, mover a "tratamiento_sede"
  // En ambos casos, las notas clínicas escritas durante la consulta se persisten
  // en el historial del pasaporte (clinicHistory).
  const handleConfirmConsultation = (needsTreatment) => {
    onUpsertInvoice && onUpsertInvoice(supplies, { includeConsultation: true });
    setShowConfirmConsult(false);
    if (needsTreatment) {
      // El paciente queda hospitalizado/en tratamiento. Recibo sigue abierta para añadir más.
      // Las notas se persistirán cuando se cierre la atención total.
      onAdvance("tratamiento_sede", { startedAt: new Date().toISOString() });
    } else {
      // Atención cerrada. Persistir notas + supplies en historial.
      onPersistHistory && onPersistHistory(notes, supplies);
      onAdvance("finalizado", { closedAt: new Date().toISOString() });
      onCloseInvoice && onCloseInvoice();
    }
  };

  const closeTreatment = () => {
    // Cerrar tratamiento en sede: persistir notas + supplies en historial y finalizar.
    onPersistHistory && onPersistHistory(notes, supplies);
    onAdvance("finalizado", { closedAt: new Date().toISOString() });
    onCloseInvoice && onCloseInvoice();
  };

  // === Estado de ventana flotante (dots macOS, draggable, maximizable) ===
  // La minimización la maneja el padre (cola de hasta 3 minimizadas).
  const [position, setPosition] = useState({ x: 100, y: 30 });
  const [size, setSize] = useState({ w: 1100, h: 660 });
  const [maximized, setMaximized] = useState(false);
  const prevState = useRef({ position, size });

  // === Layout móvil ===
  const isMobile = useIsMobile();
  const [mobileTab, setMobileTab] = useState("ficha"); // "chat" | "ficha"

  const onDragStart = (e) => {
    if (maximized) return;
    if (e.target.closest("button")) return;
    const startX = e.clientX, startY = e.clientY;
    const startPos = { ...position };
    const handleMove = (ev) => {
      setPosition({
        x: Math.max(0, startPos.x + (ev.clientX - startX)),
        y: Math.max(0, startPos.y + (ev.clientY - startY)),
      });
    };
    const handleUp = () => {
      window.removeEventListener("mousemove", handleMove);
      window.removeEventListener("mouseup", handleUp);
    };
    window.addEventListener("mousemove", handleMove);
    window.addEventListener("mouseup", handleUp);
  };

  const toggleMaximize = () => {
    if (maximized) {
      setPosition(prevState.current.position);
      setSize(prevState.current.size);
      setMaximized(false);
    } else {
      prevState.current = { position, size };
      setPosition({ x: 16, y: 16 });
      setSize({
        w: typeof window !== "undefined" ? window.innerWidth - 32 : 1200,
        h: typeof window !== "undefined" ? window.innerHeight - 32 : 720,
      });
      setMaximized(true);
    }
  };

  // === Estado del chat (cuando hay tutor identificado) ===
  const [chatDraft, setChatDraft] = useState("");
  const [chatChannel, setChatChannel] = useState("whatsapp");
  // Ancho del panel de chat (columna izquierda). Es ajustable arrastrando el
  // divisor entre el chat y la ficha clínica. Se mantiene dentro de un rango
  // razonable para que ninguno de los dos paneles quede inutilizable.
  const CHAT_MIN_W = 280;
  const CHAT_MAX_W = 720;
  const [chatPanelW, setChatPanelW] = useState(380);
  // Menú "+" del composer del chat (adjuntar foto / recibo) y sus modales.
  const [showChatAttachMenu, setShowChatAttachMenu] = useState(false);
  const [showChatImagePicker, setShowChatImagePicker] = useState(false);
  const [showChatInvoicePicker, setShowChatInvoicePicker] = useState(false);

  // Drag del divisor: ajusta chatPanelW siguiendo el cursor. Se calcula contra
  // el borde izquierdo del cuerpo (el contenedor de las 2 columnas).
  const onDividerDragStart = (e) => {
    e.preventDefault();
    const startX = e.clientX;
    const startW = chatPanelW;
    const handleMove = (ev) => {
      const next = startW + (ev.clientX - startX);
      setChatPanelW(Math.max(CHAT_MIN_W, Math.min(CHAT_MAX_W, next)));
    };
    const handleUp = () => {
      window.removeEventListener("mousemove", handleMove);
      window.removeEventListener("mouseup", handleUp);
      document.body.style.cursor = "";
      document.body.style.userSelect = "";
    };
    document.body.style.cursor = "col-resize";
    document.body.style.userSelect = "none";
    window.addEventListener("mousemove", handleMove);
    window.addEventListener("mouseup", handleUp);
  };

  const channelMessages = useMemo(
    () => (conversation || []).filter(m => m.channel === chatChannel),
    [conversation, chatChannel]
  );
  const channelStats = useMemo(() => {
    const m = {};
    (conversation || []).forEach(msg => { m[msg.channel] = (m[msg.channel] || 0) + 1; });
    return m;
  }, [conversation]);
  // Permiso de enviar recibo por chat — específico del CRM Veterinaria.
  // A diferencia de "messaging" (transversal vía Clientes), este se resuelve
  // contra el CRM "vet": cada CRM controla su propio envío de recibos.
  const canSendInvoice = showField("billing", "send-invoice");

  const handleChatSend = () => {
    if (!chatDraft.trim() || !tutorClient || !onSendMessage) return;
    onSendMessage(tutorClient.id, chatChannel, chatDraft.trim());
    setChatDraft("");
  };
  // Enviar adjunto desde el chat de la ficha: imagen o recibo. Reutiliza la
  // misma firma extendida de onSendMessage que el módulo de Mensajes
  // (4º argumento { attachment: ... }).
  const handleChatSendImage = (imageDataUrl, caption = "") => {
    if (!tutorClient || !onSendMessage) return;
    const body = caption || "📎 Imagen adjunta";
    onSendMessage(tutorClient.id, chatChannel, body, {
      attachment: { type: "image", url: imageDataUrl, caption },
    });
    setShowChatImagePicker(false);
    setShowChatAttachMenu(false);
  };
  const handleChatSendInvoice = (inv, messageText = null) => {
    if (!tutorClient || !onSendMessage) return;
    // Defensa en profundidad: aunque la opción esté oculta sin permiso, no
    // enviamos la recibo si el rol no tiene "send-invoice" en el CRM vet.
    if (!canSendInvoice) return;
    if (messageText) {
      onSendMessage(tutorClient.id, chatChannel, messageText);
    }
    const body = `📄 Recibo ${inv.number} · $${(inv.total ?? 0).toFixed(2)}`;
    onSendMessage(tutorClient.id, chatChannel, body, {
      attachment: { type: "invoice", invoiceId: inv.id },
    });
    setShowChatInvoicePicker(false);
    setShowChatAttachMenu(false);
  };
  const handleChatKeyDown = (e) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleChatSend();
    }
  };

  return (
    <>
      <div
        className={isMobile
          ? "fixed inset-0 z-50 bg-stone-50 flex flex-col overflow-hidden"
          : "fixed z-50 bg-stone-50 rounded-2xl shadow-2xl flex flex-col border border-stone-300 overflow-hidden"
        }
        style={isMobile ? undefined : {
          left: position.x,
          top: position.y,
          width: size.w,
          height: size.h,
          maxWidth: "calc(100vw - 16px)",
          maxHeight: "calc(100vh - 16px)",
        }}
      >
        {/* Title bar (en móvil sin drag/maximize, solo cerrar y minimizar) */}
        <div
          onMouseDown={isMobile ? undefined : onDragStart}
          onDoubleClick={isMobile ? undefined : toggleMaximize}
          className={`px-3 py-2 bg-gradient-to-r from-stone-800 to-stone-900 text-white flex items-center gap-2 flex-shrink-0 ${
            isMobile ? "cursor-default" : (maximized ? "cursor-default" : "cursor-move")
          } select-none`}
        >
          {isMobile ? (
            <>
              <button
                onClick={(e) => { e.stopPropagation(); onClose(); }}
                className="w-8 h-8 rounded-lg hover:bg-stone-700 grid place-items-center text-white -ml-1"
                title="Cerrar"
              >
                <X size={16} />
              </button>
              {onMinimize && (
                <button
                  onClick={(e) => { e.stopPropagation(); onMinimize(); }}
                  className="w-8 h-8 rounded-lg hover:bg-stone-700 grid place-items-center text-white"
                  title="Minimizar"
                >
                  <Minus size={16} />
                </button>
              )}
            </>
          ) : (
            <div className="flex items-center gap-1.5 mr-1">
              <button onClick={(e) => { e.stopPropagation(); onClose(); }} title="Cerrar"
                className="w-3 h-3 rounded-full bg-red-400 hover:bg-red-500 transition"></button>
              <button onClick={(e) => { e.stopPropagation(); onMinimize ? onMinimize() : onClose(); }} title="Minimizar"
                className="w-3 h-3 rounded-full bg-amber-400 hover:bg-amber-500 transition"></button>
              <button onClick={(e) => { e.stopPropagation(); toggleMaximize(); }} title={maximized ? "Restaurar" : "Maximizar"}
                className="w-3 h-3 rounded-full bg-emerald-400 hover:bg-emerald-500 transition"></button>
            </div>
          )}
          <Stethoscope size={13} className="text-orange-400 flex-shrink-0" />
          <span className="text-xs font-semibold flex-1 truncate uppercase tracking-wider">
            Servicio · {patient.name}
            {tutorClient && !isMobile && <span className="text-stone-400 normal-case tracking-normal ml-2">· {tutorClient.name}</span>}
          </span>
        </div>

        {/* En móvil: tabs Ficha / Chat */}
        {isMobile && tutorClient && onSendMessage && showField("messaging", "chat-read") && (
          <div className="flex bg-white border-b border-stone-200 flex-shrink-0">
            <button
              onClick={() => setMobileTab("ficha")}
              className={`flex-1 py-2.5 text-xs font-bold uppercase tracking-wider transition flex items-center justify-center gap-1.5 ${
                mobileTab === "ficha" ? "text-orange-700 border-b-2 border-orange-600 bg-orange-50" : "text-stone-500 border-b-2 border-transparent"
              }`}
            >
              <Stethoscope size={12} strokeWidth={2.2} /> Ficha clínica
            </button>
            <button
              onClick={() => setMobileTab("chat")}
              className={`flex-1 py-2.5 text-xs font-bold uppercase tracking-wider transition flex items-center justify-center gap-1.5 ${
                mobileTab === "chat" ? "text-orange-700 border-b-2 border-orange-600 bg-orange-50" : "text-stone-500 border-b-2 border-transparent"
              }`}
            >
              <MessageCircle size={12} strokeWidth={2.2} /> Chat
              {(conversation || []).filter(m => m.direction === "in" && m.status !== "read").length > 0 && (
                <span className="text-xs font-bold px-1.5 py-px rounded-full bg-orange-600 text-white">
                  {(conversation || []).filter(m => m.direction === "in" && m.status !== "read").length}
                </span>
              )}
            </button>
          </div>
        )}

        {/* Cuerpo: en desktop = 2 columnas, en móvil = panel activo */}
        <div className={`flex-1 overflow-hidden ${isMobile ? "flex flex-col" : "flex"}`}>

          {/* === Panel chat (izquierda) — solo si hay tutor identificado === */}
          {tutorClient && onSendMessage && showField("messaging", "chat-read") && (!isMobile || mobileTab === "chat") && (
            <div
              className={isMobile
                ? "flex-1 flex flex-col bg-white overflow-hidden"
                : "flex flex-col bg-white flex-shrink-0"
              }
              style={isMobile ? undefined : { width: chatPanelW }}
            >
              {/* Header del tutor */}
              <div className="p-3 border-b border-stone-200 bg-gradient-to-r from-white to-orange-50 flex items-center gap-2 flex-shrink-0">
                <div className={`w-9 h-9 rounded-full grid place-items-center text-white text-xs font-bold flex-shrink-0 ${
                  tutorClient.isOrg ? "bg-gradient-to-br from-stone-700 to-stone-900" : "bg-gradient-to-br from-orange-500 to-orange-700"
                }`}>
                  {tutorInitials}
                </div>
                <div className="flex-1 min-w-0">
                  <div className="font-semibold text-xs truncate">{tutorClient.name}</div>
                  {showField("tutor", "phone") && tutorClient.phone && (
                    <div className="text-xs text-stone-500 truncate font-mono">{tutorClient.phone}</div>
                  )}
                </div>
                {!canMessage && (
                  <span title="Mensajería deshabilitada para tu rol" className="text-stone-400">
                    <Lock size={11} />
                  </span>
                )}
              </div>

              {/* Tabs de canal */}
              <div className="flex gap-0.5 px-2 pt-2 bg-stone-50 border-b border-stone-200 overflow-x-auto flex-shrink-0">
                {Object.entries(CHAT_CHANNELS).map(([id, info]) => {
                  const Icon = info.icon;
                  const active = chatChannel === id;
                  const count = channelStats[id] || 0;
                  const colors = CHAT_CHANNEL_CLASSES[info.color];
                  return (
                    <button
                      key={id}
                      onClick={() => setChatChannel(id)}
                      className={`flex items-center gap-1.5 px-3 py-1.5 text-xs font-semibold rounded-t-lg transition border-b-2 flex-shrink-0 ${
                        active ? `bg-white ${colors.text} border-current` : "text-stone-500 hover:text-stone-700 border-transparent"
                      }`}
                    >
                      <Icon size={11} strokeWidth={1.8} />
                      {info.label}
                      {count > 0 && (
                        <span className={`text-xs font-bold px-1.5 py-px rounded-full ${
                          active ? colors.bg : "bg-stone-200 text-stone-600"
                        }`}>{count}</span>
                      )}
                    </button>
                  );
                })}
              </div>

              {/* Mensajes */}
              <div className="flex-1 overflow-y-auto p-3 space-y-2 bg-stone-50">
                {channelMessages.length === 0 ? (
                  <div className="flex flex-col items-center justify-center h-full text-stone-400">
                    <MessageCircle size={28} className="mb-2 opacity-30" />
                    <span className="text-xs">No hay mensajes en este canal todavía.</span>
                    <span className="text-xs mt-0.5">Escribe el primero abajo.</span>
                  </div>
                ) : (
                  channelMessages.map(msg => (
                    <div key={msg.id} className={`flex ${msg.direction === "out" ? "justify-end" : "justify-start"}`}>
                      <div className={`max-w-xs rounded-2xl px-3 py-1.5 text-xs ${
                        msg.direction === "out"
                          ? "bg-orange-600 text-white rounded-br-md"
                          : "bg-white border border-stone-200 text-stone-800 rounded-bl-md"
                      }`}>
                        <div className="leading-relaxed">{msg.body}</div>
                        <div className={`text-xs mt-0.5 flex items-center gap-1 ${
                          msg.direction === "out" ? "text-orange-100 justify-end" : "text-stone-400"
                        }`}>
                          <span className="font-mono opacity-80">
                            {new Date(msg.timestamp).toLocaleTimeString("es", { hour: "2-digit", minute: "2-digit" })}
                          </span>
                          {msg.direction === "out" && msg.status && (
                            <span className="ml-0.5">
                              {msg.status === "sent" && "✓"}
                              {msg.status === "delivered" && "✓✓"}
                              {msg.status === "read" && <span className="text-emerald-300">✓✓</span>}
                            </span>
                          )}
                        </div>
                      </div>
                    </div>
                  ))
                )}
              </div>

              {/* Composer */}
              <div className="p-2 border-t border-stone-200 bg-white flex-shrink-0 flex items-end gap-2">
                {/* Botón "+" para adjuntar foto o recibo (mismo patrón que el
                    módulo de Mensajes). Solo activo si el rol puede enviar. */}
                <div className="relative flex-shrink-0">
                  <button
                    onClick={() => setShowChatAttachMenu(v => !v)}
                    disabled={!canMessage}
                    title="Adjuntar"
                    className={`w-9 h-9 rounded-xl grid place-items-center transition ${
                      !canMessage
                        ? "bg-stone-100 text-stone-300 cursor-not-allowed"
                        : showChatAttachMenu
                          ? "bg-orange-500 text-white rotate-45"
                          : "bg-stone-100 hover:bg-stone-200 text-stone-600"
                    }`}
                  >
                    <Plus size={14} />
                  </button>
                  {showChatAttachMenu && canMessage && (
                    <>
                      <div onClick={() => setShowChatAttachMenu(false)} className="fixed inset-0 z-30"></div>
                      <div className="absolute left-0 bottom-full mb-2 w-56 bg-white border border-stone-200 rounded-xl shadow-2xl z-40 overflow-hidden">
                        <button
                          onClick={() => { setShowChatAttachMenu(false); setShowChatImagePicker(true); }}
                          className={`w-full flex items-start gap-2.5 p-3 hover:bg-orange-50 transition text-left ${
                            canSendInvoice ? "border-b border-stone-100" : ""
                          }`}
                        >
                          <div className="w-8 h-8 rounded-lg bg-blue-100 text-blue-700 grid place-items-center flex-shrink-0">
                            <Camera size={13} />
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="font-semibold text-sm">Foto</div>
                            <div className="text-xs text-stone-500 leading-snug">
                              Sube una imagen desde tu equipo.
                            </div>
                          </div>
                        </button>
                        {/* "Recibo" solo si el rol tiene el permiso de enviar
                            recibo por chat en el CRM Veterinaria. Si no, el menú
                            solo ofrece Foto. */}
                        {canSendInvoice && (
                          <button
                            onClick={() => { setShowChatAttachMenu(false); setShowChatInvoicePicker(true); }}
                            className="w-full flex items-start gap-2.5 p-3 hover:bg-orange-50 transition text-left"
                          >
                            <div className="w-8 h-8 rounded-lg bg-orange-100 text-orange-700 grid place-items-center flex-shrink-0">
                              <Receipt size={13} />
                            </div>
                            <div className="flex-1 min-w-0">
                              <div className="font-semibold text-sm">Recibo</div>
                              <div className="text-xs text-stone-500 leading-snug">
                                Comparte cualquier recibo existente.
                              </div>
                            </div>
                          </button>
                        )}
                      </div>
                    </>
                  )}
                </div>
                <textarea
                  value={chatDraft}
                  onChange={(e) => setChatDraft(e.target.value)}
                  onKeyDown={handleChatKeyDown}
                  placeholder={canMessage ? `Mensaje por ${CHAT_CHANNELS[chatChannel]?.label || chatChannel}…` : "Mensajería deshabilitada para tu rol"}
                  rows={1}
                  disabled={!canMessage}
                  className="flex-1 resize-none px-3 py-2 bg-stone-50 border border-stone-200 rounded-xl text-xs outline-none focus:border-orange-400 focus:bg-white transition disabled:opacity-50"
                  style={{ maxHeight: 80 }}
                />
                <button
                  onClick={handleChatSend}
                  disabled={!chatDraft.trim() || !canMessage}
                  className={`w-9 h-9 rounded-xl grid place-items-center transition flex-shrink-0 ${
                    chatDraft.trim() && canMessage
                      ? "bg-orange-600 hover:bg-orange-700 text-white shadow"
                      : "bg-stone-200 text-stone-400 cursor-not-allowed"
                  }`}
                  title="Enviar mensaje"
                >
                  <Send size={13} strokeWidth={2.2} />
                </button>
              </div>
            </div>
          )}

          {/* === Divisor arrastrable entre chat y ficha (solo desktop) ===
              Permite ampliar el chat o la ficha según haga falta. Se muestra
              únicamente cuando el panel de chat está visible. */}
          {!isMobile && tutorClient && onSendMessage && showField("messaging", "chat-read") && (
            <div
              onMouseDown={onDividerDragStart}
              onDoubleClick={() => setChatPanelW(380)}
              title="Arrastra para ajustar · doble clic para restablecer"
              className="group relative w-1.5 flex-shrink-0 cursor-col-resize bg-stone-200 hover:bg-orange-400 transition-colors"
            >
              {/* Zona de agarre más ancha que la línea visible, para que sea
                  fácil de tomar sin que ocupe espacio visual. */}
              <div className="absolute inset-y-0 -left-1.5 -right-1.5"></div>
              {/* Indicador visual de "grip" centrado */}
              <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 flex flex-col gap-0.5 opacity-40 group-hover:opacity-100 transition-opacity">
                <span className="w-0.5 h-0.5 rounded-full bg-stone-600 group-hover:bg-white"></span>
                <span className="w-0.5 h-0.5 rounded-full bg-stone-600 group-hover:bg-white"></span>
                <span className="w-0.5 h-0.5 rounded-full bg-stone-600 group-hover:bg-white"></span>
              </div>
            </div>
          )}

          {/* === Panel ficha clínica (derecha en desktop / tab "ficha" en móvil) === */}
          {(!isMobile || mobileTab === "ficha" || !tutorClient || !onSendMessage || !showField("messaging", "chat-read")) && (
          <div className="flex-1 min-w-0 bg-stone-50 flex flex-col overflow-hidden">
            {/* Header del paciente (avatar mascota + nombre + status) */}
            <div className="p-4 bg-white border-b border-stone-200 flex items-start gap-3 flex-shrink-0">
              <PetAvatar species={patient.species} />
              <div className="flex-1 min-w-0">
                <div className="flex items-baseline gap-2 flex-wrap">
                  <h2 className="font-serif text-xl font-bold leading-tight">{patient.name}</h2>
                  {patient.code && (
                    <span className="font-mono text-xs font-bold text-orange-700 bg-orange-50 px-2 py-px rounded border border-orange-200">
                      #{patient.code}
                </span>
              )}
            </div>
            <div className="text-xs text-stone-600 mt-0.5">
              {patient.breed} · {patient.age} · Tutor: {patient.owner}
            </div>
            <div className="mt-1.5">
              <StatusBadge status={status} />
            </div>
          </div>
        </div>

        {/* Body con scroll */}
        <div className="flex-1 overflow-y-auto p-4 space-y-3">

          {/* === FICHA DE SERVICIO: Tutor + Mascota === */}
          {/* Visible siempre en cualquier etapa para que el vet tenga contexto rápido del cliente
              y pueda contactar al tutor (si tiene permiso de mensajería). */}
          <div className="bg-white border border-stone-200 rounded-xl overflow-hidden">
            {/* Tutor */}
            <div className="p-3 border-b border-stone-100">
              <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold mb-2 flex items-center justify-between">
                <span>Tutor</span>
                {showField("tutor", "segment") && tutorClient?.segment && (
                  <span className={`text-xs font-bold px-1.5 py-0.5 rounded ${
                    tutorClient.segment === "Premium" ? "bg-purple-100 text-purple-700" :
                    tutorClient.segment === "Frecuente" ? "bg-blue-100 text-blue-700" :
                    tutorClient.segment === "Nuevo" ? "bg-emerald-100 text-emerald-700" :
                    "bg-stone-100 text-stone-700"
                  }`}>
                    {tutorClient.segment}
                  </span>
                )}
              </div>
              <div className="flex items-start gap-3">
                <div className={`w-11 h-11 rounded-xl grid place-items-center text-white text-xs font-bold flex-shrink-0 ${
                  tutorClient?.isOrg ? "bg-gradient-to-br from-stone-700 to-stone-900" : "bg-gradient-to-br from-orange-500 to-orange-700"
                }`}>
                  {tutorInitials}
                </div>
                <div className="flex-1 min-w-0">
                  {showField("tutor", "name") && (
                    <div className="font-semibold text-sm text-stone-900 leading-tight">
                      {tutorClient?.name || patient.owner || "Tutor sin registrar"}
                    </div>
                  )}
                  {tutorClient ? (() => {
                    const visibleAdmin = ["cedula", "phone", "email", "address"].filter(f => showField("tutor", f));
                    if (visibleAdmin.length === 0) {
                      return (
                        <div className="mt-1 text-xs text-stone-400 italic flex items-center gap-1.5">
                          <Lock size={10} /> Datos administrativos restringidos
                        </div>
                      );
                    }
                    return (
                      <div className="mt-1 space-y-0.5 text-xs text-stone-600">
                        {showField("tutor", "cedula") && tutorClient.cedula && (
                          <div className="font-mono">{tutorClient.cedula}</div>
                        )}
                        {showField("tutor", "phone") && tutorClient.phone && (
                          <div className="flex items-center gap-1.5">
                            <Phone size={10} className="text-stone-400 flex-shrink-0" />
                            <span className="font-mono">{tutorClient.phone}</span>
                          </div>
                        )}
                        {showField("tutor", "email") && tutorClient.email && (
                          <div className="flex items-center gap-1.5 truncate">
                            <Mail size={10} className="text-stone-400 flex-shrink-0" />
                            <span className="truncate">{tutorClient.email}</span>
                          </div>
                        )}
                        {showField("tutor", "address") && tutorClient.address && (
                          <div className="flex items-center gap-1.5 truncate">
                            <MapPin size={10} className="text-stone-400 flex-shrink-0" />
                            <span className="truncate">{tutorClient.address}</span>
                          </div>
                        )}
                      </div>
                    );
                  })() : (
                    <div className="mt-1 text-xs text-stone-400 italic">
                      Datos administrativos pendientes (los completará ventas).
                    </div>
                  )}
                  {tutorClient && (tutorClient.totalSpent || tutorClient.lastVisit) && (
                    <div className="mt-2 pt-2 border-t border-stone-100 flex items-center gap-3 text-xs">
                      {typeof tutorClient.totalSpent === "number" && (
                        <span className="text-stone-500">
                          Histórico: <strong className="text-stone-800 font-mono">${tutorClient.totalSpent.toLocaleString()}</strong>
                        </span>
                      )}
                      {tutorClient.lastVisit && (
                        <span className="text-stone-500">Visita: {tutorClient.lastVisit}</span>
                      )}
                    </div>
                  )}
                </div>
              </div>

              {/* Si hay tutor pero no chat (sin onSendMessage o sin permiso), aviso compacto */}
              {tutorClient && !onSendMessage && (
                <div className="mt-2 text-xs text-stone-400 italic flex items-center gap-1.5">
                  <Lock size={10} /> Chat no disponible en este contexto
                </div>
              )}
            </div>

            {/* Mascota */}
            <PetEditableSection
              patient={patient}
              passport={passport}
              onUpdatePassport={canEditField("clinical", "edit-pet") ? onUpdatePassport : null}
            />
          </div>

          {/* === RESERVA === */}
          {status === "reserva" && (
            <>
              <div className="bg-white border border-stone-200 rounded-xl p-3 text-sm text-stone-700">
                <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold mb-1">
                  Cita reservada
                </div>
                <p>
                  Cuando llegue {patient.name}, presiona <strong>Entrar en consulta</strong> para iniciar la atención.
                </p>
              </div>
              <button
                onClick={() => onOpenVetPassport && onOpenVetPassport(patient.code)}
                disabled={!canAccessVetPassport}
                className={`w-full flex items-center justify-center gap-2 px-4 py-3 rounded-xl text-sm font-semibold transition border ${
                  canAccessVetPassport
                    ? "bg-white hover:bg-orange-50 text-stone-700 border-stone-200 hover:border-orange-300"
                    : "bg-stone-100 text-stone-400 border-stone-200 cursor-not-allowed"
                }`}
              >
                <BookOpen size={14} /> Ver ficha clínica
              </button>
              <button
                onClick={() => onAdvance("consulta", { startedAt: new Date().toISOString() })}
                className="w-full flex items-center justify-center gap-2 px-4 py-3 rounded-xl text-sm font-semibold bg-blue-600 hover:bg-blue-700 text-white shadow transition"
              >
                <PlayCircle size={15} strokeWidth={2.2} /> Entrar en consulta
              </button>
            </>
          )}

          {/* === CONSULTA + TRATAMIENTO EN SEDE === */}
          {/* Mismo bloque para ambos: insumos + recibo activa. La diferencia es el botón final. */}
          {(status === "consulta" || status === "tratamiento_sede") && (
            <>
              <div className="grid grid-cols-2 gap-2">
                <button
                  onClick={() => setShowHistoryViewer(true)}
                  className="flex items-center justify-center gap-1.5 px-3 py-2 rounded-xl text-sm font-semibold bg-stone-900 hover:bg-stone-800 text-white shadow transition"
                  title="Ver consultas anteriores en ventana flotante"
                >
                  <History size={13} /> Consultas anteriores
                </button>
                <button
                  onClick={() => onOpenVetPassport && onOpenVetPassport(patient.code)}
                  disabled={!canAccessVetPassport}
                  className={`flex items-center justify-center gap-1.5 px-3 py-2 rounded-xl text-sm font-semibold transition border ${
                    canAccessVetPassport
                      ? "bg-white hover:bg-orange-50 text-stone-700 border-stone-200 hover:border-orange-300"
                      : "bg-stone-100 text-stone-400 border-stone-200 cursor-not-allowed"
                  }`}
                >
                  <BookOpen size={13} /> Ficha completa
                </button>
              </div>

              {/* Indicador de tratamiento activo */}
              {status === "tratamiento_sede" && (
                <div className="bg-amber-50 border border-amber-200 rounded-xl p-3 text-sm text-amber-900">
                  <div className="font-semibold flex items-center gap-1.5 text-xs tracking-widest uppercase mb-1">
                    <Activity size={11} className="animate-pulse" /> Tratamiento en curso
                  </div>
                  <p className="text-xs">
                    El paciente está hospitalizado. Sigue agregando insumos a la recibo abierta hasta cerrar la atención.
                  </p>
                </div>
              )}

              {/* Notas clínicas estructuradas — un slot por sección.
                  Cada campo se persiste independientemente en el state del paciente.
                  Al cerrar la atención, todos los slots con contenido se guardan en clinicHistory. */}
              <ClinicalNotesEditor
                patientName={patient.name}
                notes={notes}
                onChangeField={(field, value) => {
                  if (!onUpdateNotes) return;
                  onUpdateNotes({ ...notes, [field]: value });
                }}
              />

              {/* Insumos usados */}
              <div className="bg-white border border-stone-200 rounded-xl overflow-hidden">
                <div className="p-3 border-b border-stone-200 bg-stone-50 flex items-center justify-between">
                  <div className="min-w-0">
                    <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold">Insumos / medicación</div>
                    <div className="text-xs text-stone-600">{supplies.length} {supplies.length === 1 ? "ítem" : "ítems"}</div>
                  </div>
                  <button
                    onClick={() => setShowSupplyPicker(true)}
                    className="px-3 py-1.5 rounded-lg bg-emerald-500 hover:bg-emerald-600 text-white text-xs font-semibold flex items-center gap-1.5 shadow"
                  >
                    <Plus size={11} /> Agregar
                  </button>
                </div>
                <div className="p-2 space-y-1.5">
                  {supplies.length === 0 ? (
                    <div className="text-center py-4 text-xs text-stone-500 italic">
                      Sin insumos registrados aún.
                    </div>
                  ) : (
                    supplies.map((s, idx) => (
                      <div key={idx} className="flex items-center gap-2 p-2 rounded-lg bg-stone-50 border border-stone-200">
                        <Pill size={12} className="text-emerald-700 flex-shrink-0" />
                        <div className="flex-1 min-w-0">
                          <div className="text-xs font-semibold truncate">{s.name}</div>
                          <div className="text-xs text-stone-500">{s.qty} {s.unit} · ${(s.qty * (s.price || 0)).toFixed(2)}</div>
                        </div>
                        <button
                          onClick={() => updateSuppliesAndInvoice(supplies.filter((_, i) => i !== idx))}
                          className="w-6 h-6 rounded-md bg-white border border-stone-200 hover:border-red-400 grid place-items-center text-stone-500 hover:text-red-600"
                        >
                          <X size={10} />
                        </button>
                      </div>
                    ))
                  )}
                </div>
              </div>

              {/* Recibo activa (en tratamiento_sede ya existe) */}
              {invoice && (
                <button
                  onClick={onGoToSales}
                  className="w-full flex items-center justify-between gap-2 p-3 rounded-xl bg-orange-50 border border-orange-200 hover:border-orange-400 text-left transition"
                >
                  <div className="min-w-0">
                    <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold flex items-center gap-1">
                      <Receipt size={11} /> Recibo activa
                    </div>
                    <div className="font-mono text-xs font-bold text-stone-700">{invoice.number}</div>
                  </div>
                  <div className="text-right flex-shrink-0">
                    <div className="text-xs text-stone-500">Total</div>
                    <div className="font-serif text-base font-bold text-orange-700">${(invoice.total ?? 0).toFixed(2)}</div>
                  </div>
                  <ExternalLink size={11} className="text-stone-400 flex-shrink-0" />
                </button>
              )}

              {/* Botón principal cambia según etapa */}
              {status === "consulta" && (
                <button
                  onClick={() => setShowConfirmConsult(true)}
                  className="w-full flex items-center justify-center gap-2 px-4 py-3 rounded-xl text-sm font-semibold bg-stone-900 hover:bg-stone-800 text-white shadow transition"
                >
                  <CheckCircle size={15} strokeWidth={2.2} /> Confirmar consulta y abrir recibo
                </button>
              )}

              {status === "tratamiento_sede" && (
                <button
                  onClick={closeTreatment}
                  className="w-full flex items-center justify-center gap-2 px-4 py-3 rounded-xl text-sm font-semibold bg-stone-900 hover:bg-stone-800 text-white shadow transition"
                >
                  <CheckCircle size={15} strokeWidth={2.2} /> Cerrar atención · Finalizar recibo
                </button>
              )}
            </>
          )}

          {/* === CONTROL / VACUNACIÓN: calendario propio === */}
          {status === "control" && (
            <>
              <button
                onClick={() => onOpenVetPassport && onOpenVetPassport(patient.code)}
                disabled={!canAccessVetPassport}
                className={`w-full flex items-center justify-center gap-2 px-3 py-2 rounded-xl text-sm font-semibold transition border ${
                  canAccessVetPassport
                    ? "bg-white hover:bg-orange-50 text-stone-700 border-stone-200 hover:border-orange-300"
                    : "bg-stone-100 text-stone-400 border-stone-200 cursor-not-allowed"
                }`}
              >
                <BookOpen size={13} /> Ver ficha clínica
              </button>

              <FollowUpCalendar
                patient={patient}
                kind="control"
                entries={followUpEntries}
                onAdd={() => setShowAddFollowUp(true)}
                onToggleDone={onToggleFollowUpDone}
                onRemove={onRemoveFollowUp}
              />

              <button
                onClick={() => onAdvance("finalizado", { closedAt: new Date().toISOString() })}
                className="w-full flex items-center justify-center gap-2 px-3 py-2.5 rounded-xl text-sm font-semibold bg-stone-900 hover:bg-stone-800 text-white shadow transition"
              >
                <CheckCircle size={13} strokeWidth={2.2} /> Cerrar seguimiento
              </button>
            </>
          )}

          {/* === FINALIZADO === */}
          {status === "finalizado" && (
            <>
              <div className="bg-stone-100 border border-stone-200 rounded-xl p-4 text-center">
                <CheckCircle size={28} className="text-stone-400 mx-auto mb-2" strokeWidth={1.6} />
                <div className="text-sm font-semibold text-stone-700">Atención cerrada</div>
                <div className="text-xs text-stone-500 mt-1">
                  La ficha clínica conserva el historial completo.
                </div>
              </div>
              {invoice && (
                <button
                  onClick={onGoToSales}
                  className="w-full flex items-center justify-between gap-2 p-3 rounded-xl bg-orange-50 border border-orange-200 hover:border-orange-400 text-left transition"
                >
                  <div className="min-w-0">
                    <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold flex items-center gap-1">
                      <Receipt size={11} /> Recibo asociada
                    </div>
                    <div className="font-mono text-xs font-bold text-stone-700">{invoice.number}</div>
                  </div>
                  <div className="text-right flex-shrink-0">
                    <div className="text-xs text-stone-500">Total</div>
                    <div className="font-serif text-base font-bold text-orange-700">${(invoice.total ?? 0).toFixed(2)}</div>
                  </div>
                  <ExternalLink size={11} className="text-stone-400 flex-shrink-0" />
                </button>
              )}
              <button
                onClick={() => onOpenVetPassport && onOpenVetPassport(patient.code)}
                disabled={!canAccessVetPassport}
                className="w-full flex items-center justify-center gap-2 px-3 py-2 rounded-xl text-sm font-semibold bg-white hover:bg-orange-50 text-stone-700 border border-stone-200 hover:border-orange-300 transition"
              >
                <BookOpen size={13} /> Ver ficha clínica completa
              </button>
              <button
                onClick={() => onAdvance("control", {})}
                className="w-full flex items-center justify-center gap-2 px-3 py-2 rounded-xl text-sm font-semibold bg-white hover:bg-orange-50 text-orange-700 border border-orange-200 transition"
              >
                <CalendarPlus size={12} /> Programar seguimiento
              </button>
            </>
          )}
        </div>
          </div>
          )}
        </div>

        {/* Handle de resize en esquina inferior derecha */}
        <WindowResizeHandle
          size={size}
          setSize={setSize}
          disabled={isMobile || maximized}
        />
      </div>

      {/* Modal: selector de insumos médicos */}
      {showSupplyPicker && (
        <VetSupplyPickerModal
          supplies={vetSupplies}
          onClose={() => setShowSupplyPicker(false)}
          onAdd={(supply, qty) => {
            const newSupplies = [...supplies, { ...supply, qty }];
            updateSuppliesAndInvoice(newSupplies);
            setShowSupplyPicker(false);
          }}
        />
      )}

      {/* Modal: confirmar consulta y decidir si hay tratamiento adicional */}
      {showConfirmConsult && (
        <VetConfirmConsultModal
          patient={patient}
          supplies={supplies}
          onClose={() => setShowConfirmConsult(false)}
          onConfirm={handleConfirmConsultation}
        />
      )}

      {/* Modal: añadir entrada al calendario de seguimiento */}
      {showAddFollowUp && (
        <AddFollowUpEntryModal
          kind={status}
          onClose={() => setShowAddFollowUp(false)}
          onSubmit={(entry) => {
            onAddFollowUp(entry);
            setShowAddFollowUp(false);
          }}
        />
      )}

      {/* Ventana flotante: visor de consultas anteriores. Muestra el historial estructurado
          (mismas secciones que el editor: motivo, examen, diagnóstico, etc.) para que el vet
          pueda revisar evoluciones sin perder el cuadro actual de vista. */}
      {showHistoryViewer && (
        <PatientHistoryViewer
          patient={patient}
          passport={passport}
          onClose={() => setShowHistoryViewer(false)}
        />
      )}

      {/* === Modales de adjuntos del chat de la ficha === */}
      {showChatImagePicker && (
        <ChatImagePickerModal
          onClose={() => setShowChatImagePicker(false)}
          onSend={handleChatSendImage}
        />
      )}
      {showChatInvoicePicker && tutorClient && canSendInvoice && (
        <ChatInvoicePickerModal
          invoices={invoices}
          activeClientId={tutorClient.id}
          clients={clients}
          onClose={() => setShowChatInvoicePicker(false)}
          onSend={handleChatSendInvoice}
        />
      )}
    </>
  );
}

// ========== Modal: confirmar consulta ==========
// Pregunta sencilla: ¿el paciente queda hospitalizado para tratamiento o se va?
function VetConfirmConsultModal({ patient, supplies, onClose, onConfirm }) {
  const itemsCount = supplies.length;

  return (
    <div onClick={onClose} className="fixed inset-0 bg-stone-900 z-50 flex justify-center items-center p-4">
      <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden">
        <div className="p-4 border-b border-stone-200 bg-stone-50 flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-stone-900 text-white grid place-items-center shadow-lg flex-shrink-0">
            <CheckCircle size={17} strokeWidth={2.2} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold">Confirmar consulta</div>
            <h3 className="font-serif text-lg font-semibold mt-0.5 truncate">{patient.name}</h3>
          </div>
        </div>
        <div className="p-5 space-y-3">
          <p className="text-sm text-stone-700">
            Se abrirá una recibo para <strong>{patient.owner}</strong>
            {itemsCount > 0
              ? ` con la consulta + ${itemsCount} ${itemsCount === 1 ? "insumo" : "insumos"} usados.`
              : " con la consulta veterinaria base."}
          </p>
          <div className="bg-orange-50 border border-orange-200 rounded-xl p-3 text-xs text-orange-900 flex items-start gap-2">
            <Receipt size={11} className="text-orange-700 flex-shrink-0 mt-0.5" />
            <span>La recibo quedará en estado <strong>borrador</strong>. Ventas la emitirá y cobrará desde el módulo de recibos.</span>
          </div>

          <div className="text-sm font-semibold text-stone-800 pt-1">
            ¿{patient.name} requiere tratamiento adicional en sede?
          </div>
          <div className="space-y-2">
            <button
              onClick={() => onConfirm(true)}
              className="w-full flex items-start gap-3 p-3 rounded-xl border-2 border-amber-300 bg-amber-50 hover:bg-amber-100 text-left transition"
            >
              <div className="w-9 h-9 rounded-lg bg-amber-500 text-white grid place-items-center flex-shrink-0">
                <Activity size={15} strokeWidth={2} />
              </div>
              <div className="flex-1 min-w-0">
                <div className="font-semibold text-sm text-amber-900">Sí, queda hospitalizado</div>
                <div className="text-xs text-amber-800 mt-0.5">
                  Pasa a <strong>Tratamiento en sede</strong>. La recibo sigue abierta para añadir más insumos.
                </div>
              </div>
            </button>
            <button
              onClick={() => onConfirm(false)}
              className="w-full flex items-start gap-3 p-3 rounded-xl border-2 border-stone-300 bg-white hover:bg-stone-50 text-left transition"
            >
              <div className="w-9 h-9 rounded-lg bg-stone-700 text-white grid place-items-center flex-shrink-0">
                <CheckCircle size={15} strokeWidth={2} />
              </div>
              <div className="flex-1 min-w-0">
                <div className="font-semibold text-sm text-stone-800">No, se va a casa</div>
                <div className="text-xs text-stone-600 mt-0.5">
                  Pasa directo a <strong>Finalizado</strong>. La recibo queda lista para cobrar.
                </div>
              </div>
            </button>
          </div>
        </div>
        <div className="p-3 border-t border-stone-200 bg-stone-50 flex justify-end">
          <button onClick={onClose} className="px-4 py-2 rounded-xl text-sm font-semibold bg-white border border-stone-200 hover:border-stone-400 text-stone-700">
            Cancelar
          </button>
        </div>
      </div>
    </div>
  );
}

// ========== Modal: subir imagen al chat ==========
function ChatImagePickerModal({ onClose, onSend }) {
  const [image, setImage] = useState(null); // { url, name, size }
  const [caption, setCaption] = useState("");

  const handleFile = (file) => {
    if (!file) return;
    if (file.size > 5 * 1024 * 1024) {
      alert("La imagen debe ser menor a 5 MB");
      return;
    }
    const reader = new FileReader();
    reader.onload = () => setImage({ url: reader.result, name: file.name, size: file.size });
    reader.readAsDataURL(file);
  };

  return (
    <div onClick={onClose} className="fixed inset-0 bg-stone-900 z-50 flex justify-center items-center p-4">
      <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden">
        <div className="p-4 border-b border-stone-200 bg-blue-50 flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-blue-500 text-white grid place-items-center shadow-lg flex-shrink-0">
            <Camera size={17} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase text-blue-700 font-semibold">Adjuntar al chat</div>
            <h3 className="font-serif text-lg font-semibold mt-0.5">Foto o imagen</h3>
          </div>
        </div>

        <div className="p-5 space-y-3">
          {image ? (
            <div>
              <div className="rounded-xl overflow-hidden bg-stone-100 border border-stone-200">
                <img src={image.url} alt="" className="block w-full max-h-72 object-contain" />
              </div>
              <div className="mt-2 flex items-center gap-2">
                <div className="flex-1 min-w-0">
                  <div className="text-xs font-semibold text-stone-700 truncate">{image.name}</div>
                  <div className="text-xs text-stone-500">{(image.size / 1024).toFixed(1)} KB</div>
                </div>
                <button
                  onClick={() => setImage(null)}
                  className="px-2.5 py-1.5 rounded-lg bg-white border border-stone-200 hover:border-red-400 text-stone-600 hover:text-red-600 text-xs font-semibold"
                >
                  <X size={11} className="inline" /> Quitar
                </button>
              </div>
            </div>
          ) : (
            <label className="border-2 border-dashed border-stone-300 hover:border-blue-400 rounded-xl p-6 flex flex-col items-center justify-center gap-2 cursor-pointer text-stone-500 hover:text-blue-700 hover:bg-blue-50 transition">
              <div className="w-12 h-12 rounded-xl bg-blue-100 text-blue-700 grid place-items-center">
                <Camera size={20} strokeWidth={1.6} />
              </div>
              <div className="text-sm font-semibold">Click para subir imagen</div>
              <div className="text-xs text-stone-400">JPG o PNG · máx. 5 MB</div>
              <input
                type="file"
                accept="image/*"
                className="hidden"
                onChange={(e) => handleFile(e.target.files?.[0])}
              />
            </label>
          )}

          {image && (
            <div>
              <label className="text-xs font-semibold text-stone-700 block mb-1.5">
                Mensaje (opcional)
              </label>
              <textarea
                value={caption}
                onChange={(e) => setCaption(e.target.value)}
                rows={2}
                placeholder="Acompaña la foto con un mensaje..."
                className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-blue-500 resize-none"
              />
            </div>
          )}
        </div>

        <div className="p-3 border-t border-stone-200 bg-stone-50 flex gap-2">
          <button onClick={onClose} className="flex-1 px-3 py-2 rounded-xl text-sm font-semibold bg-white border border-stone-200 hover:border-stone-400 text-stone-700">
            Cancelar
          </button>
          <button
            onClick={() => image && onSend(image.url, caption)}
            disabled={!image}
            className={`flex-1 px-3 py-2 rounded-xl text-sm font-semibold transition shadow ${
              image ? "bg-emerald-500 hover:bg-emerald-600 text-white" : "bg-stone-200 text-stone-400 cursor-not-allowed"
            }`}
          >
            <Send size={12} className="inline" /> Enviar
          </button>
        </div>
      </div>
    </div>
  );
}

// ========== Modal: seleccionar recibo para enviar al chat ==========
// Importante: lista TODAS las recibos del sistema, no solo del cliente actual.
// El veterinario puede compartir la recibo de cualquier cliente con cualquier otro chat
// (caso real: cliente pide ver recibo de su socio comercial, etc.)
// ========== MODAL: ENVIAR MÉTODO DE PAGO AL CLIENTE POR CHAT ==========
// Muestra los métodos de pago activos como botones grandes con icono.
// Al hacer click envía los datos (banco, cuenta, wallet, etc.) como mensaje
// formateado al cliente.
function ChatPaymentMethodPickerModal({ paymentMethods = [], onClose, onSend }) {
  const ICON_MAP = {
    Banknote, CreditCard, ArrowRightLeft, Smartphone, Wallet, Coins,
  };
  const enabled = (paymentMethods || []).filter(m => m.enabled);

  return (
    <div onClick={onClose} className="fixed inset-0 bg-stone-900/80 z-50 flex justify-center items-center p-4">
      <div onClick={(e) => e.stopPropagation()} className="bg-stone-50 rounded-2xl w-full max-w-lg shadow-2xl overflow-hidden flex flex-col max-h-[80vh]">
        <div className="p-4 border-b border-stone-200 bg-gradient-to-br from-emerald-50 to-white flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-emerald-600 text-white grid place-items-center flex-shrink-0">
            <Wallet size={16} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase text-emerald-700 font-bold">Enviar al cliente</div>
            <h3 className="font-serif text-lg font-semibold mt-0.5">Método de pago</h3>
          </div>
          <button onClick={onClose} className="w-8 h-8 rounded-lg bg-white hover:bg-stone-100 grid place-items-center text-stone-500 flex-shrink-0">
            <X size={14} />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-4">
          {enabled.length === 0 ? (
            <div className="text-center py-8 text-stone-400 text-sm">
              <Wallet size={28} className="mx-auto mb-2 text-stone-300" />
              <div className="font-semibold mb-1">Sin métodos activos</div>
              <div className="text-xs">El admin debe activar al menos un método en Ajustes → Métodos de pago.</div>
            </div>
          ) : (
            <>
              <p className="text-xs text-stone-500 mb-3 leading-relaxed">
                Selecciona el método cuyos datos quieres enviar al cliente. El mensaje se enviará por el canal activo.
              </p>
              <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
                {enabled.map(m => {
                  const Ic = ICON_MAP[m.iconName] || Wallet;
                  const rows = renderPaymentMethodDetails(m);
                  const hasData = m.id === "efectivo" || (rows && rows.length > 0);
                  return (
                    <button
                      key={m.id}
                      onClick={() => onSend(m)}
                      disabled={!hasData}
                      title={hasData ? `Enviar datos de ${m.label}` : "Sin datos configurados. Avisa al admin."}
                      className={`flex flex-col items-center gap-2 p-4 rounded-xl border-2 transition ${
                        hasData
                          ? "bg-white border-stone-200 hover:border-emerald-500 hover:bg-emerald-50 hover:shadow-md"
                          : "bg-stone-100 border-stone-200 opacity-50 cursor-not-allowed"
                      }`}
                    >
                      <div className={`w-12 h-12 rounded-xl grid place-items-center ${
                        hasData ? "bg-stone-900 text-white" : "bg-stone-300 text-stone-500"
                      }`}>
                        <Ic size={20} strokeWidth={1.8} />
                      </div>
                      <span className={`text-xs font-semibold text-center ${hasData ? "text-stone-800" : "text-stone-500"}`}>
                        {m.label}
                      </span>
                      {!hasData && (
                        <span className="text-[9px] text-amber-700 italic">Sin datos</span>
                      )}
                    </button>
                  );
                })}
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
}

function ChatInvoicePickerModal({ invoices, activeClientId, clients = [], onClose, onSend }) {
  // El modal ahora tiene 2 pasos:
  // 1) "pick" — selección de recibo (lista filtrada con búsqueda)
  // 2) "preview" — vista de la recibo como documento + mensaje editable que la acompaña
  // Esto reemplaza el envío directo al hacer click en una recibo. El usuario revisa
  // la recibo formateada (como la verá el cliente) y opcionalmente edita el mensaje.
  const [step, setStep] = useState("pick");
  const [selectedInvoice, setSelectedInvoice] = useState(null);
  const [messageText, setMessageText] = useState("");
  const [search, setSearch] = useState("");
  const [filter, setFilter] = useState("client"); // client | all

  // Plantillas rápidas para el mensaje que acompaña la recibo
  const messageTemplates = [
    { id: "send", label: "Envío de recibo", text: "Hola! Te adjunto la recibo por nuestros servicios. Cualquier consulta quedo a tu disposición." },
    { id: "reminder", label: "Recordatorio de pago", text: "Hola! Te recuerdo que tienes pendiente esta recibo. ¿Podrías coordinar el pago?" },
    { id: "thanks", label: "Agradecimiento", text: "¡Gracias por tu pago! Te confirmo recepción y adjunto la recibo para tu registro." },
    { id: "blank", label: "Sin mensaje", text: "" },
  ];

  const filtered = useMemo(() => {
    let list = invoices;
    if (filter === "client") {
      list = list.filter(i => i.clientId === activeClientId);
    }
    if (search.trim()) {
      const q = search.toLowerCase();
      list = list.filter(i =>
        i.number.toLowerCase().includes(q) ||
        (i.clientName || "").toLowerCase().includes(q)
      );
    }
    return [...list].sort((a, b) => (b.issueDate || "").localeCompare(a.issueDate || ""));
  }, [invoices, search, filter, activeClientId]);

  const clientInvoiceCount = invoices.filter(i => i.clientId === activeClientId).length;

  // Al elegir una recibo, pasamos al preview con un mensaje por defecto.
  const handlePickInvoice = (inv) => {
    setSelectedInvoice(inv);
    // Por defecto: si está emitida, mensaje de envío; si vencida, mensaje de recordatorio.
    const defaultTemplate = inv.state === "vencido" || inv.balance > 0
      ? messageTemplates.find(t => t.id === "reminder")
      : messageTemplates.find(t => t.id === "send");
    setMessageText(defaultTemplate?.text || "");
    setStep("preview");
  };

  const handleConfirmSend = () => {
    onSend(selectedInvoice, messageText.trim() || null);
  };

  return (
    <div onClick={onClose} className="fixed inset-0 bg-stone-900/80 z-50 flex justify-center items-center p-4">
      <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl w-full max-w-2xl shadow-2xl overflow-hidden flex flex-col" style={{ maxHeight: "90vh" }}>
        {/* === HEADER === */}
        <div className="p-4 border-b border-stone-200 bg-orange-50 flex items-center gap-3 flex-shrink-0">
          {step === "preview" && (
            <button
              onClick={() => { setStep("pick"); setSelectedInvoice(null); }}
              title="Volver a la lista"
              className="w-9 h-9 rounded-lg bg-white hover:bg-stone-100 border border-stone-200 grid place-items-center text-stone-600"
            >
              <ChevronLeft size={14} />
            </button>
          )}
          <div className="w-10 h-10 rounded-xl bg-orange-500 text-white grid place-items-center shadow-lg flex-shrink-0">
            <Receipt size={17} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase text-orange-700 font-semibold">
              {step === "pick" ? "Compartir al chat" : `Previsualización · ${selectedInvoice?.number}`}
            </div>
            <h3 className="font-serif text-lg font-semibold mt-0.5">
              {step === "pick" ? "Seleccionar recibo" : "Revisa antes de enviar"}
            </h3>
          </div>
          <button onClick={onClose} className="w-9 h-9 rounded-lg bg-white hover:bg-stone-100 border border-stone-200 grid place-items-center text-stone-600">
            <X size={14} />
          </button>
        </div>

        {/* === PASO 1: SELECCIÓN === */}
        {step === "pick" && (
          <>
            <div className="p-3 border-b border-stone-200 space-y-2 flex-shrink-0">
              <div className="flex gap-1 bg-stone-100 rounded-lg p-0.5">
                <button
                  onClick={() => setFilter("client")}
                  className={`flex-1 px-3 py-1.5 rounded text-xs font-semibold transition ${
                    filter === "client" ? "bg-white text-stone-900 shadow" : "text-stone-600 hover:text-stone-900"
                  }`}
                >
                  De este cliente ({clientInvoiceCount})
                </button>
                <button
                  onClick={() => setFilter("all")}
                  className={`flex-1 px-3 py-1.5 rounded text-xs font-semibold transition ${
                    filter === "all" ? "bg-white text-stone-900 shadow" : "text-stone-600 hover:text-stone-900"
                  }`}
                >
                  Todas ({invoices.length})
                </button>
              </div>
              <div className="relative">
                <Search size={13} className="absolute left-3 top-1/2 -translate-y-1/2 text-stone-400" />
                <input
                  autoFocus
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                  placeholder="Buscar por número o cliente..."
                  className="w-full pl-9 pr-3 py-2 bg-stone-50 border border-stone-200 rounded-xl text-sm outline-none focus:border-orange-500"
                />
              </div>
            </div>

            <div className="flex-1 overflow-y-auto">
              {filtered.length === 0 ? (
                <div className="p-8 text-center text-sm text-stone-500">
                  {filter === "client"
                    ? "Este cliente no tiene recibos. Cambia a \"Todas\" para buscar otra."
                    : "Sin coincidencias."}
                </div>
              ) : (
                filtered.map(inv => (
                  <button
                    key={inv.id}
                    onClick={() => handlePickInvoice(inv)}
                    className="w-full flex items-center gap-2.5 p-3 hover:bg-orange-50 border-b border-stone-100 last:border-0 text-left transition"
                  >
                    <div className="w-9 h-9 rounded-lg bg-orange-100 text-orange-700 grid place-items-center flex-shrink-0">
                      <Receipt size={13} />
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-baseline gap-1.5 flex-wrap">
                        <span className="font-mono text-sm font-bold text-stone-800">{inv.number}</span>
                        <InvoiceStateBadge state={inv.state} />
                      </div>
                      <div className="text-xs text-stone-500 truncate">
                        {inv.clientName} · {inv.issueDate}
                      </div>
                    </div>
                    <div className="text-right flex-shrink-0">
                      <div className="font-serif text-sm font-bold text-orange-700">
                        ${inv.total.toFixed(2)}
                      </div>
                    </div>
                    <ChevronRight size={11} className="text-stone-400 flex-shrink-0" />
                  </button>
                ))
              )}
            </div>
          </>
        )}

        {/* === PASO 2: PREVIEW + MENSAJE === */}
        {step === "preview" && selectedInvoice && (
          <>
            <div className="flex-1 overflow-y-auto p-4 space-y-3 bg-stone-50">
              {/* Documento de recibo renderizado */}
              <InvoiceDocumentPreview invoice={selectedInvoice} clients={clients} />

              {/* Mensaje que acompaña la recibo */}
              <div className="bg-white border border-stone-200 rounded-xl p-3 space-y-2">
                <div className="text-[10px] tracking-widest uppercase text-stone-500 font-bold">
                  Mensaje que acompañará la recibo
                </div>
                {/* Plantillas rápidas */}
                <div className="flex flex-wrap gap-1">
                  {messageTemplates.map(t => (
                    <button
                      key={t.id}
                      onClick={() => setMessageText(t.text)}
                      className="text-[11px] font-semibold px-2 py-1 rounded-md bg-stone-100 hover:bg-orange-100 hover:text-orange-700 text-stone-600 transition"
                    >
                      {t.label}
                    </button>
                  ))}
                </div>
                <textarea
                  value={messageText}
                  onChange={(e) => setMessageText(e.target.value)}
                  placeholder="Escribe un mensaje opcional para acompañar la recibo..."
                  rows={3}
                  className="w-full px-3 py-2 border border-stone-200 rounded-lg text-sm outline-none focus:border-orange-500 resize-none"
                />
                <div className="text-[10px] text-stone-500 italic">
                  La recibo se enviará como adjunto. El mensaje aparecerá arriba.
                </div>
              </div>
            </div>

            <div className="p-3 border-t border-stone-200 bg-white flex gap-2 flex-shrink-0">
              <button
                onClick={() => { setStep("pick"); setSelectedInvoice(null); }}
                className="px-4 py-2.5 rounded-xl bg-stone-100 hover:bg-stone-200 text-stone-700 text-sm font-semibold transition"
              >
                Cancelar
              </button>
              <button
                onClick={handleConfirmSend}
                className="flex-1 px-4 py-2.5 rounded-xl bg-emerald-600 hover:bg-emerald-700 text-white text-sm font-semibold transition flex items-center justify-center gap-2"
              >
                <Send size={14} />
                Enviar recibo
              </button>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

// ========== Vista preview de recibo como documento ==========
// Renderiza la recibo en formato "papel/PDF" para mostrarla tanto en:
// - El paso de preview antes de enviar
// - Como adjunto dentro del chat (modo compacto/zoom)
function InvoiceDocumentPreview({ invoice, clients = [], compact = false }) {
  const client = clients.find(c => c.id === invoice.clientId);
  const items = invoice.items || [];
  // Recalcular subtotal si no viene, para que el preview sea consistente
  const subtotal = invoice.subtotal != null ? invoice.subtotal : items.reduce((s, i) => s + (i.total || 0), 0);
  const tax = invoice.tax != null ? invoice.tax : Math.round(subtotal * 0.16 * 100) / 100;
  const total = invoice.total != null ? invoice.total : subtotal + tax;
  const paid = invoice.paid || 0;
  const balance = total - paid;

  return (
    <div className={`bg-white border border-stone-200 rounded-xl shadow-sm overflow-hidden ${compact ? "text-xs" : ""}`}>
      {/* Cabecera tipo "documento": marca + número + estado */}
      <div className="px-5 py-4 bg-gradient-to-br from-orange-50 to-amber-50 border-b border-orange-200 flex items-start justify-between gap-3">
        <div>
          <div className={`font-serif font-bold text-orange-900 ${compact ? "text-base" : "text-xl"}`}>CRICKET</div>
          <div className="text-[10px] tracking-widest uppercase text-orange-700 font-semibold mt-0.5">
            Recibo · Comprobante de pago
          </div>
        </div>
        <div className="text-right">
          <div className={`font-mono font-bold text-stone-900 ${compact ? "text-sm" : "text-base"}`}>
            {invoice.number}
          </div>
          <div className="mt-1">
            <InvoiceStateBadge state={invoice.state} />
          </div>
        </div>
      </div>

      {/* Cuerpo: datos de cliente, fechas, items, totales */}
      <div className={`${compact ? "p-3" : "p-5"} space-y-3`}>
        {/* Cliente + fechas */}
        <div className={`grid grid-cols-2 gap-3 ${compact ? "text-[11px]" : "text-xs"}`}>
          <div>
            <div className="text-[9px] tracking-widest uppercase text-stone-500 font-bold">Cliente</div>
            <div className="font-semibold text-stone-800 mt-0.5">
              {client?.name || invoice.clientName || "Sin nombre"}
            </div>
            {client?.cedula && (
              <div className="text-stone-500 mt-0.5">{client.cedula}</div>
            )}
          </div>
          <div className="text-right">
            <div className="text-[9px] tracking-widest uppercase text-stone-500 font-bold">Emitida</div>
            <div className="font-semibold text-stone-800 mt-0.5">{invoice.issueDate || "—"}</div>
            {invoice.dueDate && (
              <div className="text-stone-500 mt-0.5">Vence: {invoice.dueDate}</div>
            )}
          </div>
        </div>

        {/* Línea separadora */}
        <div className="border-t border-dashed border-stone-300"></div>

        {/* Items */}
        <div className="space-y-1">
          <div className={`text-[9px] tracking-widest uppercase text-stone-500 font-bold ${compact ? "text-[8px]" : ""}`}>
            Detalle ({items.length} {items.length === 1 ? "ítem" : "ítems"})
          </div>
          <div className={`space-y-1 ${compact ? "text-[11px]" : "text-xs"}`}>
            {items.length === 0 ? (
              <div className="text-stone-400 italic py-2">Sin ítems en esta recibo.</div>
            ) : items.map((item, idx) => (
              <div key={idx} className="flex justify-between gap-2 py-1 border-b border-stone-100 last:border-0">
                <div className="flex-1 min-w-0">
                  <div className="text-stone-800 truncate">{item.description}</div>
                  {item.qty > 1 && (
                    <div className="text-stone-500 text-[10px]">{item.qty} × ${(item.unit || 0).toFixed(2)}</div>
                  )}
                </div>
                <div className="font-mono font-semibold text-stone-900 flex-shrink-0">
                  ${(item.total || 0).toFixed(2)}
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Totales */}
        <div className="border-t border-dashed border-stone-300 pt-2 space-y-0.5">
          <div className={`flex justify-between ${compact ? "text-[11px]" : "text-xs"} text-stone-600`}>
            <span>Subtotal</span>
            <span className="font-mono">${subtotal.toFixed(2)}</span>
          </div>
          <div className={`flex justify-between ${compact ? "text-[11px]" : "text-xs"} text-stone-600`}>
            <span>IVA 16%</span>
            <span className="font-mono">${tax.toFixed(2)}</span>
          </div>
          <div className={`flex justify-between font-bold text-orange-700 pt-1 border-t border-stone-200 ${compact ? "text-sm" : "text-base"}`}>
            <span>Total</span>
            <span className="font-mono">${total.toFixed(2)}</span>
          </div>
          {paid > 0 && (
            <>
              <div className={`flex justify-between text-emerald-700 ${compact ? "text-[11px]" : "text-xs"} pt-1`}>
                <span>Abonado</span>
                <span className="font-mono">−${paid.toFixed(2)}</span>
              </div>
              {balance > 0.01 && (
                <div className={`flex justify-between font-bold text-red-700 ${compact ? "text-[11px]" : "text-xs"}`}>
                  <span>Saldo pendiente</span>
                  <span className="font-mono">${balance.toFixed(2)}</span>
                </div>
              )}
              {balance <= 0.01 && (
                <div className={`flex justify-between font-bold text-emerald-700 ${compact ? "text-[11px]" : "text-xs"}`}>
                  <span>Estado</span>
                  <span>✓ Pagado</span>
                </div>
              )}
            </>
          )}
        </div>
      </div>

      {/* Footer del documento */}
      <div className="px-5 py-2 bg-stone-50 border-t border-stone-200 text-center text-[10px] text-stone-400 italic">
        Cricket — Gracias por confiar en nosotros.
      </div>
    </div>
  );
}

// ========== Modal: vincular cliente al chat (visitante → cliente registrado) ==========
function ChatLinkClientModal({ existingClients, chatPhone, onClose, onLink }) {
  const [mode, setMode] = useState("link"); // link | create
  const [search, setSearch] = useState("");
  const [draft, setDraft] = useState({
    name: "",
    documentId: "",
    phone: chatPhone || "",
    email: "",
    pet: { name: "", species: "dog", breed: "", age: "", gender: "Macho" },
  });
  const [step, setStep] = useState(1); // 1 = tutor, 2 = mascota

  const matches = useMemo(() => {
    if (!search.trim()) return [];
    const q = search.toLowerCase().replace(/[\s.-]/g, "");
    return existingClients.filter(c => {
      const cId = (c.documentId || "").toLowerCase().replace(/[\s.-]/g, "");
      const cName = c.name.toLowerCase();
      return cId.includes(q) || cName.includes(q);
    }).slice(0, 5);
  }, [search, existingClients]);

  return (
    <div onClick={onClose} className="fixed inset-0 bg-stone-900 z-50 flex justify-center items-center p-4">
      <div onClick={(e) => e.stopPropagation()} className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden">
        <div className="p-4 border-b border-stone-200 bg-emerald-50 flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-emerald-500 text-white grid place-items-center shadow-lg flex-shrink-0">
            <UserPlus size={17} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase text-emerald-700 font-semibold">Vincular contacto</div>
            <h3 className="font-serif text-lg font-semibold mt-0.5">Asociar a un cliente</h3>
          </div>
        </div>

        {/* Tabs: buscar existente vs crear nuevo */}
        <div className="flex border-b border-stone-200">
          <button
            onClick={() => setMode("link")}
            className={`flex-1 px-3 py-2 text-xs font-semibold transition border-b-2 ${
              mode === "link" ? "text-emerald-700 border-emerald-500" : "text-stone-500 border-transparent hover:text-stone-700"
            }`}
          >
            <Search size={11} className="inline" /> Buscar por cédula
          </button>
          <button
            onClick={() => setMode("create")}
            className={`flex-1 px-3 py-2 text-xs font-semibold transition border-b-2 ${
              mode === "create" ? "text-emerald-700 border-emerald-500" : "text-stone-500 border-transparent hover:text-stone-700"
            }`}
          >
            <UserPlus size={11} className="inline" /> Crear cliente nuevo
          </button>
        </div>

        {mode === "link" ? (
          <div className="p-5 space-y-3">
            <div className="text-xs text-stone-600">
              Si el cliente te dio su cédula por chat, ingrésala aquí para vincular el contacto al cliente registrado.
            </div>
            <input
              autoFocus
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder="V-12345678 o nombre..."
              className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-emerald-500 font-mono"
            />
            {matches.length > 0 ? (
              <div className="space-y-1">
                {matches.map(c => (
                  <button
                    key={c.id}
                    onClick={() => onLink({ documentId: c.documentId, name: c.name })}
                    className="w-full flex items-center gap-2 p-2 rounded-lg border border-stone-200 hover:border-emerald-300 hover:bg-emerald-50 text-left transition"
                  >
                    <div className="w-8 h-8 rounded-full bg-orange-500 text-white text-xs font-bold grid place-items-center flex-shrink-0">
                      {c.name.split(" ").slice(0, 2).map(s => s[0]).join("").toUpperCase()}
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="font-semibold text-sm truncate">{c.name}</div>
                      <div className="text-xs text-stone-500 font-mono">{c.documentId}</div>
                    </div>
                    <ChevronRight size={11} className="text-stone-400" />
                  </button>
                ))}
              </div>
            ) : search.trim() ? (
              <div className="text-center py-4 text-xs text-stone-500">
                Sin coincidencias. <button onClick={() => setMode("create")} className="text-emerald-700 font-semibold hover:underline">Crear nuevo</button>
              </div>
            ) : null}
          </div>
        ) : (
          <div className="p-5 space-y-3">
            {/* Indicador de paso */}
            <div className="flex items-center gap-2">
              <div className={`flex items-center gap-1.5 px-2 py-1 rounded-lg text-xs font-semibold ${
                step === 1 ? "bg-emerald-100 text-emerald-800" : "bg-stone-100 text-stone-500"
              }`}>
                <span className={`w-4 h-4 rounded-full grid place-items-center text-xs font-bold ${
                  step === 1 ? "bg-emerald-500 text-white" : "bg-stone-300 text-stone-600"
                }`}>1</span>
                Tutor
              </div>
              <div className="flex-1 h-px bg-stone-200"></div>
              <div className={`flex items-center gap-1.5 px-2 py-1 rounded-lg text-xs font-semibold ${
                step === 2 ? "bg-emerald-100 text-emerald-800" : "bg-stone-100 text-stone-500"
              }`}>
                <span className={`w-4 h-4 rounded-full grid place-items-center text-xs font-bold ${
                  step === 2 ? "bg-emerald-500 text-white" : "bg-stone-300 text-stone-600"
                }`}>2</span>
                Mascota
              </div>
            </div>

            {step === 1 ? (
              <>
                <div className="bg-amber-50 border border-amber-200 rounded-xl p-2.5 text-xs text-amber-900 flex items-start gap-2">
                  <Info size={11} className="text-amber-700 flex-shrink-0 mt-0.5" />
                  <span>Datos del tutor que escribe por chat. La mascota la registramos en el siguiente paso.</span>
                </div>
                <div>
                  <label className="text-xs font-semibold text-stone-700 block mb-1">Nombre completo *</label>
                  <input
                    value={draft.name}
                    onChange={(e) => setDraft({ ...draft, name: e.target.value })}
                    placeholder="Ej: María Pérez"
                    autoFocus
                    className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-emerald-500"
                  />
                </div>
                <div>
                  <label className="text-xs font-semibold text-stone-700 block mb-1">Cédula *</label>
                  <input
                    value={draft.documentId}
                    onChange={(e) => setDraft({ ...draft, documentId: e.target.value })}
                    placeholder="V-12345678"
                    className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-emerald-500 font-mono"
                  />
                </div>
                <div>
                  <label className="text-xs font-semibold text-stone-700 block mb-1">Teléfono</label>
                  <input
                    value={draft.phone}
                    onChange={(e) => setDraft({ ...draft, phone: e.target.value })}
                    placeholder="0414-1234567"
                    className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-emerald-500 font-mono"
                  />
                  <div className="text-xs text-stone-400 mt-0.5">Pre-rellenado del chat. Puedes cambiarlo si difiere.</div>
                </div>
              </>
            ) : (
              <>
                <div className="bg-orange-50 border border-orange-200 rounded-xl p-2.5 text-xs text-orange-900 flex items-start gap-2">
                  <PawPrint size={11} className="text-orange-700 flex-shrink-0 mt-0.5" />
                  <span>Registra la mascota principal de <strong>{draft.name}</strong>. Más mascotas se pueden agregar luego desde Pasaportes.</span>
                </div>
                <div>
                  <label className="text-xs font-semibold text-stone-700 block mb-1">Nombre de la mascota *</label>
                  <input
                    value={draft.pet.name}
                    onChange={(e) => setDraft({ ...draft, pet: { ...draft.pet, name: e.target.value } })}
                    placeholder="Ej: Toby"
                    autoFocus
                    className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-emerald-500"
                  />
                </div>
                <div>
                  <label className="text-xs font-semibold text-stone-700 block mb-1">Especie *</label>
                  <div className="grid grid-cols-3 gap-1.5">
                    {[
                      { id: "dog", label: "Perro", Icon: Dog },
                      { id: "cat", label: "Gato", Icon: Cat },
                      { id: "bird", label: "Ave", Icon: Bird },
                      { id: "rabbit", label: "Conejo", Icon: Rabbit },
                      { id: "rat", label: "Roedor", Icon: Rat },
                      { id: "fish", label: "Pez", Icon: Fish },
                      { id: "other", label: "Otros", Icon: PawPrint },
                    ].map(opt => {
                      const Ic = opt.Icon;
                      const active = draft.pet.species === opt.id;
                      return (
                        <button
                          key={opt.id}
                          onClick={() => setDraft({ ...draft, pet: { ...draft.pet, species: opt.id } })}
                          className={`flex flex-col items-center gap-1 p-2 rounded-lg border-2 text-xs font-semibold transition ${
                            active ? "border-emerald-500 bg-emerald-50 text-emerald-800" : "border-stone-200 hover:border-emerald-300"
                          }`}
                        >
                          <Ic size={14} strokeWidth={active ? 2.2 : 1.8} />
                          {opt.label}
                        </button>
                      );
                    })}
                  </div>
                </div>
                <div className="grid grid-cols-2 gap-2">
                  <div>
                    <label className="text-xs font-semibold text-stone-700 block mb-1">Raza</label>
                    <input
                      value={draft.pet.breed}
                      onChange={(e) => setDraft({ ...draft, pet: { ...draft.pet, breed: e.target.value } })}
                      placeholder="Ej: Labrador"
                      className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-emerald-500"
                    />
                  </div>
                  <div>
                    <label className="text-xs font-semibold text-stone-700 block mb-1">Edad</label>
                    <input
                      value={draft.pet.age}
                      onChange={(e) => setDraft({ ...draft, pet: { ...draft.pet, age: e.target.value } })}
                      placeholder="Ej: 4 años"
                      className="w-full px-3 py-2 bg-white border border-stone-200 rounded-xl text-sm outline-none focus:border-emerald-500"
                    />
                  </div>
                </div>
                <div>
                  <label className="text-xs font-semibold text-stone-700 block mb-1">Sexo</label>
                  <div className="flex gap-1.5">
                    {["Macho", "Hembra"].map(g => (
                      <button
                        key={g}
                        onClick={() => setDraft({ ...draft, pet: { ...draft.pet, gender: g } })}
                        className={`flex-1 px-3 py-2 rounded-lg border text-xs font-semibold transition ${
                          draft.pet.gender === g ? "border-emerald-500 bg-emerald-50 text-emerald-800" : "border-stone-200 hover:border-emerald-300"
                        }`}
                      >
                        {g}
                      </button>
                    ))}
                  </div>
                </div>
              </>
            )}
          </div>
        )}

        <div className="p-3 border-t border-stone-200 bg-stone-50 flex gap-2">
          <button onClick={onClose} className="px-3 py-2 rounded-xl text-sm font-semibold bg-white border border-stone-200 hover:border-stone-400 text-stone-700">
            Cancelar
          </button>
          {mode === "create" && step === 1 && (
            <button
              onClick={() => (draft.name.trim() && draft.documentId.trim()) && setStep(2)}
              disabled={!draft.name.trim() || !draft.documentId.trim()}
              className={`flex-1 px-3 py-2 rounded-xl text-sm font-semibold transition shadow ${
                draft.name.trim() && draft.documentId.trim() ? "bg-emerald-500 hover:bg-emerald-600 text-white" : "bg-stone-200 text-stone-400 cursor-not-allowed"
              }`}
            >
              Siguiente <ChevronRight size={12} className="inline" strokeWidth={2.5} />
            </button>
          )}
          {mode === "create" && step === 2 && (
            <>
              <button
                onClick={() => setStep(1)}
                className="px-3 py-2 rounded-xl text-sm font-semibold bg-white border border-stone-200 hover:border-stone-400 text-stone-700"
              >
                <ChevronLeft size={12} className="inline" /> Atrás
              </button>
              <button
                onClick={() => onLink(draft)}
                disabled={!draft.pet.name.trim()}
                className={`flex-1 px-3 py-2 rounded-xl text-sm font-semibold transition shadow ${
                  draft.pet.name.trim() ? "bg-emerald-500 hover:bg-emerald-600 text-white" : "bg-stone-200 text-stone-400 cursor-not-allowed"
                }`}
              >
                <Check size={12} className="inline" strokeWidth={2.5} /> Crear y vincular
              </button>
            </>
          )}
        </div>
      </div>
    </div>
  );
}

// ========== Editor de notas clínicas con secciones independientes ==========
// Cada campo (motivo, examen, diagnóstico, etc.) es un slot expandible.
// El vet va llenando uno a uno sin tener que scrollear o pelearse con un blob de texto.
// Inspirado en la hoja física del veterinario: secciones predefinidas con su propio espacio.
function ClinicalNotesEditor({ patientName, notes = {}, onChangeField }) {
  // Definición de los slots — el orden refleja el flujo natural de una consulta
  const SLOTS = [
    {
      id: "motivo",
      label: "Motivo de consulta",
      icon: AlertCircle,
      placeholder: "¿Por qué viene el tutor? Síntomas reportados, duración, evolución.",
      rows: 2,
    },
    {
      id: "examenFisico",
      label: "Evaluación física",
      icon: Activity,
      placeholder: "Peso, FC, FR, temperatura, mucosas, TLLC, ICC, ganglios, estatus.",
      rows: 3,
    },
    {
      id: "sistemas",
      label: "Revisión por sistemas",
      icon: Stethoscope,
      placeholder: "Digestivo, respiratorio, cardiovascular, urinario, reproductor, nervioso, piel, etc.",
      rows: 3,
    },
    {
      id: "examenes",
      label: "Exámenes / resultados",
      icon: FlaskConical,
      placeholder: "Hematología, química, citología, ecografía, radiografías, etc.",
      rows: 2,
    },
    {
      id: "fotos",
      label: "Fotos clínicas",
      icon: Camera,
      type: "photos",
    },
    {
      id: "diagnostico",
      label: "Diagnóstico",
      icon: BadgeCheck,
      placeholder: "Diagnóstico presuntivo o definitivo. Diferenciales si los hay.",
      rows: 2,
    },
    {
      id: "tratamiento",
      label: "Tratamiento",
      icon: Pill,
      placeholder: "Plan terapéutico, medicación prescrita, indicaciones para el tutor.",
      rows: 3,
    },
    {
      id: "recetas",
      label: "Recipe / Receta médica",
      icon: FileText,
      type: "recipe",
    },
    {
      id: "fechaControl",
      label: "Fecha de control / culminación",
      icon: CalendarClock,
      placeholder: "Próxima visita, criterio de alta, observaciones de seguimiento.",
      rows: 2,
    },
  ];

  // Track de qué slots están abiertos. Por defecto: el primero (motivo) abierto, resto cerrados.
  const [openSlots, setOpenSlots] = useState(() => ({ motivo: true }));

  const toggleSlot = (id) => {
    setOpenSlots(prev => ({ ...prev, [id]: !prev[id] }));
  };

  // Helpers para fotos (guardadas como JSON array de base64 en notes.fotos)
  const photos = useMemo(() => {
    try { return JSON.parse(notes.fotos || "[]"); } catch { return []; }
  }, [notes.fotos]);

  const addPhoto = (e) => {
    const files = e.target.files;
    if (!files?.length) return;
    Array.from(files).forEach(file => {
      const reader = new FileReader();
      reader.onload = (ev) => {
        const current = (() => { try { return JSON.parse(notes.fotos || "[]"); } catch { return []; } })();
        const newPhoto = {
          id: `ph-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 5)}`,
          data: ev.target.result,
          name: file.name,
          date: new Date().toISOString(),
          caption: "",
        };
        onChangeField("fotos", JSON.stringify([...current, newPhoto]));
      };
      reader.readAsDataURL(file);
    });
    e.target.value = "";
  };

  const removePhoto = (photoId) => {
    const updated = photos.filter(p => p.id !== photoId);
    onChangeField("fotos", JSON.stringify(updated));
  };

  const updatePhotoCaption = (photoId, caption) => {
    const updated = photos.map(p => p.id === photoId ? { ...p, caption } : p);
    onChangeField("fotos", JSON.stringify(updated));
  };

  // Helpers para recetas (guardadas como JSON array en notes.recetas)
  const recipes = useMemo(() => {
    try { return JSON.parse(notes.recetas || "[]"); } catch { return []; }
  }, [notes.recetas]);

  const addRecipe = () => {
    const current = (() => { try { return JSON.parse(notes.recetas || "[]"); } catch { return []; } })();
    const newRecipe = {
      id: `rx-${Date.now().toString(36)}`,
      medication: "",
      dose: "",
      frequency: "",
      duration: "",
      route: "",
      instructions: "",
    };
    onChangeField("recetas", JSON.stringify([...current, newRecipe]));
  };

  const updateRecipe = (recipeId, field, value) => {
    const updated = recipes.map(r => r.id === recipeId ? { ...r, [field]: value } : r);
    onChangeField("recetas", JSON.stringify(updated));
  };

  const removeRecipe = (recipeId) => {
    const updated = recipes.filter(r => r.id !== recipeId);
    onChangeField("recetas", JSON.stringify(updated));
  };

  // Stats: cuántos slots están llenos
  const slotHasContent = (slot) => {
    if (slot.type === "photos") return photos.length > 0;
    if (slot.type === "recipe") return recipes.length > 0;
    return (notes[slot.id] || "").trim().length > 0;
  };
  const filledCount = SLOTS.filter(slotHasContent).length;

  return (
    <div className="bg-white border border-stone-200 rounded-xl overflow-hidden">
      {/* Header global */}
      <div className="p-3 border-b border-stone-200 bg-stone-50 flex items-center gap-2">
        <FileText size={13} className="text-stone-600 flex-shrink-0" />
        <div className="flex-1 min-w-0">
          <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold">
            Cuadro clínico
          </div>
          <div className="text-xs text-stone-600">
            {filledCount === 0
              ? `Llena las secciones que apliquen para ${patientName}`
              : `${filledCount} de ${SLOTS.length} secciones · se guardará al cerrar`}
          </div>
        </div>
        {filledCount > 0 && (
          <span className="text-xs font-bold px-2 py-0.5 rounded-full bg-emerald-100 text-emerald-800 flex items-center gap-1">
            <CheckCircle size={10} strokeWidth={2.5} />
            {filledCount}
          </span>
        )}
      </div>

      {/* Slots */}
      <div className="divide-y divide-stone-100">
        {SLOTS.map(slot => {
          const Ic = slot.icon;
          const isOpen = !!openSlots[slot.id];
          const hasContent = slotHasContent(slot);
          const value = notes[slot.id] || "";
          const countLabel = slot.type === "photos"
            ? (photos.length > 0 ? `${photos.length} foto${photos.length !== 1 ? "s" : ""}` : null)
            : slot.type === "recipe"
              ? (recipes.length > 0 ? `${recipes.length} receta${recipes.length !== 1 ? "s" : ""}` : null)
              : (hasContent ? value : null);

          return (
            <div key={slot.id}>
              {/* Header del slot — siempre clickeable */}
              <button
                onClick={() => toggleSlot(slot.id)}
                className="w-full flex items-center gap-2.5 p-2.5 hover:bg-stone-50 transition text-left"
              >
                <div className={`w-7 h-7 rounded-lg grid place-items-center flex-shrink-0 transition ${
                  hasContent ? "bg-emerald-100 text-emerald-700" : "bg-stone-100 text-stone-500"
                }`}>
                  <Ic size={12} strokeWidth={hasContent ? 2.2 : 1.8} />
                </div>
                <div className="flex-1 min-w-0">
                  <div className="text-sm font-semibold text-stone-800 truncate">{slot.label}</div>
                  {!isOpen && hasContent && (
                    <div className="text-xs text-stone-500 truncate">{countLabel}</div>
                  )}
                  {!isOpen && !hasContent && (
                    <div className="text-xs text-stone-400 italic">Sin completar</div>
                  )}
                </div>
                {hasContent && !isOpen && (
                  <CheckCircle size={12} className="text-emerald-500 flex-shrink-0" strokeWidth={2.5} />
                )}
                <ChevronDown size={13} className={`text-stone-400 flex-shrink-0 transition-transform ${isOpen ? "rotate-180" : ""}`} />
              </button>

              {/* Body del slot */}
              {isOpen && slot.type === "photos" && (
                <div className="px-2.5 pb-2.5 space-y-2">
                  {/* Grid de fotos */}
                  {photos.length > 0 && (
                    <div className="grid grid-cols-3 gap-1.5">
                      {photos.map(ph => (
                        <div key={ph.id} className="relative group rounded-lg overflow-hidden border border-stone-200 bg-stone-50">
                          <img src={ph.data} alt={ph.caption || ph.name} className="w-full h-20 object-cover" />
                          <button
                            onClick={() => removePhoto(ph.id)}
                            className="absolute top-1 right-1 w-5 h-5 rounded-full bg-red-600 text-white grid place-items-center opacity-0 group-hover:opacity-100 transition"
                          >
                            <X size={9} />
                          </button>
                          <input
                            type="text"
                            value={ph.caption || ""}
                            onChange={(e) => updatePhotoCaption(ph.id, e.target.value)}
                            placeholder="Nota..."
                            className="w-full px-1.5 py-1 text-[10px] border-t border-stone-200 outline-none bg-white placeholder:text-stone-300"
                          />
                        </div>
                      ))}
                    </div>
                  )}
                  {/* Botón subir */}
                  <label className="flex items-center justify-center gap-2 px-3 py-2.5 rounded-xl border-2 border-dashed border-stone-200 hover:border-emerald-400 text-stone-500 hover:text-emerald-700 cursor-pointer transition text-xs font-semibold">
                    <Camera size={13} /> Subir fotos clínicas
                    <input type="file" accept="image/*" multiple onChange={addPhoto} className="hidden" />
                  </label>
                  <div className="text-[10px] text-stone-400 px-1">
                    Fotos del paciente, lesiones, radiografías, ecografías. Se guardan en el historial.
                  </div>
                </div>
              )}

              {isOpen && slot.type === "recipe" && (
                <div className="px-2.5 pb-2.5 space-y-2">
                  {recipes.map((rx, idx) => (
                    <div key={rx.id} className="bg-orange-50 border border-orange-200 rounded-xl p-2.5 space-y-1.5">
                      <div className="flex items-center justify-between">
                        <span className="text-xs font-bold text-orange-800">Receta #{idx + 1}</span>
                        <button onClick={() => removeRecipe(rx.id)} className="text-stone-400 hover:text-red-500 transition">
                          <X size={11} />
                        </button>
                      </div>
                      <input
                        type="text" value={rx.medication}
                        onChange={(e) => updateRecipe(rx.id, "medication", e.target.value)}
                        placeholder="Medicamento *"
                        className="w-full px-2.5 py-1.5 border border-stone-200 rounded-lg text-xs outline-none focus:border-orange-400 bg-white font-semibold"
                      />
                      <div className="grid grid-cols-2 gap-1.5">
                        <input type="text" value={rx.dose} onChange={(e) => updateRecipe(rx.id, "dose", e.target.value)}
                          placeholder="Dosis (ej: 500mg)" className="px-2.5 py-1.5 border border-stone-200 rounded-lg text-xs outline-none focus:border-orange-400 bg-white" />
                        <input type="text" value={rx.route} onChange={(e) => updateRecipe(rx.id, "route", e.target.value)}
                          placeholder="Vía (oral, IM, IV)" className="px-2.5 py-1.5 border border-stone-200 rounded-lg text-xs outline-none focus:border-orange-400 bg-white" />
                      </div>
                      <div className="grid grid-cols-2 gap-1.5">
                        <input type="text" value={rx.frequency} onChange={(e) => updateRecipe(rx.id, "frequency", e.target.value)}
                          placeholder="Frecuencia (c/8h)" className="px-2.5 py-1.5 border border-stone-200 rounded-lg text-xs outline-none focus:border-orange-400 bg-white" />
                        <input type="text" value={rx.duration} onChange={(e) => updateRecipe(rx.id, "duration", e.target.value)}
                          placeholder="Duración (7 días)" className="px-2.5 py-1.5 border border-stone-200 rounded-lg text-xs outline-none focus:border-orange-400 bg-white" />
                      </div>
                      <textarea value={rx.instructions} onChange={(e) => updateRecipe(rx.id, "instructions", e.target.value)}
                        placeholder="Indicaciones especiales para el tutor..." rows={2}
                        className="w-full px-2.5 py-1.5 border border-stone-200 rounded-lg text-xs outline-none focus:border-orange-400 bg-white resize-none" />
                    </div>
                  ))}
                  <button
                    onClick={addRecipe}
                    className="w-full flex items-center justify-center gap-1.5 px-3 py-2.5 rounded-xl border-2 border-dashed border-orange-200 hover:border-orange-400 text-orange-600 hover:text-orange-700 transition text-xs font-semibold"
                  >
                    <Plus size={12} /> Agregar receta
                  </button>
                </div>
              )}

              {isOpen && !slot.type && (
                <div className="px-2.5 pb-2.5">
                  <textarea
                    value={value}
                    onChange={(e) => onChangeField(slot.id, e.target.value)}
                    rows={slot.rows}
                    placeholder={slot.placeholder}
                    className="w-full px-3 py-2 bg-stone-50 border border-stone-200 rounded-lg text-sm outline-none focus:border-orange-400 focus:bg-white resize-y placeholder:text-stone-400 placeholder:text-xs leading-relaxed"
                  />
                  {hasContent && (
                    <div className="text-xs text-stone-400 mt-1 px-1">
                      {value.length} caracteres
                    </div>
                  )}
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* Acciones rápidas: expandir / colapsar todo */}
      <div className="px-3 py-2 border-t border-stone-200 bg-stone-50 flex items-center justify-between">
        <button
          onClick={() => {
            const allOpen = SLOTS.every(s => openSlots[s.id]);
            setOpenSlots(SLOTS.reduce((acc, s) => ({ ...acc, [s.id]: !allOpen }), {}));
          }}
          className="text-xs font-semibold text-stone-600 hover:text-stone-900 flex items-center gap-1 transition"
        >
          {SLOTS.every(s => openSlots[s.id]) ? (
            <><Minimize2 size={10} /> Colapsar todas</>
          ) : (
            <><Maximize2 size={10} /> Expandir todas</>
          )}
        </button>
        {filledCount > 0 && (
          <span className="text-xs text-emerald-700 font-semibold flex items-center gap-1">
            <CheckCircle size={10} strokeWidth={2.5} /> Auto-guardando
          </span>
        )}
      </div>
    </div>
  );
}

// ========== Visor flotante de historial clínico ==========
// Ventana arrastrable estilo macOS que muestra las consultas anteriores del paciente
// con la MISMA estructura que el editor (motivo, examen, diagnóstico, etc.).
// El vet revisa la evolución clínica sin perder de vista la consulta actual.
function PatientHistoryViewer({ patient, passport, onClose }) {
  const [position, setPosition] = useState({ x: 60, y: 60 });
  const [maximized, setMaximized] = useState(false);
  const [minimized, setMinimized] = useState(false);
  const [dragging, setDragging] = useState(false);
  const dragOffsetRef = useRef({ x: 0, y: 0 });

  // Filtros de tipo
  const [filterType, setFilterType] = useState("all"); // all | consulta | vacuna | cirugia
  // Selección de un evento para ver detalles completos
  const [selectedId, setSelectedId] = useState(null);

  const allEvents = useMemo(() => {
    if (!passport?.clinicHistory) return [];
    // Ordenar más reciente primero
    return [...passport.clinicHistory].sort((a, b) => (b.date || "").localeCompare(a.date || ""));
  }, [passport]);

  const filteredEvents = useMemo(() => {
    if (filterType === "all") return allEvents;
    return allEvents.filter(e => e.type === filterType);
  }, [allEvents, filterType]);

  // Auto-seleccionar el más reciente al abrir
  useEffect(() => {
    if (!selectedId && filteredEvents.length > 0) {
      setSelectedId(filteredEvents[0].id);
    }
  }, [filteredEvents, selectedId]);

  const selected = filteredEvents.find(e => e.id === selectedId);

  // Drag de la ventana
  const handleHeaderMouseDown = (e) => {
    if (maximized || minimized) return;
    if (e.target.closest("button")) return;
    dragOffsetRef.current = { x: e.clientX - position.x, y: e.clientY - position.y };
    setDragging(true);
  };
  useEffect(() => {
    if (!dragging) return;
    const onMove = (e) => {
      setPosition({
        x: Math.max(0, Math.min(window.innerWidth - 200, e.clientX - dragOffsetRef.current.x)),
        y: Math.max(0, Math.min(window.innerHeight - 80, e.clientY - dragOffsetRef.current.y)),
      });
    };
    const onUp = () => setDragging(false);
    window.addEventListener("mousemove", onMove);
    window.addEventListener("mouseup", onUp);
    return () => {
      window.removeEventListener("mousemove", onMove);
      window.removeEventListener("mouseup", onUp);
    };
  }, [dragging]);

  // Estilos según estado
  let style = {};
  let containerClass = "fixed z-50 bg-white rounded-xl shadow-2xl border border-stone-300 flex flex-col overflow-hidden";
  if (minimized) {
    containerClass += " bottom-4 left-4 w-72 h-12";
  } else if (maximized) {
    containerClass += " inset-4";
  } else {
    containerClass += " max-w-full max-h-screen";
    style = { left: position.x, top: position.y, width: 720, height: 560 };
  }

  // Definición de los slots para mostrar (mismas secciones que el editor)
  const FIELD_LABELS = [
    { id: "motivo",        label: "Motivo de consulta",      icon: AlertCircle },
    { id: "examenFisico",  label: "Evaluación física",       icon: Activity },
    { id: "sistemas",      label: "Revisión por sistemas",   icon: Stethoscope },
    { id: "examenes",      label: "Exámenes / resultados",   icon: FlaskConical },
    { id: "diagnostico",   label: "Diagnóstico",             icon: BadgeCheck },
    { id: "tratamiento",   label: "Tratamiento",             icon: Pill },
    { id: "fechaControl",  label: "Fecha de control",        icon: CalendarClock },
  ];

  return (
    <div className={containerClass} style={style}>
      {/* Title bar */}
      <div
        onMouseDown={handleHeaderMouseDown}
        onDoubleClick={() => { if (!minimized) setMaximized(m => !m); }}
        className={`flex items-center gap-2 px-3 py-2 bg-stone-100 border-b border-stone-200 ${
          maximized || minimized ? "" : "cursor-move"
        } select-none flex-shrink-0`}
      >
        {/* Dots macOS */}
        <div className="flex gap-1.5 mr-2">
          <button onClick={onClose} title="Cerrar" className="w-3 h-3 rounded-full bg-red-400 hover:bg-red-500 transition"></button>
          <button onClick={() => setMinimized(true)} title="Minimizar" className="w-3 h-3 rounded-full bg-amber-400 hover:bg-amber-500 transition"></button>
          <button onClick={() => { setMaximized(m => !m); setMinimized(false); }} title="Maximizar" className="w-3 h-3 rounded-full bg-emerald-400 hover:bg-emerald-500 transition"></button>
        </div>
        <History size={13} className="text-stone-600 flex-shrink-0" />
        <div className="flex-1 min-w-0 flex items-baseline gap-1.5">
          <span className="font-serif font-semibold text-sm">Consultas anteriores</span>
          <span className="text-stone-400">·</span>
          <span className="text-xs text-stone-600 truncate">{patient.name}</span>
          {patient.code && (
            <span className="font-mono text-xs text-orange-700 font-bold">#{patient.code}</span>
          )}
        </div>
        {minimized ? (
          <button onClick={() => setMinimized(false)} title="Restaurar" className="w-7 h-7 rounded grid place-items-center hover:bg-stone-200 text-stone-600">
            <Maximize2 size={11} />
          </button>
        ) : (
          <button onClick={() => setMaximized(m => !m)} title={maximized ? "Restaurar" : "Maximizar"} className="w-7 h-7 rounded grid place-items-center hover:bg-stone-200 text-stone-600">
            {maximized ? <Minimize2 size={11} /> : <Maximize2 size={11} />}
          </button>
        )}
      </div>

      {/* Body — solo si no está minimizada */}
      {!minimized && (
        <div className="flex-1 flex overflow-hidden min-h-0">
          {/* Sidebar izquierdo: lista de consultas */}
          <div className="w-64 flex-shrink-0 border-r border-stone-200 flex flex-col bg-stone-50">
            {/* Filtros */}
            <div className="p-2 border-b border-stone-200 bg-white flex gap-1">
              {[
                { id: "all", label: "Todas", count: allEvents.length },
                { id: "consulta", label: "Consultas", count: allEvents.filter(e => e.type === "consulta").length },
              ].map(f => (
                <button
                  key={f.id}
                  onClick={() => setFilterType(f.id)}
                  className={`flex-1 px-2 py-1 rounded text-xs font-semibold transition flex items-center justify-center gap-1 ${
                    filterType === f.id ? "bg-stone-900 text-white" : "bg-stone-100 text-stone-600 hover:bg-stone-200"
                  }`}
                >
                  {f.label}
                  <span className={`text-xs font-bold px-1 rounded ${
                    filterType === f.id ? "bg-white text-stone-900" : "bg-white text-stone-500"
                  }`}>
                    {f.count}
                  </span>
                </button>
              ))}
            </div>

            {/* Lista */}
            <div className="flex-1 overflow-y-auto">
              {filteredEvents.length === 0 ? (
                <div className="p-6 text-center text-xs text-stone-500">
                  Sin consultas registradas todavía. La primera consulta de {patient.name} aparecerá aquí cuando termine la atención actual.
                </div>
              ) : (
                filteredEvents.map(ev => {
                  const isActive = ev.id === selectedId;
                  return (
                    <button
                      key={ev.id}
                      onClick={() => setSelectedId(ev.id)}
                      className={`w-full p-2.5 border-b border-stone-200 text-left transition ${
                        isActive ? "bg-orange-50 border-l-4 border-l-orange-500" : "hover:bg-stone-100 border-l-4 border-l-transparent"
                      }`}
                    >
                      <div className="flex items-center gap-1.5 mb-0.5">
                        <span className="text-xs font-bold font-mono text-stone-700">{ev.date}</span>
                        <span className="text-xs px-1.5 py-px rounded bg-stone-200 text-stone-700 capitalize">
                          {ev.type}
                        </span>
                      </div>
                      <div className="text-xs text-stone-500 truncate" title={ev.summary}>
                        {ev.summary || "Sin resumen"}
                      </div>
                      <div className="text-xs text-stone-400 italic mt-0.5">
                        {ev.vet}
                      </div>
                    </button>
                  );
                })
              )}
            </div>
          </div>

          {/* Panel derecho: detalle del evento seleccionado */}
          <div className="flex-1 overflow-y-auto bg-white min-w-0">
            {!selected ? (
              <div className="h-full flex items-center justify-center text-center p-6">
                <div>
                  <FileText size={32} className="text-stone-300 mx-auto mb-2" strokeWidth={1.6} />
                  <div className="text-sm font-semibold text-stone-700">Selecciona una consulta</div>
                  <div className="text-xs text-stone-500 mt-0.5">para ver sus detalles</div>
                </div>
              </div>
            ) : (
              <div className="p-4 space-y-3">
                {/* Header del detalle */}
                <div className="pb-3 border-b border-stone-200">
                  <div className="flex items-baseline gap-2">
                    <span className="font-mono text-sm font-bold text-stone-800">{selected.date}</span>
                    <span className="text-xs px-2 py-0.5 rounded-full bg-stone-100 text-stone-700 capitalize">
                      {selected.type}
                    </span>
                  </div>
                  <div className="text-xs text-stone-500 mt-1 flex items-center gap-1">
                    <User size={10} /> {selected.vet}
                  </div>
                </div>

                {/* Campos estructurados (formato nuevo) */}
                {selected.fields ? (
                  FIELD_LABELS.map(slot => {
                    const Ic = slot.icon;
                    const value = (selected.fields[slot.id] || "").trim();
                    if (!value) return null; // ocultar slots vacíos
                    return (
                      <div key={slot.id} className="border-l-2 border-orange-200 pl-3">
                        <div className="flex items-center gap-1.5 mb-1">
                          <Ic size={11} className="text-orange-700 flex-shrink-0" />
                          <span className="text-xs tracking-widest uppercase text-orange-700 font-semibold">
                            {slot.label}
                          </span>
                        </div>
                        <p className="text-sm text-stone-800 whitespace-pre-wrap leading-relaxed">{value}</p>
                      </div>
                    );
                  })
                ) : (
                  // Formato legacy (string) — fallback
                  <div className="border-l-2 border-stone-200 pl-3">
                    <p className="text-sm text-stone-800 whitespace-pre-wrap leading-relaxed">
                      {selected.summary || "Sin notas"}
                    </p>
                  </div>
                )}

                {/* Insumos usados en esa consulta */}
                {selected.supplies && selected.supplies.length > 0 && (
                  <div className="bg-emerald-50 border border-emerald-200 rounded-xl p-3">
                    <div className="flex items-center gap-1.5 mb-2">
                      <Pill size={11} className="text-emerald-700" />
                      <span className="text-xs tracking-widest uppercase text-emerald-800 font-semibold">
                        Insumos / medicación
                      </span>
                    </div>
                    <div className="space-y-1">
                      {selected.supplies.map((s, idx) => (
                        <div key={idx} className="flex items-baseline gap-2 text-xs">
                          <span className="w-1 h-1 rounded-full bg-emerald-500 flex-shrink-0"></span>
                          <span className="text-stone-700 flex-1 truncate">{s.name}</span>
                          <span className="font-mono text-stone-600 flex-shrink-0">{s.qty} {s.unit}</span>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

// ========== Modal de detalle de un evento clínico ==========
// Se abre al hacer click en la lupa de cualquier evento del historial.
// Muestra todos los campos del evento con secciones estructuradas si existen.
function ClinicalEventDetailModal({ event, patientName, patientCode, onClose }) {
  // === Estado de ventana flotante (mismo patrón que VetAgendaModal) ===
  const [position, setPosition] = useState({ x: 100, y: 80 });
  const [maximized, setMaximized] = useState(false);
  const [minimized, setMinimized] = useState(false);
  const [dragging, setDragging] = useState(false);
  const dragOffsetRef = useRef({ x: 0, y: 0 });

  // Drag desde el title bar
  const handleHeaderMouseDown = (e) => {
    if (maximized || minimized) return;
    if (e.target.closest("button")) return;
    dragOffsetRef.current = { x: e.clientX - position.x, y: e.clientY - position.y };
    setDragging(true);
  };
  useEffect(() => {
    if (!dragging) return;
    const onMove = (e) => {
      setPosition({
        x: Math.max(0, Math.min(window.innerWidth - 200, e.clientX - dragOffsetRef.current.x)),
        y: Math.max(0, Math.min(window.innerHeight - 80, e.clientY - dragOffsetRef.current.y)),
      });
    };
    const onUp = () => setDragging(false);
    window.addEventListener("mousemove", onMove);
    window.addEventListener("mouseup", onUp);
    return () => {
      window.removeEventListener("mousemove", onMove);
      window.removeEventListener("mouseup", onUp);
    };
  }, [dragging]);

  // === Mapeos ===
  const typeInfo = {
    consulta:        { label: "Consulta",         Icon: Stethoscope, color: "orange",  bgGradient: "from-orange-50 to-orange-100" },
    vet:             { label: "Consulta",         Icon: Stethoscope, color: "orange",  bgGradient: "from-orange-50 to-orange-100" },
    vacuna:          { label: "Vacunación",       Icon: Syringe,     color: "blue",    bgGradient: "from-blue-50 to-blue-100" },
    vaccination:     { label: "Vacunación",       Icon: Syringe,     color: "blue",    bgGradient: "from-blue-50 to-blue-100" },
    tratamiento:     { label: "Tratamiento",      Icon: Pill,        color: "purple",  bgGradient: "from-purple-50 to-purple-100" },
    treatment:       { label: "Tratamiento",      Icon: Pill,        color: "purple",  bgGradient: "from-purple-50 to-purple-100" },
    deworming:       { label: "Desparasitación",  Icon: Pill,        color: "emerald", bgGradient: "from-emerald-50 to-emerald-100" },
    desparasitacion: { label: "Desparasitación",  Icon: Pill,        color: "emerald", bgGradient: "from-emerald-50 to-emerald-100" },
    cirugia:         { label: "Cirugía",          Icon: Scissors,    color: "red",     bgGradient: "from-red-50 to-red-100" },
    cirugía:         { label: "Cirugía",          Icon: Scissors,    color: "red",     bgGradient: "from-red-50 to-red-100" },
    surgery:         { label: "Cirugía",          Icon: Scissors,    color: "red",     bgGradient: "from-red-50 to-red-100" },
    examen:          { label: "Examen",           Icon: FlaskConical,color: "blue",    bgGradient: "from-blue-50 to-blue-100" },
    examination:     { label: "Examen",           Icon: FlaskConical,color: "blue",    bgGradient: "from-blue-50 to-blue-100" },
    no_show:         { label: "Cita perdida",     Icon: AlertCircle, color: "stone",   bgGradient: "from-stone-50 to-stone-100" },
  }[event.type] || { label: event.type, Icon: Stethoscope, color: "stone", bgGradient: "from-stone-50 to-stone-100" };

  const colorClasses = {
    orange:  { headerText: "text-orange-700",  iconBg: "bg-orange-500",  border: "border-orange-200",  accent: "border-l-orange-300" },
    blue:    { headerText: "text-blue-700",    iconBg: "bg-blue-500",    border: "border-blue-200",    accent: "border-l-blue-300" },
    purple:  { headerText: "text-purple-700",  iconBg: "bg-purple-500",  border: "border-purple-200",  accent: "border-l-purple-300" },
    emerald: { headerText: "text-emerald-700", iconBg: "bg-emerald-500", border: "border-emerald-200", accent: "border-l-emerald-300" },
    red:     { headerText: "text-red-700",     iconBg: "bg-red-500",     border: "border-red-200",     accent: "border-l-red-300" },
    stone:   { headerText: "text-stone-700",   iconBg: "bg-stone-600",   border: "border-stone-200",   accent: "border-l-stone-300" },
  }[typeInfo.color];

  const Ic = typeInfo.Icon;

  // Slots estructurados (mismas etiquetas que el editor de notas)
  const FIELD_LABELS = [
    { id: "motivo",        label: "Motivo de consulta",      icon: AlertCircle },
    { id: "examenFisico",  label: "Evaluación física",       icon: Activity },
    { id: "sistemas",      label: "Revisión por sistemas",   icon: Stethoscope },
    { id: "examenes",      label: "Exámenes / resultados",   icon: FlaskConical },
    { id: "diagnostico",   label: "Diagnóstico",             icon: BadgeCheck },
    { id: "tratamiento",   label: "Tratamiento",             icon: Pill },
    { id: "fechaControl",  label: "Fecha de control",        icon: CalendarClock },
  ];

  // === Estilos según estado de ventana ===
  let style = {};
  let containerClass = "fixed z-50 bg-white rounded-xl shadow-2xl border border-stone-300 flex flex-col overflow-hidden";
  if (minimized) {
    containerClass += " bottom-4 right-4 w-72 h-12";
  } else if (maximized) {
    containerClass += " inset-4";
  } else {
    containerClass += " max-w-full max-h-screen";
    style = { left: position.x, top: position.y, width: 560, height: 600 };
  }

  return (
    <div className={containerClass} style={style}>
      {/* Title bar arrastrable estilo macOS */}
      <div
        onMouseDown={handleHeaderMouseDown}
        onDoubleClick={() => { if (!minimized) setMaximized(m => !m); }}
        className={`flex items-center gap-2 px-3 py-2 bg-stone-100 border-b border-stone-200 ${
          maximized || minimized ? "" : "cursor-move"
        } select-none flex-shrink-0`}
      >
        {/* Dots macOS */}
        <div className="flex gap-1.5 mr-2">
          <button onClick={onClose} title="Cerrar" className="w-3 h-3 rounded-full bg-red-400 hover:bg-red-500 transition"></button>
          <button onClick={() => setMinimized(true)} title="Minimizar" className="w-3 h-3 rounded-full bg-amber-400 hover:bg-amber-500 transition"></button>
          <button onClick={() => { setMaximized(m => !m); setMinimized(false); }} title="Maximizar" className="w-3 h-3 rounded-full bg-emerald-400 hover:bg-emerald-500 transition"></button>
        </div>
        <Ic size={13} className={`${colorClasses.headerText} flex-shrink-0`} />
        <div className="flex-1 min-w-0 flex items-baseline gap-1.5">
          <span className="font-serif font-semibold text-sm">{typeInfo.label}</span>
          <span className="text-stone-400">·</span>
          <span className="text-xs text-stone-600 truncate">{patientName}</span>
          {patientCode && (
            <span className="font-mono text-xs text-orange-700 font-bold">#{patientCode}</span>
          )}
        </div>
        {minimized ? (
          <button onClick={() => setMinimized(false)} title="Restaurar" className="w-7 h-7 rounded grid place-items-center hover:bg-stone-200 text-stone-600">
            <Maximize2 size={11} />
          </button>
        ) : (
          <button onClick={() => setMaximized(m => !m)} title={maximized ? "Restaurar" : "Maximizar"} className="w-7 h-7 rounded grid place-items-center hover:bg-stone-200 text-stone-600">
            {maximized ? <Minimize2 size={11} /> : <Maximize2 size={11} />}
          </button>
        )}
      </div>

      {/* Body — solo si no está minimizada */}
      {!minimized && (
        <>
          {/* Sub-header con título grande del evento */}
          <div className={`p-4 border-b ${colorClasses.border} bg-gradient-to-br ${typeInfo.bgGradient} flex items-start gap-3 flex-shrink-0`}>
            <div className={`w-11 h-11 rounded-xl ${colorClasses.iconBg} text-white grid place-items-center shadow-lg flex-shrink-0`}>
              <Ic size={18} strokeWidth={2} />
            </div>
            <div className="flex-1 min-w-0">
              <div className={`text-xs tracking-widest uppercase font-bold ${colorClasses.headerText}`}>
                Detalle del evento · {typeInfo.label}
              </div>
              <h3 className="font-serif text-xl font-semibold mt-0.5 leading-tight">
                {event.title || typeInfo.label}
              </h3>
              <div className="text-xs text-stone-600 mt-0.5">
                {event.date} {(event.author || event.vet) && `· ${event.author || event.vet}`}
              </div>
            </div>
          </div>

          {/* Body con scroll */}
          <div className="flex-1 overflow-y-auto p-4 space-y-3 min-h-0">
            {/* Datos básicos */}
            <div className="grid grid-cols-2 gap-2">
              <div className="bg-stone-50 border border-stone-200 rounded-xl p-3">
                <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold">Fecha</div>
                <div className="font-mono text-sm font-bold text-stone-800 mt-0.5">{event.date}</div>
              </div>
              {(event.author || event.vet) && (
                <div className="bg-stone-50 border border-stone-200 rounded-xl p-3">
                  <div className="text-xs tracking-widest uppercase text-stone-500 font-semibold">Atendido por</div>
                  <div className="text-sm font-semibold text-stone-800 mt-0.5 truncate">{event.author || event.vet}</div>
                </div>
              )}
            </div>

            {/* Si tiene campos estructurados (consulta nueva) */}
            {event.fields ? (
              <div className="space-y-2">
                {FIELD_LABELS.map(slot => {
                  const Slot = slot.icon;
                  const value = (event.fields[slot.id] || "").trim();
                  if (!value) return null;
                  return (
                    <div key={slot.id} className={`border-l-4 ${colorClasses.accent} bg-stone-50 pl-3 pr-3 py-2.5 rounded-r-xl`}>
                      <div className="flex items-center gap-1.5 mb-1">
                        <Slot size={11} className={colorClasses.headerText} />
                        <span className={`text-xs tracking-widest uppercase font-bold ${colorClasses.headerText}`}>
                          {slot.label}
                        </span>
                      </div>
                      <p className="text-sm text-stone-800 whitespace-pre-wrap leading-relaxed">{value}</p>
                    </div>
                  );
                })}
              </div>
            ) : (
              // Formato legacy: nota como texto plano
              (event.note || event.summary) && (
                <div className={`border-l-4 ${colorClasses.accent} bg-stone-50 pl-3 pr-3 py-2.5 rounded-r-xl`}>
                  <div className="flex items-center gap-1.5 mb-1">
                    <FileText size={11} className={colorClasses.headerText} />
                    <span className={`text-xs tracking-widest uppercase font-bold ${colorClasses.headerText}`}>
                      Notas clínicas
                    </span>
                  </div>
                  <p className="text-sm text-stone-800 whitespace-pre-wrap leading-relaxed">
                    {event.note || event.summary}
                  </p>
                </div>
              )
            )}

            {/* Datos adicionales típicos de vacunación */}
            {event.lot && (
              <div className="bg-blue-50 border border-blue-200 rounded-xl p-3">
                <div className="text-xs tracking-widest uppercase text-blue-700 font-bold mb-1">Lote</div>
                <div className="font-mono text-sm font-bold text-blue-900">{event.lot}</div>
              </div>
            )}
            {event.nextDue && (
              <div className="bg-amber-50 border border-amber-200 rounded-xl p-3">
                <div className="text-xs tracking-widest uppercase text-amber-700 font-bold mb-1 flex items-center gap-1">
                  <CalendarClock size={11} /> Próxima dosis / control
                </div>
                <div className="font-mono text-sm font-bold text-amber-900">{event.nextDue}</div>
              </div>
            )}

            {/* Insumos usados */}
            {event.supplies && event.supplies.length > 0 && (
              <div className="bg-emerald-50 border border-emerald-200 rounded-xl p-3">
                <div className="flex items-center gap-1.5 mb-2">
                  <Pill size={11} className="text-emerald-700" />
                  <span className="text-xs tracking-widest uppercase text-emerald-800 font-bold">
                    Insumos / medicación usada
                  </span>
                </div>
                <div className="space-y-1">
                  {event.supplies.map((s, idx) => (
                    <div key={idx} className="flex items-baseline gap-2 text-sm">
                      <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 flex-shrink-0"></span>
                      <span className="text-stone-700 flex-1">{s.name}</span>
                      <span className="font-mono text-stone-600 text-xs flex-shrink-0">{s.qty} {s.unit}</span>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>

          {/* Footer */}
          <div className="p-2.5 border-t border-stone-200 bg-stone-50 flex justify-end gap-2 flex-shrink-0">
            <button className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-semibold bg-white border border-stone-200 hover:border-orange-300 text-stone-700 transition">
              <Printer size={11} /> Imprimir
            </button>
            <button onClick={onClose} className="px-3 py-1.5 rounded-lg text-xs font-semibold bg-stone-900 hover:bg-stone-800 text-white transition">
              Cerrar
            </button>
          </div>
        </>
      )}
    </div>
  );
}

// ========== Wizard: registrar pasaporte de paciente walk-in ==========
// Se abre cuando el vet hace click en una cita de Reserva sin pasaporte asociado.
// Pensado para que el veterinario NO pierda tiempo con datos administrativos:
//  - Solo pide los datos clínicos básicos de la mascota (nombre, especie, raza, edad, sexo).
//  - El nombre del tutor sólo se pregunta si la cita no lo trajo prefilled.
//  - Cédula y teléfono jamás se piden aquí — los completa ventas al momento de cobrar.
function WalkInPassportWizard({ context, onClose, onSubmit }) {
  const prefilled = context?.prefilled || {};
  const hasOwnerName = !!(prefilled.owner && prefilled.owner.trim());

  // Datos clínicos de la mascota (lo único que de verdad necesita el vet para arrancar)
  const [petName, setPetName]       = useState(prefilled.name || "");
  const [petSpecies, setPetSpecies] = useState(prefilled.species || "dog");
  const [petSpeciesOther, setPetSpeciesOther] = useState(""); // Texto libre cuando species = "other"
  const [petBreed, setPetBreed]     = useState(prefilled.breed || "");
  const [petAge, setPetAge]         = useState(prefilled.age || "");
  const [petGender, setPetGender]   = useState("");

  // Nombre del tutor — sólo se pide si la cita NO lo trajo. Cédula/teléfono nunca aquí.
  const [ownerName, setOwnerName]   = useState(prefilled.owner || "");

  const SPECIES = [
    { id: "dog",    label: "Perro",    Icon: Dog },
    { id: "cat",    label: "Gato",     Icon: Cat },
    { id: "bird",   label: "Ave",      Icon: Bird },
    { id: "rabbit", label: "Conejo",   Icon: Rabbit },
    { id: "fish",   label: "Pez",      Icon: Fish },
    { id: "rodent", label: "Roedor",   Icon: Rat },
    { id: "other",  label: "Otros",    Icon: PawPrint },
  ];

  // Mínimo para pasar a consulta: nombre y especie de la mascota.
  // Si la cita no trajo nombre de tutor, también lo exigimos para que el pasaporte no quede huérfano.
  // Si la especie es "other", también exigimos el texto que especifica cuál.
  const canSubmit = petName.trim() && petSpecies && (petSpecies !== "other" || petSpeciesOther.trim()) && (hasOwnerName || ownerName.trim());

  const handleSubmit = () => {
    if (!canSubmit) return;
    onSubmit({
      name: petName.trim(),
      species: petSpecies,
      speciesOther: petSpecies === "other" ? petSpeciesOther.trim() : "",
      breed: petBreed.trim(),
      age: petAge.trim(),
      gender: petGender,
      ownerName: ownerName.trim(),
      ownerPhone: "", // se completa en caja al cobrar
      ownerDoc: "",   // se completa en caja al cobrar
    });
  };

  return (
    <div onClick={onClose} className="fixed inset-0 bg-stone-900/70 z-50 flex justify-center items-start p-4 sm:p-12 overflow-y-auto">
      <div onClick={(e) => e.stopPropagation()} className="bg-stone-50 rounded-2xl w-full max-w-md shadow-2xl overflow-hidden flex flex-col">
        {/* Header */}
        <div className="p-4 border-b border-stone-200 bg-gradient-to-br from-amber-50 to-orange-50 flex items-start gap-3">
          <div className="w-11 h-11 rounded-xl bg-amber-500 text-white grid place-items-center shadow-lg flex-shrink-0">
            <Stethoscope size={18} strokeWidth={2} />
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-xs tracking-widest uppercase text-amber-700 font-bold">
              Datos básicos · Cita {context?.time || ""}
            </div>
            <h3 className="font-serif text-xl font-semibold mt-0.5 leading-tight">
              Pasar a consulta
            </h3>
            <p className="text-xs text-stone-600 mt-1">
              Sólo necesitamos los datos clínicos básicos de la mascota para abrir el pasaporte.
            </p>
          </div>
          <button onClick={onClose} className="w-8 h-8 rounded-lg bg-white hover:bg-stone-100 grid place-items-center text-stone-500 flex-shrink-0">
            <X size={13} />
          </button>
        </div>

        {/* Body */}
        <div className="flex-1 overflow-y-auto p-4 space-y-3">

          {/* Si la cita ya trajo el tutor, lo mostramos como contexto fijo (no editable aquí) */}
          {hasOwnerName && (
            <div className="bg-emerald-50 border border-emerald-200 rounded-lg p-2.5 flex items-center gap-2 text-xs text-emerald-800">
              <CheckCircle size={12} strokeWidth={2.5} className="flex-shrink-0" />
              <span>Tutor asociado: <strong>{prefilled.owner}</strong></span>
            </div>
          )}

          {/* Motivo de la cita (viene del evento de agenda) */}
          {context?.reason && (
            <div className="bg-blue-50 border border-blue-200 rounded-lg p-2.5">
              <div className="text-[10px] tracking-widest uppercase text-blue-700 font-bold mb-1 flex items-center gap-1">
                <Info size={11} /> Motivo de la cita
              </div>
              <div className="text-xs text-blue-900 leading-relaxed">{context.reason}</div>
            </div>
          )}

          {/* Mascota */}
          <div>
            <label className="text-xs tracking-widest uppercase text-stone-500 font-semibold block mb-1">
              Nombre de la mascota *
            </label>
            <input
              value={petName}
              onChange={(e) => setPetName(e.target.value)}
              placeholder="Bruno, Luna, Coco…"
              className="w-full px-3 py-2 bg-white border border-stone-200 rounded-lg text-sm focus:outline-none focus:border-orange-400"
              autoFocus
            />
          </div>

          <div>
            <label className="text-xs tracking-widest uppercase text-stone-500 font-semibold block mb-1.5">
              Especie *
            </label>
            <div className="grid grid-cols-3 gap-1.5">
              {SPECIES.map(s => {
                const Ic = s.Icon;
                const active = petSpecies === s.id;
                return (
                  <button
                    key={s.id}
                    onClick={() => setPetSpecies(s.id)}
                    className={`flex flex-col items-center gap-1 px-2 py-2 rounded-lg border transition ${
                      active ? "bg-orange-50 border-orange-400 text-orange-700" : "bg-white border-stone-200 text-stone-600 hover:border-orange-300"
                    }`}
                  >
                    <Ic size={16} strokeWidth={active ? 2.2 : 1.8} />
                    <span className="text-xs font-semibold">{s.label}</span>
                  </button>
                );
              })}
            </div>
            {petSpecies === "other" && (
              <input
                value={petSpeciesOther}
                onChange={(e) => setPetSpeciesOther(e.target.value)}
                placeholder="Especifica la especie (ej: hurón, iguana, tortuga…)"
                autoFocus
                className="mt-2 w-full px-3 py-2 bg-white border border-orange-300 rounded-lg text-sm focus:outline-none focus:border-orange-500"
              />
            )}
          </div>

          <div className="grid grid-cols-2 gap-2">
            <div>
              <label className="text-xs tracking-widest uppercase text-stone-500 font-semibold block mb-1">
                Raza
              </label>
              <input
                value={petBreed}
                onChange={(e) => setPetBreed(e.target.value)}
                placeholder="Mestizo, Labrador…"
                className="w-full px-3 py-2 bg-white border border-stone-200 rounded-lg text-sm focus:outline-none focus:border-orange-400"
              />
            </div>
            <div>
              <label className="text-xs tracking-widest uppercase text-stone-500 font-semibold block mb-1">
                Edad aprox.
              </label>
              <input
                value={petAge}
                onChange={(e) => setPetAge(e.target.value)}
                placeholder="2 años, 3 meses…"
                className="w-full px-3 py-2 bg-white border border-stone-200 rounded-lg text-sm focus:outline-none focus:border-orange-400"
              />
            </div>
          </div>

          <div>
            <label className="text-xs tracking-widest uppercase text-stone-500 font-semibold block mb-1.5">
              Sexo
            </label>
            <div className="grid grid-cols-3 gap-1.5">
              {[
                { id: "macho",  label: "♂ Macho" },
                { id: "hembra", label: "♀ Hembra" },
                { id: "",       label: "Desconocido" },
              ].map(g => {
                const active = petGender === g.id;
                return (
                  <button
                    key={g.id || "unk"}
                    onClick={() => setPetGender(g.id)}
                    className={`px-2 py-1.5 rounded-lg border text-xs font-semibold transition ${
                      active ? "bg-orange-50 border-orange-400 text-orange-700" : "bg-white border-stone-200 text-stone-600 hover:border-orange-300"
                    }`}
                  >
                    {g.label}
                  </button>
                );
              })}
            </div>
          </div>

          {/* Tutor — sólo si la cita no lo trajo */}
          {!hasOwnerName && (
            <div className="pt-2 mt-1 border-t border-stone-200">
              <label className="text-xs tracking-widest uppercase text-stone-500 font-semibold block mb-1">
                Nombre del tutor *
              </label>
              <input
                value={ownerName}
                onChange={(e) => setOwnerName(e.target.value)}
                placeholder="María Fernández, Fundación X…"
                className="w-full px-3 py-2 bg-white border border-stone-200 rounded-lg text-sm focus:outline-none focus:border-orange-400"
              />
              <p className="text-xs text-stone-400 italic mt-1">
                La cita no traía tutor asociado. Sólo necesitamos el nombre para vincular el pasaporte.
              </p>
            </div>
          )}

          {/* Aviso suave: lo administrativo lo completa ventas */}
          <div className="bg-stone-100 border border-stone-200 rounded-lg p-2.5 flex items-start gap-2 text-xs text-stone-600">
            <Info size={12} strokeWidth={2.2} className="flex-shrink-0 mt-0.5 text-stone-500" />
            <span>
              Los datos administrativos del tutor (cédula, teléfono, dirección) los completa <strong>ventas</strong> al momento de cobrar.
            </span>
          </div>
        </div>

        {/* Footer */}
        <div className="p-3 border-t border-stone-200 bg-white flex justify-between gap-2">
          <button onClick={onClose} className="px-3 py-2 rounded-lg text-sm font-semibold bg-white border border-stone-200 hover:border-stone-300 text-stone-700">
            Cancelar
          </button>
          <button
            onClick={handleSubmit}
            disabled={!canSubmit}
            className={`flex items-center gap-1.5 px-4 py-2 rounded-lg text-sm font-semibold transition ${
              canSubmit
                ? "bg-emerald-600 hover:bg-emerald-700 text-white shadow"
                : "bg-stone-200 text-stone-400 cursor-not-allowed"
            }`}
          >
            <Stethoscope size={13} strokeWidth={2.5} /> Pasar a consulta
          </button>
        </div>
      </div>
    </div>
  );
}
